//! AST → `krusty-ir` lowering for the core language.
//!
//! Runs after the front end (parse + type-check). Produces a backend-agnostic [`IrFile`] that any
//! backend (JVM, JS) lowers to its target — proving the FE/BE boundary is real. Covers the core
//! subset: declarations, expressions, control flow, calls, closures, and target-independent library
//! operations. Unsupported constructs make lowering return `None`; the selected backend reports that
//! as an unsupported IR-lowering shape.

use std::collections::HashMap;

use crate::ast::{self, BinOp, Decl, Expr, ExprId as AstExprId, FunBody, Stmt, TemplatePart};
use crate::frontend::{
    qualified_path, typeref_leaf, ClassNames, CtorDefaultValue, DelegateGetValueTarget,
    DestructureComponentTarget, ExprLowering, FrontendSymbols, FrontendTypeInfo, InlineCall,
    InvokeKind, IteratorDispatchTarget, LambdaCapture, LambdaInfo, ReceiverLambda, ResolvedCall,
    ResolvedConstructor, ResolvedLocalFunctionCall, ResolvedMember, ResolvedModuleTopLevelCall,
    Signature, StmtLowering,
};
use crate::ir::{
    Callee, ClassId, ExprId, FnParamInfo, IrBinOp, IrCatch, IrClass, IrConst, IrCtorArg,
    IrEnumEntry, IrExpr, IrField, IrFile, IrFunction, IrTypeOp,
};
use crate::libraries::{InlineKind, SemanticPlatform};
use crate::names::{property_getter_name, property_setter_name};
use crate::runtime::{
    CountedLoopInfo, PlatformAccessor, PlatformCtor, PlatformField, RuntimeCtor, RuntimeOp,
    TargetRuntime,
};
use crate::types::{existing_type_name, type_name, Ty, TypeName};

// --- Lower-bail diagnostics ----------------------------------------------------------------------
// `lower_file` returns `None` (silently skips a file) for any construct outside the IR subset. That is
// correct for the compiler, but opaque for the box-corpus `survey` — the roadmap of what to grow next.
// So lowering records WHY it last bailed in a caller-owned `bail` sink (on `Lower`): a coarse phase
// (`gate:class`, `deep:fun`) plus the innermost unsupported expr/stmt variant (`expr Lambda`, `call
// StringBuilder`). The compiler proper ignores it; the `survey` binary reads it (via the `_reporting`
// entry points) to map what to grow next. Set through `Lower::set_bail`.

fn default_mask_count(param_count: usize) -> usize {
    param_count.div_ceil(32).max(1)
}

fn default_mask_bit(param_index: usize) -> i32 {
    (1u32 << (param_index % 32)) as i32
}

fn is_conversion_call_name(name: &str) -> bool {
    matches!(
        name,
        "toInt"
            | "toByte"
            | "toShort"
            | "toLong"
            | "toFloat"
            | "toDouble"
            | "toChar"
            | "toUInt"
            | "toULong"
    )
}

/// The leading variant name of a `{:?}`-formatted AST node (`"Call { .. }"` → `"Call"`).
fn bail_variant(dbg: &str) -> &str {
    dbg.split(['(', '{', ' ']).next().unwrap_or("?")
}

struct ClassInfo {
    id: ClassId,
    internal: TypeName,
    fields: Vec<(String, Ty)>,
    /// method name → overloads in declaration order: (index into the class's `methods`, FunId,
    /// return Ty). Synthesized members (accessors, componentN, …) are single-entry.
    methods: HashMap<String, Vec<(u32, u32, Ty)>>,
    /// Base class internal name (`class B : A(…)`), for inherited field/method resolution.
    super_internal: Option<TypeName>,
}

impl ClassInfo {
    fn internal(&self) -> String {
        self.internal.render()
    }
}

/// Lower a checked file to IR, or `None` if it uses anything outside the core subset.
pub fn lower_file(
    file: &ast::File,
    info: &FrontendTypeInfo,
    syms: &FrontendSymbols,
    runtime: &dyn TargetRuntime,
) -> Option<IrFile> {
    lower_file_at(file, 0, info, syms, runtime)
}

/// [`lower_file`] with a caller-owned `bail` sink: on a `None` return, `bail` holds the reason (the
/// coarse phase + innermost unsupported variant). The `survey`/box-corpus diagnostics use this.
pub fn lower_file_reporting(
    file: &ast::File,
    info: &FrontendTypeInfo,
    syms: &FrontendSymbols,
    runtime: &dyn TargetRuntime,
    bail: &std::cell::RefCell<String>,
) -> Option<IrFile> {
    lower_file_at_reporting(file, 0, info, syms, runtime, bail)
}

/// Lower a checked file with its module file index. Multi-file drivers must use this so declaration ids
/// can be paired with their source file when selecting already-collected signatures.
pub fn lower_file_at(
    file: &ast::File,
    file_index: u32,
    info: &FrontendTypeInfo,
    syms: &FrontendSymbols,
    runtime: &dyn TargetRuntime,
) -> Option<IrFile> {
    let bail = std::cell::RefCell::new(String::new());
    lower_file_at_reporting(file, file_index, info, syms, runtime, &bail)
}

/// [`lower_file_at`] with a caller-owned `bail` sink (see [`lower_file_reporting`]).
pub fn lower_file_at_reporting(
    file: &ast::File,
    file_index: u32,
    info: &FrontendTypeInfo,
    syms: &FrontendSymbols,
    runtime: &dyn TargetRuntime,
    bail: &std::cell::RefCell<String>,
) -> Option<IrFile> {
    let mut lo = Lower {
        afile: file,
        file_index,
        info,
        syms,
        runtime,
        bail,
        ir: IrFile::with_package(file.package.clone()),
        fun_ids: HashMap::new(),
        fun_ids_by_decl: HashMap::new(),
        ext_fun_ids: HashMap::new(),
        ext_fun_id_by_arity: HashMap::new(),
        ext_fun_id_by_sig: HashMap::new(),
        ext_prop_get_ids: HashMap::new(),
        companion_consts: HashMap::new(),
        const_lits: HashMap::new(),
        object_const_lits: HashMap::new(),
        ext_prop_set_ids: HashMap::new(),
        classes: HashMap::new(),
        statics: HashMap::new(),
        scope: Vec::new(),
        next_value: 0,
        expected_array_elem: std::cell::Cell::new(None),
        cur_class: None,
        cur_field: None,
        field_accessor_props: std::collections::HashSet::new(),
        field_accessor_var_props: std::collections::HashSet::new(),
        cur_fn_name: String::new(),
        cur_fn_suspend: false,
        cur_tparams: Vec::new(),
        lambda_seq: 0,
        shared_cell_vars: std::collections::HashSet::new(),
        boxed_elem: HashMap::new(),
        local_fun_ids: HashMap::new(),
        cur_ret_ty: Ty::Unit,
        cur_method_returns_unit_ref: false,
        try_finally_stack: Vec::new(),
        companions: HashMap::new(),
        computed_props: HashMap::new(),
        computed_setters: HashMap::new(),
        cur_static_field: None,
        lateinit_locals: HashMap::new(),
        in_suspend_lambda_body: false,
        closure_captured_names: std::collections::HashSet::new(),
        local_delegated: HashMap::new(),
        cur_tailrec: None,
        expr_depth: 0,
        index_subst: HashMap::new(),
        inline_lambdas: Vec::new(),
        inline_active: Vec::new(),
        reified_subst: Vec::new(),
        inline_return: Vec::new(),
        inline_lambda_ret: Vec::new(),
        fn_body_tail: None,
    };

    // Pre-scan every `object`'s `const val`s so a read inlines the literal (like a top-level const),
    // removing the init-ordering hazard that would otherwise gate the object out. Only literal-valued
    // consts are recorded; a computed-value const keeps the object gated (a sound skip below).
    for &d in &file.decls {
        if let Decl::Class(c) = file.decl(d) {
            if c.is_object() {
                let internal = class_internal(file, &c.name);
                for p in c.body_props.iter().filter(|p| p.is_const) {
                    if let Some(lit) = p.init.and_then(|i| {
                        ast_literal_const(file, i, body_prop_ty(file, info, p, &*syms.libraries))
                    }) {
                        lo.object_const_lits
                            .insert((type_name(&internal), p.name.clone()), lit);
                    }
                }
            }
            // A `companion object`'s `const val`s are hoisted to `public static final` fields on the
            // OUTER class, but kotlinc INLINES a const read at every use site (`ldc`), qualified
            // (`C.HEX`) or bare from a member (`fun f() = HEX`). Record their literals under the outer
            // class's internal so both read paths (`object_const_lits`) inline the value like a top-level
            // const — otherwise a bare companion-const read finds no instance field/getter and bails.
            let internal = class_internal(file, &c.name);
            for p in c.companion_props.iter().filter(|p| p.is_const) {
                if let Some(lit) = p.init.and_then(|i| {
                    ast_literal_const(file, i, body_prop_ty(file, info, p, &*syms.libraries))
                }) {
                    lo.object_const_lits
                        .insert((type_name(&internal), p.name.clone()), lit);
                }
            }
        }
    }

    lo.set_bail("deep"); // refined below as lowering progresses (survey diagnostic only)
                         // Only files of top-level functions + *simple* classes take the IR path.
    for &d in &file.decls {
        match file.decl(d) {
            Decl::Fun(_) => {} // top-level function, extension function, or `inline fun` (expanded at call sites)
            Decl::Class(c) if is_simple_class(c) => {}
            Decl::Class(c) if c.is_enum() && is_simple_enum(c) => {}
            Decl::Class(c) if c.is_interface() && is_simple_interface(c) => {}
            Decl::Class(c)
                if c.is_object()
                    && is_simple_object(c)
                    // Every `const val` must be an inlinable literal (recorded in `object_const_lits`
                    // above) — its reads inline the value, so a method reading it is safe. A computed
                    // (non-literal) const keeps the object gated (its read would need the backing field).
                    && c.body_props.iter().all(|p| {
                        !p.is_const
                            || p.init.is_some_and(|i| is_const_literal(file, i))
                    }) => {}
            // A `val` extension property (`val Recv.name get() = …`) is lowered to a static getter; the
            // unsupported shapes (`var`, no `get()`) are skipped in pass 1.
            Decl::Property(p)
                if is_plain_body_prop(p)
                    || is_computed_prop(p)
                    || is_field_accessor_prop(p)
                    || p.delegate.is_some()
                    || p.receiver.is_some() => {}
            other => {
                lo.set_bail(match other {
                    Decl::Class(c) if c.is_object() => "gate:object",
                    Decl::Class(c) if c.is_interface() => "gate:interface",
                    Decl::Class(c) if c.is_enum() => "gate:enum",
                    Decl::Class(_) => "gate:class",
                    Decl::Property(_) => "gate:property",
                    _ => "gate:other",
                });
                return None;
            }
        }
    }

    // The `sequence {}` / `iterator {}` coroutine BUILDERS drive a suspend LAMBDA through `yield`/
    // `yieldAll` suspension points — a state machine the pass doesn't model. Skip the whole file rather
    // than emit a `Sequence`/`Iterator` whose `iterator()`/`next()` has no body (an `AbstractMethodError`
    // at the for-loop / terminal operation). Detected by the builder's `yield`/`yieldAll` calls anywhere.
    let uses_yield_builder = file.decls.iter().any(|&d| {
        let body = match file.decl(d) {
            Decl::Fun(f) => match &f.body {
                FunBody::Expr(e) | FunBody::Block(e) => Some(*e),
                FunBody::None => None,
            },
            Decl::Property(p) => p.init,
            _ => None,
        };
        let class_bodies: Vec<AstExprId> = match file.decl(d) {
            Decl::Class(c) => c
                .methods
                .iter()
                .filter_map(|m| match &m.body {
                    FunBody::Expr(e) | FunBody::Block(e) => Some(*e),
                    FunBody::None => None,
                })
                .chain(c.body_props.iter().filter_map(|p| p.init))
                .collect(),
            _ => Vec::new(),
        };
        body.into_iter().chain(class_bodies).any(|e| {
            expr_tree_calls_name(file, e, "yield") || expr_tree_calls_name(file, e, "yieldAll")
        })
    });
    if uses_yield_builder {
        return None;
    }

    // --- suspend (coroutines) lowerability gate ---------------------------------------------------
    // The coroutine transform itself lives in `jvm::suspend` (CPS signature + state machine); this only
    // decides whether the file is lowerable at all. ir_lower lowers a suspend fn body PLAINLY (a call
    // to another suspend fn becomes an ordinary call the pass then rewrites). Skip the whole file
    // (never miscompile) for shapes the pass doesn't model: an extension/member suspend fn, or a *call*
    // to a suspend fn from a NON-suspend function (call-site continuation threading isn't modeled — and
    // calling a suspend fn from a non-suspend context is a Kotlin error anyway). The pass itself skips
    // any suspend *body* shape it can't yet restructure.
    let top_suspend: Vec<String> = file
        .decls
        .iter()
        .filter_map(|&d| match file.decl(d) {
            Decl::Fun(f) if f.is_suspend => Some(f.name.clone()),
            _ => None,
        })
        .collect();
    let member_suspend: Vec<String> = file
        .decls
        .iter()
        .filter_map(|&d| match file.decl(d) {
            Decl::Class(c) => Some(c),
            _ => None,
        })
        .flat_map(|c| {
            c.methods
                .iter()
                .filter(|m| m.is_suspend)
                .map(|m| m.name.clone())
        })
        .collect();
    if !top_suspend.is_empty() || !member_suspend.is_empty() {
        // Extension suspend fns aren't modeled. (A leaf member suspend fn IS — its CPS signature on the
        // instance method; a member suspension point is skipped by the pass.)
        for &d in &file.decls {
            if let Decl::Fun(f) = file.decl(d) {
                if f.is_suspend && f.receiver.is_some() {
                    return None;
                }
            }
        }
        // Each body, tagged by whether its owner is a suspend fn. A NON-suspend body may not call a
        // top-level suspend fn (call-site threading isn't modeled, and it's a Kotlin error). A *member*
        // suspend fn may not be called at all yet (the flattener only models static suspend calls).
        let mut bodies: Vec<(AstExprId, bool)> = Vec::new();
        for &d in &file.decls {
            match file.decl(d) {
                Decl::Fun(f) => match &f.body {
                    FunBody::Expr(e) | FunBody::Block(e) => bodies.push((*e, f.is_suspend)),
                    FunBody::None => {}
                },
                Decl::Property(p) => bodies.extend(p.init.map(|e| (e, false))),
                Decl::Class(c) => {
                    for m in &c.methods {
                        match &m.body {
                            FunBody::Expr(e) | FunBody::Block(e) => bodies.push((*e, m.is_suspend)),
                            FunBody::None => {}
                        }
                    }
                    bodies.extend(
                        c.body_props
                            .iter()
                            .filter_map(|p| p.init)
                            .map(|e| (e, false)),
                    );
                }
            }
        }
        // A member `suspend fn` overriding a supertype method may need a generic-erasure BRIDGE (the CPS
        // override's descriptor vs the supertype's erased one), which the coroutine lowering does not
        // synthesize — that mismatch would miscompile (`SuspendingMutableMap : Map<K,V>`). But a bridge is
        // needed ONLY when generics are involved: if the class has NO type parameters AND every supertype
        // is a RAW (non-parameterized) type, the override's erased signature equals the supertype method's,
        // so the single CPS method directly implements it — no bridge (the common suspend-decorator /
        // interface-impl shape: a class implementing a large suspend interface). Bail only for the generic
        // shape, which still can't be modeled.
        // Whether a supertype's transitive closure contains a GENERIC type — a generic ancestor could carry
        // a suspend method that, when overridden concretely, needs an erasure bridge the coroutine pass can't
        // fix up. Walk module symbols first, then libraries; otherwise a source class in another file can
        // hide the relevant ancestry from this guard.
        let super_has_generic = |name: &str| -> bool {
            let Some(start) = syms
                .class_names
                .get(name)
                .or_else(|| existing_type_name(name))
            else {
                return false;
            };
            let mut stack = vec![start];
            let mut seen = std::collections::HashSet::new();
            while let Some(i) = stack.pop() {
                if !seen.insert(i) {
                    continue;
                }
                if let Some(c) = syms.class_by_type_name(i) {
                    if !c.tparam_names.is_empty() {
                        return true;
                    }
                    if let Some(s) = c.super_internal_name() {
                        stack.push(s);
                    }
                    stack.extend(c.interface_names());
                } else if let Some(t) = syms.libraries.resolve_type_name(i) {
                    if !t.type_params.is_empty() {
                        return true;
                    }
                    stack.extend(t.supertypes.iter_ids());
                }
            }
            false
        };
        let suspend_member_needs_bridge = file.decls.iter().any(|&d| {
            matches!(file.decl(d), Decl::Class(c)
                if (!c.supertypes.is_empty() || c.base_class.is_some())
                    && c.methods.iter().any(|m| m.is_suspend)
                    && (!c.type_params.is_empty()
                        || c.supertypes.iter().any(|s| {
                            !s.targs.is_empty()
                                || s.arg.is_some()
                                || super_has_generic(&s.name)
                        })
                        // A GENERIC classpath BASE CLASS with an open suspend fn overridden concretely
                        // needs an erasure bridge the superclass loop can't build (a classpath base breaks
                        // `resolve_method`), so guard it here too. `c.base_class` drops the type args, so
                        // check the base's own genericity (and its closure) directly.
                        || c.base_class.as_deref().is_some_and(super_has_generic)))
        });
        if suspend_member_needs_bridge {
            return None;
        }
        // A NON-suspend body may not call any suspend fn (top-level or member): call-site continuation
        // threading is only modeled inside a suspend body (and calling a suspend fn from a non-suspend
        // context is a Kotlin error). A suspend body may call both — the coroutine pass threads the
        // continuation into a static (`Call`) or member (`MethodCall`) suspend call.
        for (e, owner_suspend) in bodies {
            if !owner_suspend
                && top_suspend
                    .iter()
                    .chain(member_suspend.iter())
                    .any(|n| file.expr_uses_name(e, n))
            {
                return None;
            }
        }
    }

    // Pass 1a: register classes (id, fields) and reserve method FunIds.
    // An INTERFACE method default that references a class declared LATER in the file
    // (`filters: AuditFilters = AuditFilters()`) can't lower mid-pass — retried after the loop.
    // One entry per method: `(FunId, per-param (default expr, checker type), parameter names)`.
    type PendingIfaceDefault = (u32, Vec<(Option<crate::ast::ExprId>, Ty)>, Vec<String>);
    let mut pending_iface_defaults: Vec<PendingIfaceDefault> = Vec::new();
    for &d in &file.decls {
        if let Decl::Class(c) = file.decl(d) {
            let internal = class_internal(file, &c.name);
            // A generic class gets a JVM class `Signature` (kotlinc does), matching its bytecode.
            if let Some(s) = class_generic_sig(file, c, &*lo.syms.libraries, &lo.syms.class_names) {
                lo.ir.insert_class_signature(&internal, s);
            }
            // A field whose declared type is a bare type parameter (`val a: A`) gets a field `Signature`
            // (`TA;`); record the (field, type-param) pairs for the JVM backend to format.
            let field_sigs = class_field_tparams(c);
            if !field_sigs.is_empty() {
                lo.ir.insert_field_signatures(&internal, field_sigs);
            }
            // An `inner class` captures the enclosing instance: a synthetic `this$0` field of the outer
            // type, prepended as the first constructor-parameter field.
            let inner_outer: Option<String> = c.inner_of.as_ref().map(|o| class_internal(file, o));
            let class_sig = syms.classes.get(&c.name)?;
            let resolved_prop_ty = |name: &str| {
                class_sig
                    .props
                    .iter()
                    .find_map(|(n, t, _)| (n == name).then_some(stored_value_ty(*t)))
                    .unwrap_or(Ty::Error)
            };
            // Constructor-parameter fields, then class-body-property fields (initialized in `init_body`).
            // Field types come from the resolver's ClassSig so nested/imported/user classifier decisions
            // are made in the front end and lowering only consumes resolved semantic types.
            let mut ctor_fields: Vec<(String, Ty)> = c
                .props
                .iter()
                .filter(|p| p.is_property)
                .map(|p| (p.name.clone(), resolved_prop_ty(&p.name)))
                .collect();
            if let Some(outer) = &inner_outer {
                ctor_fields.insert(0, ("this$0".to_string(), Ty::obj(outer)));
            }
            let ctor_param_count = ctor_fields.len() as u32;
            // Computed body properties (custom getter, no backing field) become `getX()` methods, not
            // fields — exclude them here.
            let body_fields: Vec<(String, Ty)> = c
                .body_props
                .iter()
                .filter(|p| is_backing_field_prop(p))
                .map(|p| {
                    let ty =
                        p.ty.as_ref()
                            .map(|_| resolved_prop_ty(&p.name))
                            .unwrap_or_else(|| info.ty(p.init.unwrap()));
                    (p.name.clone(), ty)
                })
                .collect();
            // A custom-accessor property is read/written ONLY via `getX`/`setX` — record it so an
            // in-class access by name routes through the accessor, not a direct field read/write.
            for p in c.body_props.iter().filter(|p| is_field_accessor_prop(p)) {
                lo.field_accessor_props
                    .insert((type_name(&internal), p.name.clone()));
                if p.is_var {
                    lo.field_accessor_var_props
                        .insert((type_name(&internal), p.name.clone()));
                }
            }
            // Guard each delegated member property: only the simple shape is modeled — a concrete
            // (non-value-class, no `provideDelegate`) delegate whose `getValue` return type matches the
            // property type exactly (generic erasure / value-class unboxing would need a cast the inline
            // accessor doesn't emit). Anything else skips the file rather than miscompile.
            for p in c.body_props.iter().filter(|p| p.delegate.is_some()) {
                let dt = info.ty(p.delegate.unwrap());
                let di = dt.obj_internal()?;
                let is_value_cls = |internal: TypeName| {
                    syms.class_by_type_name(internal)
                        .is_some_and(|cs| cs.value_field.is_some())
                };
                if is_value_cls(di) || syms.method_of_name(di, "provideDelegate").is_some() {
                    return None;
                }
                let (_, _, gv_ret, _, _) = lo.delegate_getvalue_info(p.delegate.unwrap(), di)?;
                let prop_ty = syms
                    .classes
                    .get(&c.name)
                    .and_then(|cs| {
                        cs.props
                            .iter()
                            .find_map(|(n, t, _)| (n == &p.name).then_some(*t))
                    })
                    .unwrap_or(Ty::Error);
                // A generic delegate's `getValue` returns the ERASED `Object` (`<T> getValue(): T`); the
                // getter inserts a `checkcast`/unbox to the property type (kotlinc does the same), bridged by
                // `coerce_erased`. Only an erased-REFERENCE return is bridgeable — a concrete mismatched
                // return isn't, so bail on that.
                if gv_ret != prop_ty && !gv_ret.is_reference() {
                    return None;
                }
                if prop_ty.obj_internal().is_some_and(is_value_cls) {
                    return None;
                }
            }
            // Synthetic `x$delegate` instance fields for delegated member properties — one per delegated
            // body property, in declaration order, placed AFTER the real backing-field props (so the
            // accessor-synthesis loop, which is driven by `field_props`, never indexes them).
            let delegate_fields: Vec<(String, Ty)> = c
                .body_props
                .iter()
                .filter(|p| p.delegate.is_some())
                .map(|p| (format!("{}$delegate", p.name), info.ty(p.delegate.unwrap())))
                .collect();
            // Interface delegation `: I by d` whose delegate `d` is a NON-`val` constructor parameter has
            // no backing field — kotlinc synthesizes a `private final $$delegate_<i>` (i = delegation index)
            // holding it, stored in the ctor. (A `val`-param delegate already has its own field.)
            let ctor_prop_names: std::collections::HashSet<&str> = c
                .props
                .iter()
                .filter(|p| p.is_property)
                .map(|p| p.name.as_str())
                .collect();
            let iface_delegate_fields: Vec<(String, Ty)> = c
                .delegations
                .iter()
                .enumerate()
                .filter(|(_, (_, d, _))| !ctor_prop_names.contains(d.as_str()))
                .filter_map(|(i, (_, d, _))| {
                    c.props.iter().find(|p| &p.name == d).map(|p| {
                        (
                            format!("$$delegate_{i}"),
                            ty_of(file, &p.ty, &*syms.libraries),
                        )
                    })
                })
                .collect();
            // Interface delegation to an EXPRESSION (`: I by Impl()`): a synthesized `$$delegate_e<j>`
            // field holding the once-evaluated expression (stored in the ctor).
            let expr_delegate_fields: Vec<(String, Ty)> = c
                .delegation_exprs
                .iter()
                .enumerate()
                .map(|(j, (_, e))| (format!("$$delegate_e{j}"), info.ty(*e)))
                .collect();
            let fields: Vec<(String, Ty)> = ctor_fields
                .into_iter()
                .chain(body_fields)
                .chain(delegate_fields.iter().cloned())
                .chain(iface_delegate_fields.iter().cloned())
                .chain(expr_delegate_fields.iter().cloned())
                .collect();
            // The names backing a `lateinit var` — `IrField::is_lateinit` is set by name below (matched
            // in the final `fields`, so any `this$0` offset is handled). The backend null-checks every
            // read of such a field.
            let lateinit_names: std::collections::HashSet<&str> = c
                .body_props
                .iter()
                .filter(|p| p.is_lateinit)
                .map(|p| p.name.as_str())
                .collect();
            // Parallel to `fields`: each field's source type-parameter name (`val x: T` → `Some("T")`),
            // else `None`. Same ordering as `fields` (ctor props, `this$0` at 0 for an inner class, then
            // backing-field body props). Neutral metadata for the value-class pass's bound resolution.
            let mut field_type_params: Vec<Option<String>> = c
                .props
                .iter()
                .filter(|p| p.is_property)
                .map(|p| {
                    c.type_params
                        .contains(&p.ty.name)
                        .then(|| p.ty.name.clone())
                })
                .collect();
            if inner_outer.is_some() {
                field_type_params.insert(0, None);
            }
            field_type_params.extend(
                c.body_props
                    .iter()
                    .filter(|p| is_backing_field_prop(p))
                    .map(|_| None),
            );
            // Parallel `None` for each synthetic `x$delegate` field (concrete delegate type, no type-param).
            field_type_params.extend(delegate_fields.iter().map(|_| None));
            // Parallel `None` for each synthetic interface-delegation `$$delegate_N`/`$$delegate_e<j>` field.
            field_type_params.extend(iface_delegate_fields.iter().map(|_| None));
            field_type_params.extend(expr_delegate_fields.iter().map(|_| None));
            let class_ty = Ty::obj(&internal);
            // Resolve a supertype NAME written in `c`'s body to a FILE class/interface internal, if any.
            // Handles a simple name, a qualified nested name (`Outer.Bar`, parsed to slash-form
            // `Outer/Bar`), and a SIBLING or enclosing-scope nested type referenced by SIMPLE name from
            // inside a nested `c` (`class Outer { interface Foo; class Impl: Foo }`). Comparing on the
            // JVM INTERNAL name folds all three: `class_internal` maps both a decl's `Outer.Bar` and the
            // name's dot-restored `Outer.Bar` to the same `…/Outer$Bar`, subsuming the simple case.
            let resolve_file_supertype = |name: &str, want_iface: bool| -> Option<String> {
                let mangled = name.replace('/', ".");
                // Candidates in SCOPE order, nearest first: the name itself, then qualified by each
                // enclosing prefix of `c` walking outward. Returning the first candidate that names a
                // file decl (not the first file-order decl) gives Kotlin's nearest-scope-wins semantics
                // when the same simple name is a nested type under more than one outer.
                let mut candidates = vec![class_internal(file, &mangled)];
                let mut prefix = c.name.as_str();
                while let Some((p, _)) = prefix.rsplit_once('.') {
                    candidates.push(class_internal(file, &format!("{p}.{mangled}")));
                    prefix = p;
                }
                candidates.into_iter().find(|cand| {
                    file.decls.iter().any(|&d| matches!(file.decl(d),
                        Decl::Class(bc) if bc.is_interface() == want_iface && class_internal(file, &bc.name) == *cand))
                })
            };
            // Resolve a base class (`: A(args)`): a non-interface class declared in this file, OR a
            // CLASSPATH (Java/library) class — the subclass's `super(…)` becomes `invokespecial` on the
            // base's `<init>`. A base type that resolves to neither (or to an interface) → bail.
            let super_internal: Option<TypeName> = match &c.base_class {
                Some(base) => {
                    if let Some(base_internal) = resolve_file_supertype(base, false) {
                        Some(type_name(&base_internal))
                    } else {
                        // A classpath base class: map the source name to its internal (via imports). Only a
                        // CONCRETE (non-final, non-abstract) non-interface class is a safe superclass to
                        // emit — a final base fails verification, an abstract base needs abstract-method /
                        // bridge synthesis the backend doesn't do, an interface isn't a superclass. Anything
                        // else → bail (the construct stays unsupported, as before).
                        let resolved = lo
                            .syms
                            .class_names
                            .get(base)
                            .unwrap_or_else(|| type_name(base));
                        if let Some(module_base) = lo.syms.class_by_type_name(resolved) {
                            if module_base.is_interface || module_base.is_abstract {
                                return None;
                            }
                            if c.base_args.is_empty() && !module_base.ctor_params.is_empty() {
                                return None;
                            }
                            Some(resolved)
                        } else {
                            if !lo.syms.libraries.class_is_extensible_name(resolved) {
                                return None;
                            }
                            // Only a NO-ARG `super()` to a classpath base is emitted (the ctor lowering has no
                            // lowered `ClassSig` for a library base to shape a parameterized `super(args)`).
                            // When no explicit base args are written, the base MUST have a no-arg constructor,
                            // else the emitted `invokespecial <base>.<init>()V` would target a method that
                            // doesn't exist — bail rather than miscompile. (An arg-taking `: Base(x)` already
                            // bails at the `super_field_tys` arity check, since a classpath base contributes no
                            // field types.)
                            let has_no_arg_ctor = lo
                                .syms
                                .libraries
                                .resolve_type_name(resolved)
                                .is_some_and(|t| {
                                    t.constructors.is_empty()
                                        || t.constructors.iter().any(|ctor| ctor.params.is_empty())
                                });
                            if c.base_args.is_empty() && !has_no_arg_ctor {
                                return None;
                            }
                            Some(resolved)
                        }
                    }
                }
                None => None,
            };
            let superclass = super_internal.unwrap_or_else(crate::types::wk::any);
            // Implemented interfaces (`: I, J`): a file interface, or a classpath interface
            // (`Runnable`, `Comparator`) resolved through the library set; else bail.
            let mut iface_internals = Vec::new();
            for st_ref in &c.supertypes {
                let st = &st_ref.name;
                if let Some(internal) = resolve_file_supertype(st, true) {
                    iface_internals.push(type_name(&internal));
                    continue;
                }
                let resolved = lo.syms.class_names.get(st).unwrap_or_else(|| type_name(st));
                if lo
                    .syms
                    .class_by_type_name(resolved)
                    .is_some_and(|c| c.is_interface)
                    || lo
                        .syms
                        .libraries
                        .resolve_type_name(resolved)
                        .is_some_and(|t| t.is_interface())
                {
                    iface_internals.push(resolved);
                } else {
                    return None;
                }
            }
            // Per-field finality aligned to `fields`: `this$0` is final; a property field is final unless
            // `var`; each synthetic `x$delegate` field is final.
            let field_finals: Vec<bool> = inner_outer
                .iter()
                .map(|_| true)
                .chain(c.props.iter().filter(|p| p.is_property).map(|p| !p.is_var))
                .chain(
                    c.body_props
                        .iter()
                        .filter(|p| is_backing_field_prop(p))
                        .map(|p| !p.is_var),
                )
                .chain(delegate_fields.iter().map(|_| true))
                .collect();
            let ir_fields: Vec<IrField> = fields
                .iter()
                .enumerate()
                .map(|(i, (n, t))| {
                    let default = c
                        .props
                        .iter()
                        .find(|p| p.name == *n)
                        .and_then(|p| p.default)
                        .and_then(|d| const_default_of(file, d))
                        // Widen the literal to the field's type so its JVM slot width/kind matches the
                        // field local (`val x: Long = 5` parses `5` as `Int` — store it as `Long`).
                        .map(|cst| widen_const_to(cst, *t));
                    let ir = ty_to_ir(*t);
                    // Re-attach a generic field's TYPE ARGUMENTS from the property's source `TypeRef`
                    // (`ty_of`/`ty_to_ir` erase them for a general `Obj`). Read straight from the AST so
                    // `Box<Int>` keeps `<Int>` — the serialization extension needs it to build a nested
                    // generic element serializer (`Box.serializer(IntSerializer)`); descriptors still
                    // erase, so this is additive metadata on the field type only.
                    let ir = match c.props.iter().find(|p| p.name == *n) {
                        Some(p)
                            if !p.ty.targs.is_empty() && ir.non_null().obj_internal().is_some() =>
                        {
                            let fq_name = ir.non_null().obj_internal().unwrap();
                            let targs: Vec<Ty> =
                                p.ty.targs
                                    .iter()
                                    .map(|a| field_ty_with_args(file, a, &*syms.libraries))
                                    .collect();
                            let base = Ty::obj_args_name(fq_name, &targs);
                            if ir.is_nullable() {
                                Ty::nullable(base)
                            } else {
                                base
                            }
                        }
                        _ => ir,
                    };
                    // Preserve declared field nullability in IR.
                    let ir = if c.props.iter().any(|p| p.name == *n && p.ty.nullable) {
                        mark_nullable(ir)
                    } else {
                        ir
                    };
                    IrField {
                        name: n.clone(),
                        ty: ir,
                        type_param: field_type_params[i].clone(),
                        default,
                        has_default: c.props.iter().any(|p| &p.name == n && p.default.is_some()),
                        // `field_finals` covers up to the `x$delegate` fields; the trailing
                        // interface-delegation fields (`$$delegate_N`/`$$delegate_e<j>`) default to
                        // non-final, matching the prior `field_final.get(i).unwrap_or(false)`.
                        is_final: field_finals.get(i).copied().unwrap_or(false),
                        is_private: true, // user backing fields are all private (default)
                        is_lateinit: lateinit_names.contains(n.as_str()),
                    }
                })
                .collect();
            let id = lo.ir.add_class(IrClass {
                fq_name: type_name(&internal),
                is_value: c.is_value,
                is_data: c.is_data,
                decl_line: c.decl_line,
                type_param_bounds: c
                    .type_param_bounds
                    .iter()
                    .map(|(n, tr)| {
                        let bt = ty_to_ir(ty_of(file, tr, &*syms.libraries));
                        (n.clone(), if tr.nullable { mark_nullable(bt) } else { bt })
                    })
                    .collect(),
                type_params: c.type_params.clone(),
                supertypes: vec![],
                fields: ir_fields,
                ctor_param_count,
                // All primary-ctor params in declaration order; `is_field` = it's a `val`/`var` property.
                // An inner class's synthetic `this$0` (the outer instance) is the first field param —
                // never null-checked (kotlinc doesn't guard it).
                ctor_args: inner_outer
                    .iter()
                    .map(|o| IrCtorArg {
                        ty: ty_to_ir(Ty::obj(o)),
                        is_field: true,
                        check: None,
                    })
                    .chain(c.props.iter().enumerate().map(|(i, p)| {
                        let t = ty_to_ir(stored_value_ty(
                            class_sig.ctor_params.get(i).copied().unwrap_or(Ty::Error),
                        ));
                        let t = if p.ty.nullable { mark_nullable(t) } else { t };
                        // A non-null reference param gets an `Intrinsics.checkNotNullParameter` guard at
                        // `<init>` entry (kotlinc does); primitives, nullable, and class type-params skip it.
                        let is_type_param = c.type_params.contains(&p.ty.name);
                        let check = if !p.ty.nullable
                            && !is_type_param
                            && ty_of(file, &p.ty, &*syms.libraries).is_reference()
                        {
                            Some(p.name.clone())
                        } else {
                            None
                        };
                        IrCtorArg {
                            ty: t,
                            is_field: p.is_property,
                            check,
                        }
                    }))
                    .collect(),
                init_body: None,
                explicit_param_stores: false,
                methods: vec![],
                is_interface: c.is_interface(),
                is_annotation: c.is_annotation(),
                annotation_impl_of: None,
                is_sealed: c.is_sealed(),
                is_abstract: c.is_abstract(),
                is_open: c.is_open(),
                superclass,
                super_args: Vec::new(),
                // Entry names + subclass markers now; constructor-arg value-ids are lowered in pass 2.
                enum_entries: c
                    .enum_entries
                    .iter()
                    .map(|e| IrEnumEntry {
                        name: e.name.clone(),
                        args: Vec::new(),
                        subclass: None,
                    })
                    .collect(),
                enum_entry_of: None,
                prop_ref: None,
                func_ref: None,
                bridges: Vec::new(),
                interfaces: iface_internals.clone().into(),
                is_object: c.is_object(),
                is_companion: false,
                companion_class: None,
                secondary_ctors: vec![],
                has_primary_ctor: c.has_primary_ctor,
                applied_annotations: class_applied_annotations(file, c, &lo.ir),
                field_annotations: class_field_annotations(file, c, syms, &lo.ir),
                // A Kotlin `annotation class` is RUNTIME-retained unless it opts out — emit the
                // `@Retention(RUNTIME)` meta-annotation so its uses stay visible to reflection.
                runtime_retained: c.kind == ast::ClassKind::Annotation
                    && runtime_annotation_decl(file, &c.name).is_some(),
            });
            // For an `annotation class`, ALSO emit the synthetic IMPLEMENTATION class (kotlinc's
            // `…$annotationImpl`) implementing the annotation interface + the `java.lang.annotation.
            // Annotation` contract, so `A(args)` can construct an annotation instance. The backend
            // generates the whole impl from `fields` (see `emit_annotation_impl_class`).
            if c.is_annotation() {
                let mut impl_class = lo.ir.classes[id as usize].clone();
                impl_class.fq_name = type_name(&format!("{internal}$annotationImpl"));
                impl_class.is_annotation = false;
                impl_class.annotation_impl_of = Some(type_name(&internal));
                impl_class.interfaces = vec![type_name(&internal)].into();
                impl_class.superclass = type_name("kotlin/Any");
                impl_class.supertypes = vec![];
                impl_class.methods = vec![];
                lo.ir.add_class(impl_class);
            }
            let mut methods: HashMap<String, Vec<(u32, u32, Ty)>> = HashMap::new();
            let mut method_fids = Vec::new();
            for (mi, m) in c.methods.iter().enumerate() {
                // Overloads: the signature Vec preserves declaration order per name, so the i-th
                // same-name AST decl pairs with the i-th signature.
                let overload_idx = c.methods[..mi].iter().filter(|x| x.name == m.name).count();
                let sig = syms
                    .classes
                    .get(&c.name)?
                    .methods_named(&m.name)
                    .get(overload_idx)?;
                let ret = sig.ret;
                let params = tys_to_ir(&sig.params);
                let class_nonnull_tps: std::collections::HashSet<String> = c
                    .type_param_bounds
                    .iter()
                    .filter(|(_, tr)| !tr.nullable)
                    .map(|(n, _)| n.clone())
                    .collect();
                let param_checks =
                    param_checks_for(m, &sig.params, &c.type_params, &class_nonnull_tps);
                // The checker `Ty` carries no nullability, so recover the declared `?` from the method's
                // AST return type (`fun f(): T?`) — same as a top-level function. A nullable value-class
                // return (`Ucn?`) must stay the boxed `X`, not erase to the unboxed underlying.
                let ret_ir = ty_to_ir(ret);
                let ret_ir = if m.ret.as_ref().is_some_and(|r| r.nullable) {
                    mark_nullable(ret_ir)
                } else {
                    ret_ir
                };
                let fid = lo.ir.add_fun(IrFunction {
                    name: m.name.clone(),
                    params,
                    ret: ret_ir,
                    body: None,
                    is_static: false,
                    dispatch_receiver: Some(type_name(&internal)),
                    param_checks,
                });
                // A `private` method is NON-VIRTUAL: a call to it (even the unqualified `foo()` inside a
                // sibling default method) must be `invokespecial`, not `invokevirtual`/`invokeinterface` —
                // else it dispatches to a same-named override (`interface A { private fun foo(); fun bar() =
                // foo() }` called on a `B : A` with its own private `foo` would wrongly run `B.foo`).
                if m.visibility.is_private() {
                    lo.ir.private_methods.insert(fid);
                }
                // An `open`/`override` member is overridable — kotlinc's member modality stays OPEN
                // (no `ACC_FINAL`) even when nothing in this module extends the class: a separately
                // compiled module (or javac in a mixed build) may override it.
                if m.is_open {
                    lo.ir.open_methods.insert(fid);
                }
                // Mark defaults in pass 1; pass 2 overwrites the marker with lowered expressions.
                if !m.params.iter().any(|p| p.default.is_some()) && !m.params.is_empty() {
                    // No OWN defaults: an override may still inherit the base method's defaults.
                    if let Some(defaults) =
                        lo.base_const_defaults(file, c.base_class.as_deref(), &m.name, &sig.params)
                    {
                        lo.ir.fn_params.insert(
                            fid,
                            FnParamInfo::defaults(
                                m.params.iter().map(|p| p.name.clone()).collect(),
                                defaults,
                            ),
                        );
                    }
                }
                if m.params.iter().any(|p| p.default.is_some()) {
                    // Lower each CONSTANT default NOW (pass 1) for BOTH class and interface methods, so a
                    // call that OMITS them and is lowered BEFORE this method's pass-2 body — a FORWARD
                    // reference (the caller is defined earlier in the class, e.g. `hasPermission` calling a
                    // later `private resolveRoles(id, x = null)`) — can still fill them. A constant needs no
                    // param/`this` scope, so it is valid this early. A NON-constant default is left `None`:
                    // a class method's is filled by pass 2 from the body scope; an INTERFACE has no pass-2
                    // body, so an unmodeled default there drops the whole marker (an omitted-arg call then
                    // bails/skips rather than miscompiles).
                    let mut defaults = Vec::new();
                    let mut all_const = true;
                    for (p, t) in m.params.iter().zip(&sig.params) {
                        match p.default {
                            None => defaults.push(None), // a required parameter
                            Some(d) if is_const_literal(file, d) => {
                                match lo.lower_arg(d, &ty_to_ir(*t)) {
                                    Some(e) => defaults.push(Some(e)),
                                    None => {
                                        all_const = false;
                                        defaults.push(None);
                                    }
                                }
                            }
                            Some(_) => {
                                all_const = false;
                                defaults.push(None); // a non-constant default — pass 2 fills it (class only)
                            }
                        }
                    }
                    let names: Vec<String> = m.params.iter().map(|p| p.name.clone()).collect();
                    if c.is_interface() && !all_const {
                        // An interface's non-constant default may reference a class declared LATER in
                        // the file — retry once every class is registered (below); a default that
                        // still doesn't lower drops the marker (an omitted-arg call skips the file).
                        lo.ir.fn_params.remove(&fid);
                        pending_iface_defaults.push((
                            fid,
                            m.params
                                .iter()
                                .zip(&sig.params)
                                .map(|(p, t)| (p.default, *t))
                                .collect(),
                            names,
                        ));
                    } else {
                        lo.ir
                            .fn_params
                            .insert(fid, FnParamInfo::defaults(names, defaults));
                    }
                }
                // A trailing `vararg` parameter is OMITTABLE by an ADAPTED callable reference (`C::mv`
                // used as `(Int) -> Unit`): synthesize an empty-array default for it so the `$default`
                // stub fills `new T[0]` when the vararg is masked. Merge with any existing defaults.
                // Normal calls pass every argument (no mask), so this only affects the adapted-reference
                // path — additive, like kotlinc.
                if !c.is_interface() && m.params.last().is_some_and(|p| p.is_vararg) {
                    let vi = m.params.len() - 1;
                    let arr_ty = ty_to_ir(sig.params[vi]);
                    let size0 = lo.emit_const(IrConst::Int(0));
                    let empty = lo.emit_new_array(arr_ty, size0);
                    let names: Vec<String> = m.params.iter().map(|p| p.name.clone()).collect();
                    let mut info = lo
                        .ir
                        .fn_params
                        .remove(&fid)
                        .unwrap_or_else(|| FnParamInfo::names(names.clone()));
                    let mut defs = info
                        .defaults
                        .take()
                        .unwrap_or_else(|| vec![None; m.params.len()]);
                    if defs.len() == m.params.len() {
                        defs[vi] = Some(empty);
                        info.names = names;
                        info.defaults = Some(defs);
                        lo.ir.fn_params.insert(fid, info);
                    }
                }
                // Tag a `suspend` member method for the coroutine pass (same as a top-level suspend fun).
                if m.is_suspend {
                    lo.ir.suspend_funs.push(fid);
                }
                // A generic member method gets the same JVM `Signature` as a generic top-level function.
                if let Some(s) = fn_generic_sig(file, m, &*lo.syms.libraries) {
                    lo.ir.signatures.insert(fid, s);
                }
                methods
                    .entry(m.name.clone())
                    .or_default()
                    .push((mi as u32, fid, ret));
                method_fids.push(fid);
            }
            // Computed body properties → `getX()` instance methods (no backing field).
            for p in c.body_props.iter().filter(|p| is_computed_prop(p)) {
                let ty = body_prop_ty(file, info, p, &*syms.libraries);
                let gname = property_getter_name(&p.name);
                let mi = method_fids.len() as u32;
                let fid = lo.ir.add_fun(IrFunction {
                    name: gname.clone(),
                    params: vec![],
                    ret: ty_to_ir(ty),
                    body: None,
                    is_static: false,
                    dispatch_receiver: Some(type_name(&internal)),
                    param_checks: vec![],
                });
                methods.entry(gname).or_default().push((mi, fid, ty));
                method_fids.push(fid);
            }
            // Delegated body properties (`val/var x by Del()`) → a `getX()` (and `setX()` for a `var`)
            // instance method that calls the delegate's `getValue`/`setValue`. Bodies built in pass 2.
            for p in c.body_props.iter().filter(|p| p.delegate.is_some()) {
                let prop_ty = syms
                    .classes
                    .get(&c.name)
                    .and_then(|cs| {
                        cs.props
                            .iter()
                            .find_map(|(n, t, _)| (n == &p.name).then_some(*t))
                    })
                    .unwrap_or(Ty::Error);
                let gname = property_getter_name(&p.name);
                let mi = method_fids.len() as u32;
                let fid = lo.ir.add_fun(IrFunction {
                    name: gname.clone(),
                    params: vec![],
                    ret: ty_to_ir(prop_ty),
                    body: None,
                    is_static: false,
                    dispatch_receiver: Some(type_name(&internal)),
                    param_checks: vec![],
                });
                methods.entry(gname).or_default().push((mi, fid, prop_ty));
                method_fids.push(fid);
                if p.is_var {
                    let sname = property_setter_name(&p.name);
                    let mi = method_fids.len() as u32;
                    let fid = lo.ir.add_fun(IrFunction {
                        name: sname.clone(),
                        params: vec![ty_to_ir(prop_ty)],
                        ret: Ty::Unit,
                        body: None,
                        is_static: false,
                        dispatch_receiver: Some(type_name(&internal)),
                        param_checks: vec![],
                    });
                    methods.entry(sname).or_default().push((mi, fid, Ty::Unit));
                    method_fids.push(fid);
                }
            }
            // Abstract properties (`abstract val x: T`, and every interface property) → an abstract
            // `getX()` (and `setX()` for a `var`) the implementing class overrides with its field
            // accessor.
            {
                for p in c
                    .body_props
                    .iter()
                    .filter(|p| p.is_abstract || (c.is_interface() && !is_computed_prop(p)))
                {
                    let mut ty =
                        p.ty.as_ref()
                            .map(|r| ty_of(file, r, &*syms.libraries))
                            .unwrap_or_else(|| Ty::obj("kotlin/Any"));
                    let mut ir_ty = body_prop_ir_ty(file, info, p, &*syms.libraries);
                    // `ty_of` resolves only file-local types + built-ins, and an ABSTRACT property has
                    // no initializer/getter to recover a CLASSPATH type from (`val id: Vid` on an
                    // interface would erase to `Any`/`Object`). Resolve the annotation against the
                    // classpath and re-apply the declared `?` — the type drives the getter's
                    // descriptor AND its value-class erasure/mangle.
                    if ty.is_erased_top() {
                        if let Some(r) = p.ty.as_ref() {
                            if r.name != "Any" && r.name != "kotlin/Any" {
                                if let Some(rt) = lo.classpath_ty_ref(r) {
                                    ty = rt;
                                    ir_ty = if r.nullable {
                                        mark_nullable(ty_to_ir(rt))
                                    } else {
                                        ty_to_ir(rt)
                                    };
                                }
                            }
                        }
                    }
                    let gname = property_getter_name(&p.name);
                    if !methods.contains_key(&gname) {
                        let mi = method_fids.len() as u32;
                        let fid = lo.ir.add_fun(IrFunction {
                            name: gname.clone(),
                            params: vec![],
                            ret: ir_ty,
                            body: None,
                            is_static: false,
                            dispatch_receiver: Some(type_name(&internal)),
                            param_checks: vec![],
                        });
                        methods.entry(gname).or_default().push((mi, fid, ty));
                        method_fids.push(fid);
                    }
                    if p.is_var {
                        let sname = property_setter_name(&p.name);
                        if !methods.contains_key(&sname) {
                            let mi = method_fids.len() as u32;
                            let fid = lo.ir.add_fun(IrFunction {
                                name: sname.clone(),
                                params: vec![ir_ty],
                                ret: Ty::Unit,
                                body: None,
                                is_static: false,
                                dispatch_receiver: Some(type_name(&internal)),
                                param_checks: vec![],
                            });
                            methods.entry(sname).or_default().push((mi, fid, Ty::Unit));
                            method_fids.push(fid);
                        }
                    }
                }
            }
            // Synthesize `getX()`/`setX()` accessors for each backing-field property (kotlinc emits
            // them; the fields are private). Getter returns the field; setter (var only) writes it.
            // Interfaces have no backing fields. An enum's ctor properties get getters here too (kotlinc
            // emits `private` fields + `getX()`); `emit_enum_class` emits those fields private to match.
            if !c.is_interface() {
                let field_props: Vec<(String, bool, bool)> = c
                    .props
                    .iter()
                    .filter(|p| p.is_property)
                    .map(|p| (p.name.clone(), p.is_var, p.visibility.is_private()))
                    .chain(
                        c.body_props
                            .iter()
                            .filter(|p| is_backing_field_prop(p))
                            .map(|p| (p.name.clone(), p.is_var, p.visibility.is_private())),
                    )
                    .collect();
                // An inner class's `this$0` occupies field index 0, so the declared properties' fields
                // are shifted by one — map each property's `field_props` index to its real field index.
                let field_offset = if inner_outer.is_some() { 1 } else { 0 };
                // For a generic class, a field typed by a bare type parameter (`val a: A`) → its
                // synthesized accessors carry a JVM `Signature` (`getA()` → `()TA;`, `setA(TA;)V`).
                let field_tp: std::collections::HashMap<String, String> =
                    class_field_tparams(c).into_iter().collect();
                // kotlinc emits NO accessor for a `private` property (in-class reads go straight to the
                // field); synthesizing one is an extra public member → an ABI divergence. Kept when the
                // class HAS a companion — a companion reads the outer's privates through the getter
                // (kotlinc uses an `access$…` bridge krusty doesn't emit yet; box `classes/kt504.kt`).
                // A value class also keeps its getter (its unboxed-support synthesis expects it).
                // Only a companion with CODE (methods, non-const props, a base) can read the
                // outer class's privates through the getter (kt504); a CONST-ONLY companion never
                // does — its outer keeps kotlinc's shape (no getter for a private property).
                let has_companion = !c.companion_methods.is_empty()
                    || c.companion_props.iter().any(|p| !p.is_const)
                    || c.companion_base.is_some();
                for (pi, (pname, is_var, is_private)) in field_props.iter().enumerate() {
                    let fidx = pi + field_offset;
                    if *is_private && !c.is_value && !has_companion {
                        continue;
                    }
                    let fty = fields[fidx].1;
                    // Use the class field's IrType (carries declared `?` via `mark_nullable`), not the
                    // bare `Ty` — so a nullable value-class property getter erases consistently with the
                    // field (`z: Z1?` → `LZ1;`, not the collapsed final underlying).
                    let fty_ir = lo.ir.classes[id as usize].fields[fidx].ty;
                    let gname = property_getter_name(pname);
                    if !methods.contains_key(&gname) {
                        // A plain field read; if the field is `lateinit` the backend's `GetField`
                        // emission inserts the uninitialized null-check throw (so does every other read).
                        let this_e = lo.emit_get_value(0);
                        let gf = lo.emit_get_field(this_e, id, fidx as u32);
                        let ret = lo.emit_return(Some(gf));
                        let body = lo.emit_block(vec![ret], None);
                        let mi = method_fids.len() as u32;
                        let fid = lo.ir.add_fun(IrFunction {
                            name: gname.clone(),
                            params: vec![],
                            ret: fty_ir,
                            body: Some(body),
                            is_static: false,
                            dispatch_receiver: Some(type_name(&internal)),
                            param_checks: vec![],
                        });
                        if let Some(tp) = field_tp.get(pname) {
                            lo.ir.signatures.insert(
                                fid,
                                crate::ir::IrGenericSig {
                                    type_params: vec![],
                                    param_tparams: vec![],
                                    ret_tparam: Some(tp.clone()),
                                    supers: Vec::new(),
                                },
                            );
                        }
                        methods.entry(gname).or_default().push((mi, fid, fty));
                        method_fids.push(fid);
                    }
                    if *is_var {
                        let sname = property_setter_name(pname);
                        if !methods.contains_key(&sname) {
                            let this_e = lo.emit_get_value(0);
                            let v = lo.emit_get_value(1);
                            let sf = lo.emit_set_field(this_e, id, fidx as u32, v);
                            let body = lo.emit_block(vec![sf], None);
                            let mi = method_fids.len() as u32;
                            // kotlinc guards a non-null reference setter parameter with
                            // `Intrinsics.checkNotNullParameter(value, "<set-?>")` at entry (the special
                            // synthetic name kotlinc uses for a setter's value). Primitives, nullable
                            // properties, and bare type-parameter fields skip it.
                            let param_checks = if fty.is_reference()
                                && !fty_ir.is_nullable()
                                && !field_tp.contains_key(pname)
                            {
                                vec![Some("<set-?>".to_string())]
                            } else {
                                vec![None]
                            };
                            let fid = lo.ir.add_fun(IrFunction {
                                name: sname.clone(),
                                params: vec![fty_ir.clone()],
                                ret: Ty::Unit,
                                body: Some(body),
                                is_static: false,
                                dispatch_receiver: Some(type_name(&internal)),
                                param_checks,
                            });
                            // `var x = …; private set` — the setter is emitted `private`.
                            if c.body_props.iter().any(|p| {
                                &p.name == pname && p.setter.as_ref().is_some_and(|s| s.is_private)
                            }) {
                                lo.ir.private_methods.insert(fid);
                            }
                            if let Some(tp) = field_tp.get(pname) {
                                lo.ir.signatures.insert(
                                    fid,
                                    crate::ir::IrGenericSig {
                                        type_params: vec![],
                                        param_tparams: vec![Some(tp.clone())],
                                        ret_tparam: None,
                                        supers: Vec::new(),
                                    },
                                );
                            }
                            methods.entry(sname).or_default().push((mi, fid, Ty::Unit));
                            method_fids.push(fid);
                        }
                    }
                }
            }
            lo.ir.classes[id as usize].methods = method_fids;
            let _ = class_ty;
            lo.insert_class_info(
                &internal,
                ClassInfo {
                    id,
                    internal: type_name(&internal),
                    fields,
                    methods,
                    super_internal,
                },
            );
            // A `companion object`'s `val`s become static fields on the OUTER class (kotlinc's layout),
            // read as `getstatic C.X` — a `const val` as a `public static final` + `ConstantValue`, a
            // non-const `val` initialized in the outer class's `<clinit>` (see `emit_class`).
            for cp in &c.companion_props {
                let cty = body_prop_ty(file, info, cp, &*syms.libraries);
                lo.cur_class = None;
                lo.scope.clear();
                lo.boxed_elem.clear();
                lo.next_value = 0;
                // `companion_props_lowerable` admitted this companion, so its initializer MUST lower —
                // if it doesn't (or its type is `Error`), bail the whole file rather than silently drop
                // the static field (which would leave a dangling `C.X` read → NoSuchFieldError).
                let initx = cp.init?;
                if cty == Ty::Error {
                    return None;
                }
                let init = lo.lower_arg(initx, &ty_to_ir(cty))?;
                // A `const val` becomes a `ConstantValue` static; a plain non-const companion `val`
                // becomes a static field initialized in the outer class's `<clinit>`. Both are read as
                // `getstatic C.X` (registered in `companion_consts`).
                lo.ir.statics.push(crate::ir::IrStatic {
                    visibility: cp.visibility,
                    name: cp.name.clone(),
                    ty: ty_to_ir(cty),
                    init,
                    is_var: false,
                    is_const: cp.is_const,
                    owner: Some(type_name(&internal)),
                    custom_accessor: false,
                });
                lo.companion_consts
                    .insert((type_name(&internal), cp.name.clone()), cty);
            }
            // An `object`'s own `const val`s become `public static final` + `ConstantValue` fields on the
            // object class (kotlinc's layout) — reads inline the literal (`object_const_lits`), exactly as
            // kotlinc inlines a const, so the field is present for binary compatibility but never fetched.
            if c.is_object() {
                for bp in c.body_props.iter().filter(|p| p.is_const) {
                    let cty = body_prop_ty(file, info, bp, &*syms.libraries);
                    lo.cur_class = None;
                    lo.scope.clear();
                    lo.boxed_elem.clear();
                    lo.next_value = 0;
                    if let (Some(initx), false) = (bp.init, cty == Ty::Error) {
                        if let Some(init) = lo.lower_arg(initx, &ty_to_ir(cty)) {
                            lo.ir.statics.push(crate::ir::IrStatic {
                                visibility: bp.visibility,
                                name: bp.name.clone(),
                                ty: ty_to_ir(cty),
                                init,
                                is_var: false,
                                is_const: true,
                                owner: Some(type_name(&internal)),
                                custom_accessor: false,
                            });
                        }
                    }
                }
            }
            // `companion object` with methods → a synthesized `C$Companion` class (private ctor, the
            // companion methods as instance methods) + a `Companion` field on the outer class. Also
            // synthesized for a method-LESS companion that declares a supertype (`companion object :
            // EmptyContinuation()`) — it must still be emitted (extending its base/interfaces) so the
            // companion is usable as a value of that type — and for a PROPS-ONLY companion (`companion
            // object { const val X = … }`): the consts hoist to the outer class, but kotlinc still
            // emits the (member-less) `C$Companion` class + `Companion` field.
            if !c.companion_methods.is_empty()
                || c.companion_base.is_some()
                || !c.companion_supertypes.is_empty()
                || !c.companion_props.is_empty()
            {
                let comp_fq = format!("{internal}$Companion");
                // The companion's declared supertypes (`companion object : Base, I`): make the synthesized
                // companion implement its declared INTERFACES so it is genuinely an `I` at runtime. The
                // base CLASS is left as `kotlin/Any` (as before this change ignored the whole list) — a real
                // `super(args)` call isn't built in this registration pass; a companion that NEEDS its base
                // type (e.g. the coroutine `EmptyContinuation`) simply isn't usable as that type yet.
                // Only FILE interfaces are added, and only when no method needs a BRIDGE: the synthesized
                // companion isn't run through interface-bridge generation, so a companion method overriding
                // an interface method with a DIFFERENT erased descriptor (generic/covariant) would
                // `AbstractMethodError`. Verify each overriding method matches exactly; otherwise (or for a
                // classpath interface, whose methods aren't checked here) skip the file — never miscompile.
                let mut comp_ifaces = Vec::new();
                let csig0 = syms.classes.get(&c.name)?;
                for st in &c.companion_supertypes {
                    let is_file_iface = file.decls.iter().any(|&d| matches!(file.decl(d), Decl::Class(ic) if ic.name == *st && ic.is_interface()));
                    if !is_file_iface {
                        return None;
                    }
                    let iface_internal = class_internal(file, st);
                    if let Some(isig) = syms.class_by_internal(&iface_internal) {
                        for (mname, cm) in &csig0.static_methods {
                            if let Some(im) = isig.method(mname) {
                                let im_params: Option<Vec<_>> = im
                                    .params
                                    .iter()
                                    .map(|t| lo.runtime.type_descriptor(*t))
                                    .collect();
                                let cm_params: Option<Vec<_>> = cm
                                    .params
                                    .iter()
                                    .map(|t| lo.runtime.type_descriptor(*t))
                                    .collect();
                                if im.params.len() != cm.params.len()
                                    || im_params? != cm_params?
                                    || lo.runtime.type_descriptor(im.ret)?
                                        != lo.runtime.type_descriptor(cm.ret)?
                                {
                                    return None; // would need a bridge — skip, never miscompile
                                }
                            }
                        }
                    }
                    comp_ifaces.push(iface_internal);
                }
                // A companion with a declared base CLASS (`companion object : Base()`): make the synthesized
                // companion extend it (so the companion — used as a value — is an instance of `Base`, e.g.
                // the coroutine `EmptyContinuation`). Only a FILE base with NO explicit base args is modeled:
                // a no-arg base → `super()`; an all-defaulted base → fill the base's default exprs into
                // `super(…)` (mirrors the regular-class super-default-fill). The plan is computed as owned
                // data first so the `syms` borrow is dropped before lowering. Any other shape → keep `Any`.
                let comp_base_plan: Option<(String, Vec<CtorDefaultValue>)> = match &c
                    .companion_base
                {
                    Some(base) if c.companion_base_args.is_empty() => {
                        let is_file_class = file.decls.iter().any(|&d| matches!(file.decl(d), Decl::Class(bc) if bc.name == *base && !bc.is_interface()));
                        if !is_file_class {
                            return None;
                        }
                        let base_internal = class_internal(file, base);
                        let bsig = syms.class_by_internal(&base_internal)?;
                        let n = bsig.ctor_params.len();
                        if n == 0 {
                            Some((base_internal, Vec::new()))
                        } else if bsig.ctor_defaults.len() >= n
                            && bsig.ctor_defaults[..n].iter().all(|d| d.is_some())
                        {
                            let plan: Vec<CtorDefaultValue> = bsig.ctor_defaults[..n]
                                .iter()
                                .map(|d| d.clone().expect("checked all Some"))
                                .collect();
                            Some((base_internal, plan))
                        } else {
                            return None; // a required base param without a default — can't fill
                        }
                    }
                    Some(_) => return None, // explicit base args on a companion — not modeled
                    None => None,
                };
                let (comp_super, comp_super_args) =
                    if let Some((base_internal, plan)) = comp_base_plan {
                        // The defaults are file-independent (`CtorDefaultValue`), so a companion extending a
                        // base in this file fills them with no cross-file `ExprId` deref.
                        let sargs = plan
                            .iter()
                            .map(|dv| ctor_default_to_ir(&mut lo.ir, lo.runtime, dv))
                            .collect::<Option<Vec<_>>>()?;
                        (base_internal, sargs)
                    } else {
                        ("kotlin/Any".to_string(), Vec::new())
                    };
                let comp_id = lo.ir.add_class(IrClass {
                    fq_name: type_name(&comp_fq),
                    is_value: false,
                    is_data: false,
                    decl_line: 0,
                    type_param_bounds: vec![],
                    type_params: Vec::new(),
                    supertypes: vec![],
                    fields: vec![],
                    ctor_param_count: 0,
                    ctor_args: vec![],
                    init_body: None,
                    explicit_param_stores: false,
                    methods: vec![],
                    is_interface: false,
                    is_annotation: false,
                    annotation_impl_of: None,

                    is_sealed: false,
                    is_abstract: false,
                    is_open: false,
                    superclass: type_name(&comp_super),
                    super_args: comp_super_args,
                    enum_entries: vec![],
                    enum_entry_of: None,
                    prop_ref: None,
                    func_ref: None,
                    bridges: vec![],
                    interfaces: comp_ifaces.clone().into(),
                    is_object: false,
                    is_companion: true,
                    companion_class: None,
                    secondary_ctors: vec![],
                    has_primary_ctor: true,
                    applied_annotations: Vec::new(),
                    field_annotations: Vec::new(),
                    runtime_retained: false,
                });
                let csig = syms.classes.get(&c.name)?;
                let mut cmethods: HashMap<String, Vec<(u32, u32, Ty)>> = HashMap::new();
                let mut cmethod_fids = Vec::new();
                for (mi, m) in c.companion_methods.iter().enumerate() {
                    let sig = csig.static_methods.get(&m.name)?;
                    let ret = sig.ret;
                    let params = tys_to_ir(&sig.params);
                    // Companion methods have no enclosing type parameters in a param position.
                    let param_checks =
                        param_checks_for(m, &sig.params, &[], &std::collections::HashSet::new());
                    let fid = lo.ir.add_fun(IrFunction {
                        name: m.name.clone(),
                        params,
                        ret: ty_to_ir(ret),
                        body: None,
                        is_static: false,
                        dispatch_receiver: Some(type_name(&comp_fq)),
                        param_checks,
                    });
                    cmethods
                        .entry(m.name.clone())
                        .or_default()
                        .push((mi as u32, fid, ret));
                    cmethod_fids.push(fid);
                }
                lo.ir.classes[comp_id as usize].methods = cmethod_fids;
                lo.ir.classes[id as usize].companion_class = Some(type_name(&comp_fq));
                lo.insert_class_info(
                    &comp_fq,
                    ClassInfo {
                        id: comp_id,
                        internal: type_name(&comp_fq),
                        fields: vec![],
                        methods: cmethods,
                        super_internal: None,
                    },
                );
                lo.companions
                    .insert(type_name(&internal), type_name(&comp_fq));
            }
            // A `data class`'s equals/hashCode/toString/componentN are Kotlin language semantics —
            // synthesize them here as ordinary IR methods (backend-agnostic), registered so calls
            // resolve and the generic method emitter handles them.
            if c.is_data {
                // An inner `data class`'s synthetic `this$0` sits at field 0, which `synth_data_members`
                // (componentN/copy/equals/hashCode over `fields[..n]`) would treat as the first data
                // property — skip rather than miscompile.
                if c.inner_of.is_some() {
                    return None;
                }
                lo.synth_data_members(&internal, id, ctor_param_count as usize, c.is_object())?;
            }
            // A `@JvmInline value class` is emitted as a plain single-field class here (field, `<init>`,
            // getter); the JVM `value_classes` pass synthesizes its unboxed-support members
            // (`box-impl`/`unbox-impl`/`constructor-impl`/`equals-impl0`/`equals`/`hashCode`/`toString`).
            // Interface delegation `: I by d` is sugar — synthesize a forwarder for each of `I`'s
            // methods that calls `this.d.method(args)`. Bails the file if a delegate can't be modeled.
            if !c.delegations.is_empty() || !c.delegation_exprs.is_empty() {
                lo.synth_delegation_forwarders(file, c, &internal, id)?;
            }
        }
    }
    // Retry the interface defaults that failed mid-pass (forward class references): every class is
    // registered now. STRUCTURALLY scope-free defaults only — a literal, or a no-/literal-arg
    // construction of a plain (non-value) class (`filters: AuditFilters = AuditFilters()`). Anything
    // else — an implicit-`this` member call (`x: T = defaultX()`), a value-class construction (whose
    // stub-side boxing isn't modeled here) — keeps the marker dropped (omitted-arg calls skip the
    // file, never miscompile).
    for (fid, params, names) in std::mem::take(&mut pending_iface_defaults) {
        let scope_free = |lo: &Lower, d: crate::ast::ExprId| -> bool {
            if is_const_literal(file, d) {
                return true;
            }
            match file.expr(d) {
                Expr::Call { callee, args } => {
                    let Expr::Name(n) = file.expr(*callee) else {
                        return false;
                    };
                    let internal = class_internal(file, n);
                    let Some(ci) = lo.class_info(&internal) else {
                        return false;
                    };
                    let is_value = lo
                        .ir
                        .classes
                        .get(ci.id as usize)
                        .is_some_and(|c| c.is_value);
                    !is_value && args.iter().all(|&a| is_const_literal(file, a))
                }
                _ => false,
            }
        };
        if !params
            .iter()
            .all(|(d, _)| d.is_none_or(|d| scope_free(&lo, d)))
        {
            continue;
        }
        lo.scope.clear();
        lo.cur_class = None;
        let mut defaults = Vec::new();
        let mut ok = true;
        for (d, t) in &params {
            match d {
                None => defaults.push(None),
                Some(d) => match lo.lower_arg(*d, &ty_to_ir(*t)) {
                    Some(e) => defaults.push(Some(e)),
                    None => {
                        ok = false;
                        break;
                    }
                },
            }
        }
        if ok {
            lo.ir
                .fn_params
                .insert(fid, FnParamInfo::defaults(names, defaults));
        }
    }

    // Pass 1b: register top-level functions and extension functions. An `inline fun` is not emitted
    // as a standalone method — it is expanded at each call site (pass 2 skips it too).
    for &d in &file.decls {
        if let Decl::Fun(f) = file.decl(d) {
            if f.is_inline {
                continue;
            }
            if let Some(recv_ref) = &f.receiver {
                // Extension function `fun Recv.name(…)` → a static method whose first parameter is the
                // receiver (Kotlin's compilation strategy). Keyed by (erased receiver, name). A
                // receiver that doesn't resolve to a concrete type (a generic `T.foo()`) isn't modeled —
                // bail rather than guess `Object`.
                let recv_ty = lo.ext_receiver_ty(file, recv_ref);
                if recv_ty == Ty::Error {
                    return None;
                }
                let recv_key = recv_ty.erased_recv();
                // Select THIS declaration's overload from the receiver+name set by its parameter list —
                // an extension may be overloaded by arity (`fun R.f()` and `fun R.f(x)`), each emitted as
                // its own static method and keyed by arity so the call site picks the right one.
                let want: Vec<Ty> = f
                    .params
                    .iter()
                    .map(|p| {
                        let t = ty_of(file, &p.ty, &*syms.libraries);
                        if p.is_vararg {
                            Ty::array(t)
                        } else {
                            t
                        }
                    })
                    .collect();
                let sig = syms
                    .ext_fun_overloads(recv_ty, &f.name)
                    .iter()
                    .find(|s| s.params == want)
                    .or_else(|| syms.ext_fun_overloads(recv_ty, &f.name).first())?;
                let arity = sig.params.len();
                let recv_param = if recv_ref.nullable {
                    mark_nullable(ty_to_ir(recv_ty))
                } else {
                    ty_to_ir(recv_ty)
                };
                let mut params = vec![recv_param];
                params.extend(sig.params.iter().map(|t| stored_value_ty(*t)));
                let ret = ty_to_ir(sig.ret);
                let id = lo.ir.add_fun(IrFunction {
                    name: f.name.clone(),
                    params,
                    ret,
                    body: None,
                    is_static: true,
                    dispatch_receiver: None,
                    param_checks: vec![],
                });
                lo.ext_fun_id_by_arity
                    .insert((recv_key, f.name.clone(), arity), id);
                lo.ext_fun_id_by_sig
                    .insert((recv_key, f.name.clone(), sig.params.clone()), id);
                lo.ext_fun_ids
                    .entry((recv_key, f.name.clone()))
                    .or_insert(id);
                // A `private` top-level extension is `private static` on the facade (kotlinc); a
                // class-body caller goes through the `access$<name>` bridge (see `emit_pass`).
                if f.visibility.is_private() {
                    lo.ir.private_methods.insert(id);
                }
            } else {
                let sig = syms.funs.get(&f.name)?.iter().find(|sig| {
                    sig.source_file == Some(lo.file_index) && sig.source_decl == Some(d)
                })?;
                let params: Vec<Ty> = sig
                    .params
                    .iter()
                    .enumerate()
                    .map(|(i, t)| {
                        let ir = stored_value_ty(*t);
                        if f.params.get(i).is_some_and(|p| p.ty.nullable) {
                            mark_nullable(ir)
                        } else {
                            ir
                        }
                    })
                    .collect();
                let ret = ty_to_ir(sig.ret);
                let ret = if f.ret.as_ref().is_some_and(|r| r.nullable) {
                    mark_nullable(ret)
                } else {
                    ret
                };
                // A top-level function has no enclosing class type parameters.
                let param_checks =
                    param_checks_for(f, &sig.params, &[], &std::collections::HashSet::new());
                let id = lo.ir.add_fun(IrFunction {
                    name: f.name.clone(),
                    params,
                    ret,
                    body: None,
                    is_static: true,
                    dispatch_receiver: None,
                    param_checks,
                });
                lo.fun_ids.insert((f.name.clone(), sig.params.clone()), id);
                lo.fun_ids_by_decl.insert(d, id);
                // A `private` top-level function is `private static` on the facade (kotlinc); a
                // class-body caller goes through the `access$<name>` bridge (see `emit_pass`).
                if f.visibility.is_private() {
                    lo.ir.private_methods.insert(id);
                }
                // Emit a JVM generic `Signature` for a type-parameterized function (kotlinc does), so the
                // bytecode matches for generics. `None` for non-generic / not-yet-modeled shapes.
                if let Some(s) = fn_generic_sig(file, f, &*lo.syms.libraries) {
                    lo.ir.signatures.insert(id, s);
                }
                // Tag a `suspend fun` for the coroutine pass (`jvm::suspend`), which owns the whole
                // transform (CPS signature now; state machine later) — ir_lower keeps the plain form,
                // mirroring how value classes are lowered plain here and transformed in a later pass.
                if f.is_suspend {
                    lo.ir.suspend_funs.push(id);
                }
            }
        }
    }
    // Pass 1b': register lifted local functions (`fun` inside a function body) as private static
    // methods on the facade. Captured outer locals become leading parameters; calls route to the
    // resulting `FunId` in pass 2.
    for (i, s) in file.stmt_arena.iter().enumerate() {
        if let Stmt::LocalFun(_) = s {
            let stmt_id = crate::ast::StmtId(i as u32);
            if let Some(local_fun) = info.local_fun(stmt_id) {
                // Captured outer locals become extra leading parameters: runtime holder first when the
                // capture needs a shared mutable cell, otherwise the captured value.
                let mut params: Vec<Ty> = Vec::new();
                for cap in &local_fun.captures {
                    params.push(captured_param_ir(lo.runtime, cap.ty, cap.shared_cell)?);
                }
                params.extend(local_fun.sig.params.iter().map(|t| stored_value_ty(*t)));
                let ret = ty_to_ir(local_fun.sig.ret);
                let id = lo.ir.add_fun(IrFunction {
                    name: local_fun.mangled.clone(),
                    params,
                    ret,
                    body: None,
                    is_static: true,
                    dispatch_receiver: None,
                    param_checks: vec![],
                });
                lo.local_fun_ids.insert(stmt_id, id);
            }
        }
    }
    // Pass 1c: assign top-level-property indices (initializers lowered in pass 2). Registered before
    // any body so a function may read a top-level property as `GetStatic`.
    // A top-level property's `GetStatic` index must be its position in `ir.statics` (the vec the emitter
    // indexes). Pass 1a already pushed companion/object `const val` backing fields onto that vec, so the
    // per-property counter (`lo.statics.len()`) must be OFFSET by those pre-existing entries — otherwise a
    // top-level property in a file that ALSO has a companion const reads the const's slot (a wrong-field
    // `getstatic`). Only bites files with BOTH, which is why it long went unseen.
    let static_base = lo.ir.statics.len() as u32;
    for &d in &file.decls {
        if let Decl::Property(p) = file.decl(d) {
            // A top-level delegated property (`val x: T by Del()`): register a `getX()` accessor so reads
            // route to it (like a computed property), and RESERVE the two synthetic backing-field static
            // slots (`x$delegate`, `x$kprop`) in declaration order so later non-delegated statics get the
            // matching indices. The field initializers + `getX()` body are built in pass 2.
            if p.delegate.is_some() {
                // An EXTENSION delegated property (`val Recv.x by …`) isn't modeled — skip the file
                // (pass 2 would otherwise treat it as an extension property and find no getter).
                if p.receiver.is_some() {
                    return None;
                }
                let ty = if let Some(tref) = p.ty.as_ref() {
                    ty_of(file, tref, &*syms.libraries)
                } else {
                    let delegate_ty = info.ty(p.delegate?);
                    let internal = delegate_ty.obj_internal()?;
                    lo.delegate_getvalue_info(p.delegate?, internal)?.2
                };
                let fid = lo.ir.add_fun(IrFunction {
                    name: property_getter_name(&p.name),
                    params: vec![],
                    ret: ty_to_ir(ty),
                    body: None,
                    is_static: true,
                    dispatch_receiver: None,
                    param_checks: vec![],
                });
                lo.computed_props.insert(p.name.clone(), (fid, ty));
                let d_ty = p.delegate.map(|de| info.ty(de)).unwrap_or(Ty::Error);
                let d_idx = static_base + lo.statics.len() as u32;
                lo.statics
                    .insert(format!("{}$delegate", p.name), (d_idx, d_ty));
                let k_idx = static_base + lo.statics.len() as u32;
                lo.statics.insert(
                    format!("{}$kprop", p.name),
                    (k_idx, Ty::obj("kotlin/reflect/KProperty")),
                );
                continue;
            }
            // An extension property (`val/var Recv.name: T get() = … [set(v) = …]`) → a static
            // `getName(Recv): T` (and, for a `var`, `setName(Recv, T)`), exactly like an extension
            // function's lowering. No backing field; only a `get()`-bodied property is modeled. A `var`
            // needs an explicit `set(v) { … }` body (no backing field to default to).
            if let Some(recv_ref) = &p.receiver {
                if p.getter.is_none() || p.delegate.is_some() {
                    return None;
                }
                let has_set_body = p
                    .setter
                    .as_ref()
                    .is_some_and(|s| s.body.is_some() && s.param.is_some());
                if p.is_var && !has_set_body {
                    return None;
                }
                let recv_ty = ty_of(file, recv_ref, &*syms.libraries);
                let recv_key = recv_ty.erased_recv();
                let pty_ir = body_prop_ir_ty(file, info, p, &*syms.libraries);
                let gfid = lo.ir.add_fun(IrFunction {
                    name: property_getter_name(&p.name),
                    params: vec![ty_to_ir(recv_ty)],
                    ret: pty_ir,
                    body: None,
                    is_static: true,
                    dispatch_receiver: None,
                    param_checks: vec![],
                });
                lo.ext_prop_get_ids.insert((recv_key, p.name.clone()), gfid);
                if p.is_var {
                    let sfid = lo.ir.add_fun(IrFunction {
                        name: property_setter_name(&p.name),
                        params: vec![ty_to_ir(recv_ty), pty_ir],
                        ret: ty_to_ir(Ty::Unit),
                        body: None,
                        is_static: true,
                        dispatch_receiver: None,
                        param_checks: vec![],
                    });
                    lo.ext_prop_set_ids.insert((recv_key, p.name.clone()), sfid);
                }
                continue;
            }
            let ty = body_prop_ty(file, info, p, &*syms.libraries);
            let ir_ty = body_prop_ir_ty(file, info, p, &*syms.libraries);
            if is_computed_prop(p) {
                // A computed property: a `getX()` accessor (static on the facade), no backing field.
                let fid = lo.ir.add_fun(IrFunction {
                    name: property_getter_name(&p.name),
                    params: vec![],
                    ret: ir_ty,
                    body: None,
                    is_static: true,
                    dispatch_receiver: None,
                    param_checks: vec![],
                });
                lo.computed_props.insert(p.name.clone(), (fid, ty));
            } else {
                let idx = static_base + lo.statics.len() as u32;
                lo.statics.insert(p.name.clone(), (idx, ty));
                // A top-level `const val` with a compile-time literal initializer: record its value so a
                // same-file read inlines it (`ldc`), byte-identical to kotlinc, instead of `getstatic`.
                if p.is_const {
                    if let Some(c) = p.init.and_then(|i| ast_literal_const(file, i, ty)) {
                        lo.const_lits.insert(p.name.clone(), c);
                    }
                }
                // A backing-field property with a CUSTOM accessor (`val x = init get() = field`,
                // `var y = init set(v){…}`): the field above is the backing store; additionally
                // synthesize `getX()` (routing reads through it) and, for a `var`, `setX(value)`. Their
                // bodies are lowered in pass 2 with `field` bound to the static (`cur_static_field`).
                if is_field_accessor_prop(p) {
                    let gfid = lo.ir.add_fun(IrFunction {
                        name: property_getter_name(&p.name),
                        params: vec![],
                        ret: ir_ty,
                        body: None,
                        is_static: true,
                        dispatch_receiver: None,
                        param_checks: vec![],
                    });
                    lo.computed_props.insert(p.name.clone(), (gfid, ty));
                    if p.is_var {
                        let sfid = lo.ir.add_fun(IrFunction {
                            name: property_setter_name(&p.name),
                            params: vec![ir_ty],
                            ret: ty_to_ir(Ty::Unit),
                            body: None,
                            is_static: true,
                            dispatch_receiver: None,
                            param_checks: vec![None],
                        });
                        lo.computed_setters.insert(p.name.clone(), sfid);
                    }
                }
            }
        }
    }

    // Pass 2: lower bodies.
    for &d in &file.decls {
        match file.decl(d) {
            Decl::Fun(f) if f.is_inline => {} // inline functions are expanded at call sites, not emitted
            Decl::Fun(f) => {
                lo.set_bail("deep:fun");
                lo.scope.clear();
                lo.boxed_elem.clear();
                lo.next_value = 0;
                lo.cur_class = None;
                lo.cur_fn_name = f.name.clone();
                lo.cur_fn_suspend = f.is_suspend;
                // `as T` erasure is wired for TOP-LEVEL function type parameters only (the dominant
                // bucket). A class/method/inline type-parameter cast finds no match here and falls
                // through to `ty_ref`, which returns `None` for a bare `T` → the file safely bails
                // (never miscompiles) exactly as before.
                lo.cur_tparams = collect_tparams(
                    file,
                    &f.type_params,
                    &f.type_param_bounds,
                    &f.non_null_type_params,
                    &*syms.libraries,
                );
                lo.lambda_seq = 0;
                let (fid, sig) = if let Some(recv_ref) = &f.receiver {
                    // Extension body: `this` is the receiver (parameter 0), then the declared params.
                    // Pick THIS declaration's overload (by parameter list) and its arity-keyed method id.
                    let recv_ty = lo.ext_receiver_ty(file, recv_ref);
                    let recv_key = recv_ty.erased_recv();
                    let want: Vec<Ty> = f
                        .params
                        .iter()
                        .map(|p| {
                            let t = ty_of(file, &p.ty, &*syms.libraries);
                            if p.is_vararg {
                                Ty::array(t)
                            } else {
                                t
                            }
                        })
                        .collect();
                    let sig = syms
                        .ext_fun_overloads(recv_ty, &f.name)
                        .iter()
                        .find(|s| s.params == want)?;
                    let fid = *lo.ext_fun_id_by_arity.get(&(
                        recv_key,
                        f.name.clone(),
                        sig.params.len(),
                    ))?;
                    let this_v = lo.fresh_value();
                    lo.scope.push(("this".to_string(), this_v, recv_ty));
                    (fid, sig)
                } else {
                    let sig = syms.funs.get(&f.name)?.iter().find(|sig| {
                        sig.source_file == Some(lo.file_index) && sig.source_decl == Some(d)
                    })?;
                    let fid = *lo.fun_ids_by_decl.get(&d)?;
                    (fid, sig)
                };
                let mut param_vals = Vec::new();
                for (p, t) in f.params.iter().zip(&sig.params) {
                    let v = lo.fresh_value();
                    param_vals.push(v);
                    lo.scope.push((p.name.clone(), v, *t));
                }
                // Register parameter defaults for a top-level function OR EXTENSION (the latter's IR
                // function prepends the receiver as parameter 0, so the defaults/names get a leading
                // receiver slot). Plain top-level functions may also emit a facade `$default` stub; the
                // JVM backend uses one mask word per 32 parameters, so there is no 31-param cap here.
                // An EXTENSION fills its omitted defaults at the CALL SITE by REUSING these lowered default
                // exprs, so restrict it to CONSTANT defaults (a literal carries no function-local value
                // dependency); a non-constant extension default isn't modeled — skip registration so an
                // omitted-arg call bails (the file skips, never miscompiles). A plain top-level function
                // re-lowers its defaults from the AST at the call site, so it accepts any constant-literal.
                let const_ok = f.receiver.is_none()
                    || f.params.iter().all(|p| match p.default {
                        Some(d) => is_const_literal(file, d),
                        None => true,
                    });
                // A trailing `vararg` is allowed for a TOP-LEVEL function (no receiver): the vararg
                // parameter carries no default (`$default` passes its array through), so its omitted-arg
                // call routes through the stub with an empty array for the vararg slot. An extension's
                // receiver-offset vararg is left out (a later slice).
                let vararg_ok = !f.params.iter().any(|p| p.is_vararg)
                    || (f.receiver.is_none() && f.params.last().is_some_and(|p| p.is_vararg));
                if const_ok && f.params.iter().any(|p| p.default.is_some()) && vararg_ok {
                    let ir_params = lo.ir.functions[fid as usize].params.clone();
                    let recv_off = usize::from(f.receiver.is_some());
                    let mut defaults: Vec<Option<u32>> = vec![None; recv_off];
                    for (i, p) in f.params.iter().enumerate() {
                        match p.default {
                            Some(d) => {
                                defaults.push(Some(lo.lower_arg(d, &ir_params[recv_off + i])?))
                            }
                            None => defaults.push(None),
                        }
                    }
                    let mut names = vec!["$receiver".to_string(); recv_off];
                    names.extend(f.params.iter().map(|p| p.name.clone()));
                    lo.ir
                        .fn_params
                        .insert(fid, FnParamInfo::defaults(names, defaults));
                }
                // Names-only metadata supports named-argument reorder without a default stub.
                if !lo.ir.fn_params.contains_key(&fid) && !f.params.iter().any(|p| p.is_vararg) {
                    let recv_off = usize::from(f.receiver.is_some());
                    let mut names = vec!["$receiver".to_string(); recv_off];
                    names.extend(f.params.iter().map(|p| p.name.clone()));
                    lo.ir.fn_params.insert(fid, FnParamInfo::names(names));
                }
                let ret_ty = lo.ir.functions[fid as usize].ret.clone();
                // A top-level `tailrec fun` (no extension receiver): rewrite its tail self-calls into a
                // `while(true)` loop (param reassignment + `continue`) so deep recursion doesn't overflow.
                // An EXTENSION/infix `tailrec` (receiver) isn't transformed here — skip the file rather
                // than emit stack-overflowing recursion.
                if f.is_tailrec {
                    if f.receiver.is_some() {
                        return None;
                    }
                    lo.lower_tailrec_body(f, &ret_ty, fid, param_vals, sig.params.clone())?;
                } else {
                    lo.lower_body(&f.body, &ret_ty, fid)?;
                }
            }
            Decl::Class(c) => {
                lo.set_bail("deep:class");
                let internal = class_internal(file, &c.name);
                // A method that overrides a base method with a *different erased signature* (a
                // generic/covariant override) needs a synthetic JVM bridge that krusty doesn't emit
                // yet — bail rather than miscompile (the erased call wouldn't reach the override).
                if let Some(super_int) = lo.class_info(&internal)?.super_internal {
                    for (mi, m) in c.methods.iter().enumerate() {
                        if let Some((_, _, base_fid, _)) =
                            lo.resolve_method_name(super_int, &m.name)
                        {
                            // A param/return typed by a class type-param that carries a *class* upper
                            // bound (`class D<T : Foo> : Base<T>() { override fun bar(x: T) }`): kotlinc
                            // erases the override to the bound (`bar(Foo)`) and synthesizes a `bar(Object)`
                            // bridge that `checkcast`s to `Foo` — that cast is observable (it throws CCE on
                            // an out-of-bound arg passed through the erased supertype). krusty erases the
                            // type-param to `Object` instead, so it would emit neither the bound descriptor
                            // nor the casting bridge — a miscompile. Skip until bound-aware erasure exists.
                            let bound_tp = |r: &crate::ast::TypeRef| {
                                r.fun_params.is_empty()
                                    && c.type_param_bounds.iter().any(|(n, _)| *n == r.name)
                            };
                            if m.params.iter().any(|p| bound_tp(&p.ty))
                                || m.ret.as_ref().is_some_and(bound_tp)
                            {
                                return None;
                            }
                            let own_idx =
                                c.methods[..mi].iter().filter(|x| x.name == m.name).count();
                            let own_fid =
                                lo.class_info(&internal)?.methods[&m.name].get(own_idx)?.1;
                            let bp = lo.ir.functions[base_fid as usize].params.clone();
                            let br = lo.ir.functions[base_fid as usize].ret.clone();
                            let op = lo.ir.functions[own_fid as usize].params.clone();
                            let or = lo.ir.functions[own_fid as usize].ret.clone();
                            // A different ARITY means this is a sibling OVERLOAD of the base
                            // method, not an override — nothing to bridge.
                            if bp.len() != op.len() {
                                continue;
                            }
                            if bp != op || br != or {
                                // A suspend override needing an erasure bridge can't be modeled (the
                                // coroutine pass rewrites the concrete method to CPS afterwards but never
                                // fixes up the bridge) — skip the file rather than emit a broken bridge.
                                if m.is_suspend {
                                    return None;
                                }
                                // Generic/covariant override → synthesize an `ACC_BRIDGE` method with
                                // the supertype's erased descriptor that delegates to the concrete one.
                                let cid = lo.class_info(&internal)?.id;
                                lo.ir.classes[cid as usize].bridges.push(crate::ir::Bridge {
                                    name: m.name.clone(),
                                    erased_params: bp,
                                    erased_ret: br,
                                    concrete_params: op,
                                    concrete_ret: or,
                                    target_name: None,
                                    box_ret: None,
                                    unbox_params: Vec::new(),
                                });
                            }
                        }
                    }
                    // A property redeclared in the subclass (`override val field`) overrides the base's
                    // `getX()`, so external access dispatches virtually to the subclass field — correct.
                    // But a *base-class member that reads the property internally* reads the field
                    // directly (not via `getX`), bypassing the override. Bail only then.
                    let own_fields: Vec<&String> = c
                        .props
                        .iter()
                        .filter(|p| p.is_property)
                        .map(|p| &p.name)
                        .chain(c.body_props.iter().map(|p| &p.name))
                        .collect();
                    let base_name = c.base_class.clone();
                    let base_decl = base_name.as_ref().and_then(|bn| {
                        file.decls.iter().find_map(|&d| match file.decl(d) {
                            Decl::Class(bc) if bc.name == *bn => Some(bc),
                            _ => None,
                        })
                    });
                    for fname in own_fields {
                        if lo.resolve_field_name(super_int, fname).is_some() {
                            // A base with its own base, or a base member reading `fname`, risks the
                            // internal-read bypass — bail conservatively; else the override is safe.
                            let unsafe_base = base_decl.map_or(true, |bd| {
                                bd.base_class.is_some()
                                    || bd.methods.iter().any(|m| match &m.body {
                                        FunBody::Expr(e) | FunBody::Block(e) => {
                                            file.expr_uses_name(*e, fname)
                                        }
                                        FunBody::None => false,
                                    })
                                    || bd.body_props.iter().any(|p| {
                                        p.init.map_or(false, |e| file.expr_uses_name(e, fname))
                                    })
                            });
                            if unsafe_base {
                                return None;
                            }
                        }
                    }
                }
                // Property getter bridges: a property overriding a supertype property with a different
                // erased type (a covariant override `from: Sub` over `from: Super`, or a generic
                // `val x: T` erased to `Object` overridden with a concrete type) needs a synthetic
                // `getX()` returning the supertype's (erased) type that delegates to the concrete getter —
                // else a call through the supertype reference resolves to the missing erased getter.
                if !c.is_interface() {
                    let cid = lo.class_info(&internal)?.id;
                    let internal_name = existing_type_name(&internal)?;
                    for sup in lo.syms.supertype_internal_names_from(internal_name) {
                        let Some(sc) = lo.syms.class_by_type_name(sup) else {
                            continue;
                        };
                        for (pname, sty, base_is_var) in sc.props.clone() {
                            if let Some((own_ty, own_is_var)) =
                                lo.syms.prop_of_name(internal_name, &pname)
                            {
                                let sty_desc = lo.runtime.type_descriptor(sty)?;
                                let own_desc = lo.runtime.type_descriptor(own_ty)?;
                                if sty_desc != own_desc {
                                    let gname = property_getter_name(&pname);
                                    let super_ret = lo
                                        .class_info_name(sup)
                                        .and_then(|ci| ci.methods.get(&gname))
                                        .and_then(|v| v.first())
                                        .map(|(_, fid, _)| lo.ir.functions[*fid as usize].ret)
                                        .unwrap_or_else(|| ty_to_ir(sty));
                                    let own_ret = lo
                                        .class_info_name(internal_name)
                                        .and_then(|ci| ci.methods.get(&gname))
                                        .and_then(|v| v.first())
                                        .map(|(_, fid, _)| lo.ir.functions[*fid as usize].ret)
                                        .unwrap_or_else(|| ty_to_ir(own_ty));
                                    let already = lo.ir.classes[cid as usize]
                                        .bridges
                                        .iter()
                                        .any(|b| b.name == gname && b.erased_params.is_empty());
                                    if !already {
                                        lo.ir.classes[cid as usize].bridges.push(
                                            crate::ir::Bridge {
                                                name: gname,
                                                erased_params: vec![],
                                                erased_ret: super_ret,
                                                concrete_params: vec![],
                                                concrete_ret: own_ret,
                                                target_name: None,
                                                box_ret: None,
                                                unbox_params: Vec::new(),
                                            },
                                        );
                                    }
                                    // A `var` override also needs a `setX(erased)` bridge delegating to
                                    // the concrete `setX(own)` — else a write through the supertype
                                    // reference resolves to the missing erased setter (silent no-op).
                                    if base_is_var && own_is_var {
                                        let sname = property_setter_name(&pname);
                                        let has_setter = lo.ir.classes[cid as usize]
                                            .bridges
                                            .iter()
                                            .any(|b| b.name == sname && b.erased_params.len() == 1);
                                        if !has_setter {
                                            lo.ir.classes[cid as usize].bridges.push(
                                                crate::ir::Bridge {
                                                    name: sname,
                                                    erased_params: vec![ty_to_ir(sty)],
                                                    erased_ret: ty_to_ir(Ty::Unit),
                                                    concrete_params: vec![ty_to_ir(own_ty)],
                                                    concrete_ret: ty_to_ir(Ty::Unit),
                                                    target_name: None,
                                                    box_ret: None,
                                                    unbox_params: Vec::new(),
                                                },
                                            );
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                // Collection special-member stubs: a class implementing a mapped `kotlin.collections`
                // interface must provide the `java.util` method the interface declares for a Kotlin PROPERTY
                // (`Map.size` → `size()`, `keys` → `keySet()`). kotlinc emits it as a synthetic bridge
                // forwarding to the Kotlin getter (`getSize`/`getKeys`); without it the `java.util` abstract
                // stays unimplemented and a call through the interface throws `AbstractMethodError`. The
                // interface members are on the classpath (empty `props`), so scan the class's OWN overrides.
                let internal_name = existing_type_name(&internal)?;
                if !c.is_interface()
                    && lo
                        .syms
                        .supertype_internal_names_from(internal_name)
                        .iter()
                        .any(|&s| lo.syms.libraries.is_collection_interface_name(s))
                {
                    let cid = lo.class_info(&internal)?.id;
                    for p in &c.body_props {
                        let Some(stub) = lo.syms.libraries.collection_property_accessor(&p.name)
                        else {
                            continue;
                        };
                        let stub = stub.as_str();
                        let Some((own_ty, _)) = lo.syms.prop_of_name(internal_name, &p.name) else {
                            continue;
                        };
                        let already = lo.ir.classes[cid as usize]
                            .bridges
                            .iter()
                            .any(|b| b.name == stub && b.erased_params.is_empty());
                        if already {
                            continue;
                        }
                        // The `java.util` stub and the Kotlin getter share the (erased) return, so the
                        // bridge is a plain forward: `stub()` → `get<Name>()`.
                        let ret = ty_to_ir(own_ty);
                        lo.ir.classes[cid as usize].bridges.push(crate::ir::Bridge {
                            name: stub.to_string(),
                            erased_params: vec![],
                            erased_ret: ret,
                            concrete_params: vec![],
                            concrete_ret: ret,
                            target_name: Some(property_getter_name(&p.name)),
                            box_ret: None,
                            unbox_params: Vec::new(),
                        });
                    }
                }
                // Interface bridges: for each implemented-interface method, if the class's actual
                // implementation (declared or inherited) has a different erased signature than the
                // interface's, add a bridge with the interface's descriptor delegating to the impl.
                if !c.is_interface() {
                    let cid = lo.class_info(&internal)?.id;
                    let mut ifaces = lo.ir.classes[cid as usize].interfaces.clone();
                    let internal_name = existing_type_name(&internal)?;
                    for sup in lo.syms.supertype_internal_names_from(internal_name) {
                        let is_iface = lo
                            .syms
                            .class_by_type_name(sup)
                            .is_some_and(|c| c.is_interface)
                            || lo
                                .syms
                                .libraries
                                .resolve_type_name(sup)
                                .is_some_and(|t| t.is_interface());
                        if is_iface && !ifaces.contains_name(sup) {
                            ifaces.push_name(sup);
                        }
                    }
                    let mut seen: std::collections::HashSet<String> = lo.ir.classes[cid as usize]
                        .bridges
                        .iter()
                        .map(|b| format!("{}{:?}{:?}", b.name, b.erased_params, b.erased_ret))
                        .collect();
                    for itf in ifaces.iter_ids() {
                        for (mname, ifid) in lo.collect_iface_methods(itf) {
                            if let Some((_, _, impl_fid, _)) = lo.resolve_method(&internal, &mname)
                            {
                                let ip = lo.ir.functions[ifid as usize].params.clone();
                                let ir_ = lo.ir.functions[ifid as usize].ret.clone();
                                let cp = lo.ir.functions[impl_fid as usize].params.clone();
                                let cr = lo.ir.functions[impl_fid as usize].ret.clone();
                                // A bridge is an OVERRIDE adapter — legit in two shapes:
                                //  * GENERIC-IFACE direction: the interface param is the erased
                                //    `Object`, the impl concrete (`A<String>.foo(Object)` bridged
                                //    to `foo(String)`).
                                //  * FAKE-OVERRIDE direction: an ABSTRACT interface member with a
                                //    concrete param satisfied by an INHERITED erased-generic impl
                                //    (`Tr.hello(String)` over `Foo<T>.hello(Object)`, kt1939) —
                                //    kotlinc synthesizes exactly this bridge.
                                // But an interface method WITH A DEFAULT whose concrete param the
                                // impl merely erases (`B.foo(int)` next to `foo(t: T)`) is NOT
                                // overridden by it — the default stays live (KT-78321) — so no
                                // bridge must shadow it.
                                if ip.len() != cp.len() {
                                    continue;
                                }
                                let generic_iface_dir = ip
                                    .iter()
                                    .zip(&cp)
                                    .all(|(&e, &c)| e == c || e.is_erased_top());
                                let fake_override_dir = ip
                                    .iter()
                                    .zip(&cp)
                                    .all(|(&e, &c)| e == c || c.is_erased_top());
                                if !generic_iface_dir
                                    && (!fake_override_dir
                                        || lo.iface_method_is_default_name(itf, &mname))
                                {
                                    continue;
                                }
                                if ip != cp || ir_ != cr {
                                    // A generic-erasure bridge for a SUSPEND override can't be modeled: the
                                    // coroutine pass rewrites the concrete method to CPS (a trailing
                                    // `Continuation`, `Object` return) AFTER this, but never fixes up the
                                    // bridge — so the emitted bridge and its target would both lack the
                                    // continuation. Skip the file rather than emit a broken bridge. (The
                                    // early bail already lets the no-bridge case through; this catches a
                                    // mismatch reached transitively through a raw-looking super-interface.)
                                    if lo.ir.suspend_funs.contains(&impl_fid) {
                                        return None;
                                    }
                                }
                                if (ip != cp || ir_ != cr)
                                    && seen.insert(format!("{}{:?}{:?}", mname, ip, ir_))
                                {
                                    lo.ir.classes[cid as usize].bridges.push(crate::ir::Bridge {
                                        name: mname,
                                        erased_params: ip,
                                        erased_ret: ir_,
                                        concrete_params: cp,
                                        concrete_ret: cr,
                                        target_name: None,
                                        box_ret: None,
                                        unbox_params: Vec::new(),
                                    });
                                }
                            }
                        }
                        // A *classpath* generic interface (`Comparable<Foo>`, `Iterable<E>`, …) isn't in
                        // `self.classes`, so its erased single-abstract-method comes from the library set.
                        // When the class's override has a specialized descriptor (`compareTo(Foo)` vs the
                        // interface's erased `compareTo(Object)`), emit the `ACC_BRIDGE` the JVM needs to
                        // dispatch an interface-typed call — without it `(x as Comparable).compareTo(y)`
                        // hits `AbstractMethodError` instead of running the override (or throwing CCE).
                        let classpath_sam = if lo.contains_class_name(itf) {
                            None
                        } else {
                            lo.syms
                                .libraries
                                .resolve_type_name(itf)
                                .and_then(|t| t.sam_method.clone())
                        };
                        if let Some(m) = classpath_sam {
                            if let Some((_, _, impl_fid, _)) = lo.resolve_method(&internal, &m.name)
                            {
                                let ip = tys_to_ir(&m.params);
                                let ir_ = ty_to_ir(m.ret);
                                let cp = lo.ir.functions[impl_fid as usize].params.clone();
                                let cr = lo.ir.functions[impl_fid as usize].ret.clone();
                                // A suspend override needing an erasure bridge can't be modeled (the
                                // bridge isn't CPS-fixed-up) — skip the file. See the same guard above.
                                if (ip != cp || ir_ != cr) && lo.ir.suspend_funs.contains(&impl_fid)
                                {
                                    return None;
                                }
                                if (ip != cp || ir_ != cr)
                                    && seen.insert(format!("{}{:?}{:?}", m.name, ip, ir_))
                                {
                                    lo.ir.classes[cid as usize].bridges.push(crate::ir::Bridge {
                                        name: m.name.clone(),
                                        erased_params: ip,
                                        erased_ret: ir_,
                                        concrete_params: cp,
                                        concrete_ret: cr,
                                        target_name: None,
                                        box_ret: None,
                                        unbox_params: Vec::new(),
                                    });
                                }
                            }
                        }
                    }
                }
                // An interface's abstract methods have no body; its DEFAULT methods (with a body) are
                // lowered like instance methods (fall through to the normal method-body loop below).
                // An interface with only abstract methods has no bodies to lower here — but a companion
                // (its method bodies lowered on the `C$Companion` class below) still needs processing.
                if c.is_interface()
                    && c.methods.iter().all(|m| matches!(m.body, FunBody::None))
                    && c.methods
                        .iter()
                        .all(|m| !m.params.iter().any(|p| p.default.is_some()))
                    && c.companion_methods.is_empty()
                    && c.companion_props.is_empty()
                {
                    continue;
                }
                for (mi, m) in c.methods.iter().enumerate() {
                    // A `tailrec` MEMBER method isn't loop-transformed (only top-level functions are) —
                    // skip the file rather than emit stack-overflowing recursion.
                    if m.is_tailrec && !matches!(m.body, FunBody::None) {
                        return None;
                    }
                    let overload_idx = c.methods[..mi].iter().filter(|x| x.name == m.name).count();
                    let (_, fid, _) =
                        *lo.class_info(&internal)?.methods[&m.name].get(overload_idx)?;
                    // Remember the declaration line for this method's `LineNumberTable`.
                    if m.decl_line != 0 {
                        lo.ir.fn_decl_lines.insert(fid, m.decl_line);
                    }
                    lo.scope.clear();
                    lo.boxed_elem.clear();
                    lo.next_value = 0;
                    lo.cur_class = Some(type_name(&internal));
                    lo.cur_fn_name = m.name.clone();
                    lo.cur_fn_suspend = m.is_suspend;
                    lo.lambda_seq = 0;
                    // This method's own type params (`fun <R> m()`) plus the class's (`class C<T>`) are
                    // the `as T` cast targets in scope. The method's go FIRST so a same-named method
                    // param shadows the class one (`.find` takes the first match).
                    lo.cur_tparams = collect_tparams(
                        file,
                        &m.type_params,
                        &m.type_param_bounds,
                        &m.non_null_type_params,
                        &*syms.libraries,
                    );
                    for ct in class_tparams(file, c, &*syms.libraries) {
                        if !lo.cur_tparams.iter().any(|(n, _, _)| *n == ct.0) {
                            lo.cur_tparams.push(ct);
                        }
                    }
                    // `this` is value 0.
                    let this_v = lo.fresh_value();
                    lo.scope
                        .push(("this".to_string(), this_v, Ty::obj(&internal)));
                    let overload_idx = c.methods[..mi].iter().filter(|x| x.name == m.name).count();
                    let sig = syms
                        .classes
                        .get(&c.name)?
                        .methods_named(&m.name)
                        .get(overload_idx)?
                        .clone();
                    for (p, t) in m.params.iter().zip(&sig.params) {
                        let v = lo.fresh_value();
                        lo.scope.push((p.name.clone(), v, *t));
                    }
                    // Register parameter defaults (the JVM backend realizes them via the `$default`
                    // stub). Lowered with `this` = value 0 and the params = values 1..=n — the stub's
                    // value layout. `None` for a required parameter.
                    if m.params.iter().any(|p| p.default.is_some()) {
                        let last = m.params.len() - 1;
                        let mut defaults = Vec::new();
                        for (i, (p, t)) in m.params.iter().zip(&sig.params).enumerate() {
                            match p.default {
                                Some(d) => {
                                    let lowered = lo.lower_arg(d, &ty_to_ir(*t));
                                    defaults.push(Some(lowered?));
                                }
                                // A trailing `vararg` is OMITTABLE by an adapted callable reference — its
                                // default is an empty array so the `$default` stub fills `new T[0]`.
                                None if p.is_vararg && i == last => {
                                    let size0 = lo.emit_const(IrConst::Int(0));
                                    defaults.push(Some(lo.emit_new_array(ty_to_ir(*t), size0)));
                                }
                                None => defaults.push(None),
                            }
                        }
                        let names: Vec<String> = m.params.iter().map(|p| p.name.clone()).collect();
                        let info = lo
                            .ir
                            .fn_params
                            .entry(fid)
                            .or_insert_with(|| FnParamInfo::names(names.clone()));
                        info.names = names;
                        info.defaults = Some(defaults);
                    }
                    // An abstract method has no body, but its default-argument expressions have now been
                    // lowered in the same `this`/parameter scope used by the `$default` stub.
                    if matches!(m.body, FunBody::None) {
                        continue;
                    }
                    let ret_ty = lo.ir.functions[fid as usize].ret.clone();
                    lo.lower_body(&m.body, &ret_ty, fid)?;
                }
                // Computed body-property getter bodies → `getX()` methods on the class.
                for p in c.body_props.iter().filter(|p| is_computed_prop(p)) {
                    let gname = property_getter_name(&p.name);
                    let (_, fid, _) = lo.class_info(&internal)?.methods[&gname][0];
                    lo.scope.clear();
                    lo.boxed_elem.clear();
                    lo.next_value = 0;
                    lo.cur_class = Some(type_name(&internal));
                    lo.cur_fn_name = gname;
                    lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                    lo.lambda_seq = 0;
                    let this_v = lo.fresh_value();
                    lo.scope
                        .push(("this".to_string(), this_v, Ty::obj(&internal)));
                    let ret_ty = lo.ir.functions[fid as usize].ret.clone();
                    let body = p.getter.clone().unwrap();
                    lo.lower_body(&body, &ret_ty, fid)?;
                }
                // Field-backed custom accessors (`val x = init get() = field…`): overwrite the default
                // `getX`/`setX` body (built in pass 1) with the lowered custom accessor, binding the
                // `field` keyword to the property's backing field via `cur_field`.
                for p in c.body_props.iter().filter(|p| is_field_accessor_prop(p)) {
                    let class_id = lo.class_info(&internal)?.id;
                    let fidx = lo.ir.classes[class_id as usize]
                        .fields
                        .iter()
                        .position(|f| f.name == p.name)? as u32;
                    let fty_ir = lo.ir.classes[class_id as usize].fields[fidx as usize]
                        .ty
                        .clone();
                    if let Some(getter) = p.getter.clone() {
                        let gname = property_getter_name(&p.name);
                        let (_, fid, _) = lo.class_info(&internal)?.methods[&gname][0];
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_class = Some(type_name(&internal));
                        lo.cur_field = Some((class_id, fidx, fty_ir.clone()));
                        lo.cur_fn_name = gname;
                        lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                        lo.lambda_seq = 0;
                        let this_v = lo.fresh_value();
                        lo.scope
                            .push(("this".to_string(), this_v, Ty::obj(&internal)));
                        let ret_ty = lo.ir.functions[fid as usize].ret.clone();
                        lo.lower_body(&getter, &ret_ty, fid)?;
                        lo.cur_field = None;
                    }
                    if p.is_var {
                        if let Some(setter) =
                            p.setter.as_ref().filter(|s| s.body.is_some()).cloned()
                        {
                            let sname = property_setter_name(&p.name);
                            let (_, fid, _) = lo.class_info(&internal)?.methods[&sname][0];
                            let pty = body_prop_ty(file, info, p, &*syms.libraries);
                            lo.scope.clear();
                            lo.boxed_elem.clear();
                            lo.next_value = 0;
                            lo.cur_class = Some(type_name(&internal));
                            lo.cur_field = Some((class_id, fidx, fty_ir.clone()));
                            lo.cur_fn_name = sname;
                            lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                            lo.lambda_seq = 0;
                            let this_v = lo.fresh_value();
                            lo.scope
                                .push(("this".to_string(), this_v, Ty::obj(&internal)));
                            let v_v = lo.fresh_value();
                            lo.scope.push((
                                ast::setter_param_or_value(setter.param.as_ref()),
                                v_v,
                                pty,
                            ));
                            let sbody = setter.body.clone().unwrap();
                            lo.lower_body(&sbody, &Ty::Unit, fid)?;
                            lo.cur_field = None;
                        }
                    }
                }
                // Delegated body-property accessors → `getX()`/`setX()` calling the delegate's
                // getValue/setValue, with the `KProperty` passed inline as a `PropertyReference1Impl`.
                for p in c.body_props.iter().filter(|p| p.delegate.is_some()) {
                    let class_id = lo.class_info(&internal)?.id;
                    let delegate_ty = lo.info.ty(p.delegate.unwrap());
                    let delegate_internal = delegate_ty.obj_internal()?;
                    let fname = format!("{}$delegate", p.name);
                    let field_idx = lo.ir.classes[class_id as usize]
                        .fields
                        .iter()
                        .position(|f| f.name == fname)
                        .expect("delegate field") as u32;
                    // Build a fresh `PropertyReference1Impl(A::class, "x", "getX()<ret>", 0)`.
                    let gname = property_getter_name(&p.name);
                    let (_, get_fid, prop_ty) = lo.class_info(&internal)?.methods[&gname][0];
                    let prop_sig = lo.property_reference_signature(&gname, prop_ty)?;
                    let propref_impl = lo.property_reference_impl(1, false)?;
                    let make_propref = |lo: &mut Lower| {
                        let cls = lo.emit_class_const(internal.clone());
                        let nm = lo.ir_const_str(p.name.clone());
                        let sigc = lo.ir_const_str(prop_sig.clone());
                        let flag = lo.emit_const(IrConst::Int(0));
                        lo.emit_new_external(
                            propref_impl.internal.clone(),
                            propref_impl.ctor_desc.clone(),
                            vec![cls, nm, sigc, flag],
                        )
                    };
                    // getX() calls either the delegate member or the checker-recorded classpath extension.
                    let (gv_owner, gv_desc, gv_ret, gv_inline, gv_is_ext) =
                        lo.delegate_getvalue_info(p.delegate?, delegate_internal)?;
                    let this_e = lo.emit_get_value(0);
                    let dele = lo.emit_get_field(this_e, class_id, field_idx);
                    let this_arg = lo.emit_get_value(0);
                    let pref = make_propref(&mut lo);
                    let call = if gv_is_ext {
                        lo.emit_static_call(
                            gv_owner,
                            "getValue".to_string(),
                            gv_desc,
                            gv_inline,
                            vec![dele, this_arg, pref],
                        )
                    } else {
                        lo.emit_virtual_call(
                            gv_owner,
                            "getValue".to_string(),
                            gv_desc,
                            false,
                            dele,
                            vec![this_arg, pref],
                        )
                    };
                    // A generic delegate's `getValue` returns the erased `Object`; coerce to the property
                    // type (`checkcast`/unbox), exactly as kotlinc does.
                    let coerced = lo.coerce_to_static(call, prop_ty, gv_ret);
                    let ret = lo.emit_return(Some(coerced));
                    let body = lo.emit_block(vec![ret], None);
                    lo.ir.functions[get_fid as usize].body = Some(body);
                    // setX(value): this.x$delegate.setValue(this, propref, value)
                    if p.is_var {
                        let sname = property_setter_name(&p.name);
                        let (_, set_fid, _) = lo.class_info(&internal)?.methods[&sname][0];
                        let sv = lo.syms.method_of_name(delegate_internal, "setValue")?;
                        let sv_desc = lo.runtime.method_descriptor(&sv.params, sv.ret)?;
                        let this_e = lo.emit_get_value(0);
                        let dele = lo.emit_get_field(this_e, class_id, field_idx);
                        let this_arg = lo.emit_get_value(0);
                        let pref = make_propref(&mut lo);
                        let value_arg = lo.emit_get_value(1);
                        // A generic delegate's `setValue` takes the ERASED value param (`<T> setValue(…, i:
                        // T)`); a PRIMITIVE property value boxes into it (`Integer.valueOf`), exactly as
                        // kotlinc does. A reference value passes through.
                        let value_arg = match sv.params.last() {
                            Some(vp)
                                if vp.is_reference()
                                    && lo.runtime.scalar_value_repr(prop_ty).is_some() =>
                            {
                                lo.emit_type_op(
                                    IrTypeOp::ImplicitCoercion,
                                    value_arg,
                                    ty_to_ir(*vp),
                                )
                            }
                            _ => value_arg,
                        };
                        let call = lo.emit_virtual_call(
                            delegate_internal,
                            "setValue".to_string(),
                            sv_desc,
                            false,
                            dele,
                            vec![this_arg, pref, value_arg],
                        );
                        let body = lo.emit_block(vec![call], None);
                        lo.ir.functions[set_fid as usize].body = Some(body);
                    }
                }
                // Companion method bodies — lowered on the synthesized `C$Companion` class.
                if let Some(comp_name) = lo.companions.get(&type_name(&internal)).copied() {
                    let comp_fq = comp_name.render();
                    for (cmi, m) in c.companion_methods.iter().enumerate() {
                        if matches!(m.body, FunBody::None) {
                            continue;
                        }
                        // A `tailrec` companion method isn't loop-transformed (only top-level functions
                        // are) — skip the file rather than emit stack-overflowing recursion (mirrors the
                        // instance-method guard).
                        if m.is_tailrec {
                            return None;
                        }
                        let overload_idx = c.companion_methods[..cmi]
                            .iter()
                            .filter(|x| x.name == m.name)
                            .count();
                        let (_, fid, _) =
                            *lo.class_info(&comp_fq)?.methods[&m.name].get(overload_idx)?;
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_class = Some(comp_name);
                        lo.cur_fn_name = m.name.clone();
                        lo.lambda_seq = 0;
                        let this_v = lo.fresh_value();
                        lo.scope
                            .push(("this".to_string(), this_v, Ty::obj(&comp_fq)));
                        let sig = syms.classes.get(&c.name)?.static_methods.get(&m.name)?;
                        for (p, t) in m.params.iter().zip(&sig.params) {
                            let v = lo.fresh_value();
                            lo.scope.push((p.name.clone(), v, *t));
                        }
                        let ret_ty = lo.ir.functions[fid as usize].ret.clone();
                        lo.lower_body(&m.body, &ret_ty, fid)?;
                    }
                }
                // A superclass whose constructor needs more arguments than are supplied (`object : A()`
                // where `A(val x = …)` has defaulted parameters). krusty fills the base's defaults into the
                // `super(…)` call when NO explicit base args are written and EVERY base param has a default
                // (the common `: A()` shape) — handled by `super_default_fill` below. Any other arity
                // mismatch (some explicit + some defaulted, or a required param missing) still bails.
                let mut super_default_fill = false;
                if let Some(s) = lo.class_info(&internal)?.super_internal {
                    let sup_params = lo
                        .classes
                        .get(&s)
                        .map(|sup| lo.ir.classes[sup.id as usize].ctor_param_count as usize)
                        .unwrap_or(0);
                    // For a class with NO primary constructor the base arguments are supplied by each
                    // secondary ctor's `super(…)` (validated in the secondary-ctor lowering), not by a
                    // supertype-list `: Base(args)` — so this `base_args` arity check doesn't apply.
                    if sup_params > c.base_args.len() && c.has_primary_ctor {
                        // `: A()` (no explicit args) where every base param has a default (read from the
                        // base's resolve `ClassSig`) → fill them.
                        let defaults_ok = c.base_args.is_empty()
                            && lo.syms.class_by_type_name(s).is_some_and(|cs| {
                                cs.ctor_defaults.len() >= sup_params
                                    && cs.ctor_defaults[..sup_params].iter().all(|d| d.is_some())
                            });
                        if defaults_ok {
                            super_default_fill = true;
                        } else {
                            return None;
                        }
                    }
                    // An anonymous object extending a *parameterized* base class can reference the
                    // enclosing instance's (private) members, which Kotlin binds by capture — not by
                    // inheritance (a base's private field is invisible to a subclass). krusty has no
                    // outer-instance capture, so it would resolve such a name to the inherited field
                    // and miscompile (KT-3684). Bail those; SAM-style anon objects over interfaces or
                    // no-argument classes are unaffected.
                    if internal.contains("$anon$") && sup_params > 0 {
                        let capture_free = c.methods.is_empty()
                            && c.body_props.is_empty()
                            && c.init_order.is_empty()
                            && c.base_args.iter().all(|&a| {
                                matches!(
                                    file.expr(a),
                                    Expr::IntLit(_)
                                        | Expr::LongLit(_)
                                        | Expr::DoubleLit(_)
                                        | Expr::FloatLit(_)
                                        | Expr::BoolLit(_)
                                        | Expr::CharLit(_)
                                        | Expr::StringLit(_)
                                        | Expr::NullLit
                                )
                            });
                        if !capture_free {
                            return None;
                        }
                    }
                }
                // `: A()` where every base param has a default — fill the base ctor's default-value exprs
                // into `super(…)` (the same defaults a `new A()` construction fills at the call site, since
                // krusty has no synthetic `$default` ctor). The defaults are evaluated with only `this` in
                // scope (no explicit args reference the subclass params); a default referencing a base param
                // would fail to resolve and bail via `lower_arg`'s `?`.
                if super_default_fill {
                    let class_id = lo.class_info(&internal)?.id;
                    let sup_internal = lo.class_info(&internal)?.super_internal?;
                    let sup_id = lo.class_info_name(sup_internal).map(|s| s.id)?;
                    let super_field_tys: Vec<Ty> = {
                        let sup = &lo.ir.classes[sup_id as usize];
                        let n = sup.ctor_param_count as usize;
                        if sup.ctor_args.is_empty() {
                            sup.fields[..n].iter().map(|f| f.ty).collect()
                        } else {
                            sup.ctor_args[..n].iter().map(|a| a.ty).collect()
                        }
                    };
                    // Defaults are file-independent (`CtorDefaultValue`) — built directly into the
                    // `super(…)` args, so a base defined in ANOTHER file fills with no cross-file deref.
                    let defaults: Vec<CtorDefaultValue> =
                        lo.syms.class_by_type_name(sup_internal)?.ctor_defaults
                            [..super_field_tys.len()]
                            .iter()
                            .map(|d| d.clone().expect("super_default_fill checked all Some"))
                            .collect();
                    let sargs = defaults
                        .iter()
                        .map(|dv| ctor_default_to_ir(&mut lo.ir, lo.runtime, dv))
                        .collect::<Option<Vec<_>>>()?;
                    lo.ir.classes[class_id as usize].super_args = sargs;
                }
                // Base-class constructor arguments (`: A(args)`), evaluated with the primary-ctor
                // params in scope (`this`=0, params 1..N), coerced to the super's parameter types.
                // Reorder NAMED super-constructor arguments (`: Base(name = …, addr = …)`) to the base
                // constructor's parameter order; positional args are unchanged. `None` bails the file.
                let base_args = reordered_base_args(file, c)?;
                if !base_args.is_empty() {
                    let class_id = lo.class_info(&internal)?.id;
                    lo.scope.clear();
                    lo.boxed_elem.clear();
                    lo.next_value = 0;
                    lo.cur_class = Some(type_name(&internal));
                    let this_v = lo.fresh_value();
                    lo.scope
                        .push(("this".to_string(), this_v, Ty::obj(&internal)));
                    // An inner class constructor receives the captured outer instance before source
                    // constructor parameters, so source params start at slot 2. Keep the lowering scope
                    // aligned with the JVM constructor shape when lowering `super(...)` arguments.
                    if let Some(outer) = &c.inner_of {
                        let v = lo.fresh_value();
                        lo.scope.push((
                            "this$0".to_string(),
                            v,
                            Ty::obj(&class_internal(file, outer)),
                        ));
                    }
                    // ALL source ctor params (property and plain) are then in scope in declaration order
                    // — a plain parameter is an argument the initializer / `super(…)` can read.
                    for p in c.props.iter() {
                        let v = lo.fresh_value();
                        lo.scope
                            .push((p.name.clone(), v, ty_of(file, &p.ty, &*syms.libraries)));
                    }
                    // A same-file / module base is an IR class: read its constructor's parameter types
                    // (handles named-reordered args and a parameterized base). A CLASSPATH base has no IR
                    // class — use the parameter types the CHECKER resolved through the symbol source
                    // (`Checker::resolve_super_ctor_params`), so the resolution lives in the resolver, not
                    // here. Empty for a classpath base the checker couldn't resolve → bail.
                    let super_field_tys = lo.super_ctor_param_tys(&internal);
                    let super_field_tys = if super_field_tys.is_empty() && !base_args.is_empty() {
                        match syms.class_by_internal(&internal) {
                            Some(cs) if !cs.super_ctor_params.is_empty() => {
                                cs.super_ctor_params.clone()
                            }
                            _ => return None,
                        }
                    } else {
                        super_field_tys
                    };
                    // The `super(…)` call must match the resolved constructor: same arity, and each argument
                    // assignable to its param (exact, or reference-into-reference for an erased generic /
                    // `Any`). A mismatch means a base SECONDARY constructor krusty doesn't resolve — bail
                    // rather than emit an `<init>` call that won't verify. A branchy super argument
                    // (`Base("O" + if(…))`) emits merge frames the flat constructor emitter can't reconcile.
                    if base_args.len() != super_field_tys.len()
                        || base_args.iter().any(|&a| body_contains_branch(file, a))
                        || base_args.iter().zip(&super_field_tys).any(|(&a, ft)| {
                            let at = info.ty(a);
                            &ty_to_ir(at) != ft
                                && !(at.is_reference() && ir_type_is_reference(ft))
                                && at != Ty::Error
                        })
                    {
                        return None;
                    }
                    let mut sargs = Vec::new();
                    for (a, ft) in base_args.iter().zip(&super_field_tys) {
                        sargs.push(lo.lower_arg(*a, ft)?);
                    }
                    lo.ir.classes[class_id as usize].super_args = sargs;
                }
                // A `@JvmInline value class` with a DEFAULT on its single underlying property needs
                // kotlinc's synthetic `constructor-impl$default`. Lower the default in the STATIC
                // `constructor-impl` frame — the sole param is value-index 0, no `this` — and stash it by
                // class internal; the value-class JVM pass registers it as `constructor-impl`'s param
                // default so the backend emits the stub.
                if c.is_value {
                    if let Some(p) = c.props.iter().find(|p| p.is_property) {
                        if let Some(d) = p.default {
                            lo.scope.clear();
                            lo.boxed_elem.clear();
                            lo.next_value = 0;
                            lo.cur_class = Some(type_name(&internal));
                            lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                            let pty = ty_of(file, &p.ty, &*syms.libraries);
                            let v = lo.fresh_value(); // value-index 0 = the underlying param
                            lo.scope.push((p.name.clone(), v, pty));
                            if let Some(lowered) = lo.lower_arg(d, &ty_to_ir(pty)) {
                                lo.ir.insert_value_ctor_default(&internal, lowered);
                            }
                        }
                    }
                }
                // A REGULAR (non-value, non-inner) class with a DEFAULT on any primary-ctor parameter needs
                // kotlinc's synthetic `<init>(params…, int mask, DefaultConstructorMarker)` overload. Lower
                // each default in the INSTANCE `<init>` frame (`this` = value 0, params = 1..=n) and stash
                // them by class internal; the backend emits the overload (one int mask per 32 params).
                if !c.is_value
                    && c.inner_of.is_none()
                    && !c.is_interface()
                    && c.has_primary_ctor
                    && c.props.iter().any(|p| p.default.is_some())
                {
                    lo.scope.clear();
                    lo.boxed_elem.clear();
                    lo.next_value = 0;
                    lo.cur_class = Some(type_name(&internal));
                    lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                    let this_v = lo.fresh_value(); // value 0 = `this`
                    lo.scope
                        .push(("this".to_string(), this_v, Ty::obj(&internal)));
                    let mut ptys = Vec::new();
                    for p in c.props.iter() {
                        let pty = ty_of(file, &p.ty, &*syms.libraries);
                        let v = lo.fresh_value(); // params at 1..=n
                        lo.scope.push((p.name.clone(), v, pty));
                        ptys.push(pty);
                    }
                    let mut defaults = Vec::with_capacity(c.props.len());
                    let mut all_ok = true;
                    for (p, pty) in c.props.iter().zip(&ptys) {
                        match p.default {
                            Some(d) => match lo.lower_arg(d, &ty_to_ir(*pty)) {
                                Some(l) => defaults.push(Some(l)),
                                None => {
                                    all_ok = false;
                                    break;
                                }
                            },
                            None => defaults.push(None),
                        }
                    }
                    // Only register when EVERY default lowered — a partial set would emit a stub that fills
                    // some slots with a zero placeholder (a miscompile); bail to the no-stub status quo.
                    if all_ok {
                        lo.ir.insert_class_ctor_defaults(&internal, defaults);
                    }
                }
                // Constructor body: run body-property initializers and `init { … }` blocks in source
                // order, with `this` = value 0 and the constructor params as values 1..=N. For a class
                // with NO primary constructor the init steps run inside each `super(…)`-reaching secondary
                // constructor instead (lowered there, in that ctor's own value space) — skip here.
                let has_delegated = c.body_props.iter().any(|p| p.delegate.is_some());
                // Interface delegation `: I by d` whose `d` is a NON-`val` param needs a `$$delegate_<i>`
                // field store in the ctor.
                let has_iface_synth_delegate = c
                    .delegations
                    .iter()
                    .any(|(_, d, _)| !c.props.iter().any(|p| p.is_property && &p.name == d))
                    || !c.delegation_exprs.is_empty();
                // Run whenever there is ANY ctor body to lower OR any primary-constructor `val`/`var`
                // param (or inner `this$0`) to store: the param→field stores are desugared explicitly
                // into `init_body` here (no implicit auto-store in the backend).
                if (!c.init_order.is_empty()
                    || has_delegated
                    || has_iface_synth_delegate
                    || c.inner_of.is_some()
                    || c.props.iter().any(|p| p.is_property))
                    && c.has_primary_ctor
                {
                    let class_id = lo.class_info(&internal)?.id;
                    let ctor_count = lo.ir.classes[class_id as usize].ctor_param_count;
                    let _ = ctor_count;
                    lo.scope.clear();
                    lo.boxed_elem.clear();
                    lo.next_value = 0;
                    lo.cur_class = Some(type_name(&internal));
                    // Property initializers run here (`var s: T = x as T`), so class type params are
                    // in scope as `as T` cast targets.
                    lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                    let this_v = lo.fresh_value();
                    lo.scope
                        .push(("this".to_string(), this_v, Ty::obj(&internal)));
                    // An inner class's synthetic `this$0` is the first constructor parameter (value 1).
                    if let Some(outer) = &c.inner_of {
                        let v = lo.fresh_value();
                        lo.scope.push((
                            "this$0".to_string(),
                            v,
                            Ty::obj(&class_internal(file, outer)),
                        ));
                    }
                    // ALL ctor params (property and plain) in scope as values, declaration order.
                    for p in c.props.iter() {
                        let v = lo.fresh_value();
                        lo.scope
                            .push((p.name.clone(), v, ty_of(file, &p.ty, &*syms.libraries)));
                    }
                    let mut stmts = Vec::new();
                    // Desugar the primary-constructor `val`/`var` sugar: store the inner `this$0` and each
                    // property param to its backing field, right after `super(…)` and before the body
                    // initializers/`init` blocks — exactly what kotlinc emits. This used to be an implicit
                    // auto-store in `ir_emit`; carrying it as explicit `SetField`s keeps the IR sugar-free.
                    //
                    // A `@JvmInline value class` is EXCLUDED: its field store belongs only in the boxed
                    // `<init>`, but the IR ctor body is ALSO reused for the UNBOXED `constructor-impl`
                    // (where `this` is the bare underlying value — a `putfield` through it is invalid). The
                    // backend's auto-store places the store in `<init>` only, so leave that path for them.
                    if !c.is_value {
                        let mut targets: Vec<(String, u32)> = Vec::new();
                        let mut field_i = 0u32;
                        if c.inner_of.is_some() {
                            // The synthetic `this$0` (field 0) is stored BEFORE `super(…)` in the backend
                            // (`ir_emit`), not here — a `super(…)` argument may read the outer instance
                            // (`inner class Inner : Base(run { outerProp })`), and kotlinc stores it first.
                            // Reserve its field index but don't emit the (post-super) store.
                            field_i += 1;
                        }
                        for p in c.props.iter().filter(|p| p.is_property) {
                            targets.push((p.name.clone(), field_i));
                            field_i += 1;
                        }
                        for (name, idx) in targets {
                            let (pv, _) = lo.lookup(&name)?;
                            let recv = lo.emit_get_value(this_v);
                            let val = lo.emit_get_value(pv);
                            stmts.push(lo.emit_set_field(recv, class_id, idx, val));
                        }
                        // These stores ARE the param→field stores — backend must not auto-store too.
                        lo.ir.classes[class_id as usize].explicit_param_stores = true;
                    }
                    // Interface-delegation `$$delegate_<i>` stores (`this.$$delegate_i = <delegate param>`),
                    // first in the ctor body (kotlinc stores them right after `super()`).
                    for (di, (_iface, dname, _)) in c.delegations.iter().enumerate() {
                        if c.props.iter().any(|p| p.is_property && &p.name == dname) {
                            continue; // a `val`-param delegate has its own auto-stored field
                        }
                        let synth = format!("$$delegate_{di}");
                        let fidx = lo.ir.classes[class_id as usize]
                            .fields
                            .iter()
                            .position(|f| f.name == synth)?
                            as u32;
                        let (pv, _) = lo.lookup(dname)?;
                        let this_e = lo.emit_get_value(this_v);
                        let val_e = lo.emit_get_value(pv);
                        let sf = lo.emit_set_field(this_e, class_id, fidx, val_e);
                        stmts.push(sf);
                    }
                    // Expression delegates (`: I by Impl()`): evaluate the expression once into its
                    // `$$delegate_e<j>` field.
                    for (j, (_iface, e)) in c.delegation_exprs.iter().enumerate() {
                        let synth = format!("$$delegate_e{j}");
                        let fidx = lo.ir.classes[class_id as usize]
                            .fields
                            .iter()
                            .position(|f| f.name == synth)?
                            as u32;
                        let fty = lo.ir.classes[class_id as usize].fields[fidx as usize]
                            .ty
                            .clone();
                        let val_e = lo.lower_arg(*e, &fty)?;
                        let this_e = lo.emit_get_value(this_v);
                        let sf = lo.emit_set_field(this_e, class_id, fidx, val_e);
                        stmts.push(sf);
                    }
                    for step in &c.init_order {
                        match step {
                            ast::ClassInit::PropInit(i) => {
                                // A computed or abstract body property has no backing field here —
                                // nothing to initialize. A deferred `val` (`val a: Int`, no initializer)
                                // is assigned later in an `init` block, not at its declaration — skip it
                                // here too (it has no init expression).
                                if !is_backing_field_prop(&c.body_props[*i as usize])
                                    || c.body_props[*i as usize].init.is_none()
                                {
                                    continue;
                                }
                                // Computed body properties are not fields, so the field index counts
                                // only the non-computed body properties before this one.
                                let body_offset = c.body_props[..*i as usize]
                                    .iter()
                                    .filter(|p| is_backing_field_prop(p))
                                    .count();
                                let field_idx = ctor_count + body_offset as u32;
                                let field_ty = lo.ir.classes[class_id as usize].fields
                                    [field_idx as usize]
                                    .ty
                                    .clone();
                                let init_e = c.body_props[*i].init.unwrap();
                                // A branchy body-property initializer (`val k = when { … }`) emits
                                // merge-point frames in the constructor's init context that the flat
                                // emitter doesn't reconcile yet — bail rather than miscompile.
                                if matches!(
                                    lo.afile.expr(init_e),
                                    Expr::When { .. }
                                        | Expr::If { .. }
                                        | Expr::Elvis { .. }
                                        | Expr::Block { .. }
                                        | Expr::Try { .. }
                                ) {
                                    return None;
                                }
                                // A `var` declared inside the initializer and captured+mutated by a
                                // closure (`val p = run { var v=…; bar { v=… }; v }`) needs a `Ref` holder.
                                let val = lo.with_init_shared_cells(init_e, |lo| {
                                    lo.lower_arg(init_e, &field_ty)
                                })?;
                                let recv = lo.emit_get_value(this_v);
                                stmts.push(lo.emit_set_field(recv, class_id, field_idx, val));
                            }
                            ast::ClassInit::Block(e) => {
                                // An `init { … }` block: lower its statements for effect.
                                let Expr::Block {
                                    stmts: bs,
                                    trailing,
                                } = lo.afile.expr(*e).clone()
                                else {
                                    return None;
                                };
                                // A branchy VALUE assignment in `init` (`a = if(…) … else …`) emits merge
                                // frames in the constructor the flat emitter doesn't reconcile (a
                                // verify/runtime error) — bail. A branchy *statement* (`if (c) { … }`) is
                                // fine. (Pre-existing limitation, surfaced by deferred-`val` init.)
                                for &s in &bs {
                                    let branchy = match lo.afile.stmt(s) {
                                        Stmt::Assign { value, .. }
                                        | Stmt::AssignMember { value, .. } => {
                                            body_contains_branch(lo.afile, *value)
                                        }
                                        Stmt::Local { init, .. } => {
                                            body_contains_branch(lo.afile, *init)
                                        }
                                        _ => false,
                                    };
                                    if branchy {
                                        return None;
                                    }
                                }
                                // A `var` the block declares and a nested closure mutates is `Ref`-boxed.
                                lo.with_init_shared_cells(*e, |lo| -> Option<()> {
                                    for s in bs {
                                        stmts.push(lo.stmt(s)?);
                                    }
                                    if let Some(t) = trailing {
                                        stmts.push(lo.expr(t)?);
                                    }
                                    Some(())
                                })?;
                            }
                        }
                    }
                    // Initialize each delegated property's `x$delegate` field: `this.x$delegate = Del()`.
                    for p in c.body_props.iter().filter(|p| p.delegate.is_some()) {
                        let fname = format!("{}$delegate", p.name);
                        let field_idx = lo.ir.classes[class_id as usize]
                            .fields
                            .iter()
                            .position(|f| f.name == fname)
                            .expect("delegate field registered in pass 1")
                            as u32;
                        let field_ty = lo.ir.classes[class_id as usize].fields[field_idx as usize]
                            .ty
                            .clone();
                        let val = lo.lower_arg(p.delegate.unwrap(), &field_ty)?;
                        let recv = lo.emit_get_value(this_v);
                        stmts.push(lo.emit_set_field(recv, class_id, field_idx, val));
                    }
                    let body = lo.emit_block(stmts, None);
                    lo.ir.classes[class_id as usize].init_body = Some(body);
                }
                // Lower each secondary constructor to an extra `<init>(p)`. For a class WITH a primary
                // ctor every secondary delegates to it via `this(…)`. For a class with NO primary ctor a
                // secondary delegates either to a sibling (`this(…)`) or to `super(…)` (or implicitly);
                // a `super(…)`-reaching ctor also runs the field initializers + `init {}` blocks. For a
                // value class the JVM value-class pass turns these lowered `IrSecondaryCtor`s into static
                // `constructor-impl` overloads.
                if !c.secondary_ctors.is_empty() {
                    use crate::ir::CtorDelegateTarget;
                    let class_id = lo.class_info(&internal)?.id;
                    let primary_param_tys: Vec<Ty> = {
                        let n = lo.ir.classes[class_id as usize].ctor_param_count as usize;
                        lo.ir.classes[class_id as usize].fields[..n]
                            .iter()
                            .map(|f| f.ty.clone())
                            .collect()
                    };
                    // The IR param types of every secondary ctor (for resolving a sibling `this(…)`).
                    let sec_param_tys: Vec<Vec<Ty>> = c
                        .secondary_ctors
                        .iter()
                        .map(|sc| {
                            sc.params
                                .iter()
                                .map(|p| ty_to_ir(ty_of(file, &p.ty, &*syms.libraries)))
                                .collect()
                        })
                        .collect();
                    let super_param_tys = lo.super_ctor_param_tys(&internal);
                    let mut secs = Vec::new();
                    for (sc_idx, sc) in c.secondary_ctors.iter().enumerate() {
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_class = Some(type_name(&internal));
                        lo.cur_tparams = class_tparams(file, c, &*syms.libraries);
                        let this_v = lo.fresh_value();
                        lo.scope
                            .push(("this".to_string(), this_v, Ty::obj(&internal)));
                        let mut param_irs = Vec::new();
                        // A secondary ctor with a defaulted parameter needs kotlinc's synthetic
                        // `<init>(…, int mask, DefaultConstructorMarker)` overload, which krusty doesn't
                        // emit — a call omitting the default would hit a missing `<init>`. Bail.
                        if sc.params.iter().any(|p| p.default.is_some()) {
                            return None;
                        }
                        for p in &sc.params {
                            let pty = ty_of(file, &p.ty, &*syms.libraries);
                            let v = lo.fresh_value();
                            lo.scope.push((p.name.clone(), v, pty));
                            param_irs.push(ty_to_ir(pty));
                        }
                        // Resolve the delegation target + the parameter types its args must coerce to.
                        let (delegate, delegate_args, target_tys, run_init): (
                            CtorDelegateTarget,
                            Vec<AstExprId>,
                            Vec<Ty>,
                            bool,
                        ) = match &sc.delegation {
                            // A value class's secondary ctors are re-shaped by the `value_classes` IR
                            // pass, which reads this `target_params`. Keep the EXACT prior resolution
                            // for value classes (primary target when there's a primary ctor, else the
                            // unique same-arity sibling) so the pass is unaffected — value-class logic
                            // stays in `value_classes.rs` (rule 4). The primary-vs-sibling unification
                            // below is for plain classes only.
                            ast::CtorDelegation::This(args) if c.is_value => {
                                let target = if c.has_primary_ctor {
                                    primary_param_tys.clone()
                                } else {
                                    let arg_irs = tys_to_ir(&lo.arg_tys(args));
                                    // Exclude self — a `this(…)` never delegates to its own ctor.
                                    let typed = sec_param_tys.iter().enumerate().find(|(j, p)| {
                                        *j != sc_idx
                                            && p.len() == arg_irs.len()
                                            && arg_irs
                                                .iter()
                                                .zip(p.iter())
                                                .all(|(a, pp)| ir_arg_assignable(a, pp))
                                    });
                                    match typed {
                                        Some((_, p)) => p.clone(),
                                        None => {
                                            let same: Vec<&Vec<Ty>> = sec_param_tys
                                                .iter()
                                                .enumerate()
                                                .filter(|(j, p)| {
                                                    *j != sc_idx && p.len() == args.len()
                                                })
                                                .map(|(_, p)| p)
                                                .collect();
                                            if same.len() != 1 {
                                                return None;
                                            }
                                            same[0].clone()
                                        }
                                    }
                                };
                                (
                                    CtorDelegateTarget::This {
                                        target_params: target.clone(),
                                        to_primary: c.has_primary_ctor,
                                    },
                                    args.clone(),
                                    target,
                                    false,
                                )
                            }
                            ast::CtorDelegation::This(args) => {
                                // `this(…)` may target the primary constructor OR a SIBLING secondary
                                // (never itself). Build the candidate signatures — the primary (when
                                // present) plus every OTHER secondary — and pick the one accepting the
                                // arguments (by type, else the unique same-arity candidate).
                                let arg_irs = tys_to_ir(&lo.arg_tys(args));
                                // Candidate `(signature, is_primary)` pairs: the primary (index 0 when
                                // present) plus every OTHER secondary.
                                let mut candidates: Vec<(Vec<Ty>, bool)> = Vec::new();
                                if c.has_primary_ctor {
                                    candidates.push((primary_param_tys.clone(), true));
                                }
                                for (j, sig) in sec_param_tys.iter().enumerate() {
                                    if j != sc_idx {
                                        candidates.push((sig.clone(), false));
                                    }
                                }
                                let typed = candidates.iter().find(|(p, _)| {
                                    p.len() == arg_irs.len()
                                        && arg_irs
                                            .iter()
                                            .zip(p.iter())
                                            .all(|(a, pp)| ir_arg_assignable(a, pp))
                                });
                                let (target, to_primary) = match typed {
                                    Some((p, prim)) => (p.clone(), *prim),
                                    None => {
                                        let same: Vec<&(Vec<Ty>, bool)> = candidates
                                            .iter()
                                            .filter(|(p, _)| p.len() == args.len())
                                            .collect();
                                        if same.len() != 1 {
                                            return None;
                                        }
                                        (same[0].0.clone(), same[0].1)
                                    }
                                };
                                (
                                    CtorDelegateTarget::This {
                                        target_params: target.clone(),
                                        to_primary,
                                    },
                                    args.clone(),
                                    target,
                                    false,
                                )
                            }
                            ast::CtorDelegation::Super(args) => {
                                if c.has_primary_ctor {
                                    return None; // a secondary in a primary class must delegate via this(…)
                                }
                                // Resolve the base `<init>` this `super(...)` targets by argument arity:
                                // the base primary, or a base SECONDARY constructor (a base with no
                                // primary). `super_param_tys` (the base primary) still covers the common
                                // single-candidate case; multiple candidates disambiguate by arity.
                                let cands = lo.super_ctor_candidate_tys(&internal);
                                let target = match cands.len() {
                                    // Object base / untracked base — no candidate signatures.
                                    0 => super_param_tys.clone(),
                                    // Exactly one base `<init>` (a primary, or a base with a single
                                    // secondary and no primary) — that is the target.
                                    1 => cands[0].clone(),
                                    // Several base `<init>`s — disambiguate by argument arity.
                                    _ => {
                                        let same: Vec<&Vec<Ty>> = cands
                                            .iter()
                                            .filter(|p| p.len() == args.len())
                                            .collect();
                                        if same.len() != 1 {
                                            return None; // no unique base ctor of this arity
                                        }
                                        same[0].clone()
                                    }
                                };
                                (CtorDelegateTarget::Super, args.clone(), target, true)
                            }
                            ast::CtorDelegation::None => {
                                if c.has_primary_ctor {
                                    return None;
                                }
                                // Implicit `super()` — must be a no-arg base (Object, or a base ctor we
                                // can't pass args to here). Bail if the base needs constructor arguments.
                                if !super_param_tys.is_empty() {
                                    return None;
                                }
                                (CtorDelegateTarget::Super, vec![], vec![], true)
                            }
                        };
                        // A branchy delegation argument (`this("O" + if (c) …)`) records stackmap
                        // frames the secondary-ctor `<init>` prologue can't place consistently (the
                        // arg is evaluated before `this` is on the stack) — bail rather than emit a
                        // frame-inconsistent method (the file skips, never miscompiles).
                        if delegate_args
                            .iter()
                            .any(|&a| body_contains_branch(lo.afile, a))
                        {
                            return None;
                        }
                        if delegate_args.len() != target_tys.len() {
                            return None;
                        }
                        let mut dargs = Vec::new();
                        for (a, ft) in delegate_args.iter().zip(&target_tys) {
                            dargs.push(lo.lower_arg(*a, ft)?);
                        }
                        // A `super(…)`-reaching ctor runs the init steps (field initializers + `init {}`)
                        // before its own body; a `this(…)` ctor runs only its body.
                        let mut out = Vec::new();
                        if run_init {
                            out.extend(lo.lower_class_init_steps(c, class_id)?);
                        }
                        if let Some(b) = sc.body {
                            lo.append_body_stmts(b, &mut out)?;
                        }
                        let body = if out.is_empty() {
                            None
                        } else {
                            Some(lo.emit_block(out, None))
                        };
                        secs.push(crate::ir::IrSecondaryCtor {
                            params: param_irs,
                            delegate_args: dargs,
                            body,
                            delegate,
                            synthetic: false,
                        });
                    }
                    lo.ir.classes[class_id as usize].secondary_ctors = secs;
                }
                // Enum entries: lower each entry's constructor arguments (constant expressions
                // evaluated in `<clinit>`), coerced to the matching ctor-parameter field type.
                if c.is_enum() {
                    // Soundness gate for `enum class E : I`: every ABSTRACT interface member must be
                    // satisfied — by a concrete enum method of that name, or by an override in EVERY
                    // entry body. Otherwise the JVM throws `AbstractMethodError`/`IncompatibleClassChange`
                    // at an interface-typed call (e.g. an interface `val ordinal` mapped to `getOrdinal`
                    // that the enum doesn't provide). A classpath-interface supertype (abstractness not
                    // checked here) bails conservatively.
                    for st_ref in &c.supertypes {
                        let st = &st_ref.name;
                        let Some(ic) = file.decls.iter().find_map(|&d| match file.decl(d) {
                            Decl::Class(ic) if ic.name == *st && ic.is_interface() => Some(ic),
                            _ => None,
                        }) else {
                            return None; // non-file / non-interface supertype on an enum — skip
                        };
                        let generic = !ic.type_params.is_empty();
                        let mut abstract_members: Vec<String> = ic
                            .methods
                            .iter()
                            .filter(|m| matches!(m.body, FunBody::None))
                            .map(|m| m.name.clone())
                            .collect();
                        for p in &ic.body_props {
                            abstract_members.push(property_getter_name(&p.name));
                            if p.is_var {
                                abstract_members.push(property_setter_name(&p.name));
                            }
                        }
                        for m in abstract_members {
                            let enum_has = c
                                .methods
                                .iter()
                                .any(|em| em.name == m && !matches!(em.body, FunBody::None));
                            let all_entries_override = !c.enum_entries.is_empty()
                                && c.enum_entries
                                    .iter()
                                    .all(|e| e.methods.iter().any(|bm| bm.name == m));
                            if !enum_has && !all_entries_override {
                                return None; // unsatisfied abstract interface member — skip
                            }
                            // A GENERIC interface needs an erased bridge (`foo(Object)`→`foo(String)`).
                            // The bridge is computed for the ENUM class (an enum-level override) — so a
                            // generic method satisfied only by PER-ENTRY overrides (bridge would belong on
                            // each entry subclass, not modeled) skips rather than miscompiles.
                            if generic && !enum_has {
                                return None;
                            }
                        }
                    }
                    let class_id = lo.class_info(&internal)?.id;
                    // ALL primary-constructor parameters (property AND plain) define the enum
                    // constructor's user parameters, in declaration order — a plain param is a ctor
                    // argument (in scope for a body-property initializer), not a field. Each entry
                    // supplies one lowered value per parameter.
                    let param_tys: Vec<Ty> =
                        c.props.iter().map(|p| lo.field_ty(file, &p.ty)).collect();
                    // (name, default, is_vararg) per parameter — names drive named-argument reordering,
                    // defaults fill omitted arguments, and an omitted `vararg` constructs an empty array.
                    let param_meta: Vec<(&str, Option<AstExprId>, bool)> = c
                        .props
                        .iter()
                        .map(|p| (p.name.as_str(), p.default, p.is_vararg))
                        .collect();
                    for (ei, entry) in c.enum_entries.iter().enumerate() {
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_class = None;
                        // Resolve the entry's (possibly named / reordered / omitted) arguments to one
                        // expression per constructor parameter. A named argument goes to its matching
                        // parameter position; positional arguments fill in declaration order; the rest take
                        // their declared default. Any argument that can't be placed (unknown name,
                        // duplicate, over-arity) bails the whole file rather than miscompiling.
                        let mut positional: Vec<Option<AstExprId>> = vec![None; param_tys.len()];
                        let mut next_pos = 0usize;
                        for (j, &a) in entry.args.iter().enumerate() {
                            let idx = match entry.arg_names.get(j).and_then(|n| n.as_ref()) {
                                Some(name) => param_meta.iter().position(|(pn, ..)| pn == name)?,
                                None => {
                                    let p = next_pos;
                                    next_pos += 1;
                                    p
                                }
                            };
                            if idx >= positional.len() || positional[idx].is_some() {
                                return None;
                            }
                            positional[idx] = Some(a);
                        }
                        let mut lowered = Vec::new();
                        for (i, ft) in param_tys.iter().enumerate() {
                            // The placed argument, or the parameter's declared default. An omitted
                            // `vararg` parameter constructs an empty array of its element type.
                            match positional[i].or_else(|| param_meta.get(i).and_then(|p| p.1)) {
                                Some(arg) => {
                                    // Branchy entry args (`X(1 == 1)`) handled by the `<clinit>` spill.
                                    lowered.push(lo.lower_arg(arg, ft)?);
                                }
                                None if param_meta.get(i).is_some_and(|p| p.2) => {
                                    let zero = lo.emit_const(IrConst::Int(0));
                                    lowered.push(lo.emit_new_array(ty_to_ir(*ft), zero));
                                }
                                None => return None,
                            }
                        }
                        lo.ir.classes[class_id as usize].enum_entries[ei].args = lowered;
                    }
                    // Entry bodies (`ENTRY { override fun m() = … }`) → a synthesized subclass per
                    // bodied entry (`Enum$ENTRY extends Enum`) whose overrides are lowered with the
                    // enum's field/`this` scope (so a read of a constructor `val` becomes a getfield on
                    // the enum). The entry is then constructed as `new Enum$ENTRY(...)`.
                    for (ei, entry) in c.enum_entries.iter().enumerate() {
                        let body = &entry.methods;
                        let eprops = &entry.props;
                        if body.is_empty() && eprops.is_empty() {
                            continue;
                        }
                        let entry_name = &entry.name;
                        let sub_fq = format!("{internal}${entry_name}");
                        // Entry-body PROPERTIES become backing fields (+ getters + ctor init) on the
                        // subclass. Only a plainly-initialized `val`/`var` is modeled; a getter/setter/
                        // delegate/lateinit prop bails (skip, never miscompile).
                        let mut prop_fields: Vec<(String, Ty)> = Vec::new();
                        for p in eprops {
                            if p.init.is_none()
                                || p.getter.is_some()
                                || p.setter.is_some()
                                || p.delegate.is_some()
                                || p.is_lateinit
                            {
                                return None;
                            }
                            let ty = match &p.ty {
                                Some(r) => ty_of(lo.afile, r, &*syms.libraries),
                                None => lo.info.ty(p.init.unwrap()),
                            };
                            if ty == Ty::Error {
                                return None;
                            }
                            prop_fields.push((p.name.clone(), ty));
                        }
                        let sub_id = lo.ir.add_class(IrClass {
                            fq_name: type_name(&sub_fq),
                            is_value: false,
                            is_data: false,
                            decl_line: 0,
                            type_param_bounds: vec![],
                            type_params: Vec::new(),
                            supertypes: vec![],
                            fields: prop_fields
                                .iter()
                                .zip(eprops.iter())
                                .map(|((n, t), p)| IrField {
                                    is_final: !p.is_var,
                                    ..IrField::new(n.clone(), ty_to_ir(*t))
                                })
                                .collect(),
                            ctor_param_count: 0,
                            ctor_args: vec![],
                            init_body: None,
                            explicit_param_stores: false,
                            methods: vec![],
                            is_interface: false,
                            is_annotation: false,
                            annotation_impl_of: None,

                            is_sealed: false,
                            is_abstract: false,
                            is_open: false,
                            superclass: type_name(&internal),
                            super_args: vec![],
                            enum_entries: vec![],
                            enum_entry_of: Some(param_tys.clone()),
                            prop_ref: None,
                            func_ref: None,
                            bridges: vec![],
                            interfaces: Default::default(),
                            is_object: false,
                            is_companion: false,
                            companion_class: None,
                            secondary_ctors: vec![],
                            has_primary_ctor: true,
                            applied_annotations: Vec::new(),
                            field_annotations: Vec::new(),
                            runtime_retained: false,
                        });
                        // Register the subclass so an override body resolves a prop as `this.<field>` and
                        // getter synthesis can attach. Methods are filled in below.
                        lo.insert_class_info(
                            &sub_fq,
                            ClassInfo {
                                id: sub_id,
                                internal: type_name(&sub_fq),
                                fields: prop_fields.clone(),
                                methods: HashMap::new(),
                                super_internal: Some(type_name(&internal)),
                            },
                        );
                        // An override body reads through the SUBCLASS scope: an own property resolves to a
                        // subclass field, and a bare read of an INHERITED enum constructor property routes
                        // through its `getX()` getter (the enum's backing fields are now private, so a
                        // subclass `getfield` on them would be an `IllegalAccessError` — box `enum/kt2350`).
                        let body_cur = sub_fq.clone();
                        // Subclass ctor init: `this.<prop> = <init>` for each property (run after super()).
                        if !prop_fields.is_empty() {
                            lo.scope.clear();
                            lo.boxed_elem.clear();
                            lo.next_value = 0;
                            lo.cur_class = Some(type_name(&sub_fq));
                            lo.cur_fn_name = "<init>".to_string();
                            lo.lambda_seq = 0;
                            let this_v = lo.fresh_value();
                            lo.scope
                                .push(("this".to_string(), this_v, Ty::obj(&sub_fq)));
                            let mut stmts = Vec::new();
                            for (fi, (_, fty)) in prop_fields.iter().enumerate() {
                                let init = eprops[fi].init.unwrap();
                                let val = lo.lower_arg(init, &ty_to_ir(*fty))?;
                                let recv = lo.emit_get_value(this_v);
                                stmts.push(lo.emit_set_field(recv, sub_id, fi as u32, val));
                            }
                            let blk = lo.emit_block(stmts, None);
                            lo.ir.classes[sub_id as usize].init_body = Some(blk);
                        }
                        let mut mfids = Vec::new();
                        for bm in body {
                            // The override conforms to the abstract member it overrides — use that
                            // signature for the emitted descriptor (kotlinc's erased override shape). The
                            // member is declared on the enum itself, OR on an implemented interface
                            // (`enum class E : I { A { override fun … } }`).
                            let sig = match syms
                                .classes
                                .get(&c.name)
                                .and_then(|cs| cs.method(&bm.name))
                            {
                                Some(s) => s.clone(),
                                None => syms
                                    .supertype_methods(&internal)
                                    .into_iter()
                                    .find_map(|(n, s)| (n == bm.name).then_some(s))?,
                            };
                            let params = tys_to_ir(&sig.params);
                            let fid = lo.ir.add_fun(IrFunction {
                                name: bm.name.clone(),
                                params,
                                ret: ty_to_ir(sig.ret),
                                body: None,
                                is_static: false,
                                dispatch_receiver: Some(type_name(&sub_fq)),
                                param_checks: vec![],
                            });
                            lo.scope.clear();
                            lo.boxed_elem.clear();
                            lo.next_value = 0;
                            lo.cur_class = Some(type_name(&body_cur));
                            lo.cur_fn_name = bm.name.clone();
                            lo.lambda_seq = 0;
                            let this_v = lo.fresh_value();
                            lo.scope
                                .push(("this".to_string(), this_v, Ty::obj(&body_cur)));
                            for (p, t) in bm.params.iter().zip(&sig.params) {
                                let v = lo.fresh_value();
                                lo.scope.push((p.name.clone(), v, *t));
                            }
                            let ret_ty = ty_to_ir(sig.ret);
                            lo.lower_body(&bm.body, &ret_ty, fid)?;
                            mfids.push(fid);
                        }
                        lo.ir.classes[sub_id as usize].methods = mfids;
                        // Property getters (`getX()` → `return this.<field>`), kotlinc emits them on the
                        // subclass. Appended after the overrides (add_synth_method pushes onto methods).
                        for (fi, (pname, pty)) in prop_fields.iter().enumerate() {
                            let getter = property_getter_name(pname);
                            let get = lo.this_field(sub_id, fi as u32);
                            let ret = lo.emit_return(Some(get));
                            let gbody = lo.emit_block(vec![ret], None);
                            lo.add_synth_method(
                                &sub_fq,
                                sub_id,
                                &getter,
                                vec![],
                                *pty,
                                gbody,
                                true,
                            );
                        }
                        lo.ir.classes[class_id as usize].enum_entries[ei].subclass =
                            Some(type_name(&sub_fq));
                    }
                }
            }
            Decl::Property(p) => {
                lo.set_bail("deep:property");
                lo.scope.clear();
                lo.boxed_elem.clear();
                lo.next_value = 0;
                lo.cur_class = None;
                if let Some(recv_ref) = &p.receiver {
                    // Extension property getter: lower `get() = …` with `this` = receiver (param 0).
                    let recv_ty = ty_of(file, recv_ref, &*syms.libraries);
                    let recv_key = recv_ty.erased_recv();
                    let pty = body_prop_ty(file, info, p, &*syms.libraries);
                    let gfid = *lo.ext_prop_get_ids.get(&(recv_key, p.name.clone()))?;
                    lo.cur_fn_name = property_getter_name(&p.name);
                    lo.lambda_seq = 0;
                    let this_v = lo.fresh_value();
                    lo.scope.push(("this".to_string(), this_v, recv_ty));
                    let body = p.getter.clone().unwrap();
                    let pty_ir = body_prop_ir_ty(file, info, p, &*syms.libraries);
                    lo.lower_body(&body, &pty_ir, gfid)?;
                    // `var` extension property setter: `set(v) { … }` with `this` = receiver (param 0),
                    // the value parameter `v` (param 1).
                    if p.is_var {
                        let sfid = *lo.ext_prop_set_ids.get(&(recv_key, p.name.clone()))?;
                        let setter = p.setter.as_ref().unwrap();
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_fn_name = property_setter_name(&p.name);
                        lo.lambda_seq = 0;
                        let this_v = lo.fresh_value();
                        lo.scope.push(("this".to_string(), this_v, recv_ty));
                        let v_v = lo.fresh_value();
                        lo.scope.push((setter.param.clone().unwrap(), v_v, pty));
                        let sbody = setter.body.clone().unwrap();
                        lo.lower_body(&sbody, &ty_to_ir(Ty::Unit), sfid)?;
                    }
                } else if p.delegate.is_some() {
                    lo.lower_delegated_top_level(p)?;
                } else if is_field_accessor_prop(p) {
                    // A backing-field property with a custom accessor: push the backing static (its init
                    // runs in `<clinit>`), then lower the custom `getX`/`setX` bodies with `field` bound
                    // to that static (`cur_static_field`). The trivial accessor is suppressed in emit
                    // (`custom_accessor`); reads/writes route through `computed_props`/`computed_setters`.
                    let ir_ty = body_prop_ir_ty(file, info, p, &*syms.libraries);
                    let init = lo.lower_arg(p.init.unwrap(), &ir_ty)?;
                    let sidx = lo.ir.statics.len() as u32;
                    lo.ir.statics.push(crate::ir::IrStatic {
                        visibility: crate::types::Visibility::Public,
                        name: p.name.clone(),
                        ty: ir_ty,
                        init,
                        is_var: p.is_var,
                        is_const: p.is_const,
                        owner: None,
                        custom_accessor: true,
                    });
                    if let Some(&(gfid, _)) = lo.computed_props.get(&p.name) {
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_fn_name = property_getter_name(&p.name);
                        lo.lambda_seq = 0;
                        lo.cur_static_field = Some((sidx, ir_ty));
                        if let Some(getter) = p.getter.clone() {
                            lo.lower_body(&getter, &ir_ty, gfid)?;
                        } else {
                            // Default getter: `return field` → `getstatic; areturn`.
                            let read = lo.emit_get_static(sidx);
                            let ret = lo.emit_return(Some(read));
                            let body = lo.emit_block(vec![ret], None);
                            lo.ir.functions[gfid as usize].body = Some(body);
                        }
                        lo.cur_static_field = None;
                    }
                    if let Some(&sfid) = lo.computed_setters.get(&p.name) {
                        lo.scope.clear();
                        lo.boxed_elem.clear();
                        lo.next_value = 0;
                        lo.cur_fn_name = property_setter_name(&p.name);
                        lo.lambda_seq = 0;
                        let pty = body_prop_ty(file, info, p, &*syms.libraries);
                        let custom = p.setter.as_ref().filter(|s| s.body.is_some()).cloned();
                        let pname = ast::setter_param_or_value(
                            custom.as_ref().and_then(|s| s.param.as_ref()),
                        );
                        let v_v = lo.fresh_value();
                        lo.scope.push((pname, v_v, pty));
                        lo.cur_static_field = Some((sidx, ir_ty));
                        if let Some(setter) = custom {
                            let sbody = setter.body.clone().unwrap();
                            lo.lower_body(&sbody, &ty_to_ir(Ty::Unit), sfid)?;
                        } else {
                            // Default setter: `field = value` → `putstatic; return`.
                            let val = lo.emit_get_value(v_v);
                            let set = lo.emit_set_static(sidx, val);
                            let ret = lo.emit_return(None);
                            let body = lo.emit_block(vec![set, ret], None);
                            lo.ir.functions[sfid as usize].body = Some(body);
                        }
                        lo.cur_static_field = None;
                    }
                } else if let Some(&(fid, _)) = lo.computed_props.get(&p.name) {
                    // A computed property: lower its custom getter into the `getX()` body.
                    lo.cur_fn_name = property_getter_name(&p.name);
                    lo.lambda_seq = 0;
                    let ret_ty = body_prop_ir_ty(file, info, p, &*syms.libraries);
                    let body = p.getter.clone().unwrap();
                    lo.lower_body(&body, &ret_ty, fid)?;
                } else {
                    let ir_ty = body_prop_ir_ty(file, info, p, &*syms.libraries);
                    let init = lo.lower_arg(p.init.unwrap(), &ir_ty)?;
                    lo.ir.statics.push(crate::ir::IrStatic {
                        visibility: p.visibility,
                        name: p.name.clone(),
                        ty: ir_ty,
                        init,
                        is_var: p.is_var,
                        is_const: p.is_const,
                        owner: None,
                        custom_accessor: false,
                    });
                }
            }
        }
    }
    // Pass 2': lower the lifted local-function bodies. A non-capturing local function lowers like a
    // top-level static method: its parameters are values `0..n`, no captured outer scope.
    let local_funs: Vec<(crate::ast::StmtId, ast::FunDecl)> = file
        .stmt_arena
        .iter()
        .enumerate()
        .filter_map(|(i, s)| match s {
            Stmt::LocalFun(f) => Some((crate::ast::StmtId(i as u32), f.clone())),
            _ => None,
        })
        .collect();
    for (stmt_id, f) in &local_funs {
        let Some(&fid) = lo.local_fun_ids.get(stmt_id) else {
            continue;
        };
        lo.scope.clear();
        lo.boxed_elem.clear();
        lo.next_value = 0;
        lo.cur_class = None;
        lo.cur_fn_name = lo.ir.functions[fid as usize].name.clone();
        lo.lambda_seq = 0;
        let local_fun = info.local_fun(*stmt_id)?;
        let sig = local_fun.sig.clone();
        // Captured outer locals occupy the leading value slots; a boxed one binds its `Ref` holder
        // (reads/writes go through `element` via `boxed_elem`), an ordinary one binds its value.
        for cap in &local_fun.captures {
            let v = lo.fresh_value();
            if cap.shared_cell {
                let holder_ty = lo.mutable_local_ref_type(cap.ty)?;
                lo.scope.push((cap.name.clone(), v, holder_ty));
                lo.boxed_elem.insert(cap.name.clone(), cap.ty);
            } else {
                lo.scope.push((cap.name.clone(), v, cap.ty));
            }
        }
        for (p, t) in f.params.iter().zip(&sig.params) {
            let v = lo.fresh_value();
            lo.scope.push((p.name.clone(), v, *t));
        }
        let ret_ty = lo.ir.functions[fid as usize].ret.clone();
        lo.lower_body(&f.body, &ret_ty, fid)?;
    }
    // Discover classpath `@JvmInline value class`es referenced by type in this file and record their
    // REFERENCE underlying (`Result` → `Object`), so the value-class pass erases them like a user value
    // class. A primitive-underlying value class (`UInt`/`ULong` → `Int`/`Long`) is EXCLUDED — it keeps
    // its existing dedicated handling, and erasing it here would disturb that.
    {
        let mut referenced: std::collections::HashSet<TypeName> = std::collections::HashSet::new();
        let note = |t: &Ty, set: &mut std::collections::HashSet<TypeName>| {
            if let Some(fq_name) = t.non_null().obj_internal() {
                set.insert(fq_name);
            }
        };
        for f in &lo.ir.functions {
            for p in &f.params {
                note(p, &mut referenced);
            }
            note(&f.ret, &mut referenced);
        }
        for c in &lo.ir.classes {
            for f in &c.fields {
                note(&f.ty, &mut referenced);
            }
            for a in &c.ctor_args {
                let t = &a.ty;
                note(t, &mut referenced);
            }
        }
        for s in &lo.ir.statics {
            note(&s.ty, &mut referenced);
        }
        // Every EXPRESSION's resolved type — so a classpath value class produced by a member/getter or
        // any temporary (`h.id` : `Vid`, never bound to a typed local) is discovered and erased to its
        // underlying, with its sole-property getter rewritten to identity. The downstream filter keeps
        // only actual value classes, so noting all reference types here is cheap.
        for t in &lo.info.expr_types {
            note(t, &mut referenced);
        }
        for e in &lo.ir.exprs {
            match e {
                IrExpr::Variable { ty, .. } => note(ty, &mut referenced),
                // A mutable local captured by a closure holds its value in a `Ref` box; the boxed value's
                // type (`var res: Result<T>?` → `Result`) appears ONLY on the `Ref` node, not the holder's
                // `Variable.ty`. Note it so a captured value-class local still erases like any other.
                IrExpr::RefNew { elem, .. }
                | IrExpr::RefGet { elem, .. }
                | IrExpr::RefSet { elem, .. } => note(elem, &mut referenced),
                // An INLINE classpath value-class construction (`Id().v`, `RoleId("x").v` — never bound
                // to a typed local) references the value class only through the static `constructor-impl`
                // / `box-impl` call owner. Note it so its underlying erasure + getter rewrite still fire.
                IrExpr::Call {
                    callee: Callee::Static { owner, name, .. },
                    ..
                } if name.starts_with("constructor-impl") || name == "box-impl" => {
                    referenced.insert(*owner);
                }
                _ => {}
            }
        }
        for fq in referenced {
            // Skip the native unsigned builtins (`UInt`/`ULong`): their BOXED form (`kotlin/UInt`) reaches
            // here through a nullable `UInt?`, but krusty models them as primitive `Ty` variants with their
            // own nullable-boxing codegen — erasing them to `int`/`long` would break it. Derived from the
            // unsigned `Ty` variants (their box-type internal names), not a hardcoded class-name list.
            let native_unsigned = [Ty::UInt, Ty::ULong].into_iter().any(|u| {
                lo.runtime
                    .unsigned_integer_box_type(u)
                    .and_then(|b| b.obj_internal())
                    .is_some_and(|n| n == fq)
            });
            if native_unsigned {
                continue;
            }
            // The unsigned specialized arrays (`UIntArray`, `ULongArray`) are inline classes over
            // `[I`/`[J`, but the compiler models and emits them AS the primitive array — never boxing to
            // the wrapper object. Excluding them here keeps them out of the value-class erasure map.
            if crate::types::prim_array_element(&fq.render()).is_some() {
                continue;
            }
            let Some(t) = lo.syms.libraries.resolve_type_name(fq) else {
                continue;
            };
            if let Some(under) = t.value_underlying {
                // Erase the value-class type to its underlying. A REFERENCE underlying is held boxed and
                // null-capable (`Result`'s `Any?`, mirroring a type-parameter value-class field); a SCALAR
                // underlying stays the unboxed primitive (`value class Count(val n: Int)` → `int`). The
                // unsigned builtins (`UInt`/`ULong`) never reach here — they are `Ty` variants, not `Obj`,
                // so `referenced` (obj-internal names only) excludes them, keeping their dedicated handling.
                let ir_under = match lo.runtime.scalar_value_repr(under) {
                    Some(scalar) => ty_to_ir(scalar),
                    None => Ty::nullable(ty_to_ir(under)),
                };
                lo.ir.insert_external_value_class_name(fq, ir_under);
                // The sole-property getter (`getV`) — the no-arg member returning the underlying — so
                // the value-class pass can rewrite `x.v` (emitted as `invokevirtual X.getV()`) to
                // identity on the unboxed value.
                if let Some(getter) = t
                    .members
                    .iter()
                    .find(|m| m.params.is_empty() && m.ret == under && m.name.starts_with("get"))
                {
                    lo.ir
                        .insert_external_value_class_getter_name(fq, getter.name.clone());
                }
            }
        }
    }
    Some(lo.ir)
}

/// A class is in the IR subset if: a primary constructor of only `val`/`var` properties, no base
/// class/interfaces, no body properties, no companion/secondary/init, and methods (expr- or
/// The type parameters of a generic function as `(name, bound, non_null)`, for lowering `as T`. `bound`
/// is the declared upper bound kept VERBATIM as an `IrType` — `<T : CharSequence>` → `CharSequence`,
/// an unbounded `<T>` → `kotlin/Any` (NOT erased here; the JVM emitter collapses it to a concrete
/// class). `non_null` marks a non-nullable bound (`<T : Any>`, `<T : Foo>`) — such a cast null-checks
/// (kotlinc emits `Intrinsics.checkNotNull`); an unbounded `<T>` (= `<T : Any?>`) does not.
fn collect_tparams(
    file: &ast::File,
    names: &[String],
    bounds: &[(String, ast::TypeRef)],
    non_null: &std::collections::HashSet<String>,
    plat: &dyn SemanticPlatform,
) -> Vec<(String, Ty, bool)> {
    names
        .iter()
        .map(|name| {
            let bound_ref = bounds.iter().find_map(|(n, tr)| (n == name).then_some(tr));
            let bound = bound_ref
                .map(|tr| ty_to_ir(ty_of(file, tr, plat)))
                .unwrap_or(Ty::nullable(Ty::obj("kotlin/Any")));
            let non_null = non_null.contains(name) || bound_ref.is_some_and(|tr| !tr.nullable);
            (name.clone(), bound, non_null)
        })
        .collect()
}

/// Class-level type parameters (`class C<T : B>`) as cast targets, so an `x as T` in a member body or
/// property initializer erases to its bound (`Object` for an unbounded `T`) exactly like kotlinc —
/// rather than falling through to `ty_ref` (which rejects a bare `T`) and bailing the whole file.
fn class_tparams(
    file: &ast::File,
    c: &ast::ClassDecl,
    plat: &dyn SemanticPlatform,
) -> Vec<(String, Ty, bool)> {
    // A value/inline class's generic underlying (`value class Foo<T : String>(val x: T)`) has a
    // box/unbox erasure krusty doesn't model — an `as T` there must keep bailing (skip the file),
    // not lower to a checkcast against the bound (which would store the wrong runtime type).
    if c.is_value {
        return Vec::new();
    }
    collect_tparams(
        file,
        &c.type_params,
        &c.type_param_bounds,
        &std::collections::HashSet::new(),
        plat,
    )
}

/// block-bodied) without an extension receiver.
/// A `const val`'s compile-time literal initializer as an `IrConst`, narrowed to its declared type
/// (`const val b: Byte = 1` → `Byte(1)`). `None` for any non-literal initializer (then the read stays a
/// `getstatic`). Lets a same-file const read inline the value (`ldc`), byte-identical to kotlinc.
/// Whether every `break`/`continue` EXPRESSION in `e` sits in a TAIL position — one where the operand
/// stack is empty at the jump (an elvis RHS, an `if`/`when`-branch value, a block's trailing value). A
/// `break`/`continue` used mid-expression (`x + break`, `inc() downTo continue`, `while (break)`) would
/// jump with values still on the operand stack, which krusty's emitter does not clear (a VerifyError), so
/// such a body is declined (the file skips) rather than miscompiled; the common tail forms compile.
fn break_continue_tail_only(file: &ast::File, e: AstExprId, tail: bool) -> bool {
    match file.expr(e) {
        Expr::Break { .. } | Expr::Continue { .. } => tail,
        Expr::Elvis { lhs, rhs } => {
            break_continue_tail_only(file, *lhs, false)
                && break_continue_tail_only(file, *rhs, tail)
        }
        Expr::If {
            cond,
            then_branch,
            else_branch,
        } => {
            break_continue_tail_only(file, *cond, false)
                && break_continue_tail_only(file, *then_branch, tail)
                && else_branch.is_none_or(|b| break_continue_tail_only(file, b, tail))
        }
        Expr::When { subject, arms } => {
            subject.is_none_or(|s| break_continue_tail_only(file, s, false))
                && arms.iter().all(|a| {
                    a.conditions
                        .iter()
                        .all(|&c| break_continue_tail_only(file, c, false))
                        && break_continue_tail_only(file, a.body, tail)
                })
        }
        Expr::Block { stmts, trailing } => {
            stmts
                .iter()
                .all(|&s| break_continue_stmt_tail_only(file, s))
                && trailing.is_none_or(|t| break_continue_tail_only(file, t, tail))
        }
        // Any other expression's children evaluate with their values on the operand stack — a
        // `break`/`continue` there is NOT in tail position.
        _ => {
            let ok = std::cell::Cell::new(true);
            file.any_child_expr(
                e,
                &mut |c| {
                    if !break_continue_tail_only(file, c, false) {
                        ok.set(false);
                    }
                    false
                },
                &mut |s| {
                    if !break_continue_stmt_tail_only(file, s) {
                        ok.set(false);
                    }
                    false
                },
            );
            ok.get()
        }
    }
}

fn break_continue_stmt_tail_only(file: &ast::File, s: ast::StmtId) -> bool {
    match file.stmt(s) {
        Stmt::Local { init, .. } | Stmt::Destructure { init, .. } => {
            break_continue_tail_only(file, *init, true)
        }
        Stmt::LocalDelegate { delegate, .. } => break_continue_tail_only(file, *delegate, true),
        Stmt::Assign { value, .. } => break_continue_tail_only(file, *value, true),
        Stmt::AssignMember {
            receiver, value, ..
        } => {
            break_continue_tail_only(file, *receiver, false)
                && break_continue_tail_only(file, *value, true)
        }
        Stmt::AssignIndex {
            array,
            indices,
            value,
        } => {
            break_continue_tail_only(file, *array, false)
                && indices
                    .iter()
                    .all(|&i| break_continue_tail_only(file, i, false))
                && break_continue_tail_only(file, *value, true)
        }
        // A loop CONDITION / range is a dirty (non-tail) position (`while (break)`); the body is scanned
        // like any block.
        Stmt::While { cond, body, .. } | Stmt::DoWhile { body, cond, .. } => {
            break_continue_tail_only(file, *cond, false)
                && break_continue_tail_only(file, *body, true)
        }
        Stmt::For { range, body, .. } => {
            break_continue_tail_only(file, range.start, false)
                && break_continue_tail_only(file, range.end, false)
                && break_continue_tail_only(file, *body, true)
        }
        Stmt::ForEach { iterable, body, .. } => {
            // The iterable is a dirty (non-tail) position for `break`/`continue`. Even a
            // short-circuiting `for (v in foo() ?: continue)` — where the jump itself has a clean
            // operand stack — is declined: a local assigned past the jump (the iterator, or a `val`
            // fed by the iterable) is unset on the continue edge, and krusty's StackMapTable does not
            // yet merge that `top` local state into the loop back-edge frame (VerifyError). Skip until
            // the emitter tracks definite-assignment across the jump.
            break_continue_tail_only(file, *iterable, false)
                && break_continue_tail_only(file, *body, true)
        }
        Stmt::Return(Some(e), _) => break_continue_tail_only(file, *e, true),
        Stmt::Expr(e) => break_continue_tail_only(file, *e, true),
        // No hosted expression (a bare `break`/`continue`/`return`, `lateinit`), or a nested local
        // function whose `break`/`continue` is scoped to its own loops — nothing unsafe at this level.
        _ => true,
    }
}

fn ast_literal_const(file: &ast::File, e: AstExprId, ty: Ty) -> Option<crate::ir::IrConst> {
    use crate::ir::IrConst;
    use ast::Expr;
    Some(match file.expr(e) {
        Expr::IntLit(v) => match ty {
            Ty::Byte => IrConst::Byte(*v as i8),
            Ty::Short => IrConst::Short(*v as i16),
            Ty::Char => IrConst::Char(char::from_u32(*v as u32)?),
            _ => IrConst::Int(*v as i32),
        },
        Expr::LongLit(v) => IrConst::Long(*v),
        Expr::DoubleLit(v) => IrConst::Double(*v),
        Expr::FloatLit(v) => IrConst::Float(*v),
        Expr::BoolLit(b) => IrConst::Boolean(*b),
        Expr::StringLit(s) => IrConst::String(s.clone()),
        Expr::CharLit(c) => IrConst::Char(*c),
        Expr::UIntLit(v) => IrConst::Int(*v as i32),
        Expr::ULongLit(v) => IrConst::Long(*v),
        _ => return None,
    })
}

/// Whether a class's `companion object` properties are all lowerable: each a `const val` with a plain
/// compile-time initializer (no getter/setter/delegate). Such a const becomes a `public static final` +
/// `ConstantValue` field on the OUTER class (kotlinc's layout). An empty list is trivially lowerable.
/// The class's super-constructor arguments reordered to the base constructor's parameter order. When
/// no argument is named (the common case), returns `base_args` unchanged. A named argument goes to its
/// matching base parameter position; positional args fill in order. Returns `None` (bail the file) on
/// an unknown name, a duplicate, or over-arity, or when the base class / its params aren't found.
fn reordered_base_args(file: &ast::File, c: &ast::ClassDecl) -> Option<Vec<AstExprId>> {
    let base_args = &c.base_args;
    let names = match base_args
        .first()
        .and_then(|a| file.base_arg_names.get(&a.0))
    {
        Some(n) => n,
        None => return Some(base_args.clone()),
    };
    let base_name = c.base_class.as_deref()?;
    let base_simple = base_name.rsplit('/').next().unwrap_or(base_name);
    let base = file.decls.iter().find_map(|&d| match file.decl(d) {
        ast::Decl::Class(bc) if bc.name == base_simple => Some(bc),
        _ => None,
    })?;
    let params: Vec<&str> = base
        .props
        .iter()
        .filter(|p| p.is_property)
        .map(|p| p.name.as_str())
        .collect();
    let mut positional: Vec<Option<AstExprId>> = vec![None; params.len()];
    let mut next_pos = 0usize;
    for (i, &a) in base_args.iter().enumerate() {
        let idx = match names.get(i).and_then(|n| n.as_ref()) {
            Some(nm) => params.iter().position(|p| p == nm)?,
            None => {
                let p = next_pos;
                next_pos += 1;
                p
            }
        };
        if idx >= positional.len() || positional[idx].is_some() {
            return None;
        }
        positional[idx] = Some(a);
    }
    let reordered: Vec<AstExprId> = positional.into_iter().collect::<Option<Vec<_>>>()?;
    // The super arguments are lowered (and thus EVALUATED) in the returned order. Kotlin evaluates them
    // in SOURCE order regardless of the parameter order. When the reordering changes the order AND any
    // argument is not a compile-time LITERAL, evaluating in the reordered order could observably differ
    // (a `Base(k = f(), o = g())` eval-order test, or a bare name that is a getter with side effects) —
    // bail rather than miscompile. Literals are the only shape provably side-effect-free without types.
    if reordered != *base_args
        && base_args.iter().any(|&a| {
            !matches!(
                file.expr(a),
                Expr::IntLit(_)
                    | Expr::LongLit(_)
                    | Expr::DoubleLit(_)
                    | Expr::FloatLit(_)
                    | Expr::BoolLit(_)
                    | Expr::CharLit(_)
                    | Expr::StringLit(_)
                    | Expr::NullLit
            )
        })
    {
        return None;
    }
    Some(reordered)
}

fn companion_props_lowerable(c: &ast::ClassDecl) -> bool {
    // A plain companion `val` with an initializer and no custom accessor/delegate — emitted as a static
    // field on the OUTER class (a `const val` as a `ConstantValue`, a non-const `val` initialized in the
    // outer class's `<clinit>`), read as `getstatic C.X`.
    c.companion_props.iter().all(|p| {
        !p.is_var
            && p.init.is_some()
            && p.getter.is_none()
            && p.setter.is_none()
            && p.delegate.is_none()
    })
}

fn is_simple_class(c: &ast::ClassDecl) -> bool {
    // A `data class` is structurally a simple class; its equals/hashCode/toString/componentN are
    // synthesized as ordinary IR methods (see `synth_data_members`). `value`/inline classes need
    // unboxing and are excluded.
    // A base class (`: A(args)`) is allowed when `A` is itself a simple/open class in this file
    // (checked at registration); interface supertypes are not yet supported.
    // Interface supertypes (`class C : I`) are allowed when each is a file interface (checked at
    // registration); a base class is allowed when it's a simple/open file class.
    // `abstract class` is allowed: its abstract methods (no body) are emitted as `ACC_ABSTRACT`,
    // concrete methods normally. A `@JvmInline value class` is structurally a single-field class; its
    // unboxed-support members are synthesized (see `synth_value_members`). Use-site unboxing isn't done
    // yet, so the resolver still rejects value-class *files* — admission here is for member synthesis.
    // A `companion object` with methods is supported (synthesized `C$Companion` class). A companion
    // `val` (const or non-const, plain backing field) is too — emitted as a static field on the OUTER
    // class (`ConstantValue` for a const, `<clinit>`-initialized otherwise). See `companion_props_lowerable`.
    !c.is_object() && !c.is_enum() && !c.is_interface() && companion_props_lowerable(c)
        // Secondary constructors: in a class WITH a primary ctor each must delegate to it (`this(…)`);
        // a class with NO primary ctor admits `this(…)` (to a sibling), `super(…)`, or implicit
        // delegation — each becomes its own `<init>` (see the secondary-ctor lowering).
        && (if c.has_primary_ctor {
            c.secondary_ctors.iter().all(|sc| matches!(sc.delegation, ast::CtorDelegation::This(_)))
        } else {
            true
        })
        // A non-`val`/`var` primary-ctor parameter (`class C(x: Int) { val y = x }`) is an argument only
        // (no field), available in the constructor body — lowered via `ctor_args`. (Both property and
        // plain params are fine here.)
        // Body properties (`class C { val x = … }`) are allowed when they're plain backing fields
        // initialized in the constructor; `init { … }` blocks run there too (see `init_order`). An
        // `abstract val x: T` (no field, emitted as an abstract `getX()`) is also allowed.
        && c.body_props.iter().all(|p| is_plain_body_prop(p) || is_computed_prop(p) || is_field_accessor_prop(p) || p.is_abstract || is_deferred_val_prop(p) || is_lateinit_prop(p) || p.delegate.is_some())
        // Methods are non-extension; an abstract method (no body) is allowed on an abstract class
        // (the checker only permits that), and emitted as an `ACC_ABSTRACT` declaration.
        && c.methods.iter().all(|m| m.receiver.is_none())
}

/// An `enum class` the IR can emit: a primary constructor of `val`/`var` props, concrete (non-extension,
/// bodied) or abstract methods, plain body-props, and no companion / secondary ctors / supertypes.
/// Per-entry bodies (`ENTRY { override fun m() = … }`) are emitted as anonymous subclasses; only
/// method overrides are supported (a property override would need backing-field plumbing — deferred).
fn is_simple_enum(c: &ast::ClassDecl) -> bool {
    let abstract_names: std::collections::HashSet<&str> = c
        .methods
        .iter()
        .filter(|m| matches!(m.body, FunBody::None))
        .map(|m| m.name.as_str())
        .collect();
    c.is_enum()
        && c.companion_methods.is_empty() && c.companion_props.is_empty()
        && c.secondary_ctors.is_empty()
        // An enum may implement interfaces (`enum class E : I`) — supertypes are interfaces only (an enum
        // can't extend a class); the lowering resolves them as interfaces or bails. A plain (non-property)
        // primary-ctor param is allowed: it is a constructor argument (in scope for body-property
        // initializers), emitted from `ctor_args`, not a field.
        // A body property must be a plain backing field with an initializer — a computed/abstract/
        // delegated body property on an enum isn't emitted yet, so skip those. A plain `val x = …` is
        // emitted as a backing field initialized in the enum constructor (see `emit_enum_class`).
        && c.body_props.iter().all(|p| {
            is_plain_body_prop(p) && !p.is_abstract && p.init.is_some() && p.delegate.is_none()
        })
        && c.methods.iter().all(|m| m.receiver.is_none())
        // Entry-body overrides: concrete, non-extension methods only.
        && c.enum_entries.iter().all(|e| e.methods.iter().all(|m| m.receiver.is_none() && !matches!(m.body, FunBody::None)))
        // Every entry must override EVERY abstract member: a bodyless entry would instantiate the
        // abstract enum, and an entry that overrides only some members would leave its synthesized
        // subclass with an unimplemented abstract method (AbstractMethodError). kotlinc requires full
        // coverage; if any entry's overrides don't cover all abstract members, skip (never miscompile).
        && (abstract_names.is_empty() || c.enum_entries.iter().all(|e| {
            let overridden: std::collections::HashSet<&str> = e.methods.iter().map(|m| m.name.as_str()).collect();
            abstract_names.iter().all(|n| overridden.contains(n))
        }))
}

/// An `object Foo` the IR can emit as a singleton: no primary-constructor params, plain body
/// properties, concrete (bodied, non-extension) methods, no inheritance/interfaces/companion.
fn is_simple_object(c: &ast::ClassDecl) -> bool {
    c.is_object()
        // INTERFACE supertypes are allowed (`object X : KSerializer<C>`); a base CLASS supertype
        // (`object A : Sealed()`) too — the general class lowering computes the `superclass` + emits the
        // `super(args)` call, and bails the file if the base isn't a simple file class. But a base class
        // AND interfaces together (`object O : A(), T`) invites a qualified `super<A>`/`super<T>` call
        // krusty doesn't dispatch — skip that combination.
        && (c.base_class.is_none() || c.supertypes.is_empty())
        && c.companion_methods.is_empty() && c.companion_props.is_empty() && c.secondary_ctors.is_empty()
        && c.props.is_empty()
        && c.body_props.iter().all(is_plain_body_prop)
        && c.methods.iter().all(|m| m.receiver.is_none() && !matches!(m.body, FunBody::None))
        // An `init { … }` block with side effects must not run when a `const val` is read (a const is
        // inlined, not fetched through INSTANCE) — krusty doesn't model const-inlining, so bail.
        && c.init_order.iter().all(|s| matches!(s, ast::ClassInit::PropInit(_)))
    // (A `const val` read from a method is safe: `object_const_lits` inlines the literal at the read
    // site — like kotlinc — so no backing field is fetched. The call site additionally requires each
    // const to be an inlinable literal.)
}

/// An `interface` the IR can emit: only abstract methods (no default/bodied methods, which need a
/// `DefaultImpls` class), no properties (abstract property getters not modeled), no companion.
fn is_simple_interface(c: &ast::ClassDecl) -> bool {
    c.is_interface()
        // A companion is supported when it has no base/supertype and its props are lowerable — its
        // methods become a synthesized `C$Companion` class and its props static fields on the interface
        // (see `emit_interface_class`).
        && c.companion_base.is_none()
        && c.companion_supertypes.is_empty()
        && companion_props_lowerable(c)
        && c.props.is_empty()
        // Abstract properties (`val x: T`, no initializer/getter) become abstract `getX()`/`setX()`;
        // a property with an initializer or custom getter (an interface can't have a backing field)
        // isn't modeled.
        && c.body_props.iter().all(|p| p.init.is_none() && p.getter.is_none() && p.ty.is_some())
        // Non-extension methods only; a method may be abstract (no body) OR a default method (with a
        // body, emitted as a JVM default method).
        && c.methods.iter().all(|m| m.receiver.is_none())
}

/// A class-body property that is a plain backing field: a normal (non-extension) `val`/`var` with an
/// initializer and no custom getter/setter and not `lateinit`.
/// Whether a file-local delegate class's `getValue` references its `KProperty` parameter (its second
/// parameter) in the body — i.e. uses property reflection. Such delegates need the property reference
/// to resolve through `@Metadata` (not emitted for delegated properties), so they're skipped. A
/// library/classpath delegate (not found here) returns `false` — library `getValue`s don't reflect.
fn delegate_getvalue_uses_property(file: &ast::File, internal: TypeName) -> bool {
    for &d in &file.decls {
        let ast::Decl::Class(c) = file.decl(d) else {
            continue;
        };
        if !internal.matches(&class_internal(file, &c.name)) {
            continue;
        }
        for m in &c.methods {
            if m.name != "getValue" {
                continue;
            }
            let Some(param) = m.params.get(1) else {
                continue;
            };
            let body = match &m.body {
                ast::FunBody::Expr(e) | ast::FunBody::Block(e) => *e,
                ast::FunBody::None => continue,
            };
            if file.expr_uses_name(body, &param.name) {
                return true;
            }
        }
    }
    false
}

fn is_plain_body_prop(p: &ast::PropDecl) -> bool {
    p.receiver.is_none()
        && !p.is_lateinit
        && p.getter.is_none()
        // A visibility-only setter (`var x = 1; private set`, no body) is still a plain backing field — the
        // only difference is the setter's access flag (handled at emit). A setter with a BODY is not plain.
        && p.setter.as_ref().is_none_or(|s| s.body.is_none())
        && p.init.is_some()
}

/// Whether a body-property initializer *AST expression* is the field's JVM default value:
/// `0`/`0L`/`0.0`/`0.0f`/`false`/`'\0'`/`null`, or such a zero literal under a primitive conversion
/// (`0.toByte()`/`0.toChar()`). kotlinc elides a field initializer equal to the field's default — the
/// JVM zero-initializes the field, so re-storing the default would clobber a value a base constructor's
/// virtual call already wrote. Decided on the AST (a default-value literal has no side effect to lose).
fn ast_init_is_jvm_default(file: &ast::File, e: AstExprId) -> bool {
    match file.expr(e) {
        Expr::IntLit(0) | Expr::LongLit(0) | Expr::NullLit | Expr::BoolLit(false) => true,
        Expr::DoubleLit(d) => *d == 0.0,
        Expr::FloatLit(f) => *f == 0.0,
        Expr::CharLit(c) => *c as u32 == 0,
        // `0.toByte()` / `0.toChar()` — a primitive conversion of a zero literal is still the default.
        Expr::Call { callee, args } if args.is_empty() => match file.expr(*callee) {
            Expr::Member { receiver, name } if is_conversion_call_name(name) => {
                ast_init_is_jvm_default(file, *receiver)
            }
            _ => false,
        },
        _ => false,
    }
}

/// A *deferred* `val` body property: declared with an explicit type and NO initializer/getter/setter
/// (`val a: Int`), assigned exactly once in an `init` block. It's a real backing field, just initialized
/// in the constructor body rather than at the declaration.
fn is_deferred_val_prop(p: &ast::PropDecl) -> bool {
    !p.is_var
        && p.receiver.is_none()
        && !p.is_lateinit
        && p.init.is_none()
        && p.getter.is_none()
        && p.setter.is_none()
        && !p.is_abstract
        && p.ty.is_some()
}

/// A `lateinit var x: T` — a mutable backing-field property with no initializer (the field defaults to
/// `null`); the synthesized getter throws `UninitializedPropertyAccessException` when the field is still
/// `null`. The declared type is non-null but the JVM field is a plain (nullable-at-runtime) reference.
fn is_lateinit_prop(p: &ast::PropDecl) -> bool {
    p.is_lateinit
        && p.is_var
        && p.receiver.is_none()
        && p.init.is_none()
        && p.getter.is_none()
        && p.setter.is_none()
        && !p.is_abstract
        && p.ty.is_some()
}

/// A computed property `val x: T get() = expr` — a custom getter, no backing field (no initializer),
/// immutable (no setter). Compiled to a `getX()` accessor; reads call it.
/// The `Ty` of a body property: its explicit annotation, else inferred from the getter body (a computed
/// `val xx get() = x`) or the initializer.
fn body_prop_ty(
    file: &ast::File,
    info: &FrontendTypeInfo,
    p: &ast::PropDecl,
    plat: &dyn SemanticPlatform,
) -> Ty {
    let ty = if let Some(r) = p.ty.as_ref() {
        let base = ty_of(file, r, plat);
        // `ty_of` resolves only file-local types + built-ins; a CLASSPATH type (`ArrayList<Int>`) erases to
        // `kotlin/Any`. When the declared annotation is NOT `Any` yet erased to it, recover the concrete
        // type the checker resolved the initializer/getter against (which IS this annotation, classpath-
        // resolved) — so a top-level `val prop: ArrayList<Int>` backing field is `ArrayList`, not `Object`.
        if base.is_erased_top() && r.name != "Any" && r.name != "kotlin/Any" {
            if let Some(FunBody::Expr(g) | FunBody::Block(g)) = p.getter {
                return stored_value_ty(info.ty(g));
            }
            if let Some(i) = p.init {
                return stored_value_ty(info.ty(i));
            }
        }
        base
    } else if let Some(FunBody::Expr(g) | FunBody::Block(g)) = p.getter {
        info.ty(g)
    } else if let Some(i) = p.init {
        info.ty(i)
    } else {
        Ty::Error
    };
    stored_value_ty(ty)
}

fn stored_value_ty(ty: Ty) -> Ty {
    if ty == Ty::Unit {
        Ty::obj("kotlin/Unit")
    } else {
        ty
    }
}

fn body_prop_ir_ty(
    file: &ast::File,
    info: &FrontendTypeInfo,
    p: &ast::PropDecl,
    plat: &dyn SemanticPlatform,
) -> Ty {
    let ir = ty_to_ir(body_prop_ty(file, info, p, plat));
    if p.ty.as_ref().is_some_and(|r| r.nullable) {
        mark_nullable(ir)
    } else {
        ir
    }
}

fn is_computed_prop(p: &ast::PropDecl) -> bool {
    p.receiver.is_none()
        && !p.is_lateinit
        && !p.is_var
        && p.init.is_none()
        && p.getter.is_some()
        && p.setter.is_none()
        // A getter that reads `field` has a REAL backing field (assigned in a constructor), so it is
        // NOT a computed (field-less) property.
        && !p.getter_reads_field
    // The type may be inferred from the getter body (`val xx get() = x`) — no explicit annotation needed.
}

/// A body property with a real backing field — neither a computed property (custom getter, no field)
/// nor an `abstract` one (emitted as an abstract `getX()`, the field lives on the subclass) nor a
/// delegated one (`by Del()` — its field is the synthetic `x$delegate`, accessor calls `getValue`).
fn is_backing_field_prop(p: &ast::PropDecl) -> bool {
    // A `const val` is NEVER an instance backing field — Kotlin only allows `const` in an `object`,
    // `companion object`, or at top level, where it compiles to a `public static final` + `ConstantValue`
    // field (emitted on the static path) and every read is inlined. Excluding it here also suppresses the
    // `getX()` accessor (kotlinc emits none for a const).
    !p.is_const && !is_computed_prop(p) && !p.is_abstract && p.delegate.is_none()
}

/// A backing-field property whose accessor is CUSTOM and reads/writes `field` (`val x = init get() =
/// field…`, `var x = init set(v) { field = … }`). The backing field is emitted as usual; the
/// synthesized `getX`/`setX` run the custom body (with `field` bound to that field) instead of the
/// default field read/write.
fn is_field_accessor_prop(p: &ast::PropDecl) -> bool {
    is_backing_field_prop(p)
        // A backing field exists with an initializer, OR when a getter reads `field` (the field is
        // then assigned in a constructor instead of at the declaration).
        && (p.init.is_some() || p.getter_reads_field)
        && (p.getter.is_some() || p.setter.as_ref().is_some_and(|s| s.body.is_some()))
}

/// One active inlined-lambda parameter: `(param name, lambda parameter names, lambda body, lambda
/// parameter types, the inline fn's name — the implicit label for a `return@<fn>` local return)`.
type InlineLambda = (String, Vec<String>, AstExprId, Vec<Ty>, String);

/// Lowering info for a local delegated property (`val x by Del()` in a function body). Reads compile to
/// `<delegate>.getValue(null, propref)`, a `var`'s writes to `setValue(null, propref, value)`.
#[derive(Clone)]
struct LocalDelegate {
    /// Tree-backed internal name of the delegate type (owner of `getValue`/`setValue`).
    delegate_internal: TypeName,
    /// Resolved `getValue(Object, KProperty): T` signature.
    getvalue_sig: Signature,
    /// Resolved `setValue(Object, KProperty, value): Unit` signature — `None` for a `val`.
    setvalue_sig: Option<Signature>,
    /// The property name (for the inline `PropertyReference0Impl` metadata).
    name: String,
    /// The logical property return type.
    ret_ty: Ty,
}

/// Context for lowering a `tailrec` function into a `while(true)` loop.
#[derive(Clone)]
struct TailrecCtx {
    name: String,
    param_vals: Vec<u32>,
    param_tys: Vec<Ty>,
    label: String,
}

/// Options for the iterator-protocol for-each lowering: the `forEachIndexed` index-counter name,
/// the loop label, and whether the loop is a spliced stdlib HOF (`forEach`/`forEachIndexed`) —
/// which binds kotlinc's inline `$iv` locals (receiver, element, parameter) into the spill scope.
struct ForeachOpts<'a> {
    index: Option<&'a str>,
    label: Option<String>,
    hof_splice: bool,
}

pub(crate) struct Lower<'a> {
    afile: &'a ast::File,
    file_index: u32,
    info: &'a FrontendTypeInfo,
    syms: &'a FrontendSymbols,
    runtime: &'a dyn TargetRuntime,
    /// Caller-owned sink for the reason `lower_file_at` last returned `None` — a survey/box-corpus
    /// diagnostic, plus the internal `deep*`-phase refinement (formerly the `BAIL_REASON` thread-local).
    bail: &'a std::cell::RefCell<String>,
    ir: IrFile,
    /// Top-level function ids keyed by (name, parameter types) so overloads (same name,
    /// different params) each map to their own compiled method.
    fun_ids: HashMap<(String, Vec<Ty>), u32>,
    /// Top-level function ids keyed by source declaration id. This is the preferred path for
    /// checker-resolved module calls; the name/params map remains for older call sites during migration.
    fun_ids_by_decl: HashMap<crate::ast::DeclId, u32>,
    /// Top-level extension functions, keyed by `(erased receiver, name)` ([`Ty::erased_recv`]) —
    /// separate from `fun_ids` since `fun Int.foo()` and `fun String.foo()` share a name but differ by
    /// receiver. Same key scheme as `FrontendSymbols::ext_funs` so the two never disagree. Holds the FIRST
    /// overload's id (the common case is a single overload); an extension overloaded by arity is
    /// disambiguated at the call site through [`Self::ext_fun_id_by_arity`].
    ext_fun_ids: HashMap<(Ty, String), u32>,
    /// Every extension overload id keyed additionally by its logical parameter arity, so a call resolves
    /// `fun R.f()` vs `fun R.f(x)` to the right emitted static method. Filled alongside `ext_fun_ids`.
    ext_fun_id_by_arity: HashMap<(Ty, String, usize), u32>,
    /// Every extension overload id keyed by the full selected source signature. Source expressions whose
    /// checker handoff carries params use this instead of reselecting from receiver/name.
    ext_fun_id_by_sig: HashMap<(Ty, String, Vec<Ty>), u32>,
    /// Top-level extension PROPERTIES (`val/var Recv.name: T get() = … [set(v) = …]`), keyed by
    /// `(erased receiver, name)` → the synthesized static getter (`getName(Recv): T`) / setter
    /// (`setName(Recv, T)`) FunId.
    ext_prop_get_ids: HashMap<(Ty, String), u32>,
    /// `(outer class internal, companion `const val` name)` → its type. Such a const lives as a
    /// `public static final` field on the OUTER class; a `C.X` read lowers to `getstatic C.X`.
    companion_consts: HashMap<(TypeName, String), Ty>,
    /// Top-level `const val` name → its compile-time literal value. A same-file read inlines this as a
    /// constant (kotlinc's `ldc`), exactly like the reference compiler — byte-identical, no `getstatic`.
    const_lits: HashMap<String, crate::ir::IrConst>,
    /// `(object internal, const-val name)` → its compile-time literal value. A `const val` inside an
    /// `object` is inlined at every read (unqualified inside the object's own methods, or qualified
    /// `Obj.NAME`), exactly as kotlinc inlines it — so no `getstatic` is needed and a read during the
    /// object's own initialization can't observe an uninitialized field.
    object_const_lits: HashMap<(TypeName, String), crate::ir::IrConst>,
    ext_prop_set_ids: HashMap<(Ty, String), u32>,
    classes: HashMap<TypeName, ClassInfo>,
    /// Top-level property name → (index into `ir.statics`, type).
    statics: HashMap<String, (u32, Ty)>,
    scope: Vec<(String, u32, Ty)>,
    next_value: u32,
    /// The DECLARED element type for the immediately-following array-creating call, set by a NESTED-array
    /// local's initializer (`val x: Array<Array<*>> = arrayOf(arrayOf(1))`) so the OUTER array is built
    /// over the declared (wider) element `Array<*>` = `Object[]` — able to hold a later `arrayOf("OK")`.
    /// Consumed take-once by [`Lower::synth_array_elem`] (the inner `arrayOf(1)` keeps its own element). A
    /// `Cell` so the take-once read works through `&self`; save/restore guards a nested-array initializer.
    expected_array_elem: std::cell::Cell<Option<Ty>>,
    cur_class: Option<TypeName>,
    /// When lowering a property's custom accessor body (`get()`/`set()`), the property's backing field
    /// `(class_id, field_index, field_ir_type)` — so the `field` keyword reads/writes it. `None`
    /// outside an accessor body.
    cur_field: Option<(u32, u32, Ty)>,
    /// `(class internal, property name)` for every property with a CUSTOM accessor over a backing
    /// field. Such a property is read/written ONLY through `getX`/`setX` (even in-class) — never as a
    /// direct field — so `resolve_field` declines it (the `field` keyword reaches the field via
    /// `cur_field` instead).
    field_accessor_props: std::collections::HashSet<(TypeName, String)>,
    /// The subset of [`Self::field_accessor_props`] that are `var`s — their WRITE routes through the
    /// custom `setX`. A `val` custom-accessor property (no setter) is NOT here: it is assigned once
    /// in a constructor by writing its backing field directly.
    field_accessor_var_props: std::collections::HashSet<(TypeName, String)>,
    /// Name of the enclosing function/method being lowered — used to name synthesized lambda impl
    /// methods `<enclosing>$lambda$<n>` (matching kotlinc).
    cur_fn_name: String,
    /// Whether the enclosing function is `suspend`. A non-suspend function cannot call a suspend fn, so
    /// `&&`/`||` short-circuit safely there; inside a suspend body the right operand may carry a
    /// suspension that the CPS flattener models only at unconditional positions, so `&&`/`||` keep the
    /// eager (operands-unconditional) form there until the flattener models conditional suspension.
    cur_fn_suspend: bool,
    /// Type parameters in scope for the function body being lowered: `(name, bound, non_null)`. `bound`
    /// is the declared upper bound as an un-erased `IrType` (`kotlin/Any` when unbounded); `non_null`
    /// is set for a non-nullable bound (`<T : Any>`, `<T : Foo>`) — drives the `as T` null assertion.
    cur_tparams: Vec<(String, Ty, bool)>,
    /// Per-enclosing-function counter for lambda impl-method naming.
    lambda_seq: u32,
    /// Names of local `var`s in the current lowered body that need a shared mutable cell because a
    /// non-inlined closure captures them from an outer local scope.
    shared_cell_vars: std::collections::HashSet<String>,
    /// A boxed mutable-capture local's name → its element (unboxed) type. The scope holds the name
    /// bound to the `Ref$XxxRef` HOLDER value; reads/writes go through `RefGet`/`RefSet` with this type.
    boxed_elem: HashMap<String, Ty>,
    /// A local function's `StmtId` → its lifted static `FunId` (a private method on the facade). A
    /// checker-selected local-function call target lowers to `Callee::Local(fid)`.
    local_fun_ids: HashMap<crate::ast::StmtId, u32>,
    /// Return type of the function currently being lowered — used to coerce `return` values (e.g. a
    /// generic-erased `Object` return gets the `checkcast` kotlinc inserts).
    cur_ret_ty: Ty,
    /// True while lowering a method whose JVM return is the `kotlin/Unit` SINGLETON (a reference) rather
    /// than `void` — i.e. a `() -> Unit` lambda's closure method (its `invoke` returns `Object`). A
    /// valueless `return`/`return@lambda` there must push `Unit.INSTANCE` (`areturn`), not `return`
    /// (`void`), or the verifier rejects it ("method expects a return value"). A plain `Unit` function
    /// (`fun f(): Unit`) is a `void` method, so this stays false for it.
    cur_method_returns_unit_ref: bool,
    /// `finally` blocks of the enclosing `try`s (outermost first) whose protected region covers the
    /// statement being lowered. A `return` inside them must run each `finally` (innermost first) before
    /// transferring control — so the lowerer inlines them at the `return`. Pushed while a try-body/catch
    /// with a `finally` is lowered.
    try_finally_stack: Vec<AstExprId>,
    /// Outer-class internal name → its `C$Companion` internal name, for routing `C.foo()` calls.
    companions: HashMap<TypeName, TypeName>,
    /// Top-level computed property name → (its synthesized `getX()` `FunId`, property type). A read of
    /// the property compiles to a call to the getter. For a *computed* property there is no backing
    /// field; for a top-level backing-field property with a custom getter (`val x = init get() = field`)
    /// this routes reads through the custom `getX()` too (the field is in `statics`).
    computed_props: HashMap<String, (u32, Ty)>,
    /// Top-level backing-field property name → its synthesized `setX()` `FunId` (a custom `var` setter).
    /// A write of the name compiles to a call to `setX(value)` instead of a direct `putstatic`.
    computed_setters: HashMap<String, u32>,
    /// While lowering a top-level custom accessor body, the property's backing STATIC field
    /// (index into `ir.statics`, type) that the `field` keyword reads/writes (the static analogue of
    /// `cur_field`, which is for an instance field).
    cur_static_field: Option<(u32, Ty)>,
    /// `lateinit var` LOCALS in scope: value-index → source name. A read of such a local is wrapped in
    /// the uninitialized-check (`dup; ifnonnull L; throwUninitializedPropertyAccessException(name); L`),
    /// mirroring the member-field lateinit path. Captured lateinit locals are not modeled (the file
    /// bails — see `closure_captured_names`), so every entry here is a plain value slot read via
    /// `GetValue`.
    lateinit_locals: HashMap<u32, String>,
    /// Whether we are lowering a SUSPEND LAMBDA's body (the general lambda-mode machine): its
    /// `invokeSuspend` flattener models fewer shapes than a named fn's (no try/finally), so some
    /// splices (`withLock` with a non-suspending body) stay on their call-based fallback there.
    in_suspend_lambda_body: bool,
    /// Names referenced (read or written) inside a NON-inline closure (a non-inline lambda or a local
    /// function) in the body currently being lowered. A `lateinit var` local among them is not modeled
    /// (its slot / uninitialized-guard aren't threaded through the closure's captured representation), so
    /// such a file bails (skip, never miscompile). Inline-spliced lambdas keep their captures in the
    /// outer scope, so they are NOT collected here (an inline `run { x = … }` over a lateinit works).
    closure_captured_names: std::collections::HashSet<String>,
    /// Local delegated property name → its delegate info. A read of the name compiles to the delegate's
    /// `getValue` (a `var`'s write to `setValue`); there is no value slot for the property itself, only
    /// the synthesized `$delegate` local (its value index is held here).
    local_delegated: HashMap<String, LocalDelegate>,
    /// Active `tailrec` function being lowered: its (unqualified) name, the value indices of its
    /// parameters (to reassign), and their types. A tail-position `return f(args)` to this same function
    /// becomes "reassign the params, `continue` the wrapping `while(true)`" instead of a real call.
    cur_tailrec: Option<TailrecCtx>,
    /// Current expression-lowering recursion depth — guards against a stack overflow on a pathologically
    /// deep expression (a stress test with thousands of nested operators): past the limit, lowering
    /// bails (the file is skipped, never miscompiled or crashed).
    expr_depth: u32,
    /// Substitution of an AST expr id → an already-lowered IR value, consulted at the top of [`Self::expr`].
    /// Used for a compound index-assign (`a[i] op= v`): the parser desugars it to `a[i] = a[i] op v`
    /// REUSING the `array`/`index` expr ids, so a side-effecting receiver/index would be evaluated twice.
    /// The store spills each to a temp once and maps the shared id to a `GetValue(temp)` for the duration,
    /// so the embedded read and the write both load the temp (idempotent) instead of re-evaluating.
    index_subst: HashMap<AstExprId, u32>,
    /// Active inlined-lambda parameters while expanding an `inline fun` body, as a stack so nested
    /// inline calls compose: a call `param(args)` in the inline body inlines the lambda body in place.
    inline_lambdas: Vec<InlineLambda>,
    /// Call-site expression ids currently being inline-expanded. A genuinely recursive inline call
    /// re-enters the SAME call site (the `rec(n-1)` in `rec`'s own body), which would expand forever —
    /// so re-entering an active call id bails (the file skips). Source-level NESTING (`a { a { 5 } }`)
    /// uses DISTINCT call sites, so it is allowed. (kotlinc rejects only genuine recursion.)
    inline_active: Vec<u32>,
    /// Active reified type-parameter bindings while expanding a `<reified T>` inline fn: `T` → the
    /// call's actual type argument. Consulted by `subst_type_ref` so `is T`/`as T`/`T::class` in the
    /// inlined body specialize to the concrete type. A stack — nested reified inline calls compose.
    reified_subst: Vec<std::collections::HashMap<String, ast::TypeRef>>,
    /// Active inline-fn return targets while expanding an `inline fun` whose body has `return`: each is
    /// `(result slot, end label, return type)`. A `return x` in the inlined body lowers to `result = x;
    /// break@end` (the body is wrapped in a `do { … } while(false)` labeled `end`), turning the function
    /// return into a jump to the body's end. Innermost (`.last()`) is the enclosing inline fn; lambda
    /// args with returns are pre-bailed, so a `return` always belongs to the innermost inline body.
    inline_return: Vec<(u32, String, Ty)>,
    /// Active *labeled* lambda-return targets while splicing an inline lambda whose body contains a
    /// `return@<label>` (a local return from that lambda). Each is `(label, result slot, end label,
    /// return type, fn_tail)`: a `return@label x` lowers to `slot = x; break@end`, the spliced lambda
    /// body being wrapped in a `do { … } while(false)`. The label is the inline fn name the lambda was
    /// passed to. `fn_tail` marks a splice whose CALL is the enclosing function's tail expression —
    /// there a NON-LOCAL `return v` is equivalent to `return@label v` (the splice result IS the
    /// function result), so the return-lowering routes it through the frame instead of emitting a
    /// real `Return` the suspend flattener can't model inside the splice's `try`/`finally`.
    inline_lambda_ret: Vec<(String, u32, String, Ty, bool)>,
    /// The enclosing function's TAIL expression (an expression body, a block's trailing value, or the
    /// value of a final `return`), if any — the expression whose value is the function's result.
    /// Consulted by tail-position splice gates (`fn_tail` above).
    fn_body_tail: Option<AstExprId>,
}

impl<'a> Lower<'a> {
    /// Record why lowering last bailed, into the caller-owned `bail` sink (a survey diagnostic + the
    /// internal `deep*`-phase refinement). Replaces the former free `set_bail` thread-local write.
    fn set_bail(&self, reason: &str) {
        *self.bail.borrow_mut() = reason.to_string();
    }

    fn arg_tys(&self, args: &[AstExprId]) -> Vec<Ty> {
        args.iter().map(|&a| self.info.ty(a)).collect()
    }

    /// Candidate `(erased receiver, name)` keys for an extension-property lookup, most-specific first.
    /// A property with a type-parameter receiver (`val <T> T.p` / `val <T> Array<T>.p`) is registered
    /// under an `Any`-erased receiver, so a concrete receiver must fall back through the generalized
    /// keys to find it — mirroring [`FrontendSymbols::ext_prop`] so the checker and lowerer agree.
    fn ext_prop_keys(recv: Ty, name: &str) -> Vec<(Ty, String)> {
        recv.erased_recv_candidates()
            .into_iter()
            .map(|k| (k, name.to_string()))
            .collect()
    }

    fn ext_prop_get_id(&self, recv: Ty, name: &str) -> Option<u32> {
        Self::ext_prop_keys(recv, name)
            .into_iter()
            .find_map(|k| self.ext_prop_get_ids.get(&k).copied())
    }

    fn ext_prop_set_id(&self, recv: Ty, name: &str) -> Option<u32> {
        Self::ext_prop_keys(recv, name)
            .into_iter()
            .find_map(|k| self.ext_prop_set_ids.get(&k).copied())
    }

    /// Whether the LOWERED IR subtree at `e` contains a suspension point — a recorded cross-unit
    /// suspend call, or a call to a same-file `suspend` function. Stops at a nested `Lambda` (its
    /// body is a separate method). Used where kotlinc's evaluation order forces an already-pushed
    /// operand (a call receiver) into a continuation spill slot.
    fn ir_subtree_suspends(&self, e: u32) -> bool {
        if self.ir.suspend_calls.contains_key(&e) {
            return true;
        }
        match &self.ir.exprs[e as usize] {
            IrExpr::Call {
                callee: Callee::Local(fid),
                ..
            } if self.ir.suspend_funs.contains(fid) => return true,
            IrExpr::MethodCall { class, index, .. } => {
                if self.ir.classes[*class as usize]
                    .methods
                    .get(*index as usize)
                    .is_some_and(|fid| self.ir.suspend_funs.contains(fid))
                {
                    return true;
                }
            }
            IrExpr::Lambda { .. } => return false,
            _ => {}
        }
        let mut found = false;
        crate::ir::for_each_child(&self.ir.exprs, e, &mut |c| {
            if !found && self.ir_subtree_suspends(c) {
                found = true;
            }
        });
        found
    }

    fn emit_library_member_call(
        &mut self,
        recv: u32,
        owner_fallback: TypeName,
        member: crate::libraries::LibraryMember,
        logical_ret: Ty,
        suspend: bool,
        args: Vec<u32>,
    ) -> u32 {
        let owner = member.owner_type_or(owner_fallback);
        let interface = member.is_interface || self.library_type_is_interface(owner);
        // kotlinc pushes the receiver BEFORE evaluating arguments; an argument that suspends forces
        // the pushed receiver into a continuation spill slot (an unnamed temp local in its
        // bytecode). Mirror it with a temp in the spill scope: `val tmp = recv; tmp.m(<arg>)`.
        if self.cur_fn_suspend && args.iter().any(|&a| self.ir_subtree_suspends(a)) {
            let rv = self.fresh_value();
            let decl = self.emit_named_variable(rv, ty_to_ir(Ty::obj_name(owner)), Some(recv));
            let recv_g = self.emit_get_value(rv);
            let call = self.emit_virtual_call(
                owner,
                member.name,
                member.descriptor,
                interface,
                recv_g,
                args,
            );
            if suspend {
                self.ir.suspend_calls.insert(call, ty_to_ir(logical_ret));
            }
            return self.emit_block(vec![decl], Some(call));
        }
        let call =
            self.emit_virtual_call(owner, member.name, member.descriptor, interface, recv, args);
        if suspend {
            self.ir.suspend_calls.insert(call, ty_to_ir(logical_ret));
        }
        call
    }

    fn emit_virtual_call(
        &mut self,
        owner: impl Into<TypeName>,
        name: String,
        descriptor: String,
        interface: bool,
        recv: u32,
        args: Vec<u32>,
    ) -> u32 {
        self.emit_call(
            Callee::Virtual {
                owner: owner.into(),
                name,
                descriptor,
                interface,
            },
            Some(recv),
            args,
        )
    }

    fn emit_library_static_call(
        &mut self,
        callable: crate::libraries::LibraryCallable,
        args: Vec<u32>,
        record_suspend: bool,
    ) -> u32 {
        let logical_ret = callable.ret;
        let call = self.emit_static_call(
            callable.owner_type(),
            callable.name,
            callable.descriptor,
            callable.inline,
            args,
        );
        if record_suspend {
            self.ir.suspend_calls.insert(call, ty_to_ir(logical_ret));
        }
        call
    }

    fn emit_static_call(
        &mut self,
        owner: impl Into<TypeName>,
        name: String,
        descriptor: String,
        inline: InlineKind,
        args: Vec<u32>,
    ) -> u32 {
        self.emit_call(
            Callee::Static {
                owner: owner.into(),
                name,
                descriptor,
                inline,
            },
            None,
            args,
        )
    }

    fn emit_local_call(&mut self, fid: u32, args: Vec<u32>) -> u32 {
        self.emit_call(Callee::Local(fid), None, args)
    }

    fn emit_local_default_call(&mut self, fid: u32, args: Vec<u32>) -> u32 {
        self.emit_call(Callee::LocalDefault(fid), None, args)
    }

    fn emit_method_call(
        &mut self,
        class: u32,
        index: u32,
        receiver: u32,
        args: Vec<Option<u32>>,
    ) -> u32 {
        self.ir.add_expr(IrExpr::MethodCall {
            class,
            index,
            receiver,
            args,
        })
    }

    fn emit_external_call(
        &mut self,
        symbol: impl Into<String>,
        dispatch_receiver: Option<u32>,
        args: Vec<u32>,
    ) -> u32 {
        self.emit_call(Callee::External(symbol.into()), dispatch_receiver, args)
    }

    fn emit_cross_file_call(
        &mut self,
        facade: TypeName,
        name: String,
        params: Vec<Ty>,
        ret: Ty,
        args: Vec<u32>,
    ) -> u32 {
        self.emit_call(
            Callee::CrossFile {
                facade,
                name,
                params,
                ret,
            },
            None,
            args,
        )
    }

    fn emit_call(&mut self, callee: Callee, dispatch_receiver: Option<u32>, args: Vec<u32>) -> u32 {
        self.ir.add_expr(IrExpr::Call {
            callee,
            dispatch_receiver,
            args,
        })
    }

    fn emit_new(&mut self, class: u32, args: Vec<u32>, ctor_params: Option<Vec<Ty>>) -> u32 {
        self.ir.add_expr(IrExpr::New {
            class,
            args,
            ctor_params,
        })
    }

    fn emit_new_external(
        &mut self,
        internal: impl AsRef<str>,
        ctor_desc: impl Into<String>,
        args: Vec<u32>,
    ) -> u32 {
        self.ir.new_external(internal.as_ref(), ctor_desc, args)
    }

    fn emit_const(&mut self, value: IrConst) -> u32 {
        self.ir.add_expr(IrExpr::Const(value))
    }

    fn emit_zero_value(&mut self, ty: Ty) -> u32 {
        self.emit_const(IrConst::zero_for_value_type(self.runtime.ir_value_type(ty)))
    }

    fn emit_unit(&mut self) -> u32 {
        self.ir.add_expr(IrExpr::UnitInstance)
    }

    fn emit_class_const(&mut self, internal: String) -> u32 {
        if internal.is_empty() {
            self.ir.class_const(None)
        } else {
            self.ir.class_const(Some(&internal))
        }
    }

    fn emit_new_array(&mut self, array_type: Ty, size: u32) -> u32 {
        self.ir.add_expr(IrExpr::NewArray { array_type, size })
    }

    fn emit_vararg(&mut self, array_type: Ty, elements: Vec<u32>) -> u32 {
        self.ir.add_expr(IrExpr::Vararg {
            array_type,
            elements,
        })
    }

    fn emit_static_instance(&mut self, owner: u32, ty: u32, field: &'static str) -> u32 {
        self.ir
            .add_expr(IrExpr::StaticInstance { owner, ty, field })
    }

    fn emit_get_field(&mut self, receiver: u32, class: u32, index: u32) -> u32 {
        self.ir.add_expr(IrExpr::GetField {
            receiver,
            class,
            index,
        })
    }

    fn emit_get_value(&mut self, index: u32) -> u32 {
        self.ir.add_expr(IrExpr::GetValue(index))
    }

    fn emit_variable(&mut self, index: u32, ty: Ty, init: Option<u32>) -> u32 {
        self.ir.add_expr(IrExpr::Variable {
            index,
            ty,
            init,
            named: false,
        })
    }

    /// A NAMED source variable declaration (`val x = …`, a destructuring component, a loop
    /// variable) — the suspend state machine spills these by SCOPE, not liveness (see
    /// `IrExpr::Variable::named`).
    fn emit_named_variable(&mut self, index: u32, ty: Ty, init: Option<u32>) -> u32 {
        self.ir.add_expr(IrExpr::Variable {
            index,
            ty,
            init,
            named: true,
        })
    }

    fn emit_set_value(&mut self, var: u32, value: u32) -> u32 {
        self.ir.add_expr(IrExpr::SetValue { var, value })
    }

    fn emit_type_op(&mut self, op: IrTypeOp, arg: u32, type_operand: Ty) -> u32 {
        self.ir.add_expr(IrExpr::TypeOp {
            op,
            arg,
            type_operand,
        })
    }

    fn emit_primitive_bin_op(&mut self, op: IrBinOp, lhs: u32, rhs: u32) -> u32 {
        self.ir.add_expr(IrExpr::PrimitiveBinOp { op, lhs, rhs })
    }

    fn emit_set_field(&mut self, receiver: u32, class: u32, index: u32, value: u32) -> u32 {
        self.ir.add_expr(IrExpr::SetField {
            receiver,
            class,
            index,
            value,
        })
    }

    fn emit_get_static(&mut self, index: u32) -> u32 {
        self.ir.add_expr(IrExpr::GetStatic(index))
    }

    fn emit_set_static(&mut self, index: u32, value: u32) -> u32 {
        self.ir.add_expr(IrExpr::SetStatic { index, value })
    }

    fn emit_return(&mut self, value: Option<u32>) -> u32 {
        self.ir.add_expr(IrExpr::Return(value))
    }

    fn emit_block(&mut self, stmts: Vec<u32>, value: Option<u32>) -> u32 {
        self.ir.add_expr(IrExpr::Block { stmts, value })
    }

    fn emit_when(&mut self, branches: Vec<(Option<u32>, u32)>) -> u32 {
        self.ir.add_expr(IrExpr::When { branches })
    }

    fn emit_while(
        &mut self,
        cond: u32,
        body: u32,
        update: Option<u32>,
        post_test: bool,
        label: Option<String>,
    ) -> u32 {
        self.ir.add_expr(IrExpr::While {
            cond,
            body,
            update,
            post_test,
            label,
        })
    }

    fn emit_break(&mut self, label: Option<String>) -> u32 {
        self.ir.add_expr(IrExpr::Break { label })
    }

    fn emit_continue(&mut self, label: Option<String>) -> u32 {
        self.ir.add_expr(IrExpr::Continue { label })
    }

    fn emit_throw(&mut self, operand: u32) -> u32 {
        self.ir.add_expr(IrExpr::Throw { operand })
    }

    fn emit_try(
        &mut self,
        body: u32,
        catches: Vec<IrCatch>,
        finally: Option<u32>,
        result: Ty,
    ) -> u32 {
        self.ir.add_expr(IrExpr::Try {
            body,
            catches,
            finally,
            result,
        })
    }

    fn emit_external_static_field(
        &mut self,
        owner: impl Into<String>,
        name: impl Into<String>,
        descriptor: impl Into<String>,
    ) -> u32 {
        let owner = owner.into();
        self.ir.external_static_field(&owner, name, descriptor)
    }

    /// Returns the already-checked `getValue` target for a delegated property.
    fn delegate_getvalue_info(
        &self,
        delegate_expr: AstExprId,
        delegate_internal: TypeName,
    ) -> Option<(TypeName, String, Ty, InlineKind, bool)> {
        // Property-reference delegates need dedicated bytecode support.
        if delegate_internal.starts_with("kotlin/reflect/") {
            return None;
        }
        match self.info.delegate_getvalue(delegate_expr)? {
            DelegateGetValueTarget::Member { owner, params, ret } => {
                let desc = self.runtime.method_descriptor(params, *ret)?;
                Some((*owner, desc, *ret, InlineKind::None, false))
            }
            DelegateGetValueTarget::Extension(c) => {
                Some((c.owner, c.descriptor.clone(), c.ret, c.inline, true))
            }
        }
    }

    fn scalar_value_repr(&self, ty: Ty) -> Option<Ty> {
        self.runtime.scalar_value_repr(ty)
    }

    fn has_scalar_value_repr(&self, ty: Ty) -> bool {
        self.scalar_value_repr(ty).is_some()
    }

    /// Box `arg` (the lowered value of `operand`) when the operand is a PRIMITIVE, so it can feed a
    /// JVM `instanceof` (which needs a reference; a raw scalar VerifyErrors). Uses the operand's ACTUAL
    /// representation — an inline body specializes a generic type parameter to a primitive in its SLOT
    /// even though the checker's `info.ty` still reports the erased reference — so a bare name consults
    /// its scope slot type. A reference operand is returned unchanged.
    fn box_operand_for_instanceof(&mut self, operand: AstExprId, arg: u32) -> u32 {
        let operand_repr = match self.afile.expr(operand) {
            Expr::Name(n) => self
                .lookup(n)
                .map(|(_, t)| t)
                .unwrap_or(self.info.ty(operand)),
            _ => self.info.ty(operand),
        };
        if self.has_scalar_value_repr(operand_repr) && !operand_repr.is_reference() {
            self.emit_type_op(
                IrTypeOp::ImplicitCoercion,
                arg,
                ty_to_ir(Ty::obj("kotlin/Any")),
            )
        } else {
            arg
        }
    }

    fn unsigned_integer_box_type(&self, ty: Ty) -> Option<Ty> {
        self.runtime.unsigned_integer_box_type(ty)
    }

    fn scalar_one_const(&self, ty: Ty) -> Option<IrConst> {
        Some(match self.scalar_value_repr(ty)?.int_arithmetic_repr() {
            Ty::Int => IrConst::Int(1),
            Ty::Long => IrConst::Long(1),
            Ty::Double => IrConst::Double(1.0),
            Ty::Float => IrConst::Float(1.0),
            _ => return None,
        })
    }

    /// Build a call to a user `inc`/`dec` MEMBER operator on a variable (`x.inc()`), given the
    /// variable's IR slot and type — used to desugar an overloaded `x++`/`x--` to `x = x.inc()`.
    /// `None` when the type has no such member operator (numeric, or an extension operator).
    fn lower_member_inc_dec(&mut self, var_slot: u32, ty: Ty, dec: bool) -> Option<ExprId> {
        if ty.is_numeric_or_char() {
            return None;
        }
        // A value class's `inc`/`dec` is realized by the value_classes pass over its unboxed form —
        // a plain member call here would VerifyError. Bail (the file skips) — value-class logic stays
        // in value_classes.rs (rule 4).
        if self.value_class_underlying(ty).is_some() {
            return None;
        }
        let op = if dec { "dec" } else { "inc" };
        // Member operator on the (non-null) receiver type.
        if let Some(internal) = ty.obj_internal().map(|s| s.to_string()) {
            if let Some((class, index, _, _)) = self.resolve_method(&internal, op) {
                let recv = self.emit_get_value(var_slot);
                return Some(self.emit_method_call(class, index, recv, vec![]));
            }
        }
        // Top-level extension operator (`operator fun T?.inc()`). Only for a REFERENCE receiver — a
        // nullable-primitive extension (`Int?.inc`) boxes wrong here and risks the recursion the
        // checker guards, so leave those to skip.
        if ty.erased_recv().is_reference() {
            if let Some(&fid) = self.ext_fun_ids.get(&(ty.erased_recv(), op.to_string())) {
                let recv = self.emit_get_value(var_slot);
                return Some(self.emit_local_call(fid, vec![recv]));
            }
        }
        None
    }

    fn implicit_coercion(&mut self, arg: u32, ty: Ty) -> u32 {
        self.emit_type_op(IrTypeOp::ImplicitCoercion, arg, ty_to_ir(ty))
    }

    fn scalar_update_value(&mut self, current: u32, ty: Ty, op: IrBinOp, one: IrConst) -> u32 {
        let arithmetic_ty = ty.int_arithmetic_repr();
        let lhs = if arithmetic_ty != ty {
            self.implicit_coercion(current, arithmetic_ty)
        } else {
            current
        };
        let rhs = self.emit_const(one);
        let sum = self.emit_primitive_bin_op(op, lhs, rhs);
        if arithmetic_ty != ty {
            self.implicit_coercion(sum, ty)
        } else {
            sum
        }
    }

    /// The class-constant name for an UNBOUND class literal `T::class` (`ldc <name>.class`): the JVM
    /// internal of a reference type (`kotlin/String` → `java/lang/String`), or the array descriptor used
    /// verbatim as a class constant (`Array<Any>::class` → `[Ljava/lang/Object;`).
    fn class_literal_ldc_internal(&self, ty: Ty) -> Option<String> {
        let d = self.runtime.type_descriptor(ty)?;
        Some(
            match d.strip_prefix('L').and_then(|s| s.strip_suffix(';')) {
                Some(inner) => inner.to_string(),
                None => d,
            },
        )
    }

    fn compare_ordered(&mut self, ty: Ty, op: IrBinOp, lhs: u32, rhs: u32) -> Option<u32> {
        if ty.is_unsigned() {
            let call = self.runtime_call(RuntimeOp::UnsignedCompare, ty, vec![lhs, rhs])?;
            let zero = self.emit_const(IrConst::Int(0));
            Some(self.emit_primitive_bin_op(op, call, zero))
        } else {
            Some(self.emit_primitive_bin_op(op, lhs, rhs))
        }
    }

    fn runtime_call(&mut self, op: RuntimeOp, ty: Ty, args: Vec<u32>) -> Option<u32> {
        let c = self.runtime.runtime_callable(op, ty)?;
        Some(self.emit_library_static_call(c, args, false))
    }

    fn platform_static_field(&mut self, field: PlatformField) -> u32 {
        self.emit_external_static_field(field.owner, field.name, field.descriptor)
    }

    /// Lower a bare-name call to a classpath `object` member imported unqualified (`import Obj.m; m(args)`,
    /// recorded by the checker as [`ExprLowering::ObjectMemberCall`]). Reads the singleton
    /// (`getstatic Obj.INSTANCE`) as the dispatch receiver and invokes the member — the same shape a
    /// qualified `Obj.m(args)` lowers to. `call_expr` is the AST call, for generic-return coercion.
    fn lower_object_member_call(
        &mut self,
        internal: TypeName,
        name: &str,
        args: &[AstExprId],
        call_expr: AstExprId,
    ) -> Option<u32> {
        // A SAME-FILE object or companion: read the singleton (`Obj.INSTANCE` or `C.Companion`) and
        // invoke the recorded member on it. The classpath path below needs a library type.
        if let Some(ci) = self.class_info_name(internal) {
            let cid = ci.id;
            let (class_id, index, fid, ret) = self.resolve_method_name(internal, name)?;
            let params = self.ir.functions[fid as usize].params.clone();
            if params.len() != args.len() {
                return None;
            }
            let recv = if self.ir.classes[cid as usize].is_object {
                self.emit_static_instance(cid, cid, "INSTANCE")
            } else if self.ir.classes[cid as usize].is_companion {
                let internal_name = internal.render();
                let outer = internal_name.strip_suffix("$Companion")?;
                let field =
                    self.runtime
                        .companion_instance_field(outer, &internal_name, "Companion")?;
                self.platform_static_field(field)
            } else {
                return None;
            };
            let mut a: Vec<Option<u32>> = Vec::with_capacity(args.len());
            for (&arg, pt) in args.iter().zip(&params) {
                a.push(Some(self.lower_arg(arg, pt)?));
            }
            let mc = self.emit_method_call(class_id, index, recv, a);
            return Some(self.coerce_generic_read(mc, call_expr, ret));
        }
        let internal_name = internal.render();
        let resolved = self.info.resolved_member(call_expr).cloned()?;
        let m = resolved.member;
        if m.name != name || m.params.len() != args.len() {
            return None;
        }
        let field = self.runtime.object_instance_field(&internal_name)?;
        let recv = self.platform_static_field(field);
        let mut a = Vec::new();
        for (i, &arg) in args.iter().enumerate() {
            match m.params.get(i) {
                Some(p) => a.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                None => a.push(self.expr(arg)?),
            }
        }
        let ret = resolved.ret;
        let suspend = resolved.suspend;
        let physical_ret = m.physical_ret;
        let call = self.emit_library_member_call(recv, internal, m, ret, suspend, a);
        let call = self.coerce_to_static(call, ret, physical_ret);
        Some(self.coerce_generic_read(call, call_expr, ret))
    }

    fn mutable_local_ref_type(&self, elem: Ty) -> Option<Ty> {
        self.runtime.mutable_local_ref_type(elem)
    }

    /// The `Ref` element type for a mutable value-class local captured by a closure. A value class is
    /// stored UNBOXED as its underlying (a primitive `Z(Int)` → `Ref$IntRef`; a non-null reference value
    /// class holds its underlying) — EXCEPT a NULLABLE reference-underlying value class (`Result<T>?`),
    /// which is represented BOXED: keep its value-class type so the box/unbox pass recognises the boxed
    /// value through the `Ref` (and `x!!` unboxes it).
    fn shared_cell_elem_ty(&self, kty: Ty) -> Ty {
        match self.value_class_underlying(kty) {
            Some(u) if kty.is_nullable() && self.runtime.scalar_value_repr(u).is_none() => kty,
            Some(u) => u,
            None => kty,
        }
    }

    fn property_reference_impl(&self, arity: usize, mutable: bool) -> Option<PlatformCtor> {
        self.runtime.property_reference_impl(arity, mutable)
    }

    fn property_reference_signature(&self, getter_name: &str, ret: Ty) -> Option<String> {
        self.runtime.property_reference_signature(getter_name, ret)
    }

    fn library_type_is_interface(&self, internal: TypeName) -> bool {
        self.syms
            .libraries
            .resolve_type_name(internal)
            .is_some_and(|t| t.is_interface())
    }

    fn insert_class_info(&mut self, internal: &str, mut info: ClassInfo) -> Option<ClassInfo> {
        let name = type_name(internal);
        info.internal = name;
        self.classes.insert(name, info)
    }

    fn class_info(&self, internal: &str) -> Option<&ClassInfo> {
        existing_type_name(internal).and_then(|name| self.classes.get(&name))
    }

    fn class_info_mut(&mut self, internal: &str) -> Option<&mut ClassInfo> {
        existing_type_name(internal).and_then(|name| self.classes.get_mut(&name))
    }

    fn class_info_name_mut(&mut self, internal: TypeName) -> Option<&mut ClassInfo> {
        self.classes.get_mut(&internal)
    }

    fn class_info_name(&self, internal: TypeName) -> Option<&ClassInfo> {
        self.classes.get(&internal)
    }

    fn contains_class(&self, internal: &str) -> bool {
        existing_type_name(internal).is_some_and(|name| self.classes.contains_key(&name))
    }

    fn contains_class_name(&self, internal: TypeName) -> bool {
        self.classes.contains_key(&internal)
    }

    /// Whether the current module declares a top-level function `name` (shadow-precedence test) — asked
    /// through the module source rather than touching `syms.funs` directly.
    fn module_declares(&self, name: &str) -> bool {
        crate::module_symbols::ModuleSymbols::new(self.syms).declares_top_level(name)
    }
    fn fresh_value(&mut self) -> u32 {
        let v = self.next_value;
        self.next_value += 1;
        v
    }

    /// The parameter types of a class's superclass constructor (`super(args)` targets these). Empty for
    /// `java/lang/Object` or a base whose IR class isn't in this file (then we can't model the call).
    fn super_ctor_param_tys(&self, internal: &str) -> Vec<Ty> {
        self.super_class(internal)
            .map(|sup| sup.id)
            .map(|sid| {
                let sup = &self.ir.classes[sid as usize];
                if sup.ctor_args.is_empty() {
                    let n = sup.ctor_param_count as usize;
                    sup.fields[..n].iter().map(|f| f.ty.clone()).collect()
                } else {
                    sup.ctor_args.iter().map(|a| a.ty).collect()
                }
            })
            .unwrap_or_default()
    }

    /// Candidate base-`<init>` signatures a `super(...)` may target: the base's primary constructor
    /// (when it has one) plus every base SECONDARY constructor (a base with no primary constructor
    /// exposes only these). The caller matches the `super(...)` argument arity against these to pick
    /// the base `<init>` to call.
    fn super_ctor_candidate_tys(&self, internal: &str) -> Vec<Vec<Ty>> {
        let Some(sid) = self.super_class(internal).map(|sup| sup.id) else {
            return Vec::new();
        };
        let sup = &self.ir.classes[sid as usize];
        let mut out = Vec::new();
        if sup.has_primary_ctor {
            out.push(if sup.ctor_args.is_empty() {
                let n = sup.ctor_param_count as usize;
                sup.fields[..n].iter().map(|f| f.ty.clone()).collect()
            } else {
                sup.ctor_args.iter().map(|a| a.ty).collect()
            });
        }
        for sc in &sup.secondary_ctors {
            out.push(sc.params.clone());
        }
        out
    }

    fn super_class(&self, internal: &str) -> Option<&ClassInfo> {
        self.class_info(internal)?
            .super_internal
            .and_then(|s| self.class_info_name(s))
    }

    /// Lower a class's body-property initializers + `init {}` blocks (source order) into IR effect
    /// statements, assuming `this` (and any constructor params) are already in scope and value numbering
    /// continues from `self.next_value`. Returns `None` on an unsupported initializer shape (a branchy
    /// value initializer in a constructor). Used by both the primary `<init>` and each `super(...)`-
    /// reaching secondary constructor of a no-primary class.
    fn lower_class_init_steps(&mut self, c: &ast::ClassDecl, class_id: u32) -> Option<Vec<ExprId>> {
        let ctor_count = self.ir.classes[class_id as usize].ctor_param_count;
        let this_v = self
            .scope
            .iter()
            .find_map(|(n, v, _)| (n == "this").then_some(*v))?;
        let mut stmts = Vec::new();
        for step in &c.init_order {
            match step {
                ast::ClassInit::PropInit(i) => {
                    if !is_backing_field_prop(&c.body_props[*i]) || c.body_props[*i].init.is_none()
                    {
                        continue;
                    }
                    let body_offset = c.body_props[..*i]
                        .iter()
                        .filter(|p| is_backing_field_prop(p))
                        .count();
                    let field_idx = ctor_count + body_offset as u32;
                    let field_ty = self.ir.classes[class_id as usize].fields[field_idx as usize]
                        .ty
                        .clone();
                    let init_e = c.body_props[*i].init.unwrap();
                    // kotlinc elides a field initializer that stores the field's JVM default value — a
                    // base-class constructor's virtual call may have already written the field, and a
                    // default-value store would clobber it (see `fieldInitializerOptimization`).
                    if ast_init_is_jvm_default(self.afile, init_e) {
                        continue;
                    }
                    if matches!(
                        self.afile.expr(init_e),
                        Expr::When { .. }
                            | Expr::If { .. }
                            | Expr::Elvis { .. }
                            | Expr::Block { .. }
                            | Expr::Try { .. }
                    ) {
                        return None;
                    }
                    let val = self.lower_arg(init_e, &field_ty)?;
                    let recv = self.emit_get_value(this_v);
                    stmts.push(self.emit_set_field(recv, class_id, field_idx, val));
                }
                ast::ClassInit::Block(e) => {
                    let Expr::Block {
                        stmts: bs,
                        trailing,
                    } = self.afile.expr(*e).clone()
                    else {
                        return None;
                    };
                    for &s in &bs {
                        let branchy = match self.afile.stmt(s) {
                            Stmt::Assign { value, .. } | Stmt::AssignMember { value, .. } => {
                                body_contains_branch(self.afile, *value)
                            }
                            Stmt::Local { init, .. } => body_contains_branch(self.afile, *init),
                            _ => false,
                        };
                        if branchy {
                            return None;
                        }
                    }
                    for s in bs {
                        stmts.push(self.stmt(s)?);
                    }
                    if let Some(t) = trailing {
                        stmts.push(self.expr(t)?);
                    }
                }
            }
        }
        Some(stmts)
    }

    // ---- Builder surface for the synthetic registry (`crate::synthetics`) ------------------------
    // A synthetic's IR-override body builds its IR against the active `Lower` through these. Kept thin
    // so the registry (not lowering) owns each synthetic's body.

    /// Append an IR expression, returning its id.
    pub(crate) fn emit(&mut self, e: IrExpr) -> ExprId {
        self.ir.add_expr(e)
    }

    /// Lower an argument expression in value position (no target-element coercion).
    pub(crate) fn synth_expr(&mut self, e: AstExprId) -> Option<ExprId> {
        self.expr(e)
    }

    /// Whether `e` lowers with control flow (records a stackmap frame) — a synthetic that builds a
    /// value on the stack declines such an element rather than strand operands across the frame.
    pub(crate) fn synth_is_branchy(&self, e: AstExprId) -> bool {
        is_branchy(self.afile, e)
    }

    /// The element type of an array-creating call (`arrayOf`/`arrayOfNulls<T>`/`Array<T>(n){}`/
    /// `emptyArray<T>()`). Prefers the call's explicit type argument resolved through `ty_ref` — so a
    /// reified `T` inside an expanded `<reified T>` inline body specializes the element (`new String[]`,
    /// not the erased `Object[]`); falls back to the checker-inferred `Array<T>` element otherwise.
    pub(crate) fn synth_array_elem(&self, call: AstExprId) -> Option<Ty> {
        // A nested-array local's outermost array creation uses the DECLARED (wider) element — see
        // `expected_array_elem`. Take-once, so only the outermost creation consumes it.
        if let Some(t) = self.expected_array_elem.take() {
            return Some(t);
        }
        if let Some(t) = self
            .afile
            .call_type_args
            .get(&call.0)
            .and_then(|ts| ts.first())
            .and_then(|tr| self.ty_ref(tr))
        {
            return Some(t);
        }
        self.info.ty(call).array_elem()
    }

    /// Build a fresh `PropertyReference0Impl(<facade>::class, name, "name()<ret>", 0)` for a local
    /// delegated property's `getValue`/`setValue` call (the `KProperty` argument). The enclosing facade
    /// is the empty-internal `ClassConst` sentinel (resolved to `self.facade` at emit).
    fn make_local_propref(&mut self, ld: &LocalDelegate) -> Option<ExprId> {
        let propref_impl = self.property_reference_impl(0, false)?;
        let cls = self.emit_class_const(String::new());
        let nm = self.ir_const_str(ld.name.clone());
        let getter_name = property_getter_name(&ld.name);
        let signature = self.property_reference_signature(&getter_name, ld.ret_ty)?;
        let sig = self.ir_const_str(signature);
        let flag = self.emit_const(IrConst::Int(0));
        Some(self.emit_new_external(
            propref_impl.internal,
            propref_impl.ctor_desc,
            vec![cls, nm, sig, flag],
        ))
    }

    /// Lower a top-level delegated property `val x: T by Del()` (pass 2). Model: two synthetic statics —
    /// `x$delegate: Del` (init = the delegate expression) and `x$kprop: KProperty` (init = an inline
    /// `PropertyReference0Impl(Facade::class, "x", "getX()<ret>", 1)`) — plus a `getX()` body that calls
    /// `x$delegate.getValue(null, x$kprop)`. Reads of `x` route to `getX()` via `computed_props` (set in
    /// pass 1c). Returns `None` (skips the file) if `getValue` can't be resolved on the delegate type.
    /// (kotlinc keeps the `KProperty`s in one `$$delegatedProperties` array; the per-prop field here is
    /// runtime-equivalent — a byte-parity nicety to revisit.)
    fn lower_delegated_top_level(&mut self, p: &ast::PropDecl) -> Option<()> {
        let delegate_expr = p.delegate?;
        let delegate_ty = self.info.ty(delegate_expr);
        let delegate_internal = delegate_ty.obj_internal()?;
        // If the delegate's `getValue` reflects on its `KProperty` parameter (`p.name`, `p.returnType`,
        // `p.toString()`, …), correctness needs the synthesized property reference to resolve through the
        // facade's `@Metadata` — which krusty doesn't emit for delegated properties. Skip rather than
        // miscompile. A `getValue` that ignores the property parameter is unaffected.
        if delegate_getvalue_uses_property(self.afile, delegate_internal) {
            return None;
        }
        // `getValue` is a MEMBER operator on the delegate, or a classpath EXTENSION operator
        // (`operator fun Lazy<T>.getValue(...)` in `LazyKt`, `@InlineOnly` → `this.value`).
        let (gv_owner, gv_desc, gv_ret, gv_inline, gv_is_ext) =
            self.delegate_getvalue_info(delegate_expr, delegate_internal)?;
        let prop_ty =
            p.ty.as_ref()
                .map(|r| ty_of(self.afile, r, &*self.syms.libraries))
                .unwrap_or(gv_ret);

        // x$delegate: Del — init = lowered delegate expression.
        let delegate_ir = ty_to_ir(delegate_ty);
        let init_d = self.lower_arg(delegate_expr, &delegate_ir)?;
        let idx_d = self.ir.statics.len() as u32;
        self.ir.statics.push(crate::ir::IrStatic {
            visibility: crate::types::Visibility::Public,
            name: format!("{}$delegate", p.name),
            owner: None,
            ty: delegate_ir,
            init: init_d,
            is_var: false,
            is_const: false,
            custom_accessor: false,
        });

        // x$kprop: KProperty — init = new PropertyReference0Impl(Facade::class, "x", "getX()<ret>", 1).
        let facade_cls = self.emit_class_const(String::new());
        let name_c = self.ir_const_str(p.name.clone());
        let getter_name = property_getter_name(&p.name);
        let sig_str = self.property_reference_signature(&getter_name, prop_ty)?;
        let sig_c = self.ir_const_str(sig_str);
        let flag_c = self.emit_const(IrConst::Int(1));
        let propref_impl = self.property_reference_impl(0, false)?;
        let propref = self.emit_new_external(
            propref_impl.internal,
            propref_impl.ctor_desc,
            vec![facade_cls, name_c, sig_c, flag_c],
        );
        let kprop_ty = ty_to_ir(Ty::obj("kotlin/reflect/KProperty"));
        let idx_p = self.ir.statics.len() as u32;
        self.ir.statics.push(crate::ir::IrStatic {
            visibility: crate::types::Visibility::Public,
            name: format!("{}$kprop", p.name),
            owner: None,
            ty: kprop_ty,
            init: propref,
            is_var: false,
            is_const: false,
            custom_accessor: false,
        });

        // getX(): a member → `x$delegate.getValue(null, x$kprop)`; an extension → the static
        // `getValue(x$delegate, null, x$kprop)`.
        let get_d = self.emit_get_static(idx_d);
        let null_a = self.emit_const(IrConst::Null);
        let get_p = self.emit_get_static(idx_p);
        let call = if gv_is_ext {
            self.emit_static_call(
                gv_owner,
                "getValue".to_string(),
                gv_desc,
                gv_inline,
                vec![get_d, null_a, get_p],
            )
        } else {
            let is_iface = self
                .syms
                .class_by_type_name(delegate_internal)
                .map(|c| c.is_interface)
                .unwrap_or(false);
            self.emit_virtual_call(
                gv_owner,
                "getValue".to_string(),
                gv_desc,
                is_iface,
                get_d,
                vec![null_a, get_p],
            )
        };
        let ret = self.emit_return(Some(call));
        let body = self.emit_block(vec![ret], None);
        let (fid, _) = self.computed_props[&p.name];
        self.ir.functions[fid as usize].body = Some(body);
        Some(())
    }

    /// Destructure a trailing lambda argument into `(parameter names, body)`, or `None` if `arg` is
    /// not a lambda.
    pub(crate) fn synth_arg_lambda(&self, arg: AstExprId) -> Option<(Vec<String>, AstExprId)> {
        match self.afile.expr(arg).clone() {
            Expr::Lambda { params, body } => Some((params, body)),
            _ => None,
        }
    }

    /// Build the fill loop shared by `IntArray(n) { i -> e }` and `Array<T>(n) { i -> e }`:
    ///   `{ val n = <size>; val a = new T[n]; var i = 0; while (i < n) { a[i] = <body[it:=i]>; i++ }; a }`
    /// `NewArray` allocates (`newarray`/`anewarray`); `kotlin/Array.set` stores (the backend picks
    /// `iastore`/`aastore`/… by the array element type).
    pub(crate) fn build_fill_array(
        &mut self,
        elem: Ty,
        size_arg: AstExprId,
        params: Vec<String>,
        body: AstExprId,
    ) -> Option<ExprId> {
        // For a boxed `Array<T>` (element `Obj("kotlin/Int")`) the array is `Integer[]`, but the filled
        // VALUE is the UNBOXED primitive — `kotlin/Array.set` boxes it once before `aastore`. Lowering the
        // value to the boxed element would double-box. A reference element is unchanged.
        let value_ir = ty_to_ir(elem.unboxed_primitive().unwrap_or(elem));
        let int_ir = ty_to_ir(Ty::Int);
        // val n = <size> (evaluated once — the bound is read again in the loop)
        let size = self.lower_arg(size_arg, &int_ir)?;
        let n_v = self.fresh_value();
        let var_n = self.emit_variable(n_v, int_ir.clone(), Some(size));
        // val a = new T[n] — the whole array type (`kotlin/IntArray` or `kotlin/Array<X>`) drives the
        // emitter's `newarray`/`anewarray` + element boxing.
        let arr_ir = ty_to_ir(Ty::array(elem));
        let gn0 = self.emit_get_value(n_v);
        let alloc = self.emit_new_array(arr_ir, gn0);
        let arr_v = self.fresh_value();
        let var_arr = self.emit_variable(arr_v, arr_ir, Some(alloc));
        // var i = 0
        let i_v = self.fresh_value();
        let zero = self.emit_const(IrConst::Int(0));
        let var_i = self.emit_variable(i_v, int_ir, Some(zero));
        // cond: i < n
        let gi = self.emit_get_value(i_v);
        let gn = self.emit_get_value(n_v);
        let cond = self.emit_primitive_bin_op(IrBinOp::Lt, gi, gn);
        // body: a[i] = <lambda body with the index param bound to i>
        let pname = ast::first_lambda_param_or_it(&params);
        let depth = self.scope.len();
        self.scope.push((pname, i_v, Ty::Int));
        let body_val = self.lower_arg(body, &value_ir);
        self.scope.truncate(depth);
        let body_val = body_val?;
        // Spill the element value into a temp before the store: a branchy body (`{ it % 2 == 0 }`)
        // records a stackmap frame, and `kotlin/Array.set` pushes the array + index *before* the value
        // — without the spill those operands would be stranded on the stack across that frame.
        let tmp_v = self.fresh_value();
        let var_tmp = self.emit_variable(tmp_v, value_ir, Some(body_val));
        let ga = self.emit_get_value(arr_v);
        let gi2 = self.emit_get_value(i_v);
        let gtmp = self.emit_get_value(tmp_v);
        let set = self.emit_external_call("kotlin/Array.set", Some(ga), vec![gi2, gtmp]);
        let wbody = self.emit_block(vec![var_tmp, set], None);
        // update: i = i + 1
        let gi3 = self.emit_get_value(i_v);
        let one = self.emit_const(IrConst::Int(1));
        let inc_val = self.emit_primitive_bin_op(IrBinOp::Add, gi3, one);
        let inc = self.emit_set_value(i_v, inc_val);
        let wh = self.emit_while(cond, wbody, Some(inc), false, None);
        let result = self.emit_get_value(arr_v);
        Some(self.emit_block(vec![var_n, var_arr, var_i, wh], Some(result)))
    }

    /// Resolve a `catch` exception type name to its JVM internal name (mirrors the checker): a file
    /// class, a known class-name, or a classpath/stdlib throwable alias.
    fn catch_internal(&self, name: &str) -> Option<String> {
        self.syms
            .class_names
            .get(name)
            .map(TypeName::render)
            .or_else(|| self.syms.classes.get(name).map(|c| c.internal()))
    }

    /// Lower construction of a classpath (non-IR) class — `RuntimeException("x")`, `StringBuilder()`.
    /// The constructor descriptor is resolved from the classpath; arguments are coerced to its
    /// parameter types. Bails when the constructor can't be resolved or arity mismatches.
    /// The leftmost simple name of a dotted `Name`/`Member` chain (`a.b.c` → `a`), or `None`. Lets a
    /// fully-qualified package path be told apart from a member access on a value in scope.
    fn ast_dotted_root(&self, e: AstExprId) -> Option<String> {
        match self.afile.expr(e) {
            Expr::Name(n) => Some(n.clone()),
            Expr::Member { receiver, .. } => self.ast_dotted_root(*receiver),
            _ => None,
        }
    }

    /// The classpath internal a qualified constructor receiver+name denotes — a nested type
    /// (`Outer.Nested` → `Outer$Nested`) or a FULLY-QUALIFIED class via a package path (`a.b.Ctx` →
    /// `a/b/Ctx`). `None` when the receiver's root is a value in scope (an ordinary member call) or the
    /// path is not a classpath type. Mirrors the checker's `qualified_nested_ctor_internal`.
    fn nested_ctor_internal(&self, receiver: AstExprId, name: &str) -> Option<String> {
        let root = self.ast_dotted_root(receiver)?;
        if self.lookup(&root).is_some() {
            return None;
        }
        match self.afile.expr(receiver) {
            Expr::Name(outer) => self.resolve_qualified_nested(&format!("{outer}.{name}")),
            Expr::Member { .. } => {
                let internal = format!("{}/{name}", qualified_path(self.afile, receiver)?);
                self.syms
                    .libraries
                    .resolve_type(&internal)
                    .map(|_| internal)
            }
            _ => None,
        }
    }

    /// Lower a FULLY-QUALIFIED top-level function call `a.b.helper(args)` — the receiver is a package path
    /// (its root is not a value in scope) and `helper` is a top-level function of that package (compiled
    /// to `a/b/<File>Kt`). Emits the `invokestatic` to the facade, threading a `Continuation` if the
    /// callee is `suspend`. `None` (→ normal member-call handling) when the receiver is not a package, the
    /// name resolves elsewhere, or the shape is a vararg/defaulted/inline call this focused path leaves to
    /// a later slice (a plain FQ call is the common form).
    fn lower_fq_toplevel_call(
        &mut self,
        receiver: AstExprId,
        _name: &str,
        args: &[AstExprId],
        e: AstExprId,
    ) -> Option<u32> {
        let root = self.ast_dotted_root(receiver)?;
        if self.lookup(&root).is_some() {
            return None;
        }
        let pkg = qualified_path(self.afile, receiver)?;
        let arg_tys = self.arg_tys(args);
        // A trailing lambda was typed against its (receiver/suspend SAM) block parameter by the checker,
        // so its stored type already carries the right arity for overload resolution here.
        let has_trailing_lambda =
            self.afile.call_has_trailing_lambda.contains(&e.0) && !arg_tys.is_empty();
        // The CHECKER resolved this FQ top-level call and recorded the callable (keyed by the call
        // `ExprId`); the lowerer reads it.
        let c = self.info.resolved_top_level(e).cloned()?;
        if !c.owner_package_matches(pkg.as_str()) {
            return None;
        }
        // A vararg FQ call is a later slice (sound skip).
        let last_is_array = c.params.last().is_some_and(|p| p.array_elem().is_some());
        if last_is_array {
            return None;
        }
        let mut a = Vec::new();
        if c.default_call {
            // A `name$default` FQ call: fill the provided prefix, place a TRAILING LAMBDA in the last slot
            // (middle parameters default) or append trailing placeholders, then an `int` bit-mask (a bit
            // per omitted parameter) and a `null` marker. Mirrors the bare-name top-level `$default` path.
            self.append_default_call_args(&mut a, &c.params, args, has_trailing_lambda)?;
        } else {
            if c.params.len() != args.len() {
                return None;
            }
            for (i, &arg) in args.iter().enumerate() {
                a.push(self.lower_arg(arg, &ty_to_ir(c.params[i]))?);
            }
        }
        let call_inline = c.inline.can_inline();
        let physical_ret = c.physical_ret;
        let logical_ret = c.ret;
        let erased_generic_ret = physical_ret.is_erased_top() && logical_ret != physical_ret;
        let suspend = c.suspend;
        let call = self.emit_library_static_call(c, a, suspend);
        // Inline calls and non-inline FQ calls with an ERASED generic return (`Object`) both need the
        // substituted static result type the checker inferred, mirroring the bare-name path.
        Some(if call_inline || erased_generic_ret {
            self.coerce_erased_call_result(e, call, &physical_ret, true)
        } else {
            call
        })
    }

    fn lower_external_new(
        &mut self,
        internal: &str,
        call: AstExprId,
        args: &[AstExprId],
    ) -> Option<u32> {
        // A user class defined in ANOTHER file of this compilation (found by internal name in the global
        // symbol table, but not in THIS file's IR classes) → construct via `NewCrossFile` from its
        // `ClassSig` ctor params. Only the simple exact-arity primary-ctor case (defaults/secondary bail).
        if let Some(cs) = self.syms.class_by_internal(internal) {
            // A sibling-file value class (unboxed — no instance `<init>`), annotation (an interface +
            // synthetic impl), or inner class (needs an outer instance) isn't constructed via a plain
            // cross-file `new`; bail those (the test skips rather than miscompiles).
            if cs.value_field.is_some() || cs.is_annotation || cs.inner_of.is_some() {
                return None;
            }
            if !cs.is_interface && cs.ctor_params.len() == args.len() {
                let params = tys_to_ir(&cs.ctor_params);
                let mut a = Vec::new();
                for (arg, pty) in args.iter().zip(&params) {
                    a.push(self.lower_arg(*arg, pty)?);
                }
                return Some(self.ir.new_cross_file(internal, params, a));
            }
            return None; // sibling-file user class but arity/defaults/secondary not modeled cross-file
        }
        match self.info.resolved_constructor(call).cloned()? {
            // A classpath `@JvmInline value class` is constructed via its static
            // `constructor-impl(U): U`, which returns the UNBOXED underlying value.
            ResolvedConstructor::ValueClass {
                underlying: under,
                arg,
            } => {
                if let Some(source_arg) = arg {
                    let desc = self.runtime.method_descriptor(&[under], under)?;
                    let arg = self.lower_arg(source_arg, &ty_to_ir(under))?;
                    return Some(self.emit_static_call(
                        internal.to_string(),
                        "constructor-impl".to_string(),
                        desc,
                        InlineKind::None,
                        vec![arg],
                    ));
                }
                let marker = Ty::obj("kotlin/jvm/internal/DefaultConstructorMarker");
                let desc = self
                    .runtime
                    .method_descriptor(&[under, Ty::Int, marker], under)?;
                let dummy = self.emit_const(IrConst::Null);
                let mask = self.emit_const(IrConst::Int(1));
                let null_marker = self.emit_const(IrConst::Null);
                Some(self.emit_static_call(
                    internal.to_string(),
                    "constructor-impl$default".to_string(),
                    desc,
                    InlineKind::None,
                    vec![dummy, mask, null_marker],
                ))
            }
            ResolvedConstructor::Plain { member, args } => {
                let mut lowered = Vec::new();
                for (arg, pty) in args.iter().zip(&member.params) {
                    lowered.push(self.lower_arg(*arg, &ty_to_ir(*pty))?);
                }
                Some(self.emit_new_external(internal, member.descriptor, lowered))
            }
            ResolvedConstructor::PlainSlots { member, slots } => {
                let (lowered, prelude) =
                    self.lower_call_slot_args_source_order(args, &slots, &member.params, false)?;
                let new = self.emit_new_external(internal, member.descriptor, lowered);
                Some(self.wrap_arg_prelude(new, prelude))
            }
            ResolvedConstructor::Synthetic { ctor, args } => {
                let mut lowered = Vec::new();
                for (i, pty) in ctor.real_params.iter().enumerate() {
                    if i < ctor.provided {
                        lowered.push(self.lower_arg(args[i], &ty_to_ir(*pty))?);
                    } else {
                        lowered.push(self.zero_placeholder(*pty));
                    }
                }
                if let Some(mask) = ctor.mask {
                    lowered.push(self.emit_const(IrConst::Int(mask)));
                }
                lowered.push(self.emit_const(IrConst::Null)); // DefaultConstructorMarker
                Some(self.emit_new_external(internal, ctor.descriptor, lowered))
            }
            ResolvedConstructor::NamedDefault {
                descriptor,
                real_params,
                slots,
                mask,
            } => {
                let (mut lowered, prelude) =
                    self.lower_call_slot_args_source_order(args, &slots, &real_params, true)?;
                self.append_default_mask_marker(&mut lowered, mask);
                let new = self.emit_new_external(internal, descriptor, lowered);
                Some(self.wrap_arg_prelude(new, prelude))
            }
        }
    }

    /// A call to a type-parameter-returning function whose erased `Object` result needs a coercion
    /// krusty doesn't model — skip the file rather than miscompile. The result of `f<Unit>()` must
    /// become `Unit.INSTANCE` (not the raw object); inside an `inline` expansion an erased result
    /// feeding a boxed/`Int?` slot mis-frames the verifier. Both reach here as a tail-returned `T`.
    fn erased_generic_call_unmodeled(&self, e: AstExprId, fname: &str) -> bool {
        let returns_typaram = self.afile.decls.iter().any(|&d| {
            matches!(self.afile.decl(d), Decl::Fun(f)
                if f.name == fname
                    && !f.type_params.is_empty()
                    && f.ret.as_ref().is_some_and(|r| f.type_params.contains(&r.name)))
        });
        if !returns_typaram {
            return false;
        }
        let unit_targ = self
            .afile
            .call_type_args
            .get(&e.0)
            .and_then(|ts| ts.first())
            .is_some_and(|r| matches!(r.name.as_str(), "Unit" | "Nothing"));
        unit_targ || !self.inline_active.is_empty()
    }

    /// A call whose declared return is a type parameter erases to `Object`; the checker recovers the
    /// real static type at the call site (a primitive type argument arrives here as its boxed wrapper,
    /// `Integer` — the erased slot's actual reference representation). When that type is a more specific
    /// reference, insert the `checkcast` kotlinc emits so a member access on the result resolves and
    /// verifies (`asSeq<String>(x).length`); the wrapper is unboxed to a primitive only at a use site
    /// that needs it, by the normal coercion path — never eagerly here (an `Int?` consumer keeps it
    /// boxed, and `null` must not be unboxed).
    /// If `v` is the compiler-inserted unbox of a CALL result (an `ImplicitCoercion` of a `Call`/
    /// `MethodCall` to a primitive — `map.put(k,v): V?` typed as a primitive), return the inner call;
    /// otherwise `v` unchanged. Used to drop the pointless, null-NPE-prone unbox of a DISCARDED statement
    /// value. Restricted to call results so it never strips a user `as`-to-primitive (whose operand is
    /// not a call), which has an observable `ClassCastException` side effect.
    fn strip_discarded_unbox(&self, v: u32) -> u32 {
        if let IrExpr::TypeOp {
            op: IrTypeOp::ImplicitCoercion,
            arg,
            type_operand,
        } = self.ir.expr(v)
        {
            if !ir_type_is_reference(type_operand)
                && matches!(
                    self.ir.expr(*arg),
                    IrExpr::Call { .. } | IrExpr::MethodCall { .. }
                )
            {
                return *arg;
            }
        }
        v
    }

    fn coerce_erased_call_result(
        &mut self,
        e: AstExprId,
        call: u32,
        ret: &Ty,
        ret_is_tparam: bool,
    ) -> u32 {
        // The erased return is a type parameter — `Object` when unbounded, or a concrete bound
        // (`CharSequence` for `<T : CharSequence>`). Only then does the checker's substituted static
        // type refine it; a concrete reference return (a value class, a bridge result) must NOT be cast,
        // or codegen inserts a spurious `checkcast` that breaks verification.
        let phys = ret.non_null();
        if !(ret_is_tparam || phys.is_erased_top()) {
            return call;
        }
        // When the substituted static type is a strictly more specific reference than the erased return
        // (`asSeq<String>(x): String` physically `CharSequence`), insert the `checkcast` kotlinc emits so
        // a member access on the result verifies.
        let st = self.info.ty(e);
        // Record the CALL's logical type keyed by its own id (the outer `fn expr` records only the wrapper
        // this returns). The value-class pass reads it so a library value-class return (`runCatching: Result`)
        // reprs as its UNBOXED underlying — letting the wrapping coercion strip as a redundant same-type cast.
        if st != Ty::Error {
            self.ir.logical_types.insert(call, ty_to_ir(st));
        }
        if self.has_scalar_value_repr(st) && phys.is_erased_top() {
            return self.emit_type_op(IrTypeOp::ImplicitCoercion, call, ty_to_ir(st));
        }
        if st.is_reference() && !st.is_erased_top() && st != Ty::Null && st.non_null() != phys {
            return self.emit_type_op(IrTypeOp::Cast, call, ty_to_ir(st));
        }
        call
    }

    /// Lower a lambda literal `{ a, b -> body }` to an `IrExpr::Lambda` (emitted as `invokedynamic` +
    /// `LambdaMetafactory`). The body becomes a synthesized static method `<enclosing>$lambda$<n>`
    /// with the lambda's (real, from the checker) parameter types. Non-capturing only: a body that
    /// reads any enclosing local/parameter, or a lambda inside a class method (which could capture
    /// `this`/fields), bails (`None`) rather than miscompile.
    /// Append a loop body's statements to `out`: a block's statements (plus its trailing expression),
    /// or a single non-block body expression (`for (x in xs) f(x)` — no braces). Returns `None` if any
    /// statement can't be lowered.
    /// A statement that transfers control away unconditionally (`return`/`break`/`continue`, or an
    /// expression of type `Nothing` — a `throw` or a call that never returns). Code after it in the same
    /// block is unreachable; kotlinc drops it, and emitting it would leave the verifier without the
    /// stackmap frame a (dead) branch target needs (`VerifyError: Expecting a stack map frame`).
    fn stmt_diverges(&self, s: crate::ast::StmtId) -> bool {
        match self.afile.stmt(s) {
            Stmt::Return(..) | Stmt::Break(_) | Stmt::Continue(_) => true,
            Stmt::Expr(e) => self.expr_diverges(*e),
            _ => false,
        }
    }

    /// True for an expression that transfers control away unconditionally. A `Nothing`-typed expression
    /// (`throw`, `return`, a never-returning call) qualifies; so does a constant-condition `if` whose
    /// taken branch diverges (`if (true) return`) — the lowerer const-folds it to just that branch
    /// (see the `Expr::BoolLit` fold in the `Expr::If` arm), so the trailing code is dead and must drop.
    fn expr_diverges(&self, e: AstExprId) -> bool {
        if self.info.ty(e) == Ty::Nothing {
            return true;
        }
        if let Expr::If {
            cond,
            then_branch,
            else_branch,
        } = self.afile.expr(e)
        {
            return match self.afile.expr(*cond) {
                Expr::BoolLit(true) => self.expr_diverges(*then_branch),
                Expr::BoolLit(false) => else_branch.is_some_and(|eb| self.expr_diverges(eb)),
                _ => false,
            };
        }
        false
    }

    /// The underlying type of a `@JvmInline value class` (`Z(val v: Int)` → `Int`), or `None` for an
    /// ordinary type. A value-class value is represented unboxed as this type.
    fn value_class_underlying(&self, t: Ty) -> Option<Ty> {
        let internal = t.obj_internal()?;
        self.syms
            .class_by_type_name(internal)
            .and_then(|c| c.value_field.as_ref())
            .map(|(_, u)| *u)
    }

    /// Forward a resolved extension callable's DECLARED source receiver onto the emitted call, verbatim —
    /// no value-class reasoning here (`ir_lower` stays value-class-agnostic). The value-class pass reads
    /// `ext_call_source_receiver` to decide whether a `Boxed` receiver unboxes (`fun Result<T>.getOrThrow`).
    fn record_ext_source_receiver(&mut self, call: u32, source_receiver: Option<Ty>) {
        if let Some(sr) = source_receiver {
            self.ir.ext_call_source_receiver.insert(call, sr);
        }
    }

    fn append_body_stmts(&mut self, body: AstExprId, out: &mut Vec<u32>) -> Option<()> {
        match self.afile.expr(body).clone() {
            Expr::Block { stmts, trailing } => {
                let mut diverged = false;
                for s in stmts {
                    self.append_stmt(s, out)?;
                    if self.stmt_diverges(s) {
                        diverged = true;
                        break;
                    }
                }
                if !diverged {
                    if let Some(t) = trailing {
                        out.push(self.expr(t)?);
                    }
                }
            }
            _ => out.push(self.expr(body)?),
        }
        Some(())
    }

    /// Lower one statement into `out`. A destructuring declaration splices its bindings directly so the
    /// component locals live in the enclosing scope (a nested `Block` would scope them away at emit).
    fn append_stmt(&mut self, s: crate::ast::StmtId, out: &mut Vec<u32>) -> Option<()> {
        // A checker-erased statement (a `kotlin.contracts.contract { … }` block) emits no bytecode.
        if matches!(self.info.stmt_lowers.get(&s), Some(StmtLowering::Erased)) {
            return Some(());
        }
        if let Stmt::Destructure { entries, init } = self.afile.stmt(s).clone() {
            return self.lower_destructure(s, &entries, init, out);
        }
        out.push(self.stmt(s)?);
        Some(())
    }

    /// Lower `val (a, b, …) = init` into `out`: a temp bound to `init`, then one local per component
    /// (`a = temp.component1()`, …). Each component is a user-class `componentN` (data class) or a
    /// library member (`Pair`, `Map.Entry`); a generic component's erased return coerces to its element.
    /// Lower a single-spread call `foo(*a)` to a top-level `vararg` function: pass the array through
    /// the platform array-copy helper + `checkcast`, exactly as kotlinc does, instead of packing the
    /// array as one element. Returns `None` (→ the file skips) for any shape this doesn't handle: more
    /// than one argument, a non-spread sole argument, a non-`Name` (non-reusable) spread expression, an
    /// unsupported element type, or a callee that isn't a single-`vararg`-parameter top-level function in
    /// this file.
    fn lower_single_spread_call(
        &mut self,
        call: AstExprId,
        callee: AstExprId,
        args: &[AstExprId],
    ) -> Option<ExprId> {
        let spread = match args {
            [spread] if self.afile.is_spread_arg(*spread) => *spread,
            _ => {
                self.set_bail("call spread: not single spread arg");
                return None;
            }
        };
        // kotlinc loads the spread twice; only a simple reusable name is safe without a temp.
        if !matches!(self.afile.expr(spread), ast::Expr::Name(_)) {
            self.set_bail("call spread: non-reusable spread expression");
            return None;
        }
        let ast::Expr::Name(fname) = self.afile.expr(callee).clone() else {
            self.set_bail("call spread: non-name callee");
            return None;
        };
        let target = self
            .info
            .resolved_module_top_level(call)
            .filter(|target| {
                target.name == fname && target.call_sig.vararg && target.params.len() == 1
            })
            .cloned();
        let Some(target) = target else {
            self.set_bail("call spread: no resolved single-vararg module target");
            return None;
        };
        let Some(fid) = target
            .source_file
            .filter(|file| *file == self.file_index)
            .and(target.source_decl)
            .and_then(|decl| self.fun_ids_by_decl.get(&decl).copied())
        else {
            self.set_bail("call spread: resolved target not in current file");
            return None;
        };
        let Some(elem) = target.params[0].array_elem() else {
            self.set_bail("call spread: selected vararg param is not array");
            return None;
        };
        // A primitive element uses the matching platform array-copy overload and needs no checkcast
        // (the result is already the exact array type). Unsigned `UInt`/`ULong` varargs are a value-class
        // array with a different copy path — leave those (skip) rather than miscompile.
        let prim = matches!(
            elem,
            Ty::Int
                | Ty::Long
                | Ty::Byte
                | Ty::Short
                | Ty::Char
                | Ty::Boolean
                | Ty::Float
                | Ty::Double
        );
        if !elem.is_reference() && !prim {
            return None;
        }
        let array_ty = target.params[0];
        let array_ir = ty_to_ir(array_ty);

        // Platform array copy. The JVM primitive overload returns the exact array type (no cast); the
        // reference overload returns `Object[]` and needs a `checkcast` to the element array type.
        let a0 = self.lower_arg(spread, &array_ir)?;
        let a1 = self.lower_arg(spread, &array_ir)?;
        let size = self.emit_external_call("kotlin/Array.size", Some(a1), vec![]);
        let copy = self.runtime_call(RuntimeOp::ArrayCopyOf, array_ir, vec![a0, size])?;
        let arg = if prim {
            copy // primitive `copyOf` already returns `[<prim>` — no cast
        } else {
            self.emit_type_op(IrTypeOp::Cast, copy, array_ir)
        };
        Some(self.emit_local_call(fid, vec![arg]))
    }

    fn lower_destructure(
        &mut self,
        stmt: ast::StmtId,
        entries: &[(String, bool)],
        init: AstExprId,
        out: &mut Vec<u32>,
    ) -> Option<()> {
        let it_ty = self.info.ty(init);
        let init_v = self.expr(init)?;
        let tmp = self.fresh_value();
        out.push(self.emit_variable(tmp, ty_to_ir(it_ty), Some(init_v)));
        for (idx, (name, _)) in entries.iter().enumerate() {
            if name == "_" {
                continue;
            }
            let recv = self.emit_get_value(tmp);
            let target = self
                .info
                .resolved_destructure_component(stmt, idx)
                .cloned()?;
            let (call, log_ty) =
                self.lower_destructure_component_target(recv, it_ty, idx, target)?;
            self.bind_destructure_component(name, call, log_ty, out)?;
        }
        Some(())
    }

    fn lower_destructure_component_target(
        &mut self,
        recv: u32,
        recv_ty: Ty,
        idx: usize,
        target: DestructureComponentTarget,
    ) -> Option<(u32, Ty)> {
        let internal = recv_ty.kotlin_class_internal()?;
        match target {
            DestructureComponentTarget::ModuleMember {
                owner,
                name,
                params,
                ret,
            } => {
                if !params.is_empty() {
                    return None;
                }
                let owner = owner.render();
                let (class, method, _, found_ret) =
                    self.link_local_method(&owner, &name, &params)?;
                if found_ret != ret {
                    return None;
                }
                Some((self.emit_method_call(class, method, recv, vec![]), ret))
            }
            DestructureComponentTarget::CrossFileModuleMember {
                owner,
                name,
                params,
                ret,
                interface,
            } => {
                if !params.is_empty() {
                    return None;
                }
                let c = self.emit_call(
                    Callee::CrossFileVirtual {
                        owner,
                        name,
                        params,
                        ret: ty_to_ir(ret),
                        interface,
                    },
                    Some(recv),
                    vec![],
                );
                Some((c, ret))
            }
            DestructureComponentTarget::LibraryMember(m) => {
                let physical_ret = m.member.physical_ret;
                let ret = m.ret;
                let c =
                    self.emit_library_member_call(recv, internal, m.member, ret, m.suspend, vec![]);
                Some((self.coerce_to_static(c, ret, physical_ret), ret))
            }
            DestructureComponentTarget::LibraryExtension(c) => {
                let ret = c.ret;
                let physical_ret = c.physical_ret;
                let call = self.emit_library_static_call(c, vec![recv], false);
                Some((self.coerce_to_static(call, ret, physical_ret), ret))
            }
            DestructureComponentTarget::ModuleExtension {
                receiver,
                name,
                params,
                ret,
            } => {
                if receiver.erased_recv() != recv_ty.erased_recv() || !params.is_empty() {
                    return None;
                }
                let fid = *self
                    .ext_fun_id_by_sig
                    .get(&(receiver.erased_recv(), name, params))?;
                if self.ir.functions[fid as usize].ret != ret {
                    return None;
                }
                Some((self.emit_local_call(fid, vec![recv]), ret))
            }
            DestructureComponentTarget::ModulePropertyGetter {
                owner,
                property,
                ret,
                interface,
            } => {
                let getter = property_getter_name(&property);
                let owner_rendered = owner.render();
                if let Some((class, method, _, found_ret)) =
                    self.link_local_method(&owner_rendered, &getter, &[])
                {
                    if found_ret != ret {
                        return None;
                    }
                    return Some((self.emit_method_call(class, method, recv, vec![]), ret));
                }
                let c = self.emit_call(
                    Callee::CrossFileVirtual {
                        owner,
                        name: getter,
                        params: vec![],
                        ret: ty_to_ir(ret),
                        interface,
                    },
                    Some(recv),
                    vec![],
                );
                Some((c, ret))
            }
            DestructureComponentTarget::IndexedGet(m) => {
                let physical_ret = m.member.physical_ret;
                let ret = m.ret;
                let i = self.emit_const(IrConst::Int(idx as i32));
                let c = self.emit_library_member_call(
                    recv,
                    internal,
                    m.member,
                    ret,
                    m.suspend,
                    vec![i],
                );
                Some((self.coerce_to_static(c, ret, physical_ret), ret))
            }
        }
    }

    /// Bind one destructured component `name` to its (already-lowered) initializer value `call` of
    /// logical type `log_ty`, pushing the local into `out`/scope. A `var` captured+written by a closure
    /// is boxed into a `Ref$XxxRef`, exactly like a plain mutable local, so the closure's write is seen.
    fn bind_destructure_component(
        &mut self,
        name: &str,
        call: u32,
        log_ty: Ty,
        out: &mut Vec<u32>,
    ) -> Option<()> {
        if self.shared_cell_vars.contains(name) {
            let elem_ty = self.shared_cell_elem_ty(log_ty);
            let elem = ref_elem_ir(elem_ty);
            let holder = self.fresh_value();
            let holder_ty = self.mutable_local_ref_type(elem_ty)?;
            self.scope.push((name.to_string(), holder, holder_ty));
            self.boxed_elem.insert(name.to_string(), elem_ty);
            let new_ref = self.ir.add_expr(IrExpr::RefNew { elem, init: call });
            out.push(self.emit_named_variable(holder, ty_to_ir(holder_ty), Some(new_ref)));
        } else {
            let v = self.fresh_value();
            self.scope.push((name.to_string(), v, log_ty));
            out.push(self.emit_named_variable(v, ty_to_ir(log_ty), Some(call)));
        }
        Some(())
    }

    fn lower_lambda(&mut self, e: AstExprId, params: &[String], body: AstExprId) -> Option<u32> {
        self.lower_lambda_sam(e, params, body, None)
    }

    /// `sam`: `(interface internal name, abstract-method name, method returns void)`. The void flag
    /// distinguishes a SAM whose method is `()V` (`Runnable.run`) — the impl runs the body for effect
    /// and returns void — from a `Unit`-typed-but-`Object`-returning target (`FunctionN.invoke`).
    fn lower_lambda_sam(
        &mut self,
        e: AstExprId,
        params: &[String],
        body: AstExprId,
        sam: Option<(String, String, bool)>,
    ) -> Option<u32> {
        let Ty::Fun(sig) = self.info.ty(e) else {
            return None;
        };
        // A `suspend` lambda needs a `SuspendLambda` subclass with a state-machine `invokeSuspend`, not
        // krusty's `invokedynamic`/`LambdaMetafactory` path — not yet modeled. Bail (skip the file)
        // rather than emit a plain `Function0` where a `Function1<Continuation,…>` is expected.
        if sig.suspend {
            return None;
        }
        let arity = sig.params.len();
        // A RECEIVER lambda passed to a `Recv.(value…) -> R` user parameter: its FIRST `sig.params` entry
        // is the receiver (the closure method's leading parameter), bound as the implicit `this` so a bare
        // member/extension call inside dispatches against it. The user's EXPLICIT params are the remaining
        // (value) parameters. `None` for an ordinary lambda.
        let lambda_info = lambda_info(self.info, e);
        let recv_ty = lambda_info.receiver;
        let value_arity = if recv_ty.is_some() {
            arity.saturating_sub(1)
        } else {
            arity
        };
        // A RECEIVER lambda inside a class method would need two `this`es — its own receiver AND the
        // enclosing instance — which the single-`this`-slot closure shape can't carry. Bail (skip). A
        // PLAIN lambda instead captures the enclosing `this` like any other free variable (added below).
        if self.cur_class.is_some() && recv_ty.is_some() {
            return None;
        }
        // A `Nothing`-returning lambda whose body is an unconditional NON-LOCAL `return` (`f { return … }`)
        // is handled by the diverging path below: it only ever splices (the impl method is marked
        // inline-only and not emitted), so its `return` becomes the enclosing fn's return, and the splicer
        // synthesizes the stack-map frame the host's now-unreachable post-invoke continuation needs. But a
        // Nothing lambda WITHOUT a bare return (a `throw`, or only a `return@label` — which can materialize
        // as a real closure) isn't modeled that way — bail (skip, never miscompile) as before.
        if sig.ret == Ty::Nothing && !body_has_bare_return(self.afile, body) {
            return None;
        }
        // Bound parameter names: explicit, or the implicit single `it` for a unary lambda. For a receiver
        // lambda these are the VALUE parameters only (the receiver binds as `this`, separately).
        let bind_names = ast::lambda_params_or_implicit(params, value_arity)?;
        if bind_names.len() != value_arity {
            return None;
        }
        // Captured free variables: enclosing locals/parameters the body reads but the lambda doesn't
        // bind. Each is passed into the impl method as a leading parameter and bound into the closure
        // at the `invokedynamic` call site (kotlinc's capture convention). Dedup by name, keeping the
        // innermost binding (the last in the scope stack). A real CLOSURE also captures a name used in a
        // NESTED lambda (`f { g { use(outer) } }`); an INLINE-spliced lambda accesses it directly, so its
        // captures must NOT be inflated by nested uses (the splice's stack frames would break).
        // Descend into nested lambdas to detect TRANSITIVE captures for EVERY lambda, including an
        // inline-splice one: a nested closure inside a block-bodied splice (`xs.map { x -> val r =
        // ys.map { y -> outer } }`) captures `outer` from the enclosing frame, so the splice must keep
        // `outer` in scope for it. (A splice accesses its OWN direct captures inline; a deeper name it
        // only threads through for the nested closure.)
        let deep = true;
        let mut captures: Vec<(String, u32, Ty)> = Vec::new();
        for (name, v, ty) in self.scope.iter().rev() {
            let used = if deep {
                self.afile.expr_uses_name_deep(body, name)
            } else {
                self.afile.expr_uses_name(body, name)
            };
            if !bind_names.contains(name) && !captures.iter().any(|(n, _, _)| n == name) && used {
                captures.push((name.clone(), *v, *ty));
            }
        }
        captures.reverse();
        // A lambda in a class member that REFERENCES the enclosing instance (`this`/`super`, or a bare
        // member access) captures `this` — slot 0 of the enclosing method — as its FIRST captured
        // parameter, like any captured local; `cur_class` stays set so member accesses lower to
        // `GetField(GetValue(0))`/`this.m(…)` reading that param. Only a REAL closure (invokedynamic)
        // needs it — an INLINE-spliced lambda runs in the enclosing method where `this` is already slot 0.
        // Capture only when actually used: capturing an UNUSED `this` is wrong where `this` isn't
        // available yet (a lambda in a base-ctor argument, pre-`super()`), and when NOT captured we clear
        // `cur_class` for the body so a missed member access bails (returns None) rather than miscompiles.
        // Capture the enclosing `this` when a bare member access needs it — for a REAL closure it becomes
        // capture field 0, for an INLINE-spliced lambda the splicer remaps it (like any captured local) to
        // the enclosing method's slot 0, so an enclosing-member call (`es.find { same(it.v, 3) }`, `same`
        // a method of the enclosing class) resolves in both. Previously the `deep`/InlineSplice gate cleared
        // `cur_class` for a spliced lambda, so such a call bailed ("this construct is not yet supported").
        let captures_this = self.cur_class.is_some()
            && recv_ty.is_none()
            && self.lambda_uses_enclosing_this(body, &bind_names, deep);
        let captures_outer_this = !captures_this
            && recv_ty.is_none()
            && self.cur_class.is_some()
            && self.lookup("this$0").is_some()
            && self.lambda_uses_outer_this_param(body, &bind_names, deep);
        if captures_this {
            let tty = Ty::obj_name(self.cur_class.unwrap());
            captures.insert(0, ("this".to_string(), 0, tty));
        } else if captures_outer_this {
            let (v, tty) = self.lookup("this$0")?;
            captures.insert(0, ("this".to_string(), v, tty));
        }
        // The capture values are read in the *enclosing* scope before it's swapped out.
        let capture_vals: Vec<u32> = captures
            .iter()
            .map(|(_, v, _)| self.emit_get_value(*v))
            .collect();
        // Lower the body in a fresh value-numbering scope: captured params first (values `0..n_cap`),
        // then the lambda's own parameters.
        let saved_scope = std::mem::take(&mut self.scope);
        let saved_next = self.next_value;
        self.next_value = 0;
        for (name, _, ty) in &captures {
            let v = self.fresh_value();
            self.scope.push((name.clone(), v, *ty));
        }
        // For a receiver lambda, the FIRST closure parameter is the receiver — bind it as `this` (and the
        // value parameters are `sig.params[1..]`). `cur_class` is already cleared (the guard above bails
        // on a lambda inside a class method), so bare member/extension calls route through implicit-`this`.
        let value_params: &[Ty] = if let Some(rty) = recv_ty {
            let v = self.fresh_value();
            self.scope.push(("this".to_string(), v, rty));
            &sig.params[1..]
        } else {
            &sig.params
        };
        // A lambda parameter is a `FunctionN` generic position, so a reference-underlying value-class
        // parameter (`Result<T>`) arrives BOXED. The value-class pass handles the resulting unbox at a
        // member/extension call (`it.getOrThrow()`) via `IrFile::lambda_own_params_from`; the lowerer stays
        // value-class-agnostic here and just binds the parameter slots.
        for (name, pty) in bind_names.iter().zip(value_params.iter()) {
            let v = self.fresh_value();
            self.scope.push((name.clone(), v, *pty));
        }
        // The closure method returns the `kotlin/Unit` SINGLETON (a reference) when the lambda is
        // `() -> Unit` and not a `void` SAM (`Runnable`) nor a diverging body — so a `return@lambda`
        // inside it (a LOCAL return from the closure method) must `areturn Unit.INSTANCE`, not `return`.
        let sam_void_pre = matches!(&sam, Some((_, _, true)));
        let returns_unit_ref =
            sig.ret == Ty::Unit && !sam_void_pre && self.info.ty(body) != Ty::Nothing;
        let saved_unit_ref =
            std::mem::replace(&mut self.cur_method_returns_unit_ref, returns_unit_ref);
        // When this closure does NOT capture the enclosing `this`, lower its body with `cur_class`
        // cleared: a bare instance-member access then fails to resolve and the lambda bails (skip)
        // rather than emitting a `GetField(GetValue(0))` that reads the wrong captured slot. When it
        // DOES capture `this` (slot 0), keep `cur_class` so those accesses resolve against it.
        let saved_cur_class = if captures_this {
            self.cur_class
        } else {
            self.cur_class.take()
        };
        // An ANONYMOUS FUNCTION's body owns its `return`: a bare `return e` is a LOCAL return from this
        // closure method, not a non-local return of the enclosing fn. Lower its body with `cur_ret_ty`
        // set to the closure's own return type so `return` coerces to and `areturn`s that type.
        let is_anon_fun = self.afile.anon_fun_lambdas.contains(&e.0);
        let saved_ret_ty = if is_anon_fun {
            Some(std::mem::replace(&mut self.cur_ret_ty, sig.ret))
        } else {
            None
        };
        // A `var` declared INSIDE this lambda's body and mutated by a further (non-inline) closure
        // (`{ var v = …; call { v = … }; v }`) needs a `Ref` holder so the nested write is observed.
        // UNION the body-local shared cells with the inherited set (captured enclosing cells stay boxed)
        // for the duration of body lowering.
        let saved_cells = self.shared_cell_vars.clone();
        for n in shared_cell_vars_for_expr(self.afile, body, self.info) {
            self.shared_cell_vars.insert(n);
        }
        // The closure METHOD is its own return scope — spliced-lambda return frames from the enclosing
        // function must not capture a `return`/`return@label` lowered inside it (a non-local return
        // across a non-inline boundary is illegal Kotlin anyway; don't let one silently bind).
        let saved_lam_frames = std::mem::take(&mut self.inline_lambda_ret);
        let ve = self.expr(body);
        self.inline_lambda_ret = saved_lam_frames;
        self.shared_cell_vars = saved_cells;
        if let Some(rt) = saved_ret_ty {
            self.cur_ret_ty = rt;
        }
        self.cur_class = saved_cur_class;
        self.cur_method_returns_unit_ref = saved_unit_ref;
        self.scope = saved_scope;
        self.next_value = saved_next;
        let ve = ve?;
        let diverges = self.info.ty(body) == Ty::Nothing;
        // The SAM's `invoke` returns `Object`, so the impl method returns a reference. A `Unit` lambda
        // runs its body for effect then returns the `kotlin/Unit` singleton; a value lambda returns its
        // (boxed) body value; a diverging body falls through to its own `throw`/`return`.
        let sam_void = matches!(&sam, Some((_, _, true)));
        // `block` is the impl-method body (with a synthetic `return`); `inline_body` is the equivalent
        // *value-producing* form (no synthetic return) the bytecode inliner emits directly — so a
        // user `return` in the lambda becomes a real return from the *enclosing* method (a correct
        // non-local return), not the lambda.
        let (ret_ty, block, inline_body) = if diverges {
            let b = self.emit_block(vec![ve], None);
            (ty_to_ir(sig.ret), b, ve)
        } else if sam_void {
            // The SAM method returns `void` (`run()V`): run the body for effect, no return value.
            let b = self.emit_block(vec![ve], None);
            (ty_to_ir(Ty::Unit), b, ve)
        } else if sig.ret == Ty::Unit {
            let unit = self.emit_unit();
            let ret = self.emit_return(Some(unit));
            let b = self.emit_block(vec![ve, ret], None);
            let inline_b = self.emit_block(vec![ve], Some(unit));
            (ty_to_ir(stored_value_ty(Ty::Unit)), b, inline_b)
        } else {
            let ret_val = if sig.ret.is_reference()
                && !matches!(sig.ret, Ty::Null)
                && !sig.ret.is_erased_top()
            {
                self.emit_type_op(IrTypeOp::Cast, ve, ty_to_ir(sig.ret))
            } else {
                ve
            };
            let ret = self.emit_return(Some(ret_val));
            let b = self.emit_block(vec![ret], None);
            (ty_to_ir(sig.ret), b, ret_val)
        };
        let impl_name = format!("{}$lambda${}", self.cur_fn_name, self.lambda_seq);
        self.lambda_seq += 1;
        // Impl parameters: captured variables first, then the lambda's own parameters.
        let mut params_ir: Vec<Ty> = captures.iter().map(|(_, _, t)| ty_to_ir(*t)).collect();
        let own_params_from = params_ir.len() as u32;
        params_ir.extend(sig.params.iter().map(|t| stored_value_ty(*t)));
        let fid = self.ir.add_fun(IrFunction {
            name: impl_name,
            params: params_ir,
            ret: ret_ty,
            body: Some(block),
            is_static: true,
            dispatch_receiver: None,
            param_checks: Vec::new(),
        });
        // Record where this lambda's OWN parameters begin (after the captures) so the value-class pass can
        // treat a reference-underlying value-class own-param as BOXED — it arrives through `FunctionN`'s
        // generic `Object` invoke slot. The lowerer stays value-class-agnostic; the pass decides VC-ness.
        self.ir.lambda_own_params_from.insert(fid, own_params_from);
        // A BARE `return` in a lambda body is a NON-LOCAL return (from the enclosing function) — valid only
        // when the lambda is spliced inline, never as a standalone closure method (the `areturn` would carry
        // the enclosing fn's return type, not the lambda's). Mark the impl method inline-only so the backend
        // skips it (an invalid, dead method); the splice uses `inline_body`. A LABELED `return@x` is a LOCAL
        // return from the lambda (a normal `return` in the closure method), so it stays emittable.
        // An anonymous function is exempt: its bare `return` was already lowered as this closure
        // method's OWN return (`cur_ret_ty` above), so the method is a valid, emittable closure — not a
        // splice-only body.
        if !is_anon_fun && body_has_bare_return(self.afile, body) {
            self.ir.inline_only_fns.insert(fid);
        }
        // A lambda impl method lives ON THE CLASS declaring the enclosing member (kotlinc's placement:
        // same class as the `invokedynamic` call site, so a PRIVATE impl — and any enclosing-`this`
        // member access — resolves without bridges); a top-level declaration's lambda keeps its impl on
        // the file facade. (Skip an inline-only impl — it is spliced, never emitted as a standalone
        // method.)
        if !self.ir.inline_only_fns.contains(&fid) {
            if let Some(internal) = self.cur_class {
                if let Some(cid) = self.class_info_name(internal).map(|ci| ci.id) {
                    self.ir.classes[cid as usize].methods.push(fid);
                }
            }
        }
        // kotlinc emits every standalone lambda impl `private static final` — it is reachable only
        // through the same-class `invokedynamic`, never part of the public ABI.
        self.ir.private_methods.insert(fid);
        Some(self.ir.add_expr(IrExpr::Lambda {
            impl_fn: fid,
            arity: arity as u8,
            captures: capture_vals,
            sam: sam.map(|(i, m, _)| (i, m)),
            inline_body: Some(inline_body),
        }))
    }

    /// Whether a lambda body references the ENCLOSING instance: an explicit `this`/`super`, or a bare
    /// name that resolves to an instance field/method of `cur_class` (an implicit-`this` member access).
    /// Drives whether a class-member closure must capture the enclosing `this`. Names BOUND by the lambda
    /// (its parameters / `it`) are not enclosing references. A miss is safe — the caller clears
    /// `cur_class` when this returns false, so any member access it overlooked simply fails to lower.
    /// Whether the lambda `body` references the enclosing instance (`this`/`super`, or a bare
    /// instance-field/method access). `deep` mirrors the capture-scan depth: a REAL closure counts a use
    /// anywhere (incl. inside a NESTED lambda, which captures it transitively); an INLINE-spliced lambda
    /// counts only a DIRECT use — a use confined to a nested lambda is that lambda's own capture, and
    /// counting it here would make the outer splice's `this`-capture asymmetric with its (shallow) named
    /// captures.
    fn lambda_uses_enclosing_this(&self, body: AstExprId, bound: &[String], deep: bool) -> bool {
        let Some(cur) = self.cur_class else {
            return false;
        };
        fn scan(lo: &Lower, cur: TypeName, bound: &[String], e: AstExprId, deep: bool) -> bool {
            if let Expr::Name(n) = lo.afile.expr(e) {
                // `this`/`super` (incl. labeled `this@Outer`) are bare names here, not a dedicated
                // variant — an explicit enclosing-instance reference.
                if n == "this" || n == "super" || n.starts_with("this@") || n.starts_with("super@")
                {
                    return true;
                }
                // A bare name resolving to an instance field/method of the enclosing class is an
                // implicit-`this` member access.
                if !bound.contains(n)
                    && (lo.resolve_field_name(cur, n).is_some()
                        || lo.resolve_method_name(cur, n).is_some())
                {
                    return true;
                }
            }
            // A SHALLOW (inline-splice) scan does not descend into a NESTED lambda's body.
            if !deep && matches!(lo.afile.expr(e), Expr::Lambda { .. }) {
                return false;
            }
            lo.afile
                .any_child_expr(e, &mut |c| scan(lo, cur, bound, c, deep), &mut |s| {
                    lo.afile
                        .any_child_stmt(s, &mut |c| scan(lo, cur, bound, c, deep))
                })
        }
        scan(self, cur, bound, body, deep)
    }

    /// In an inner-class constructor prelude (`super(...)` arguments), the captured outer instance is a
    /// constructor parameter (`this$0`) and the inner `this` is still uninitialized. A lambda that only
    /// needs an outer member should capture that parameter as its implicit receiver instead of capturing
    /// the inner `this` and reading `this.this$0` before `super()`.
    fn lambda_uses_outer_this_param(&self, body: AstExprId, bound: &[String], deep: bool) -> bool {
        let Some((_, outer_ty)) = self.lookup("this$0") else {
            return false;
        };
        let Some(outer) = outer_ty.obj_internal() else {
            return false;
        };
        fn scan(lo: &Lower, outer: TypeName, bound: &[String], e: AstExprId, deep: bool) -> bool {
            if let Expr::Name(n) = lo.afile.expr(e) {
                if !bound.contains(n)
                    && (lo.resolve_field_name(outer, n).is_some()
                        || lo.resolve_method_name(outer, n).is_some())
                {
                    return true;
                }
            }
            if !deep && matches!(lo.afile.expr(e), Expr::Lambda { .. }) {
                return false;
            }
            lo.afile
                .any_child_expr(e, &mut |c| scan(lo, outer, bound, c, deep), &mut |s| {
                    lo.afile
                        .any_child_stmt(s, &mut |c| scan(lo, outer, bound, c, deep))
                })
        }
        scan(self, outer, bound, body, deep)
    }

    /// Whether the AST subtree at `e` contains a NON-LOCAL `return` (no label — it exits the enclosing
    /// FUNCTION). Labeled returns (`return@withLock`) are local to their lambda and don't count. The
    /// walk descends into nested lambdas: a plain `return` is only legal inside inline lambdas, where
    /// it still exits the enclosing function. Used to gate the `withLock` splice — the suspend
    /// flattener doesn't model a `return` inside the splice's `try`/`finally`.
    fn ast_body_has_nonlocal_return(&self, e: AstExprId) -> bool {
        if matches!(self.afile.expr(e), Expr::Return { label: None, .. }) {
            return true;
        }
        self.afile
            .any_child_expr(e, &mut |c| self.ast_body_has_nonlocal_return(c), &mut |s| {
                matches!(self.afile.stmt(s), Stmt::Return(_, None))
                    || self
                        .afile
                        .any_child_stmt(s, &mut |c| self.ast_body_has_nonlocal_return(c))
            })
    }

    /// Does the AST expression `body` (a lambda body, function body, …) contain a SUSPENSION point — a
    /// call to a `suspend` function (top-level, member, extension, or `invoke` operator)? Works at the
    /// AST level, so it is usable during lowering before the IR `suspend_calls` set exists. The scan
    /// descends into nested lambdas (conservative: a suspension anywhere counts), matching the file's
    /// suspend gate. Used both to classify a suspend lambda literal and to guard the non-inlined
    /// suspend-inline-HOF path (a plain `Function0` argument cannot legally call a suspend function).
    fn ast_body_suspends(&self, body: AstExprId) -> bool {
        let susp_names: std::collections::HashSet<String> = self
            .afile
            .decls
            .iter()
            .filter_map(|&d| match self.afile.decl(d) {
                ast::Decl::Fun(f) if f.is_suspend => Some(f.name.clone()),
                _ => None,
            })
            .collect();
        let call_names_cell = std::cell::RefCell::new(Vec::new());
        collect_call_names(self.afile, body, &call_names_cell);
        if call_names_cell
            .into_inner()
            .iter()
            .any(|n| susp_names.contains(n))
        {
            return true;
        }
        // A MEMBER / invoke-operator suspend call (`getResult()` = `GetResult.suspend operator fun
        // invoke()`, `x.m()` where `m` is `suspend`) is invisible to the top-level-name check above —
        // resolve each callee's type + method `is_suspend` so the body isn't misclassified as leaf.
        let callees = std::cell::RefCell::new(Vec::new());
        collect_calls(self.afile, body, &callees);
        callees.into_inner().into_iter().any(|call| {
            let method_suspends = |internal: TypeName, name: &str| {
                self.syms
                    .class_by_type_name(internal)
                    .map(|c| c.methods_named(name))
                    .is_some_and(|sigs| sigs.iter().any(|s| s.is_suspend))
            };
            // The checker's `Invoke` lowering carries suspend-ness reliably (the receiver's static
            // type may be `Error` at the call site): a suspend function VALUE, or a suspend `invoke`
            // operator on a class receiver.
            if let Some(ExprLowering::Invoke { kind, .. }) = self.info.expr_lowers.get(&call) {
                match kind {
                    InvokeKind::Function { suspend, .. } if *suspend => return true,
                    InvokeKind::Operator {
                        receiver_ty,
                        member: None,
                    } if receiver_ty
                        .obj_internal()
                        .is_some_and(|i| method_suspends(i, "invoke")) =>
                    {
                        return true
                    }
                    InvokeKind::Operator {
                        member: Some(member),
                        ..
                    } if member.suspend => return true,
                    _ => {}
                }
            }
            // A classpath top-level `suspend fun` called by name (`delay(…)`): the CHECKER recorded
            // the resolved callable with its suspend flag.
            if self
                .info
                .resolved_top_level(call)
                .is_some_and(|c| c.suspend)
                || self
                    .info
                    .resolved_module_top_level(call)
                    .is_some_and(|c| c.suspend)
            {
                return true;
            }
            // A plain member call `recv.m(args)` to a suspend method — a USER class method (its
            // suspend flag is in `syms`), or a CLASSPATH member / suspend EXTENSION (`Mutex.withLock`)
            // whose suspend-ness the CHECKER recorded on the resolved callable. The lowerer only reads.
            if let ast::Expr::Call { callee, .. } = self.afile.expr(call) {
                if let ast::Expr::Member { receiver, name } = self.afile.expr(*callee) {
                    let recv_ty = self.info.ty(*receiver);
                    if recv_ty
                        .obj_internal()
                        .is_some_and(|i| method_suspends(i, name))
                    {
                        return true;
                    }
                    if self
                        .info
                        .resolved_member(call)
                        .is_some_and(|m| m.member.suspend)
                        || self
                            .info
                            .resolved_extension(call)
                            .is_some_and(|c| c.suspend)
                    {
                        return true;
                    }
                }
            }
            false
        })
    }

    /// Lower a `suspend` lambda literal to a concrete `kotlin/coroutines/jvm/internal/SuspendLambda`
    /// subclass (kotlinc's representation), returning a `New` of that class with the captured values and
    /// a `null` completion. Arity 0 with no INTERNAL suspension for now: the class implements
    /// `Function{n+1}`, captures the free variables as fields (set in `<init>`, copied into the fresh
    /// instance `invoke` builds), and carries `invokeSuspend(Object)` (the body, result boxed) plus the
    /// erased `invoke(Object)` (`new This(captures.., (Continuation)arg).invokeSuspend(Unit)`).
    fn lower_suspend_lambda(
        &mut self,
        body: AstExprId,
        params: &[Ty],
        bind_names: Vec<String>,
    ) -> Option<u32> {
        let arity = params.len();
        if self.cur_class.is_some() {
            return None;
        }
        // Captured free variables: enclosing locals/parameters the body reads but the lambda doesn't
        // bind as one of its own parameters.
        let mut captures: Vec<(String, u32, Ty)> = Vec::new();
        for (name, v, ty) in self.scope.iter().rev() {
            if !bind_names.contains(name)
                && !captures.iter().any(|(n, _, _)| n == name)
                && self.afile.expr_uses_name(body, name)
            {
                captures.push((name.clone(), *v, *ty));
            }
        }
        captures.reverse();
        let n_cap = captures.len() as u32;
        // Own parameters are modeled only for a LEAF lambda (no captures, no internal suspension) for
        // now — a param + capture/suspension combination needs the general lambda-mode machine.
        if arity > 0 && n_cap > 0 {
            return None;
        }
        // Does the lambda body call a `suspend` function? (AST-level, like the file's suspend gate.)
        // If so its `invokeSuspend` is a state machine with the lambda instance as the continuation —
        // for now only a single TAIL suspend call (`{ foo() }`) with no captures is modeled; anything
        // else bails (skip the file) rather than miscompile the continuation threading.
        let body_suspends = self.ast_body_suspends(body);
        let jvm_arity = arity + 1; // + the trailing continuation
        let function_iface = self
            .syms
            .libraries
            .function_type(jvm_arity)?
            .obj_internal()?
            .to_string();
        let internal = class_internal(
            self.afile,
            &format!("{}$suspend${}", self.cur_fn_name, self.lambda_seq),
        );
        self.lambda_seq += 1;
        let cont_ir = ty_to_ir(Ty::obj("kotlin/coroutines/Continuation"));
        let object_ir = ty_to_ir(Ty::obj("kotlin/Any"));

        // Fields: one per captured variable. `<init>(cap0.., Continuation completion)` stores each
        // capture, then `super(jvm_arity, completion)`. Ctor value-indices: this=0, cap_i=1+i,
        // completion=1+n_cap.
        let mut fields: Vec<(String, Ty)> = captures
            .iter()
            .map(|(name, _, ty)| (name.clone(), ty_to_ir(*ty)))
            .collect();
        // Own parameters become fields after the captures — set by `create(value.., completion)` (NOT
        // the constructor / creation site). `param_field_base` is their first field index.
        let param_field_base = n_cap;
        for (name, ty) in bind_names.iter().zip(params.iter()) {
            fields.push((name.clone(), ty_to_ir(*ty)));
        }
        // A suspending lambda's state-machine fields go after the captures/params. The coroutine pass
        // appends its `result`/`label`/spilled fields after this prefix.
        let ctor_args: Vec<IrCtorArg> = captures
            .iter()
            .map(|(_, _, ty)| IrCtorArg {
                ty: ty_to_ir(*ty),
                is_field: false,
                check: None,
            })
            .chain(std::iter::once(IrCtorArg {
                ty: cont_ir.clone(),
                is_field: false,
                check: None,
            }))
            .collect();
        let init_stores: Vec<u32> = (0..n_cap)
            .map(|i| {
                let this = self.emit_get_value(0);
                let val = self.emit_get_value(1 + i);
                self.emit_set_field(this, 0, i, val)
            })
            .collect();
        let init_body =
            (!init_stores.is_empty()).then(|| self.emit_block(init_stores.clone(), None));
        let arity_const = self.emit_const(IrConst::Int(jvm_arity as i32));
        let completion_get = self.emit_get_value(1 + n_cap);
        // Captures and own parameters are `final`; only the `label` state cursor is mutable. All fields
        // are non-private (read/written by the coroutine state machine cross-class).
        let ir_fields: Vec<IrField> = fields
            .into_iter()
            .enumerate()
            .map(|(i, (name, ty))| IrField {
                is_final: i < (n_cap + arity as u32) as usize,
                is_private: false,
                ..IrField::new(name, ty)
            })
            .collect();
        let class = IrClass {
            fq_name: type_name(&internal),
            is_value: false,
            is_data: false,
            decl_line: 0,
            type_param_bounds: vec![],
            type_params: Vec::new(),
            supertypes: vec![],
            fields: ir_fields,
            ctor_param_count: 0,
            ctor_args,
            init_body,
            explicit_param_stores: false,
            methods: vec![],
            is_interface: false,
            is_annotation: false,
            annotation_impl_of: None,

            is_sealed: false,
            is_abstract: false,
            is_open: false,
            superclass: type_name("kotlin/coroutines/jvm/internal/SuspendLambda"),
            super_args: vec![arity_const, completion_get],
            enum_entries: vec![],
            enum_entry_of: None,
            prop_ref: None,
            func_ref: None,
            bridges: vec![],
            interfaces: vec![type_name(&function_iface)].into(),
            is_object: false,
            is_companion: false,
            companion_class: None,
            secondary_ctors: vec![],
            has_primary_ctor: true,
            applied_annotations: Vec::new(),
            field_annotations: Vec::new(),
            runtime_retained: false,
        };
        let class_id = self.ir.add_class(class);
        // Patch the `<init>` field stores with the now-known class id.
        for &s in &init_stores {
            if let IrExpr::SetField { class, .. } = &mut self.ir.exprs[s as usize] {
                *class = class_id;
            }
        }

        // invokeSuspend(Object result): either the LEAF form (throwOnFailure; load captures; return
        // box(<body>)) or, when the body suspends, a TAIL state machine with `this` as the continuation.
        let throw_on_failure = |s: &mut Self, value_idx: u32| -> Option<u32> {
            let v = s.emit_get_value(value_idx);
            s.runtime_call(RuntimeOp::ThrowOnFailure, Ty::Unit, vec![v])
        };
        // Set when the body needs the general (multi-suspension / control-flow) lambda-mode machine,
        // built by the coroutine pass from the plain `invokeSuspend` body.
        let mut needs_pass_sm = false;
        let inv_susp_body = if body_suspends {
            // Single-suspension lambda (`{ foo() }` or `{ val a = foo(); <tail> }`), no captures (gated
            // above). The continuation is `this`: thread it into the call, dispatch on `this.label`.
            // invokeSuspend value-indices are `this`=0, `result`=1, body locals from 2 — so lower the
            // body with `next_value` reset to 2 (saved/restored so the enclosing method is unaffected).
            let saved_next_sm = self.next_value;
            self.next_value = 2;
            // Bind captures to locals 2..2+n_cap (the coroutine pass reloads them from their fields at
            // each invokeSuspend entry). Only the GENERAL machine is used when there are captures; the
            // inline hand-roll requires `n_cap == 0`.
            let saved_scope_sm = std::mem::take(&mut self.scope);
            for (name, _, ty) in &captures {
                let lv = self.fresh_value();
                self.scope.push((name.clone(), lv, *ty));
            }
            // Own parameters bind to locals after the captures (their fields are reloaded by the pass).
            for (name, pty) in bind_names.iter().zip(params.iter()) {
                let lv = self.fresh_value();
                self.scope.push((name.clone(), lv, *pty));
            }
            // The lambda body is itself a `suspend` context — a suspend MEMBER call inside it
            // (`repo.get(...)` on a classpath suspend interface) must be recorded in `ir.suspend_calls`
            // (gated on `cur_fn_suspend`) so the coroutine pass threads its continuation; without this the
            // call emits without the trailing `Continuation` and fails at runtime (`NoSuchMethodError`).
            let saved_cur_suspend = self.cur_fn_suspend;
            self.cur_fn_suspend = true;
            let saved_in_sl = self.in_suspend_lambda_body;
            self.in_suspend_lambda_body = true;
            // The suspend-lambda machine is its own return scope — don't let an enclosing splice's
            // return frame capture a `return` lowered inside it (illegal across the boundary anyway).
            let saved_lam_frames = std::mem::take(&mut self.inline_lambda_ret);
            // Evaluate WITHOUT `?` so the `cur_fn_suspend` / `scope` state is always restored, even when the
            // body bails (an early `?` here would leak `cur_fn_suspend = true` into the enclosing method).
            let body_val = self.expr(body);
            self.inline_lambda_ret = saved_lam_frames;
            self.cur_fn_suspend = saved_cur_suspend;
            self.in_suspend_lambda_body = saved_in_sl;
            self.scope = saved_scope_sm;
            let body_val = body_val?;
            needs_pass_sm = true;
            // `tmp` goes ABOVE the body's locals (next_value still points past them here).
            let tmp_idx = self.next_value;
            self.next_value = saved_next_sm;
            let body_ty = ty_to_ir(self.info.ty(body));
            let (mut b_stmts, b_val) = match &self.ir.exprs[body_val as usize] {
                IrExpr::Block {
                    stmts,
                    value: Some(v),
                } => (stmts.clone(), *v),
                _ => (Vec::new(), body_val),
            };
            // Bind the body value to a temp (`val tmp = <value>; return box(tmp)`) so a CONDITIONAL
            // suspension in the value (`if (c) foo() else 7`) surfaces as a `Variable{init: When}`
            // the flattener's `stmt_cond_suspension` handles — not a raw `return box(When)`.
            b_stmts.push(self.emit_variable(tmp_idx, body_ty, Some(b_val)));
            let tmpg = self.emit_get_value(tmp_idx);
            let boxed = self.emit_type_op(IrTypeOp::ImplicitCoercion, tmpg, object_ir.clone());
            b_stmts.push(self.emit_return(Some(boxed)));
            self.emit_block(b_stmts, None)
        } else {
            let mut stmts = vec![throw_on_failure(self, 1)?];
            let saved_scope = std::mem::take(&mut self.scope);
            let saved_next = self.next_value;
            self.next_value = 2; // this=0, result=1
            for (i, (name, _, ty)) in captures.iter().enumerate() {
                let lv = self.fresh_value();
                let this = self.emit_get_value(0);
                let getf = self.emit_get_field(this, class_id, i as u32);
                stmts.push(self.emit_variable(lv, ty_to_ir(*ty), Some(getf)));
                self.scope.push((name.clone(), lv, *ty));
            }
            // Own parameters: load each from its field and bind it in the body's scope. The source
            // `Ty` comes from the type checker (the lambda parameter's declared/inferred type).
            for (i, name) in bind_names.iter().enumerate() {
                let pty = params[i];
                let lv = self.fresh_value();
                let this = self.emit_get_value(0);
                let getf = self.emit_get_field(this, class_id, param_field_base + i as u32);
                stmts.push(self.emit_variable(lv, ty_to_ir(pty), Some(getf)));
                self.scope.push((name.clone(), lv, pty));
            }
            let body_val = self.expr(body);
            self.scope = saved_scope;
            self.next_value = saved_next;
            let body_val = body_val?;
            let body_ty = self.info.ty(body);
            if body_ty == Ty::Unit {
                // A `suspend () -> Unit` lambda: run the body for effect, then return the `Unit`
                // singleton — boxing a Unit-typed (no-value) body would `areturn` an empty stack.
                stmts.push(body_val);
                let unit = self.emit_unit();
                stmts.push(self.emit_return(Some(unit)));
            } else if body_ty == Ty::Nothing {
                // The body always diverges (throws/returns) — no trailing return.
                stmts.push(body_val);
            } else {
                let boxed =
                    self.emit_type_op(IrTypeOp::ImplicitCoercion, body_val, object_ir.clone());
                stmts.push(self.emit_return(Some(boxed)));
            }
            self.emit_block(stmts, None)
        };
        let invoke_susp_fid = self.add_synth_method(
            &internal,
            class_id,
            "invokeSuspend",
            vec![object_ir.clone()],
            Ty::obj("kotlin/Any"),
            inv_susp_body,
            true,
        )?; // invokeSuspend is method index 0.
            // Hand the plain `invokeSuspend` to the coroutine pass to flatten into the general state machine
            // (its result/label/spilled fields are appended after the captures/params at `field_base`).
        if needs_pass_sm {
            self.ir
                .suspend_lambda_sm
                .push((invoke_susp_fid, class_id, n_cap + arity as u32));
        }

        // invoke(Object p0.., Object completion): `r = new This(this.cap.., (Continuation)completion);
        // r.param_i = (paramType)p_i; return r.invokeSuspend(Unit.INSTANCE)`. Value-indices: this=0,
        // params 1..=arity, completion=arity+1, the fresh `r` local at arity+2.
        let lambda_ty = Ty::obj(&internal);
        let completion_idx = arity as u32 + 1;
        let mut new_args: Vec<u32> = (0..n_cap)
            .map(|i| {
                let this = self.emit_get_value(0);
                self.emit_get_field(this, class_id, i)
            })
            .collect();
        let comp_get = self.emit_get_value(completion_idx);
        new_args.push(self.emit_type_op(IrTypeOp::Cast, comp_get, cont_ir.clone()));
        let new_inst = self.emit_new(class_id, new_args, None);
        let r_idx = arity as u32 + 2;
        let mut inv_stmts = vec![self.emit_variable(r_idx, lambda_ty.clone(), Some(new_inst))];
        // Store each own parameter (coerced from the erased `Object` argument) into its field.
        for (i, pty) in params.iter().enumerate() {
            let pv = self.emit_get_value(1 + i as u32);
            let coerced = self.emit_type_op(IrTypeOp::ImplicitCoercion, pv, ty_to_ir(*pty));
            let rg = self.emit_get_value(r_idx);
            inv_stmts.push(self.emit_set_field(rg, class_id, param_field_base + i as u32, coerced));
        }
        let rg2 = self.emit_get_value(r_idx);
        let unit = self.emit_unit();
        let call_is = self.emit_method_call(class_id, 0, rg2, vec![Some(unit)]);
        inv_stmts.push(self.emit_return(Some(call_is)));
        let inv_body = self.emit_block(inv_stmts, None);
        self.add_synth_method(
            &internal,
            class_id,
            "invoke",
            vec![object_ir.clone(); arity + 1],
            Ty::obj("kotlin/Any"),
            inv_body,
            true,
        )?;

        // create(value.., Continuation completion): Continuation — the `SuspendLambda` factory that
        // `startCoroutine`/`createCoroutine` invoke at runtime (the base throws "not overridden"). Builds
        // `new This(this.cap.., completion)`, stores each own parameter, and returns the new lambda.
        // Value-indices: this=0, params 1..=arity, completion=arity+1, the fresh `r` at arity+2.
        let mut create_new_args: Vec<u32> = (0..n_cap)
            .map(|i| {
                let this = self.emit_get_value(0);
                self.emit_get_field(this, class_id, i)
            })
            .collect();
        // The completion parameter is already a `Continuation` (the ctor's last param) — no cast.
        create_new_args.push(self.emit_get_value(completion_idx));
        let create_new = self.emit_new(class_id, create_new_args, None);
        let cr_idx = arity as u32 + 2;
        let mut create_stmts = vec![self.emit_variable(cr_idx, lambda_ty, Some(create_new))];
        for (i, pty) in params.iter().enumerate() {
            let pv = self.emit_get_value(1 + i as u32);
            let coerced = self.emit_type_op(IrTypeOp::ImplicitCoercion, pv, ty_to_ir(*pty));
            let rg = self.emit_get_value(cr_idx);
            create_stmts.push(self.emit_set_field(
                rg,
                class_id,
                param_field_base + i as u32,
                coerced,
            ));
        }
        let crg = self.emit_get_value(cr_idx);
        create_stmts.push(self.emit_return(Some(crg)));
        let create_body = self.emit_block(create_stmts, None);
        let mut create_params: Vec<Ty> = vec![Ty::obj("kotlin/Any"); arity];
        create_params.push(Ty::obj("kotlin/coroutines/Continuation"));
        self.add_synth_method(
            &internal,
            class_id,
            "create",
            create_params,
            Ty::obj("kotlin/coroutines/Continuation"),
            create_body,
            true,
        )?;

        // Creation site: `new This(captures.., (Continuation) null)`.
        let mut site_args: Vec<u32> = captures
            .iter()
            .map(|(_, v, _)| self.emit_get_value(*v))
            .collect();
        site_args.push(self.emit_const(IrConst::Null));
        Some(self.emit_new(class_id, site_args, None))
    }

    /// Register a synthesized instance method (a real `IrFunction` with an IR body) on a class, so
    /// it resolves like any other method and the generic emitter handles it — no backend special-case.
    fn add_synth_method(
        &mut self,
        internal: &str,
        class_id: ClassId,
        name: &str,
        params: Vec<Ty>,
        ret: Ty,
        body: u32,
        force_override: bool,
    ) -> Option<u32> {
        if self
            .class_info(internal)
            .map_or(false, |ci| ci.methods.contains_key(name))
        {
            return None; // a user-defined override exists — don't synthesize over it
        }
        // Don't synthesize over a member a superclass provides. For a `data class` member
        // (`force_override`), only a *final* base member blocks generation — an `open` override IS
        // overridden by the synthesized member (KT-6206); a final one is inherited (can't override).
        // Other synthesis (an interface-delegation forwarder) inherits any base member.
        if let Some(s) = self.class_info(internal).and_then(|ci| ci.super_internal) {
            let blocks = if force_override {
                self.syms
                    .method_of_name(s, name)
                    .map_or(false, |sig| sig.is_final)
            } else {
                self.resolve_method_name(s, name).is_some()
            };
            if blocks {
                return None;
            }
        }
        let fid = self.ir.add_fun(IrFunction {
            name: name.to_string(),
            params,
            ret: ty_to_ir(ret),
            body: Some(body),
            is_static: false,
            dispatch_receiver: Some(type_name(internal)),
            param_checks: Vec::new(),
        });
        let idx = self.ir.classes[class_id as usize].methods.len() as u32;
        self.ir.classes[class_id as usize].methods.push(fid);
        if let Some(ci) = self.class_info_mut(internal) {
            ci.methods
                .entry(name.to_string())
                .or_default()
                .push((idx, fid, ret));
        }
        Some(fid)
    }

    /// Synthesize forwarding methods for `: Iface by delegate` — each of `Iface`'s methods becomes
    /// `fun m(args) = this.delegate.m(args)` (an `invokeinterface` on the delegate field). Only
    /// user-interface delegation with a simple `val`-parameter delegate is modeled; anything else
    /// (classpath interface, missing field) returns `None` so the file is skipped, never miscompiled.
    /// Default-argument INHERITANCE: an override declared without defaults reuses the nearest base
    /// class's same-named method's defaults (Kotlin forbids re-declaring defaults on an override;
    /// kotlinc keeps the `$default` stub on the declaring class). Walk the same-module base-class chain
    /// for a method matching `name` + arity whose params carry CONSTANT defaults, and lower them so an
    /// omitted-argument call to the override can fill them. Returns `None` (the call then bails/skips)
    /// when no base default is found, a base is not a module class, or any base default is non-constant.
    fn base_const_defaults(
        &mut self,
        file: &ast::File,
        base_class: Option<&str>,
        name: &str,
        param_tys: &[Ty],
    ) -> Option<Vec<Option<u32>>> {
        let mut cur = base_class.map(str::to_string);
        while let Some(bn) = cur {
            let bc = file.decls.iter().find_map(|&d| match file.decl(d) {
                Decl::Class(c) if c.name == bn => Some(c),
                _ => None,
            })?;
            if let Some(bm) = bc
                .methods
                .iter()
                .find(|m| m.name == name && m.params.len() == param_tys.len())
            {
                if bm.params.iter().any(|p| p.default.is_some()) {
                    let mut defaults = Vec::with_capacity(param_tys.len());
                    for (p, t) in bm.params.iter().zip(param_tys) {
                        match p.default {
                            None => defaults.push(None),
                            Some(d) if is_const_literal(file, d) => {
                                defaults.push(Some(self.lower_arg(d, &ty_to_ir(*t))?));
                            }
                            Some(_) => return None, // a non-constant base default isn't modeled
                        }
                    }
                    return Some(defaults);
                }
            }
            cur = bc.base_class.clone();
        }
        None
    }

    fn synth_delegation_forwarders(
        &mut self,
        file: &ast::File,
        c: &ast::ClassDecl,
        internal: &str,
        class_id: ClassId,
    ) -> Option<()> {
        for (di, (iface_name, delegate, has_primitive_targ)) in c.delegations.iter().enumerate() {
            // A `val`-param delegate has its own field (`a`); a non-`val` param uses the synthesized
            // `$$delegate_<di>` (see field synthesis + the ctor store).
            let is_synth = !c.props.iter().any(|p| p.is_property && &p.name == delegate);
            // A SYNTHESIZED-field delegation to a primitive-instantiated generic interface (`A<Long> by a`
            // where `a` is a non-`val` param) needs the substituted-type bridges that a raw erased-`Object`
            // forward mis-coerces (an `int` literal boxed as `Integer` reaches a `Long` parameter) — skip
            // rather than miscompile. A `val`-param delegate forwards through its own typed field and is
            // handled correctly, so it is not affected.
            if is_synth && *has_primitive_targ {
                return None;
            }
            let synth_name = format!("$$delegate_{di}");
            let delegate_idx =
                self.class_info(internal)?
                    .fields
                    .iter()
                    .position(|(n, _)| n == delegate || n == &synth_name)? as u32;
            self.forward_iface_methods(
                file,
                iface_name,
                delegate_idx,
                class_id,
                internal,
                is_synth,
            )?;
        }
        // Expression delegates (`: I by Impl()`) always use a synthesized `$$delegate_e<j>` field.
        for (j, (iface_name, _e)) in c.delegation_exprs.iter().enumerate() {
            let synth_name = format!("$$delegate_e{j}");
            let delegate_idx = self
                .class_info(internal)?
                .fields
                .iter()
                .position(|(n, _)| n == &synth_name)? as u32;
            self.forward_iface_methods(file, iface_name, delegate_idx, class_id, internal, true)?;
        }
        Some(())
    }

    /// Synthesize, on `internal`, a forwarding method for each of interface `iface_name`'s methods that
    /// calls it on the delegate field at `delegate_idx` (`fun m(args) = this.<field>.m(args)`). When
    /// the delegate is synthesized (a non-`val` param or an expression — not a `val`-param field), bail
    /// (skip the file) on a PROPERTY interface (`getX`/`setX` would go un-forwarded → `AbstractMethodError`)
    /// or a GENERIC one (`A<Long, Int>` needs substituted-type bridges a raw forward mis-coerces).
    fn forward_iface_methods(
        &mut self,
        file: &ast::File,
        iface_name: &str,
        delegate_idx: u32,
        class_id: ClassId,
        internal: &str,
        is_synth: bool,
    ) -> Option<()> {
        // A synthesized-field delegation to a PROPERTY interface (`getX`/`setX`) would go un-forwarded
        // (an `AbstractMethodError`) — skip. A generic interface instantiated with REFERENCE type
        // arguments (`A<String> by a`) forwards correctly at the erased (`Object`) level; only a PRIMITIVE
        // instantiation needs bridges, and that is rejected at the delegation site.
        let iface_internal = self
            .syms
            .class_names
            .get(iface_name)
            .map(TypeName::render)
            .unwrap_or_else(|| class_internal(file, iface_name));
        let iface_sig = self
            .syms
            .class_by_internal(&iface_internal)
            .or_else(|| self.syms.classes.get(iface_name));
        if is_synth && iface_sig.is_some_and(|s| !s.props.is_empty()) {
            return None;
        }
        // Collect the delegated interface's methods AND those inherited from its super-interfaces
        // (`interface Second : First` → forward `First`'s methods too): a `: Second by s` class must
        // implement every method Second exposes, not just the ones Second declares directly. Walk the
        // module-`ClassSig` super-interface graph breadth-first, deduping by name + parameter types.
        let mut methods: Vec<(String, Vec<Ty>, Ty)> = Vec::new();
        let mut seen_ifaces: std::collections::HashSet<TypeName> = std::collections::HashSet::new();
        let mut queue = vec![existing_type_name(&iface_internal)
            .or_else(|| self.syms.classes.get(iface_name).map(|c| c.internal_name()))?];
        while let Some(cur) = queue.pop() {
            if !seen_ifaces.insert(cur) {
                continue;
            }
            // A classpath (non-module) interface in the delegated hierarchy can't have its method set
            // enumerated here, so its forwarders would be missing — bail (skip the file) rather than
            // emit a class with un-forwarded abstract methods (an `AbstractMethodError` at runtime).
            let cs = self.syms.class_by_type_name(cur)?;
            for (n, sigs) in &cs.methods {
                for s in sigs {
                    if !methods.iter().any(|(on, op, _)| on == n && *op == s.params) {
                        methods.push((n.clone(), s.params.clone(), s.ret));
                    }
                }
            }
            // Super-interfaces (and any base) are stored by internal name; the module table is keyed by
            // simple name, so recurse on the last path segment (same-module interfaces resolve; a
            // classpath super-interface simply isn't found and is skipped, as before).
            queue.extend(cs.interface_names());
            if let Some(sup) = cs.super_internal_name() {
                queue.push(sup);
            }
        }
        for (mname, params, ret) in methods {
            let params_ir = tys_to_ir(&params);
            let descriptor = self.runtime.method_descriptor(&params, ret)?;
            let field = self.this_field(class_id, delegate_idx);
            let args: Vec<u32> = (0..params.len())
                .map(|i| self.emit_get_value(i as u32 + 1))
                .collect();
            let call = self.emit_virtual_call(
                iface_internal.clone(),
                mname.clone(),
                descriptor,
                true,
                field,
                args,
            );
            let body = if ret == Ty::Unit {
                self.emit_block(vec![call], None)
            } else {
                let ret_stmt = self.emit_return(Some(call));
                self.emit_block(vec![ret_stmt], None)
            };
            self.add_synth_method(internal, class_id, &mname, params_ir, ret, body, false);
        }
        Some(())
    }

    /// Box an unsigned primitive to its target/library value-class object via the platform synthetic
    /// factory — not a plain boxed carrier, which would lose unsigned identity (`is UInt`, `toString`).
    fn box_unsigned(&mut self, val: u32, ty: Ty) -> Option<u32> {
        self.runtime_call(RuntimeOp::UnsignedBox, ty, vec![val])
    }

    /// Unbox a possibly `Object`-typed unsigned library object back to its scalar carrier: checkcast to the
    /// target value-class type, then `unbox-impl`.
    fn unbox_unsigned(&mut self, val: u32, ty: Ty) -> Option<u32> {
        let c = self
            .runtime
            .runtime_callable(RuntimeOp::UnsignedUnbox, ty)?;
        let owner = c.owner_type();
        let owner_ty = Ty::obj_name(owner);
        let cast = self.emit_type_op(IrTypeOp::Cast, val, ty_to_ir(owner_ty));
        Some(self.emit_virtual_call(owner, c.name, c.descriptor, false, cast, vec![]))
    }

    fn unsigned_to_string(&mut self, val: u32, ty: Ty) -> Option<u32> {
        self.runtime_call(RuntimeOp::UnsignedToString, ty, vec![val])
    }

    fn ir_const_str(&mut self, s: String) -> u32 {
        self.emit_const(IrConst::String(s))
    }
    fn this_field(&mut self, class_id: ClassId, i: u32) -> u32 {
        let this = self.emit_get_value(0);
        self.emit_get_field(this, class_id, i)
    }
    /// The `Int` hash of a field value `v` of type `t` (Kotlin's per-field `.hashCode()`). A value-class
    /// field reads here as its erased underlying; the JVM value-class pass boxes it at the reference
    /// boundary (`Objects.hashCode`) so the value class's own `hashCode` runs.
    /// Whether class `class_id`'s field `i` has a nullable reference type (its lowered `IrType` carries
    /// the `?`), so `hashCode` keeps it on the null-safe `Objects.hashCode` path.
    /// kotlinc's per-field hash in a data-class `hashCode`, shape-for-shape:
    ///
    /// - a non-null primitive → the boxed type's STATIC `hashCode(prim)` (`Integer.hashCode(I)`);
    /// - an array (primitive or boxed, regardless of nullability) → `java.util.Arrays.hashCode`
    ///   (kotlinc CONTENT-hashes data-class arrays even though its `equals` compares them by
    ///   reference — mirror the quirk, the platform layer picks the exact overload);
    /// - any other reference → `invokevirtual <declared class>.hashCode()` on the field's own class
    ///   (a BOXED nullable primitive dispatches on `kotlin/Any` — `Int?` has no JVM class of its own);
    /// - an opaque type (no classifier) → the platform's null-safe object hash.
    ///
    /// A field that can hold null — declared nullable, or a TYPE-PARAMETER field (`val t: T`, whose
    /// erased bound admits null) — wraps its hash in kotlinc's guard `if (f == null) 0 else hash(f)`,
    /// re-reading the field in the non-null arm (no `dup`), phrased so the `When` lowers to kotlinc's
    /// exact layout: `ifnonnull <hash arm>; iconst_0; goto end; <re-read; hash>; end`.
    fn field_hash(&mut self, class_id: ClassId, idx: u32, t: Ty) -> Option<u32> {
        let field = &self.ir.classes[class_id as usize].fields[idx as usize];
        let guarded = field.ty.is_nullable() || field.type_param.is_some();
        // Keys for recording this field's chosen `hashCode` owner (read by the pool seeder).
        let class_internal = self.ir.classes[class_id as usize].fq_name();
        let field_name = field.name.clone();
        // The checker `Ty` of a nullable-primitive field is `Nullable(Int)` — test the classifier
        // under the `?`.
        let is_prim = matches!(
            t.non_null(),
            Ty::Int
                | Ty::Short
                | Ty::Byte
                | Ty::Char
                | Ty::Boolean
                | Ty::Long
                | Ty::Double
                | Ty::Float
        );
        // The hash of the (known non-null) field value `v`.
        let hash_of = |s: &mut Self, v: u32| -> Option<u32> {
            if is_prim {
                return if guarded {
                    // The field is BOXED (`Int?`): kotlinc dispatches `Object.hashCode()` — the
                    // Kotlin type has no JVM class of its own to name as the owner.
                    Some(s.emit_virtual_call(
                        "kotlin/Any",
                        "hashCode".into(),
                        "()I".into(),
                        false,
                        v,
                        vec![],
                    ))
                } else {
                    s.runtime_call(RuntimeOp::HashCode, t, vec![v])
                };
            }
            if t.is_array() {
                return s.runtime_call(RuntimeOp::ArrayHashCode, t, vec![v]);
            }
            match t.non_null().kotlin_class_internal() {
                Some(cls) => {
                    // An INTERFACE-typed field (including annotation types — interfaces at the JVM
                    // level) dispatches `Object.hashCode()`, matching kotlinc: `hashCode` is not an
                    // interface member, so a Methodref on the interface owner would be rejected at
                    // runtime (`IncompatibleClassChangeError`). Interface-ness resolves from the
                    // source file's classes or the classpath; an UNRESOLVABLE classifier also takes
                    // the `Object` owner — always legal, and kotlinc's owner for every non-class.
                    let is_class = s
                        .syms
                        .class_by_internal(&cls.render())
                        .map(|c| !c.is_interface)
                        .unwrap_or_else(|| {
                            s.syms
                                .libraries
                                .resolve_type_name(cls)
                                .is_some_and(|lt| !lt.is_interface())
                        });
                    let owner = if is_class {
                        cls
                    } else {
                        type_name("kotlin/Any")
                    };
                    // Record the owner (backend maps `kotlin/Any` → `java/lang/Object`) so the pool seeder
                    // interns the SAME `hashCode` methodref this body emits.
                    s.ir.set_data_hashcode_owner(&class_internal, &field_name, owner.render());
                    Some(s.emit_virtual_call(
                        owner,
                        "hashCode".into(),
                        "()I".into(),
                        false,
                        v,
                        vec![],
                    ))
                }
                None => s.runtime_call(RuntimeOp::HashCode, t, vec![v]),
            }
        };
        let v = self.this_field(class_id, idx);
        if !guarded {
            return hash_of(self, v);
        }
        let nullc = self.emit_const(IrConst::Null);
        let isnull = self.emit_primitive_bin_op(IrBinOp::RefEq, v, nullc);
        let zero = self.emit_const(IrConst::Int(0));
        let v2 = self.this_field(class_id, idx);
        let hc = hash_of(self, v2)?;
        Some(self.emit_when(vec![(Some(isnull), zero), (None, hc)]))
    }
    /// A `Boolean` IR expr testing field *inequality* (IEEE-aware for float/double, structural for
    /// refs) — used to build `equals` as a chain of `if (a != b) return false` early-outs.
    fn field_ne(&mut self, a: u32, b: u32, t: Ty) -> Option<u32> {
        match t {
            Ty::Double | Ty::Float => {
                let cmp = self.runtime_call(RuntimeOp::PrimitiveCompare, t, vec![a, b])?;
                let z = self.emit_const(IrConst::Int(0));
                Some(self.emit_primitive_bin_op(IrBinOp::Ne, cmp, z))
            }
            // Int/Long/… → native compare; reference (incl. an array property, which a data class
            // compares by reference, not content) → `!Intrinsics.areEqual` via the reference Ne path.
            _ => Some(self.emit_primitive_bin_op(IrBinOp::Ne, a, b)),
        }
    }
    /// `if (cond) return false` — a no-`else` statement-`when` whose only branch diverges.
    fn guard_return_false(&mut self, cond: u32) -> u32 {
        self.guard_return_bool(cond, false)
    }
    /// `if (cond) return <b>` — a no-`else` statement-`when` whose only branch diverges.
    fn guard_return_bool(&mut self, cond: u32, b: bool) -> u32 {
        let f = self.emit_const(IrConst::Boolean(b));
        let ret = self.emit_return(Some(f));
        let blk = self.emit_block(vec![ret], None);
        self.emit_when(vec![(Some(cond), blk)])
    }

    /// Synthesize a `data class`'s `componentN`/`toString`/`hashCode`/`equals` as IR methods over the
    /// first `n` (primary-constructor) fields.
    fn synth_data_members(
        &mut self,
        internal: &str,
        class_id: ClassId,
        n: usize,
        is_object: bool,
    ) -> Option<()> {
        let fields: Vec<(String, Ty)> = self.class_info(internal)?.fields[..n].to_vec();

        // componentN(): `return this.fieldN`.
        for (i, (fname, t)) in fields.iter().enumerate() {
            let get = self.this_field(class_id, i as u32);
            let ret = self.emit_return(Some(get));
            let body = self.emit_block(vec![ret], None);
            let fid = self.add_synth_method(
                internal,
                class_id,
                &format!("component{}", i + 1),
                vec![],
                *t,
                body,
                true,
            );
            // The checker `Ty` drops the declared `?`; the IrField carries it (re-applied at field
            // creation). Recover it on the synthesized return — the value-class mangler hashes a
            // nullable `Lfq?;` element differently from `Lfq;` (`component2` of a `Vid?` property is
            // `component2-<hash of :Lfq?;>` in kotlinc).
            if let Some(fid) = fid {
                if let Some(irf) = self.ir.classes[class_id as usize]
                    .fields
                    .iter()
                    .find(|f| f.name == *fname)
                {
                    self.ir.functions[fid as usize].ret = irf.ty;
                }
            }
        }

        // copy(f1, f2, …): `return P(f1, f2, …)`. Emitted BEFORE toString/hashCode/equals to match
        // kotlinc's data-class member order (componentN, copy, copy$default, toString, hashCode, equals).
        // A `data object` (a singleton) has NO componentN/copy — kotlinc emits only equals/hashCode/toString.
        if !is_object {
            let params: Vec<Ty> = fields.iter().map(|(_, t)| ty_to_ir(*t)).collect();
            let args: Vec<u32> = (0..fields.len())
                .map(|i| self.emit_get_value(i as u32 + 1))
                .collect();
            let new = self.emit_new(class_id, args, None);
            let ret = self.emit_return(Some(new));
            let body = self.emit_block(vec![ret], None);
            if let Some(copy_fid) = self.add_synth_method(
                internal,
                class_id,
                "copy",
                params,
                Ty::obj(internal),
                body,
                true,
            ) {
                // Recover each parameter's declared `?` from its IrField (see componentN above) — it
                // decides the value-class mangle hash and the nullable-erasure of the parameter.
                for (k, (fname, _)) in fields.iter().enumerate() {
                    if let Some(irf) = self.ir.classes[class_id as usize]
                        .fields
                        .iter()
                        .find(|f| f.name == *fname)
                    {
                        self.ir.functions[copy_fid as usize].params[k] = irf.ty;
                    }
                }
                // `copy`'s parameters are the primary-ctor properties, so they take the SAME
                // `checkNotNullParameter` guards kotlinc emits at the constructor — a non-null reference
                // parameter is null-checked at `copy` entry. Reuse the class's precomputed ctor checks.
                let mut checks: Vec<Option<String>> = self.ir.classes[class_id as usize]
                    .ctor_args
                    .iter()
                    .map(|a| a.check.clone())
                    .collect();
                checks.resize(fields.len(), None);
                self.ir.functions[copy_fid as usize].param_checks = checks;
                // Each `copy` parameter defaults to the corresponding receiver property. The `$default`
                // stub's bit-mask is one `int` per 32 params (multi-mask), so any parameter count works.
                {
                    let defaults: Vec<Option<u32>> = (0..fields.len())
                        .map(|i| {
                            let this = self.emit_get_value(0);
                            Some(self.emit_get_field(this, class_id, i as u32))
                        })
                        .collect();
                    self.ir.fn_params.insert(
                        copy_fid,
                        FnParamInfo::defaults(
                            fields.iter().map(|(n, _)| n.clone()).collect(),
                            defaults,
                        ),
                    );
                }
            }
        }

        // toString(): `"Simple(f1=" + f1 + ", f2=" + f2 + ")"`.
        {
            let simple = internal
                .rsplit('/')
                .next()
                .unwrap_or(internal)
                .replace('$', ".");
            // Build ONE `StringConcat` (kotlinc emits a single `StringBuilder`): the class-name prefix is
            // merged with the first field's `name=` (`"P(x="`), then each field value, `", name="`
            // separators, and a closing `")"`.
            let mut parts: Vec<u32> = Vec::new();
            let mut prefix = format!("{simple}(");
            for (i, (name, _)) in fields.iter().enumerate() {
                if i == 0 {
                    prefix.push_str(&format!("{name}="));
                    parts.push(self.ir_const_str(std::mem::take(&mut prefix)));
                } else {
                    parts.push(self.ir_const_str(format!(", {name}=")));
                }
                let mut fv = self.this_field(class_id, i as u32);
                // A data class renders an array property with the platform array-to-string helper (so
                // `[true]`, not the default array identity string), matching kotlinc.
                let field_ir_ty = self.ir.classes[class_id as usize].fields[i].ty;
                if let Some(rendered) =
                    self.runtime_call(RuntimeOp::ArrayToString, field_ir_ty, vec![fv])
                {
                    fv = rendered;
                }
                parts.push(fv);
            }
            if fields.is_empty() {
                parts.push(self.ir_const_str(prefix));
            }
            parts.push(self.ir_const_str(")".to_string()));
            let acc = self.ir.add_expr(IrExpr::StringConcat(parts));
            let ret = self.emit_return(Some(acc));
            let body = self.emit_block(vec![ret], None);
            if let Some(fid) = self.add_synth_method(
                internal,
                class_id,
                "toString",
                vec![],
                Ty::String,
                body,
                true,
            ) {
                self.ir.open_methods.insert(fid); // kotlinc keeps the Object-override open
            }
        }

        // hashCode(): kotlinc emits `return 0` for an empty data class, `return h(f0)` for a single field,
        // and for ≥2 fields a `result` LOCAL it folds into — `result = h(f0); result = result*31 + h(fN);
        // return result` (an explicit `istore`/`iload` round-trip per field). Match that shape exactly.
        {
            let body = if fields.is_empty() {
                let zero = self.emit_const(IrConst::Int(0));
                let ret = self.emit_return(Some(zero));
                self.emit_block(vec![ret], None)
            } else if fields.len() == 1 {
                let h = self.field_hash(class_id, 0, fields[0].1)?;
                let ret = self.emit_return(Some(h));
                self.emit_block(vec![ret], None)
            } else {
                // `result` occupies the first local slot after `this` (hashCode takes no parameters).
                const RV: u32 = 1;
                let mut stmts = Vec::new();
                let h0 = self.field_hash(class_id, 0, fields[0].1)?;
                stmts.push(self.emit_variable(RV, ty_to_ir(Ty::Int), Some(h0)));
                for (i, f) in fields.iter().enumerate().skip(1) {
                    let h = self.field_hash(class_id, i as u32, f.1)?;
                    let prev = self.emit_get_value(RV);
                    let c31 = self.emit_const(IrConst::Int(31));
                    let mul = self.emit_primitive_bin_op(IrBinOp::Mul, prev, c31);
                    let add = self.emit_primitive_bin_op(IrBinOp::Add, mul, h);
                    stmts.push(self.emit_set_value(RV, add));
                }
                let getr = self.emit_get_value(RV);
                stmts.push(self.emit_return(Some(getr)));
                self.emit_block(stmts, None)
            };
            if let Some(fid) =
                self.add_synth_method(internal, class_id, "hashCode", vec![], Ty::Int, body, true)
            {
                self.ir.open_methods.insert(fid); // kotlinc keeps the Object-override open
            }
        }

        // equals(other), matching kotlinc's shape exactly:
        //   if (this === other) return true
        //   if (other !is T) return false
        //   val o = other as T            // cast ONCE into a local, then reuse
        //   if (this.f1 != o.f1) return false; …
        //   return true
        {
            let class_ty = ty_to_ir(Ty::obj(internal));
            // The cast result lives in the first local slot after `this` (0) and `other` (1).
            const OV: u32 = 2;
            let mut stmts = Vec::new();
            // `this === other` referential-identity fast-path.
            let this0 = self.emit_get_value(0);
            let other0 = self.emit_get_value(1);
            let ident = self.emit_primitive_bin_op(IrBinOp::RefEq, this0, other0);
            let id_guard = self.guard_return_bool(ident, true);
            stmts.push(id_guard);
            // `other !is T` → return false.
            let other = self.emit_get_value(1);
            let not_inst = self.emit_type_op(IrTypeOp::NotInstanceOf, other, class_ty.clone());
            let g = self.guard_return_false(not_inst);
            stmts.push(g);
            // `val o = other as T` — one checkcast, stored to the local.
            let other_v = self.emit_get_value(1);
            let ocast = self.emit_type_op(IrTypeOp::Cast, other_v, class_ty.clone());
            stmts.push(self.emit_variable(OV, class_ty.clone(), Some(ocast)));
            for (i, (_, t)) in fields.iter().enumerate() {
                let af = self.this_field(class_id, i as u32);
                let o_local = self.emit_get_value(OV);
                let bf = self.emit_get_field(o_local, class_id, i as u32);
                let ne = self.field_ne(af, bf, *t)?;
                let g = self.guard_return_false(ne);
                stmts.push(g);
            }
            let t = self.emit_const(IrConst::Boolean(true));
            stmts.push(self.emit_return(Some(t)));
            let body = self.emit_block(stmts, None);
            let obj = ty_to_ir(Ty::obj("kotlin/Any"));
            if let Some(fid) = self.add_synth_method(
                internal,
                class_id,
                "equals",
                vec![obj],
                Ty::Boolean,
                body,
                true,
            ) {
                self.ir.open_methods.insert(fid); // kotlinc keeps the Object-override open
            }
        }
        Some(())
    }

    fn lookup(&self, name: &str) -> Option<(u32, Ty)> {
        self.scope
            .iter()
            .rev()
            .find_map(|(n, v, t)| (n == name).then_some((*v, *t)))
    }

    fn class_of(&self, ty: Ty) -> Option<&ClassInfo> {
        ty.obj_internal().and_then(|i| self.class_info_name(i))
    }

    fn single_lambda_arg(&self, args: &[AstExprId]) -> Option<(AstExprId, Vec<String>, AstExprId)> {
        let [arg] = args else {
            return None;
        };
        let Expr::Lambda { params, body } = self.afile.expr(*arg).clone() else {
            return None;
        };
        Some((*arg, params, body))
    }

    /// Route a library `inline fun` call with a lambda argument (`recv.<name> { … }`) to the bytecode
    /// inliner (`Callee::Static` with `inline`), carrying the receiver and the lambda — so its real body
    /// is spliced rather than desugared per-function. Metadata-driven: gated on the resolved callable's
    /// `is_inline` flag, not the name. Only routes a non-capturing, single-value-return lambda (which the
    /// emitter is guaranteed to splice); `None` ⇒ the call falls through to its desugar / normal lowering.
    fn try_route_lambda_inline(
        &mut self,
        e: AstExprId,
        receiver: AstExprId,
        lam_arg: AstExprId,
    ) -> Option<u32> {
        // The bytecode splicer substitutes the receiver inline; it can relocate a simple value but not
        // an `invokedynamic` (a lambda literal or callable reference `::A` as the receiver), so the
        // splice would fail at emit and fall back to a real call to the private `@InlineOnly` callee
        // (IllegalAccessError). Bail so the `let`/`also` desugar — which binds the receiver to a local
        // first — handles it instead.
        if matches!(
            self.afile.expr(receiver),
            Expr::CallableRef { .. } | Expr::Lambda { .. }
        ) {
            return None;
        }
        // The CHECKER resolved this `@InlineOnly` scope fn (`let`/`also`) and recorded the callable; read
        // it. `c.inline` gates the splice (no call is emitted for a `must_inline` callee).
        let c = self.info.resolved_extension(e).cloned()?;
        if !c.inline.can_inline() {
            return None;
        }
        // The emitter's lambda-splice is branchless-only: a branch in the lambda body produces a
        // stackmap frame it can't relocate mid-splice. Route only a branchless body; a branchy one
        // falls through to the per-function desugar, which lowers the body with normal branchy codegen.
        if let Expr::Lambda { body, .. } = self.afile.expr(lam_arg) {
            if body_contains_branch(self.afile, *body) {
                return None;
            }
        }
        let lam = self.expr(lam_arg)?;
        // The argument must be a real lambda (with an `inline_body` to splice) — a callable reference
        // (`::foo`) has none. The emitter handles any lambda body, incl. captures and non-local return.
        if !matches!(
            self.ir.expr(lam),
            IrExpr::Lambda {
                inline_body: Some(_),
                ..
            }
        ) {
            return None;
        }
        let recv = self.expr(receiver)?;
        let (logical, physical) = (c.ret, c.physical_ret);
        let source_receiver = c.source_receiver;
        let call = self.emit_library_static_call(c, vec![recv, lam], false);
        // Record the declared source receiver so the value-class pass keeps a REFERENCE-underlying
        // value-class receiver (`Result.getOrElse`) unboxed: the spliced `-impl` body reads it as the raw
        // underlying, so boxing it to the `Object` receiver parameter (which the descriptor otherwise
        // implies) would feed the body a boxed `kotlin.Result` and mis-`checkcast` it (CCE). The other
        // extension-lowering paths record this; the inline-lambda path must too.
        self.record_ext_source_receiver(call, source_receiver);
        // The inline fn's erased return is `Object` (a generic `R`); coerce the spliced result to the
        // logical return type (`5.let { it+1 }: Int` unboxes `Integer`→`int`), as a normal call would.
        Some(self.coerce_to_static(call, logical, physical))
    }

    /// The internal name of an explicit serializer `X` from `@Serializable(with = X::class)` on class
    /// `c`, or `None`. The arg is a class-literal `X::class` (`CallableRef{name:"class"}`); `X`'s
    /// internal comes from the checker's type of the literal's receiver.
    fn custom_serializer_of(&self, c: &ast::ClassDecl) -> Option<String> {
        let i = c
            .annotations
            .iter()
            .position(|a| a.rsplit(['/', '.']).next() == Some("Serializable"))?;
        let arg = c.annotation_args.get(i).and_then(|args| args.first())?;
        // `X::class` — a class literal; annotation args aren't type-checked, so resolve `X`'s internal
        // name from the symbol table (imports/classpath seed) rather than the checker's expr types.
        if let Expr::CallableRef {
            receiver: Some(r),
            name,
        } = self.afile.expr(*arg)
        {
            if name == "class" {
                if let Expr::Name(x) = self.afile.expr(*r) {
                    return self.syms.class_names.get(x).map(TypeName::render);
                }
            }
        }
        None
    }

    fn class_decl(&self, name: &str) -> Option<&ast::ClassDecl> {
        self.afile
            .decls
            .iter()
            .find_map(|&d| match self.afile.decl(d) {
                Decl::Class(c) if c.name == name => Some(c),
                _ => None,
            })
    }

    fn class_decl_by_type_name(&self, internal: TypeName) -> Option<&ast::ClassDecl> {
        self.afile
            .decls
            .iter()
            .find_map(|&d| match self.afile.decl(d) {
                Decl::Class(c) if type_name(&class_internal(self.afile, &c.name)) == internal => {
                    Some(c)
                }
                _ => None,
            })
    }

    fn serializable_uses_companion_accessor(&self, c: &ast::ClassDecl) -> bool {
        // A plain data class OR a `@Serializable enum` (both relocate `serializer()` to their `Companion`);
        // sealed/generic/custom-serializer classes keep the static accessor.
        matches!(
            c.kind,
            crate::ast::ClassKind::Class | crate::ast::ClassKind::Enum
        ) && !c.is_sealed()
            && c.type_params.is_empty()
            && self.custom_serializer_of(c).is_none()
    }

    /// The IR fq-name id of a `@Serializable` USER class for `ty` (the value/type-arg of a reified
    /// serialization call), or `None`. Detection mirrors the plugin/checker (annotation simple name).
    fn serializable_internal(&self, ty: Ty) -> Option<TypeName> {
        let internal = ty.obj_internal()?;
        let cd = self.class_decl_by_type_name(internal)?;
        let is_ser = cd
            .annotations
            .iter()
            .any(|a| a.rsplit(['/', '.']).next() == Some("Serializable"));
        if !is_ser {
            return None;
        }
        self.class_info_name(internal)
            .map(|ci| self.ir.classes[ci.id as usize].fq_name_id())
    }

    /// `C.serializer()` — routed through `C.Companion` for a PLAIN non-generic `@Serializable` class
    /// (the plugin relocates the accessor there), else `invokestatic C.serializer()` (enum / sealed /
    /// generic keep the static form). The plugin fills the accessor body before emit.
    fn serializer_crossfile(&mut self, c_internal: TypeName) -> u32 {
        let ret = ty_to_ir(Ty::obj_args_name(
            type_name("kotlinx/serialization/KSerializer"),
            &[Ty::obj_name(c_internal)],
        ));
        let companion_routed = self
            .class_decl_by_type_name(c_internal)
            .is_some_and(|c| self.serializable_uses_companion_accessor(c));
        if companion_routed {
            let c_internal_rendered = c_internal.render();
            let comp = format!("{c_internal_rendered}$Companion");
            let recv = self
                .ir
                .external_static_instance(&c_internal_rendered, &comp, "Companion");
            return self.ir.add_expr(IrExpr::Call {
                callee: Callee::CrossFileVirtual {
                    owner: type_name(&comp),
                    name: "serializer".to_string(),
                    params: vec![],
                    ret,
                    interface: false,
                },
                dispatch_receiver: Some(recv),
                args: vec![],
            });
        }
        self.emit_cross_file_call(c_internal, "serializer".to_string(), vec![], ret, vec![])
    }

    /// Desugar a REIFIED kotlinx serialization round-trip call — `fmt.encodeToString(x)` /
    /// `fmt.decodeFromString<C>(s)` — into the 2-arg member with a synthesized `C.serializer()`. The
    /// reified inline form can't be called directly (`UnsupportedOperationException` at runtime), so
    /// krusty rewrites it the way kotlinc's inliner would. `None` (fall through) unless the receiver is a
    /// `StringFormat` and `C` is a `@Serializable` user class.
    fn try_reified_serial(
        &mut self,
        receiver: AstExprId,
        name: &str,
        args: &[AstExprId],
        call: AstExprId,
    ) -> Option<u32> {
        let [arg] = args else {
            return None;
        };
        let fmt = self.info.ty(receiver).obj_internal()?;
        let resolved = self.info.resolved_member(call)?;
        if resolved.member.name != name || resolved.member.params.len() != args.len() {
            return None;
        }
        // Core stays generic: it detects the call structurally and records the resolved facts (format
        // type, `@Serializable` class) plus the already-lowered operands in a `PluginPlaceholder`. The
        // serialization plugin owns the `StringFormat` member descriptors and specializes this node
        // (into the 2-arg member call, with a `checkcast` for decode) before emit.
        //
        // INVARIANT: a placeholder is only produced when `C` is an in-file `@Serializable` class
        // (`serializable_internal`), and `plugins::run_enabled` runs the serialization plugin exactly
        // when the file has such a class — so every placeholder is specialized before emit. If this
        // ever emits for a class that does NOT trigger `run_enabled` (e.g. a cross-file `@Serializable`),
        // the placeholder would survive; `jvm_can_emit` then DECLINES the file (no miscompile) rather
        // than emitting an un-lowered node.
        let (kind, c) = match name {
            "encodeToString" => (
                "encodeToString",
                self.serializable_internal(self.info.ty(*arg))?,
            ),
            "decodeFromString" => {
                // The decoded type is the explicit type argument `<C>`.
                let targ = self
                    .afile
                    .call_type_args
                    .get(&call.0)
                    .and_then(|ts| ts.first())
                    .and_then(|tr| self.ty_ref(tr))?;
                ("decodeFromString", self.serializable_internal(targ)?)
            }
            _ => return None,
        };
        let recv = self.expr(receiver)?;
        let ser = self.serializer_crossfile(c);
        let value = self.expr(*arg)?;
        Some(self.ir.add_expr(IrExpr::PluginPlaceholder {
            plugin: "serialization",
            kind,
            exprs: vec![recv, ser, value],
            data: vec![fmt, c],
        }))
    }

    /// Lower a call's arguments, filling omitted trailing parameters from their **constant-literal**
    /// defaults (`fun f(x: Int = 5)` called `f()`). A non-literal default (one referencing other
    /// params or `this`) needs the `$default` synthetic method krusty doesn't emit yet → `None`.
    /// Lower a (possibly named / defaulted) call's arguments into parameter-slot order. Returns
    /// `(args, prelude)` where `prelude` is a list of temp-declaration statements that MUST run before the
    /// call — non-empty only for a REORDERED named call with side-effecting arguments, whose Kotlin
    /// source-order evaluation is realized by spilling each argument to a temp in source order and loading
    /// the temps in slot order. The caller wraps the built call expression in `Block { stmts: prelude,
    /// value: call }` so the temps live in the enclosing scope (a temp declared in a value-position
    /// `Block` used AS an argument would be scoped away before a later argument reads it).
    fn lower_args_defaulted(
        &mut self,
        call: AstExprId,
        param_meta: &[(String, Option<AstExprId>)],
        args: &[AstExprId],
        ir_params: &[Ty],
    ) -> Option<(Vec<u32>, Vec<u32>)> {
        let n = ir_params.len();
        if args.len() > n {
            return None;
        }
        // Place each argument into its parameter slot: a positional arg fills the next free position;
        // a named arg (`x = …`) fills its named parameter. Unfilled slots take constant-literal
        // defaults. (Arguments are evaluated in slot order — fine for the side-effect-free common case.)
        let names = self
            .afile
            .call_arg_names
            .get(&call.0)
            .cloned()
            .unwrap_or_default();
        let mut slot: Vec<Option<AstExprId>> = vec![None; n];
        let mut pos = 0;
        // The slot each SOURCE-order argument lands in. Kotlin evaluates arguments in source order; this
        // helper lowers them in slot order, so a named-argument call that REORDERS evaluation
        // (`f(b = …, a = …)`) would run side effects out of order. Detect a non-monotonic placement and,
        // if any reordered argument may have side effects, skip (proper source-order temp-spilling isn't
        // modeled yet) — pure reordered arguments (const/name reads) are order-independent and proceed.
        let mut arg_slot: Vec<usize> = Vec::with_capacity(args.len());
        let mut seen_named = false;
        for (i, &arg) in args.iter().enumerate() {
            match names.get(i).and_then(|o| o.as_ref()) {
                None => {
                    if seen_named {
                        // A TRAILING LAMBDA is the one positional argument allowed after named args — it
                        // fills the LAST parameter. Only the final argument may be such.
                        if i == args.len() - 1 && n > 0 && slot[n - 1].is_none() {
                            slot[n - 1] = Some(arg);
                            arg_slot.push(n - 1);
                        } else {
                            return None;
                        }
                    } else if i == args.len() - 1
                        && n > 0
                        && slot[n - 1].is_none()
                        && self.afile.call_has_trailing_lambda.contains(&call.0)
                    {
                        // A SYNTACTIC trailing lambda always binds to the LAST parameter; any preceding
                        // parameter left without a positional argument takes its default. So `host("x") {}`
                        // on `host(a, modifier = d, builder)` fills `builder` (not `modifier`) and defaults
                        // `modifier`. Without this, the lambda lands in the next free slot (`modifier`) and
                        // the required `builder` is left unfilled → lowering bails.
                        slot[n - 1] = Some(arg);
                        arg_slot.push(n - 1);
                    } else {
                        if pos >= n {
                            return None;
                        }
                        slot[pos] = Some(arg);
                        arg_slot.push(pos);
                        pos += 1;
                    }
                }
                Some(nm) => {
                    seen_named = true;
                    let idx = param_meta.iter().position(|(name, _)| name == nm)?;
                    if idx >= n || slot[idx].is_some() {
                        return None;
                    }
                    slot[idx] = Some(arg);
                    arg_slot.push(idx);
                }
            }
        }
        let reordered = arg_slot.windows(2).any(|w| w[0] > w[1]);
        // Whether the reordering moves a SIDE-EFFECTING argument out of source order. A pure argument
        // (const literal / bare name read) is order-independent, so slot-order lowering is still correct
        // (and byte-identical to before). The TRAILING LAMBDA is excluded: it is the last source argument
        // AND fills the last slot, so it is never evaluated out of order.
        let needs_source_order = reordered
            && args.iter().enumerate().any(|(i, &a)| {
                let is_trailing_lambda =
                    i == args.len() - 1 && matches!(self.afile.expr(a), Expr::Lambda { .. });
                !is_trailing_lambda
                    && !is_const_literal(self.afile, a)
                    && !matches!(self.afile.expr(a), Expr::Name(_))
            });
        if !needs_source_order {
            let mut a = Vec::new();
            for (k, pt) in ir_params.iter().enumerate() {
                match slot[k] {
                    Some(arg) => a.push(self.lower_arg(arg, pt)?),
                    None => {
                        let def = param_meta.get(k).and_then(|(_, d)| *d)?;
                        if !is_const_literal(self.afile, def) {
                            return None;
                        }
                        a.push(self.lower_arg(def, pt)?);
                    }
                }
            }
            return Some((a, Vec::new()));
        }
        // Source-order spill: lower each source argument into a fresh temp in SOURCE order (the prelude),
        // then load the temps in SLOT order for the call. The caller runs the prelude before the call.
        let mut slot_temp: Vec<Option<u32>> = vec![None; n];
        let mut prelude: Vec<u32> = Vec::new();
        for (i, &arg) in args.iter().enumerate() {
            let k = arg_slot[i];
            let v = self.lower_arg(arg, &ir_params[k])?;
            let tmp = self.fresh_value();
            let decl = self.emit_variable(tmp, ty_to_ir(ir_params[k]), Some(v));
            prelude.push(decl);
            slot_temp[k] = Some(tmp);
        }
        let mut a = Vec::new();
        for k in 0..n {
            let val = match slot_temp[k] {
                Some(tmp) => self.emit_get_value(tmp),
                None => {
                    let def = param_meta.get(k).and_then(|(_, d)| *d)?;
                    if !is_const_literal(self.afile, def) {
                        return None;
                    }
                    self.lower_arg(def, &ir_params[k])?
                }
            };
            a.push(val);
        }
        Some((a, prelude))
    }

    /// Wrap a call expression whose arguments needed a source-order temp `prelude` (from
    /// [`lower_args_defaulted`]) in a `Block { stmts: prelude, value: call }`, so the temps are declared
    /// in the enclosing scope and stay live while the call loads them. An empty prelude returns `call`
    /// unchanged (the common path).
    fn wrap_arg_prelude(&mut self, call: u32, prelude: Vec<u32>) -> u32 {
        if prelude.is_empty() {
            return call;
        }
        self.emit_block(prelude, Some(call))
    }

    /// Lower a top-level function call that OMITS one or more defaulted arguments, via kotlinc's
    /// `foo$default(realparams…, int mask, Object marker)` synthetic (`Callee::LocalDefault`, emitted by
    /// `emit_facade_default_stub`). Each PROVIDED argument is evaluated in SOURCE order into a temp (so a
    /// reordered named call keeps left-to-right side-effect order) and loaded in slot order; each OMITTED
    /// slot gets a zero placeholder and its bit set in the mask; the marker is `null`. Used when the plain
    /// call-site fill (`lower_args_defaulted`) can't handle the omission (a NON-const default). Returns
    /// `None` (caller skips) if the labels don't map cleanly or an argument can't be lowered. `param_meta`
    /// gives each parameter's (name, default) — a slot with no default that is omitted ⇒ `None` (can't
    /// call `$default`).
    fn lower_toplevel_default_call(
        &mut self,
        call: AstExprId,
        fid: u32,
        param_meta: &[(String, Option<AstExprId>)],
        args: &[AstExprId],
        ir_params: &[Ty],
        vararg: bool,
    ) -> Option<u32> {
        let n = ir_params.len();
        if args.len() > n || param_meta.len() != n {
            return None;
        }
        // Only when a `$default` synthetic is actually emitted for `fid` (simple defaults, unmangled) —
        // the same gate the emitter uses, so a routed call always has a target and the stub is sound.
        if !crate::ir::toplevel_default_stub_safe(&self.ir, fid) {
            return None;
        }
        // Map each source argument onto its parameter slot (label → named position; unlabelled → next
        // free positional). `arg_slot[i]` is the slot source-argument `i` lands in.
        let names = self.afile.call_arg_names.get(&call.0).cloned();
        let mut slot: Vec<Option<AstExprId>> = vec![None; n];
        let mut arg_slot: Vec<usize> = Vec::with_capacity(args.len());
        let mut pos = 0usize;
        for (i, &arg) in args.iter().enumerate() {
            match names
                .as_ref()
                .and_then(|ns| ns.get(i))
                .and_then(|o| o.as_ref())
            {
                None => {
                    while pos < n && slot[pos].is_some() {
                        pos += 1;
                    }
                    if pos >= n {
                        return None;
                    }
                    slot[pos] = Some(arg);
                    arg_slot.push(pos);
                    pos += 1;
                }
                Some(nm) => {
                    let idx = param_meta.iter().position(|(name, _)| name == nm)?;
                    if slot[idx].is_some() {
                        return None;
                    }
                    slot[idx] = Some(arg);
                    arg_slot.push(idx);
                }
            }
        }
        // The trailing `vararg` slot is filled with an EMPTY array (not via `$default`); only the
        // OMITTED case is modeled here — a provided vararg element would need array collection (a later
        // slice), so bail if the vararg slot received an argument.
        if vararg && slot[n - 1].is_some() {
            return None;
        }
        // Every omitted slot must have a default so `$default` can fill it — except the trailing `vararg`
        // (filled with an empty array below).
        for (k, s) in slot.iter().enumerate() {
            if s.is_none() && param_meta[k].1.is_none() && !(vararg && k == n - 1) {
                return None;
            }
        }
        // Provided arguments evaluated in SOURCE order into temps (preserving side-effect order).
        let mut slot_temp: Vec<Option<u32>> = vec![None; n];
        let mut prelude: Vec<u32> = Vec::new();
        for (i, &arg) in args.iter().enumerate() {
            let k = arg_slot[i];
            let v = self.lower_arg(arg, &ir_params[k])?;
            let tmp = self.fresh_value();
            let decl = self.emit_variable(tmp, ir_params[k], Some(v));
            prelude.push(decl);
            slot_temp[k] = Some(tmp);
        }
        crate::trace_compiler!(
            "resolve",
            "lower_toplevel_default_call fid={fid} ir_params={ir_params:?} slot_temp={slot_temp:?}"
        );
        // Build the `$default` argument list in slot order: provided temp, or a zero placeholder for an
        // omitted slot (with its mask bit set). Then the mask words and the null marker.
        let mut a: Vec<u32> = Vec::with_capacity(n + default_mask_count(n) + 1);
        let mut omitted = Vec::new();
        for (k, item) in slot_temp.iter().enumerate() {
            match item {
                Some(tmp) => a.push(self.emit_get_value(*tmp)),
                // The omitted trailing `vararg` slot gets an EMPTY array and NO mask bit (a vararg is
                // passed through by `$default`, not filled from the mask).
                None if vararg && k == n - 1 => a.push(self.empty_array(ir_params[k])),
                None => {
                    omitted.push(k);
                    a.push(self.zero_placeholder(ir_params[k]));
                }
            }
        }
        self.append_default_masks_marker(&mut a, n, omitted);
        let dcall = self.emit_local_default_call(fid, a);
        Some(self.wrap_arg_prelude(dcall, prelude))
    }

    fn lower_cross_file_module_call(
        &mut self,
        call: AstExprId,
        target: &ResolvedModuleTopLevelCall,
        facade: TypeName,
        args: &[AstExprId],
    ) -> Option<u32> {
        if target.call_sig.vararg {
            return None;
        }
        let ir_params = tys_to_ir(&target.params);
        let n = ir_params.len();
        let ctx_n = target.context_args.len();
        if ctx_n > n {
            return None;
        }

        let names = self
            .afile
            .call_arg_names
            .get(&call.0)
            .cloned()
            .unwrap_or_default();
        let mut slot: Vec<Option<AstExprId>> = vec![None; n];
        let mut arg_slot: Vec<usize> = Vec::with_capacity(args.len());
        let mut pos = ctx_n;
        let mut seen_named = false;
        for (i, &arg) in args.iter().enumerate() {
            match names.get(i).and_then(|o| o.as_ref()) {
                None => {
                    if seen_named {
                        if i == args.len() - 1
                            && n > ctx_n
                            && slot[n - 1].is_none()
                            && self.afile.call_has_trailing_lambda.contains(&call.0)
                        {
                            slot[n - 1] = Some(arg);
                            arg_slot.push(n - 1);
                        } else {
                            return None;
                        }
                    } else if i == args.len() - 1
                        && n > ctx_n
                        && slot[n - 1].is_none()
                        && self.afile.call_has_trailing_lambda.contains(&call.0)
                    {
                        slot[n - 1] = Some(arg);
                        arg_slot.push(n - 1);
                    } else {
                        while pos < n && slot[pos].is_some() {
                            pos += 1;
                        }
                        if pos >= n {
                            return None;
                        }
                        slot[pos] = Some(arg);
                        arg_slot.push(pos);
                        pos += 1;
                    }
                }
                Some(nm) => {
                    seen_named = true;
                    let idx = target
                        .call_sig
                        .param_names
                        .iter()
                        .position(|name| name == nm)?;
                    if idx < ctx_n || idx >= n || slot[idx].is_some() {
                        return None;
                    }
                    slot[idx] = Some(arg);
                    arg_slot.push(idx);
                }
            }
        }

        let mut slot_temp: Vec<Option<u32>> = vec![None; n];
        let mut prelude = Vec::new();
        for (i, &arg) in args.iter().enumerate() {
            let k = arg_slot[i];
            let v = self.lower_arg(arg, &ir_params[k])?;
            let tmp = self.fresh_value();
            let decl = self.emit_variable(tmp, ir_params[k], Some(v));
            prelude.push(decl);
            slot_temp[k] = Some(tmp);
        }

        let mut lowered_args = Vec::with_capacity(n + 2);
        for (k, item) in slot_temp.iter().enumerate() {
            if k < ctx_n {
                let (v, _) = self.lookup(&target.context_args[k])?;
                lowered_args.push(self.emit_get_value(v));
            } else if let Some(tmp) = item {
                lowered_args.push(self.emit_get_value(*tmp));
            } else if target.call_sig.param_has_default(k) {
                let default = target
                    .param_default_values
                    .get(k)
                    .and_then(|v| v.as_ref())?;
                if !default.fills_param_ty(target.params[k]) {
                    return None;
                }
                lowered_args.push(ctor_default_to_ir(&mut self.ir, self.runtime, default)?);
            } else {
                return None;
            }
        }

        let ret = ty_to_ir(target.ret);
        let emitted = self.emit_cross_file_call(
            facade,
            target.name.clone(),
            ir_params.clone(),
            ret,
            lowered_args,
        );
        if target.suspend {
            self.ir.suspend_calls.insert(emitted, ret);
        }
        Some(self.wrap_arg_prelude(emitted, prelude))
    }

    /// Lower a NAMED-argument call to a same-file USER-class instance method (`z.test(b = …, a = …)`)
    /// whose parameters are all required (no defaults/varargs) and exactly supplied. Evaluates the
    /// RECEIVER first, then each argument in SOURCE order into a temp, then invokes the method with the
    /// temps loaded in parameter (slot) order — matching Kotlin's left-to-right evaluation while binding
    /// each labelled argument to its position. The whole thing is a `Block { stmts: [recv temp, arg
    /// temps…], value: MethodCall }` so the temps live across the call. Returns `None` (caller skips the
    /// file) if the labels don't map cleanly. Preconditions (exact arity, no vararg/defaults) are checked
    /// by the caller.
    fn lower_named_member_call(
        &mut self,
        call: AstExprId,
        receiver: AstExprId,
        name: &str,
        args: &[AstExprId],
        internal: &str,
    ) -> Option<u32> {
        let (class, index, fid, _) = self.resolve_method(internal, name)?;
        let params = self.ir.functions[fid as usize].params.clone();
        let n = params.len();
        let sig = self.syms.method_of(internal, name)?;
        let param_names = sig.param_names;
        if param_names.len() != n || args.len() != n {
            return None;
        }
        // Map each source argument onto its parameter slot (a label names a parameter; an unlabelled arg
        // fills the next free position). `arg_slot[i]` is the slot source-argument `i` lands in.
        let names = self.afile.call_arg_names.get(&call.0)?;
        let mut slot: Vec<Option<AstExprId>> = vec![None; n];
        let mut arg_slot: Vec<usize> = Vec::with_capacity(n);
        let mut pos = 0usize;
        for (i, &arg) in args.iter().enumerate() {
            match names.get(i).and_then(|o| o.as_ref()) {
                None => {
                    if pos >= n || slot[pos].is_some() {
                        return None;
                    }
                    slot[pos] = Some(arg);
                    arg_slot.push(pos);
                    pos += 1;
                }
                Some(nm) => {
                    let idx = param_names.iter().position(|p| p == nm)?;
                    if slot[idx].is_some() {
                        return None;
                    }
                    slot[idx] = Some(arg);
                    arg_slot.push(idx);
                }
            }
        }
        // Receiver first (a `z.test(…)` where `z` has side effects evaluates `z` before the arguments).
        let recv_v = self.expr(receiver)?;
        let recv_tmp = self.fresh_value();
        let recv_ty = ty_to_ir(self.info.ty(receiver));
        let recv_decl = self.emit_variable(recv_tmp, recv_ty, Some(recv_v));
        let mut prelude = vec![recv_decl];
        // Arguments in SOURCE order → temps (typed by their target slot).
        let mut slot_temp: Vec<Option<u32>> = vec![None; n];
        for (i, &arg) in args.iter().enumerate() {
            let k = arg_slot[i];
            let v = self.lower_arg(arg, &params[k])?;
            let tmp = self.fresh_value();
            let decl = self.emit_variable(tmp, params[k], Some(v));
            prelude.push(decl);
            slot_temp[k] = Some(tmp);
        }
        // Load the temps in slot order for the call.
        let recv_read = self.emit_get_value(recv_tmp);
        let mut a: Vec<Option<u32>> = Vec::with_capacity(n);
        for slot in &slot_temp {
            let tmp = (*slot)?;
            a.push(Some(self.emit_get_value(tmp)));
        }
        let mcall = self.emit_method_call(class, index, recv_read, a);
        Some(self.emit_block(prelude, Some(mcall)))
    }

    /// Lower a named same-module extension call while preserving source evaluation order.
    fn lower_named_ext_call(
        &mut self,
        call: AstExprId,
        receiver: AstExprId,
        fid: u32,
        args: &[AstExprId],
    ) -> Option<u32> {
        let params = self.ir.functions[fid as usize].params.clone();
        let n = params.len();
        if args.len() + 1 != n {
            return None;
        }
        let names = self.ir.param_names(fid)?.to_vec();
        if names.len() != n {
            return None;
        }
        // Map each source argument onto a LOGICAL slot in `1..n` (slot 0 is the receiver).
        let arg_names = self.afile.call_arg_names.get(&call.0)?;
        let mut slot_filled = vec![false; n];
        slot_filled[0] = true;
        let mut arg_slot: Vec<usize> = Vec::with_capacity(args.len());
        let mut pos = 1usize;
        for (i, _) in args.iter().enumerate() {
            match arg_names.get(i).and_then(|o| o.as_ref()) {
                None => {
                    if pos >= n || slot_filled[pos] {
                        return None;
                    }
                    slot_filled[pos] = true;
                    arg_slot.push(pos);
                    pos += 1;
                }
                Some(nm) => {
                    let idx = names.iter().position(|p| p == nm).filter(|&x| x >= 1)?;
                    if slot_filled[idx] {
                        return None;
                    }
                    slot_filled[idx] = true;
                    arg_slot.push(idx);
                }
            }
        }
        let recv_v = self.lower_ext_receiver(receiver, &params[0], &params[0])?;
        let recv_tmp = self.fresh_value();
        let recv_decl = self.emit_variable(recv_tmp, params[0], Some(recv_v));
        let mut prelude = vec![recv_decl];
        let mut slot_temp: Vec<Option<u32>> = vec![None; n];
        for (i, &arg) in args.iter().enumerate() {
            let k = arg_slot[i];
            let v = self.lower_arg(arg, &params[k])?;
            let tmp = self.fresh_value();
            let decl = self.emit_variable(tmp, params[k], Some(v));
            prelude.push(decl);
            slot_temp[k] = Some(tmp);
        }
        // Build args `[receiver, slot1, …]` in slot order.
        let mut a = vec![self.emit_get_value(recv_tmp)];
        for slot in slot_temp.iter().skip(1) {
            let tmp = (*slot)?;
            a.push(self.emit_get_value(tmp));
        }
        let ecall = self.emit_local_call(fid, a);
        Some(self.emit_block(prelude, Some(ecall)))
    }

    /// Lower source-order arguments into temporaries, then load them in checker-resolved parameter-slot
    /// order. This preserves Kotlin's left-to-right evaluation while keeping name resolution in the
    /// checker.
    fn lower_args_from_resolved_slots(
        &mut self,
        call: AstExprId,
        args: &[AstExprId],
        params: &[Ty],
    ) -> Option<(Vec<u32>, Vec<u32>)> {
        let slots = self.info.resolved_call_arg_slots.get(&call)?.clone();
        if slots.len() != args.len() || slots.iter().any(Option::is_none) {
            return None;
        }
        if params.len() != slots.len() {
            return None;
        }
        let mut slot_temp: Vec<Option<u32>> = vec![None; params.len()];
        let mut prelude = Vec::new();
        for &arg in args {
            let slot_idx = slots.iter().position(|slot| *slot == Some(arg))?;
            if slot_temp[slot_idx].is_some() {
                return None;
            }
            let ir_ty = ty_to_ir(params[slot_idx]);
            let value = self.lower_arg(arg, &ir_ty)?;
            let tmp = self.fresh_value();
            prelude.push(self.emit_variable(tmp, ir_ty, Some(value)));
            slot_temp[slot_idx] = Some(tmp);
        }
        let mut lowered = Vec::with_capacity(params.len());
        for tmp in slot_temp {
            lowered.push(self.emit_get_value(tmp?));
        }
        Some((lowered, prelude))
    }

    /// The receiver's class type for member access. The checker types a bare `object` name as
    /// `Error` (it's only a qualifier), so map an object-name receiver to its object type; otherwise
    /// use the checker's inferred type.
    fn recv_ty(&self, receiver: AstExprId) -> Ty {
        if let Expr::Name(rn) = self.afile.expr(receiver) {
            let internal = class_internal(self.afile, rn);
            if self
                .class_info(&internal)
                .map_or(false, |ci| self.ir.classes[ci.id as usize].is_object)
            {
                return Ty::obj(&internal);
            }
        }
        self.info.ty(receiver)
    }

    /// The emitted id of a top-level extension `name` applicable to `recv_ty`, plus the receiver type
    /// the extension was found on. Exact receiver matches win before walking supertypes.
    fn ext_fun_id_for_recv(&self, recv_ty: Ty, name: &str, n_args: usize) -> Option<(u32, Ty)> {
        let pick = |recv: Ty| {
            self.ext_fun_id_by_arity
                .get(&(recv.erased_recv(), name.to_string(), n_args))
                .or_else(|| {
                    self.ext_fun_ids
                        .get(&(recv.erased_recv(), name.to_string()))
                })
                .copied()
        };
        if let Some(fid) = pick(recv_ty) {
            return Some((fid, recv_ty));
        }
        if let Some(i) = recv_ty.non_null().obj_internal() {
            if self.resolve_method_name(i, name).is_some() {
                return None;
            }
        }
        let mut seen = std::collections::HashSet::new();
        let mut queue: std::collections::VecDeque<TypeName> = std::collections::VecDeque::new();
        if let Some(c) = recv_ty
            .non_null()
            .obj_internal()
            .and_then(|i| self.syms.class_by_type_name(i))
        {
            for i in c.interface_names() {
                queue.push_back(i);
            }
            if let Some(s) = c.super_internal_name() {
                queue.push_back(s);
            }
        }
        while let Some(internal) = queue.pop_front() {
            if !seen.insert(internal) {
                continue;
            }
            let Some(c) = self.syms.class_by_type_name(internal) else {
                continue;
            };
            if c.tparam_names.is_empty() {
                if let Some(fid) = pick(Ty::obj_name(internal)) {
                    return Some((fid, Ty::obj_name(internal)));
                }
            }
            for i in c.interface_names() {
                queue.push_back(i);
            }
            if let Some(s) = c.super_internal_name() {
                queue.push_back(s);
            }
        }
        None
    }

    fn lower_ext_receiver(
        &mut self,
        receiver: AstExprId,
        decl_recv: &Ty,
        param0: &Ty,
    ) -> Option<u32> {
        let recv_ty = self.recv_ty(receiver);
        let recv = self.lower_arg(receiver, param0)?;
        if recv_ty.is_reference() && recv_ty.erased_recv() != decl_recv.erased_recv() {
            return Some(self.emit_type_op(IrTypeOp::Cast, recv, *param0));
        }
        Some(recv)
    }

    /// An arithmetic operator member of a primitive numeric type called by its METHOD name
    /// (`a.plus(b)`, `a.times(b)`, … — valid Kotlin, identical to `a + b`). The checker already typed it;
    /// lower it to the same `PrimitiveBinOp` the operator form produces (with mixed-operand promotion and
    /// the unsigned `div`/`rem` intrinsics). Returns `None` for a name/receiver this doesn't model.
    fn lower_prim_op_method(
        &mut self,
        recv: AstExprId,
        name: &str,
        arg: AstExprId,
        result_ty: Ty,
    ) -> Option<u32> {
        let lt = self.info.ty(recv);
        // Bitwise/shift operator-methods (`a.and(b)`, `a shl b`, …) are stdlib intrinsics on `Int`/`Long`
        // only — kotlinc maps them to `iand`/`ishl`/… . `and`/`or`/`xor` take the receiver's own type;
        // the shifts take an `Int` count (no numeric promotion). Recognized here so both the plain `.`
        // call and an (unnecessary) safe `?.` call on a non-null primitive share one lowering.
        // `a.compareTo(b)` on numeric primitives → `{Integer,Long,Float,Double}.compare(a, b)` (−1/0/1)
        // after promoting both operands to their common type (`1.compareTo(1.1)` → `Double.compare`).
        // `Byte`/`Short`/`Char` compare in the `int` category. Shared so `a?.compareTo(b)` on a non-null
        // primitive lowers identically; a user `operator compareTo` has a reference receiver, handled
        // elsewhere.
        if name == "compareTo" && self.has_scalar_value_repr(lt) {
            let at = self.info.ty(arg);
            if lt == Ty::Char && at == Ty::Char {
                let pir = ty_to_ir(Ty::Int);
                let l = self.lower_arg(recv, &pir)?;
                let r = self.lower_arg(arg, &pir)?;
                return self.runtime_call(RuntimeOp::PrimitiveCompare, Ty::Int, vec![l, r]);
            }
            if let Some(p) =
                Ty::promote(lt, at).filter(|p| self.has_scalar_value_repr(*p) && *p != Ty::Boolean)
            {
                let pir = ty_to_ir(p);
                let l = self.lower_arg(recv, &pir)?;
                let r = self.lower_arg(arg, &pir)?;
                return self.runtime_call(RuntimeOp::PrimitiveCompare, p, vec![l, r]);
            }
        }
        let lt_bits = self.scalar_value_repr(lt).unwrap_or(lt);
        if matches!(lt_bits, Ty::Int | Ty::Long) {
            let shift = matches!(name, "shl" | "shr" | "ushr");
            let bop = match name {
                "and" => Some(IrBinOp::BitAnd),
                "or" => Some(IrBinOp::BitOr),
                "xor" => Some(IrBinOp::BitXor),
                "shl" => Some(IrBinOp::Shl),
                "shr" => Some(IrBinOp::Shr),
                "ushr" => Some(IrBinOp::Ushr),
                _ => None,
            };
            if let Some(op) = bop {
                let l = self.expr(recv)?;
                let rt = if shift { Ty::Int } else { lt };
                let r = self.lower_arg(arg, &ty_to_ir(rt))?;
                return Some(self.emit_primitive_bin_op(op, l, r));
            }
        }
        if lt == Ty::Boolean {
            let bop = match name {
                "and" => Some(IrBinOp::BitAnd),
                "or" => Some(IrBinOp::BitOr),
                "xor" => Some(IrBinOp::BitXor),
                _ => None,
            };
            if let Some(op) = bop {
                let l = self.expr(recv)?;
                let r = self.lower_arg(arg, &ty_to_ir(Ty::Boolean))?;
                return Some(self.emit_primitive_bin_op(op, l, r));
            }
        }
        let op = BinOp::from_arith_operator_name(name)?;
        let (lt, rt) = (self.info.ty(recv), self.info.ty(arg));
        if !self.has_scalar_value_repr(lt)
            || !self.has_scalar_value_repr(rt)
            || lt == Ty::Boolean
            || rt == Ty::Boolean
        {
            return None;
        }
        // Unsigned `div`/`rem` need platform unsigned helpers (signed `+`/`-`/`*` share opcodes).
        if lt.is_unsigned() && matches!(op, BinOp::Div | BinOp::Rem) {
            let l = self.expr(recv)?;
            let r = self.expr(arg)?;
            let runtime_op = if op == BinOp::Div {
                RuntimeOp::UnsignedDivide
            } else {
                RuntimeOp::UnsignedRemainder
            };
            return self.runtime_call(runtime_op, lt, vec![l, r]);
        }
        let irop = bin_to_ir(op)?;
        let mut l = self.expr(recv)?;
        let mut r = self.expr(arg)?;
        // Compute in the operands' common stack representation — the numeric-promoted type, or plain
        // `Int` for the int-category types (`Char`/`Byte`/`Short`) that share the int stack but have no
        // promotion rule. Then coerce the result to whatever type the resolver assigned the call:
        // `Char.plus(Int)` → `Char` (i2c), `Int.plus(Long)` → `Long`, `UInt.plus(UInt)` → `UInt`
        // (same int rep, a no-op). One generic flow driven by the resolved types — no per-type case.
        let lrep = self.scalar_value_repr(lt)?;
        let rrep = self.scalar_value_repr(rt)?;
        let op_ty = Ty::promote(lrep, rrep).unwrap_or(Ty::Int);
        let op_ir = ty_to_ir(op_ty);
        if lrep != op_ty {
            l = self.emit_type_op(IrTypeOp::ImplicitCoercion, l, op_ir);
        }
        if rrep != op_ty {
            r = self.emit_type_op(IrTypeOp::ImplicitCoercion, r, op_ir);
        }
        let raw = self.emit_primitive_bin_op(irop, l, r);
        Some(match self.scalar_value_repr(result_ty) {
            Some(rep) if rep != op_ty => {
                self.emit_type_op(IrTypeOp::ImplicitCoercion, raw, ty_to_ir(result_ty))
            }
            _ => raw,
        })
    }

    /// Resolve a field by name, walking the superclass chain. Returns the *owning* class id, the
    /// field index within that class, and its type.
    fn resolve_field(&self, internal: &str, name: &str) -> Option<(ClassId, u32, Ty)> {
        self.resolve_field_name(existing_type_name(internal)?, name)
    }

    fn resolve_field_name(&self, internal: TypeName, name: &str) -> Option<(ClassId, u32, Ty)> {
        let mut cur = Some(internal);
        while let Some(ci_name) = cur {
            let ci = self.class_info_name(ci_name)?;
            if let Some(idx) = ci.fields.iter().position(|(fn_, _)| fn_ == name) {
                // A custom-accessor property is never a direct field read: decline it so the caller
                // routes the access through `getX`/`setX` (the accessor's own `field` reaches the
                // field via `cur_field`, not this resolver).
                if self
                    .field_accessor_props
                    .contains(&(ci_name, name.to_string()))
                {
                    return None;
                }
                return Some((ci.id, idx as u32, ci.fields[idx].1));
            }
            cur = ci.super_internal;
        }
        None
    }

    /// All `(method_name, FunId)` declared by an interface and its super-interfaces (transitively).
    fn collect_iface_methods(&self, itf: TypeName) -> Vec<(String, u32)> {
        let mut out = Vec::new();
        let mut stack = vec![itf];
        let mut seen = std::collections::HashSet::new();
        while let Some(i) = stack.pop() {
            if !seen.insert(i) {
                continue;
            }
            if let Some(ci) = self.class_info_name(i) {
                for (name, overloads) in &ci.methods {
                    for &(_, fid, _) in overloads {
                        out.push((name.clone(), fid));
                    }
                }
                stack.extend(self.ir.classes[ci.id as usize].interfaces.iter_ids());
            }
        }
        out
    }

    /// Lower a property reference to a synthesized `PropertyReference*Impl`. The checker types the
    /// expression as its callable shape; this JVM lowering pass chooses the reflection runtime class.
    fn lower_prop_ref(&mut self, _e: AstExprId, recv: AstExprId, name: &str) -> Option<u32> {
        // BOUND: the receiver is a value evaluated once and captured — an in-scope `Name`
        // (`obj::p`) or an arbitrary expression (`A(..)::p`, receiver evaluated exactly once).
        // UNBOUND: `Type::p` — the `Name` is a class, and the reference takes the receiver as its
        // `get` argument. `capture` holds the captured-receiver expression for the bound forms.
        let (owner, capture): (TypeName, Option<u32>) = match self.afile.expr(recv).clone() {
            Expr::Name(rn) => match self.lookup(&rn) {
                Some((v, ty)) => (ty.obj_internal()?, Some(self.emit_get_value(v))),
                None => {
                    let owner = class_internal(self.afile, &rn);
                    let owner_name = type_name(&owner);
                    // An OBJECT singleton receiver (`O::p`) is BOUND to `O.INSTANCE`; a plain class name
                    // (`Type::p`) stays an UNBOUND reference (`get(receiver)`).
                    match self
                        .class_info_name(owner_name)
                        .map(|ci| ci.id)
                        .filter(|&cid| self.ir.classes[cid as usize].is_object)
                    {
                        Some(cid) => {
                            let inst = self.emit_static_instance(cid, cid, "INSTANCE");
                            (owner_name, Some(inst))
                        }
                        None => (owner_name, None),
                    }
                }
            },
            _ => {
                // Only a USER-class receiver is handled here; a library receiver is left to
                // `lower_bound_library_prop_ref` (checked BEFORE capturing, so the receiver expression
                // isn't evaluated twice).
                let owner = self.info.ty(recv).obj_internal()?;
                if !self.contains_class_name(owner) {
                    return None;
                }
                (owner, Some(self.expr(recv)?))
            }
        };
        let owner_id = self.class_info_name(owner)?.id;
        // A member field property dispatches through the instance `getName()`/`setName()`; an EXTENSION
        // property (`val A.ext`, not a field) dispatches through the static `getName(A)`/`setName(A, v)`
        // on the facade — `ext_facade = Some(())` selects that emit shape.
        let (prop_ty, is_var, ext_facade): (Ty, bool, Option<Option<TypeName>>) = {
            // Search the receiver class and its superclasses for a backing field — an inherited member
            // property's getter/setter are inherited too, so the reference dispatches them on the
            // receiver just like an own property.
            let mut field = None;
            let mut cur = Some(owner_id);
            while let Some(cid) = cur {
                let cls = &self.ir.classes[cid as usize];
                if let Some(idx) = cls.fields.iter().position(|f| f.name == *name) {
                    field = Some((cls.fields[idx].ty, !cls.fields[idx].is_final));
                    break;
                }
                cur = cls
                    .has_non_top_superclass()
                    .then(|| self.class_info_name(cls.superclass).map(|c| c.id))
                    .flatten();
            }
            if let Some((pty, is_var)) = field {
                (pty, is_var, None)
            } else {
                let gfid = self.ext_prop_get_id(Ty::obj_name(owner), name)?;
                let is_var = self.ext_prop_set_id(Ty::obj_name(owner), name).is_some();
                (self.ir.functions[gfid as usize].ret, is_var, Some(None))
            }
        };
        // A user function whose name collides with a MEMBER property's accessor (`var x` alongside a
        // `fun getX()`/`fun setX()`) means the `getX()`/`setX()` the reference dispatches to isn't
        // reliably emitted — the two share a JVM name and krusty doesn't split them by descriptor, so
        // the accessor the ref calls can be missing. Decline (skip) rather than miscompile into a
        // NoSuchMethodError. (An extension property's accessor lives on the facade, so no clash.)
        if ext_facade.is_none() {
            if let Some(sig) = self.syms.class_by_type_name(owner) {
                if sig.methods.contains_key(&property_getter_name(name))
                    || (is_var && sig.methods.contains_key(&property_setter_name(name)))
                {
                    return None;
                }
            }
        }
        // A mutable (`var`) reference uses the `KMutableProperty*` runtime class and gets a `set`
        // method (emitted alongside `get`); an immutable one stays `KProperty*`.
        let bound = capture.is_some();
        let synth_fq = class_internal(
            self.afile,
            &format!("{}$propref${}${}", self.cur_fn_name, name, self.lambda_seq),
        );
        self.lambda_seq += 1;
        let superclass = self
            .property_reference_impl(if bound { 0 } else { 1 }, is_var)?
            .internal;
        let synth_id = self.ir.add_class(IrClass {
            fq_name: type_name(&synth_fq),
            is_value: false,
            is_data: false,
            decl_line: 0,
            type_param_bounds: vec![],
            type_params: Vec::new(),
            supertypes: vec![],
            fields: vec![],
            ctor_param_count: 0,
            ctor_args: vec![],
            init_body: None,
            explicit_param_stores: false,
            methods: vec![],
            is_interface: false,
            is_annotation: false,
            annotation_impl_of: None,

            is_sealed: false,
            is_abstract: false,
            is_open: false,
            superclass: type_name(&superclass),
            super_args: vec![],
            enum_entries: vec![],
            enum_entry_of: None,
            prop_ref: Some(crate::ir::PropRef {
                owner_internal: Some(owner),
                prop_name: name.to_string(),
                getter_name: property_getter_name(name),
                prop_ty,
                bound,
                static_dispatch: false,
                mutable: is_var,
                ext_facade,
            }),
            func_ref: None,
            bridges: vec![],
            interfaces: Default::default(),
            is_object: false,
            is_companion: false,
            companion_class: None,
            secondary_ctors: vec![],
            has_primary_ctor: true,
            applied_annotations: Vec::new(),
            field_annotations: Vec::new(),
            runtime_retained: false,
        });
        if let Some(recv_e) = capture {
            // `new <Synth>(receiver)` — the captured receiver is the constructor's `Object` argument.
            Some(self.emit_new(
                synth_id,
                vec![recv_e],
                Some(vec![ty_to_ir(Ty::obj("kotlin/Any"))]),
            ))
        } else {
            Some(self.emit_static_instance(synth_id, synth_id, "INSTANCE"))
        }
    }

    /// Lower a BOUND property reference on a LIBRARY-type receiver (`"kotlin"::length`) to a bound
    /// `PropertyReference0Impl` subclass whose `get()` dispatches the resolved classpath getter
    /// (`String.length()I`) on the captured receiver. The user-property `lower_prop_ref` needs an IR
    /// class + a `Name` receiver, so a library owner / arbitrary-expression receiver lands here.
    /// The checker makes every property-vs-method / null-safety / emittability decision and records the
    /// getter target; the lowerer just emits its descriptor.
    fn lower_bound_library_prop_ref(
        &mut self,
        e: AstExprId,
        recv: AstExprId,
        name: &str,
    ) -> Option<u32> {
        let rty = self.info.ty(recv);
        // A user-class receiver is handled by `lower_prop_ref`; only a library receiver falls here.
        if rty
            .obj_internal()
            .is_some_and(|i| self.contains_class_name(i))
        {
            return None;
        }
        let p = self.info.bound_property_ref(e)?.clone();
        let prop_ty = ty_to_ir(p.prop_ty);
        let cap = self.expr(recv)?;
        let synth_fq = class_internal(
            self.afile,
            &format!("{}$propref${}${}", self.cur_fn_name, name, self.lambda_seq),
        );
        self.lambda_seq += 1;
        let superclass = self.property_reference_impl(0, false)?.internal;
        let synth_id = self.ir.add_class(IrClass {
            fq_name: type_name(&synth_fq),
            is_value: false,
            is_data: false,
            decl_line: 0,
            type_param_bounds: vec![],
            type_params: Vec::new(),
            supertypes: vec![],
            fields: vec![],
            ctor_param_count: 0,
            ctor_args: vec![],
            init_body: None,
            explicit_param_stores: false,
            methods: vec![],
            is_interface: false,
            is_annotation: false,
            annotation_impl_of: None,
            is_sealed: false,
            is_abstract: false,
            is_open: false,
            superclass: type_name(&superclass),
            super_args: vec![],
            enum_entries: vec![],
            enum_entry_of: None,
            prop_ref: Some(crate::ir::PropRef {
                owner_internal: Some(p.owner),
                prop_name: name.to_string(),
                getter_name: p.getter_name,
                prop_ty,
                bound: true,
                static_dispatch: false,
                mutable: false,
                ext_facade: None,
            }),
            func_ref: None,
            bridges: vec![],
            interfaces: Default::default(),
            is_object: false,
            is_companion: false,
            companion_class: None,
            secondary_ctors: vec![],
            has_primary_ctor: true,
            applied_annotations: Vec::new(),
            field_annotations: Vec::new(),
            runtime_retained: false,
        });
        Some(self.emit_new(
            synth_id,
            vec![cap],
            Some(vec![ty_to_ir(Ty::obj("kotlin/Any"))]),
        ))
    }

    /// Lower an ADAPTED top-level function reference (`::foo` where `foo` has trailing default parameters,
    /// passed where a shorter function type is expected). Synthesize a static adapter of the expected
    /// arity whose body calls `foo`'s `$default` stub — filling the retained parameters, a zero
    /// placeholder + mask bit per dropped default, and the `null` marker — then wrap it in the same
    /// `Lambda`/metafactory closure a plain `::foo` produces. `None` (skip) if the `$default` stub isn't
    /// available for `foo`.
    /// Lower a VARARG-COLLECTION adapted reference (`::of` where `of(fixed…, vararg x)` is passed where a
    /// larger-arity function type is expected): a static adapter whose extra parameters (beyond `fixed`)
    /// are packed into the vararg array and passed to a plain call of the target.
    #[allow(clippy::too_many_arguments)]
    fn lower_adapted_vararg_collect(
        &mut self,
        e: AstExprId,
        name: &str,
        target_params: &[Ty],
        adapted_params: &[Ty],
        ret: Ty,
        fixed: usize,
        object_internal: Option<TypeName>,
    ) -> Option<u32> {
        let n = adapted_params.len();
        // The vararg's ARRAY type is the target's last parameter; each collected argument is coerced to
        // its element type (boxing a primitive into an `Object[]`).
        let arr_ty = target_params[target_params.len() - 1];
        let elem_ir = ty_to_ir(arr_ty.array_elem().unwrap_or(Ty::obj("kotlin/Any")));
        let mut collected = Vec::with_capacity(n - fixed);
        for k in fixed..n {
            let v = self.emit_get_value(k as u32);
            collected.push(self.emit_type_op(IrTypeOp::ImplicitCoercion, v, elem_ir));
        }
        let arr = self.emit_vararg(ty_to_ir(arr_ty), collected);
        let call = if let Some(internal) = object_internal {
            // A member of a same-file `object`: dispatch on its `INSTANCE` singleton.
            let cid = self.class_info_name(internal)?.id;
            let (class_id, index, _fid, _) = self.resolve_method_name(internal, name)?;
            let recv = self.emit_static_instance(cid, cid, "INSTANCE");
            let mut a: Vec<Option<u32>> = (0..fixed as u32)
                .map(|k| Some(self.emit_get_value(k)))
                .collect();
            a.push(Some(arr));
            self.emit_method_call(class_id, index, recv, a)
        } else {
            let fid = *self
                .fun_ids
                .get(&(name.to_string(), target_params.to_vec()))?;
            let mut a: Vec<u32> = (0..fixed as u32).map(|k| self.emit_get_value(k)).collect();
            a.push(arr);
            self.emit_local_call(fid, a)
        };
        let unit_return = ret == Ty::Unit;
        let body = if unit_return {
            let unit = self.emit_unit();
            let ret_e = self.emit_return(Some(unit));
            self.emit_block(vec![call, ret_e], None)
        } else {
            let ret_e = self.emit_return(Some(call));
            self.emit_block(vec![ret_e], None)
        };
        let adapter_ret = ty_to_ir(stored_value_ty(ret));
        let adapter_fid = self.ir.add_fun(IrFunction {
            name: format!("{}$adaptvc${}", self.cur_fn_name, e.0),
            params: adapted_params.iter().map(|t| ty_to_ir(*t)).collect(),
            ret: adapter_ret,
            body: Some(body),
            is_static: true,
            dispatch_receiver: None,
            param_checks: Vec::new(),
        });
        Some(self.ir.add_expr(IrExpr::Lambda {
            impl_fn: adapter_fid,
            arity: n as u8,
            captures: vec![],
            sam: None,
            inline_body: None,
        }))
    }

    #[allow(clippy::too_many_arguments)]
    fn lower_adapted_ref(
        &mut self,
        e: AstExprId,
        name: &str,
        target_params: &[Ty],
        adapted_params: &[Ty],
        ret: Ty,
        vararg_tail: bool,
        target_vararg: bool,
    ) -> Option<u32> {
        let (n, m) = (adapted_params.len(), target_params.len());
        let fid = *self
            .fun_ids
            .get(&(name.to_string(), target_params.to_vec()))?;
        // The adapter's own N params fill the retained slots (`GetValue(0..N-1)`).
        let mut a: Vec<u32> = Vec::with_capacity(m + 2);
        for k in 0..n {
            a.push(self.emit_get_value(k as u32));
        }
        let dcall = if n == m {
            // No dropped parameters (a pure return coercion): a plain full-arity call.
            self.emit_local_call(fid, a)
        } else if vararg_tail {
            // A single dropped trailing `vararg`: pass an EMPTY array of its element type and call the
            // target directly (no `$default`). `target_params[m-1]` is the vararg's ARRAY type.
            a.push(self.empty_array(ty_to_ir(target_params[m - 1])));
            self.emit_local_call(fid, a)
        } else {
            // Trailing DEFAULTS: `foo$default(retained…, <placeholder>…, mask, null)` — each dropped slot
            // gets a zero placeholder and its mask bit; the marker is null.
            if !crate::ir::toplevel_default_stub_safe(&self.ir, fid) {
                return None;
            }
            let mut omitted = Vec::new();
            for (k, &pt) in target_params.iter().enumerate().skip(n) {
                if k == m - 1 && target_vararg {
                    // The dropped trailing vararg gets an EMPTY array and NO mask bit (passed through by
                    // `$default`, not filled from the mask).
                    a.push(self.empty_array(ty_to_ir(pt)));
                } else {
                    omitted.push(k);
                    a.push(self.zero_placeholder(pt));
                }
            }
            self.append_default_masks_marker(&mut a, m, omitted);
            self.emit_local_default_call(fid, a)
        };
        // A `Unit`-returning invoke (a coercion, or the target itself returns `Unit`) yields the `Unit`
        // SINGLETON — a `kotlin/Unit` object, not `void` — to match the `FunctionN.invoke` SAM: run the
        // call as a statement (its value, if any, discarded) and return `Unit.INSTANCE`. Otherwise return
        // the call's result directly. `coerce_unit` ⇒ `ret == Unit`; a target that already returns `Unit`
        // takes the same singleton path.
        let unit_return = ret == Ty::Unit;
        let body = if unit_return {
            let unit = self.emit_unit();
            let ret_e = self.emit_return(Some(unit));
            self.emit_block(vec![dcall, ret_e], None)
        } else {
            let ret_e = self.emit_return(Some(dcall));
            self.emit_block(vec![ret_e], None)
        };
        let adapter_ret = ty_to_ir(stored_value_ty(ret));
        let adapter_fid = self.ir.add_fun(IrFunction {
            name: format!("{}$adapt${}", self.cur_fn_name, e.0),
            params: adapted_params.iter().map(|t| ty_to_ir(*t)).collect(),
            ret: adapter_ret,
            body: Some(body),
            is_static: true,
            dispatch_receiver: None,
            param_checks: Vec::new(),
        });
        Some(self.ir.add_expr(IrExpr::Lambda {
            impl_fn: adapter_fid,
            arity: n as u8,
            captures: vec![],
            sam: None,
            inline_body: None,
        }))
    }

    /// Lower a top-level property reference `::foo` to a `(Mutable)PropertyReference0Impl` singleton.
    /// The property is backed by a static getter (`getFoo`) — and a setter (`setFoo`) for a `var` — on
    /// the file facade, so the synthesized `get`/`set` dispatch via `invokestatic`. `owner_internal` is
    /// the declaring facade (empty = this file's facade, resolved at emit); a cross-file property names
    /// its facade explicitly. The expression evaluates to the singleton's `INSTANCE`.
    fn lower_toplevel_prop_ref(&mut self, e: AstExprId, name: &str) -> Option<u32> {
        // A DELEGATED top-level property (`val x by Delegate`) reserves a `x$delegate` static and has no
        // plain `setX`; its reference needs reflection metadata (`getDelegate()`) krusty doesn't emit.
        // Skip (the whole `::x` expression then fails to lower and the case is dropped, not miscompiled).
        if self.statics.contains_key(&format!("{name}$delegate")) {
            return None;
        }
        // Resolve the property's type, mutability, and declaring facade. A same-file property leaves the
        // facade implicit; a cross-file one carries its facade id. `const val`s have no accessor, so they
        // can't be referenced — skip.
        let (owner, prop_ty, is_var): (Option<TypeName>, Ty, bool) =
            if let Some((ty, is_var, is_const)) = self.syms.props.get(name).cloned() {
                if is_const {
                    return None;
                }
                (None, ty, is_var)
            } else if let Some((facade, ty, is_var, is_const)) =
                self.syms.prop_facades.get(name).cloned()
            {
                if is_const {
                    return None;
                }
                (Some(facade), ty, is_var)
            } else {
                return None;
            };
        let prop_ty = ty_to_ir(prop_ty);
        let superclass = self.property_reference_impl(0, is_var)?.internal;
        let synth_fq = class_internal(
            self.afile,
            &format!("{}$propref${}${}", self.cur_fn_name, name, self.lambda_seq),
        );
        self.lambda_seq += 1;
        let synth_id = self.ir.add_class(IrClass {
            fq_name: type_name(&synth_fq),
            is_value: false,
            is_data: false,
            decl_line: 0,
            type_param_bounds: vec![],
            type_params: Vec::new(),
            supertypes: vec![],
            fields: vec![],
            ctor_param_count: 0,
            ctor_args: vec![],
            init_body: None,
            explicit_param_stores: false,
            methods: vec![],
            is_interface: false,
            is_annotation: false,
            annotation_impl_of: None,
            is_sealed: false,
            is_abstract: false,
            is_open: false,
            superclass: type_name(&superclass),
            super_args: vec![],
            enum_entries: vec![],
            enum_entry_of: None,
            prop_ref: Some(crate::ir::PropRef {
                owner_internal: owner,
                prop_name: name.to_string(),
                getter_name: property_getter_name(name),
                prop_ty,
                bound: false,
                static_dispatch: true,
                mutable: is_var,
                ext_facade: None,
            }),
            func_ref: None,
            bridges: vec![],
            interfaces: Default::default(),
            is_object: false,
            is_companion: false,
            companion_class: None,
            secondary_ctors: vec![],
            has_primary_ctor: true,
            applied_annotations: Vec::new(),
            field_annotations: Vec::new(),
            runtime_retained: false,
        });
        let _ = e;
        Some(self.emit_static_instance(synth_id, synth_id, "INSTANCE"))
    }

    /// Lower a method reference `obj::m` (bound — the receiver is an in-scope value, captured) or
    /// `Type::m` (unbound — the receiver is a user class, supplied as the first argument) to a
    /// synthesized static impl `(receiver, args…) -> receiver.m(args)` wrapped in a closure, exactly
    /// as a lambda `{ a -> obj.m(a) }` / `{ r, a -> r.m(a) }` would lower. `params`/`ret` are the
    /// reference's function type. Only user-class methods are modeled (the receiver/method must
    /// resolve in the IR class table); a `Unit`/`Nothing` return is skipped.
    /// Wrap a `Unit`-returning target function in a SAM impl `(target params) -> { target(params);
    /// return Unit.INSTANCE }`. A `Unit` method handle returns `void`, but a functional interface's
    /// `invoke` must yield the `kotlin/Unit` singleton — `LambdaMetafactory` won't adapt `void`. `uniq`
    /// (the ref's AST id) keeps the synthesized name distinct across overloaded enclosing functions.
    fn unit_ref_wrapper(&mut self, target_fid: u32, uniq: u32) -> u32 {
        let params = self.ir.functions[target_fid as usize].params.clone();
        let argvals: Vec<u32> = (0..params.len() as u32)
            .map(|i| self.emit_get_value(i))
            .collect();
        let call = self.emit_local_call(target_fid, argvals);
        let unit = self.emit_unit();
        let ret_e = self.emit_return(Some(unit));
        let block = self.emit_block(vec![call, ret_e], None);
        let impl_name = format!("{}$unitref${}", self.cur_fn_name, uniq);
        self.ir.add_fun(IrFunction {
            name: impl_name,
            params,
            ret: ty_to_ir(stored_value_ty(Ty::Unit)),
            body: Some(block),
            is_static: true,
            dispatch_receiver: None,
            param_checks: Vec::new(),
        })
    }

    fn lower_method_ref(
        &mut self,
        e: AstExprId,
        recv: AstExprId,
        name: &str,
        params: &[Ty],
        ret: Ty,
    ) -> Option<u32> {
        if ret == Ty::Nothing {
            return None;
        }
        let Expr::Name(rn) = self.afile.expr(recv).clone() else {
            return None;
        };
        // Bound `obj::m` (`rn` an in-scope value) / `O::m` (`rn` an object → its `INSTANCE`): the
        // receiver is CAPTURED. Unbound `Type::m` (`rn` a class): the receiver is the reference's first
        // parameter (`param_tys[0]`). `capture` holds the bound receiver expression.
        let (capture, recv_ty): (Option<u32>, Ty) = match self.lookup(&rn) {
            Some((v, ty)) => (Some(self.emit_get_value(v)), ty),
            None => {
                let internal = class_internal(self.afile, &rn);
                let internal_name = type_name(&internal);
                let cid = self.class_info_name(internal_name)?.id;
                if self.ir.classes[cid as usize].is_object {
                    let inst = self.emit_static_instance(cid, cid, "INSTANCE");
                    (Some(inst), Ty::obj_name(internal_name))
                } else {
                    (None, *params.first()?)
                }
            }
        };
        let internal = recv_ty.obj_internal()?;
        // An UNBOUND reference to a same-module extension function (`A::foo`): the lifted static
        // `foo(recv, args…)` is the impl — emit a `FunctionReferenceImpl` calling `invokestatic
        // <facade>.foo(recv, args)` (equatable, same shape as a top-level `::foo` ref). The receiver is
        // the first parameter, not captured. (A member of the same name, resolved below, wins; a BOUND
        // `obj::ext` is handled by `lower_bound_expr_ref`. A value-class receiver is skipped.)
        if capture.is_none()
            && self.resolve_method_name(internal, name).is_none()
            && self
                .ext_fun_ids
                .contains_key(&(recv_ty.erased_recv(), name.to_string()))
        {
            let param_tys = tys_to_ir(params);
            return self.make_func_ref(
                e.0,
                false,
                params.len() as u8,
                None,
                name.to_string(),
                1,
                crate::ir::FrDispatch::Static,
                None,
                name.to_string(),
                false,
                param_tys,
                ty_to_ir(ret),
                None,
                None,
            );
        }
        // The universal Object methods (`A::equals`, `obj::hashCode`, `x::toString`) are not user
        // methods, so `resolve_method` finds nothing — reference them against `java/lang/Object`. The
        // checker already types these with `Any` parameters and a `Boolean`/`Int`/`String` return, so
        // the invoke's derived descriptor matches `equals(Object)Z` / `hashCode()I` / `toString()String`;
        // `invokevirtual` on the (captured bound / first-parameter unbound) receiver dispatches any real
        // override at runtime.
        if matches!(name, "equals" | "hashCode" | "toString")
            && self.resolve_method_name(internal, name).is_none()
            // A BOUND receiver that may be null (nullable, or an erased type-parameter/`Any`/`Object`)
            // needs the null-safe intrinsic kotlinc uses (`x::toString` on `null` yields "null"); a
            // plain `invokevirtual` on the captured null NPEs. Only handle a bound ref on a concrete
            // non-null receiver; decline (skip) otherwise. Unbound refs take the receiver as a call arg.
            && (capture.is_none()
                || (!matches!(recv_ty, Ty::TyParam(..) | Ty::Nullable(..))
                    && recv_ty.kotlin_class_internal().is_some_and(|i| {
                        i != crate::types::wk::any() && i != crate::types::wk::java_object()
                    })))
        {
            let bound = capture.is_some();
            let dispatch = if bound {
                crate::ir::FrDispatch::VirtualBound
            } else {
                crate::ir::FrDispatch::VirtualUnbound
            };
            let param_tys = tys_to_ir(params);
            return self.make_func_ref(
                e.0,
                bound,
                params.len() as u8,
                Some(crate::types::wk::java_object()),
                name.to_string(),
                0,
                dispatch,
                Some(crate::types::wk::java_object()),
                name.to_string(),
                false,
                param_tys,
                ty_to_ir(ret),
                capture,
                None,
            );
        }
        // Only a user-class method is modeled (the invoke does `invokevirtual`/`invokeinterface
        // internal.name`); a classpath/library receiver fails here → bail (skip), never miscompile.
        let (_, _, target_fid, _) = self.resolve_method_name(internal, name)?;
        // A PRIVATE target can't be invoked from the separate reference class (`IllegalAccessError`);
        // retarget the reference's invoke at a synthetic `access$<name>` accessor on the owner (a public
        // instance method that forwards to the private one). The reflection NAME (`fn_name`) stays the
        // real method; only the physical `call_name` changes. Bail (skip) if the accessor can't be made,
        // rather than emit an illegal private access.
        let call_name = if self.ir.private_methods.contains(&target_fid) {
            self.ensure_private_accessor_name(internal, name)?
        } else {
            name.to_string()
        };
        // Dispatch on the receiver's STATIC type: an interface receiver needs `invokeinterface`.
        let call_interface = self
            .class_info_name(internal)
            .is_some_and(|ci| self.ir.classes[ci.id as usize].is_interface);
        let bound = capture.is_some();
        let dispatch = if bound {
            crate::ir::FrDispatch::VirtualBound
        } else {
            crate::ir::FrDispatch::VirtualUnbound
        };
        let param_tys = tys_to_ir(params);
        self.make_func_ref(
            e.0,
            bound,
            params.len() as u8,
            Some(internal),
            name.to_string(),
            0, // member
            dispatch,
            Some(internal),
            call_name,
            call_interface,
            param_tys,
            ty_to_ir(ret),
            capture,
            None,
        )
    }

    /// Lower `::foo` where `foo` is imported from a SAME-FILE `object` (`import Host.foo`) — a bound
    /// reference to the singleton member: capture `Host.INSTANCE` and emit a `VirtualBound`
    /// `FunctionReferenceImpl` invoking the member, exactly as `Host::foo` lowers.
    fn lower_imported_object_ref(
        &mut self,
        e: AstExprId,
        internal: TypeName,
        name: &str,
        params: &[Ty],
        ret: Ty,
    ) -> Option<u32> {
        if ret == Ty::Nothing {
            return None;
        }
        let cid = self.class_info_name(internal)?.id;
        let inst = self.emit_static_instance(cid, cid, "INSTANCE");
        let (_, _, target_fid, _) = self.resolve_method_name(internal, name)?;
        let call_name = if self.ir.private_methods.contains(&target_fid) {
            self.ensure_private_accessor_name(internal, name)?
        } else {
            name.to_string()
        };
        let param_tys = tys_to_ir(params);
        self.make_func_ref(
            e.0,
            true,
            params.len() as u8,
            Some(internal),
            name.to_string(),
            0,
            crate::ir::FrDispatch::VirtualBound,
            Some(internal),
            call_name,
            false,
            param_tys,
            ty_to_ir(ret),
            Some(inst),
            None,
        )
    }

    /// An unqualified member-function reference `::m` inside a class — a BOUND ref to the enclosing
    /// receiver (`this::m`): capture `this` (value 0) and emit the same `FunctionReferenceImpl` the
    /// `obj::m` form does. Member-property and extension implicit refs aren't modeled here (the type
    /// isn't `Ty::Fun` / there's no member method), so they fall through.
    fn lower_implicit_this_method_ref(&mut self, e: AstExprId, name: &str) -> Option<u32> {
        let internal = self.cur_class?;
        let (_, _, target_fid, _) = self.resolve_method_name(internal, name)?;
        let Ty::Fun(sig) = self.info.ty(e) else {
            return None;
        };
        if sig.ret == Ty::Nothing {
            return None;
        }
        // A private target is reached through a synthetic accessor (the reference is a separate class).
        // If the accessor can't be synthesized, BAIL (skip the file) rather than fall back to the private
        // method, which would emit an illegal access.
        let call_name = if self.ir.private_methods.contains(&target_fid) {
            self.ensure_private_accessor_name(internal, name)?
        } else {
            name.to_string()
        };
        let call_interface = self
            .class_info_name(internal)
            .is_some_and(|ci| self.ir.classes[ci.id as usize].is_interface);
        let this_e = self.emit_get_value(0);
        let param_tys = tys_to_ir(&sig.params);
        self.make_func_ref(
            e.0,
            true,
            sig.params.len() as u8,
            Some(internal),
            name.to_string(),
            0,
            crate::ir::FrDispatch::VirtualBound,
            Some(internal),
            call_name,
            call_interface,
            param_tys,
            ty_to_ir(sig.ret),
            Some(this_e),
            None,
        )
    }

    /// Bound callable reference on an arbitrary EXPRESSION receiver (`"abc"::get`, `1::foo`, `mk()::m`):
    /// the receiver is evaluated once and captured into the closure. Handles a bound extension function
    /// (`expr::extFun` → the lifted static `extFun(recv, args…)`, captured receiver) and a bound member
    /// on a user-class receiver (a synthesized impl invoking the member). Returns None for unmodeled
    /// shapes (library-type members, `Unit`/`Nothing` SAM-return).
    fn lower_bound_expr_ref(
        &mut self,
        e: AstExprId,
        recv: AstExprId,
        name: &str,
        params: &[Ty],
        ret: Ty,
    ) -> Option<u32> {
        if ret == Ty::Nothing {
            return None;
        }
        let rty = self.info.ty(recv);
        // Bound extension reference: the extension is a lifted static `name(recv, args…)`. Capture the
        // receiver; the metafactory binds it and `invoke(args)` supplies the rest (same as a local-fun
        // ref). `arity` = the extension's declared params (the receiver is bound, not a parameter). A
        // `Unit` return is wrapped so `invoke` yields the `Unit` singleton.
        if let Some(&fid) = self.ext_fun_ids.get(&(rty.erased_recv(), name.to_string())) {
            // An ADAPTED extension reference (the target has trailing default/vararg params the reference
            // omits) can't use the direct metafactory bind — that would call a non-existent lower-arity
            // static. Decline (skip) until the synthesized-adapter path lands. `params` is the exposed
            // prefix; the static leads with the receiver, so the non-adapted arity is `params.len() + 1`.
            if params.len() + 1 < self.ir.functions[fid as usize].params.len() {
                return None;
            }
            // A BOUND extension reference on a REFERENCE receiver (`obj::ext`) → a `FunctionReferenceImpl`
            // whose captured receiver is passed as the first `invokestatic <facade>.ext(recv, args)`
            // argument (`StaticBound`) — real reference equality (two `obj::ext` on the same receiver are
            // equal), unlike an `invokedynamic` lambda. The target signature leads with the receiver type.
            if rty.obj_internal().is_some() {
                let cap = self.expr(recv)?;
                let param_tys = tys_to_ir(params);
                let mut target = vec![ty_to_ir(rty)];
                target.extend(param_tys.iter().copied());
                return self.make_func_ref(
                    e.0,
                    true,
                    params.len() as u8,
                    None,
                    name.to_string(),
                    1,
                    crate::ir::FrDispatch::StaticBound,
                    None,
                    name.to_string(),
                    false,
                    param_tys,
                    ty_to_ir(ret),
                    Some(cap),
                    Some(target),
                );
            }
            // A PRIMITIVE-receiver bound extension (`1::plusFour`): the captured receiver boxes into the
            // `FunctionN` and unboxes at the call — the `invokedynamic` lambda form models that (and its
            // reference equality isn't exercised, unlike the reference-receiver case above).
            let cap = self.expr(recv)?;
            let impl_fn = if ret == Ty::Unit {
                self.unit_ref_wrapper(fid, e.0)
            } else {
                fid
            };
            return Some(self.ir.add_expr(IrExpr::Lambda {
                impl_fn,
                arity: params.len() as u8,
                captures: vec![cap],
                sam: None,
                inline_body: None,
            }));
        }
        // Bound member reference on a LIBRARY-type receiver (`"KOTLIN"::get`): the invoke dispatches the
        // resolved classpath instance method (`java/lang/String.charAt(I)C`) on the captured receiver — a
        // `VirtualBound` `FunctionReferenceImpl` (real reference equality). No IR impl is synthesized; the
        // physical target's owner/name/interface come straight from the resolved member. Applies when the
        // receiver is NOT a user IR class (a builtin/primitive/library type, or an `Obj` with no user
        // method of this name) — those go through the synthesized-impl path below.
        let user_method = rty
            .obj_internal()
            .filter(|internal| self.resolve_method_name(*internal, name).is_some());
        if user_method.is_none() {
            // A null-risky receiver (type parameter / nullable / bare erased `Any`) may be `null`;
            // kotlinc null-guards `toString`/`equals`/`hashCode` on those (`null::toString` → "null"),
            // so a direct `invokevirtual` on the captured null would NPE. Skip → clean file skip. This is
            // the SAME predicate the checker applies (kept in lock-step); enforced here too because a
            // `t::toString` (Name receiver) reaches this path only after `lower_method_ref` bails on the
            // erased `kotlin/Any` receiver, and `resolve_instance_ref`'s Object-owner reject is a further
            // backstop for members inherited from `Any`.
            if matches!(rty, Ty::TyParam(..) | Ty::Nullable(..))
                || rty.kotlin_class_internal() == Some(crate::types::wk::any())
            {
                return None;
            }
            let m = self.info.bound_member_ref(e)?.clone();
            if m.name != name {
                return None;
            }
            if m.suspend {
                return None;
            }
            let owner = m.owner?;
            let call_interface = self.library_type_is_interface(owner);
            let cap = self.expr(recv)?;
            let param_tys = tys_to_ir(params);
            return self.make_func_ref(
                e.0,
                true,
                params.len() as u8,
                Some(owner),
                m.name.clone(),
                0,
                crate::ir::FrDispatch::VirtualBound,
                Some(owner),
                m.physical_name.clone().unwrap_or(m.name),
                call_interface,
                param_tys,
                ty_to_ir(ret),
                Some(cap),
                None,
            );
        }
        // Bound member reference on a user-class receiver: synthesize `(recv, args…) -> recv.name(args…)`
        // and capture the receiver.
        let internal = user_method.expect("user method internal");
        let (class_id, index, target_fid, _ret) = self.resolve_method_name(internal, name)?;
        let is_adapted = params.len() < self.ir.functions[target_fid as usize].params.len();
        // The synthesized impl lives in a SEPARATE reference class; a private target would be an illegal
        // `invokespecial` from there. Target the public `access$name` accessor instead (an ordinary
        // `invokevirtual`), forwarding to the private member from inside the owner.
        let (class_id, index) = if self.ir.private_methods.contains(&target_fid) {
            // The forwarding accessor carries no `$default` stub, so an ADAPTED reference (which fills
            // omitted parameters through `$default`) can't dispatch it — decline (skip) rather than emit
            // a call to a non-existent `access$name$default`.
            if is_adapted {
                return None;
            }
            let acc = self.ensure_private_accessor_name(internal, name)?;
            let (cid, idx, _, _) = self.resolve_method_name(internal, &acc)?;
            (cid, idx)
        } else {
            (class_id, index)
        };
        let cap = self.expr(recv)?;
        let recv_v = self.emit_get_value(0);
        let mut arg_vs: Vec<Option<u32>> = (0..params.len() as u32)
            .map(|i| Some(self.emit_get_value(i + 1)))
            .collect();
        // ADAPTED reference: the target method has more parameters than the reference exposes (trailing
        // defaults / a vararg). Pad the omitted ones with `None`, which the `MethodCall` emitter fills
        // through the target's `$default` stub (an empty array for a vararg, the default for a default).
        let target_arity = self.ir.functions[target_fid as usize].params.len();
        while arg_vs.len() < target_arity {
            arg_vs.push(None);
        }
        let mc = self.emit_method_call(class_id, index, recv_v, arg_vs);
        let (stmts, impl_ret) = if ret == Ty::Unit {
            let unit = self.emit_unit();
            let ret_e = self.emit_return(Some(unit));
            (vec![mc, ret_e], ty_to_ir(stored_value_ty(Ty::Unit)))
        } else {
            let ret_e = self.emit_return(Some(mc));
            (vec![ret_e], ty_to_ir(ret))
        };
        let block = self.emit_block(stmts, None);
        // Name with the ref's globally-unique AST expr id (not the per-function `lambda_seq`): two
        // OVERLOADED enclosing functions share `cur_fn_name`, so a seq-based name would clash.
        let impl_name = format!("{}$boundref${}", self.cur_fn_name, e.0);
        let mut impl_params: Vec<Ty> = vec![ty_to_ir(rty)];
        impl_params.extend(params.iter().map(|t| stored_value_ty(*t)));
        let bfid = self.ir.add_fun(IrFunction {
            name: impl_name,
            params: impl_params,
            ret: impl_ret,
            body: Some(block),
            is_static: true,
            dispatch_receiver: None,
            param_checks: Vec::new(),
        });
        Some(self.ir.add_expr(IrExpr::Lambda {
            impl_fn: bfid,
            arity: params.len() as u8,
            captures: vec![cap],
            sam: None,
            inline_body: None,
        }))
    }

    /// Ensure a synthetic accessor for the PRIVATE member method `method_name` on `internal`, so a
    /// SEPARATE class (a callable-reference impl) can reach it without an illegal private access. kotlinc
    /// emits a `static synthetic access$m`; krusty emits an equivalent public INSTANCE method `access$<m>`
    /// whose body is `this.<m>(args)` — an in-class call, so its `invokespecial` on the private method is
    /// legal. Memoized by name. Returns the accessor's method name (to retarget the reference's invoke),
    /// or `None` if the target method can't be resolved.
    fn ensure_private_accessor(&mut self, internal: &str, method_name: &str) -> Option<String> {
        self.ensure_private_accessor_name(existing_type_name(internal)?, method_name)
    }

    fn ensure_private_accessor_name(
        &mut self,
        internal: TypeName,
        method_name: &str,
    ) -> Option<String> {
        let accessor = format!("access${method_name}");
        if self
            .class_info_name(internal)
            .is_some_and(|ci| ci.methods.contains_key(&accessor))
        {
            return Some(accessor);
        }
        let (class_id, index, fid, ret) = self.resolve_method_name(internal, method_name)?;
        let params = self.ir.functions[fid as usize].params.clone();
        let ret_ir = self.ir.functions[fid as usize].ret;
        let recv = self.emit_get_value(0);
        let args: Vec<Option<u32>> = (0..params.len())
            .map(|i| Some(self.emit_get_value((i + 1) as u32)))
            .collect();
        let call = self.emit_method_call(class_id, index, recv, args);
        // Wrap in an explicit return so the method's control flow terminates: `return this.<m>(args)`
        // for a value-returning target, or the call then a bare `return` for a `Unit`/void one.
        let stmts = if ret == Ty::Unit {
            let r = self.emit_return(None);
            vec![call, r]
        } else {
            vec![self.emit_return(Some(call))]
        };
        let body = self.emit_block(stmts, None);
        let acc_fid = self.ir.add_fun(IrFunction {
            name: accessor.clone(),
            params,
            ret: ret_ir,
            body: Some(body),
            is_static: false,
            dispatch_receiver: Some(internal),
            param_checks: Vec::new(),
        });
        let cid = self.class_info_name(internal)?.id;
        let idx = self.ir.classes[cid as usize].methods.len() as u32;
        self.ir.classes[cid as usize].methods.push(acc_fid);
        if let Some(ci) = self.class_info_name_mut(internal) {
            ci.methods
                .entry(accessor.clone())
                .or_default()
                .push((idx, acc_fid, ret));
        }
        Some(accessor)
    }

    /// Build a synthesized function-reference subclass of `FunctionReferenceImpl` (real Kotlin reference
    /// EQUALITY) and return the expression that produces an instance: `new <Synth>(receiver)` for a bound
    /// ref, or `<Synth>.INSTANCE` for an unbound one. See `crate::ir::FuncRef` / `emit_func_ref_class`.
    #[allow(clippy::too_many_arguments)]
    fn make_func_ref(
        &mut self,
        uniq: u32,
        bound: bool,
        arity: u8,
        owner_class: Option<TypeName>,
        fn_name: String,
        flags: i32,
        dispatch: crate::ir::FrDispatch,
        call_owner: Option<TypeName>,
        call_name: String,
        call_interface: bool,
        param_tys: Vec<Ty>,
        ret_ty: Ty,
        capture: Option<u32>,
        // For `StaticBound` the physical target call takes the captured receiver as a leading argument,
        // so its signature has one more entry than the (invoke) `param_tys`. `None` ⇒ same as `param_tys`.
        target_override: Option<Vec<Ty>>,
    ) -> Option<u32> {
        let synth_fq = class_internal(self.afile, &format!("{}$fnref${}", self.cur_fn_name, uniq));
        let superclass = self
            .runtime
            .function_reference_impl_type()?
            .obj_internal()?;
        let synth_id = self.ir.add_class(IrClass {
            fq_name: type_name(&synth_fq),
            is_value: false,
            is_data: false,
            decl_line: 0,
            type_param_bounds: vec![],
            type_params: Vec::new(),
            supertypes: vec![],
            fields: vec![],
            ctor_param_count: 0,
            ctor_args: vec![],
            init_body: None,
            explicit_param_stores: false,
            methods: vec![],
            is_interface: false,
            is_annotation: false,
            annotation_impl_of: None,

            is_sealed: false,
            is_abstract: false,
            is_open: false,
            superclass,
            super_args: vec![],
            enum_entries: vec![],
            enum_entry_of: None,
            prop_ref: None,
            func_ref: Some(crate::ir::FuncRef {
                bound,
                arity,
                owner_class,
                fn_name,
                flags,
                dispatch,
                call_owner,
                call_name,
                call_interface,
                target_param_tys: target_override.unwrap_or_else(|| param_tys.clone()),
                target_ret_ty: ret_ty,
                // Per-INVOKE-parameter (indexed by the invoke arg `k`), so always `param_tys.len()` —
                // independent of `target_param_tys` (which may lead with a `StaticBound` receiver).
                unbox_params: vec![None; param_tys.len()],
                unbox_param_nullable: vec![false; param_tys.len()],
                param_tys,
                ret_ty,
                box_ret: None,
                staticbound_recv_unbox: None,
            }),
            bridges: vec![],
            interfaces: Default::default(),
            is_object: false,
            is_companion: false,
            companion_class: None,
            secondary_ctors: vec![],
            has_primary_ctor: true,
            applied_annotations: Vec::new(),
            field_annotations: Vec::new(),
            runtime_retained: false,
        });
        match capture {
            Some(cap) => Some(self.emit_new(
                synth_id,
                vec![cap],
                Some(vec![ty_to_ir(Ty::obj("kotlin/Any"))]),
            )),
            None => Some(self.emit_static_instance(synth_id, synth_id, "INSTANCE")),
        }
    }

    /// For an unqualified call inside an inner class, resolve `name` as an ENCLOSING method (reached
    /// through `this$0`). Returns `(method_class, method_index, method_fid, inner_class_id)`.
    fn inner_outer_method(&self, name: &str) -> Option<(ClassId, u32, u32, ClassId)> {
        let cur = self.cur_class.as_ref()?;
        let cur_id = self.class_info_name(*cur)?.id;
        let outer = match self.ir.classes[cur_id as usize].fields.first() {
            Some(IrField { name: n0, ty, .. })
                if n0 == "this$0" && ty.non_null().obj_internal().is_some() =>
            {
                ty.non_null().obj_internal().unwrap().to_string()
            }
            _ => return None,
        };
        let (c, i, f, _) = self.resolve_method(&outer, name)?;
        Some((c, i, f, cur_id))
    }

    /// Emit `recv.name(args)` on an already-lowered receiver using the checker-recorded selected target.
    fn lower_op_call(
        &mut self,
        recv_v: u32,
        recv_ty: Ty,
        name: &str,
        args: &[AstExprId],
        source_expr: AstExprId,
    ) -> Option<(u32, Ty)> {
        let selected = self
            .info
            .resolved_calls
            .get(&source_expr)
            .or_else(|| self.info.resolved_operator_call(source_expr, name))
            .cloned()?;
        self.lower_selected_op_call(recv_v, recv_ty, name, args, selected)
    }

    fn lower_stmt_op_call(
        &mut self,
        stmt: ast::StmtId,
        recv_v: u32,
        recv_ty: Ty,
        name: &str,
        args: &[AstExprId],
    ) -> Option<(u32, Ty)> {
        let selected = self.info.resolved_stmt_operator_call(stmt, name).cloned()?;
        self.lower_selected_op_call(recv_v, recv_ty, name, args, selected)
    }

    fn lower_selected_op_call(
        &mut self,
        recv_v: u32,
        recv_ty: Ty,
        name: &str,
        args: &[AstExprId],
        selected: ResolvedCall,
    ) -> Option<(u32, Ty)> {
        let internal = recv_ty.kotlin_class_internal()?;
        match selected {
            ResolvedCall::Member(resolved) => {
                let member = resolved.member;
                if member.name != name || member.params.len() != args.len() {
                    return None;
                }
                let physical_ret = member.physical_ret;
                let mut a = Vec::new();
                for (k, &arg) in args.iter().enumerate() {
                    a.push(self.lower_arg(arg, &ty_to_ir(member.params[k]))?);
                }
                let ret = resolved.ret;
                let suspend = resolved.suspend;
                let call = self.emit_library_member_call(recv_v, internal, member, ret, suspend, a);
                Some((self.coerce_to_static(call, ret, physical_ret), ret))
            }
            ResolvedCall::ModuleMember {
                owner,
                name: target,
                params: selected_params,
                ret: selected_ret,
                interface,
            } => {
                if target != name || selected_params.len() != args.len() {
                    return None;
                }
                let mut a = Vec::new();
                for (k, &arg) in args.iter().enumerate() {
                    a.push(self.lower_arg(arg, &ty_to_ir(selected_params[k]))?);
                }
                let owner = owner.render();
                if let Some((class, midx, _fid, _ret)) =
                    self.link_local_method(&owner, name, &selected_params)
                {
                    let call = self.emit_method_call(
                        class,
                        midx,
                        recv_v,
                        a.into_iter().map(Some).collect(),
                    );
                    Some((call, selected_ret))
                } else {
                    let call = self.emit_call(
                        Callee::CrossFileVirtual {
                            owner: type_name(&owner),
                            name: target,
                            params: tys_to_ir(&selected_params),
                            ret: ty_to_ir(selected_ret),
                            interface,
                        },
                        Some(recv_v),
                        a,
                    );
                    Some((call, selected_ret))
                }
            }
            ResolvedCall::ModuleExtension {
                receiver,
                name: target,
                params: selected_params,
                ret: selected_ret,
            } => {
                if target != name || receiver.erased_recv() != recv_ty.erased_recv() {
                    return None;
                }
                let fid = *self.ext_fun_id_by_sig.get(&(
                    receiver.erased_recv(),
                    target.to_string(),
                    selected_params.clone(),
                ))?;
                let params = self.ir.functions[fid as usize].params.clone();
                let ret = self.ir.functions[fid as usize].ret;
                if ret != selected_ret
                    || params.len() != args.len() + 1
                    || params.get(1..) != Some(selected_params.as_slice())
                {
                    return None;
                }
                let mut a = vec![recv_v];
                for (k, &arg) in args.iter().enumerate() {
                    a.push(self.lower_arg(arg, &params[k + 1])?);
                }
                let call = self.emit_local_call(fid, a);
                Some((call, ret))
            }
            _ => None,
        }
    }
    fn resolve_method(&self, internal: &str, name: &str) -> Option<(ClassId, u32, u32, Ty)> {
        self.resolve_method_name(existing_type_name(internal)?, name)
    }

    /// Overload-aware companion to [`Self::resolve_method_name`]: walk the base chain and select
    /// the overload of `name` whose parameter COUNT matches `nargs`. Exactly one fit resolves;
    /// zero or several (same-arity overloads — those need parameter types) return `None` so the
    /// caller bails (skip, never misdispatch).
    fn resolve_method_by_arity(
        &self,
        internal: TypeName,
        name: &str,
        nargs: usize,
    ) -> Option<(ClassId, u32, u32, Ty)> {
        let mut seen = std::collections::HashSet::new();
        let mut cur = Some(internal);
        while let Some(ci_name) = cur {
            if !seen.insert(ci_name) {
                break; // supertype cycle (ill-formed source) — stop
            }
            let Some(ci) = self.class_info_name(ci_name) else {
                break;
            };
            if let Some(overloads) = ci.methods.get(name) {
                let mut fits = overloads
                    .iter()
                    .filter(|&&(_, fid, _)| self.ir.functions[fid as usize].params.len() == nargs);
                match (fits.next(), fits.next()) {
                    // Exactly one arity fit on this rung: the most-derived match wins.
                    (Some(&(idx, fid, ret)), None) => return Some((ci.id, idx, fid, ret)),
                    // Several same-arity overloads: needs parameter types — bail (skip, not guess).
                    (Some(_), Some(_)) => return None,
                    // No fit on this rung (`Derived.f(Int)` next to an inherited `f()`): keep
                    // walking — the fitting overload may live on a base class.
                    (None, _) => {}
                }
            }
            cur = ci.super_internal;
        }
        None
    }

    fn resolve_method_name(
        &self,
        internal: TypeName,
        name: &str,
    ) -> Option<(ClassId, u32, u32, Ty)> {
        let mut cur = Some(internal);
        while let Some(ci_name) = cur {
            // Stop at a non-IR (classpath) super rather than aborting the whole lookup — the interface
            // default-method fallback below still applies.
            let Some(ci) = self.class_info_name(ci_name) else {
                break;
            };
            if let Some(overloads) = ci.methods.get(name) {
                // Sole overload only: this lookup carries no argument types, so an overloaded
                // name cannot be resolved here (callers bail → skip, never misdispatch).
                return match overloads.as_slice() {
                    &[(idx, fid, ret)] => Some((ci.id, idx, fid, ret)),
                    _ => None,
                };
            }
            cur = ci.super_internal;
        }
        // Inherited interface DEFAULT method (`class C : I` calling `I`'s `fun f() = …` it doesn't
        // override): search the class's (and supers') interfaces transitively for a method WITH a body.
        // Returns the interface's class id, so the call emits `invokeinterface` on the receiver.
        // A VALUE-class receiver (erased to its underlying type) needs boxing to dispatch an interface
        // default — not modeled here, so skip the fallback (the caller bails → file skipped, not wrong).
        if self
            .syms
            .class_by_type_name(internal)
            .is_some_and(|c| c.value_field.is_some())
        {
            return None;
        }
        let mut stack = vec![internal];
        let mut seen = std::collections::HashSet::new();
        while let Some(cn) = stack.pop() {
            if !seen.insert(cn) {
                continue;
            }
            let Some(ci) = self.class_info_name(cn) else {
                continue;
            };
            if let Some(sup) = ci.super_internal {
                stack.push(sup);
            }
            for itf in self.ir.classes[ci.id as usize].interfaces.iter_ids() {
                if let Some(ici) = self.class_info_name(itf) {
                    // Only a genuine DEFAULT method (a body in the source) is a valid inherited target.
                    // An ABSTRACT interface method reached here (e.g. via class delegation `by`, where
                    // the class neither defines nor IR-registers it) would emit an `invokeinterface` to an
                    // unimplemented method (`AbstractMethodError`). Check the AST (order-independent; the
                    // IR body is set later in pass 2).
                    if self.iface_method_is_default_name(itf, name) {
                        if let Some(&[(idx, fid, ret)]) = ici.methods.get(name).map(Vec::as_slice) {
                            return Some((ici.id, idx, fid, ret));
                        }
                    }
                }
                stack.push(itf);
            }
        }
        None
    }

    fn link_local_method(
        &self,
        owner: &str,
        name: &str,
        params: &[Ty],
    ) -> Option<(ClassId, u32, u32, Ty)> {
        let ci = self.class_info(owner)?;
        ci.methods.get(name)?.iter().find_map(|&(idx, fid, ret)| {
            (self.ir.functions[fid as usize].params.as_slice() == params)
                .then_some((ci.id, idx, fid, ret))
        })
    }

    /// Whether a same-file interface's method is a DEFAULT method (declared with a body) — checked on
    /// the AST so it's independent of pass-2 lowering order.
    fn iface_method_is_default_name(&self, iface_internal: TypeName, name: &str) -> bool {
        self.afile.decls.iter().any(|&d| {
            matches!(self.afile.decl(d), Decl::Class(c) if c.is_interface()
                && type_name(&class_internal(self.afile, &c.name)) == iface_internal
                && c.methods.iter().any(|m| m.name == name && !matches!(m.body, FunBody::None)))
        })
    }

    /// Lower a call argument, inserting an explicit `ImplicitCoercion` when a primitive must box
    /// into a reference parameter (`Int` → `Any`) or a wrapper must unbox into a primitive param.
    /// Box/unbox is the backend's concern, but the *coercion* is explicit in the IR.
    /// Whether `e` is the `emptyArray()` reified intrinsic call — a bare `emptyArray(...)` with no
    /// arguments. kotlinc treats `emptyArray`/`arrayOfNulls`/`arrayOf` as codegen intrinsics; this
    /// recognizes the empty case so it can be specialized to the target element type at the use site.
    fn is_empty_array_intrinsic(&self, e: AstExprId) -> bool {
        if let Expr::Call { callee, args } = self.afile.expr(e) {
            if args.is_empty() {
                if let Expr::Name(n) = self.afile.expr(*callee) {
                    // `emptyArray` is a compiler intrinsic (no stdlib body) recognized by resolved symbol;
                    // a user-defined function or local of that name shadows it, exactly as in kotlinc.
                    return n == "emptyArray"
                        && self.lookup(n).is_none()
                        && !self.module_declares(n);
                }
            }
        }
        false
    }

    /// Lower `for (x in iterable)` over a non-array `iterable` via the Kotlin iterator protocol:
    /// `val it = iterable.iterator(); while (it.hasNext()) { val x = it.next(); body }`. The element
    /// type comes from the iterable's generic argument (`List<Int>` → `Int`); `next()` returns the
    /// erased `Object`, so a primitive element unboxes and a specific reference checkcasts. Bails
    /// (skip) if the iterator methods or the element type can't be resolved.
    /// `for (x in range)` over an `IntRange`/`LongRange`/`CharRange` value → a counted loop:
    /// `last = range.getLast(); i = range.getFirst(); while (i <= last) { x = i; …; i++ }` (step +1).
    /// The bounds are read once via the virtual getters; element/counter are the unboxed primitive.
    fn lower_foreach_range(
        &mut self,
        name: &str,
        iterable: AstExprId,
        body: AstExprId,
        it_ty: Ty,
        loop_info: CountedLoopInfo,
        label: Option<String>,
    ) -> Option<u32> {
        let internal = it_ty.obj_internal()?.to_string();
        let elem = loop_info.elem;
        let depth = self.scope.len();
        let elem_ir = ty_to_ir(elem);
        // Evaluate the range once into a temp (the getters must share one receiver).
        let rng = self.expr(iterable)?;
        let r_v = self.fresh_value();
        let var_r = self.emit_variable(r_v, ty_to_ir(it_ty), Some(rng));
        let getter = |this: &mut Self, accessor: &PlatformAccessor| {
            let recv = this.emit_get_value(r_v);
            this.emit_virtual_call(
                internal.clone(),
                accessor.name.clone(),
                accessor.descriptor.clone(),
                false,
                recv,
                vec![],
            )
        };
        // i = range.getFirst()
        let first = getter(self, &loop_info.first);
        let i_v = self.fresh_value();
        self.scope.push((name.to_string(), i_v, elem));
        let var_i = self.emit_named_variable(i_v, elem_ir.clone(), Some(first));
        // last = range.getLast()  (hoisted)
        let last = getter(self, &loop_info.last);
        let n_v = self.fresh_value();
        let var_n = self.emit_variable(n_v, elem_ir.clone(), Some(last));
        // condition: i <= last. Unsigned element types use the platform unsigned comparator so values
        // past the sign bit order correctly.
        let gi = self.emit_get_value(i_v);
        let gn = self.emit_get_value(n_v);
        let cond = self.compare_ordered(elem, IrBinOp::Le, gi, gn)?;
        // body (the loop variable `x` is the counter `i` itself)
        let mut out = Vec::new();
        if self.append_body_stmts(body, &mut out).is_none() {
            self.scope.truncate(depth);
            return None;
        }
        // i += 1  (the loop update, at the `continue` target)
        let gi2 = self.emit_get_value(i_v);
        let one = self.emit_const(self.scalar_one_const(elem)?);
        let inc = self.emit_primitive_bin_op(IrBinOp::Add, gi2, one);
        let incs = self.emit_set_value(i_v, inc);
        // Break when the counter reaches the inclusive last *before* incrementing, so a range ending at
        // `Int.MAX_VALUE`/`Long.MAX_VALUE` doesn't wrap past it and loop forever (same overflow-safe
        // counted-loop shape as `Stmt::For`). The break + increment are the `update` (the `continue`
        // target), so a `continue` also hits the bound check rather than skipping to the wrapping `i++`.
        let ic = self.emit_get_value(i_v);
        let ec = self.emit_get_value(n_v);
        let at_end = self.emit_primitive_bin_op(IrBinOp::Eq, ic, ec);
        let brk = self.emit_break(None);
        let if_break = self.emit_when(vec![(Some(at_end), brk)]);
        let update = self.emit_block(vec![if_break, incs], None);
        let wbody = self.emit_block(out, None);
        let wh = self.emit_while(cond, wbody, Some(update), false, label);
        self.scope.truncate(depth);
        Some(self.emit_block(vec![var_r, var_i, var_n, wh], None))
    }

    /// `for (x in progression)` over an `IntProgression`/`LongProgression`/`CharProgression` (and the
    /// unsigned `UInt`/`ULong` variants) value — a counted loop whose increment is the progression's
    /// `step` (which may be negative, e.g. from `downTo`), so the loop direction is decided at runtime.
    /// The progression's `getLast()` is already the exact final element (the stdlib computed it via
    /// `getProgressionLastElement`, including any `step`), so the `i == last` break lands precisely and
    /// guards against overflowing past a `MAX`/`MIN` bound:
    ///   i = p.getFirst(); last = p.getLast(); step = p.getStep();
    ///   while ((step > 0 && i <= last) || (step < 0 && i >= last)) { x = i; …; if (i == last) break; i += step }
    /// An unsigned progression compares its sign-bit-spanning elements via the platform unsigned
    /// comparator; its `step` stays signed, so the direction test is an ordinary signed comparison.
    fn lower_foreach_progression(
        &mut self,
        name: &str,
        iterable: AstExprId,
        body: AstExprId,
        it_ty: Ty,
        loop_info: CountedLoopInfo,
        label: Option<String>,
    ) -> Option<u32> {
        let internal = it_ty.obj_internal()?.to_string();
        let depth = self.scope.len();
        let elem = loop_info.elem;
        let elem_ir = ty_to_ir(elem);
        let (step_accessor, step_ty) = loop_info.step.clone()?;
        // Evaluate the progression once; the three getters share the one receiver.
        let rng = self.expr(iterable)?;
        let r_v = self.fresh_value();
        let var_r = self.emit_variable(r_v, ty_to_ir(it_ty), Some(rng));
        let getter = |this: &mut Self, accessor: &PlatformAccessor| {
            let recv = this.emit_get_value(r_v);
            this.emit_virtual_call(
                internal.clone(),
                accessor.name.clone(),
                accessor.descriptor.clone(),
                false,
                recv,
                vec![],
            )
        };
        // i = p.getFirst()
        let first = getter(self, &loop_info.first);
        let i_v = self.fresh_value();
        self.scope.push((name.to_string(), i_v, elem));
        let var_i = self.emit_named_variable(i_v, elem_ir.clone(), Some(first));
        // last = p.getLast()  (hoisted)
        let last = getter(self, &loop_info.last);
        let n_v = self.fresh_value();
        let var_n = self.emit_variable(n_v, elem_ir.clone(), Some(last));
        // step = p.getStep()  (hoisted)
        let step = getter(self, &step_accessor);
        let s_v = self.fresh_value();
        let var_s = self.emit_variable(s_v, ty_to_ir(step_ty), Some(step));
        // The step zero literal, in the step's own (signed) type.
        let zero_step = |this: &mut Self| {
            this.emit_const(if step_ty == Ty::Long {
                IrConst::Long(0)
            } else {
                IrConst::Int(0)
            })
        };
        // Compare two counter-typed values; unsigned elements use the platform unsigned comparator.
        let cmp = |this: &mut Self, op: IrBinOp, a: u32, b: u32| -> Option<u32> {
            let la = this.emit_get_value(a);
            let lb = this.emit_get_value(b);
            this.compare_ordered(elem, op, la, lb)
        };
        // cond: (step > 0 && i <= last) || (step < 0 && i >= last). A constant step folds to one branch
        // at the bytecode level; iterating is correct for either direction.
        let sg1 = self.emit_get_value(s_v);
        let z1 = zero_step(self);
        let step_pos = self.emit_primitive_bin_op(IrBinOp::Gt, sg1, z1);
        let i_le = cmp(self, IrBinOp::Le, i_v, n_v)?;
        let asc = self.emit_primitive_bin_op(IrBinOp::And, step_pos, i_le);
        let sg2 = self.emit_get_value(s_v);
        let z2 = zero_step(self);
        let step_neg = self.emit_primitive_bin_op(IrBinOp::Lt, sg2, z2);
        let i_ge = cmp(self, IrBinOp::Ge, i_v, n_v)?;
        let desc = self.emit_primitive_bin_op(IrBinOp::And, step_neg, i_ge);
        let cond = self.emit_primitive_bin_op(IrBinOp::Or, asc, desc);
        // body (the loop variable is the counter `i`)
        let mut out = Vec::new();
        if self.append_body_stmts(body, &mut out).is_none() {
            self.scope.truncate(depth);
            return None;
        }
        // update (the `continue` target): break exactly at `last`, then `i += step`. Breaking before the
        // increment keeps a progression ending at `MAX_VALUE`/`MIN_VALUE` from wrapping past it.
        let ic = self.emit_get_value(i_v);
        let ec = self.emit_get_value(n_v);
        let at_end = self.emit_primitive_bin_op(IrBinOp::Eq, ic, ec);
        let brk = self.emit_break(None);
        let if_break = self.emit_when(vec![(Some(at_end), brk)]);
        let gi2 = self.emit_get_value(i_v);
        let gs = self.emit_get_value(s_v);
        let inc = self.emit_primitive_bin_op(IrBinOp::Add, gi2, gs);
        let incs = self.emit_set_value(i_v, inc);
        let update = self.emit_block(vec![if_break, incs], None);
        let wbody = self.emit_block(out, None);
        let wh = self.emit_while(cond, wbody, Some(update), false, label);
        self.scope.truncate(depth);
        Some(self.emit_block(vec![var_r, var_i, var_n, var_s, wh], None))
    }

    fn lower_foreach_iterator(
        &mut self,
        name: &str,
        iterable: AstExprId,
        body: AstExprId,
        it_ty: Ty,
        opts: ForeachOpts<'_>,
    ) -> Option<u32> {
        let ForeachOpts {
            index,
            label,
            hof_splice,
        } = opts;
        let protocol = self.info.iterator_protocol(iterable).cloned()?;
        let iter_dispatch = protocol.iterator;
        let iter_ty = protocol.iter_ty;
        let iter_internal = iter_ty.obj_internal()?;
        let hasnext_m = protocol.has_next;
        let next_m = protocol.next;
        let elem = protocol.elem_ty;
        let depth = self.scope.len();
        // `forEachIndexed`: an `Int` index counter, declared before the loop and bound to the lambda's
        // first parameter, incremented at the end of each iteration.
        let (idx_v, var_idx) = if let Some(iname) = index {
            let v = self.fresh_value();
            self.scope.push((iname.to_string(), v, Ty::Int));
            let zero = self.emit_const(IrConst::Int(0));
            (
                Some(v),
                Some(self.emit_named_variable(v, ty_to_ir(Ty::Int), Some(zero))),
            )
        } else {
            (None, None)
        };

        // it = iterable.iterator()  (member virtual call, or the extension's static call)
        let recv = self.expr(iterable)?;
        // A spliced stdlib HOF (`forEach`/`forEachIndexed`): kotlinc binds the receiver to the named
        // inline local `$this$forEach$iv` before iterating — in scope (spilled) at every suspension
        // in the body. A plain `for` loop has no such local.
        let (recv, var_recv) = if hof_splice {
            let rv = self.fresh_value();
            let vr = self.emit_named_variable(rv, ty_to_ir(it_ty), Some(recv));
            (self.emit_get_value(rv), Some(vr))
        } else {
            (recv, None)
        };
        let iter_call = match iter_dispatch {
            IteratorDispatchTarget::Member {
                owner_fallback,
                member,
            } => {
                let ret = member.ret;
                let suspend = member.suspend;
                self.emit_library_member_call(recv, owner_fallback, *member, ret, suspend, vec![])
            }
            IteratorDispatchTarget::Extension(callable) => {
                self.emit_library_static_call(*callable, vec![recv], false)
            }
        };
        let it_v = self.fresh_value();
        let var_it = self.emit_named_variable(it_v, ty_to_ir(iter_ty), Some(iter_call));

        // cond: it.hasNext()
        let it_g = self.emit_get_value(it_v);
        let hasnext_ret = hasnext_m.ret;
        let hasnext_suspend = hasnext_m.suspend;
        let cond = self.emit_library_member_call(
            it_g,
            iter_internal,
            hasnext_m,
            hasnext_ret,
            hasnext_suspend,
            vec![],
        );

        // x = (elem) it.next()  — unbox a primitive element, checkcast a specific reference.
        let it_g2 = self.emit_get_value(it_v);
        let next_ret = next_m.ret;
        let next_suspend = next_m.suspend;
        let next_call = self.emit_library_member_call(
            it_g2,
            iter_internal,
            next_m,
            next_ret,
            next_suspend,
            vec![],
        );
        let x_init = if elem.is_unsigned() {
            // The element is a boxed `kotlin/UInt`/`ULong` — checkcast + `unbox-impl`, not the
            // `Integer` unbox a plain JVM-scalar coercion would emit.
            self.unbox_unsigned(next_call, elem)?
        } else if self.has_scalar_value_repr(elem) {
            self.emit_type_op(IrTypeOp::ImplicitCoercion, next_call, ty_to_ir(elem))
        } else if !elem.is_erased_top() {
            self.emit_type_op(IrTypeOp::Cast, next_call, ty_to_ir(elem))
        } else {
            next_call
        };
        let x_v = self.fresh_value();
        // A spliced stdlib HOF binds the loop ELEMENT (`item$iv$iv`) and the lambda PARAMETER (`it`)
        // as SEPARATE named locals, exactly as kotlinc's inline expansion does — both join the
        // suspend spill scope. A plain `for` loop binds only the loop variable.
        let (var_x, var_param) = if hof_splice {
            let vi = self.emit_named_variable(x_v, ty_to_ir(elem), Some(x_init));
            let p_v = self.fresh_value();
            self.scope.push((name.to_string(), p_v, elem));
            let g = self.emit_get_value(x_v);
            let vp = self.emit_named_variable(p_v, ty_to_ir(elem), Some(g));
            (vi, Some(vp))
        } else {
            self.scope.push((name.to_string(), x_v, elem));
            // A destructuring loop (`for ((a, b) in …)`) binds a parser-synthesized `$dest$…` entry
            // that the prepended `Stmt::Destructure` consumes immediately — kotlinc never
            // materializes it as a named local, so it must stay an unnamed temp (out of the suspend
            // spill scope).
            let vx = if name.starts_with("$dest$") {
                self.emit_variable(x_v, ty_to_ir(elem), Some(x_init))
            } else {
                self.emit_named_variable(x_v, ty_to_ir(elem), Some(x_init))
            };
            (vx, None)
        };

        let mut out = vec![var_x];
        if let Some(vp) = var_param {
            out.push(vp);
        }
        if self.append_body_stmts(body, &mut out).is_none() {
            self.scope.truncate(depth);
            return None;
        }
        // index += 1 (forEachIndexed)
        let update = idx_v.map(|iv| {
            let g = self.emit_get_value(iv);
            let one = self.emit_const(IrConst::Int(1));
            let inc = self.emit_primitive_bin_op(IrBinOp::Add, g, one);
            self.emit_set_value(iv, inc)
        });
        let wbody = self.emit_block(out, None);
        let wh = self.emit_while(cond, wbody, update, false, label);
        self.scope.truncate(depth);
        let mut stmts = Vec::new();
        if let Some(vr) = var_recv {
            stmts.push(vr);
        }
        if let Some(vi) = var_idx {
            stmts.push(vi);
        }
        stmts.push(var_it);
        stmts.push(wh);
        Some(self.emit_block(stmts, None))
    }

    /// Lower a positional argument list against parallel parameter types, coercing each argument to its
    /// parameter (numeric widening, boxing, lambda → `FunctionN`, …) via [`Self::lower_arg`]. `None` if
    /// any argument fails to lower (the whole call then declines). Folds the `let mut a = Vec::new(); for
    /// … { a.push(self.lower_arg(…)?) }` loop the call paths otherwise re-implement at each dispatch arm.
    fn lower_args(&mut self, args: &[AstExprId], targets: &[Ty]) -> Option<Vec<u32>> {
        let mut a = Vec::with_capacity(args.len());
        for (arg, t) in args.iter().zip(targets) {
            a.push(self.lower_arg(*arg, t)?);
        }
        Some(a)
    }

    /// The single abstract method of a same-module interface `internal` as `(method_name, returns_void)`
    /// — used for SAM conversion. `None` if not a single-method interface in this module.
    fn sam_target(&self, internal: &str) -> Option<(String, bool)> {
        let ci = self.class_info(internal)?;
        let cls = &self.ir.classes[ci.id as usize];
        if !cls.is_interface {
            return None;
        }
        // The SAM is the single ABSTRACT method (no body) — default/inherited methods don't count.
        let mut abstract_methods = cls
            .methods
            .iter()
            .filter(|&&m| self.ir.functions[m as usize].body.is_none());
        let only = abstract_methods.next()?;
        if abstract_methods.next().is_some() {
            return None; // more than one abstract method — not a SAM
        }
        let f = &self.ir.functions[*only as usize];
        Some((f.name.clone(), f.ret == ty_to_ir(Ty::Unit)))
    }

    /// Whether `internal` is a SAM interface a lambda ARGUMENT can be soundly converted to: a non-generic
    /// user `fun interface` whose method involves no value class (mirrors the checker's gate). Generic /
    /// value-class / library SAMs are excluded — `lower_lambda_sam`'s metafactory descriptor can't model
    /// them yet.
    fn is_simple_fun_interface(&self, internal: &str) -> bool {
        self.syms.class_by_internal(internal).is_some_and(|c| {
            // Generic fun interfaces allowed (erased SAM descriptor); value-class methods excluded —
            // see the matching note in `resolve::simple_fun_interface`.
            c.is_fun_interface
        })
    }

    /// Turn a void `Unit` result into the 1-slot `kotlin/Unit.INSTANCE` reference value: run `effect`
    /// (a lowered Unit expression, which leaves nothing on the stack) for its side effects, then yield
    /// the singleton. The single rule for materializing a Unit VALUE where the JVM has only `void` — used
    /// where a Unit flows into a reference target (`= unitExpr` as `Any?`) or is an `==`/`!=` operand.
    fn unit_value_after_effect(&mut self, effect: u32) -> u32 {
        let unit = self.emit_unit();
        self.emit_block(vec![effect], Some(unit))
    }

    pub(crate) fn lower_arg(&mut self, arg: AstExprId, target: &Ty) -> Option<u32> {
        // A lambda flowing into a CLASSPATH suspend-lambda parameter (`runBlocking { … }` and the other
        // coroutine builders). The JVM descriptor erases the parameter to a bare `FunctionN`, so neither the
        // target nor the checked argument type carries `suspend = true`; the STRUCTURAL marker is a trailing
        // `Continuation` parameter on the checked lambda type (`suspend CoroutineScope.() -> R` erases to
        // `Function2<CoroutineScope, Continuation<R>, Object>`). Strip that continuation and route the lambda
        // to `lower_suspend_lambda`, which builds the real `SuspendLambda` state machine — the coroutine
        // builder then drives it. (Recognized BEFORE the SAM path below, which would wrap it as a plain
        // `FunctionN` whose body ignores the continuation and VerifyErrors when driven as a coroutine.)
        if matches!(self.afile.expr(arg), Expr::Lambda { .. }) {
            if let Ty::Fun(s) = self.info.ty(arg) {
                let tail_continuation = s
                    .params
                    .last()
                    .and_then(|p| p.obj_internal())
                    .is_some_and(|n| n.matches("kotlin/coroutines/Continuation"));
                if tail_continuation && !s.suspend {
                    // Value parameters are everything before the trailing continuation (the receiver of a
                    // `Recv.() -> R` builder lambda is modeled as the single value parameter `it`).
                    let value_params: Vec<Ty> = s.params[..s.params.len() - 1].to_vec();
                    if let Expr::Lambda {
                        params: lparams,
                        body,
                    } = self.afile.expr(arg).clone()
                    {
                        let bind_names =
                            ast::lambda_params_or_implicit(&lparams, value_params.len())?;
                        if bind_names.len() == value_params.len() {
                            return self.lower_suspend_lambda(body, &value_params, bind_names);
                        }
                    }
                    return None;
                }
            }
        }
        // SAM conversion: a lambda flowing into a simple `fun interface` parameter becomes an instance of
        // that interface whose single abstract method runs the lambda (the checker validated the target).
        if let Some(internal) = target.non_null().obj_internal() {
            let internal = internal.render();
            if self.is_simple_fun_interface(&internal) {
                if let Expr::Lambda { params, body } = self.afile.expr(arg).clone() {
                    if let Some((method, void)) = self.sam_target(&internal) {
                        return self.lower_lambda_sam(
                            arg,
                            &params,
                            body,
                            Some((internal.to_string(), method, void)),
                        );
                    }
                }
                // A non-literal FUNCTION value (`fnVal`, `expr::ref`) SAM-converted to the interface needs
                // a wrapper forwarding to its `invoke`. A naive wrapper miscompiles a NULLABLE value
                // (wrapping `null` into a non-null instance changes `r == null`), a contravariant
                // intersection type, and a suspend value — so skip rather than miscompile. (A value already
                // OF the interface type is not a `Ty::Fun` and passes through below.)
                if matches!(self.info.ty(arg), Ty::Fun(_)) {
                    return None;
                }
            }
        }
        // A value flowing into a `suspend` function-type parameter. A LAMBDA literal becomes a concrete
        // `SuspendLambda` subclass (`lower_suspend_lambda`); any other value (a suspend function value
        // passed through) needs continuation threading not yet modeled, so it bails (skip the file).
        if let Ty::Fun(s) = target.non_null() {
            if s.suspend {
                let params = &s.params;
                if let Expr::Lambda {
                    params: lparams,
                    body,
                } = self.afile.expr(arg).clone()
                {
                    // Bind names: explicit, or the implicit single `it`, or none (arity 0).
                    let bind_names = ast::lambda_params_or_implicit(&lparams, params.len())?;
                    // Parameter `Ty`s come from the checked lambda type; absent metadata falls back to `Any`.
                    let ty_params: Vec<Ty> = self
                        .info
                        .ty(arg)
                        .fun_params()
                        .map(|p| p.to_vec())
                        .filter(|p| p.len() == params.len())
                        .unwrap_or_else(|| vec![Ty::obj("kotlin/Any"); params.len()]);
                    if bind_names.len() == params.len() {
                        return self.lower_suspend_lambda(body, &ty_params, bind_names);
                    }
                }
                return None;
            }
        }
        let at = self.info.ty(arg);
        // `emptyArray<T>()` is a reified intrinsic — expand it to a fresh empty array of the *target*
        // element type (the reified `T`), exactly as kotlinc specializes it, rather than calling the
        // throwing stub. Recognized by the call shape (not the erased `Array<Any>` type, which a real
        // `Object[]` value also has); the target supplies the otherwise-erased element.
        if self.is_empty_array_intrinsic(arg) && ir_array_element(target).is_some() {
            return Some(self.emit_vararg(*target, vec![]));
        }
        let e = self.expr(arg)?;
        let target_ref = ir_type_is_reference(target);
        // An unsigned value flowing into a reference context (`Any`, a generic, a collection element)
        // boxes via the inline-class `box-impl` factory to a `kotlin/UInt`/`ULong` object.
        if at.is_unsigned() && target_ref {
            return self.box_unsigned(e, at);
        }
        // A reference (`Any`, a smart-cast `is UInt`) flowing into an unsigned target unboxes the
        // `kotlin.UInt`/`ULong` value type — but krusty erases unsigned to `int` and would emit an
        // `Integer` unbox (ClassCastException). Skip rather than miscompile.
        if at.is_reference() && self.unsigned_integer_box_type(target.non_null()).is_some() {
            return None;
        }
        if at == Ty::Unit && target_ref {
            // A `Unit` value flowing into a reference target (`fun f(): Any? = unitExpr`, `Unit?`).
            Some(self.unit_value_after_effect(e))
        } else if self.has_scalar_value_repr(at) && target_ref {
            Some(self.emit_type_op(IrTypeOp::ImplicitCoercion, e, target.clone()))
        } else if at.is_reference() && !target_ref && *target != Ty::Unit && *target != Ty::Error {
            Some(self.emit_type_op(IrTypeOp::ImplicitCoercion, e, target.clone()))
        } else if self.has_scalar_value_repr(at)
            && !target_ref
            && *target != Ty::Error
            && *target != Ty::Unit
            && ty_to_ir(at) != *target
        {
            // Primitive numeric widening/narrowing (`Int` → `Long`, `Double` → `Int`): emit a
            // coercion (the backend does the `i2l`/`d2i`/… conversion).
            Some(self.emit_type_op(IrTypeOp::ImplicitCoercion, e, target.clone()))
        } else if at.is_erased_top() && target_ref && !ir_type_is_object(target) {
            // A generic type-parameter return is erased to `Object` in the JVM signature; flowing it
            // into a more specific reference target needs a `checkcast` (kotlinc inserts one — the
            // value really is the target type at runtime). `as`-style, but never null here.
            Some(self.emit_type_op(IrTypeOp::Cast, e, target.clone()))
        } else {
            Some(e)
        }
    }

    /// A member read of a property declared as a generic type parameter has the erased *physical*
    /// type `pty` (`Object`) on the JVM, but the checker may have substituted a more specific
    /// *logical* type (`Box<Int>().x : Int`). Insert the coercion kotlinc emits on such a read: an
    /// unbox for a primitive target, a checkcast for a more specific reference target. A no-op when
    /// the logical and physical types already agree (every non-generic read).
    /// Insert the unbox/checkcast bridging an erased physical type to a known logical type — the same
    /// coercion as [`coerce_generic_read`] but with both types given directly (for synthesized reads,
    /// e.g. a destructuring `componentN()` call whose erased `Object` becomes the element type).
    /// A typed zero/`null` placeholder for an omitted `$default` parameter — the value is ignored
    /// (the synthetic stub substitutes the real default when the mask bit is set), but its type must
    /// match the descriptor slot: `0` for a primitive, `null` for a reference.
    fn zero_placeholder(&mut self, t: Ty) -> u32 {
        // A NON-nullable primitive stored in its `Obj("kotlin/…")` value-class form is a JVM primitive
        // (e.g. a non-null `Int` parameter is `int`), so its zero is the primitive `0`, not a null ref.
        let t = t.unboxed_primitive().unwrap_or(t);
        let c = match t {
            Ty::Long => IrConst::Long(0),
            Ty::Double => IrConst::Double(0.0),
            Ty::Float => IrConst::Float(0.0),
            // Plain JVM-int-family primitives and value-class scalar reps → `0`.
            t if self.has_scalar_value_repr(t) => IrConst::Int(0),
            _ => IrConst::Null,
        };
        self.emit_const(c)
    }

    fn append_default_mask_marker(&mut self, out: &mut Vec<u32>, mask: i32) {
        out.push(self.emit_const(IrConst::Int(mask)));
        out.push(self.emit_const(IrConst::Null));
    }

    fn append_default_masks_marker(
        &mut self,
        out: &mut Vec<u32>,
        param_count: usize,
        omitted: impl IntoIterator<Item = usize>,
    ) {
        let mut masks = vec![0i32; default_mask_count(param_count)];
        for i in omitted {
            masks[i / 32] |= default_mask_bit(i);
        }
        for mask in masks {
            out.push(self.emit_const(IrConst::Int(mask)));
        }
        out.push(self.emit_const(IrConst::Null));
    }

    fn empty_array(&mut self, array_type: Ty) -> u32 {
        let size = self.emit_const(IrConst::Int(0));
        self.emit_new_array(array_type, size)
    }

    fn append_default_call_args(
        &mut self,
        out: &mut Vec<u32>,
        params: &[Ty],
        args: &[AstExprId],
        trailing_lambda: bool,
    ) -> Option<()> {
        let mask: i32 = if trailing_lambda && args.len() < params.len() {
            let prefix_len = args.len().checked_sub(1)?;
            let last = params.len() - 1;
            for j in 0..params.len() {
                let pj = ty_to_ir(params[j]);
                if j < prefix_len {
                    out.push(self.lower_arg(args[j], &pj)?);
                } else if j == last {
                    out.push(self.lower_arg(args[prefix_len], &pj)?);
                } else {
                    out.push(self.zero_placeholder(params[j]));
                }
            }
            (prefix_len..last).map(|j| 1i32 << j).sum()
        } else if args.len() <= params.len() {
            for (i, &arg) in args.iter().enumerate() {
                out.push(self.lower_arg(arg, &ty_to_ir(params[i]))?);
            }
            for &param in &params[args.len()..] {
                out.push(self.zero_placeholder(param));
            }
            (args.len()..params.len()).map(|j| 1i32 << j).sum()
        } else {
            return None;
        };
        self.append_default_mask_marker(out, mask);
        Some(())
    }

    fn lower_assert_fails_with_default(
        &mut self,
        call: AstExprId,
        callable: &crate::libraries::LibraryCallable,
        args: &[AstExprId],
    ) -> Option<u32> {
        if !self.runtime.is_reified_assert_fails_with_default(callable) {
            return None;
        }
        let expected = self
            .afile
            .call_type_args
            .get(&call.0)?
            .first()
            .and_then(|r| self.ty_ref(r))?;
        let exc_internal = expected.obj_internal()?.to_string();
        let lambda_arg = *args.last()?;
        let lambda_param = callable
            .params
            .last()
            .copied()
            .or_else(|| self.syms.libraries.function_type(0))
            .unwrap_or_else(|| Ty::fun(Vec::new(), Ty::obj("kotlin/Any")));
        let lambda = self.lower_arg(lambda_arg, &lambda_param)?;
        let invoke = self.ir.add_expr(IrExpr::InvokeFunction {
            func: lambda,
            args: Vec::new(),
            ret: Ty::obj("kotlin/Any"),
        });
        let msg = self.ir_const_str("Expected an exception to be thrown.".to_string());
        let assertion_ctor = self.runtime.runtime_ctor(RuntimeCtor::AssertionError)?;
        let assertion =
            self.emit_new_external(assertion_ctor.internal, assertion_ctor.ctor_desc, vec![msg]);
        let throw_assertion = self.emit_throw(assertion);
        let body = self.emit_block(vec![invoke], Some(throw_assertion));
        let catch_var = self.fresh_value();
        let caught = self.emit_get_value(catch_var);
        Some(self.emit_try(
            body,
            vec![IrCatch {
                var: catch_var,
                exc_internal: type_name(&exc_internal),
                body: caught,
            }],
            None,
            ty_to_ir(callable.ret),
        ))
    }

    /// The `kotlin.assert` codegen intrinsic. kotlinc does NOT inline the stdlib body (which reads
    /// `kotlin/_Assertions.ENABLED`); it guards on the JVM's per-class assertion status and skips even
    /// evaluating the condition when disabled. Lower `assert(cond)` / `assert(cond) { msg }` to
    /// `if (<ThisClass>.class.desiredAssertionStatus()) { if (!cond) throw AssertionError([msg]) }` — the
    /// enclosing-class `Class` literal is the `ClassConst` facade sentinel; the outer guard short-circuits
    /// so `cond` (and the message lambda) run only when assertions are enabled.
    fn lower_assert(
        &mut self,
        callable: &crate::libraries::LibraryCallable,
        args: &[AstExprId],
    ) -> Option<u32> {
        if callable.name != "assert" || !callable.owner.contains("PreconditionsKt") {
            return None;
        }
        // `// ASSERTIONS_MODE: always-disable` — the call is elided entirely; the condition (and message
        // lambda) are not even evaluated, matching kotlinc. Yield an empty `Unit` statement.
        if self.afile.assert_always_disabled {
            return Some(self.emit_block(vec![], None));
        }
        let cond = self.lower_arg(*args.first()?, &ty_to_ir(Ty::Boolean))?;
        // The thrown `AssertionError`: no-arg for `assert(cond)`; for `assert(cond) { msg }` invoke the
        // message lambda and pass its value to `AssertionError(Object)`.
        let assertion = if args.len() >= 2 {
            let lambda_param = callable
                .params
                .last()
                .copied()
                .or_else(|| self.syms.libraries.function_type(0))
                .unwrap_or_else(|| Ty::fun(Vec::new(), Ty::obj("kotlin/Any")));
            let lambda = self.lower_arg(args[1], &lambda_param)?;
            let msg = self.ir.add_expr(IrExpr::InvokeFunction {
                func: lambda,
                args: Vec::new(),
                ret: Ty::obj("kotlin/Any"),
            });
            self.emit_new_external(
                "java/lang/AssertionError",
                "(Ljava/lang/Object;)V",
                vec![msg],
            )
        } else {
            self.emit_new_external("java/lang/AssertionError", "()V", vec![])
        };
        let throw = self.emit_throw(assertion);
        let throw_block = self.emit_block(vec![throw], None);
        let empty = self.emit_block(vec![], None);
        // `if (cond) {} else { throw }` ≡ `if (!cond) throw`.
        let check = self.emit_when(vec![(Some(cond), empty), (None, throw_block)]);
        // `// ASSERTIONS_MODE: always-enable` — the check runs UNCONDITIONALLY (no per-class guard).
        if self.afile.assert_always_enabled {
            return Some(check);
        }
        // `<ThisClass>.class.desiredAssertionStatus()` — the per-class JVM assertion flag.
        let cls = self.emit_class_const(String::new());
        let enabled = self.emit_virtual_call(
            "java/lang/Class".to_string(),
            "desiredAssertionStatus".to_string(),
            "()Z".to_string(),
            false,
            cls,
            vec![],
        );
        // `if (enabled) { <check> }` — no else; the whole `assert` is a `Unit` statement.
        Some(self.emit_when(vec![(Some(enabled), check)]))
    }

    /// Lower Kotlin console intrinsics to `System.out.print*`; returns `None` for other callables.
    fn lower_println(
        &mut self,
        callable: &crate::libraries::LibraryCallable,
        args: &[AstExprId],
    ) -> Option<u32> {
        if !matches!(callable.name.as_str(), "println" | "print")
            || !callable.owner.contains("ConsoleKt")
        {
            return None;
        }
        let descriptor = if callable.descriptor.is_empty() {
            self.runtime.method_descriptor(&callable.params, Ty::Unit)?
        } else {
            callable.descriptor.clone()
        };
        let out =
            self.emit_external_static_field("java/lang/System", "out", "Ljava/io/PrintStream;");
        let mut a = Vec::new();
        for (i, &arg) in args.iter().enumerate() {
            let pty = callable
                .params
                .get(i)
                .copied()
                .unwrap_or_else(|| Ty::obj("kotlin/Any"));
            a.push(self.lower_arg(arg, &ty_to_ir(pty))?);
        }
        Some(self.emit_virtual_call(
            "java/io/PrintStream".to_string(),
            callable.name.clone(),
            descriptor,
            false,
            out,
            a,
        ))
    }

    /// `a == b` / `a != b` where BOTH operands are nullable boxed numbers (`Double?`, `Int?`, … — e.g.
    /// smart-cast from `Any?`). Kotlin compares them by VALUE with numeric promotion and IEEE-754
    /// semantics, not by `equals` (which is type-specific: `Integer.equals(Double)` is always false).
    /// Conform the two numbers — promote both to the wider primitive, IEEE-compare — with null handling:
    /// `==` is `(a == null) ? (b == null) : (b != null && a~ == b~)`. `lp`/`rp` are the operand underlying
    /// primitives. Returns `None` (fall through to the generic path) if the pair has no numeric promotion.
    fn lower_numeric_eq_conform(
        &mut self,
        lhs: AstExprId,
        rhs: AstExprId,
        lp: Ty,
        rp: Ty,
        negated: bool,
    ) -> Option<u32> {
        let common = Ty::promote(lp, rp)?;
        let cir = ty_to_ir(common);
        let av = self.expr(lhs)?;
        let bv = self.expr(rhs)?;
        let any = ty_to_ir(Ty::nullable(Ty::obj("kotlin/Any")));
        let avar_i = self.fresh_value();
        let bvar_i = self.fresh_value();
        let avar = self.emit_variable(avar_i, any, Some(av));
        let bvar = self.emit_variable(bvar_i, any, Some(bv));
        let is_null = |this: &mut Self, slot: u32| {
            let g = this.emit_get_value(slot);
            let n = this.emit_const(IrConst::Null);
            this.emit_primitive_bin_op(IrBinOp::RefEq, g, n)
        };
        // Both non-null: unbox each to its own primitive, promote to the common type, primitive-compare
        // (IEEE for Float/Double — `dcmpl`/`fcmpl`, so `-0.0 == 0.0` and `NaN != NaN`).
        let unbox_to_common = |this: &mut Self, slot: u32, p: Ty| {
            let g = this.emit_get_value(slot);
            let prim = this.emit_type_op(IrTypeOp::ImplicitCoercion, g, ty_to_ir(p));
            if p == common {
                prim
            } else {
                this.emit_type_op(IrTypeOp::ImplicitCoercion, prim, cir)
            }
        };
        let a_unb = unbox_to_common(self, avar_i, lp);
        let b_unb = unbox_to_common(self, bvar_i, rp);
        let cmp = self.emit_primitive_bin_op(IrBinOp::Eq, a_unb, b_unb);
        // `if (b == null) false else cmp` (reached only when `a` is non-null).
        let b_null2 = is_null(self, bvar_i);
        let false_c = self.emit_const(IrConst::Boolean(false));
        let inner = self.emit_when(vec![(Some(b_null2), false_c), (None, cmp)]);
        // `if (a == null) (b == null) else <inner>`.
        let a_null = is_null(self, avar_i);
        let b_null1 = is_null(self, bvar_i);
        let mut eq = self.emit_when(vec![(Some(a_null), b_null1), (None, inner)]);
        if negated {
            let t = self.emit_const(IrConst::Boolean(true));
            let f = self.emit_const(IrConst::Boolean(false));
            eq = self.emit_when(vec![(Some(eq), f), (None, t)]);
        }
        Some(self.emit_block(vec![avar, bvar], Some(eq)))
    }

    /// Mark a value's substituted STATIC type for the backend's box/unbox coercion (an unsigned/primitive
    /// value out of an erased `Object` unboxes). A REFERENCE narrowing (`Object`→`String`, `Object[]`→
    /// `Array<Int>`) is NOT tagged here: the backend owns erasure and inserts that `checkcast` at the
    /// CONSUMPTION site (return / argument / receiver), keyed on the value's actual physical type.
    fn coerce_to_static(&mut self, read: u32, logical: Ty, physical: Ty) -> u32 {
        if logical == physical || matches!(logical, Ty::Null | Ty::Error) {
            return read;
        }
        // An unsigned value out of an erased reference: checkcast to the inline-class object, then
        // `unbox-impl` — the wrapper is `kotlin/UInt`, not `Integer`.
        if logical.is_unsigned() && physical.is_reference() {
            return self
                .unbox_unsigned(read, logical)
                .expect("unsigned integer target must provide box/unbox shape");
        }
        // A primitive out of an erased reference unboxes through the value-class pass's `ImplicitCoercion`
        // channel — the emitter decides (box/unbox/nothing) from the value's actual type.
        if self.has_scalar_value_repr(logical) && physical.is_reference() {
            self.emit_type_op(IrTypeOp::ImplicitCoercion, read, ty_to_ir(logical))
        } else if logical.is_reference()
            && !matches!(logical, Ty::Null)
            && physical.is_reference()
            && logical.non_null() != physical.non_null()
        {
            // Tag the substituted static type on a reference read whose declared (physical) type differs.
            // NO erasure OR value-class decision here — a plain `Cast`. The value-class PASS rewrites a
            // `Cast` to a value class into box/unbox; the EMITTER emits the `checkcast` for a genuine
            // erased-top narrowing and NOTHING otherwise (both keyed on the value's physical type).
            self.emit_type_op(IrTypeOp::Cast, read, ty_to_ir(logical))
        } else {
            read
        }
    }

    fn coerce_generic_read(&mut self, read: u32, member: AstExprId, pty: Ty) -> u32 {
        let lt = self.info.ty(member);
        if lt == Ty::Error {
            return read;
        }
        self.coerce_to_static(read, lt, pty)
    }

    /// Read a backing-field property `recv.name` on an in-file class, given the ALREADY-LOWERED receiver
    /// and the receiver's internal name. A read from OUTSIDE the declaring class goes through the public
    /// `getX()` accessor (the backing field is private, matching kotlinc); inside, the field is read
    /// directly. A generic field's erased read is coerced to the concrete member type (`checkcast`/unbox).
    /// `recv_slot_ty` is the receiver's declared SLOT type (when it is a simple `Name`); for a DIRECT
    /// field read whose slot is wider than the owning class (an erased generic / `Any?` narrowed by `is`),
    /// the receiver is `checkcast`'d to the owner so `getfield` verifies. `None` when `name` isn't a
    /// backing field. Shared by the `.` (Expr::Member) and `?.` (Expr::SafeCall) member-read paths so they
    /// don't re-implement the resolve→getter/GetField→coerce sequence independently.
    fn lower_field_read_on(
        &mut self,
        recv: u32,
        recv_internal: &str,
        name: &str,
        e: AstExprId,
        recv_slot_ty: Option<Ty>,
    ) -> Option<u32> {
        let (class, idx, pty) = self.resolve_field(recv_internal, name)?;
        let owner_internal = self.ir.classes[class as usize].fq_name_id();
        if self.cur_class != Some(owner_internal) {
            if let Some((mclass, mindex, _, _)) =
                self.resolve_method(recv_internal, &property_getter_name(name))
            {
                let read = self.emit_method_call(mclass, mindex, recv, vec![]);
                return Some(self.coerce_generic_read(read, e, pty));
            }
        }
        // Smartcast: if the receiver's slot type isn't the owning class, checkcast it so `getfield` is
        // valid (an erased generic / `Any?` local narrowed by `is`).
        let recv = if recv_slot_ty.is_some_and(|t| t != Ty::obj_name(owner_internal)) {
            self.emit_type_op(IrTypeOp::Cast, recv, ty_to_ir(Ty::obj_name(owner_internal)))
        } else {
            recv
        };
        let read = self.emit_get_field(recv, class, idx);
        Some(self.coerce_generic_read(read, e, pty))
    }

    /// Lower a zero-arg member READ `recv.name` on a builtin/library/another-file receiver — the shared
    /// path behind a qualified `recv.name` and a receiver-lambda's implicit `this.name`. The member is
    /// resolved generically through the library/stdlib classpath reader by its own name, its `getX()`
    /// accessor form, or a collection-mapped name (no per-member hardcode — `String.length` resolves as
    /// `java/lang/String.length()` just like `uppercase()`). `recv` is the already-lowered receiver
    /// value. `e` is the source property read, so lowering reuses checker-selected handles and applies
    /// expression-specific generic coercions. Returns `None` when the type exposes no such member.
    fn lower_member_read_on(&mut self, recv: u32, rt: Ty, name: &str, e: AstExprId) -> Option<u32> {
        // Resolve against the NON-NULL type. A receiver whose static type keeps its `?` (a smart-cast /
        // `!!` value bound to a call-result local, whose narrowing krusty doesn't propagate to the read
        // site) is a valid reference at runtime — the getter dispatches the same, and krusty does not
        // enforce null-safety. Without this a `foo().bar` on a `Foo?`-typed result resolves no member.
        let rt = rt.non_null();
        // A property on a class defined in ANOTHER file → its public `getX()` accessor (the backing
        // field is private). Resolved from the sibling class's `ClassSig`.
        if let Ty::Obj(i, _) = rt {
            if self.class_of(rt).is_none() {
                if let Some((owner, ret_ty, is_iface)) = self
                    .syms
                    .class_by_type_name(i)
                    .filter(|cs| cs.value_field.is_none())
                    .and_then(|cs| {
                        cs.props
                            .iter()
                            .find_map(|(n, t, _)| (n == name).then_some((i, *t, cs.is_interface)))
                    })
                {
                    return Some(self.emit_call(
                        Callee::CrossFileVirtual {
                            owner,
                            name: property_getter_name(name),
                            params: vec![],
                            ret: ty_to_ir(ret_ty),
                            interface: is_iface,
                        },
                        Some(recv),
                        vec![],
                    ));
                }
            }
        }
        // A Kotlin property is a zero-arg member. Resolve the semantic property name through the
        // library source first; mapped builtins supply their physical owner/name/descriptor there.
        let internal = match rt {
            Ty::String => type_name("kotlin/String"),
            Ty::Obj(i, _) => i,
            _ => return None,
        };
        let resolved = self.info.resolved_member(e).cloned().map(|r| {
            let m = r.member;
            let physical_ret = m.physical_ret;
            (m, physical_ret)
        });
        if let Some((m, physical_ret)) = resolved {
            let read =
                self.emit_library_member_call(recv, internal, m, physical_ret, false, vec![]);
            return Some(self.coerce_generic_read(read, e, physical_ret));
        }
        None
    }

    fn lower_call_slot_args(
        &mut self,
        source_args: &[AstExprId],
        slots: &[Option<AstExprId>],
        params: &[Ty],
    ) -> Option<Vec<u32>> {
        self.lower_call_slot_args_with_element(source_args, slots, params, None)
    }

    fn lower_call_slot_args_with_element(
        &mut self,
        source_args: &[AstExprId],
        slots: &[Option<AstExprId>],
        params: &[Ty],
        elem_prim: Option<Ty>,
    ) -> Option<Vec<u32>> {
        if slots.len() != params.len() {
            return None;
        }
        let mut arg_slots = Vec::with_capacity(source_args.len());
        for &arg in source_args {
            let slot = slots.iter().position(|slot| *slot == Some(arg))?;
            arg_slots.push(slot);
        }
        let reordered = arg_slots.windows(2).any(|w| w[0] > w[1]);
        if reordered
            && source_args.iter().any(|&arg| {
                !is_const_literal(self.afile, arg) && !matches!(self.afile.expr(arg), Expr::Name(_))
            })
        {
            return None;
        }
        let mut lowered = Vec::with_capacity(slots.len());
        for (i, slot) in slots.iter().enumerate() {
            match slot {
                Some(arg) => {
                    let param = params[i];
                    if param.is_erased_top()
                        && elem_prim.is_some_and(|elem| {
                            let arg_ty = self.info.ty(*arg);
                            self.has_scalar_value_repr(arg_ty) && arg_ty != elem
                        })
                    {
                        let elem = elem_prim?;
                        let value = self.lower_arg(*arg, &ty_to_ir(elem))?;
                        lowered.push(self.emit_type_op(
                            IrTypeOp::ImplicitCoercion,
                            value,
                            ty_to_ir(param),
                        ));
                    } else {
                        lowered.push(self.lower_arg(*arg, &ty_to_ir(param))?);
                    }
                }
                None => lowered.push(self.zero_placeholder(params[i])),
            }
        }
        Some(lowered)
    }

    fn lower_call_slot_args_source_order(
        &mut self,
        source_args: &[AstExprId],
        slots: &[Option<AstExprId>],
        params: &[Ty],
        fill_omitted: bool,
    ) -> Option<(Vec<u32>, Vec<u32>)> {
        if slots.len() != params.len() {
            return None;
        }
        let mut slot_temp: Vec<Option<u32>> = vec![None; params.len()];
        let mut prelude = Vec::new();
        for &arg in source_args {
            let slot_idx = slots.iter().position(|slot| *slot == Some(arg))?;
            if slot_temp[slot_idx].is_some() {
                return None;
            }
            let ir_ty = ty_to_ir(params[slot_idx]);
            let value = self.lower_arg(arg, &ir_ty)?;
            let tmp = self.fresh_value();
            prelude.push(self.emit_variable(tmp, ir_ty, Some(value)));
            slot_temp[slot_idx] = Some(tmp);
        }
        let mut lowered = Vec::with_capacity(params.len());
        for (i, tmp) in slot_temp.into_iter().enumerate() {
            match tmp {
                Some(tmp) => lowered.push(self.emit_get_value(tmp)),
                None if fill_omitted => lowered.push(self.zero_placeholder(params[i])),
                None => return None,
            }
        }
        Some((lowered, prelude))
    }

    fn lower_method_slot_args_source_order(
        &mut self,
        source_args: &[AstExprId],
        slots: &[Option<AstExprId>],
        params: &[Ty],
    ) -> Option<(Vec<Option<u32>>, Vec<u32>)> {
        if slots.len() != params.len() {
            return None;
        }
        let mut slot_temp: Vec<Option<u32>> = vec![None; params.len()];
        let mut prelude = Vec::new();
        for &arg in source_args {
            let slot_idx = slots.iter().position(|slot| *slot == Some(arg))?;
            if slot_temp[slot_idx].is_some() {
                return None;
            }
            let ir_ty = ty_to_ir(params[slot_idx]);
            let value = self.lower_arg(arg, &ir_ty)?;
            let tmp = self.fresh_value();
            prelude.push(self.emit_variable(tmp, ir_ty, Some(value)));
            slot_temp[slot_idx] = Some(tmp);
        }
        let lowered = slots
            .iter()
            .enumerate()
            .map(|(i, slot)| {
                if slot.is_some() {
                    Some(self.emit_get_value(slot_temp[i]?))
                } else {
                    None
                }
            })
            .collect();
        Some((lowered, prelude))
    }

    /// Lower a classpath instance-member call with omitted arguments through the member's `$default`
    /// synthetic, using the checker-recorded argument slots.
    fn lower_library_default_member_call(
        &mut self,
        recv: u32,
        rt: Ty,
        call: AstExprId,
        resolved: &ResolvedMember,
        args: &[AstExprId],
    ) -> Option<u32> {
        let slots = self.info.resolved_call_arg_slots.get(&call).cloned()?;
        if slots.iter().all(Option::is_some) {
            return None;
        }
        let member = &resolved.member;
        // The receiver may be typed nullable at this point; the member/default synthetic lives on the
        // non-null class either way.
        let owner = member
            .owner
            .map(|owner| owner.render())
            .or_else(|| self.class_of(rt).map(|ci| ci.internal()))
            .or_else(|| rt.non_null().obj_internal().map(|n| n.render()))?;
        crate::trace_compiler!(
            "resolve",
            "lower_library_default_member_call {owner}.{} args={} named={}",
            member.name,
            args.len(),
            self.afile.call_arg_names.contains_key(&call.0)
        );
        // An INLINE callee (`Mutex.withLock` with its defaulted `owner`) must NOT route through the
        // `$default` synthetic — kotlinc always splices it; the dedicated inline lowerings
        // (`lower_suspend_withlock`, the splicer) handle it downstream.
        if !matches!(member.inline, crate::libraries::InlineKind::None) {
            return None;
        }
        let logical_ret = resolved.ret;
        let default_target = self.info.resolved_default_member_call(call)?;
        let desc = default_target.descriptor.clone();
        let real = &default_target.real_params;
        let suspend = default_target.suspend;
        // Evaluate the PROVIDED arguments in SOURCE order (each into a temp), then feed them to the
        // `$default` synthetic in PARAMETER order — kotlinc's evaluation-order semantics for a named
        // call whose labels don't follow declaration order (`copy(createdAt = now(), status = P)`),
        // where a side-effecting argument must not be reordered past a later one.
        let (slot_args, prelude) =
            self.lower_call_slot_args_source_order(args, &slots, real, true)?;
        let mut a = vec![recv];
        a.extend(slot_args);
        let mask: i32 = slots
            .iter()
            .enumerate()
            .filter(|(_, s)| s.is_none())
            .map(|(i, _)| 1i32 << i)
            .sum();
        self.append_default_mask_marker(&mut a, mask);
        let call = self.emit_static_call(
            owner,
            format!("{}$default", member.name),
            desc,
            InlineKind::None,
            a,
        );
        if suspend {
            self.ir.suspend_calls.insert(call, ty_to_ir(logical_ret));
        }
        // No reordering happened without a prelude — return the call directly. Otherwise the temps
        // must be declared before the call (a `Block` whose value is the call).
        if prelude.is_empty() {
            Some(call)
        } else {
            Some(self.emit_block(prelude, Some(call)))
        }
    }

    /// Lower a checker-resolved local function call. Local functions are lifted to private static IR
    /// functions; captures and implicit context parameters become leading arguments.
    fn lower_local_function_call(
        &mut self,
        target: &ResolvedLocalFunctionCall,
        args: &[AstExprId],
    ) -> Option<u32> {
        if args.len() != target.provided_arg_count {
            return None;
        }
        let stmt_id = target.stmt_id;
        let fid = *self.local_fun_ids.get(&stmt_id)?;
        let params = self.ir.functions[fid as usize].params.clone();
        let local_fun = self.info.local_fun(stmt_id)?;
        let ncap = local_fun.captures.len();
        let ctx_n = target.context_args.len();
        if ncap + target.sig.params.len() != params.len()
            || args.len() + ctx_n > target.sig.params.len()
        {
            return None;
        }

        let mut lowered = Vec::new();
        for cap in &local_fun.captures {
            let (cv, _) = self.lookup(&cap.name)?;
            lowered.push(self.emit_get_value(cv));
        }
        for src in &target.context_args {
            let (v, _) = self.lookup(src)?;
            lowered.push(self.emit_get_value(v));
        }
        for (arg, pt) in args.iter().zip(&params[ncap + ctx_n..]) {
            lowered.push(self.lower_arg(*arg, pt)?);
        }
        if lowered.len() < params.len() {
            let crate::ast::Stmt::LocalFun(f) = self.afile.stmt(stmt_id) else {
                return None;
            };
            for (i, pt) in params[lowered.len()..].iter().enumerate() {
                let fp = f.params.get(ctx_n + args.len() + i)?;
                let def = fp.default?;
                lowered.push(self.lower_arg(def, pt)?);
            }
        }
        Some(self.emit_local_call(fid, lowered))
    }

    /// Lower a CALL `recv.name(args)` that resolves to a top-level EXTENSION function on `rt` — the
    /// shared path behind a qualified `recv.name(args)` and a receiver-lambda / extension-fn body's
    /// implicit `this.name(args)` (`"ab".run { uppercase() }`, `fun String.shout() = uppercase()`).
    /// `recv_ir` is the already-lowered receiver value. Tries a public library extension first
    /// (`invokestatic facade.name(recv, args)`), then a private `@InlineOnly` extension whose real body
    /// the backend splices (`String.uppercase()` → `toUpperCase(Locale.ROOT)`). `None` when neither
    /// resolves. No stdlib name is hardcoded — owner/descriptor come from the library reader.
    /// Resolve a classpath extension `recv.name(args)`, retrying once with integer-LITERAL `Int`
    /// arguments widened to `Long` — Kotlin adapts an integer literal to a wider expected type, so
    /// `longRange step 3` resolves `LongProgression.step(Long)`. A non-literal `Int` is left as-is
    /// (kotlinc rejects `longRange step intVar`). Mirrors the checker's classpath-extension adaptation.
    /// The reified-type substitution to record for a spliceable classpath extension call: pair the
    /// callee's generic type-parameter NAMES (from its `Signature`) with the call's explicit type
    /// ARGUMENTS (`getFor<Prov>` → `[("T", Prov)]`). Empty unless the callee is inline (its body is
    /// spliced) and the call supplies type arguments — so a `<reified T>` extension whose compiled body
    /// carries `reifiedOperationMarker`/`T::class` specializes to the concrete type at the splice.
    fn reified_call_subst_for(
        &self,
        ast_call: AstExprId,
        c: &crate::libraries::LibraryCallable,
        recv_ty: Option<Ty>,
    ) -> Vec<(String, Ty)> {
        if !c.inline.can_inline() {
            return Vec::new();
        }
        let formals = c
            .signature
            .as_deref()
            .map(|s| self.syms.libraries.signature_formal_names(s))
            .unwrap_or_default();
        // The type ARGUMENTS come pre-resolved from the checker (`resolved_call_type_args`) — the checker
        // resolves imports/classpath types the lowerer's local `ty_ref` can't (a wildcard-imported class).
        if let Some(targs) = self.info.resolved_call_type_args.get(&ast_call) {
            return formals
                .iter()
                .zip(targs)
                .map(|(name, ty)| (name.clone(), *ty))
                .collect();
        }
        // No EXPLICIT type arguments: a reified `T` that appears in the RECEIVER position
        // (`Collection<T>.toTypedArray()`, `T` inferred from the receiver `List<Int>`) is bound by the
        // receiver's type arguments — pair the reified formals with them positionally.
        // Guarded to an EXACT count match (`Collection<T>` = 1 formal ↔ 1 receiver type-arg) so a receiver
        // whose type-parameter arity differs from the reified formals can't mis-bind — a positional pairing
        // is only sound when they align.
        if let Some(Ty::Obj(_, args)) = recv_ty.map(|t| t.non_null()) {
            if !formals.is_empty() && formals.len() == args.len() {
                return formals
                    .iter()
                    .zip(args.iter())
                    .map(|(name, ty)| (name.clone(), *ty))
                    .collect();
            }
        }
        Vec::new()
    }

    fn lower_ext_call_on(
        &mut self,
        recv_ir: u32,
        rt: Ty,
        _name: &str,
        args: &[AstExprId],
        e: AstExprId,
    ) -> Option<u32> {
        // The CHECKER resolved this extension and recorded the callable (keyed by the call `ExprId`).
        let c = self.info.resolved_extension(e).cloned()?;
        // The first parameter is the extension receiver. Box a primitive receiver flowing into a generic
        // `Object` receiver param; a reference receiver widens to its declared param type for free.
        let p0 = *c.params.first().unwrap_or(&rt);
        let recv = if self.has_scalar_value_repr(rt) && p0.is_reference() {
            self.coerce_to_static(recv_ir, rt, p0)
        } else {
            recv_ir
        };
        let source_receiver = c.source_receiver;
        let mut a = vec![recv];
        let explicit_params = c.params.get(1..)?;
        if let Some(slots) = self.info.resolved_call_arg_slots.get(&e).cloned() {
            let slot_args = self.lower_call_slot_args(args, &slots, explicit_params)?;
            if c.default_call {
                let mask: i32 = slots
                    .iter()
                    .enumerate()
                    .filter(|(_, slot)| slot.is_none())
                    .map(|(i, _)| 1i32 << i)
                    .sum();
                a.extend(slot_args);
                self.append_default_mask_marker(&mut a, mask);
            } else {
                if slots.iter().any(Option::is_none) {
                    return None;
                }
                a.extend(slot_args);
            }
        } else {
            if c.default_call {
                return None;
            }
            for (i, &arg) in args.iter().enumerate() {
                match explicit_params.get(i) {
                    Some(p) => a.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                    None => a.push(self.expr(arg)?),
                }
            }
        }
        // For a `<reified T>` extension the backend must SPLICE (its compiled body carries a
        // `reifiedOperationMarker`/`T::class` the JVM can't call directly): bind the callee's reified
        // type-parameter NAMES to the call's explicit type arguments, or — when omitted — to the RECEIVER's
        // type arguments (`Collection<T>.toTypedArray()` infers `T` from the receiver) so the splicer
        // specializes the body.
        let reified_subst = self.reified_call_subst_for(e, &c, Some(rt));
        let physical_ret = c.physical_ret;
        let suspend_default = c.default_call && c.suspend;
        let call = self.emit_library_static_call(c, a, suspend_default);
        if !reified_subst.is_empty() {
            self.ir.reified_call_subst.insert(call, reified_subst);
        }
        self.record_ext_source_receiver(call, source_receiver);
        Some(self.coerce_erased_call_result(e, call, &physical_ret, true))
    }

    /// Lower an unqualified CALL `name(args)` against the implicit `this` receiver — the body of a
    /// receiver lambda (`"ab".run { uppercase() }`) or an extension function (`fun String.f() =
    /// uppercase()`), where `cur_class` is cleared and the `this` slot holds the external receiver. The
    /// implicit receiver takes priority over a receiver-less top-level function (Kotlin scoping), so
    /// this runs first. Tries, in order: a user instance method, a builtin/library member, then a stdlib
    /// extension. `None` when none match (the call falls through to top-level resolution).
    /// Lower call arguments, packing a trailing `vararg` parameter (`fun f(vararg s: T)` called
    /// `f(a, b)`): the fixed args lower against their params, the remaining become the elements of a
    /// fresh array of the vararg param's type — unless a lone argument already OF that array type is
    /// passed through (a spread). A non-`vararg` call lowers positionally (identical to `lower_args`).
    fn lower_call_args_vararg(
        &mut self,
        args: &[AstExprId],
        params: &[Ty],
        vararg: bool,
        n_fixed: usize,
    ) -> Option<Vec<u32>> {
        if !vararg {
            return self.lower_args(args, params);
        }
        let array_param = params[n_fixed];
        let mut out = Vec::with_capacity(n_fixed + 1);
        for i in 0..n_fixed {
            out.push(self.lower_arg(args[i], &params[i])?);
        }
        let trailing = &args[n_fixed..];
        if trailing.len() == 1 && self.info.ty(trailing[0]) == array_param {
            out.push(self.lower_arg(trailing[0], &array_param)?); // a spread / pass-through
        } else {
            let elem = array_param.array_elem().unwrap_or(array_param);
            let mut elements = Vec::with_capacity(trailing.len());
            for &arg in trailing {
                elements.push(self.lower_arg(arg, &elem)?);
            }
            out.push(self.emit_vararg(array_param, elements));
        }
        Some(out)
    }

    /// Lower an implicit-receiver user instance-method call that OMITS one or more CONSTANT-default
    /// arguments (`resolveRoles(subjectId)` where `resolveRoles(id, filter = null)`). Map the provided
    /// args (positional or named) onto their slots, fill each omitted slot with its registered constant
    /// default, and build a plain `MethodCall` on `this` — semantically identical to kotlinc's `$default`
    /// dispatch for a constant default (it passes the same value), and the same fill the explicit-receiver
    /// and extension paths use. `None` (caller falls through / skips) when a name doesn't map, a slot is
    /// double-filled, or an omitted slot's default is non-constant (that needs the `$default` synthetic).
    /// Whether a method resolved by NAME (`resolve_method`, which does no overload disambiguation) is the
    /// one the checker actually selected for call `e` — judged by return type. Lenient: only rejects when
    /// BOTH types are concrete and clearly differ (a genuine wrong-overload pick, e.g. `Boolean` vs `Int`);
    /// an erased / type-variable / mixed return can't be told apart here, so it is allowed (the per-arg
    /// `lower_arg` type-checks remain the backstop). Used to gate the omitted-constant-default fill so an
    /// overloaded method never fills the wrong overload's defaults (which would silently miscompile).
    fn member_ret_matches_call(&self, resolved_ret: &Ty, e: AstExprId) -> bool {
        let call_ty = self.info.ty(e);
        let (a, b) = (resolved_ret.non_null(), call_ty.non_null());
        match (a.obj_internal(), b.obj_internal()) {
            (Some(ai), Some(bi)) => ai == bi,
            (None, None) => a == b,
            _ => true,
        }
    }

    fn lower_this_member_default_call(
        &mut self,
        this_v: u32,
        class: ClassId,
        index: u32,
        mfid: u32,
        call: AstExprId,
        args: &[AstExprId],
    ) -> Option<u32> {
        let params = self.ir.functions[mfid as usize].params.clone();
        let info = self.ir.fn_params.get(&mfid)?;
        let defaults = info.defaults.clone()?;
        let names = info.names.clone();
        let n = params.len();
        if names.len() != n || args.len() >= n {
            return None;
        }
        let arg_names = self.afile.call_arg_names.get(&call.0).cloned();
        let mut slot: Vec<Option<u32>> = vec![None; n];
        let mut pos = 0usize;
        for (ai, arg) in args.iter().enumerate() {
            let nm = arg_names
                .as_ref()
                .and_then(|v| v.get(ai).cloned().flatten());
            let p = match nm {
                Some(s) => names.iter().position(|f| *f == s)?,
                None => {
                    let p = pos;
                    pos += 1;
                    p
                }
            };
            if p >= n || slot[p].is_some() {
                return None;
            }
            slot[p] = Some(self.lower_arg(*arg, &params[p])?);
        }
        let recv = self.emit_get_value(this_v);
        let mut a: Vec<Option<u32>> = Vec::with_capacity(n);
        for (k, s) in slot.iter().enumerate() {
            let v = match s {
                Some(v) => *v,
                // A constant default — clone it as a fresh node (avoid aliasing). A non-constant default
                // isn't fillable at the call site here (needs `$default`) → skip the file.
                None => match defaults
                    .get(k)
                    .and_then(|d| *d)
                    .map(|d| self.ir.exprs[d as usize].clone())
                {
                    Some(IrExpr::Const(c)) => self.emit_const(c),
                    _ => return None,
                },
            };
            a.push(Some(v));
        }
        Some(self.emit_method_call(class, index, recv, a))
    }

    fn lower_this_member_call(
        &mut self,
        this_v: u32,
        this_ty: Ty,
        name: &str,
        args: &[AstExprId],
        e: AstExprId,
    ) -> Option<u32> {
        // A user instance method on the receiver's class — `this.m(args)`.
        if let Some(internal) = this_ty.obj_internal() {
            // Arity-aware resolution first — with overloads split across the hierarchy the plain
            // name walk stops at the most-derived rung and can return a sibling of the wrong arity
            // (`Derived.f(Int)` for a `f()` call). Fall back to the name walk for its extra
            // fallbacks (interface defaults) and for the omitted-default-argument shape, where the
            // call's arg count is legitimately below the method's arity.
            if let Some((class, index, mfid, ret)) = self
                .resolve_method_by_arity(internal, name, args.len())
                .or_else(|| self.resolve_method_name(internal, name))
            {
                let params = self.ir.functions[mfid as usize].params.clone();
                let vararg = self.syms.method_is_vararg_name(internal, name);
                if let Some(n_fixed) = vararg_arity(vararg, params.len(), args.len()) {
                    let recv = self.emit_get_value(this_v);
                    let a = self.lower_call_args_vararg(args, &params, vararg, n_fixed)?;
                    return Some(self.emit_method_call(
                        class,
                        index,
                        recv,
                        a.into_iter().map(Some).collect(),
                    ));
                }
                // An implicit-receiver member call OMITTING one or more CONSTANT-default arguments
                // (`resolveRoles(subjectId)` on `resolveRoles(id, filter = null)`): fill the omitted slots
                // with their constant defaults and call the plain method — the same call-site fill the
                // explicit-receiver (`recv.m(…)`) and extension paths already use. A non-constant default
                // needs the `$default` synthetic (not modeled here) → `None`, so the file skips.
                //
                // `resolve_method` selects by NAME only (no arg-type disambiguation), so with OVERLOADS it
                // may pick the wrong one and fill the wrong defaults. Guard by requiring the resolved
                // method's return type to match the checker's (correctly overload-resolved) call type —
                // a mismatch means the wrong overload, so bail (skip the file) rather than miscompile.
                if args.len() < params.len() && !vararg && self.member_ret_matches_call(&ret, e) {
                    if let Some(v) =
                        self.lower_this_member_default_call(this_v, class, index, mfid, e, args)
                    {
                        return Some(v);
                    }
                }
            }
        }
        if matches!(name, "toString" | "hashCode") && args.is_empty() {
            let recv = self.emit_get_value(this_v);
            return Some(self.emit_external_call(format!("kotlin/Any.{name}"), Some(recv), vec![]));
        }
        if let Some(resolved) = self.info.resolved_member(e).cloned() {
            let recv = self.emit_get_value(this_v);
            if let Some(r) =
                self.lower_library_default_member_call(recv, this_ty, e, &resolved, args)
            {
                return Some(r);
            }
            let ret = resolved.ret;
            let member = resolved.member;
            let a = if let Some(slots) = self.info.resolved_call_arg_slots.get(&e).cloned() {
                if slots.iter().any(Option::is_none) {
                    return None;
                }
                self.lower_call_slot_args(args, &slots, &member.params)?
            } else {
                if args.len() < member.params.len()
                    && member
                        .params
                        .last()
                        .is_none_or(|p| p.array_elem().is_none())
                {
                    return None;
                }
                let mut lowered = Vec::new();
                for (i, &arg) in args.iter().enumerate() {
                    match member.params.get(i) {
                        Some(p) => lowered.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                        None => lowered.push(self.expr(arg)?),
                    }
                }
                lowered
            };
            let owner = member
                .owner
                .or_else(|| this_ty.obj_internal())
                .unwrap_or_else(crate::types::wk::any);
            let physical_ret = member.physical_ret;
            let call = self.emit_library_member_call(recv, owner, member, ret, false, a);
            return Some(self.coerce_generic_read(call, e, physical_ret));
        }
        // A MODULE extension on the receiver (`fun Recv.name(args)` declared in this compilation) —
        // `invokestatic <facade>.name(this, args)` (the receiver is the first parameter of the lowered
        // static impl). Mirrors a qualified `recv.name(args)` module-extension call. Prefer the overload
        // whose arity matches the call (`fun R.f()` vs `fun R.f(x)`), else the primary id.
        if let Some(&fid) = self
            .ext_fun_id_by_arity
            .get(&(this_ty.erased_recv(), name.to_string(), args.len()))
            .or_else(|| {
                self.ext_fun_ids
                    .get(&(this_ty.erased_recv(), name.to_string()))
            })
        {
            let params = self.ir.functions[fid as usize].params.clone();
            if params.len() == args.len() + 1 {
                let recv = self.emit_get_value(this_v);
                let mut a = vec![recv];
                for (arg, pt) in args.iter().zip(&params[1..]) {
                    a.push(self.lower_arg(*arg, pt)?);
                }
                return Some(self.emit_local_call(fid, a));
            }
        }
        // A stdlib/library EXTENSION on the receiver (`uppercase`/`reversed`).
        let recv = self.emit_get_value(this_v);
        self.lower_ext_call_on(recv, this_ty, name, args, e)
    }

    /// Inline a receiver-lambda scope call the checker resolved (`x.run { … }`, `x.apply { … }`,
    /// `with(x) { … }`): evaluate the receiver into a fresh slot bound as `this`, lower the lambda body
    /// against it, then yield the body value (`run`/`with`) or the receiver (`apply`/`also`). The
    /// receiver lambda runs in the caller, so `cur_class` is cleared — its members are reached through
    /// the implicit-`this` paths (member/getter/extension), never the enclosing class's private fields.
    fn lower_receiver_lambda(&mut self, rl: ReceiverLambda) -> Option<u32> {
        let rty = self.info.ty(rl.receiver);
        let recv = self.expr(rl.receiver)?;
        let depth = self.scope.len();
        let p_slot = self.fresh_value();
        let saved_cur = self.cur_class;
        self.cur_class = None;
        self.scope.push(("this".to_string(), p_slot, rty));
        let var_p = self.emit_variable(p_slot, ty_to_ir(rty), Some(recv));
        let body_val = self.expr(rl.body);
        self.scope.truncate(depth);
        self.cur_class = saved_cur;
        let body_val = body_val?;
        let result = if rl.returns_receiver {
            let recv_read = self.emit_get_value(p_slot);
            self.emit_block(vec![var_p, body_val], Some(recv_read))
        } else {
            self.emit_block(vec![var_p], Some(body_val))
        };
        Some(result)
    }

    /// Inline a scope function over an ALREADY-LOWERED receiver value (`recv_val`) — the shared core for
    /// a safe-call scope fn (`s?.let { … }`). Binds `recv_val` to a fresh slot named `pname` (`it` for
    /// `let`/`also`, `this` for `run`/`apply` — which also clears `cur_class`), lowers the body, and
    /// yields the body value or the receiver (`returns_receiver`). Returns the inlined block value.
    fn lower_scope_inline_on(
        &mut self,
        recv_val: u32,
        rty: Ty,
        pname: &str,
        body: AstExprId,
        returns_receiver: bool,
    ) -> Option<u32> {
        // A nullable-primitive receiver from a chained `…?.let { … }` binds the scope param as the
        // unboxed primitive — matching the checker, so `it + 1` is primitive math.
        let (rty, recv_val) = match rty.nullable_primitive() {
            Some(prim) => {
                let unboxed =
                    self.emit_type_op(IrTypeOp::ImplicitCoercion, recv_val, ty_to_ir(prim));
                (prim, unboxed)
            }
            None => (rty, recv_val),
        };
        let depth = self.scope.len();
        let p_slot = self.fresh_value();
        let saved_cur = self.cur_class;
        if pname == "this" {
            self.cur_class = None;
        }
        self.scope.push((pname.to_string(), p_slot, rty));
        // NAMED: the scope-fn binding (`it`/`this`) is a real source binding — kotlinc's spliced
        // scope fn keeps it as a named LVT local, in scope (and spilled) at suspensions inside.
        let var_p = self.emit_named_variable(p_slot, ty_to_ir(rty), Some(recv_val));
        let body_val = self.expr(body);
        self.scope.truncate(depth);
        self.cur_class = saved_cur;
        let body_val = body_val?;
        // A receiver-returning scope fn (`also`/`apply`) whose body DIVERGES (non-local `return`/`throw`,
        // body typed `Nothing`): the trailing "read the receiver back" is unreachable. Emitting it leaves
        // dead code after the divergence (a stray value load with no stackmap frame → `VerifyError`), so
        // drop it and let the divergent body be the block value — identical to the non-receiver form.
        let body_diverges = self.info.ty(body) == Ty::Nothing;
        Some(if returns_receiver && !body_diverges {
            let recv_read = self.emit_get_value(p_slot);
            self.emit_block(vec![var_p, body_val], Some(recv_read))
        } else {
            self.emit_block(vec![var_p], Some(body_val))
        })
    }

    /// The non-null-branch value of a safe-call scope function (`s?.let`/`?.run`/`?.also`/`?.apply`):
    /// inline the scope fn with `recv_val` (the non-null receiver) bound. `None` when `name`/args aren't
    /// a recognized lambda-bearing scope call (the caller falls back to the member-access path).
    fn lower_safe_scope_member(
        &mut self,
        recv_val: u32,
        rty: Ty,
        name: &str,
        args: &Option<Vec<AstExprId>>,
    ) -> Option<u32> {
        let [arg] = args.as_deref()? else {
            return None;
        };
        let (params, body) = self.synth_arg_lambda(*arg)?;
        let (pname, returns_receiver) = match name {
            "let" => (ast::first_lambda_param_or_it(&params), false),
            "also" => (ast::first_lambda_param_or_it(&params), true),
            "run" if params.is_empty() => ("this".to_string(), false),
            "apply" if params.is_empty() => ("this".to_string(), true),
            _ => return None,
        };
        self.lower_scope_inline_on(recv_val, rty, &pname, body, returns_receiver)
    }

    /// A field's declared type: `ty_of` (file-local classes + built-ins), falling back to the
    /// classpath-aware [`ty_ref`] when `ty_of` erases a CLASSPATH reference type to `Any` (it doesn't
    /// consult imports). Keeps the field decl, constructor parameter and getter agreeing on the real type.
    fn field_ty(&self, file: &ast::File, r: &ast::TypeRef) -> Ty {
        let base = ty_of(file, r, &*self.syms.libraries);
        // A property of type `Unit` holds the `kotlin/Unit` singleton (its value), so its field, ctor
        // parameter, and getter return are the `kotlin/Unit` REFERENCE — not the 0-word `Ty::Unit` whose
        // descriptor `V` is illegal for a field/parameter. (Only a `Unit` *return position* erases to void.)
        let base = stored_value_ty(base);
        if base.is_erased_top() {
            // Resolve the NON-nullable form (`ty_ref` bails on a nullable type); the caller re-applies
            // the field's nullability to the IrType, so `Uuid` and `Uuid?` recover the same base type.
            if let Some(rt) = self.classpath_ty_ref(r) {
                return rt;
            }
        }
        base
    }

    /// An extension function RECEIVER type: `ty_of` (file-local + built-ins, e.g. `String`), falling back
    /// to the classpath-aware [`ty_ref`] when `ty_of` can't resolve it (a classpath type like
    /// `kotlinx...SerialDescriptor` — `ty_of` yields `Error`/`Any` since it doesn't consult imports). The
    /// registration and body-lowering of the extension must agree with the checker's receiver descriptor.
    fn ext_receiver_ty(&self, file: &ast::File, r: &ast::TypeRef) -> Ty {
        let base = ty_of(file, r, &*self.syms.libraries);
        if base == Ty::Error || base.is_erased_top() {
            if let Some(rt) = self.classpath_ty_ref(r) {
                return rt;
            }
        }
        base
    }

    fn classpath_ty_ref(&self, r: &ast::TypeRef) -> Option<Ty> {
        let nn = ast::TypeRef {
            nullable: false,
            ..r.clone()
        };
        self.ty_ref(&nn)
            .filter(|t| *t != Ty::Error && !t.is_erased_top())
    }

    fn type_exists(&self, internal: &str) -> bool {
        self.syms.class_by_internal(internal).is_some()
            || self.syms.libraries.resolve_type(internal).is_some()
    }

    /// Resolve a dotted nested type/qualifier (`Subject.User` → `lib/Subject$User`) — the
    /// lowerer's mirror of the checker's `resolve_qualified_nested`. The longest simple-name prefix that
    /// maps to a known internal names the outer type; remaining segments join with `$`. Existence is
    /// verified against module symbols and libraries so a bogus `A.B` stays unresolved.
    fn resolve_qualified_nested(&self, name: &str) -> Option<String> {
        // A nested type under a resolvable outer type FIRST (`Subject.User` → `lib/Subject$User`), matching
        // the checker — an in-scope type name shadows a package path.
        if let Some((outer, rest)) = name.split_once('.') {
            let base = self
                .syms
                .classes
                .get(outer)
                .map(|c| c.internal())
                .or_else(|| {
                    self.syms
                        .class_names
                        .get(outer)
                        .filter(|i| !i.starts_with("__ty/"))
                        .map(TypeName::render)
                })
                // A name PRUNED from the global index (ambiguous across the classpath) still resolves
                // through this file's explicit import — the same fallback the checker's
                // `imported_type_internal` gives, so checker and lowerer agree. (`import a.b.Subject`.)
                .or_else(|| {
                    self.afile.imports.iter().find_map(|imp| {
                        let cand = imp.replace('.', "/");
                        (imp.rsplit('.').next() == Some(outer) && self.type_exists(&cand))
                            .then_some(cand)
                    })
                })
                // The file's OWN package is an implicit wildcard — a same-package classpath type used
                // UNQUALIFIED (`is V.Ok` where `V` is a classpath type in this file's package) resolves as
                // `<pkg>/V`, matching the checker's implicit-same-package-wildcard resolution.
                .or_else(|| {
                    let pkg = self.afile.package.as_deref()?;
                    let cand = format!("{}/{outer}", pkg.replace('.', "/"));
                    self.type_exists(&cand).then_some(cand)
                });
            if let Some(base) = base {
                let candidate = format!("{base}${}", rest.replace('.', "$"));
                if self.type_exists(&candidate) {
                    return Some(candidate);
                }
            }
        }
        // A fully-qualified PACKAGE path (`lib.Thing` → `lib/Thing`) — verified on the classpath. Mirrors
        // the checker so a qualified constructor / type ref lowers to the same internal name.
        let fq = name.replace('.', "/");
        if self.type_exists(&fq) {
            return Some(fq);
        }
        // An unqualified same-package classpath type (`Thing` in this file's package) → `<pkg>/Thing`.
        let pkg = self.afile.package.as_deref()?;
        let cand = format!("{}/{}", pkg.replace('.', "/"), name.replace('.', "$"));
        self.type_exists(&cand).then_some(cand)
    }

    fn ty_ref(&self, r: &ast::TypeRef) -> Option<Ty> {
        // A reified type parameter (inside an expanded `<reified T>` inline body) resolves to the type
        // bound at the call site — `Array<T>`, `val x: T`, a return `T`, etc. all specialize. The bound
        // type is already concrete (built through `subst_type_ref`), so this recurses at most once.
        if !self.reified_subst.is_empty() {
            let s = self.subst_type_ref(r);
            if s.name != r.name {
                return self.ty_ref(&s);
            }
        }
        if r.nullable {
            return None;
        }
        // `Unit` as a type is the reference class `kotlin/Unit` (a cast target / checkcast operand),
        // not the `Ty::Unit` control-flow marker (which isn't a reference).
        if r.name == "Unit" {
            return Some(Ty::obj("kotlin/Unit"));
        }
        // A function type — the arrow form `(A) -> B` (parser name `<fun>`, params in `fun_params`) or
        // the named `FunctionN<…>` form. Both test/cast against `kotlin/jvm/functions/FunctionN`, whose
        // identity depends only on the arity (param/return types are erased for `instanceof`/`checkcast`),
        // so build a `Ty::Fun` of the right arity with erased `Any` slots.
        if (r.name == "<fun>" || !r.fun_params.is_empty()) && r.fun_params.len() <= 22 {
            let params = vec![Ty::obj("kotlin/Any"); r.fun_params.len()];
            return Some(Ty::fun(params, Ty::obj("kotlin/Any")));
        }
        if let Some(suffix) = r.name.strip_prefix("Function") {
            if let Ok(arity) = suffix.parse::<usize>() {
                // Match the checker's `typeref_leaf`: only `Function0..Function22` map to an ordinary
                // `FunctionN` interface (higher arities are the big-arity `FunctionN`, left unresolved).
                if arity <= 22 && r.targs.len() == arity + 1 {
                    let params = vec![Ty::obj("kotlin/Any"); arity];
                    return Some(Ty::fun(params, Ty::obj("kotlin/Any")));
                }
            }
        }
        let t = if let Some(p) = Ty::from_name(&r.name) {
            p
        } else if let Some(elem) = Ty::primitive_array_element(&r.name) {
            // `IntArray`/`CharArray`/… → the primitive array type (`int[]`/…), NOT a same-named classpath
            // class — resolve it here, before the `class_names` fallback, exactly as `resolve_ty` does
            // (the JDK ships an unrelated `sun.jvm.hotspot.utilities.IntArray`).
            Ty::array(elem)
        } else if r.name == "Array" {
            let e = r.arg.as_ref().and_then(|a| self.ty_ref(a))?;
            if !e.is_reference() {
                return None;
            }
            Ty::array(e)
        } else if self.contains_class(&r.name) {
            Ty::obj(&r.name)
        } else if self.contains_class(&class_internal(self.afile, &r.name)) {
            // A nested class by source name (`Outer.Inner` → `Outer$Inner`).
            Ty::obj(&class_internal(self.afile, &r.name))
        } else if let Some(cs) = self.syms.classes.get(&r.name) {
            Ty::obj(&cs.internal())
        } else if let Some(internal) = self.syms.class_names.get(&r.name) {
            // A classpath / built-in mapped type (`Number`, `CharSequence`, `Runnable`, a Java class) —
            // the same name→internal map the checker resolves `is`/`as` targets against. `"__ty/<prim>"`
            // is an alias to a primitive, which `is`/`as` here doesn't model (skip).
            if internal.starts_with("__ty/") {
                return None;
            }
            Ty::obj_name(internal)
        } else if let Some(internal) = self.resolve_qualified_nested(&r.name) {
            // A dotted CLASSPATH nested type (`Subject.User`) → `Outer$Nested`, matching the checker's
            // `resolve_ty` — so an `is`/`as` target on such a type resolves the same internal name.
            Ty::obj(&internal)
        } else if let Some(internal) = self
            .cur_class
            .as_ref()
            .map(|c| format!("{c}${}", r.name))
            .filter(|n| self.contains_class(n))
        {
            // A sibling nested type unqualified within the enclosing class body (`is Inner`/`as Inner` /
            // `Inner` type in `class Outer { class Inner }`) → `Outer$Inner`, matching the checker's
            // nested-type scoping (`resolve_ty`/`resolve_ty_no_diag`).
            Ty::obj(&internal)
        } else {
            return None;
        };
        if t.is_reference() {
            Some(t)
        } else {
            None
        }
    }

    /// Run `f` with `shared_cell_vars` seeded from `root`'s captured-and-mutated `var`s, restoring the
    /// previous set afterward. The constructor lowers property initializers / `init` blocks outside any
    /// `lower_body`, so each must seed the set the same way a function body does — this is that one place.
    fn with_init_shared_cells<T>(&mut self, root: AstExprId, f: impl FnOnce(&mut Self) -> T) -> T {
        let saved = std::mem::replace(
            &mut self.shared_cell_vars,
            shared_cell_vars_for_expr(self.afile, root, self.info),
        );
        let r = f(self);
        self.shared_cell_vars = saved;
        r
    }

    fn lower_body(&mut self, body: &FunBody, ret_ty: &Ty, fid: u32) -> Option<()> {
        // A `break`/`continue` used in a NON-tail expression position (`x + break`, a loop condition)
        // jumps with operand-stack values the emitter doesn't clear — decline the body (skip, never
        // miscompile). The common tail forms (an elvis RHS, a `when` arm) compile.
        if let FunBody::Expr(be) | FunBody::Block(be) = body {
            if !break_continue_tail_only(self.afile, *be, true) {
                self.set_bail("break/continue in non-tail expression position");
                return None;
            }
        }
        let prev_shared_cell_vars = std::mem::replace(
            &mut self.shared_cell_vars,
            shared_cell_vars_for_body(self.afile, body, self.info),
        );
        let prev_closure_captured = std::mem::replace(
            &mut self.closure_captured_names,
            closure_captured_names_for_body(self.afile, body, self.info),
        );
        self.cur_ret_ty = ret_ty.clone();
        // The function's tail expression: an expression body, a block's trailing value, or the value
        // of a final `return` statement. Tail-position splice gates consult this.
        self.fn_body_tail = match body {
            FunBody::Expr(e) => Some(*e),
            FunBody::Block(blk) => match self.afile.expr(*blk) {
                Expr::Block { stmts, trailing } => trailing.or_else(|| match stmts.last() {
                    Some(&s) => match self.afile.stmt(s) {
                        Stmt::Return(Some(v), None) => Some(*v),
                        _ => None,
                    },
                    None => None,
                }),
                _ => None,
            },
            FunBody::None => None,
        };
        // A named/local function returning `Unit` is a `void` JVM method (only a `() -> Unit` lambda's
        // closure method returns the `Unit` reference) — reset so a nested fun doesn't inherit it.
        self.cur_method_returns_unit_ref = false;
        // Defensive: the stack is push/pop-balanced within a body, but a bail mid-lowering of a previous
        // body must not leak an enclosing `finally` into this one.
        self.try_finally_stack.clear();
        // Local delegated properties are function-scoped — don't leak into the next body.
        self.local_delegated.clear();
        let b = match body {
            FunBody::Expr(e) => {
                let diverges = self.info.ty(*e) == Ty::Nothing;
                let stmts = if *ret_ty == Ty::Unit || diverges {
                    vec![self.expr(*e)?] // Unit, or a diverging expr (it returns/throws on its own — no wrap)
                } else {
                    // Coerce the body to the return type (a generic-erased `Object` return gets the
                    // `checkcast` kotlinc inserts).
                    let ve = self.lower_arg(*e, ret_ty)?;
                    vec![self.emit_return(Some(ve))]
                };
                self.emit_block(stmts, None)
            }
            FunBody::Block(blk) => self.block_as_body(*blk, ret_ty)?,
            FunBody::None => return None,
        };
        self.ir.functions[fid as usize].body = Some(b);
        self.shared_cell_vars = prev_shared_cell_vars;
        self.closure_captured_names = prev_closure_captured;
        Some(())
    }

    fn block_as_body(&mut self, block: AstExprId, ret_ty: &Ty) -> Option<u32> {
        let Expr::Block { stmts, trailing } = self.afile.expr(block).clone() else {
            return None;
        };
        let depth = self.scope.len();
        let mut out = Vec::new();
        let mut diverged = false;
        for s in stmts {
            self.append_stmt(s, &mut out)?;
            if self.stmt_diverges(s) {
                diverged = true;
                break;
            }
        }
        // A block that diverges before its trailing value (`{ …; throw X; <unreachable trailing> }`)
        // needs no `return` — the diverging statement already transfers control; the trailing is dead.
        if diverged {
            self.scope.truncate(depth);
            return Some(self.emit_block(out, None));
        }
        if let Some(t) = trailing {
            let tt = self.info.ty(t);
            let diverges = tt == Ty::Nothing;
            // A value-less statement (e.g. a no-`else` `when`) can only be a value-returning
            // function's body if it's exhaustive (hence diverging). krusty doesn't prove
            // exhaustiveness, so bail rather than emit `return <no-value>`.
            if *ret_ty != Ty::Unit && !diverges && tt == Ty::Unit {
                self.scope.truncate(depth);
                return None;
            }
            // In a `tailrec` body the trailing expr is in TAIL position: a self-call there must become
            // update+continue (via `lower_tail_expr`), not plain (stack-overflowing) recursion — and a
            // NON-tail self-call there makes `lower_tail_expr` bail, so the file is skipped rather than
            // miscompiled. (`block_as_body` also lowers ordinary non-`tailrec` block bodies — those keep
            // the plain return path below.)
            if self.cur_tailrec.is_some() && *ret_ty != Ty::Unit {
                let tail = self.lower_tail_expr(t, ret_ty)?;
                out.push(tail);
                self.scope.truncate(depth);
                return Some(self.emit_block(out, None));
            }
            let ve = self.expr(t)?;
            if *ret_ty == Ty::Unit || diverges {
                out.push(ve); // Unit trailing, or a diverging one (returns/throws itself — no wrap)
            } else {
                out.push(self.emit_return(Some(ve)));
            }
        }
        self.scope.truncate(depth);
        Some(self.emit_block(out, None))
    }

    /// Lower a `tailrec fun` body: rewrite tail-position self-calls into a `while(true)` loop (reassign
    /// the param slots, then `continue`). Bails (skip file) if a self-call appears in a non-tail position
    /// the transform can't handle — never miscompiles into stack-overflowing recursion.
    fn lower_tailrec_body(
        &mut self,
        f: &ast::FunDecl,
        ret_ty: &Ty,
        fid: u32,
        param_vals: Vec<u32>,
        param_tys: Vec<Ty>,
    ) -> Option<()> {
        self.cur_ret_ty = ret_ty.clone();
        self.fn_body_tail = None; // the tailrec loop transform owns tail positions here
        self.cur_method_returns_unit_ref = false;
        self.try_finally_stack.clear();
        self.local_delegated.clear();
        let label = "$tailrec".to_string();
        self.cur_tailrec = Some(TailrecCtx {
            name: f.name.clone(),
            param_vals,
            param_tys,
            label: label.clone(),
        });
        // A `try`/`finally` in a `tailrec` body isn't soundly loop-transformable (a tail call in a
        // `finally` can't be optimized — kotlinc rejects it too), and krusty's try-with-return codegen
        // would miscompile under the transform — skip the file rather than emit bad bytecode.
        let has_try = match &f.body {
            FunBody::Block(b) | FunBody::Expr(b) => body_has_try(self.afile, *b),
            FunBody::None => false,
        };
        if has_try {
            self.cur_tailrec = None;
            return None;
        }
        let unit = *ret_ty == Ty::Unit;
        let loop_body = match &f.body {
            // A `Unit` body recurses with a bare expression STATEMENT (`if (c) f(args)`), not
            // `return f(args)` — handled by a tail-statement walk (`lower_tail_unit`); a value body uses
            // the return-driven transform (`lower_tail_expr` for an expr body, `block_as_body` +
            // `Stmt::Return` interception for a block body).
            FunBody::Block(blk) if unit => self.lower_tail_unit(*blk),
            FunBody::Expr(e) if !unit => self.lower_tail_expr(*e, ret_ty),
            FunBody::Block(blk) if !unit => self.block_as_body(*blk, ret_ty),
            _ => None, // a `Unit` expr-body tailrec / no body — not modeled, skip
        };
        self.cur_tailrec = None;
        let loop_body = loop_body?;
        let cond = self.emit_const(IrConst::Boolean(true));
        let whilexpr = self.emit_while(cond, loop_body, None, false, Some(label));
        let body = self.emit_block(vec![whilexpr], None);
        self.ir.functions[fid as usize].body = Some(body);
        Some(())
    }

    /// Whether `callee(args)` is a tail self-call to the current `tailrec` function (same unqualified
    /// name, not shadowed by a local, matching arity).
    fn is_tail_self_call(&self, callee: AstExprId, args: &[AstExprId]) -> bool {
        let Some(ctx) = &self.cur_tailrec else {
            return false;
        };
        matches!(self.afile.expr(callee), Expr::Name(n) if *n == ctx.name)
            && self.lookup(&ctx.name).is_none()
            && args.len() == ctx.param_vals.len()
    }

    /// Emit a tail self-call: evaluate the args into temps (so reassignment can't alias), reassign each
    /// parameter slot, then `continue` the wrapping loop.
    fn tail_update_continue(&mut self, args: &[AstExprId]) -> Option<u32> {
        let ctx = self.cur_tailrec.clone()?;
        let mut stmts = Vec::new();
        let mut temps = Vec::new();
        for (a, t) in args.iter().zip(&ctx.param_tys) {
            let v = self.lower_arg(*a, &ty_to_ir(*t))?;
            let tmp = self.fresh_value();
            stmts.push(self.emit_variable(tmp, ty_to_ir(*t), Some(v)));
            temps.push(tmp);
        }
        for (pv, tmp) in ctx.param_vals.iter().zip(&temps) {
            let read = self.emit_get_value(*tmp);
            stmts.push(self.emit_set_value(*pv, read));
        }
        stmts.push(self.emit_continue(Some(ctx.label.clone())));
        Some(self.emit_block(stmts, None))
    }

    /// Lower an expression in TAIL position of a `tailrec` body: an `if` recurses into both branches; a
    /// self-call becomes update+continue; any other expression returns its value (bailing if it still
    /// contains a self-call — that would be non-tail recursion).
    fn lower_tail_expr(&mut self, e: AstExprId, ret_ty: &Ty) -> Option<u32> {
        match self.afile.expr(e).clone() {
            Expr::If {
                cond,
                then_branch,
                else_branch: Some(eb),
            } => {
                let c = self.expr(cond)?;
                let t = self.lower_tail_expr(then_branch, ret_ty)?;
                let el = self.lower_tail_expr(eb, ret_ty)?;
                Some(self.emit_when(vec![(Some(c), t), (None, el)]))
            }
            Expr::Call { callee, args } if self.is_tail_self_call(callee, &args) => {
                self.tail_update_continue(&args)
            }
            Expr::Block { .. } => self.block_as_body(e, ret_ty),
            _ => {
                // Base case: a non-recursive value. If it still references the function (a non-tail
                // self-call, e.g. `f(x) + 1`), we can't loop-ize it — skip the file rather than recurse.
                let ctx_name = self.cur_tailrec.as_ref()?.name.clone();
                if self.afile.expr_uses_name(e, &ctx_name) {
                    return None;
                }
                let v = self.lower_arg(e, ret_ty)?;
                Some(self.emit_return(Some(v)))
            }
        }
    }

    /// Lower a `Unit`-returning `tailrec` body block. A `Unit` body recurses with a bare statement
    /// (`if (c) f(args)` / `{ …; f(args) }`), not `return f(args)`: walk to the tail position and rewrite
    /// its self-calls into update+continue, then exit the loop via a trailing `return` on fall-through.
    /// Bails (skip file) on any self-call outside tail position — never miscompiles into recursion.
    fn lower_tail_unit(&mut self, block: AstExprId) -> Option<u32> {
        let Expr::Block { stmts, trailing } = self.afile.expr(block).clone() else {
            return None;
        };
        if stmts.is_empty() && trailing.is_none() {
            return None;
        }
        let (body, diverges) = self.lower_tail_unit_block(&stmts, trailing)?;
        let mut out = vec![body];
        if !diverges {
            // No tail self-call fired on this path → return `Unit`, exiting the `while(true)` loop.
            out.push(self.emit_return(None));
        }
        Some(self.emit_block(out, None))
    }

    /// Lower a block's statements + optional trailing expression in TAIL position. Only the final
    /// element — the trailing expr, or the last statement when there is none — is the tail. Returns the
    /// block IR and whether every path through it transfers control (`continue`/`return`/`throw`), i.e.
    /// never falls through. A self-call in any non-tail position → bail.
    fn lower_tail_unit_block(
        &mut self,
        stmts: &[crate::ast::StmtId],
        trailing: Option<AstExprId>,
    ) -> Option<(u32, bool)> {
        let name = self.cur_tailrec.as_ref()?.name.clone();
        let depth = self.scope.len();
        let mut out = Vec::new();
        // Leading non-tail statements: all of them when a trailing expr is the tail, else all but the last.
        let non_tail = if trailing.is_some() {
            stmts.len()
        } else {
            stmts.len().saturating_sub(1)
        };
        for &s in &stmts[..non_tail] {
            if self
                .afile
                .any_child_stmt(s, &mut |e| self.afile.expr_uses_name(e, &name))
            {
                self.scope.truncate(depth);
                return None;
            }
            if self.append_stmt(s, &mut out).is_none() {
                self.scope.truncate(depth);
                return None;
            }
            if self.stmt_diverges(s) {
                // A non-tail statement that always transfers control makes the tail dead — stop here.
                self.scope.truncate(depth);
                return Some((self.emit_block(out, None), true));
            }
        }
        let tail = match trailing {
            Some(t) => self.lower_tail_unit_expr(t),
            None => self.lower_tail_unit_stmt(*stmts.last()?),
        };
        let Some((ir, diverges)) = tail else {
            self.scope.truncate(depth);
            return None;
        };
        out.push(ir);
        self.scope.truncate(depth);
        Some((self.emit_block(out, None), diverges))
    }

    /// Lower the TAIL statement of a `Unit` `tailrec` body. Returns `(ir, always_transfers_control)`.
    fn lower_tail_unit_stmt(&mut self, s: crate::ast::StmtId) -> Option<(u32, bool)> {
        if let Stmt::Expr(e) = self.afile.stmt(s).clone() {
            return self.lower_tail_unit_expr(e);
        }
        // A non-`Expr` tail statement (assignment, etc.) is never a tail self-call — bail if it still
        // references the function, else lower it normally (the loop's `return` exits afterward).
        let name = self.cur_tailrec.as_ref()?.name.clone();
        if self
            .afile
            .any_child_stmt(s, &mut |e| self.afile.expr_uses_name(e, &name))
        {
            return None;
        }
        let mut tmp = Vec::new();
        self.append_stmt(s, &mut tmp)?;
        let d = self.stmt_diverges(s);
        Some((self.emit_block(tmp, None), d))
    }

    /// Lower a `Unit`-typed expression in TAIL position: `if` recurses into both branches (a no-`else`
    /// `if` whose condition is false falls through), a self-call becomes update+continue, a `{ … }`
    /// block recurses; anything else runs for effect (bailing on a non-tail self-call).
    fn lower_tail_unit_expr(&mut self, e: AstExprId) -> Option<(u32, bool)> {
        match self.afile.expr(e).clone() {
            Expr::If {
                cond,
                then_branch,
                else_branch,
            } => {
                let c = self.expr(cond)?;
                let (t, td) = self.lower_tail_unit_expr(then_branch)?;
                match else_branch {
                    Some(eb) => {
                        let (el, ed) = self.lower_tail_unit_expr(eb)?;
                        Some((self.emit_when(vec![(Some(c), t), (None, el)]), td && ed))
                    }
                    // No `else`: a false condition falls through past the `when` → never diverges.
                    None => Some((self.emit_when(vec![(Some(c), t)]), false)),
                }
            }
            Expr::Call { callee, args } if self.is_tail_self_call(callee, &args) => {
                Some((self.tail_update_continue(&args)?, true))
            }
            Expr::Block { stmts, trailing } => self.lower_tail_unit_block(&stmts, trailing),
            _ => {
                // Base case: run for effect. A lingering self-call here is non-tail → bail.
                let name = self.cur_tailrec.as_ref()?.name.clone();
                if self.afile.expr_uses_name(e, &name) {
                    return None;
                }
                let v = self.expr(e)?;
                Some((v, false))
            }
        }
    }

    /// Lower a compound assignment the checker selected as an `opAssign` operator call
    /// (`StmtLowering::PlusAssign`):
    /// `target op= rhs` → `target.plusAssign(rhs)` (member `invokevirtual`, or extension `invokestatic`
    /// with the receiver as the first argument). `value` is the parser's desugared `Binary { op, lhs, rhs }`
    /// where `lhs` is the target read.
    fn lower_plus_assign(&mut self, value: AstExprId) -> Option<u32> {
        let Expr::Binary { op, lhs, rhs } = self.afile.expr(value).clone() else {
            return None;
        };
        let aname = match op {
            BinOp::Add => "plusAssign",
            BinOp::Sub => "minusAssign",
            BinOp::Mul => "timesAssign",
            BinOp::Div => "divAssign",
            BinOp::Rem => "remAssign",
            _ => return None,
        };
        let recv_key = self.recv_ty(lhs).erased_recv();
        // Extension operator: `invokestatic owner.plusAssign(recv, arg)` (receiver is the first param).
        if let Some(&fid) = self.ext_fun_ids.get(&(recv_key, aname.to_string())) {
            let params = self.ir.functions[fid as usize].params.clone();
            if params.len() == 2 {
                let r = self.lower_arg(lhs, &params[0])?;
                let a = self.lower_arg(rhs, &params[1])?;
                return Some(self.emit_local_call(fid, vec![r, a]));
            }
        }
        let internal = self.recv_ty(lhs).obj_internal().map(|s| s.to_string())?;
        if let Some((class, index, mfid, _)) = self.resolve_method(&internal, aname) {
            let params = self.ir.functions[mfid as usize].params.clone();
            if let [param] = params.as_slice() {
                let r = self.expr(lhs)?;
                let a = self.lower_arg(rhs, param)?;
                return Some(self.emit_method_call(class, index, r, vec![Some(a)]));
            }
        }
        // Classpath inline `MutableCollection.plusAssign` (`@InlineOnly`): emit an inline
        // `invokestatic owner.plusAssign(recv, arg)` — the bytecode splicer expands its real body
        // (`add`/`addAll`) at the call site. The CHECKER resolved and recorded it (keyed by the target).
        let c = self.info.synthetic_ext(lhs, aname).cloned()?;
        if c.params.len() == 2 {
            let r = self.lower_arg(lhs, &ty_to_ir(c.params[0]))?;
            let a = self.lower_arg(rhs, &ty_to_ir(c.params[1]))?;
            return Some(self.emit_library_static_call(c, vec![r, a], false));
        }
        None
    }

    fn stmt(&mut self, s: crate::ast::StmtId) -> Option<u32> {
        let r = self.stmt_inner(s);
        if r.is_none() && self.bail.borrow().starts_with("deep") {
            self.set_bail(&format!(
                "stmt {}",
                bail_variant(&format!("{:?}", self.afile.stmt(s)))
            ));
        }
        r
    }

    fn stmt_inner(&mut self, s: crate::ast::StmtId) -> Option<u32> {
        // A compound assignment routed to an `opAssign` operator (checker-selected) — emit the call.
        if matches!(
            self.info.stmt_lowers.get(&s),
            Some(StmtLowering::PlusAssign)
        ) {
            if let Stmt::Assign { value, .. } | Stmt::AssignMember { value, .. } =
                self.afile.stmt(s).clone()
            {
                return self.lower_plus_assign(value);
            }
        }
        match self.afile.stmt(s).clone() {
            Stmt::Expr(e) => {
                let v = self.expr(e)?;
                // A statement's value is DISCARDED. If it is an unbox of an erased reference result
                // (`map.put(k, v)` returns `V?` but is typed as a primitive, so the call result is
                // coerced `Object` → `int`), drop the unbox: kotlinc pops the reference, and unboxing a
                // null result would NPE. A statement top is never a numeric widening (no target type),
                // so a coercion to a non-reference here is always that unbox.
                Some(self.strip_discarded_unbox(v))
            }
            Stmt::Return(e, ret_label) => {
                // Inside a `tailrec` function (no spliced-lambda label): a `return f(args)` to the same
                // function is a tail call — reassign the params and `continue` the loop. A `return` whose
                // value otherwise references the function is non-tail recursion the loop can't model →
                // bail (skip file) rather than stack-overflow.
                if ret_label.is_none() && self.cur_tailrec.is_some() {
                    if let Some(ve) = e {
                        if let Expr::Call { callee, args } = self.afile.expr(ve).clone() {
                            if self.is_tail_self_call(callee, &args) {
                                return self.tail_update_continue(&args);
                            }
                        }
                        let name = self.cur_tailrec.as_ref().unwrap().name.clone();
                        if self.afile.expr_uses_name(ve, &name) {
                            return None;
                        }
                    }
                }
                // A `return@label` matching an active spliced-lambda frame is a LOCAL return from that
                // lambda: break to the lambda's end label (`Unit` result — run any value for effect). A
                // labeled return with no matching frame is a `return@enclosingFn` — fall through to the
                // normal function-return handling below (the label names the enclosing function).
                // A NON-LOCAL `return` where EVERY active spliced-lambda frame is in fn-TAIL position
                // (`fun f(): T = mutex.withLock { … return v … }`) is equivalent to a labeled return
                // through the innermost frame: each splice's result is directly the next level's (and
                // finally the function's) result, so `v` bubbles out identically — and the splice's
                // `try`/`finally` needs no unmodeled in-`try` `Return`.
                let frame = if let Some(lbl) = &ret_label {
                    self.inline_lambda_ret
                        .iter()
                        .rev()
                        .find(|(l, ..)| l == lbl)
                        .cloned()
                } else if !self.inline_lambda_ret.is_empty()
                    && self.inline_lambda_ret.iter().all(|&(.., tail)| tail)
                {
                    self.inline_lambda_ret.last().cloned()
                } else {
                    None
                };
                {
                    if let Some((_, slot, brk, rty, _)) = frame {
                        let mut stmts = Vec::new();
                        if let Some(e) = e {
                            // A VALUE-result labeled return (`x.let { return@let v }`) assigns `v` to the
                            // frame's result slot; the wrapper loop's value is read from it afterward. A
                            // `Unit` result just runs the (side-effecting) expression for effect.
                            if rty != Ty::Unit && rty != Ty::Nothing {
                                let val = self.lower_arg(e, &rty)?;
                                // A SUSPENDING result (`return@withLock create(...)`): the coroutine
                                // flattener splits a suspension out of a `Variable` initializer but not out
                                // of a `SetValue`. Hoist it into a fresh temp first so the suspension sits
                                // in a `Variable` init the state machine can flatten, then store the temp.
                                // Detect a suspend call the same way the flattener does — a same-file
                                // `Call`/`MethodCall` to a `suspend_funs` target, or a recorded
                                // cross-unit `suspend_calls` entry.
                                let val_suspends = self.ir.suspend_calls.contains_key(&val)
                                    || match &self.ir.exprs[val as usize] {
                                        IrExpr::Call {
                                            callee: Callee::Local(fid),
                                            ..
                                        } => self.ir.suspend_funs.contains(fid),
                                        IrExpr::MethodCall { class, index, .. } => self.ir.classes
                                            [*class as usize]
                                            .methods
                                            .get(*index as usize)
                                            .is_some_and(|fid| self.ir.suspend_funs.contains(fid)),
                                        _ => false,
                                    };
                                let val = if val_suspends {
                                    let tmp = self.fresh_value();
                                    stmts.push(self.emit_variable(tmp, ty_to_ir(rty), Some(val)));
                                    self.emit_get_value(tmp)
                                } else {
                                    val
                                };
                                stmts.push(self.emit_set_value(slot, val));
                            } else {
                                stmts.push(self.expr(e)?);
                            }
                        }
                        stmts.push(self.emit_break(Some(brk)));
                        return Some(self.emit_block(stmts, None));
                    }
                }
                // Inside an expanded `inline fun` body: `return x` is not a real method return — it
                // assigns the inline result slot and breaks to the body's end label (the `do…while(false)`
                // wrapper). A `try { … } finally { … }` around the return is not yet combined with this
                // transfer, so bail that combination (the file skips — never a miscompile).
                if let Some((slot, label, rty)) = self.inline_return.last().cloned() {
                    if !self.try_finally_stack.is_empty() {
                        return None;
                    }
                    let mut stmts = Vec::new();
                    // A `Unit`-returning inline fn has no result slot — `return`/`return Unit` is a bare
                    // `break`. Otherwise assign the (coerced) value to the result slot, then break.
                    if rty != Ty::Unit {
                        let val = match e {
                            Some(e) if self.info.ty(e) != Ty::Nothing => self.lower_arg(e, &rty)?,
                            Some(e) => self.expr(e)?,
                            None => self.emit_unit(),
                        };
                        stmts.push(self.emit_set_value(slot, val));
                    } else if let Some(e) = e {
                        // `return someUnitExpr` — run the expression for its side effects.
                        stmts.push(self.expr(e)?);
                    }
                    stmts.push(self.emit_break(Some(label)));
                    return Some(self.emit_block(stmts, None));
                }
                let v = match e {
                    // Coerce to the enclosing function's return type (generic-erased `Object` → cast).
                    Some(e) if self.cur_ret_ty != Ty::Unit && self.info.ty(e) != Ty::Nothing => {
                        let rt = self.cur_ret_ty.clone();
                        Some(self.lower_arg(e, &rt)?)
                    }
                    Some(e) => Some(self.expr(e)?),
                    // A valueless `return@lambda` in a `() -> Unit` closure method must `areturn` the
                    // `kotlin/Unit` singleton (the method's JVM return is a reference, not `void`).
                    None if self.cur_method_returns_unit_ref => Some(self.emit_unit()),
                    None => None,
                };
                // Inside one or more `try { … } finally { … }`, a `return` must run each enclosing
                // `finally` (innermost first) before transferring control — `{ val tmp = <value>;
                // <finally>…; return tmp }`. The value is captured into a temp first so a `finally` that
                // mutates state can't change what is returned (Kotlin evaluates the value, then runs the
                // finallys).
                if !self.try_finally_stack.is_empty() {
                    let finallys = self.try_finally_stack.clone();
                    let mut stmts = Vec::new();
                    let ret_val = match v {
                        Some(val) => {
                            let tmp = self.fresh_value();
                            let vty = self.cur_ret_ty.clone();
                            stmts.push(self.emit_variable(tmp, vty, Some(val)));
                            Some(tmp)
                        }
                        None => None,
                    };
                    // Inline each finally (innermost first). A `return` *inside* a finally must run
                    // only the finallys that enclose it — never itself — so lower finally `i` with the
                    // stack truncated to its enclosers (`finallys[..i]`, outermost-first). Without this,
                    // a finally whose body returns (e.g. `try { return 0 } finally { return 1 }`) would
                    // re-inline itself at its own `return` and recurse forever.
                    let saved = std::mem::take(&mut self.try_finally_stack);
                    for i in (0..finallys.len()).rev() {
                        self.try_finally_stack = finallys[..i].to_vec();
                        let lowered = self.expr(finallys[i]);
                        let Some(s) = lowered else {
                            self.try_finally_stack = saved;
                            return None;
                        };
                        stmts.push(s);
                    }
                    self.try_finally_stack = saved;
                    let rv = ret_val.map(|tmp| self.emit_get_value(tmp));
                    stmts.push(self.emit_return(rv));
                    return Some(self.emit_block(stmts, None));
                }
                Some(self.emit_return(v))
            }
            Stmt::LocalLateinit { name, ty } => {
                // A lateinit local captured by a NON-inline closure isn't modeled: the closure holds the
                // slot in a captured/`Ref` representation whose read path carries no uninitialized guard,
                // so the guard would be dropped (a miscompile) or its frame would be wrong. Bail (skip).
                if self.closure_captured_names.contains(&name) {
                    return None;
                }
                // `ty_ref` yields `Some` only for a non-null reference type; a nullable/primitive/
                // unresolved annotation returns `None`, bailing (a lateinit must be a non-null reference).
                let kty = self.ty_ref(&ty)?;
                let v = self.fresh_value();
                self.scope.push((name.clone(), v, kty));
                self.lateinit_locals.insert(v, name.clone());
                // The slot defaults to `null` (kotlinc: `aconst_null; astore`); a read while still null
                // throws via the `LateinitCheck` wrapper (see the local-read path).
                let null = self.emit_const(IrConst::Null);
                Some(self.emit_named_variable(v, ty_to_ir(kty), Some(null)))
            }
            Stmt::Local { name, init, ty, .. } => {
                let init_ty = self.info.ty(init);
                // A diverging initializer (`val x = when { … all branches return … }`) never binds
                // anything — emit it for effect (it returns/throws), no slot store.
                if init_ty == Ty::Nothing {
                    return self.expr(init);
                }
                // `Unit` as a stored value: kotlinc runs the initializer for effect, then binds the
                // `kotlin.Unit` singleton to the slot (a `kotlin/Unit` reference). `val u = f()` where
                // `f(): Unit` → run `f()`, then store `GETSTATIC kotlin/Unit.INSTANCE`.
                if init_ty == Ty::Unit {
                    let unit_ty = stored_value_ty(Ty::Unit);
                    let side = self.expr(init)?;
                    let unit_val = self.emit_unit();
                    let seq = self.emit_block(vec![side], Some(unit_val));
                    let v = self.fresh_value();
                    self.scope.push((name.clone(), v, unit_ty));
                    return Some(self.emit_named_variable(v, ty_to_ir(unit_ty), Some(seq)));
                }
                // Use the declared type only when it's a builtin krusty `Ty`; for a user/class type
                // (`val en: En`) `Ty::from_name` is `None`, so fall back to the checker's inferred
                // type — otherwise the local is typed `Error` and e.g. `==` takes the wrong path.
                // Resolve the declared type: a builtin, else a known file class (`A?` → reference
                // `A`, not the `null` initializer's `Ty::Null`), else the checker's inferred type.
                let kty = match ty.as_ref() {
                    // A declared function type (`val f: (C) -> Int`): use the annotation's `Ty::Fun`.
                    Some(r) if !r.fun_params.is_empty() || r.name == "<fun>" => {
                        ty_of(self.afile, r, &*self.syms.libraries)
                    }
                    // Nullable builtin non-reference values (`Int?`, `Unit?`, `Nothing?`) use the shared
                    // source `Nullable(T)` form; the JVM backend maps that to a reference slot.
                    Some(r)
                        if r.nullable
                            && Ty::from_name(&r.name).is_some_and(|t| !t.is_reference())
                            && !self.contains_class(&class_internal(self.afile, &r.name)) =>
                    {
                        ty_of(self.afile, r, &*self.syms.libraries)
                    }
                    Some(r) if Ty::from_name(&r.name).is_some() => Ty::from_name(&r.name).unwrap(),
                    Some(r) if self.contains_class(&class_internal(self.afile, &r.name)) => {
                        Ty::obj(&class_internal(self.afile, &r.name))
                    }
                    // A primitive array (`ByteArray` → `[B`) or a boxed `Array<X>` — resolve via `ty_of`
                    // (which maps the element). NOT the class/catch fallbacks, which would resolve a bare
                    // `ByteArray`/`IntArray` through the global simple-name index to an unrelated JDK class
                    // (`jdk/internal/util/ByteArray`), corrupting the local's stackmap frame type. After the
                    // file-class arm so a user class of the same name still wins.
                    Some(r)
                        if r.name == "Array" || Ty::primitive_array_element(&r.name).is_some() =>
                    {
                        ty_of(self.afile, r, &*self.syms.libraries)
                    }
                    // A library reference type (`Throwable?`, `List<Int>`): use the declared reference
                    // type, not the initializer's. A `null` initializer is `Ty::Null`, which would type
                    // the slot as `top` in frames; the declared reference type keeps the slot a
                    // reference so a later reassign + use across branches verifies.
                    Some(r) if self.catch_internal(&r.name).is_some() => {
                        Ty::obj(&self.catch_internal(&r.name).unwrap())
                    }
                    // A declared reference type whose simple name isn't in the lowerer's local index
                    // (`Result<T>?` — pruned/auto-imported) — reuse the type the CHECKER already resolved
                    // for this local (through imports), so a `null`-initialized local keeps its declared
                    // (value-)class type instead of collapsing to the initializer's `Any?`.
                    Some(_) if self.info.local_decl_types.contains_key(&s) => {
                        self.info.local_decl_types[&s]
                    }
                    _ => init_ty,
                };
                // A mutable local captured (and written) by a closure is boxed into a `Ref$XxxRef`:
                // the local holds the holder, reads/writes go through `element`, and the closure
                // captures the shared holder (so its writes are visible here and vice versa).
                if self.shared_cell_vars.contains(&name) {
                    // A `@JvmInline value class` var is represented UNBOXED as its underlying type, so its
                    // `Ref` holder + element use that underlying type (`var z: Z(Int)` → `Ref.IntRef`) —
                    // except a nullable reference value class (`Result<T>?`) stays BOXED (see helper).
                    let elem_ty = self.shared_cell_elem_ty(kty);
                    let elem = ref_elem_ir(elem_ty);
                    let it = self.lower_arg(init, &ty_to_ir(kty))?;
                    let holder = self.fresh_value();
                    let holder_ty = self.mutable_local_ref_type(elem_ty)?;
                    self.scope.push((name.clone(), holder, holder_ty));
                    self.boxed_elem.insert(name.clone(), elem_ty);
                    // A single `Variable` (no scoping block) so the holder's slot lives in the enclosing
                    // scope — the closure's capture reads it later.
                    let new_ref = self.ir.add_expr(IrExpr::RefNew { elem, init: it });
                    return Some(self.emit_named_variable(
                        holder,
                        ty_to_ir(holder_ty),
                        Some(new_ref),
                    ));
                }
                // A NESTED-array local (`val x: Array<Array<*>> = arrayOf(arrayOf(1))`): its outermost
                // array-creating initializer builds over the DECLARED element (`Array<*>` = `Object[]`),
                // wide enough to hold a later `arrayOf("OK")`. Narrow to a nested-array element only — a
                // concrete/nullable element (`Array<Int?>`) keeps its inferred creation (see
                // `collectionLiterals`). Take-once (consumed by the outer creation's `synth_array_elem`).
                let nested_array_elem = kty
                    .non_null()
                    .obj_internal()
                    .is_some_and(|n| n.matches("kotlin/Array"))
                    .then(|| kty.array_elem())
                    .flatten()
                    .filter(|e| {
                        e.non_null()
                            .obj_internal()
                            .is_some_and(|n| n.matches("kotlin/Array"))
                    });
                // SAVE-RESTORE (not set-then-clear): a nested-array local INSIDE the initializer (`… = run
                // { val y: Array<Array<Int>> = …; arrayOf(y) }`) must not clobber this one's expected element.
                let prev_expected = self.expected_array_elem.replace(nested_array_elem);
                // Coerce the initializer to the declared type (a generic-erased `Object` flowing into a
                // typed `val` gets the `checkcast` kotlinc inserts).
                let it = self.lower_arg(init, &ty_to_ir(kty))?;
                self.expected_array_elem.set(prev_expected);
                let v = self.fresh_value();
                self.scope.push((name.clone(), v, kty));
                // A nullable-declared local (`val v: X? = null`) carries its nullability into the IrType —
                // `Ty` drops it, but the JVM value-class pass keys boxing (`X(null)` vs `null`) on it.
                let mut var_ty = ty_to_ir(kty);
                // The local is nullable if explicitly declared `?`, OR (when inferred) its initializer is a
                // call to a function with a nullable return — `Ty` drops nullability, so a `val x = zap()`
                // where `zap(): ZN2?` would otherwise type `x` non-null and the JVM value-class pass would
                // treat a boxed `ZN2?` as unboxed.
                let nullable = match ty.as_ref() {
                    Some(r) => r.nullable,
                    None => {
                        if let ast::Expr::Call { callee, .. } = self.afile.expr(init) {
                            match self.afile.expr(*callee) {
                                // A free-function call (`val x = zap()` where `zap(): T?`).
                                ast::Expr::Name(n) => self.afile.decls.iter().any(|&d| matches!(self.afile.decl(d),
                                    ast::Decl::Fun(f) if &f.name == n && f.ret.as_ref().is_some_and(|rr| rr.nullable))),
                                // A method call (`val x = t.foo()` where `foo(): T?`): resolve the method on the
                                // receiver's class and read its (nullability-carrying) IR return type — a nullable
                                // value-class return (`X?`) is a boxed `X`, so the local must stay boxed, not unbox.
                                ast::Expr::Member { receiver, name } => {
                                    let recv_ty = self.info.ty(*receiver);
                                    recv_ty
                                        .obj_internal()
                                        .and_then(|internal| self.resolve_method_name(internal, name))
                                        .is_some_and(|(_, _, fid, _)| {
                                            self.ir.functions[fid as usize].ret.is_nullable()
                                        })
                                }
                                _ => false,
                            }
                        } else {
                            false
                        }
                    }
                };
                if nullable {
                    var_ty = mark_nullable(var_ty);
                }
                Some(self.emit_named_variable(v, var_ty, Some(it)))
            }
            Stmt::LocalDelegate {
                is_var,
                name,
                ty,
                delegate,
            } => {
                let delegate_ty = self.info.ty(delegate);
                let delegate_internal = delegate_ty.obj_internal()?;
                // Same soundness guards as member delegation: only a concrete (non-value-class, no
                // `provideDelegate`) delegate whose `getValue` return matches the property type.
                let is_value_cls = |s: TypeName| {
                    self.syms
                        .class_by_type_name(s)
                        .is_some_and(|cs| cs.value_field.is_some())
                };
                if is_value_cls(delegate_internal)
                    || self
                        .syms
                        .method_of_name(delegate_internal, "provideDelegate")
                        .is_some()
                    || delegate_getvalue_uses_property(self.afile, delegate_internal)
                {
                    return None;
                }
                let (gv, gv_ret) = match self.info.delegate_getvalue(delegate)? {
                    DelegateGetValueTarget::Member { owner, params, ret } => {
                        if *owner != delegate_internal {
                            return None;
                        }
                        (
                            Signature {
                                params: params.clone(),
                                ret: *ret,
                                vararg: false,
                                required: params.len(),
                                param_defaults: Vec::new(),
                                param_default_values: Vec::new(),
                                param_names: Vec::new(),
                                lambda_param_types: Vec::new(),
                                lambda_recv: Vec::new(),
                                is_inline: false,
                                is_final: true,
                                is_suspend: false,
                                context_count: 0,
                                source_decl: None,
                                source_file: None,
                                package: String::new(),
                            },
                            *ret,
                        )
                    }
                    DelegateGetValueTarget::Extension(_) => return None,
                };
                let prop_ty = ty
                    .as_ref()
                    .map(|r| ty_of(self.afile, r, &*self.syms.libraries))
                    .unwrap_or(gv_ret);
                if gv_ret != prop_ty || prop_ty.obj_internal().is_some_and(is_value_cls) {
                    return None;
                }
                let setvalue_sig = if is_var {
                    Some(self.syms.method_of_name(delegate_internal, "setValue")?)
                } else {
                    None
                };
                // Lower the delegate into a fresh `$delegate` local.
                let dv = self.fresh_value();
                let init = self.lower_arg(delegate, &ty_to_ir(delegate_ty))?;
                self.scope
                    .push((format!("{name}$delegate"), dv, delegate_ty));
                self.local_delegated.insert(
                    name.clone(),
                    LocalDelegate {
                        delegate_internal,
                        getvalue_sig: gv,
                        setvalue_sig,
                        name: name.clone(),
                        ret_ty: prop_ty,
                    },
                );
                Some(self.emit_named_variable(dv, ty_to_ir(delegate_ty), Some(init)))
            }
            Stmt::Destructure { entries, init } => {
                // A direct `stmt()` call wraps the bindings in a Block; the block builders use
                // `append_stmt` instead so the component locals live in the enclosing scope.
                let mut out = Vec::new();
                self.lower_destructure(s, &entries, init, &mut out)?;
                Some(self.emit_block(out, None))
            }
            Stmt::Assign { name, value } => {
                // `field = …` inside a custom setter body writes the property's backing field.
                if name == "field" {
                    if let Some((class_id, fidx, fty)) = self.cur_field.clone() {
                        let val = self.lower_arg(value, &fty)?;
                        let this_e = self.emit_get_value(0);
                        return Some(self.emit_set_field(this_e, class_id, fidx, val));
                    }
                    // A top-level custom setter writes the backing STATIC field.
                    if let Some((sidx, fty)) = self.cur_static_field {
                        let val = self.lower_arg(value, &fty)?;
                        return Some(self.emit_set_static(sidx, val));
                    }
                }
                // A local delegated `var`: write through the delegate's `setValue(null, propref, value)`.
                if let Some(ld) = self.local_delegated.get(&name).cloned() {
                    let sv = ld.setvalue_sig.clone()?;
                    let value_ty = sv.params.last().copied().unwrap_or(Ty::Error);
                    let val = self.lower_arg(value, &ty_to_ir(value_ty))?;
                    let (dslot, _) = self.lookup(&format!("{name}$delegate"))?;
                    let dele = self.emit_get_value(dslot);
                    let null_a = self.emit_const(IrConst::Null);
                    let pref = self.make_local_propref(&ld)?;
                    return Some(self.emit_virtual_call(
                        ld.delegate_internal,
                        "setValue".to_string(),
                        self.runtime.method_descriptor(&sv.params, sv.ret)?,
                        false,
                        dele,
                        vec![null_a, pref, val],
                    ));
                }
                // A boxed mutable-capture local: write through its `Ref` holder's `element`.
                if let Some(elem) = self.boxed_elem.get(&name).cloned() {
                    let (holder, _) = self.lookup(&name)?;
                    let hv = self.emit_get_value(holder);
                    let val = self.lower_arg(value, &ty_to_ir(elem))?;
                    return Some(self.ir.add_expr(IrExpr::RefSet {
                        holder: hv,
                        elem: ref_elem_ir(elem),
                        value: val,
                    }));
                }
                // A backing field of the enclosing class (`this.<field>`) shadows a same-named top-level
                // property — resolve it BEFORE `statics` (kotlinc: a member's unqualified name binds to the
                // class member first). Requires `this` in scope (a class member, not a top-level function).
                let own_field = self.lookup("this").and_then(|(this_v, _)| {
                    self.cur_class.as_ref().and_then(|c| {
                        // A `var` custom-accessor property writes through `setX`, never the raw field.
                        // A `val` custom-accessor (no setter) is assigned once in a constructor by
                        // writing its backing field directly, so it is NOT excluded here.
                        if self.field_accessor_var_props.contains(&(*c, name.clone())) {
                            return None;
                        }
                        self.class_info_name(*c).and_then(|ci| {
                            ci.fields
                                .iter()
                                .position(|(fn_, _)| *fn_ == name)
                                .map(|i| (this_v, ci.id, i as u32, ty_to_ir(ci.fields[i].1)))
                        })
                    })
                });
                if let Some((v, sty)) = self.lookup(&name) {
                    // Coerce to the slot's declared type — a generic-erased `Object` value assigned to a
                    // typed `var` gets the `checkcast` kotlinc inserts (else the slot frame is
                    // inconsistent: `String?` at init vs `Object` after the assignment).
                    let val = self.lower_arg(value, &ty_to_ir(sty))?;
                    Some(self.emit_set_value(v, val))
                } else if let Some((this_v, class, idx, field_ty)) = own_field {
                    let recv = self.emit_get_value(this_v);
                    let val = self.lower_arg(value, &field_ty)?;
                    Some(self.emit_set_field(recv, class, idx, val))
                } else if let Some(sfid) = self.computed_setters.get(&name).copied() {
                    // A top-level backing-field `var` with a custom setter → call `setX(value)` (which
                    // runs the custom body), not a direct `putstatic`.
                    let ty = self
                        .statics
                        .get(&name)
                        .map(|&(_, t)| t)
                        .unwrap_or(Ty::Error);
                    let val = self.lower_arg(value, &ty_to_ir(ty))?;
                    Some(self.emit_local_call(sfid, vec![val]))
                } else if let Some((idx, ty)) = self.statics.get(&name).cloned() {
                    let val = self.lower_arg(value, &ty_to_ir(ty))?;
                    Some(self.emit_set_static(idx, val))
                } else if let Some((facade, ty, is_var, _)) =
                    self.syms.prop_facades.get(&name).cloned()
                {
                    // A `var` from ANOTHER file → call its facade's `setX(v)` (the field is private).
                    if !is_var {
                        return None;
                    }
                    let val = self.lower_arg(value, &ty_to_ir(ty))?;
                    Some(self.emit_cross_file_call(
                        facade,
                        property_setter_name(&name),
                        vec![ty_to_ir(ty)],
                        Ty::Unit,
                        vec![val],
                    ))
                } else {
                    // `this` is an external receiver (an inlined `apply`/`run` whose backing field is
                    // private) — write through the property setter `setX(v)`.
                    let (this_v, this_ty) = self.lookup("this")?;
                    let recv = self.emit_get_value(this_v);
                    {
                        let internal = this_ty.obj_internal()?.to_string();
                        let (sclass, sindex, sfid, _) =
                            self.resolve_method(&internal, &property_setter_name(&name))?;
                        let pty = self.ir.functions[sfid as usize]
                            .params
                            .first()
                            .cloned()
                            .unwrap_or_else(|| ty_to_ir(Ty::obj("kotlin/Any")));
                        let val = self.lower_arg(value, &pty)?;
                        Some(self.emit_method_call(sclass, sindex, recv, vec![Some(val)]))
                    }
                }
            }
            // `name++` / `name--` on a local numeric variable → `name = name ± 1`. (In statement
            // position the pre/post distinction is irrelevant — the value isn't observed.) A built-in
            // numeric primitive only; a `var` field/property or a user `operator inc`/`dec` bails.
            Stmt::IncDec { name, dec } => {
                // A boxed mutable-capture local: `x++`/`x--` reads/writes through its `Ref` holder.
                if let Some(elem) = self.boxed_elem.get(&name).cloned() {
                    let (holder, _) = self.lookup(&name)?;
                    let one = self.scalar_one_const(elem)?;
                    let op = if dec { IrBinOp::Sub } else { IrBinOp::Add };
                    let hv = self.emit_get_value(holder);
                    let cur = self.ir.add_expr(IrExpr::RefGet {
                        holder: hv,
                        elem: ty_to_ir(elem),
                    });
                    let nv = self.scalar_update_value(cur, elem, op, one);
                    let hv2 = self.emit_get_value(holder);
                    return Some(self.ir.add_expr(IrExpr::RefSet {
                        holder: hv2,
                        elem: ty_to_ir(elem),
                        value: nv,
                    }));
                }
                // A `var` field of the enclosing class (`this.x++` written bare) inside its own method —
                // `this.x = this.x ± 1` via a direct field read/write. (`obj.x++`/`arr[i]++` were already
                // desugared to a compound assignment by the parser; an external `this`, e.g. an inlined
                // `apply`, isn't handled here.)
                if self.lookup(&name).is_none() {
                    let (this_v, this_ty) = self.lookup("this")?;
                    let internal = this_ty.obj_internal()?.to_string();
                    let (fty, is_var) = self.syms.prop_of(&internal, &name)?;
                    if !is_var {
                        return None;
                    }
                    let one_c = self.scalar_one_const(fty)?;
                    let op = if dec { IrBinOp::Sub } else { IrBinOp::Add };
                    // A field of *this* class is read/written directly; an inherited one (or an external
                    // `this`), or a CUSTOM-accessor property, goes through its getter/setter accessors.
                    let own = self.cur_class.as_ref().and_then(|c| {
                        if self.field_accessor_props.contains(&(*c, name.clone())) {
                            return None;
                        }
                        self.class_info_name(*c).and_then(|ci| {
                            ci.fields
                                .iter()
                                .position(|(fn_, _)| *fn_ == name)
                                .map(|i| (ci.id, i as u32))
                        })
                    });
                    let recv = self.emit_get_value(this_v);
                    let cur_val = if let Some((class, idx)) = own {
                        self.emit_get_field(recv, class, idx)
                    } else {
                        let (gclass, gindex, _, _) =
                            self.resolve_method(&internal, &property_getter_name(&name))?;
                        self.emit_method_call(gclass, gindex, recv, vec![])
                    };
                    let nv = self.scalar_update_value(cur_val, fty, op, one_c);
                    let recv2 = self.emit_get_value(this_v);
                    return Some(if let Some((class, idx)) = own {
                        self.emit_set_field(recv2, class, idx, nv)
                    } else {
                        let (sclass, sindex, _, _) =
                            self.resolve_method(&internal, &property_setter_name(&name))?;
                        self.emit_method_call(sclass, sindex, recv2, vec![Some(nv)])
                    });
                }
                let (v, ty) = self.lookup(&name)?;
                // A user `inc`/`dec` operator on a non-numeric variable → `x = x.inc()`.
                if let Some(call) = self.lower_member_inc_dec(v, ty, dec) {
                    return Some(self.emit_set_value(v, call));
                }
                let one = self.scalar_one_const(ty)?;
                let op = if dec { IrBinOp::Sub } else { IrBinOp::Add };
                let cur = self.emit_get_value(v);
                let nv = self.scalar_update_value(cur, ty, op, one);
                Some(self.emit_set_value(v, nv))
            }
            // `receiver.field = value` → `IrSetField` (var property of a class in this IR).
            Stmt::AssignMember {
                receiver,
                name,
                value,
            } => {
                // A compound member-assign (`recv.a op= v`) reuses the `receiver` expr id in the
                // parser's desugared `recv.a = recv.a op v`, so a side-effecting receiver (`foo.a += v`
                // where `foo` is a property getter, or `bar().a += v`) would be evaluated TWICE. Spill a
                // non-pure receiver to a temp once, mapping its id to `GetValue(temp)` for the store —
                // mirroring the compound index-assign caching. A local/`this` receiver is pure (left to
                // re-load, keeping bytecode parity with kotlinc for the common case).
                let mut prelude = Vec::new();
                let spill = self.is_compound_member_assign(receiver, &name, value)
                    && !self.index_subst.contains_key(&receiver)
                    && !self.is_pure_index_operand(receiver);
                if spill {
                    let lowered = self.expr(receiver)?;
                    let slot = self.fresh_value();
                    let ty = ty_to_ir(self.info.ty(receiver));
                    let var = self.emit_variable(slot, ty, Some(lowered));
                    let getv = self.emit_get_value(slot);
                    self.index_subst.insert(receiver, getv);
                    prelude.push(var);
                }
                let store = self.lower_assign_member(s, receiver, &name, value);
                if spill {
                    self.index_subst.remove(&receiver);
                }
                let store = store?;
                if prelude.is_empty() {
                    Some(store)
                } else {
                    prelude.push(store);
                    Some(self.emit_block(prelude, None))
                }
            }
            Stmt::AssignIndex {
                array,
                indices,
                value,
            } => {
                // A MULTI-index store (`recv[i, j] = v`) → the `set(i, j, …, v)` operator (a user member,
                // a same-module extension, or a library member; `lower_op_call` covers all three).
                let &[index] = indices.as_slice() else {
                    let rt = self.info.ty(array);
                    let recv_v = self.expr(array)?;
                    let mut set_args = indices.clone();
                    set_args.push(value);
                    if let Some((v, _)) = self.lower_stmt_op_call(s, recv_v, rt, "set", &set_args) {
                        return Some(v);
                    }
                    self.set_bail("stmt AssignIndex(multi)");
                    return None;
                };
                // A compound index-assign (`a[i] op= v`) desugars (in the parser) to `value = a[i] op v`,
                // REUSING the `array`/`index` expr ids — so lowering the store and the embedded read would
                // evaluate a side-effecting receiver/index twice (`a[f()] += v` calls `f()` twice). Spill
                // each non-pure operand to a temp once, mapping its shared id to a `GetValue(temp)` for the
                // duration of the store (a bare name/literal is left to re-evaluate — pure, and matches
                // kotlinc's bytecode). The substitution is consulted at the top of [`Self::expr`].
                let mut prelude = Vec::new();
                if self.is_compound_index_assign(array, index, value) {
                    for sub in [array, index] {
                        if !self.index_subst.contains_key(&sub) && !self.is_pure_index_operand(sub)
                        {
                            let lowered = self.expr(sub)?;
                            let slot = self.fresh_value();
                            let ty = ty_to_ir(self.info.ty(sub));
                            let var = self.emit_variable(slot, ty, Some(lowered));
                            let getv = self.emit_get_value(slot);
                            self.index_subst.insert(sub, getv);
                            prelude.push(var);
                        }
                    }
                }
                let store = self.lower_index_store(s, array, index, value);
                self.index_subst.remove(&array);
                self.index_subst.remove(&index);
                let store = store?;
                if prelude.is_empty() {
                    Some(store)
                } else {
                    prelude.push(store);
                    Some(self.emit_block(prelude, None))
                }
            }
            Stmt::While { cond, body, label } => {
                let c = self.expr(cond)?;
                let depth = self.scope.len();
                let mut out = Vec::new();
                self.append_body_stmts(body, &mut out)?;
                self.scope.truncate(depth);
                let b = self.emit_block(out, None);
                Some(self.emit_while(c, b, None, false, label))
            }
            Stmt::DoWhile { body, cond, label } => {
                let depth = self.scope.len();
                let mut out = Vec::new();
                self.append_body_stmts(body, &mut out)?;
                self.scope.truncate(depth);
                // The condition is lowered after the body's scope is dropped — a `do…while` condition
                // can't see body-local declarations (Kotlin scopes them to the body).
                let c = self.expr(cond)?;
                let b = self.emit_block(out, None);
                Some(self.emit_while(c, b, None, true, label))
            }
            Stmt::Break(label) => Some(self.emit_break(label)),
            Stmt::Continue(label) => Some(self.emit_continue(label)),
            // `for (i in a..b [step s])` over an `Int` range → a counted `while`. The bound is
            // hoisted to a local (evaluated once, per Kotlin); the step defaults to 1.
            Stmt::For {
                name,
                range,
                body,
                label,
            } => {
                use crate::ast::RangeKind;
                let depth = self.scope.len();
                // The counter type is the bound type (`Int`, `Long`, or unsigned `UInt`/`ULong`). A
                // `Byte`/`Short` range widens to an `IntRange`, so the counter is `Int` and the bounds
                // coerce up (matching the checker and `Short.rangeTo(Short): IntRange`).
                let elem = self.info.ty(range.start).range_counter_type()?;
                let elem_ir = ty_to_ir(elem);
                let one = self.scalar_one_const(elem)?;
                // loop var = start. The bounds may be erased (`l[0]` → `Object`); coerce them to the
                // counter's primitive type so the value is unboxed before the slot store.
                let start = self.lower_arg(range.start, &elem_ir)?;
                let i_v = self.fresh_value();
                self.scope.push((name.clone(), i_v, elem));
                let var_i = self.emit_variable(i_v, elem_ir.clone(), Some(start));
                // The bound. kotlinc folds a CONSTANT bound with unit step into a single `i < C` exclusive
                // test — no hoisted local, no overflow guard: `1..10` → `i < 11`, `0 until 10` → `i < 10`.
                // Match that for a literal `Int` bound; every other case hoists the (possibly
                // side-effecting / non-constant) bound into a temp and keeps the overflow-safe shape.
                // The exclusive comparison constant: `until C` → `C` (`i < C`); `..C` → `C+1` (`i < C+1`);
                // `downTo C` → `C-1` (`C-1 < i`, i.e. `i > C-1`). The `±1` folds must not over/underflow.
                let inline_bound: Option<i32> = if elem == Ty::Int {
                    match self.afile.expr(range.end) {
                        Expr::IntLit(v) => {
                            let v = *v;
                            match range.kind {
                                RangeKind::Until if i32::try_from(v).is_ok() => Some(v as i32),
                                RangeKind::Through if v < i32::MAX as i64 => Some(v as i32 + 1),
                                RangeKind::DownTo if v > i32::MIN as i64 => Some(v as i32 - 1),
                                _ => None,
                            }
                        }
                        _ => None,
                    }
                } else {
                    None
                };
                // A bound that is already a plain local (not reassigned in the body) is read directly —
                // kotlinc does not hoist it into a second slot. Only a complex/reassigned bound is hoisted.
                // The direct read is valid ONLY when the local's slot already holds the counter's unboxed
                // scalar: a reference/boxed bound (an `Any`/`Int?` smart-cast to `Int`) would put an
                // `Object` where the comparison expects an `int`, so it must take the coercing hoist path.
                let end_local = if inline_bound.is_none() {
                    self.expr_as_reusable_local(range.end, body).filter(|_| {
                        match self.afile.expr(range.end) {
                            Expr::Name(n) => self
                                .lookup(n)
                                .is_some_and(|(_, ty)| self.has_scalar_value_repr(ty)),
                            _ => true,
                        }
                    })
                } else {
                    None
                };
                let (var_end, end_v) = if inline_bound.is_some() {
                    (None, None)
                } else if let Some(idx) = end_local {
                    (None, Some(idx))
                } else {
                    let end_e = self.lower_arg(range.end, &elem_ir)?;
                    let ev = self.fresh_value();
                    let var = self.emit_variable(ev, elem_ir.clone(), Some(end_e));
                    (Some(var), Some(ev))
                };
                // condition. Constant bound: a single `i < C`. Otherwise compare against the hoisted
                // bound; unsigned element types use the platform unsigned comparator.
                let cmp = match range.kind {
                    RangeKind::Through => IrBinOp::Le,
                    RangeKind::Until => IrBinOp::Lt,
                    RangeKind::DownTo => IrBinOp::Ge,
                };
                let cond = if let Some(b) = inline_bound {
                    let gi = self.emit_get_value(i_v);
                    let c = self.emit_const(IrConst::Int(b));
                    // Descending compares the constant against the counter (`C-1 < i`) so the emitted
                    // operand order (`iconst C-1; iload i; if_icmpge`) matches kotlinc; ascending is `i < C`.
                    let (lhs, rhs) = if matches!(range.kind, RangeKind::DownTo) {
                        (c, gi)
                    } else {
                        (gi, c)
                    };
                    self.emit_primitive_bin_op(IrBinOp::Lt, lhs, rhs)
                } else {
                    let gi = self.emit_get_value(i_v);
                    let ge = self.emit_get_value(end_v.unwrap());
                    self.compare_ordered(elem, cmp, gi, ge)?
                };
                // body + increment
                let mut out = Vec::new();
                if self.append_body_stmts(body, &mut out).is_none() {
                    self.scope.truncate(depth);
                    return None;
                }
                // The counted `Stmt::For` is always unit-step: a range with a `step` (or any trailing
                // infix) is parsed as a progression value and lowered by `lower_foreach_progression`.
                let step = self.emit_const(one);
                let inc_op = if matches!(range.kind, RangeKind::DownTo) {
                    IrBinOp::Sub
                } else {
                    IrBinOp::Add
                };
                let gi2 = self.emit_get_value(i_v);
                let inc_val = self.emit_primitive_bin_op(inc_op, gi2, step);
                // The increment is the loop `update` (runs at the `continue` target), not a body stmt —
                // so `continue` advances the counter instead of skipping it.
                let inc = self.emit_set_value(i_v, inc_val);
                // Non-overflowing loop: break when the counter reaches the (inclusive) bound, *before*
                // the increment — so `0..Int.MAX_VALUE` / `x downTo Int.MIN_VALUE` don't wrap past it and
                // loop forever. The break + increment are the loop `update` (the `continue` target), so a
                // `continue` also hits the bound check instead of skipping to the wrapping increment.
                // Skip the overflow break entirely when the loop can't wrap past its bound: a constant
                // inline bound (folded to `i < C`), or an exclusive `until` (the counter never reaches
                // `end`). kotlinc emits no guard there. Every other form keeps the `i == end` break.
                let no_guard = inline_bound.is_some() || matches!(range.kind, RangeKind::Until);
                let update = if no_guard {
                    inc
                } else {
                    let end_v = end_v.unwrap();
                    let ic = self.emit_get_value(i_v);
                    let ec = self.emit_get_value(end_v);
                    let at_end = self.emit_primitive_bin_op(IrBinOp::Eq, ic, ec);
                    let brk = self.emit_break(None);
                    let if_break = self.emit_when(vec![(Some(at_end), brk)]);
                    self.emit_block(vec![if_break, inc], None)
                };
                let wbody = self.emit_block(out, None);
                let wh = self.emit_while(cond, wbody, Some(update), false, label);
                self.scope.truncate(depth);
                let mut prologue = vec![var_i];
                if let Some(ve) = var_end {
                    prologue.push(ve);
                }
                prologue.push(wh);
                Some(self.emit_block(prologue, None))
            }
            // `for (x in arr)` over an array → an index loop `i=0; while (i<arr.size) { x=arr[i]; …; i++ }`.
            Stmt::ForEach {
                name,
                iterable,
                body,
                label,
            } => self.lower_for_each(&name, iterable, body, label, false),
            // A local-function declaration emits no code here — its body is lifted to a separate static
            // method (pass 2'); a call to it routes to that method.
            Stmt::LocalFun(_) => Some(self.emit_block(vec![], None)),
            // A local class is lowered via its hoisted top-level `Decl::Class`; the in-body statement
            // emits nothing.
            Stmt::LocalClass(_) => Some(self.emit_block(vec![], None)),
        }
    }

    /// Lower a `for (name in iterable) body` (also the inlined target of `iterable.forEach { … }`):
    /// dispatch to the counted range loop, the array/`String` index loop, or the iterator protocol.
    /// Whether `e`'s AST subtree contains a SUSPEND call (a call the checker resolved to a suspend
    /// member/function). Stops at a nested `Lambda` (its body is a separate scope). Used to gate the
    /// suspend-only inline-HOF loop desugar below: a non-suspend HOF keeps its normal library call.
    fn ast_subtree_suspends(&self, e: AstExprId) -> bool {
        let call_suspends = self.info.resolved_member(e).is_some_and(|m| m.suspend)
            || self.info.resolved_extension(e).is_some_and(|c| c.suspend)
            || self.info.resolved_top_level(e).is_some_and(|c| c.suspend)
            || self
                .info
                .resolved_module_top_level(e)
                .is_some_and(|c| c.suspend)
            || self.info.resolved_companion(e).is_some_and(|m| m.suspend);
        if call_suspends {
            return true;
        }
        if matches!(self.afile.expr(e), Expr::Lambda { .. }) {
            return false;
        }
        self.afile
            .any_child_expr(e, &mut |c| self.ast_subtree_suspends(c), &mut |s| {
                self.afile
                    .any_child_stmt(s, &mut |c| self.ast_subtree_suspends(c))
            })
    }

    /// Whether `internal` is (or transitively extends) a `Collection` — so a value of it can be passed to
    /// `java.util.Collection.addAll`. Used to gate the flatMap loop desugar.
    fn type_is_collection(&self, internal: TypeName) -> bool {
        let is_coll = |n: TypeName| {
            n.matches("kotlin/collections/Collection")
                || n.matches("kotlin/collections/MutableCollection")
                || n.matches("kotlin/collections/List")
                || n.matches("kotlin/collections/MutableList")
                || n.matches("kotlin/collections/Set")
                || n.matches("kotlin/collections/MutableSet")
                || n.matches("java/util/Collection")
                || n.matches("java/util/List")
                || n.matches("java/util/Set")
                || n.matches("java/util/ArrayList")
        };
        let mut stack = vec![internal];
        let mut seen = std::collections::HashSet::new();
        while let Some(i) = stack.pop() {
            if !seen.insert(i) {
                continue;
            }
            if is_coll(i) {
                return true;
            }
            if let Some(c) = self.syms.class_by_type_name(i) {
                if let Some(s) = c.super_internal_name() {
                    stack.push(s);
                }
                stack.extend(c.interface_names());
            } else if let Some(t) = self.syms.libraries.resolve_type_name(i) {
                stack.extend(t.supertypes.iter_ids());
            }
        }
        false
    }

    /// Desugar `recv.map { … }` / `recv.flatMap { … }` whose LAMBDA BODY suspends into an accumulating
    /// loop — `val acc = ArrayList(); for (e in recv) acc.add/addAll(<body>); acc` — exactly kotlinc's
    /// inline expansion. A stdlib collection HOF lowers its lambda to a separate `FunctionN` impl method,
    /// which cannot suspend; inlining it into the loop puts the suspension in an ordinary for-loop the
    /// coroutine pass already models. Gated to the suspend case only, so a non-suspend HOF keeps its
    /// byte-identical library call. `is_flat` selects `addAll` (flatMap) vs `add` (map). `None` (decline)
    /// when the receiver has no resolvable iterator (the caller falls back to the normal call path).
    /// The common concrete (non-`Nothing`/`Unit`) type of EVERY `return@<label>` value expression in
    /// `e`'s subtree — used to recover a `withLock`/inline-lambda result type that inference collapsed to
    /// `Nothing` because every path is a non-local return. Recurses into both `Stmt::Return` and
    /// `Expr::Return` forms and their surrounding constructs (a `?.let { return@label v }` nests the
    /// return under a safe-call/lambda). Returns `None` when there is no such return OR the returns
    /// disagree: a heterogeneous set has no single result-slot type, so the caller must DECLINE rather
    /// than coerce every value to one arbitrarily-picked type (a wrong `checkcast` / narrowed slot).
    fn labeled_return_ty(&self, e: AstExprId, label: &str) -> Option<Ty> {
        let tys: std::cell::RefCell<Vec<Ty>> = std::cell::RefCell::new(Vec::new());
        self.collect_labeled_return_tys(e, label, &tys);
        let tys = tys.into_inner();
        let first = *tys.first()?;
        tys.iter().all(|t| *t == first).then_some(first)
    }

    fn collect_labeled_return_tys(
        &self,
        e: AstExprId,
        label: &str,
        out: &std::cell::RefCell<Vec<Ty>>,
    ) {
        if let Expr::Return {
            value: Some(v),
            label: Some(l),
        } = self.afile.expr(e)
        {
            if l == label {
                let t = self.info.ty(*v);
                if !matches!(t, Ty::Nothing | Ty::Unit) {
                    out.borrow_mut().push(t);
                }
            }
        }
        self.afile.any_child_expr(
            e,
            &mut |c| {
                self.collect_labeled_return_tys(c, label, out);
                false
            },
            &mut |s| {
                if let Stmt::Return(Some(v), Some(l)) = self.afile.stmt(s) {
                    if l == label {
                        let t = self.info.ty(*v);
                        if !matches!(t, Ty::Nothing | Ty::Unit) {
                            out.borrow_mut().push(t);
                        }
                    }
                }
                self.afile.any_child_stmt(s, &mut |c| {
                    self.collect_labeled_return_tys(c, label, out);
                    false
                });
                false
            },
        );
    }

    fn lower_suspend_withlock(
        &mut self,
        call: AstExprId,
        receiver: AstExprId,
        lbody: AstExprId,
    ) -> Option<u32> {
        let mutex_ty = self.info.ty(receiver);
        let receiver_internal = mutex_ty.obj_internal()?.to_string();
        let lock_m = self.info.synthetic_member_call(call, "lock")?.clone();
        let unlock_m = self.info.synthetic_member_call(call, "unlock")?.clone();
        let lock_owner = lock_m
            .owner
            .map(|owner| owner.render())
            .unwrap_or_else(|| receiver_internal.clone());
        let unlock_owner = unlock_m
            .owner
            .map(|owner| owner.render())
            .unwrap_or_else(|| receiver_internal.clone());
        // The withLock result type. When EVERY path of the lambda is a non-local `return@withLock`, type
        // inference gives the call (and the lambda body) `Nothing` — all paths diverge. A `Nothing`/`Unit`
        // result slot is wrong: it would carry zero JVM-slot words (colliding with the next local) and the
        // `return@withLock` handler would discard the returned value rather than store it. Recover the real
        // type from the returned expressions; DECLINE (`?`) when they have no single common type rather
        // than pick one arbitrarily and coerce the others to it.
        let rty = match self.info.ty(call) {
            Ty::Nothing | Ty::Unit => self.labeled_return_ty(lbody, "withLock")?,
            t => t,
        };
        let mutex_slot = self.fresh_value();
        let recv = self.expr(receiver)?;
        // NAMED: kotlinc's spliced `withLock` binds the receiver as the named inline local
        // `$this$withLock…` — in scope (and spilled) at every suspension inside the lock body.
        let var_mutex = self.emit_named_variable(mutex_slot, ty_to_ir(mutex_ty), Some(recv));
        let m1 = self.emit_get_value(mutex_slot);
        let null1 = self.emit_const(IrConst::Null);
        let lock_call = self.emit_virtual_call(
            lock_owner,
            lock_m.name.clone(),
            lock_m.descriptor.clone(),
            lock_m.is_interface,
            m1,
            vec![null1],
        );
        if lock_m.suspend {
            self.ir
                .suspend_calls
                .insert(lock_call, ty_to_ir(lock_m.ret));
        }
        let result_slot = self.fresh_value();
        let dflt = self.emit_zero_value(rty);
        let var_result = self.emit_variable(result_slot, ty_to_ir(rty), Some(dflt));
        let brk = format!("$withlock${}", self.fresh_value());
        // TAIL-position splice (`fun f(): T = mutex.withLock { … }`) whose result type IS the
        // function's return type: a non-local `return v` inside is equivalent to `return@withLock v`
        // and lowers through this frame (see `inline_lambda_ret`).
        let fn_tail = self.fn_body_tail == Some(call) && rty == self.cur_ret_ty;
        self.inline_lambda_ret.push((
            "withLock".to_string(),
            result_slot,
            brk.clone(),
            rty,
            fn_tail,
        ));
        let depth = self.scope.len();
        let body_val = self.expr(lbody);
        self.inline_lambda_ret.pop();
        self.scope.truncate(depth);
        let body_val = body_val?;
        let mut body_stmts: Vec<u32> = Vec::new();
        if self.info.ty(lbody) == Ty::Nothing {
            body_stmts.push(body_val);
        } else {
            // Surface a value-bearing Block's statements so suspensions inside them reach the
            // flattener at STATEMENT level — it doesn't split a suspension out of a `SetValue`
            // whose value is a whole block (`splice_return_blocks` runs only on the fn's top-level
            // body and never descends into this splice's loop). Only the trailing value flows into
            // the result slot. Iterate: an elvis/safe-call value may itself be a value-block.
            let mut v = body_val;
            while let IrExpr::Block {
                stmts,
                value: Some(inner),
            } = self.ir.exprs[v as usize].clone()
            {
                body_stmts.extend(stmts);
                v = inner;
            }
            body_stmts.push(self.emit_set_value(result_slot, v));
        }
        let brk_stmt = self.emit_break(Some(brk.clone()));
        body_stmts.push(brk_stmt);
        let loop_body = self.emit_block(body_stmts, None);
        let cond = self.emit_const(IrConst::Boolean(true));
        let whilew = self.emit_while(cond, loop_body, None, false, Some(brk));
        let m2 = self.emit_get_value(mutex_slot);
        let null2 = self.emit_const(IrConst::Null);
        let unlock_call = self.emit_virtual_call(
            unlock_owner,
            unlock_m.name.clone(),
            unlock_m.descriptor.clone(),
            unlock_m.is_interface,
            m2,
            vec![null2],
        );
        let try_body = self.emit_block(vec![whilew], None);
        let fin = self.emit_block(vec![unlock_call], None);
        let tryf = self.emit_try(try_body, vec![], Some(fin), Ty::Unit);
        let get = self.emit_get_value(result_slot);
        Some(self.emit_block(vec![var_mutex, lock_call, var_result, tryf], Some(get)))
    }

    fn lower_suspend_accumulate_hof(
        &mut self,
        is_flat: bool,
        param: &str,
        receiver: AstExprId,
        body: AstExprId,
    ) -> Option<u32> {
        let it_ty = self.info.ty(receiver);
        let protocol = self.info.iterator_protocol(receiver).cloned()?;
        let iter_dispatch = protocol.iterator;
        let iter_ty = protocol.iter_ty;
        let iter_internal = iter_ty.obj_internal()?;
        let hasnext_m = protocol.has_next;
        let next_m = protocol.next;
        let elem = protocol.elem_ty;

        // acc = new ArrayList()
        let acc_new = self.emit_new_external("java/util/ArrayList", "()V", vec![]);
        let acc_v = self.fresh_value();
        let acc_ty = Ty::obj("java/util/ArrayList");
        let var_acc = self.emit_named_variable(acc_v, ty_to_ir(acc_ty), Some(acc_new));

        // it = recv.iterator()  — kotlinc's inline expansion is TWO frames deep
        // (`flatMap` → `flatMapTo`, `map` → `mapTo`), each binding the receiver to a named inline
        // local (`$this$flatMap$iv`, then `$this$flatMapTo$iv$iv`); both join the suspend spill
        // scope like any named var.
        let recv = self.expr(receiver)?;
        let recv_v = self.fresh_value();
        let var_recv = self.emit_named_variable(recv_v, ty_to_ir(it_ty), Some(recv));
        let recv_g0 = self.emit_get_value(recv_v);
        let recv_to_v = self.fresh_value();
        let var_recv_to = self.emit_named_variable(recv_to_v, ty_to_ir(it_ty), Some(recv_g0));
        let recv_g = self.emit_get_value(recv_to_v);
        let iter_call = match iter_dispatch {
            IteratorDispatchTarget::Member {
                owner_fallback,
                member,
            } => {
                let ret = member.ret;
                let suspend = member.suspend;
                self.emit_library_member_call(recv_g, owner_fallback, *member, ret, suspend, vec![])
            }
            IteratorDispatchTarget::Extension(callable) => {
                self.emit_library_static_call(*callable, vec![recv_g], false)
            }
        };
        let it_v = self.fresh_value();
        let var_it = self.emit_named_variable(it_v, ty_to_ir(iter_ty), Some(iter_call));

        // cond: it.hasNext()
        let it_g = self.emit_get_value(it_v);
        let hasnext_ret = hasnext_m.ret;
        let hasnext_suspend = hasnext_m.suspend;
        let cond = self.emit_library_member_call(
            it_g,
            iter_internal,
            hasnext_m,
            hasnext_ret,
            hasnext_suspend,
            vec![],
        );

        // body: e = (elem) it.next(); acc.add/addAll(<inlined lambda body>)
        let it_g2 = self.emit_get_value(it_v);
        let next_ret = next_m.ret;
        let next_suspend = next_m.suspend;
        let next_call = self.emit_library_member_call(
            it_g2,
            iter_internal,
            next_m,
            next_ret,
            next_suspend,
            vec![],
        );
        // Coerce the `Object` iterator result to the element type — the SAME four-way split
        // `lower_foreach_iterator` uses: unbox an unsigned/scalar-value-class element (a `checkcast` +
        // `istore` would store a reference into a primitive slot → VerifyError), else `checkcast` a
        // concrete reference, else leave `Any` as-is.
        let elem_val = if elem.is_unsigned() {
            self.unbox_unsigned(next_call, elem)?
        } else if self.has_scalar_value_repr(elem) {
            self.emit_type_op(IrTypeOp::ImplicitCoercion, next_call, ty_to_ir(elem))
        } else if elem != Ty::obj("kotlin/Any") {
            self.emit_type_op(IrTypeOp::Cast, next_call, ty_to_ir(elem))
        } else {
            next_call
        };
        // Bind the element to the lambda's parameter, then lower the lambda body and bind ITS value to a
        // fresh local — as SEPARATE statements, not a bundled block. The body value can be a suspend call;
        // the coroutine pass surfaces a suspension from a plain `Variable{ init: <suspend call> }` (in a
        // loop body it already models), but NOT from a block-valued init inside a loop nor from a call
        // argument. So `val e = next; val part = <body>; acc.add*(part)`.
        let depth = self.scope.len();
        // kotlinc binds the loop ELEMENT (`element$iv$iv`) and the lambda PARAMETER (`it`) as
        // SEPARATE named locals — both join the suspend spill scope.
        let elem_iv = self.fresh_value();
        let var_e = self.emit_named_variable(elem_iv, ty_to_ir(elem), Some(elem_val));
        let elem_bv = self.fresh_value();
        self.scope.push((param.to_string(), elem_bv, elem));
        let elem_g = self.emit_get_value(elem_iv);
        let var_p = self.emit_named_variable(elem_bv, ty_to_ir(elem), Some(elem_g));
        let body_val = self.expr(body);
        self.scope.truncate(depth);
        let body_val = body_val?;
        // The lambda body lowers to a value-block (`{ stmts…; value }`). Splice its statements into the
        // loop and bind `part` to the block's VALUE — a plain `Variable{ init: <value> }` the coroutine
        // pass surfaces (a block-valued init inside a loop body isn't normalized).
        let (mut loop_stmts, body_v) = match self.ir.exprs[body_val as usize].clone() {
            IrExpr::Block {
                stmts,
                value: Some(v),
            } => (stmts, v),
            _ => (Vec::new(), body_val),
        };
        let part_ty = self.info.ty(body);
        // flatMap emits `ArrayList.addAll(Collection)`, but kotlinc's flatMap accepts any `Iterable` and
        // handles a non-`Collection` via an iterating extension we don't model here — so decline (the
        // caller falls back / the file bails) when the element result isn't a `Collection` subtype.
        if is_flat
            && !part_ty
                .obj_internal()
                .is_some_and(|i| self.type_is_collection(i))
        {
            self.scope.truncate(depth);
            return None;
        }
        let part_v = self.fresh_value();
        let var_part = self.emit_variable(part_v, ty_to_ir(part_ty), Some(body_v));
        let acc_g = self.emit_get_value(acc_v);
        let part_g = self.emit_get_value(part_v);
        let (add_name, add_desc, add_arg) = if is_flat {
            ("addAll", "(Ljava/util/Collection;)Z", part_g)
        } else {
            // `add(Object)` takes a reference — box a value/primitive result.
            let boxed = self.emit_type_op(
                IrTypeOp::ImplicitCoercion,
                part_g,
                ty_to_ir(Ty::obj("kotlin/Any")),
            );
            ("add", "(Ljava/lang/Object;)Z", boxed)
        };
        let add_call = self.emit_virtual_call(
            "java/util/ArrayList".to_string(),
            add_name.to_string(),
            add_desc.to_string(),
            false,
            acc_g,
            vec![add_arg],
        );
        let mut wstmts = vec![var_e, var_p];
        wstmts.append(&mut loop_stmts);
        wstmts.push(var_part);
        wstmts.push(add_call);
        let wbody = self.emit_block(wstmts, None);
        let wh = self.emit_while(cond, wbody, None, false, None);
        let acc_read = self.emit_get_value(acc_v);
        Some(self.emit_block(
            vec![var_recv, var_acc, var_recv_to, var_it, wh],
            Some(acc_read),
        ))
    }

    fn lower_for_each(
        &mut self,
        name: &str,
        iterable: AstExprId,
        body: AstExprId,
        label: Option<String>,
        hof_splice: bool,
    ) -> Option<u32> {
        let it_ty = self.info.ty(iterable);
        // A platform range/progression value may expose a counted-loop shape. The platform owns the
        // library class names, physical getter names, and descriptors; common lowering only builds the
        // generic loop once that shape is supplied.
        if let Some(loop_info) = it_ty
            .obj_internal()
            .and_then(|internal| self.runtime.counted_loop_info_name(internal))
        {
            return if loop_info.step.is_some() {
                self.lower_foreach_progression(name, iterable, body, it_ty, loop_info, label)
            } else {
                self.lower_foreach_range(name, iterable, body, it_ty, loop_info, label)
            };
        }
        // An array, or a `String` (iterated as its `Char`s), uses an index loop; any other iterable
        // (`List`, `Set`, a progression value, …) uses the iterator protocol.
        let elem = if it_ty == Ty::String {
            Some(Ty::Char)
        } else {
            it_ty.array_elem()
        };
        let Some(elem) = elem else {
            return self.lower_foreach_iterator(
                name,
                iterable,
                body,
                it_ty,
                ForeachOpts {
                    index: None,
                    label,
                    hof_splice,
                },
            );
        };
        let depth = self.scope.len();
        // Evaluate the array once. When the iterable is ALREADY a plain (non-boxed) local, iterate on
        // that local directly — kotlinc reuses the existing slot rather than storing a redundant copy.
        let (arr_v, var_arr) = if let Some(v) = self.expr_as_reusable_local(iterable, body) {
            (v, None)
        } else {
            let v = self.fresh_value();
            let arr_val = self.expr(iterable)?;
            let var = self.emit_variable(v, ty_to_ir(it_ty), Some(arr_val));
            (v, Some(var))
        };
        // i = 0
        let i_v = self.fresh_value();
        let zero = self.emit_const(IrConst::Int(0));
        let var_i = self.emit_variable(i_v, ty_to_ir(Ty::Int), Some(zero));
        // n = arr.size (hoisted)
        let n_v = self.fresh_value();
        let arr_g = self.emit_get_value(arr_v);
        let size = if it_ty == Ty::String {
            self.emit_external_call("kotlin/String.length", Some(arr_g), vec![])
        } else {
            self.emit_external_call("kotlin/Array.size", Some(arr_g), vec![])
        };
        let var_n = self.emit_variable(n_v, ty_to_ir(Ty::Int), Some(size));
        // condition: i < n
        let gi = self.emit_get_value(i_v);
        let gn = self.emit_get_value(n_v);
        let cond = self.emit_primitive_bin_op(IrBinOp::Lt, gi, gn);
        // loop var `x = arr[i]`, bound for the body
        let x_v = self.fresh_value();
        self.scope.push((name.to_string(), x_v, elem));
        let arr_g2 = self.emit_get_value(arr_v);
        let gi2 = self.emit_get_value(i_v);
        let elem_get = if it_ty == Ty::String {
            self.emit_external_call("kotlin/String.get", Some(arr_g2), vec![gi2])
        } else {
            self.emit_external_call("kotlin/Array.get", Some(arr_g2), vec![gi2])
        };
        let var_x = self.emit_variable(x_v, ty_to_ir(elem), Some(elem_get));
        let mut out = vec![var_x];
        if self.append_body_stmts(body, &mut out).is_none() {
            self.scope.truncate(depth);
            return None;
        }
        let gi3 = self.emit_get_value(i_v);
        let one = self.emit_const(IrConst::Int(1));
        let inc = self.emit_primitive_bin_op(IrBinOp::Add, gi3, one);
        let incs = self.emit_set_value(i_v, inc);
        let wbody = self.emit_block(out, None);
        let wh = self.emit_while(cond, wbody, Some(incs), false, label);
        self.scope.truncate(depth);
        let mut stmts = Vec::new();
        if let Some(va) = var_arr {
            stmts.push(va);
        }
        stmts.extend([var_i, var_n, wh]);
        Some(self.emit_block(stmts, None))
    }

    /// If `e` is a plain (non-boxed) local variable read that the loop `body` does NOT reassign, its IR
    /// value index — so a loop over it (`for (x in localArr)`, or a counted loop whose bound is a local)
    /// reads the existing local directly instead of snapshotting a copy, matching kotlinc. `None`
    /// otherwise (then it's stored into a fresh temp): kotlinc snapshots a value whose backing `var` is
    /// reassigned in the body so the loop keeps the ORIGINAL — reusing the live local would read the new.
    fn expr_as_reusable_local(&self, e: AstExprId, body: AstExprId) -> Option<u32> {
        if let Expr::Name(n) = self.afile.expr(e) {
            let n = n.clone();
            if self.boxed_elem.contains_key(&n) || self.expr_reassigns_name(body, &n) {
                return None;
            }
            return self.lookup(&n).map(|(v, _)| v);
        }
        None
    }

    /// Whether `name` is reassigned (`name = …`) anywhere in the expression subtree `e`.
    fn expr_reassigns_name(&self, e: AstExprId, name: &str) -> bool {
        self.afile
            .any_child_expr(e, &mut |x| self.expr_reassigns_name(x, name), &mut |s| {
                self.stmt_reassigns_name(s, name)
            })
    }

    /// Whether statement `s` (or a nested expression) reassigns `name`.
    fn stmt_reassigns_name(&self, s: crate::ast::StmtId, name: &str) -> bool {
        if let Stmt::Assign { name: n, .. } = self.afile.stmt(s) {
            if n == name {
                return true;
            }
        }
        self.afile
            .any_child_stmt(s, &mut |x| self.expr_reassigns_name(x, name))
    }

    /// Whether a `Stmt::AssignIndex` is a desugared compound assign (`a[i] op= v`): the parser emits
    /// `value = (a[i]) op v` reusing the SAME `array`/`index` expr ids, so the embedded `Index` matches.
    /// Lower the STORE of `receiver.name = value` (the receiver already spilled by the caller when
    /// compound). Dispatches to an extension-property setter, a cross-file/classpath setter, the
    /// declaring class's `setX()` accessor, or a direct `putfield`.
    fn lower_assign_member(
        &mut self,
        stmt: ast::StmtId,
        receiver: AstExprId,
        name: &str,
        value: AstExprId,
    ) -> Option<u32> {
        let rt = self.info.ty(receiver);
        // A `var` extension property write (`x.name = v`) → its static setter `setName(x, v)`.
        if let Some(sfid) = self.ext_prop_set_id(rt, name) {
            let rty = self.ir.functions[sfid as usize]
                .params
                .first()
                .cloned()
                .unwrap_or_else(|| ty_to_ir(rt));
            let pty = self.ir.functions[sfid as usize]
                .params
                .get(1)
                .cloned()
                .unwrap_or_else(|| ty_to_ir(self.info.ty(value)));
            let r = self.lower_arg(receiver, &rty)?;
            let v = self.lower_arg(value, &pty)?;
            return Some(self.emit_local_call(sfid, vec![r, v]));
        }
        // A property write on a `var` of a class defined in ANOTHER file → its `setX(v)` accessor
        // (the backing field is private). A cross-file `val` write bails.
        if self.class_of(rt).is_none() {
            if let Ty::Obj(i, _) = &rt {
                if let Some((owner, pty, is_var, interface)) = self
                    .syms
                    .class_by_type_name(*i)
                    .filter(|cs| cs.value_field.is_none())
                    .and_then(|cs| {
                        cs.props.iter().find_map(|(n, t, v)| {
                            (n.as_str() == name).then_some((*i, *t, *v, cs.is_interface))
                        })
                    })
                {
                    if !is_var {
                        return None;
                    }
                    let r = self.expr(receiver)?;
                    let v = self.lower_arg(value, &ty_to_ir(pty))?;
                    return Some(self.emit_call(
                        Callee::CrossFileVirtual {
                            owner,
                            name: property_setter_name(name),
                            params: vec![ty_to_ir(pty)],
                            ret: Ty::Unit,
                            interface,
                        },
                        Some(r),
                        vec![v],
                    ));
                }
            }
        }
        // A `var` member of a CLASSPATH type → its setter resolved by real `@Metadata` name
        // (mirrors the getter read in `lower_member_read_on`). The setter `LibraryCallable`
        // carries the owner/descriptor for the `invokevirtual`; its parameter type coerces the
        // value (`Int` literal into a `Long` setter).
        if self.class_of(rt).is_none() {
            if let Ty::Obj(_, _) = &rt {
                if let Some(setter) = self.info.property_setter(stmt).cloned() {
                    let pty = setter
                        .params
                        .first()
                        .map(|t| ty_to_ir(*t))
                        .unwrap_or_else(|| ty_to_ir(self.info.ty(value)));
                    let setter_owner = setter.owner_type();
                    let is_iface = self.library_type_is_interface(setter_owner);
                    let r = self.expr(receiver)?;
                    let v = self.lower_arg(value, &pty)?;
                    return Some(self.emit_virtual_call(
                        setter_owner,
                        setter.name,
                        setter.descriptor,
                        is_iface,
                        r,
                        vec![v],
                    ));
                }
            }
        }
        let owner_internal = self.class_of(rt)?.internal();
        // The backing field is private; a write from outside the declaring class goes through
        // the public `setX()` accessor (matching kotlinc). Inside the class, write directly.
        if self.cur_class != existing_type_name(&owner_internal) {
            if let Some((mclass, mindex, mfid, _)) =
                self.resolve_method(&owner_internal, &property_setter_name(name))
            {
                let pty = self.ir.functions[mfid as usize].params[0].clone();
                let r = self.expr(receiver)?;
                let v = self.lower_arg(value, &pty)?;
                return Some(self.emit_method_call(mclass, mindex, r, vec![Some(v)]));
            }
        }
        let (class, idx, field_ty) = {
            let ci = self.class_of(rt)?;
            let idx = ci.fields.iter().position(|(fn_, _)| fn_.as_str() == name)? as u32;
            (ci.id, idx, ty_to_ir(ci.fields[idx as usize].1))
        };
        let r = self.expr(receiver)?;
        // Coerce the value to the field's type (e.g. `Int` literal into a `Long` field).
        let v = self.lower_arg(value, &field_ty)?;
        Some(self.emit_set_field(r, class, idx, v))
    }

    /// Whether `receiver.name = value` is a compound assignment (`receiver.name op= …`): the parser
    /// desugars it to `receiver.name = receiver.name op rhs`, so the `value` is a `Binary` whose left
    /// operand re-reads the SAME `receiver`/`name`. The caller spills a side-effecting receiver once.
    fn is_compound_member_assign(&self, receiver: AstExprId, name: &str, value: AstExprId) -> bool {
        if let Expr::Binary { lhs, .. } = self.afile.expr(value) {
            if let Expr::Member {
                receiver: r2,
                name: n2,
            } = self.afile.expr(*lhs)
            {
                return *r2 == receiver && n2.as_str() == name;
            }
        }
        false
    }

    fn is_compound_index_assign(
        &self,
        array: AstExprId,
        index: AstExprId,
        value: AstExprId,
    ) -> bool {
        let Expr::Binary { lhs, .. } = self.afile.expr(value) else {
            return false;
        };
        let Expr::Index { array: a2, indices } = self.afile.expr(*lhs) else {
            return false;
        };
        *a2 == array && matches!(indices.as_slice(), [only] if *only == index)
    }

    /// Whether an index-assign receiver/index operand is side-effect-free, so re-evaluating it (rather
    /// than spilling to a temp) is sound and keeps bytecode parity with kotlinc. A bare `Name` qualifies
    /// ONLY when it is a local variable: a property `Name` may be a getter call with side effects (kotlinc
    /// evaluates the index once), so it is spilled.
    fn is_pure_index_operand(&self, e: AstExprId) -> bool {
        match self.afile.expr(e) {
            Expr::Name(n) => self.lookup(n).is_some(),
            Expr::IntLit(_)
            | Expr::LongLit(_)
            | Expr::UIntLit(_)
            | Expr::ULongLit(_)
            | Expr::CharLit(_)
            | Expr::BoolLit(_)
            | Expr::NullLit => true,
            _ => false,
        }
    }

    /// Lower the STORE of an index-assign `array[index] = value` (the receiver/index already spilled by
    /// the caller when compound). Dispatches to a user `operator fun set`, a library `set`/`put`, or the
    /// `kotlin/Array.set` intrinsic.
    fn lower_index_store(
        &mut self,
        stmt: ast::StmtId,
        array: AstExprId,
        index: AstExprId,
        value: AstExprId,
    ) -> Option<u32> {
        let at = self.info.ty(array);
        // A non-array receiver uses the checker-selected `set`/`put` operator target. A non-array object
        // without a recorded operator is NOT an array, so bail rather than fall through to `aastore`.
        if at.array_elem().is_none() && at.obj_internal().is_some() {
            let vt = self.info.ty(value);
            if matches!(
                self.info
                    .resolved_stmt_operator_call(stmt, "set")
                    .or_else(|| self.info.resolved_stmt_operator_call(stmt, "put")),
                Some(ResolvedCall::Member(_))
            ) {
                // A narrowing store into a primitive-element collection (`List<Byte>[i] = intVal`) needs
                // `(value).toByte()` before boxing as the element wrapper — not yet modeled. Bail (skip the
                // file) rather than box the wrong wrapper type.
                if let Some(elem) = self.info.resolved_index_store_get_return(stmt) {
                    if self.has_scalar_value_repr(elem) && elem != vt {
                        return None;
                    }
                }
            }
            let recv_v = self.expr(array)?;
            if let Some((v, _)) = self.lower_stmt_op_call(stmt, recv_v, at, "set", &[index, value])
            {
                return Some(v);
            }
            if let Some((v, _)) = self.lower_stmt_op_call(stmt, recv_v, at, "put", &[index, value])
            {
                return Some(v);
            }
            return None;
        }
        let a = self.expr(array)?;
        // The index is always an `Int` — unbox a generic/erased `Object` index (a destructured
        // `IndexedValue` element used as `arr[value]`) so `aastore`/`iastore` gets an `int`, not an `Object`.
        let i = self.lower_arg(index, &ty_to_ir(Ty::Int))?;
        // Coerce the element to the array's element type (boxing/unboxing, and materializing
        // `Unit.INSTANCE` for a `Unit` value into an `Array<Any>`) — same as the user-`set`/
        // collection paths above, rather than storing the raw value. EXCEPT a NON-NULL primitive element
        // (`Array<Int>` = `Integer[]`): `kotlin/Array.set` boxes the value exactly ONCE before `aastore`,
        // so pass it the UNBOXED primitive — coercing to the boxed element would double-box (`valueOf`
        // fed an `Integer`). A NULLABLE element (`Array<Int?>`) keeps `boxed_prim_of == None`, so
        // `Array.set` does NOT box: coerce the value to the boxed element (`Integer`/`null`) here instead.
        let elem = at.array_elem().unwrap_or_else(|| Ty::obj("kotlin/Any"));
        let en = elem.non_null();
        let value_ty =
            if !elem.is_nullable() && (en.is_jvm_scalar() || en.unboxed_primitive().is_some()) {
                en.unboxed_primitive().unwrap_or(en)
            } else {
                elem
            };
        let v = self.lower_arg(value, &ty_to_ir(value_ty))?;
        Some(self.emit_external_call("kotlin/Array.set", Some(a), vec![i, v]))
    }

    /// Substitute a reified type-parameter reference (`is T`/`as T`/`T::class` inside an expanded
    /// `<reified T>` inline body) with the concrete type bound at the call site. Nullability is the
    /// union of the reference's and the bound type's. Unchanged when no reified binding is active.
    fn subst_type_ref(&self, tr: &ast::TypeRef) -> ast::TypeRef {
        for frame in self.reified_subst.iter().rev() {
            if let Some(bound) = frame.get(&tr.name) {
                let mut out = bound.clone();
                out.nullable = out.nullable || tr.nullable;
                return out;
            }
        }
        tr.clone()
    }

    /// Expand a call to a user-defined `inline fun`: bind its value parameters to the (once-evaluated)
    /// arguments, register its lambda arguments for inlining at their invoke sites, then lower its body
    /// in place — exactly what kotlinc's inliner does. Returns `None` (the file bails, never miscompiles)
    /// for anything outside the supported subset. `call_id` is the call expression (for reified type args).
    fn lower_inline_fn_call(
        &mut self,
        fname: &str,
        args: &[AstExprId],
        call_id: u32,
        recv: Option<AstExprId>,
        module_target: Option<&ResolvedModuleTopLevelCall>,
    ) -> Option<u32> {
        // Find the selected source declaration. Receiver-less module calls carry the checker's
        // declaration key; extension inline calls still use the receiver-qualified declaration path.
        let f = if let Some(target) = module_target {
            if recv.is_some() || target.name != fname || target.source_file != Some(self.file_index)
            {
                return None;
            }
            let decl = target.source_decl?;
            match self.afile.decl(decl) {
                Decl::Fun(f) if f.name == fname && f.receiver.is_none() => f.clone(),
                _ => return None,
            }
        } else {
            self.afile
                .decls
                .iter()
                .find_map(|&d| match self.afile.decl(d) {
                    Decl::Fun(f) if f.name == fname && f.receiver.is_some() == recv.is_some() => {
                        Some(f)
                    }
                    _ => None,
                })?
                .clone()
        };
        // A non-extension call must hit a non-extension fn and vice versa. An extension binds its receiver
        // as `this` (below). No default/vararg params. Non-reified generic type params are SPECIALIZED
        // from the actual argument types; REIFIED type params are bound to the call's explicit type
        // arguments and substituted into `is T`/`as T`/`T::class` in the body.
        if f.receiver.is_some() != recv.is_some() {
            return None;
        }
        // The extension receiver type (`inline fun String.foo()` → `String`), or `None` for a plain fn.
        // A GENERIC receiver (`<T> T.foo()`) is specialized to the ACTUAL receiver's type at the call site.
        let recv_ty = match (&f.receiver, recv) {
            (Some(r), Some(ra)) => {
                let t = if f.type_params.iter().any(|tp| tp == &r.name) {
                    self.recv_ty(ra)
                } else {
                    ty_of(self.afile, r, &*self.syms.libraries)
                };
                if t == Ty::Error {
                    return None;
                }
                Some(t)
            }
            (None, None) => None,
            _ => return None,
        };
        // Default parameters ARE modeled (an inline fn substitutes the default expression directly — no
        // `$default` method): an omitted parameter is filled with its default below. A `vararg` IS
        // supported, but only as the LAST parameter of a plain (non-extension) inline fn whose element
        // isn't a type parameter or a function type. The two aren't combined (rare) — bail on the overlap.
        let has_default = f.params.iter().any(|p| p.default.is_some());
        let vararg = f.params.last().is_some_and(|p| p.is_vararg);
        if has_default && vararg {
            return None;
        }
        if f.params.iter().rev().skip(1).any(|p| p.is_vararg) {
            return None; // a non-last vararg (only reachable with trailing named args) — bail
        }
        if vararg {
            let vp = f.params.last().unwrap();
            let is_tparam = f.type_params.iter().any(|tp| tp == &vp.ty.name);
            if recv_ty.is_some() || is_tparam || !vp.ty.fun_params.is_empty() {
                return None;
            }
        }
        let body = match f.body {
            FunBody::Expr(e) | FunBody::Block(e) => e,
            FunBody::None => return None,
        };
        let pnames: Vec<String> = f.params.iter().map(|p| p.name.clone()).collect();
        // A body with `return`s is wrapped in a `do { … } while(false)` and each `return` becomes
        // `result = x; break` (see below). A `return` lexically inside a *nested lambda* of the body
        // would be a non-local return targeting the WRONG inline level — but a lambda argument carrying a
        // return is already pre-bailed at registration, so the only returns that survive are direct.
        let has_return = body_has_return(self.afile, body);
        // Whether every path through the body returns/throws (its checked type is `Nothing`) — then the
        // `do…while` wrapper omits the unreachable fall-through (avoids an unframed dead `goto` tail).
        let body_diverges = self.info.ty(body) == Ty::Nothing;
        // Value-parameter types + return type. An extension is keyed in `ext_funs` by `(erased
        // receiver, name)` with value params only; a GENERIC extension isn't registered there (its
        // receiver erased to `Any`), so derive from the decl.
        let (sig_params, sig_ret): (Vec<Ty>, Ty) = if let Some(rt) = &recv_ty {
            // Match THIS declaration's overload by its parameter list (an extension may be overloaded
            // by arity); fall back to the first overload when the decl's types don't line up.
            let want: Vec<Ty> = f
                .params
                .iter()
                .map(|p| ty_of(self.afile, &p.ty, &*self.syms.libraries))
                .collect();
            let overloads = self.syms.ext_fun_overloads(*rt, fname);
            if let Some(s) = overloads
                .iter()
                .find(|s| s.params == want)
                .or_else(|| overloads.first())
            {
                (s.params.clone(), s.ret)
            } else {
                let ps = f
                    .params
                    .iter()
                    .map(|p| ty_of(self.afile, &p.ty, &*self.syms.libraries))
                    .collect();
                let r = f
                    .ret
                    .as_ref()
                    .map_or(Ty::Unit, |t| ty_of(self.afile, t, &*self.syms.libraries));
                (ps, r)
            }
        } else {
            if let Some(target) = module_target {
                (target.params.clone(), target.ret)
            } else {
                let want: Vec<Ty> = f
                    .params
                    .iter()
                    .map(|p| ty_of(self.afile, &p.ty, &*self.syms.libraries))
                    .collect();
                let s = self.syms.fun_by_params(fname, &want)?;
                (s.params.clone(), s.ret)
            }
        };
        if sig_params.len() != pnames.len() {
            return None;
        }
        // Fixed (non-vararg) parameter count. A vararg call supplies `>= n_fixed` arguments (the rest pack
        // into the trailing array); a non-vararg call must match exactly (after default-filling).
        let n_fixed = if vararg {
            sig_params.len() - 1
        } else {
            sig_params.len()
        };
        // Effective per-parameter arguments. For a non-vararg call, place named arguments at their declared
        // position and fill each omitted parameter with its default expression (an inline fn substitutes the
        // default directly — no `$default` method). A vararg call keeps the raw list (packed below).
        let eff_storage: Vec<AstExprId>;
        let has_named = self
            .afile
            .call_arg_names
            .get(&call_id)
            .is_some_and(|n| n.iter().any(|x| x.is_some()));
        let args: &[AstExprId] = if vararg {
            if args.len() < n_fixed {
                return None;
            }
            args
        } else if has_default || has_named {
            let names = self
                .afile
                .call_arg_names
                .get(&call_id)
                .cloned()
                .unwrap_or_default();
            let np = f.params.len();
            if args.len() > np {
                return None;
            }
            let mut slot: Vec<Option<AstExprId>> = vec![None; np];
            let mut pos = 0;
            for (i, &arg) in args.iter().enumerate() {
                match names.get(i).and_then(|o| o.as_ref()) {
                    None => {
                        if pos >= np {
                            return None;
                        }
                        slot[pos] = Some(arg);
                        pos += 1;
                    }
                    Some(nm) => {
                        let idx = f.params.iter().position(|p| &p.name == nm)?;
                        if slot[idx].is_some() {
                            return None;
                        }
                        slot[idx] = Some(arg);
                    }
                }
            }
            let mut eff = Vec::with_capacity(np);
            for (k, p) in f.params.iter().enumerate() {
                match slot[k] {
                    Some(a) => eff.push(a),
                    None => match p.default {
                        Some(d) => eff.push(d),
                        None => return None,
                    },
                }
            }
            eff_storage = eff;
            &eff_storage
        } else {
            if sig_params.len() != args.len() {
                return None;
            }
            args
        };
        // A genuinely recursive inline call re-enters the SAME call site, expanding without bound — bail
        // (skip). Source-level NESTING of the same fn (`a { a { 5 } }`) uses DISTINCT call sites, so it is
        // allowed. (kotlinc rejects only genuine recursion.)
        if self.inline_active.contains(&call_id) {
            return None;
        }
        // Specialize non-reified type params from the actual arguments: a parameter declared `T` binds
        // `T` to the call's concrete argument type, so the inlined body (and a lambda parameter typed `T`)
        // uses e.g. `Int` rather than the erased `Any`. Empty for a non-generic inline fn (no change).
        let tparams: std::collections::HashSet<&str> =
            f.type_params.iter().map(String::as_str).collect();
        let mut tbinds: std::collections::HashMap<String, Ty> = std::collections::HashMap::new();
        for (i, p) in f.params.iter().enumerate().take(n_fixed) {
            if tparams.contains(p.ty.name.as_str())
                && !matches!(self.afile.expr(args[i]), Expr::Lambda { .. })
            {
                tbinds
                    .entry(p.ty.name.clone())
                    .or_insert(self.info.ty(args[i]));
            }
        }
        // A generic-RECEIVER extension (`<T> T.foo`): bind the type parameter to the SPECIALIZED receiver
        // type, so a lambda parameter typed by it (`f: (T) -> …`) specializes too. Without this the lambda
        // param slot is typed the erased `Object` while the checker recorded the concrete type in its
        // frames — an inconsistent-frame `VerifyError` (`<T> T.alsoLog { … }` capturing a variable).
        if let (Some(rt), Some(recv_ref)) = (recv_ty, &f.receiver) {
            if tparams.contains(recv_ref.name.as_str()) {
                tbinds.entry(recv_ref.name.clone()).or_insert(rt);
            }
        }
        let active_depth = self.inline_active.len();
        self.inline_active.push(call_id);
        // Bind each reified type parameter to the call's explicit type argument (resolved through any
        // enclosing reified binding, so nested reified inlines compose). A missing arg (e.g. a purely
        // inferred reified type) bails — the file skips, never miscompiles.
        let reif_depth = self.reified_subst.len();
        if !f.reified_type_params.is_empty() {
            let targs = self.afile.call_type_args.get(&call_id);
            let mut map = std::collections::HashMap::new();
            for (i, tp) in f.type_params.iter().enumerate() {
                if f.reified_type_params.contains(tp) {
                    let actual = match targs.and_then(|ts| ts.get(i)) {
                        Some(a) => self.subst_type_ref(a),
                        None => {
                            self.inline_active.truncate(active_depth);
                            return None;
                        }
                    };
                    map.insert(tp.clone(), actual);
                }
            }
            self.reified_subst.push(map);
        }
        let depth = self.scope.len();
        let lam_depth = self.inline_lambdas.len();
        let mut stmts = Vec::new();
        // An extension fn binds its receiver as `this`: evaluate it once into a temp, visible as `this`
        // in the body (so `this`, `this.member`, and implicit-receiver member access all resolve to it).
        if let Some(rt) = &recv_ty {
            let recv_ast = match recv {
                Some(r) => r,
                None => {
                    self.scope.truncate(depth);
                    self.inline_active.truncate(active_depth);
                    self.reified_subst.truncate(reif_depth);
                    return None;
                }
            };
            let rt = *rt;
            let slot = self.fresh_value();
            let val = match self.lower_arg(recv_ast, &ty_to_ir(rt)) {
                Some(v) => v,
                None => {
                    self.scope.truncate(depth);
                    self.inline_active.truncate(active_depth);
                    self.reified_subst.truncate(reif_depth);
                    return None;
                }
            };
            stmts.push(self.emit_variable(slot, ty_to_ir(rt), Some(val)));
            self.scope.push(("this".to_string(), slot, rt));
        }
        for (i, pty) in sig_params.iter().enumerate() {
            // The trailing `vararg` parameter: pack the remaining arguments into a fresh array bound to it
            // (a `kotlin/Array`/`IntArray`/… local), exactly as the non-inline call site does. The inlined
            // body then iterates it normally.
            if vararg && i == n_fixed {
                let elem_ty = match pty.array_elem() {
                    Some(t) => t,
                    None => {
                        self.scope.truncate(depth);
                        self.inline_lambdas.truncate(lam_depth);
                        self.inline_active.truncate(active_depth);
                        self.reified_subst.truncate(reif_depth);
                        return None;
                    }
                };
                let elem_ir = ty_to_ir(elem_ty);
                let mut elements = Vec::new();
                for &arg in &args[n_fixed..] {
                    if is_branchy(self.afile, arg) {
                        self.scope.truncate(depth);
                        self.inline_lambdas.truncate(lam_depth);
                        self.inline_active.truncate(active_depth);
                        self.reified_subst.truncate(reif_depth);
                        return None;
                    }
                    match self.lower_arg(arg, &elem_ir) {
                        Some(v) => elements.push(v),
                        None => {
                            self.scope.truncate(depth);
                            self.inline_lambdas.truncate(lam_depth);
                            self.inline_active.truncate(active_depth);
                            self.reified_subst.truncate(reif_depth);
                            return None;
                        }
                    }
                }
                let arr = self.emit_vararg(ty_to_ir(*pty), elements);
                let slot = self.fresh_value();
                let var = self.emit_variable(slot, ty_to_ir(*pty), Some(arr));
                stmts.push(var);
                self.scope.push((pnames[i].clone(), slot, *pty));
                continue;
            }
            if let Ty::Fun(fnsig) = pty {
                // A lambda parameter is inline-SPLICED (its body expanded at each invoke site) only when it
                // is a literal lambda AND used solely as a callee (`f(args)`) in the body. If the parameter
                // is also used as a VALUE — passed to another call (`a(f)`), stored, or returned — it must
                // be materialized as a `FunctionN` instead (the value-binding branch below); a callable-ref
                // argument is never a body to splice.
                let arg_expr = self.afile.expr(args[i]).clone();
                let splice = matches!(arg_expr, Expr::Lambda { .. })
                    && !name_used_as_value(self.afile, body, &pnames[i]);
                if let (
                    true,
                    Expr::Lambda {
                        params,
                        body: lbody,
                    },
                ) = (splice, arg_expr)
                {
                    // A single-parameter lambda may name its parameter implicitly as `it`.
                    let params = ast::lambda_params_or_implicit(&params, fnsig.params.len())?;
                    // A bare `return` (non-local) or a `return@other` in the lambda body isn't modeled —
                    // bail. A `return@<thisInlineFn>` IS modeled (a local return from the spliced lambda,
                    // handled by the `inline_lambda_ret` frame set up at the invoke site), so it's allowed.
                    if body_has_disallowed_return(self.afile, lbody, fname)
                        || params.len() != fnsig.params.len()
                    {
                        self.scope.truncate(depth);
                        self.inline_lambdas.truncate(lam_depth);
                        self.inline_active.truncate(active_depth);
                        self.reified_subst.truncate(reif_depth);
                        return None;
                    }
                    // The lambda's parameter types, with the inline fn's type params specialized
                    // (`(T)->T` on a `twice(1){…}` call → `it: Int`, not the erased `Any` of `fnsig`).
                    let lam_param_tys: Vec<Ty> = f.params[i]
                        .ty
                        .fun_params
                        .iter()
                        .map(|fp| {
                            tbinds
                                .get(fp.name.as_str())
                                .copied()
                                .unwrap_or_else(|| ty_of(self.afile, fp, &*self.syms.libraries))
                        })
                        .collect();
                    let lam_param_tys = if lam_param_tys.len() == fnsig.params.len() {
                        lam_param_tys
                    } else {
                        fnsig.params.clone()
                    };
                    self.inline_lambdas.push((
                        pnames[i].clone(),
                        params,
                        lbody,
                        lam_param_tys,
                        fname.to_string(),
                    ));
                } else {
                    // A function-typed argument that is NOT a lambda literal — a callable reference
                    // (`::g`, `obj::m`), or a function-valued variable. It can't be inline-expanded as a
                    // body, so bind it as a function VALUE (a `FunctionN`): `f(v)` in the inlined body then
                    // invokes it via `.invoke`. Semantically identical (kotlinc inlines the reference too;
                    // the value form is box-OK and verifies) — no FunctionN-drop bookkeeping needed.
                    let slot = self.fresh_value();
                    let val = match self.lower_arg(args[i], &ty_to_ir(*pty)) {
                        Some(v) => v,
                        None => {
                            self.scope.truncate(depth);
                            self.inline_lambdas.truncate(lam_depth);
                            self.inline_active.truncate(active_depth);
                            self.reified_subst.truncate(reif_depth);
                            return None;
                        }
                    };
                    let var = self.emit_variable(slot, ty_to_ir(*pty), Some(val));
                    stmts.push(var);
                    self.scope.push((pnames[i].clone(), slot, *pty));
                }
            } else {
                // A value parameter: evaluate once into a temp, visible by name in the body. A parameter
                // declared as a type param uses the call's concrete argument type (specialized), not the
                // erased `Any` — so the inlined body sees `Int` and avoids spurious boxing.
                let spty = tbinds
                    .get(f.params[i].ty.name.as_str())
                    .copied()
                    .unwrap_or(*pty);
                let slot = self.fresh_value();
                let val = match self.lower_arg(args[i], &ty_to_ir(spty)) {
                    Some(v) => v,
                    None => {
                        self.scope.truncate(depth);
                        self.inline_lambdas.truncate(lam_depth);
                        self.inline_active.truncate(active_depth);
                        self.reified_subst.truncate(reif_depth);
                        return None;
                    }
                };
                let var = self.emit_variable(slot, ty_to_ir(spty), Some(val));
                stmts.push(var);
                self.scope.push((pnames[i].clone(), slot, spty));
            }
        }
        // For a body with `return`s, set up the inline-return target (result slot + end label) so a
        // `return x` lowers to `result = x; break@end`; the body is then wrapped in `do { … } while(false)`
        // labeled `end`. A `Unit` return type needs no result slot (a `return` is a bare `break`).
        // The result slot holds the value the CHECKER assigned to this call — a generic return
        // SPECIALIZED to the concrete argument types (`foo(1){…}: T` → `Int`), not the erased declared
        // `sig_ret` (`Object`). Using the specialized type keeps the slot, the `return` coercions, and
        // the downstream use (`foo(…) != 1`) consistent — no primitive-into-Object-slot VerifyError.
        let ret_ty = {
            let specialized = self.info.ty(AstExprId(call_id));
            // Only a NON-nullable, concrete specialization is a valid slot type: a nullable primitive
            // (`Int?`) has no unboxed slot form, so keep the erased `sig_ret` (a boxed reference) there.
            if specialized != Ty::Error
                && specialized != Ty::Unit
                && specialized == specialized.non_null()
            {
                ty_to_ir(specialized)
            } else {
                ty_to_ir(sig_ret)
            }
        };
        let target = if has_return {
            let slot = self.fresh_value();
            let label = format!("$inl${slot}");
            self.inline_return
                .push((slot, label.clone(), ret_ty.clone()));
            Some((slot, label))
        } else {
            None
        };
        let body_val = self.expr(body);
        self.scope.truncate(depth);
        self.inline_lambdas.truncate(lam_depth);
        self.inline_active.truncate(active_depth);
        self.reified_subst.truncate(reif_depth);
        if has_return {
            self.inline_return.pop();
        }
        let body_val = body_val?;
        if let Some((slot, label)) = target {
            let unit_ret = ret_ty == Ty::Unit;
            // `while(true) { <body>; [result = fall-through value;] break@end }` — runs the inlined body
            // exactly once (the trailing `break` exits), while any `return` inside breaks early (after
            // setting the result). A standard `while(true)`+`break` shape the frame emitter handles.
            // If the body ALWAYS diverges (every path returns — type `Nothing`), the fall-through assign +
            // break are unreachable dead code AFTER a `goto`, which would lack a stackmap frame — so omit
            // them and emit the body alone (its internal `return`s already break to the end).
            let loop_body = if body_diverges {
                body_val
            } else {
                let brk = self.emit_break(Some(label.clone()));
                if unit_ret {
                    self.emit_block(vec![body_val, brk], None)
                } else {
                    let assign = self.emit_set_value(slot, body_val);
                    self.emit_block(vec![assign, brk], None)
                }
            };
            let cond = self.emit_const(IrConst::Boolean(true));
            let loopw = self.emit_while(cond, loop_body, None, false, Some(label));
            if !unit_ret {
                // Initialize the result slot to a type default so its frame type is consistent at the
                // loop head (an uninitialized slot is `top` there but the body assigns it → mismatch).
                // Map through `kotlin_class_internal` so a SOURCE primitive `Ty` (`Ty::Long`) and the
                // legacy `Obj("kotlin/Long")` scalar form both resolve — `obj_internal` alone is `None`
                // for the source variants and would fall to a wrong `Null` default (VerifyError: storing
                // `null` into an `int` slot).
                let init = if ir_type_is_reference(&ret_ty) {
                    IrConst::Null
                } else {
                    match ret_ty.non_null().kotlin_class_internal() {
                        Some(n) if n.matches("kotlin/Long") => IrConst::Long(0),
                        Some(n) if n.matches("kotlin/Float") => IrConst::Float(0.0),
                        Some(n) if n.matches("kotlin/Double") => IrConst::Double(0.0),
                        Some(n) if n.matches("kotlin/Boolean") => IrConst::Boolean(false),
                        Some(n) if n.matches("kotlin/Char") => IrConst::Char('\0'),
                        _ => IrConst::Int(0), // Int/Short/Byte
                    }
                };
                let init = self.emit_const(init);
                stmts.push(self.emit_variable(slot, ret_ty, Some(init)));
            }
            stmts.push(loopw);
            let value = if unit_ret {
                self.emit_unit()
            } else {
                self.emit_get_value(slot)
            };
            Some(self.emit_block(stmts, Some(value)))
        } else if stmts.is_empty() {
            Some(body_val)
        } else {
            Some(self.emit_block(stmts, Some(body_val)))
        }
    }

    /// Expand a call `param(args)` to an inlined lambda parameter: bind the lambda's parameters to the
    /// (evaluated) arguments, then lower its body in place. The body's value is the call's value.
    /// Lower a selected invoke-operator call (`ExprLowering::Invoke`). A function-value receiver
    /// becomes a direct function invocation (splicing through an inline lambda parameter when the
    /// receiver names one); an operator receiver becomes the selected member call (a user-class
    /// `invoke` method, or a classpath member resolved from library data).
    fn lower_invoke(
        &mut self,
        e: AstExprId,
        receiver: AstExprId,
        params: &[Ty],
        kind: InvokeKind,
        args: &[AstExprId],
    ) -> Option<u32> {
        match kind {
            InvokeKind::Function { ret, suspend } => {
                if let Expr::Name(fname) = self.afile.expr(receiver).clone() {
                    if let Some(idx) = self.inline_lambdas.iter().rposition(|(n, ..)| *n == fname) {
                        return self.lower_inline_lambda_invoke(idx, args);
                    }
                }
                crate::trace_compiler!(
                    "suspend",
                    "lower_invoke Function: recv_ty={:?} params={params:?} ret={ret:?} nargs={} suspend={suspend}",
                    self.info.ty(receiver),
                    args.len()
                );
                let func = self.expr(receiver)?;
                let mut ir_args = Vec::with_capacity(args.len());
                for (&arg, param) in args.iter().zip(params) {
                    ir_args.push(self.lower_arg(arg, &ty_to_ir(*param))?);
                }
                let invoke = self.ir.add_expr(IrExpr::InvokeFunction {
                    func,
                    args: ir_args,
                    ret: ty_to_ir(ret),
                });
                // A SUSPEND function value (`block: suspend (A)->R`) implements `Function{N+1}` and is a
                // suspension point — record it so the coroutine pass threads the `Continuation` into its
                // args (then `Function{N+1}.invoke` is selected by arg count) and does the SUSPENDED check.
                if suspend {
                    self.ir.suspend_calls.insert(invoke, ret);
                }
                Some(invoke)
            }
            InvokeKind::Operator {
                receiver_ty: rt,
                member: None,
            } => {
                // A user class with a member `operator fun invoke`: a direct method call.
                if let Some((class, index, fid, mret)) = self
                    .class_of(rt)
                    .map(|ci| ci.internal())
                    .and_then(|i| self.resolve_method(&i, "invoke"))
                {
                    let recv = self.expr(receiver)?;
                    let target_params = self.ir.functions[fid as usize].params.clone();
                    let a = self.lower_args(args, &target_params)?;
                    let call = self.emit_method_call(
                        class,
                        index,
                        recv,
                        a.into_iter().map(Some).collect(),
                    );
                    return Some(self.coerce_generic_read(call, e, mret));
                }
                None
            }
            InvokeKind::Operator {
                receiver_ty: rt,
                member: Some(resolved),
            } => {
                // A classpath/cross-file type whose `invoke` member was selected by the checker.
                let recv = self.expr(receiver)?;
                let ret = resolved.ret;
                let member = resolved.member;
                let physical_ret = member.physical_ret;
                let mut a = Vec::new();
                for (i, &arg) in args.iter().enumerate() {
                    match member.params.get(i) {
                        Some(p) => a.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                        None => a.push(self.expr(arg)?),
                    }
                }
                let owner = member.owner.map(|owner| owner.render()).unwrap_or_else(|| {
                    rt.obj_internal()
                        .map(|n| n.render())
                        .unwrap_or_else(|| "kotlin/Any".to_string())
                });
                let call = self.emit_virtual_call(
                    owner,
                    member.name,
                    member.descriptor,
                    member.is_interface,
                    recv,
                    a,
                );
                Some(self.coerce_to_static(call, ret, physical_ret))
            }
            InvokeKind::ExtensionOperator { receiver_ty: rt } => {
                // `recv(args)` via an `operator fun Recv.invoke(...)` EXTENSION → `invokestatic
                // <facade>.invoke(recv, args)`. The receiver is the lifted static's leading argument.
                let &fid = self
                    .ext_fun_ids
                    .get(&(rt.erased_recv(), "invoke".to_string()))?;
                let target_params = self.ir.functions[fid as usize].params.clone();
                let recv = self.lower_arg(receiver, target_params.first()?)?;
                let mut a = vec![recv];
                for (i, &arg) in args.iter().enumerate() {
                    let pt = target_params
                        .get(i + 1)
                        .copied()
                        .unwrap_or(ty_to_ir(Ty::obj("kotlin/Any")));
                    a.push(self.lower_arg(arg, &pt)?);
                }
                Some(self.emit_local_call(fid, a))
            }
        }
    }

    fn lower_inline_lambda_invoke(&mut self, idx: usize, args: &[AstExprId]) -> Option<u32> {
        let (_, lam_params, lam_body, lam_param_tys, lam_label) = self.inline_lambdas[idx].clone();
        if args.len() != lam_params.len() || lam_params.len() != lam_param_tys.len() {
            return None;
        }
        let depth = self.scope.len();
        let mut stmts = Vec::new();
        for ((pname, pty), &arg) in lam_params.iter().zip(&lam_param_tys).zip(args) {
            let slot = self.fresh_value();
            let val = match self.lower_arg(arg, &ty_to_ir(*pty)) {
                Some(v) => v,
                None => {
                    self.scope.truncate(depth);
                    return None;
                }
            };
            let var = self.emit_variable(slot, ty_to_ir(*pty), Some(val));
            stmts.push(var);
            self.scope.push((pname.clone(), slot, *pty));
        }
        // A `return@<inlineFn>` in the lambda body is a LOCAL return from this lambda invocation. Wrap the
        // spliced body in a `while(true){ … break }` labeled `brk` and register a frame so the labeled
        // return lowers to `break@brk` — exactly the inline-fn return mechanism, one level in. Only a
        // `Unit`-result lambda (the `forEach`/`onEach` shape) is modeled; a value-result labeled return
        // (a `let { return@let v }`) is not yet — bail rather than miscompile.
        if body_has_labeled_return(self.afile, lam_body, &lam_label) {
            let lam_ret = self.info.ty(lam_body);
            // VALUE-result labeled return (`x.let { if (c) return@let a; b }`): bind a result slot,
            // wrap the body in a `while(true){ result = <fall-through value>; break@brk }` (a
            // `return@let v` inside assigns `result = v` then breaks — see the handler above), and yield
            // the slot. A body that always diverges (every path a `return@let`) has a `Nothing`
            // fall-through with no result type here — leave that (rarer) shape to the Unit path / skip.
            if lam_ret != Ty::Unit && lam_ret != Ty::Nothing {
                let brk = format!("$lamret${}", self.fresh_value());
                let result_slot = self.fresh_value();
                let dflt = self.emit_zero_value(lam_ret);
                let decl = self.emit_variable(result_slot, ty_to_ir(lam_ret), Some(dflt));
                stmts.push(decl);
                self.inline_lambda_ret.push((
                    lam_label.clone(),
                    result_slot,
                    brk.clone(),
                    lam_ret,
                    false,
                ));
                let body_val = self.expr(lam_body);
                self.inline_lambda_ret.pop();
                self.scope.truncate(depth);
                let body_val = body_val?;
                // Normal fall-through: the body's own value is the result.
                let assign = self.emit_set_value(result_slot, body_val);
                let brk_stmt = self.emit_break(Some(brk.clone()));
                let loop_body = self.emit_block(vec![assign, brk_stmt], None);
                let cond = self.emit_const(IrConst::Boolean(true));
                let loopw = self.emit_while(cond, loop_body, None, false, Some(brk));
                stmts.push(loopw);
                let get = self.emit_get_value(result_slot);
                return Some(self.emit_block(stmts, Some(get)));
            }
            let brk = format!("$lamret${}", self.fresh_value());
            self.inline_lambda_ret
                .push((lam_label.clone(), 0, brk.clone(), Ty::Unit, false));
            let body_val = self.expr(lam_body);
            self.inline_lambda_ret.pop();
            self.scope.truncate(depth);
            let body_val = body_val?;
            let brk_stmt = self.emit_break(Some(brk.clone()));
            let loop_body = self.emit_block(vec![body_val, brk_stmt], None);
            let cond = self.emit_const(IrConst::Boolean(true));
            let loopw = self.emit_while(cond, loop_body, None, false, Some(brk));
            stmts.push(loopw);
            let unit = self.emit_unit();
            return Some(self.emit_block(stmts, Some(unit)));
        }
        // A BARE `return` in the spliced lambda body is NON-LOCAL: it returns from the function enclosing
        // the lambda literal, NOT from the inline fn whose call is being expanded. Clear the inline-return
        // stack while lowering the body so such a `return` lowers to the real enclosing-function return
        // (`cur_ret_ty`), not the inline fn's result-slot break. Restored after (the inline fn's own body,
        // lowered elsewhere, keeps its frame).
        let saved_inl_ret = std::mem::take(&mut self.inline_return);
        let body_val = self.expr(lam_body);
        self.inline_return = saved_inl_ret;
        self.scope.truncate(depth);
        let body_val = body_val?;
        if stmts.is_empty() {
            Some(body_val)
        } else {
            Some(self.emit_block(stmts, Some(body_val)))
        }
    }

    /// Build the pieces of a safe property/length access `recv?.<name>` (NO call args) for fusion with a
    /// surrounding `?:` over a PRIMITIVE result: returns `(var, cond, member)` where `var` binds the
    /// receiver once, `cond` is `recv != null`, and `member` is the UNBOXED member value read on the
    /// non-null receiver. Lets `s?.length ?: -1` compile to a `dup`/`ifnull` primitive select with no
    /// boxing (kotlinc's form) instead of boxing the member then unboxing it through the elvis.
    fn lower_safe_prop_member(
        &mut self,
        source: AstExprId,
        receiver: AstExprId,
        name: &str,
    ) -> Option<(u32, u32, u32)> {
        let rty = self.info.ty(receiver);
        if !rty.is_reference() {
            return None;
        }
        let recv_ty = rty.non_null();
        let internal = recv_ty.kotlin_class_internal()?.to_string();
        let rv = self.expr(receiver)?;
        let v = self.fresh_value();
        let var = self.emit_variable(v, mark_nullable(ty_to_ir(rty)), Some(rv));
        let get1 = self.emit_get_value(v);
        let nullc = self.emit_const(IrConst::Null);
        let cond = self.emit_primitive_bin_op(IrBinOp::Ne, get1, nullc);
        let recv2 = self.emit_get_value(v);
        let member = if let Some((fclass, idx, _)) = self.resolve_field(&internal, name) {
            let owner_internal = self.ir.classes[fclass as usize].fq_name();
            if self.cur_class != existing_type_name(&owner_internal) {
                if let Some((mclass, mindex, _, _)) =
                    self.resolve_method(&internal, &property_getter_name(name))
                {
                    self.emit_method_call(mclass, mindex, recv2, vec![])
                } else {
                    self.emit_get_field(recv2, fclass, idx)
                }
            } else {
                self.emit_get_field(recv2, fclass, idx)
            }
        } else {
            self.lower_member_read_on(recv2, recv_ty, name, source)?
        };
        Some((var, cond, member))
    }

    fn expr(&mut self, e: AstExprId) -> Option<u32> {
        // A compound index-assign spilled this expr to a temp — reuse the temp load instead of
        // re-evaluating (see [`Self::index_subst`]).
        if let Some(&v) = self.index_subst.get(&e) {
            return Some(v);
        }
        // Guard against a stack overflow on a pathologically deep expression (a stress test with
        // thousands of nested operators): bail past the limit so the file is skipped, not crashed.
        self.expr_depth += 1;
        if self.expr_depth > 500 {
            self.expr_depth -= 1;
            return None;
        }
        let r = self.expr_inner(e);
        self.expr_depth -= 1;
        // Record the expression's LOGICAL (source) type verbatim, keyed by its IR id — the value-class
        // pass reads it to recover a value's representation when the IR node alone is ambiguous (a library
        // call's physical `Object` result whose logical type is a value class). VC-agnostic: just the type.
        if let Some(id) = r {
            let ty = self.info.ty(e);
            if ty != Ty::Error {
                self.ir.logical_types.insert(id, ty_to_ir(ty));
            }
        }
        // Survey diagnostic: tag the innermost unsupported expression that caused the bail (the first
        // `None` to bubble up wins, since deeper frames run first and a tag is only refined from a
        // coarse `deep*` phase). A `Call` is tagged by its callee name — the single most useful signal.
        if r.is_none() && self.bail.borrow().starts_with("deep") {
            let reason = match self.afile.expr(e).clone() {
                Expr::Call { callee, .. } => {
                    let name = match self.afile.expr(callee) {
                        Expr::Name(n) => n.clone(),
                        Expr::Member { name, .. } => format!(".{name}"),
                        o => bail_variant(&format!("{o:?}")).to_string(),
                    };
                    format!("call {name}")
                }
                o => format!("expr {}", bail_variant(&format!("{o:?}"))),
            };
            self.set_bail(&reason);
        }
        r
    }

    fn expr_inner(&mut self, e: AstExprId) -> Option<u32> {
        Some(match self.afile.expr(e).clone() {
            Expr::IntLit(v) => self.emit_const(IrConst::Int(v as i32)),
            Expr::LongLit(v) => self.emit_const(IrConst::Long(v)),
            // Unsigned literals are the signed int/long bit pattern of their magnitude (`UInt.MAX` =
            // 0xFFFFFFFFu reinterprets to int -1, which is what kotlinc stores).
            Expr::UIntLit(v) => self.emit_const(IrConst::Int(v as u32 as i32)),
            Expr::ULongLit(v) => self.emit_const(IrConst::Long(v)),
            Expr::DoubleLit(v) => self.emit_const(IrConst::Double(v)),
            Expr::FloatLit(v) => self.emit_const(IrConst::Float(v)),
            Expr::CharLit(c) => self.emit_const(IrConst::Char(c)),
            Expr::BoolLit(b) => self.emit_const(IrConst::Boolean(b)),
            Expr::StringLit(s) => self.ir_const_str(s),
            Expr::NullLit => self.emit_const(IrConst::Null),
            // `throw e` — throw the exception value; control never returns.
            Expr::Throw { operand } => {
                let v = self.expr(operand)?;
                // Throwing an erased generic value (`throw id(e)`, where `id` returns a type parameter
                // and is physically `Object`) needs the `checkcast Throwable` kotlinc inserts — the JVM
                // `athrow` requires a `Throwable` on the stack.
                let v = if self.info.ty(operand).is_erased_top() {
                    self.emit_type_op(IrTypeOp::Cast, v, ty_to_ir(Ty::obj("kotlin/Throwable")))
                } else {
                    v
                };
                self.emit_throw(v)
            }
            // `return value` in expression position (`x ?: return null`). Only the simple function-return
            // case is modeled here; an enclosing `finally`, an `inline fun` expansion frame, or a label
            // naming a spliced lambda needs the richer `Stmt::Return` handling — skip the file instead.
            Expr::Return { value, label } => {
                if !self.try_finally_stack.is_empty() || !self.inline_return.is_empty() {
                    return None;
                }
                if let Some(lbl) = &label {
                    if self.inline_lambda_ret.iter().any(|(l, ..)| l == lbl) {
                        return None;
                    }
                }
                let v = match value {
                    Some(ve) if self.cur_ret_ty != Ty::Unit && self.info.ty(ve) != Ty::Nothing => {
                        let rt = self.cur_ret_ty.clone();
                        Some(self.lower_arg(ve, &rt)?)
                    }
                    Some(ve) => Some(self.expr(ve)?),
                    None => None,
                };
                self.emit_return(v)
            }
            // `break`/`continue` in expression position (`m[k] ?: continue`) — the same loop jump as the
            // statement form, lowered to `IrExpr::Break`/`Continue`. A pending `finally` between the jump
            // and its loop isn't modeled here (as for a `return`), so bail then.
            Expr::Break { label } => {
                if !self.try_finally_stack.is_empty() {
                    return None;
                }
                self.emit_break(label)
            }
            Expr::Continue { label } => {
                if !self.try_finally_stack.is_empty() {
                    return None;
                }
                self.emit_continue(label)
            }
            // `try { … } catch (e: E) { … } … [finally { f }]` (nested try already rejected by checker).
            Expr::Try {
                body,
                catches,
                finally,
            } => {
                // A `finally` is inlined at each exit. A `break`/`continue` that escapes the `try` would
                // need the `finally` run before it (not modeled) — bail. A `return` IS modeled: the
                // `finally` is pushed onto `try_finally_stack` and inlined at each `return` inside the
                // body/catch (`Stmt::Return`); the normal/exception exits are inlined by `emit_try`.
                if finally.is_some()
                    && (body_has_break_continue(self.afile, body)
                        || catches
                            .iter()
                            .any(|c| body_has_break_continue(self.afile, c.body)))
                {
                    return None;
                }
                // A `break`/`continue` INSIDE the `finally` that escapes it (out to an enclosing loop)
                // isn't modeled either — the jump leaves the `finally` mid-run. Skip rather than emit
                // bytecode the verifier rejects.
                if let Some(f) = finally {
                    if finally_has_escaping_break_continue(self.afile, f) {
                        return None;
                    }
                }
                // A `finally` that declares locals is inlined on several exit paths (normal, each `return`,
                // the exception catch-all); the duplicated locals' slots clash across copies (a verify
                // error) — skip rather than miscompile.
                if let Some(f) = finally {
                    if body_declares_local(self.afile, f) {
                        return None;
                    }
                }
                let result = ty_to_ir(self.info.ty(e));
                if let Some(f) = finally {
                    self.try_finally_stack.push(f);
                }
                let body_ir = self.expr(body);
                let mut ir_catches = Vec::new();
                let mut ok = body_ir.is_some();
                for c in &catches {
                    let exc_internal = match self.catch_internal(&c.ty.name) {
                        Some(x) => x,
                        None => {
                            ok = false;
                            break;
                        }
                    };
                    let v = self.fresh_value();
                    self.scope.push((c.name.clone(), v, Ty::obj(&exc_internal)));
                    let cbody = self.expr(c.body);
                    self.scope.pop();
                    match cbody {
                        Some(cb) => ir_catches.push(crate::ir::IrCatch {
                            var: v,
                            exc_internal: type_name(&exc_internal),
                            body: cb,
                        }),
                        None => {
                            ok = false;
                            break;
                        }
                    }
                }
                if finally.is_some() {
                    self.try_finally_stack.pop();
                }
                if !ok {
                    return None;
                }
                let fin = match finally {
                    Some(f) => Some(self.expr(f)?),
                    None => None,
                };
                self.emit_try(body_ir?, ir_catches, fin, result)
            }
            // `operand!!` — assert non-null. On a reference, `Intrinsics.checkNotNull` throws if null
            // and yields the value; on a (non-null) primitive it is a no-op.
            Expr::NotNull { operand } => {
                // `null!!` (a statically-null operand) always throws — emit an actual `throw
                // NullPointerException()` (an `athrow` the verifier knows diverges), not the
                // `checkNotNull` call (which is `(Object)V` and so appears to fall through, leaving a
                // handler placed right after it with an inconsistent frame).
                if self.info.ty(operand) == Ty::Null {
                    let exc =
                        self.emit_new_external("java/lang/NullPointerException", "()V", vec![]);
                    return Some(self.emit_throw(exc));
                }
                let v = self.expr(operand)?;
                if self.info.ty(operand).is_reference() {
                    let asserted = self.ir.add_expr(IrExpr::NotNullAssert { operand: v });
                    // `Int?!!` narrows to the unboxed primitive — unbox the wrapper after the null check.
                    let result = self.info.ty(e);
                    if self.has_scalar_value_repr(result) {
                        self.emit_type_op(IrTypeOp::ImplicitCoercion, asserted, ty_to_ir(result))
                    } else {
                        asserted
                    }
                } else {
                    v
                }
            }
            // `r?.m(args)` / `r?.p` → `{ val t = r; if (t != null) t.m(args)/t.p else null }`.
            Expr::SafeCall {
                receiver,
                name,
                args,
            } => {
                let rty = self.info.ty(receiver);
                let result_ty = self.info.ty(e);
                // Does the single lambda argument's body DIVERGE (non-local `return`/`throw`, typed
                // `Nothing`)? Only meaningful once we know the call is a scope fn that runs the body EXACTLY
                // once (`let`/`also`/`run`/`apply` — see `from_scope_fn` below): for those, a diverging body
                // means the non-null arm produces no value. It is NOT sufficient for a collection HOF
                // (`forEach`/`map`) that may run the body zero times on an empty receiver, so this is gated
                // by `from_scope_fn` at the guard, never used alone.
                let lambda_body_diverges = args
                    .as_ref()
                    .filter(|a| a.len() == 1)
                    .and_then(|a| match self.afile.expr(a[0]) {
                        Expr::Lambda { body, .. } => Some(*body),
                        _ => None,
                    })
                    .is_some_and(|body| self.info.ty(body) == Ty::Nothing);
                // A statically-`null` receiver (`null?.toString()`): the receiver is always null, so the
                // member is never invoked and the whole safe call is `null`. Run the receiver for any side
                // effects (a bare `null` literal has none), then yield `null`.
                if rty == Ty::Null {
                    let recv = self.expr(receiver)?;
                    let nullc = self.emit_const(IrConst::Null);
                    return Some(self.emit_block(vec![recv], Some(nullc)));
                }
                // A primitive receiver can never be null, so `a?.foo(b)` is a vacuous safe call (kotlinc
                // warns "unnecessary safe call") ≡ `a.foo(b)`. Fold an arithmetic operator-method call to
                // the plain primitive op — `var a = 10; a?.plus(10)` works like `a.plus(10)`.
                if !rty.is_reference() {
                    if let Some([arg]) = args.as_deref() {
                        if let Some(r) =
                            self.lower_prim_op_method(receiver, &name, *arg, self.info.ty(e))
                        {
                            return Some(r);
                        }
                    }
                }
                // The receiver must be a reference (the `?.` null-check is on an object). The result may be
                // a reference OR a nullable-primitive (`s?.length` : `Int?`) — the assembly below boxes the
                // primitive member value into the wrapper (`null` in the other branch).
                if !rty.is_reference()
                    || (!result_ty.is_reference()
                        && result_ty.nullable_primitive().is_none()
                        && result_ty != Ty::Unit)
                {
                    return None;
                }
                // The receiver internal comes from the NON-null form (`Int?` in a chained `?.let` unwraps
                // to `Int`). A nullable-primitive receiver has no class internal — the scope-fn path
                // (tried first) unboxes it itself, so a placeholder owner suffices for the null-check.
                let nn = rty.non_null();
                let internal_id = if nn == Ty::String {
                    type_name("kotlin/String")
                } else if let Some(i) = nn.obj_internal() {
                    i
                } else if self.has_scalar_value_repr(nn) {
                    // A nullable-PRIMITIVE receiver (`Int?` in a chained `?.let`) has no class internal —
                    // the scope-fn path (tried first) unboxes it; a placeholder owner suffices.
                    crate::types::wk::any()
                } else {
                    // A non-object, non-primitive receiver (e.g. a literal `null?.…`): unsupported — bail.
                    return None;
                };
                let internal = internal_id.render();
                let rv = self.expr(receiver)?;
                let v = self.fresh_value();
                // The `?.` receiver is NULLABLE by construction — carry that into the temp's IrType (`Ty`
                // drops it). For a value-class receiver this keeps it BOXED (`MyC?` → `LMyC;`), so storing
                // the boxed `as?`/nullable value doesn't mismatch an unboxed-`int` slot.
                let var = self.emit_variable(v, mark_nullable(ty_to_ir(rty)), Some(rv));
                let get1 = self.emit_get_value(v);
                let nullc = self.emit_const(IrConst::Null);
                let cond = self.emit_primitive_bin_op(IrBinOp::Ne, get1, nullc);
                let recv2 = self.emit_get_value(v);
                // A safe-call scope function (`s?.let { it… }`, `s?.run { … }`): inline it with the
                // non-null receiver `recv2`; the surrounding null-check + nullable-wrap below make the
                // whole `s?.…` yield `null` when `s` is null.
                // `from_scope_fn`: the member came from the scope-fn inliner (`let`/`also`/`run`/`apply`,
                // which run the body EXACTLY once). Only then does a diverging lambda body imply the whole
                // non-null arm diverges — the gate that keeps a collection HOF (`forEach`) out of the
                // divergence guard below.
                let mut from_scope_fn = false;
                let member = if let Some(m) = self.lower_safe_scope_member(recv2, rty, &name, &args)
                {
                    from_scope_fn = true;
                    m
                } else {
                    match args {
                        Some(args) => {
                            if let Some((class, index, fid, _)) =
                                self.resolve_method(&internal, &name)
                            {
                                let params = self.ir.functions[fid as usize].params.clone();
                                if args.len() != params.len() {
                                    return None;
                                }
                                let a = self.lower_args(&args, &params)?;
                                self.emit_method_call(
                                    class,
                                    index,
                                    recv2,
                                    a.into_iter().map(Some).collect(),
                                )
                            } else if let Some(&fid) =
                                self.ext_fun_ids.get(&(nn.erased_recv(), name.clone()))
                            {
                                // A same-module EXTENSION function via safe call (`s?.id()` where
                                // `fun String.id()` is declared in this module): a static call whose first
                                // argument is the (already non-null) receiver, exactly as the qualified
                                // call lowers it. Stdlib/classpath extensions take the `lower_ext_call_on`
                                // fallback below.
                                let params = self.ir.functions[fid as usize].params.clone();
                                if params.len() != args.len() + 1 {
                                    return None;
                                }
                                let mut a = vec![recv2];
                                for (arg, pt) in args.iter().zip(&params[1..]) {
                                    a.push(self.lower_arg(*arg, pt)?);
                                }
                                self.emit_local_call(fid, a)
                            } else {
                                // A classpath instance method (`s?.substring(1)`).
                                if let Some(resolved) = self.info.resolved_member(e).cloned() {
                                    let m = resolved.member;
                                    if m.name != name || m.params.len() != args.len() {
                                        return None;
                                    }
                                    let mut a = Vec::new();
                                    for (arg, pt) in args.iter().zip(&m.params) {
                                        a.push(self.lower_arg(*arg, &ty_to_ir(*pt))?);
                                    }
                                    let ret = resolved.ret;
                                    let physical_ret = m.physical_ret;
                                    let call = self.emit_library_member_call(
                                        recv2,
                                        internal_id,
                                        m,
                                        ret,
                                        resolved.suspend,
                                        a,
                                    );
                                    self.coerce_to_static(call, ret, physical_ret)
                                } else {
                                    // A stdlib EXTENSION via safe call (`s?.uppercase()`) — inline it on
                                    // the non-null receiver, the same path as the qualified call.
                                    self.lower_ext_call_on(recv2, nn, &name, &args, e)?
                                }
                            }
                        }
                        None => {
                            if let Some(read) =
                                self.lower_field_read_on(recv2, &internal, &name, e, None)
                            {
                                read
                            } else {
                                // A classpath property (`list?.size`) — a zero-arg accessor.
                                self.lower_member_read_on(recv2, nn, &name, e)?
                            }
                        }
                    }
                };
                crate::trace_compiler!(
                    "value_classes",
                    "safecall {name} result_ty={result_ty:?} obj_internal={:?} vc={}",
                    result_ty.obj_internal(),
                    result_ty.obj_internal().is_some_and(|i| self
                        .syms
                        .classes
                        .get(i.render().rsplit('/').next().unwrap_or(""))
                        .is_some_and(|c| c.value_field.is_some()))
                );
                // A nullable-primitive result (`s?.length` : `Int?`): box the primitive member value so
                // both `when` branches are the wrapper reference (the other branch is `null`).
                let member = if result_ty.nullable_primitive().is_some() {
                    self.emit_type_op(IrTypeOp::ImplicitCoercion, member, ty_to_ir(result_ty))
                } else if result_ty.obj_internal().is_some_and(|i| {
                    self.syms
                        .classes
                        .get(i.render().rsplit('/').next().unwrap_or(""))
                        .is_some_and(|c| c.value_field.is_some())
                }) {
                    // A nullable VALUE-CLASS result (`a?.foo()` : `Z?`): the member returns the unboxed
                    // underlying, but the `when` merges it with a `null` branch — coerce to the NULLABLE
                    // value class so the JVM value-class pass `box-impl`s it (both branches then references).
                    self.emit_type_op(
                        IrTypeOp::ImplicitCoercion,
                        member,
                        mark_nullable(ty_to_ir(result_ty)),
                    )
                } else if result_ty == Ty::Unit {
                    // A `Unit` result (`x?.let { for … }`): run the member for effect, then yield
                    // `Unit.INSTANCE` so this branch matches the `null` branch (both references).
                    let unit = self.emit_unit();
                    self.emit_block(vec![member], Some(unit))
                } else {
                    member
                };
                // A safe call whose non-null arm DIVERGES — either the member/block value is `Nothing?`
                // (`x?.let { return … }`, `x?.run { throw … }`, or a member returning `Nothing`) or a
                // receiver-returning scope block diverges (`x?.also { return … }`, `x?.apply { throw … }`).
                // A diverging arm produces no value, so modelling it as a value-producing `when` branch would
                // merge a valueless branch with the `null` branch and leave a `Top` on the operand stack
                // (VerifyError). Instead guard the divergent member as a plain statement — `if (recv != null)
                // { member }` — and yield `null` unconditionally; the `null` is only ever observed when the
                // receiver was null (else control left via the `return`/`throw`).
                if result_ty.non_null() == Ty::Nothing || (from_scope_fn && lambda_body_diverges) {
                    let guard = self.emit_when(vec![(Some(cond), member)]);
                    let nullv = self.emit_const(IrConst::Null);
                    return Some(self.emit_block(vec![var, guard], Some(nullv)));
                }
                let nullb = self.emit_const(IrConst::Null);
                let when = self.emit_when(vec![(Some(cond), member), (None, nullb)]);
                self.emit_block(vec![var], Some(when))
            }
            // `a ?: b` → `{ val t = a; if (t != null) t else b }` (t bound once, so `a` runs once).
            Expr::Elvis { lhs, rhs } => {
                let result_ty = self.info.ty(e);
                // Fuse `recv?.prop ?: default` for a PRIMITIVE result: null-check the receiver and select
                // the UNBOXED member or the default — no boxing of the member (kotlinc's `dup;ifnull`
                // form). Only the no-arg property/length safe-access is fused here.
                if self.has_scalar_value_repr(result_ty) {
                    if let Expr::SafeCall {
                        receiver,
                        name,
                        args: None,
                    } = self.afile.expr(lhs).clone()
                    {
                        if let Some((var, cond, member)) =
                            self.lower_safe_prop_member(lhs, receiver, &name)
                        {
                            // The member is the natural primitive; convert to the elvis result type if it
                            // differs (`s?.length ?: 0L` → `i2l`).
                            let member = self.emit_type_op(
                                IrTypeOp::ImplicitCoercion,
                                member,
                                ty_to_ir(result_ty),
                            );
                            let rv = self.lower_arg(rhs, &ty_to_ir(result_ty))?;
                            let when = self.emit_when(vec![(Some(cond), member), (None, rv)]);
                            return Some(self.emit_block(vec![var], Some(when)));
                        }
                    }
                }
                let lty = self.info.ty(lhs);
                // A trivial elvis kotlinc folds at compile time (it warns "left/right operand is never
                // null"/"is always null"): a non-reference (primitive) lhs is never null, so `x ?: d` == `x`
                // (the rhs is dead — drop it, but still emit `x` for its side effects); a statically-`null`
                // lhs makes the elvis always take the rhs, so `null ?: d` == `d`.
                if lty == Ty::Null {
                    return self.lower_arg(rhs, &ty_to_ir(result_ty));
                }
                // A `Nothing`/`Nothing?` lhs. A DIVERGING lhs (`throw`/`return`/a `Nothing` call) makes
                // the elvis just the lhs (the rhs is dead). A non-diverging one is a `Nothing?`-returning
                // call — always `null` at runtime (`Nothing` has no non-null value) — so the elvis takes the
                // rhs after evaluating the lhs for side effects.
                let lty_is_nothing = lty.non_null() == Ty::Nothing;
                if lty_is_nothing {
                    if self.expr_diverges(lhs) {
                        return self.expr(lhs);
                    }
                    let lv = self.expr(lhs)?;
                    let tmp = self.fresh_value();
                    let sink = self.emit_variable(tmp, Ty::obj("kotlin/Any"), Some(lv));
                    let rv = self.lower_arg(rhs, &ty_to_ir(result_ty))?;
                    return Some(self.emit_block(vec![sink], Some(rv)));
                }
                if !lty.is_reference() {
                    return self.lower_arg(lhs, &ty_to_ir(result_ty));
                }
                let lv = self.expr(lhs)?;
                let v = self.fresh_value();
                let var = self.emit_variable(v, ty_to_ir(lty), Some(lv));
                let get1 = self.emit_get_value(v);
                let nullc = self.emit_const(IrConst::Null);
                let cond = self.emit_primitive_bin_op(IrBinOp::Ne, get1, nullc);
                // When the elvis result is a primitive (a nullable-primitive lhs, `Int? ?: 0`), the
                // non-null lhs unboxes to the primitive and the rhs coerces to it too.
                let result_ty = self.info.ty(e);
                let mut get2 = self.emit_get_value(v);
                if self.has_scalar_value_repr(result_ty) && lty.is_reference() {
                    // Unbox to the wrapper's OWN primitive (`Integer`→`Int`), then numeric-convert to the
                    // result if it differs (`Int? ?: 0.0` → unbox to `Int`, then `i2d` to `Double`) —
                    // unboxing `Integer` straight to `Double` would be an invalid checkcast.
                    if let Some(lp) = lty.nullable_primitive() {
                        get2 = self.emit_type_op(IrTypeOp::ImplicitCoercion, get2, ty_to_ir(lp));
                        if lp != result_ty {
                            get2 = self.emit_type_op(
                                IrTypeOp::ImplicitCoercion,
                                get2,
                                ty_to_ir(result_ty),
                            );
                        }
                    }
                }
                let rv = self.lower_arg(rhs, &ty_to_ir(result_ty))?;
                let when = self.emit_when(vec![(Some(cond), get2), (None, rv)]);
                self.emit_block(vec![var], Some(when))
            }
            // A block in expression position: `{ stmt; …; trailing }`; value is the trailing expr.
            Expr::Block { stmts, trailing } => {
                let depth = self.scope.len();
                let mut out = Vec::new();
                let mut diverged = false;
                for &s in &stmts {
                    if self.append_stmt(s, &mut out).is_none() {
                        self.scope.truncate(depth);
                        return None;
                    }
                    if self.stmt_diverges(s) {
                        diverged = true;
                        break;
                    }
                }
                let value = match trailing {
                    Some(t) if !diverged => match self.expr(t) {
                        Some(v) => Some(v),
                        None => {
                            self.scope.truncate(depth);
                            return None;
                        }
                    },
                    _ => None,
                };
                self.scope.truncate(depth);
                self.emit_block(out, value)
            }
            Expr::Lambda { params, body } => return self.lower_lambda(e, &params, body),
            // Unbound top-level function reference `::foo` → the same `invokedynamic` +
            // `LambdaMetafactory` machinery as a lambda, but the impl method handle points directly at
            // the referenced function (no synthesized body). Bound/object/constructor references bail.
            Expr::CallableRef { receiver, name } => {
                // `::foo` imported from a same-file `object` → a bound reference to the singleton member.
                if let Some(ExprLowering::ImportedObjectMemberRef { internal }) =
                    self.info.expr_lowers.get(&e).cloned()
                {
                    if let Ty::Fun(sig) = self.info.ty(e) {
                        return self.lower_imported_object_ref(
                            e,
                            internal,
                            &name,
                            &sig.params,
                            sig.ret,
                        );
                    }
                }
                // A VARARG-COLLECTION adapted reference (`::of` where `of(vararg x)` is passed where a
                // larger-arity function type is expected): the adapter collects its extra parameters into
                // the vararg array.
                if let Some(ExprLowering::AdaptedVarargCollect {
                    name: tname,
                    target_params,
                    adapted_params,
                    ret,
                    fixed,
                    object_internal,
                }) = self.info.expr_lowers.get(&e).cloned()
                {
                    return self.lower_adapted_vararg_collect(
                        e,
                        &tname,
                        &target_params,
                        &adapted_params,
                        ret,
                        fixed,
                        object_internal,
                    );
                }
                // An ADAPTED same-file top-level function reference (`::foo` with trailing defaults passed
                // where a shorter function type is expected): synthesize an arity-matching adapter that
                // calls `foo`'s `$default` stub.
                if let Some(ExprLowering::AdaptedRef {
                    name: tname,
                    target_params,
                    adapted_params,
                    ret,
                    vararg_tail,
                    target_vararg,
                    coerce_unit: _,
                }) = self.info.expr_lowers.get(&e).cloned()
                {
                    return self.lower_adapted_ref(
                        e,
                        &tname,
                        &target_params,
                        &adapted_params,
                        ret,
                        vararg_tail,
                        target_vararg,
                    );
                }
                // A class literal (the checker recorded bound-vs-unbound). UNBOUND `T::class` → a `Class`
                // constant; BOUND `expr::class` → `expr.getClass()` (evaluated once).
                if name == "class" {
                    if let Some(ExprLowering::ClassLiteral { unbound }) =
                        self.info.expr_lowers.get(&e).cloned()
                    {
                        // `T::class` on a REIFIED type parameter: inside an expanded `<reified T>` inline
                        // body the receiver name resolves to the call-site type via `reified_subst`, so
                        // emit that concrete class constant (`Prov::class`) rather than the erased marker.
                        if let Some(recv) = receiver {
                            if let Expr::Name(n) = self.afile.expr(recv).clone() {
                                let sub = self
                                    .reified_subst
                                    .iter()
                                    .rev()
                                    .find_map(|frame| frame.get(&n).cloned());
                                if let Some(sub) = sub {
                                    let ty = self.ty_ref(&sub)?;
                                    let internal = self.class_literal_ldc_internal(ty)?;
                                    return Some(self.emit_class_const(internal));
                                }
                            }
                        }
                        return match unbound {
                            Some(ty) => {
                                let internal = self.class_literal_ldc_internal(ty)?;
                                Some(self.emit_class_const(internal))
                            }
                            None => {
                                let recv = receiver?;
                                // A primitive receiver (`42::class`) is boxed first (an `Object` target
                                // makes `lower_arg` box to the primitive's wrapper), so `getClass` yields
                                // the wrapper class — matching an unbound `Int::class` (also the wrapper).
                                let r = if self.info.ty(recv).is_reference() {
                                    self.expr(recv)?
                                } else {
                                    self.lower_arg(recv, &ty_to_ir(Ty::obj("kotlin/Any")))?
                                };
                                Some(self.emit_virtual_call(
                                    "java/lang/Object".to_string(),
                                    "getClass".to_string(),
                                    "()Ljava/lang/Class;".to_string(),
                                    false,
                                    r,
                                    vec![],
                                ))
                            }
                        };
                    }
                }
                // A property reference is typed by its callable shape, but still lowers to the Kotlin
                // property-reference runtime object on the JVM.
                if let Some(recv) = receiver {
                    if let Some(pr) = self.lower_prop_ref(e, recv, &name) {
                        return Some(pr);
                    }
                    // A bound property ref on a LIBRARY receiver (`"kotlin"::length`) — its type is a
                    // `KProperty0`, not `Ty::Fun`, so it must lower before the function-ref fallthrough.
                    if !matches!(self.info.ty(e), Ty::Fun(_)) {
                        if let Some(pr) = self.lower_bound_library_prop_ref(e, recv, &name) {
                            return Some(pr);
                        }
                    }
                }
                // An unqualified `::m` inside a class binds to the enclosing receiver (`this::m`) — a
                // member function takes precedence over a same-named top-level decl (matches the checker).
                if receiver.is_none() {
                    if let Some(r) = self.lower_implicit_this_method_ref(e, &name) {
                        return Some(r);
                    }
                }
                // Top-level property reference `::foo` lowers to a `(Mutable)PropertyReference0Impl`
                // singleton whose `get`/`set` dispatch statically to the facade accessor.
                if receiver.is_none() {
                    if let Some(pr) = self.lower_toplevel_prop_ref(e, &name) {
                        return Some(pr);
                    }
                }
                let Ty::Fun(sig) = self.info.ty(e) else {
                    return None;
                };
                let arity = sig.params.len();
                if let Some(recv) = receiver {
                    // `lower_method_ref` handles Name receivers (bound local/object, unbound class). An
                    // arbitrary expression receiver (`"abc"::get`, `1::foo`) or a bound extension falls
                    // through to `lower_bound_expr_ref`, which evaluates+captures the receiver once.
                    if let Some(r) = self.lower_method_ref(e, recv, &name, &sig.params, sig.ret) {
                        return Some(r);
                    }
                    return self.lower_bound_expr_ref(e, recv, &name, &sig.params, sig.ret);
                }
                // Local function reference `::localFun` (the checker mapped this ref to its decl): a
                // closure over the lifted static method, capturing the same outer locals the method
                // takes as leading params. A `Unit` SAM-return is wrapped (`invoke` yields the `Unit`
                // singleton); `Nothing` stays unmodeled.
                if let Some(ExprLowering::LocalFunction { stmt_id }) = self.info.expr_lowers.get(&e)
                {
                    if let Some(&fid) = self.local_fun_ids.get(stmt_id) {
                        if sig.ret == Ty::Nothing {
                            return None;
                        }
                        let local_fun = self.info.local_fun(*stmt_id)?;
                        let captures: Vec<u32> = local_fun
                            .captures
                            .iter()
                            .map(|cap| {
                                self.lookup(&cap.name)
                                    .map(|(cv, _)| self.emit_get_value(cv))
                            })
                            .collect::<Option<Vec<_>>>()?;
                        let impl_fn = if sig.ret == Ty::Unit {
                            self.unit_ref_wrapper(fid, e.0)
                        } else {
                            fid
                        };
                        return Some(self.ir.add_expr(IrExpr::Lambda {
                            impl_fn,
                            arity: arity as u8,
                            captures,
                            sam: None,
                            inline_body: None,
                        }));
                    }
                }
                // Constructor references use the class path only when the checker did not identify a
                // module or classpath function reference with the same name.
                let classpath_function_ref =
                    self.info
                        .expr_lowers
                        .get(&e)
                        .and_then(|lowering| match lowering {
                            ExprLowering::ClasspathTopLevelFunctionRef(callable) => Some(callable),
                            _ => None,
                        });
                let names_a_function = self.fun_ids.iter().any(|((n, _), _)| n == &name)
                    || classpath_function_ref.is_some();
                if !self.module_declares(&name) && !names_a_function {
                    let ci = self.class_of(sig.ret)?;
                    let class_id = ci.id;
                    let ctor_count = self.ir.classes[class_id as usize].ctor_param_count as usize;
                    let ctor_args = self.ir.classes[class_id as usize].ctor_args.clone();
                    let field_tys: Vec<Ty> = if ctor_args.is_empty() {
                        self.ir.classes[class_id as usize].fields[..ctor_count]
                            .iter()
                            .map(|f| f.ty.clone())
                            .collect()
                    } else {
                        ctor_args.iter().map(|a| a.ty).collect()
                    };
                    if field_tys.len() != arity {
                        return None;
                    }
                    let argvals: Vec<u32> =
                        (0..arity as u32).map(|i| self.emit_get_value(i)).collect();
                    let new_e = self.emit_new(class_id, argvals, None);
                    let ret_e = self.emit_return(Some(new_e));
                    let block = self.emit_block(vec![ret_e], None);
                    let impl_name = format!("{}$ctorref${}", self.cur_fn_name, self.lambda_seq);
                    self.lambda_seq += 1;
                    let fid = self.ir.add_fun(IrFunction {
                        name: impl_name,
                        params: field_tys,
                        ret: ty_to_ir(sig.ret),
                        body: Some(block),
                        is_static: true,
                        dispatch_receiver: None,
                        param_checks: Vec::new(),
                    });
                    return Some(self.ir.add_expr(IrExpr::Lambda {
                        impl_fn: fid,
                        arity: arity as u8,
                        captures: vec![],
                        sam: None,
                        inline_body: None,
                    }));
                }
                // Module top-level function references target the checker-approved single overload.
                if let Some(fid) = self
                    .fun_ids
                    .iter()
                    .find_map(|((n, _), id)| (n == &name).then_some(*id))
                {
                    let ret = self.ir.functions[fid as usize].ret.clone();
                    let fn_params = self.ir.functions[fid as usize].params.clone();
                    if fn_params.len() != arity {
                        return None;
                    }
                    if ret == Ty::Nothing {
                        return None;
                    }
                    return self.make_func_ref(
                        e.0,
                        false,
                        arity as u8,
                        None,
                        name.clone(),
                        1,
                        crate::ir::FrDispatch::Static,
                        None,
                        name.clone(),
                        false,
                        fn_params,
                        ret,
                        None,
                        None,
                    );
                }
                // Classpath top-level function references are selected by the checker.
                let c = classpath_function_ref?;
                if c.params.len() != arity || c.vararg_elem.is_some() || c.ret == Ty::Nothing {
                    return None;
                }
                let param_tys = tys_to_ir(&c.params);
                let owner = c.owner_type();
                let target_name = c.name.clone();
                let ret = ty_to_ir(c.ret);
                return self.make_func_ref(
                    e.0,
                    false,
                    arity as u8,
                    Some(owner),
                    name.clone(),
                    1,
                    crate::ir::FrDispatch::Static,
                    Some(owner),
                    target_name,
                    false,
                    param_tys,
                    ret,
                    None,
                    None,
                );
            }
            Expr::Name(n) => {
                // `this@Label` the checker resolved: `LabeledThisInner` (the current receiver) reads as a
                // bare `this`; `LabeledThisOuter` (the immediate enclosing class of an `inner class`) reads
                // the captured outer instance `this.this$0` (field index 0). Any other (unmarked) label
                // can't be reached yet — bail (skip).
                let n = if n.starts_with("this@") {
                    match self.info.expr_lowers.get(&e) {
                        Some(ExprLowering::LabeledThisInner) => "this".to_string(),
                        Some(ExprLowering::LabeledThisOuter) => {
                            let internal = self.cur_class?;
                            let class = self.class_info_name(internal)?.id;
                            if let Some((v, _)) = self.lookup("this$0") {
                                return Some(self.emit_get_value(v));
                            }
                            let this0 = self.emit_get_value(0);
                            return Some(self.emit_get_field(this0, class, 0));
                        }
                        _ => return None,
                    }
                } else {
                    n
                };
                // `COROUTINE_SUSPENDED` (a `kotlin.coroutines` intrinsic, recognized via the registry) —
                // read the sentinel through the target runtime. A local of the same name shadows it
                // (resolved through the scope below).
                if self.lookup(&n).is_none()
                    && crate::libraries::coroutine_intrinsic(&n)
                        == Some(crate::libraries::CoroutineIntrinsic::CoroutineSuspended)
                {
                    return self.runtime_call(RuntimeOp::CoroutineSuspended, Ty::Unit, vec![]);
                }
                // The `field` keyword inside a custom accessor body reads the property's backing field.
                if n == "field" {
                    if let Some((class_id, fidx, _)) = self.cur_field {
                        let this_e = self.emit_get_value(0);
                        return Some(self.emit_get_field(this_e, class_id, fidx));
                    }
                    // A top-level custom accessor reads the backing STATIC field.
                    if let Some((sidx, _)) = self.cur_static_field {
                        return Some(self.emit_get_static(sidx));
                    }
                }
                // A CLASSPATH `object` referenced as a value (`EmptyCoroutineContext`) — the checker
                // recorded it; read `getstatic <internal>.INSTANCE`.
                if let Some(ExprLowering::ObjectValue { internal }) = self.info.expr_lowers.get(&e)
                {
                    let internal = internal.render();
                    let field = self.runtime.object_instance_field(&internal)?;
                    return Some(self.platform_static_field(field));
                }
                // A class NAME with a typed `companion object` used as a VALUE (`val c: I = C`): read its
                // companion singleton `getstatic C.Companion:LC$Companion;`. Only classes whose companion
                // declares a supertype get a registered `C$Companion` ClassSig (checked here); a local of
                // the same name shadows it.
                if self.lookup(&n).is_none() {
                    if let Some(cls) = self.syms.classes.get(&n) {
                        let cls_internal = cls.internal();
                        let comp_internal = format!("{cls_internal}$Companion");
                        if self.syms.class_by_internal(&comp_internal).is_some() {
                            let field = self.runtime.companion_instance_field(
                                &cls_internal,
                                &comp_internal,
                                "Companion",
                            )?;
                            return Some(self.platform_static_field(field));
                        }
                    }
                }
                // A local delegated property: read through the delegate's `getValue(null, propref)`.
                if let Some(ld) = self.local_delegated.get(&n).cloned() {
                    // Resolve the `$delegate` slot via the CURRENT scope (so a capture-remapped value
                    // space is honored); bail if it isn't reachable here (e.g. captured into a closure we
                    // don't thread the delegate through).
                    let (dslot, _) = self.lookup(&format!("{n}$delegate"))?;
                    let dele = self.emit_get_value(dslot);
                    let null_a = self.emit_const(IrConst::Null);
                    let pref = self.make_local_propref(&ld)?;
                    return Some(
                        self.emit_virtual_call(
                            ld.delegate_internal,
                            "getValue".to_string(),
                            self.runtime
                                .method_descriptor(&ld.getvalue_sig.params, ld.getvalue_sig.ret)?,
                            false,
                            dele,
                            vec![null_a, pref],
                        ),
                    );
                }
                // A boxed mutable-capture local: read through its `Ref` holder's `element`.
                if let Some(elem) = self.boxed_elem.get(&n).cloned() {
                    let (holder, _) = self.lookup(&n)?;
                    let hv = self.emit_get_value(holder);
                    return Some(self.ir.add_expr(IrExpr::RefGet {
                        holder: hv,
                        elem: ref_elem_ir(elem),
                    }));
                }
                if let Some((v, slot_ty)) = self.lookup(&n) {
                    let mut read = self.emit_get_value(v);
                    // A `lateinit var` local read throws `UninitializedPropertyAccessException` while the
                    // slot is still null — wrap the raw read in the guard before any smart-cast narrowing
                    // (kotlinc inserts the guard on the read; the narrowing then applies to its result).
                    if let Some(name) = self.lateinit_locals.get(&v).cloned() {
                        read = self.ir.add_expr(IrExpr::LateinitCheck {
                            operand: read,
                            name,
                        });
                    }
                    // Smart-cast: the checker narrowed this read (`if (s is String) s` → `String`) below
                    // the variable's declared slot type. Insert the `checkcast` (a more specific
                    // reference) or unbox (a nullable primitive narrowed to the primitive) kotlinc emits.
                    let narrowed = self.info.ty(e);
                    // A reference (`Any`) smart-cast to `UInt`/`ULong` (`if (x is UInt) … x …`) would
                    // unbox the `kotlin.UInt` value type, but krusty erases unsigned to `int` and would
                    // emit an `Integer` unbox (ClassCastException) — skip rather than miscompile.
                    if narrowed.is_unsigned() && slot_ty.is_reference() {
                        return None;
                    }
                    if narrowed != slot_ty && narrowed != Ty::Error {
                        if self.has_scalar_value_repr(narrowed) && slot_ty.is_reference() {
                            self.emit_type_op(IrTypeOp::ImplicitCoercion, read, ty_to_ir(narrowed))
                        } else if narrowed.is_reference()
                            && slot_ty.is_reference()
                            && !matches!(narrowed, Ty::Null)
                            // A "narrowing" to `kotlin/Any` is a no-op WIDENING to the top type — never a
                            // real smart-cast. It arises when an inline expansion specializes a slot to a
                            // more concrete type than the checker's erased `info.ty` (a generic inline
                            // parameter/`this` bound to the actual argument type); the spurious
                            // `checkcast Object` it would emit erases the value and breaks verification.
                            && !narrowed
                                .obj_internal()
                                .is_some_and(|n| n.matches("kotlin/Any"))
                        {
                            self.emit_type_op(IrTypeOp::Cast, read, ty_to_ir(narrowed))
                        } else {
                            read
                        }
                    } else {
                        read
                    }
                } else if let Some(&(fid, _)) = self.computed_props.get(&n) {
                    // A computed top-level property → call its `getX()` accessor.
                    self.emit_local_call(fid, vec![])
                } else if let Some(c) = self.const_lits.get(&n).cloned() {
                    // A same-file `const val` read → inline its literal (`ldc`), like kotlinc.
                    self.emit_const(c)
                } else if let Some(c) = self
                    .cur_class
                    .as_ref()
                    .and_then(|cc| self.object_const_lits.get(&(*cc, n.clone())))
                    .cloned()
                {
                    // A `const val` of the enclosing `object` read UNQUALIFIED inside its own method
                    // (`fun m() = MAX`) → inline the literal, like kotlinc.
                    self.emit_const(c)
                } else if let Some(&(idx, sty)) = self.statics.get(&n) {
                    let read = self.emit_get_static(idx);
                    // Smart-cast of a top-level `val` to a scalar (`val x: Any; if (x is Double) …`)
                    // unboxes the reference field read, mirroring the local-variable path above.
                    let narrowed = self.info.ty(e);
                    if narrowed != sty
                        && self.has_scalar_value_repr(narrowed)
                        && sty.is_reference()
                        && !narrowed.is_unsigned()
                    {
                        self.emit_type_op(IrTypeOp::ImplicitCoercion, read, ty_to_ir(narrowed))
                    } else {
                        read
                    }
                } else if let Some((facade, ty, _, is_const)) =
                    self.syms.prop_facades.get(&n).cloned()
                {
                    if is_const {
                        // A `const val` from another file has a PUBLIC field and NO accessor — read it as
                        // `getstatic <facade>.X` (kotlinc inlines the constant; a field read is equivalent
                        // and avoids a `NoSuchMethodError` on the non-existent `getX`).
                        self.emit_external_static_field(
                            facade.render(),
                            n.clone(),
                            self.runtime.type_descriptor(ty)?,
                        )
                    } else {
                        // A top-level property from ANOTHER file → call its facade's `getX()` (the field is
                        // private), reusing the backend-agnostic cross-file callee.
                        self.emit_cross_file_call(
                            facade,
                            property_getter_name(&n),
                            vec![],
                            ty_to_ir(ty),
                            vec![],
                        )
                    }
                } else if let Some(class) = self
                    .class_info(&class_internal(self.afile, &n))
                    .filter(|ci| self.ir.classes[ci.id as usize].is_object)
                    .map(|ci| ci.id)
                {
                    // A bare `object` name → its singleton instance.
                    self.emit_static_instance(class, class, "INSTANCE")
                } else if n == "Unit" {
                    // The `Unit` singleton used as a value → `getstatic kotlin/Unit.INSTANCE`.
                    self.emit_unit()
                } else if let Some((owner, field, cty)) = {
                    // A bare CLASSPATH class with a companion object (`Json` → `Json.Default`): read the
                    // companion-instance static field. Resolve the simple name to its classpath internal
                    // via imports (`class_names`), exactly as the checker did. The checker already typed
                    // this as the companion's type, so member calls on it resolve normally.
                    self.syms
                        .class_names
                        .get(&n)
                        .filter(|i| !i.starts_with("__ty/"))
                        .map(|i| i.to_string())
                        .and_then(|internal| {
                            self.syms
                                .libraries
                                .resolve_type(&internal)
                                .and_then(|lt| lt.companion_object)
                                .map(|(f, t)| (internal, f, t.render()))
                        })
                } {
                    self.ir.external_static_instance(&owner, &cty, field)
                } else {
                    // Unqualified member of the enclosing class: a backing field (`this.<field>`), or a
                    // computed property (`this.getX()`).
                    let (this_v, this_ty) = self.lookup("this")?;
                    let recv = self.emit_get_value(this_v);
                    // `this` was flow-narrowed to a subtype by an enclosing `if (this is B)`, and this
                    // member exists only on `B` — `checkcast` the receiver to `B`, then read the member
                    // (backing field or getter) on `B`.
                    if let Some(bi) = self.info.narrowed_this_member.get(&e).copied() {
                        let cast =
                            self.emit_type_op(IrTypeOp::Cast, recv, ty_to_ir(Ty::obj_name(bi)));
                        // `B`'s backing field is private, and `this` is the ENCLOSING class (a
                        // different class), so read through the property getter — a direct `getfield`
                        // would be an `IllegalAccessError`. Fall back to a direct field read only when
                        // there is no getter (a public/platform field).
                        if let Some((class, index, _, _)) =
                            self.resolve_method_name(bi, &property_getter_name(&n))
                        {
                            return Some(self.emit_method_call(class, index, cast, vec![]));
                        }
                        if let Some(ResolvedCall::Member(resolved)) =
                            self.info.resolved_calls.get(&e).cloned()
                        {
                            let member = resolved.member;
                            let ret = resolved.ret;
                            let physical_ret = member.physical_ret;
                            let call = self.emit_library_member_call(
                                cast,
                                bi,
                                member,
                                ret,
                                resolved.suspend,
                                vec![],
                            );
                            return Some(self.coerce_to_static(call, ret, physical_ret));
                        }
                        let (fclass, idx, _) = self.resolve_field_name(bi, &n)?;
                        return Some(self.emit_get_field(cast, fclass, idx));
                    }
                    let read = if let Some(cur) = self.cur_class {
                        // An interface has no backing fields — its properties are abstract getters, so
                        // an unqualified property read in a default method routes through the getter
                        // (`invokeinterface getX`), never a (nonexistent) interface field.
                        let cur_is_iface = self
                            .class_info_name(cur)
                            .is_some_and(|ci| self.ir.classes[ci.id as usize].is_interface);
                        let field = if cur_is_iface
                            || self.field_accessor_props.contains(&(cur, n.clone()))
                        {
                            // A custom-accessor property reads through `getX`, never the raw field.
                            None
                        } else {
                            self.class_info_name(cur).and_then(|ci| {
                                ci.fields
                                    .iter()
                                    .position(|(fn_, _)| *fn_ == n)
                                    .map(|i| (ci.id, i as u32))
                            })
                        };
                        if let Some((class, idx)) = field {
                            self.emit_get_field(recv, class, idx)
                        } else if let Some((class, index, _, _)) =
                            self.resolve_method_name(cur, &property_getter_name(&n))
                        {
                            self.emit_method_call(class, index, recv, vec![])
                        } else {
                            // An inner class reads an enclosing member through `this$0` (its field 0).
                            let cur_id = self.class_info_name(cur)?.id;
                            let outer = match self.ir.classes[cur_id as usize].fields.first() {
                                Some(IrField { name: n0, ty, .. })
                                    if n0 == "this$0" && ty.non_null().obj_internal().is_some() =>
                                {
                                    ty.non_null().obj_internal().unwrap().to_string()
                                }
                                _ => return None,
                            };
                            let this0 = if let Some((v, vty)) = self.lookup("this$0") {
                                if !vty
                                    .obj_internal()
                                    .is_some_and(|n| n.matches(outer.as_str()))
                                {
                                    return None;
                                }
                                self.emit_get_value(v)
                            } else {
                                self.emit_get_field(recv, cur_id, 0)
                            };
                            // The outer backing field is private — read it through its synthesized getter.
                            let (class, index, _, _) =
                                self.resolve_method(&outer, &property_getter_name(&n))?;
                            self.emit_method_call(class, index, this0, vec![])
                        }
                    } else {
                        // An extension/receiver-lambda implicit receiver: `fun A.f() = n` (or
                        // `recv.run { n }`) reads `this.n` from OUTSIDE class A — through the property
                        // getter (the backing field is private) for a user class, the field directly when
                        // one resolves, else the shared builtin/library member read (`String.length`, a
                        // collection accessor, …) — the same path a qualified `this.n` read takes.
                        let internal = this_ty.obj_internal();
                        if let Some(internal) = internal {
                            if let Some((class, index, _, _)) =
                                self.resolve_method_name(internal, &property_getter_name(&n))
                            {
                                self.emit_method_call(class, index, recv, vec![])
                            } else if let Some((fclass, idx, _)) =
                                self.resolve_field_name(internal, &n)
                            {
                                self.emit_get_field(recv, fclass, idx)
                            } else {
                                self.lower_member_read_on(recv, this_ty, &n, e)?
                            }
                        } else {
                            self.lower_member_read_on(recv, this_ty, &n, e)?
                        }
                    };
                    // Smart-cast narrowing: a nullable-primitive *field* read narrowed to its primitive
                    // (after `field != null`) must unbox the wrapper, exactly as the local-variable read
                    // path does — else the `Integer` value reaches an `int` context (a verify error).
                    let narrowed = self.info.ty(e);
                    let field_is_ref = this_ty
                        .obj_internal()
                        .and_then(|i| self.syms.prop_of_name(i, &n))
                        .map_or(false, |(t, _)| t.is_reference());
                    if self.has_scalar_value_repr(narrowed) && field_is_ref {
                        self.emit_type_op(IrTypeOp::ImplicitCoercion, read, ty_to_ir(narrowed))
                    } else {
                        read
                    }
                }
            }
            Expr::Index { array, indices } => {
                let at = self.info.ty(array);
                if let [index] = indices.as_slice() {
                    if at.array_elem().is_some() {
                        let a = self.expr(array)?;
                        let i = self.expr(*index)?;
                        return Some(self.emit_external_call("kotlin/Array.get", Some(a), vec![i]));
                    }
                }
                let recv_v = self.expr(array)?;
                if let Some((v, ret)) = self.lower_op_call(recv_v, at, "get", &indices, e) {
                    return Some(self.coerce_generic_read(v, e, ret));
                }
                self.set_bail("expr Index");
                return None;
            }
            Expr::Member { receiver, name } => {
                if let Some(ExprLowering::ExternalStaticFieldRead {
                    owner,
                    name,
                    descriptor,
                }) = self.info.expr_lowers.get(&e).cloned()
                {
                    let owner = owner.render();
                    return Some(self.emit_external_static_field(&owner, &name, &descriptor));
                }
                // `X::class.java`.
                if matches!(
                    self.info.expr_lowers.get(&e),
                    Some(ExprLowering::ClassLiteralJava)
                ) {
                    return self.expr(receiver);
                }
                // A classpath nested singleton object recorded by the checker (`PrimitiveKind.STRING`) →
                // `getstatic <Outer$Nested>.INSTANCE`.
                if let Some(ExprLowering::ObjectValue { internal }) = self.info.expr_lowers.get(&e)
                {
                    let internal = internal.render();
                    let field = self.runtime.object_instance_field(&internal)?;
                    return Some(self.platform_static_field(field));
                }
                // A classpath EXTENSION property recorded by the checker (`d.elementDescriptors`) →
                // `invokestatic <Kt>.get<Name>(recv)`.
                if let Some(ExprLowering::ExtensionPropertyGet { getter }) =
                    self.info.expr_lowers.get(&e).cloned()
                {
                    // Coerce the receiver to the getter's first (receiver) parameter type — a primitive /
                    // array / value-class receiver must be boxed/unboxed to match the static getter's
                    // descriptor, exactly as an extension-function call coerces its receiver arg. Passing the
                    // raw receiver value VerifyErrors (`arr.indices`).
                    let target = getter
                        .params
                        .first()
                        .copied()
                        .unwrap_or_else(|| self.info.ty(receiver));
                    let a = self.lower_arg(receiver, &target)?;
                    return Some(self.emit_library_static_call(*getter, vec![a], false));
                }
                // Reading an annotation member (`a.x`, `a` typed as the annotation interface): the JVM
                // accessor is the bare member name `x()` (not `getX`), dispatched by `invokeinterface`.
                if let Ty::Obj(internal, _) = self.info.ty(receiver) {
                    if let Some(field) = self
                        .ir
                        .classes
                        .iter()
                        .find(|c| c.fq_name_id() == internal && c.is_annotation)
                        .and_then(|c| c.fields.iter().find(|f| f.name == *name))
                    {
                        let descriptor =
                            format!("(){}", self.runtime.ir_type_descriptor(field.ty)?);
                        let a = self.expr(receiver)?;
                        return Some(self.emit_virtual_call(
                            internal.to_string(),
                            name.clone(),
                            descriptor,
                            true,
                            a,
                            vec![],
                        ));
                    }
                }
                let rt = self.recv_ty(receiver);
                if self.info.resolved_member(e).is_some() {
                    let recv = self.expr(receiver)?;
                    let recv = if rt.is_reference()
                        && matches!(self.afile.expr(receiver), Expr::Name(n)
                            if self.lookup(n).map_or(false, |(_, t)| t != rt))
                    {
                        self.emit_type_op(IrTypeOp::Cast, recv, ty_to_ir(rt))
                    } else {
                        recv
                    };
                    return self.lower_member_read_on(recv, rt, &name, e);
                }
                // A `val` extension property read (`x.doubled`) → its static getter `getDoubled(x)`.
                let rty = self.info.ty(receiver);
                if let Some(gfid) = self.ext_prop_get_id(rty, &name) {
                    let target = self.ir.functions[gfid as usize]
                        .params
                        .first()
                        .cloned()
                        .unwrap_or_else(|| ty_to_ir(rty));
                    let a = self.lower_arg(receiver, &target)?;
                    return Some(self.emit_local_call(gfid, vec![a]));
                }
                // Primitive companion constant `Int.MAX_VALUE` / `Double.NaN` / ... selected by the checker.
                if let Some(lc) = self.info.resolved_library_companion_const(e) {
                    let c = match lc.value {
                        // `Char.MAX_VALUE`/`MIN_VALUE` read back as an integer ConstantValue, but the
                        // constant's type is `Char` — emit a `Char` const so it boxes to `Character` (not
                        // `Integer`) in a vararg/generic position.
                        crate::libraries::LibConst::Int(v) if lc.ty == Ty::Char => {
                            IrConst::Char(char::from_u32(v as u32).unwrap_or('\0'))
                        }
                        crate::libraries::LibConst::Int(v) => IrConst::Int(v),
                        crate::libraries::LibConst::Long(v) => IrConst::Long(v),
                        crate::libraries::LibConst::Float(v) => IrConst::Float(v),
                        crate::libraries::LibConst::Double(v) => IrConst::Double(v),
                    };
                    return Some(self.emit_const(c));
                }
                // `EnumClass.ENTRY` — a static enum-constant read.
                if let Expr::Name(rn) = self.afile.expr(receiver).clone() {
                    let internal = class_internal(self.afile, &rn);
                    if let Some(ci) = self.class_info(&internal) {
                        let cls = ci.id;
                        if let Some(idx) = self.ir.classes[cls as usize]
                            .enum_entries
                            .iter()
                            .position(|e| e.name == name)
                        {
                            return Some(self.ir.add_expr(IrExpr::EnumEntry {
                                class: cls,
                                index: idx as u32,
                            }));
                        }
                    }
                    // `Obj.NAME` where `NAME` is a `const val` of an `object` → inline the literal
                    // (kotlinc inlines a const read; no `getstatic`).
                    let internal_name = type_name(&internal);
                    if let Some(c) = self
                        .object_const_lits
                        .get(&(internal_name, name.clone()))
                        .cloned()
                    {
                        return Some(self.emit_const(c));
                    }
                    // `C.X` where `X` is a companion `const val` → `getstatic C.X` (the field lives on the
                    // outer class C; the JVM initializes it from its `ConstantValue` attribute).
                    if let Some(cty) = self.companion_consts.get(&(internal_name, name.clone())) {
                        return Some(self.emit_external_static_field(
                            internal,
                            name.clone(),
                            self.runtime.type_descriptor(*cty)?,
                        ));
                    }
                    // `Kind.PENDING` on a CLASSPATH enum -> `getstatic <internal>.PENDING:L<internal>;`.
                    if let Some(enum_internal) = self.info.resolved_library_enum_entry_owner(e) {
                        let enum_internal = enum_internal.render();
                        return Some(self.emit_external_static_field(
                            enum_internal.clone(),
                            name.clone(),
                            format!("L{enum_internal};"),
                        ));
                    }
                }
                // `Outer.NestedEnum.ENTRY` — receiver is a `Member` chain naming a nested enum. The
                // checker typed this expression as the enum's own type; use that internal to emit the
                // enum-constant read (the bare-`Name` case above only covers a top-level enum).
                if matches!(self.afile.expr(receiver), Expr::Member { .. }) {
                    if let Some(internal) = self.info.ty(e).obj_internal() {
                        if let Some(ci) = self.class_info_name(internal) {
                            let cls = ci.id;
                            if let Some(idx) = self.ir.classes[cls as usize]
                                .enum_entries
                                .iter()
                                .position(|en| en.name == name)
                            {
                                return Some(self.ir.add_expr(IrExpr::EnumEntry {
                                    class: cls,
                                    index: idx as u32,
                                }));
                            }
                        }
                    }
                }
                // `e.ordinal` / `e.name` on an enum value: dispatched on the receiver's STATIC type while
                // the platform owns the inherited accessor's physical name/descriptor.
                if let Some(accessor) = self.runtime.enum_member_accessor(&name) {
                    if let Some(ci) = self.class_of(rt) {
                        let cid = ci.id as usize;
                        if !self.ir.classes[cid].enum_entries.is_empty() {
                            // Read the owner before the mutable `self.expr` borrow (drops `ci`'s borrow).
                            let owner = self.ir.classes[cid].fq_name();
                            let recv = self.expr(receiver)?;
                            return Some(self.emit_virtual_call(
                                owner,
                                accessor.name,
                                accessor.descriptor,
                                false,
                                recv,
                                vec![],
                            ));
                        }
                    }
                }
                if rt == Ty::Char && name == "code" {
                    // `c.code` → the `Char`'s code unit as an `Int` (a no-op coercion on the JVM stack).
                    let c = self.expr(receiver)?;
                    self.emit_type_op(IrTypeOp::ImplicitCoercion, c, ty_to_ir(Ty::Int))
                } else if rt.array_elem().is_some() && name == "size" {
                    let a = self.expr(receiver)?;
                    self.emit_external_call("kotlin/Array.size", Some(a), vec![])
                } else if let Some(rci) = self.class_of(rt) {
                    // Resolve the field through the superclass chain — it may be declared on a base
                    // class (`b.baseField`). `class` is the *owning* class (whose fieldref we emit).
                    let recv_internal = rci.internal();
                    let recv = self.expr(receiver)?;
                    // The receiver's declared slot type (when it is a simple `Name`) drives the
                    // smartcast `checkcast` inside the shared field-read helper.
                    let slot_ty = match self.afile.expr(receiver) {
                        Expr::Name(n) => self.lookup(n).map(|(_, t)| t),
                        _ => None,
                    };
                    if let Some(read) =
                        self.lower_field_read_on(recv, &recv_internal, &name, e, slot_ty)
                    {
                        read
                    } else if let Some((class, index, _, _)) =
                        self.resolve_method(&recv_internal, &property_getter_name(&name))
                    {
                        // A computed property → `recv.getX()`.
                        self.emit_method_call(class, index, recv, vec![])
                    } else {
                        return None;
                    }
                } else {
                    // A property read on a builtin/library/another-file receiver (`s.length`,
                    // `list.size`, a sibling class's `getX()`): resolved generically through the shared
                    // member-read helper (no per-member name hardcode). The receiver may be smart-cast to
                    // a narrower reference type than its slot (`Any` narrowed by `is String`) — checkcast.
                    let recv = self.expr(receiver)?;
                    let recv = if rt.is_reference()
                        && matches!(self.afile.expr(receiver), Expr::Name(n)
                            if self.lookup(n).map_or(false, |(_, t)| t != rt))
                    {
                        self.emit_type_op(IrTypeOp::Cast, recv, ty_to_ir(rt))
                    } else {
                        recv
                    };
                    self.lower_member_read_on(recv, rt, &name, e)?
                }
            }
            Expr::Binary { op, lhs, rhs } => {
                // `&&` / `||` SHORT-CIRCUIT: the right operand must not be evaluated when the left
                // already decides the result (`x != 0 && 10 / x > 0` must not divide when `x == 0`).
                // Lower to a branch — `a && b` → `if (a) b else false`, `a || b` → `if (a) true else b`
                // — never the eager `iand`/`ior` (which evaluates both, a miscompile for a side-effecting
                // or throwing right operand). This is also the control-flow shape kotlinc emits.
                if matches!(op, BinOp::And | BinOp::Or) {
                    // Constant-fold a literal left operand (kotlinc folds these; a `const val` initializer
                    // must stay a constant, not a branch): `false && _` → false, `true && b` → b,
                    // `true || _` → true, `false || b` → b.
                    if let Expr::BoolLit(lv) = self.afile.expr(lhs) {
                        let lv = *lv;
                        return match (op, lv) {
                            (BinOp::And, false) => Some(self.emit_const(IrConst::Boolean(false))),
                            (BinOp::Or, true) => Some(self.emit_const(IrConst::Boolean(true))),
                            // `true && b` / `false || b` → the right operand.
                            _ => self.expr(rhs),
                        };
                    }
                    // Inside a suspend body the right operand may carry a suspension the CPS flattener
                    // models only at an unconditional position — keep the eager form (`iand`/`ior`) there;
                    // a non-suspend body can't call a suspend fn, so the branch short-circuit is safe.
                    if !self.cur_fn_suspend {
                        let l = self.expr(lhs)?;
                        let r = self.expr(rhs)?;
                        let konst = |this: &mut Self, b: bool| this.emit_const(IrConst::Boolean(b));
                        let (then_e, else_e) = if op == BinOp::And {
                            let f = konst(self, false);
                            (r, f)
                        } else {
                            let t = konst(self, true);
                            (t, r)
                        };
                        return Some(self.emit_when(vec![(Some(l), then_e), (None, else_e)]));
                    }
                }
                // Unsigned `+`/`-`/`*`/`==`/`!=` match the signed two's-complement opcodes, but
                // `/`/`%` need target unsigned intrinsics. Comparisons use the platform unsigned
                // comparator and compare its result with zero.
                let lty = self.info.ty(lhs);
                if lty.is_unsigned()
                    && matches!(
                        op,
                        BinOp::Div | BinOp::Rem | BinOp::Lt | BinOp::Le | BinOp::Gt | BinOp::Ge
                    )
                {
                    let l = self.expr(lhs)?;
                    let r = self.expr(rhs)?;
                    if matches!(op, BinOp::Lt | BinOp::Le | BinOp::Gt | BinOp::Ge) {
                        return self.compare_ordered(lty, bin_to_ir(op)?, l, r);
                    }
                    return match op {
                        BinOp::Div => self.runtime_call(RuntimeOp::UnsignedDivide, lty, vec![l, r]),
                        BinOp::Rem => {
                            self.runtime_call(RuntimeOp::UnsignedRemainder, lty, vec![l, r])
                        }
                        _ => unreachable!(),
                    };
                }
                // A user `operator fun LhsType.plus(…)` (etc.) extension overrides the builtin operator.
                let op_name = op.arith_operator_name();
                if let Some(opn) = op_name {
                    let recv_key = self.recv_ty(lhs).erased_recv();
                    if let Some(&fid) = self.ext_fun_ids.get(&(recv_key, opn.to_string())) {
                        let params = self.ir.functions[fid as usize].params.clone();
                        // Only route to the extension when the RIGHT operand matches its parameter —
                        // `Int + Int` inside an `Int.plus(V)` body is the builtin op, not a re-entry into
                        // the extension (the checker types it `Int`; the lowerer must agree).
                        let rt = self.info.ty(rhs);
                        let arg_ok = params.len() == 2
                            && (ty_to_ir(rt) == params[1]
                                || (rt.is_reference() && ir_type_is_reference(&params[1])));
                        if arg_ok {
                            let l = self.lower_arg(lhs, &params[0])?;
                            let r = self.lower_arg(rhs, &params[1])?;
                            return Some(self.emit_local_call(fid, vec![l, r]));
                        }
                    }
                    if let Some(internal) = self.recv_ty(lhs).obj_internal().map(|s| s.to_string())
                    {
                        if let Some((class, index, mfid, _)) = self.resolve_method(&internal, opn) {
                            let params = self.ir.functions[mfid as usize].params.clone();
                            if let [param] = params.as_slice() {
                                let l = self.expr(lhs)?;
                                let r = self.lower_arg(rhs, param)?;
                                return Some(self.emit_method_call(class, index, l, vec![Some(r)]));
                            }
                        }
                    }
                }
                // A class `compareTo(o): Int` drives relational operators.
                if matches!(op, BinOp::Lt | BinOp::Le | BinOp::Gt | BinOp::Ge) {
                    if let Some(internal) = self.recv_ty(lhs).obj_internal().map(|s| s.to_string())
                    {
                        if let Some((class, index, mfid, _)) =
                            self.resolve_method(&internal, "compareTo")
                        {
                            let params = self.ir.functions[mfid as usize].params.clone();
                            if let [param] = params.as_slice() {
                                let l = self.expr(lhs)?;
                                let r = self.lower_arg(rhs, param)?;
                                let cmp = self.emit_method_call(class, index, l, vec![Some(r)]);
                                let zero = self.emit_const(IrConst::Int(0));
                                return Some(self.emit_primitive_bin_op(bin_to_ir(op)?, cmp, zero));
                            }
                        }
                        // A CLASSPATH `Comparable` type (`class Money : Comparable<Money>` compiled
                        // separately): `compareTo` is a classpath member, not user IR. The checker records
                        // the selected member on the binary expression; lowering only emits that target.
                        let lt = self.recv_ty(lhs);
                        let rt = self.info.ty(rhs);
                        // Reference right operand only — matches the checker guard (a primitive arg to an
                        // erased generic `Comparable.compareTo(Object)` would need a box not applied here).
                        if rt.is_reference() {
                            if let Some(resolved) =
                                self.info.resolved_member(e).cloned().filter(|resolved| {
                                    resolved.member.name == "compareTo" && resolved.ret == Ty::Int
                                })
                            {
                                let l = self.expr(lhs)?;
                                let param = resolved.member.params.first().copied().unwrap_or(rt);
                                let r = self.lower_arg(rhs, &ty_to_ir(param))?;
                                let owner_fallback = lt
                                    .kotlin_class_internal()
                                    .unwrap_or_else(crate::types::wk::any);
                                let cmp = self.emit_library_member_call(
                                    l,
                                    owner_fallback,
                                    resolved.member,
                                    resolved.ret,
                                    resolved.suspend,
                                    vec![r],
                                );
                                let zero = self.emit_const(IrConst::Int(0));
                                return Some(self.emit_primitive_bin_op(bin_to_ir(op)?, cmp, zero));
                            }
                        }
                    }
                }
                // A library operator function on a reference receiver (`list + x` → `CollectionsKt.plus(list,
                // x)`): the CHECKER resolved `a.plus(b)` and recorded the callable (keyed by the binary
                // `ExprId`); the lowerer reads it and emits, lowering operands to the callee's parameter
                // types (a primitive element boxes to `Object`).
                if op_name.is_some() {
                    let lt = self.info.ty(lhs);
                    if lt.is_reference() && self.info.ty(rhs) != Ty::Error {
                        if let Some(c) = self.info.resolved_extension(e).cloned() {
                            if c.params.len() == 2 {
                                let l = self.lower_arg(lhs, &ty_to_ir(c.params[0]))?;
                                let r = self.lower_arg(rhs, &ty_to_ir(c.params[1]))?;
                                return Some(self.emit_library_static_call(c, vec![l, r], false));
                            }
                        }
                    }
                }
                if op == BinOp::Add
                    && (self.info.ty(lhs) == Ty::String || self.info.ty(rhs) == Ty::String)
                {
                    // Flatten the left-nested concat chain (`a + b + c + …`) iteratively, then fold —
                    // a deep chain (a stress test with hundreds of `+`) would otherwise recurse through
                    // `expr` once per operator and overflow the stack. The emitted `String.plus` chain
                    // is identical to the recursive lowering.
                    let is_concat = |this: &Self, l: AstExprId, r: AstExprId| {
                        this.info.ty(l) == Ty::String || this.info.ty(r) == Ty::String
                    };
                    let mut operands = vec![rhs];
                    let mut cur = lhs;
                    loop {
                        match self.afile.expr(cur).clone() {
                            Expr::Binary {
                                op: BinOp::Add,
                                lhs: l2,
                                rhs: r2,
                            } if is_concat(self, l2, r2) => {
                                operands.push(r2);
                                cur = l2;
                            }
                            _ => {
                                operands.push(cur);
                                break;
                            }
                        }
                    }
                    operands.reverse();
                    // Lower an operand, converting an unsigned value to its UNSIGNED decimal string
                    // (`String.plus`/`String.valueOf` on the erased int would print the signed value).
                    let lower_concat_operand = |this: &mut Self, oe: AstExprId| -> Option<u32> {
                        let v = this.expr(oe)?;
                        let t = this.info.ty(oe);
                        Some(if t.is_unsigned() {
                            this.unsigned_to_string(v, t)?
                        } else {
                            v
                        })
                    };
                    let mut acc = lower_concat_operand(self, operands[0])?;
                    for &op_e in &operands[1..] {
                        let r = lower_concat_operand(self, op_e)?;
                        acc = self.emit_external_call("kotlin/String.plus", Some(acc), vec![r]);
                    }
                    acc
                } else {
                    // Both operands are nullable boxed numbers (`Double? == Int?`, e.g. smart-cast from
                    // `Any?`): compare by value with numeric promotion + IEEE — `equals` is type-specific
                    // and would be wrong. The generic path below would route these to a (false) `areEqual`.
                    if matches!(op, BinOp::Eq | BinOp::Ne) {
                        if let (Some(lp), Some(rp)) = (
                            self.info.ty(lhs).nullable_primitive(),
                            self.info.ty(rhs).nullable_primitive(),
                        ) {
                            if let Some(res) =
                                self.lower_numeric_eq_conform(lhs, rhs, lp, rp, op == BinOp::Ne)
                            {
                                return Some(res);
                            }
                        }
                    }
                    let irop = bin_to_ir(op)?;
                    // A primitive op needs both operands in one type. For mixed numeric operands
                    // (`Double < Int`, `1 + 2L`) coerce both to the promoted type; the backend emits
                    // the conversion. Non-numeric mixes (e.g. involving `Char`) have no promotion → bail.
                    let (lt, rt) = (self.info.ty(lhs), self.info.ty(rhs));
                    let mut l = self.expr(lhs)?;
                    let mut r = self.expr(rhs)?;
                    // A `Unit` operand of `==`/`!=` is the `Unit.INSTANCE` singleton — materialize it so the
                    // structural `areEqual` gets an `Object` (`foo() != bar()` where `bar(): Unit`).
                    if matches!(op, BinOp::Eq | BinOp::Ne) {
                        if lt == Ty::Unit {
                            l = self.unit_value_after_effect(l);
                        }
                        if rt == Ty::Unit {
                            r = self.unit_value_after_effect(r);
                        }
                    }
                    // `Char` arithmetic (`'a' + 1`, `c - 1`, `c1 - c2`): `Char`/`Int` share the int stack
                    // representation, but there is no numeric *promotion* between them. Do the op on ints
                    // (coerce the `Char` operands to `Int` — a no-op on the stack, but it types the result
                    // as `Int`); a `Char` result then truncates with `i2c` (Kotlin wraps mod 2^16), a
                    // `Char - Char` difference is a plain `Int`. The checker already typed `e` accordingly.
                    if lt == Ty::Char
                        && matches!(op, BinOp::Add | BinOp::Sub)
                        && (rt == Ty::Int || rt == Ty::Char)
                    {
                        let int_ir = ty_to_ir(Ty::Int);
                        let li = self.emit_type_op(IrTypeOp::ImplicitCoercion, l, int_ir.clone());
                        let ri = if rt == Ty::Char {
                            self.emit_type_op(IrTypeOp::ImplicitCoercion, r, int_ir)
                        } else {
                            r
                        };
                        let raw = self.emit_primitive_bin_op(irop, li, ri);
                        return Some(if self.info.ty(e) == Ty::Char {
                            self.emit_type_op(IrTypeOp::ImplicitCoercion, raw, ty_to_ir(Ty::Char))
                        } else {
                            raw
                        });
                    }
                    if self.has_scalar_value_repr(lt) && self.has_scalar_value_repr(rt) && lt != rt
                    {
                        let p = Ty::promote(lt, rt)?;
                        let pir = ty_to_ir(p);
                        if lt != p {
                            l = self.emit_type_op(IrTypeOp::ImplicitCoercion, l, pir.clone());
                        }
                        if rt != p {
                            r = self.emit_type_op(IrTypeOp::ImplicitCoercion, r, pir);
                        }
                    } else if matches!(op, BinOp::Eq | BinOp::Ne)
                        && lt.is_reference() != rt.is_reference()
                    {
                        // A nullable-primitive wrapper (`Int?`) compared with a primitive: match kotlinc's
                        // short-circuit — when the wrapper is null the result is fixed (`!=`→true,
                        // `==`→false) WITHOUT evaluating the primitive side (which may have side effects).
                        // `{ val t = wrapper; if (t == null) <fixed> else t.unbox <op> prim }`.
                        let l_wp = lt.nullable_primitive();
                        let r_wp = rt.nullable_primitive();
                        if let Some(wp) = l_wp.or(r_wp) {
                            let (w_e, w_ty, p_e) = if l_wp.is_some() {
                                (lhs, lt, rhs)
                            } else {
                                (rhs, rt, lhs)
                            };
                            let wv = self.expr(w_e)?;
                            let v = self.fresh_value();
                            let var = self.emit_variable(v, ty_to_ir(w_ty), Some(wv));
                            let getn = self.emit_get_value(v);
                            let nullc = self.emit_const(IrConst::Null);
                            let isnull = self.emit_primitive_bin_op(IrBinOp::Eq, getn, nullc);
                            let getw = self.emit_get_value(v);
                            let unboxed =
                                self.emit_type_op(IrTypeOp::ImplicitCoercion, getw, ty_to_ir(wp));
                            let pv = self.lower_arg(p_e, &ty_to_ir(wp))?;
                            let cmp = self.emit_primitive_bin_op(irop, unboxed, pv);
                            let fixed = self.emit_const(IrConst::Boolean(op == BinOp::Ne));
                            let when = self.emit_when(vec![(Some(isnull), fixed), (None, cmp)]);
                            return Some(self.emit_block(vec![var], Some(when)));
                        }
                        // A general `Any == 5`: box the primitive operand → structural `Intrinsics.areEqual`.
                        let obj = ty_to_ir(Ty::obj("kotlin/Any"));
                        if self.has_scalar_value_repr(lt) {
                            l = self.emit_type_op(IrTypeOp::ImplicitCoercion, l, obj);
                        } else {
                            r = self.emit_type_op(IrTypeOp::ImplicitCoercion, r, obj);
                        }
                    }
                    self.emit_primitive_bin_op(irop, l, r)
                }
            }
            Expr::If {
                cond,
                then_branch,
                else_branch,
            } => {
                // Constant-fold a literal-boolean condition (`if (false) { … }`) — emit only the taken
                // branch, like kotlinc's dead-code elimination. (Emitting the dead branch can produce
                // unverifiable frames, e.g. a `try` whose handler slot conflicts in unreachable code.)
                match self.afile.expr(cond) {
                    Expr::BoolLit(true) => return self.expr(then_branch),
                    Expr::BoolLit(false) => {
                        return match else_branch {
                            Some(els) => self.expr(els),
                            // `if (false) {}` with no else is a no-op `Unit` statement.
                            None => Some(self.emit_block(vec![], None)),
                        };
                    }
                    _ => {}
                }
                let c = self.expr(cond)?;
                // When the `if`'s result type is a reference but a branch is a primitive (`if (c) true else
                // null` → `Boolean?`), the primitive branch must be boxed at the merge so both branches
                // agree on the (reference) stack type — `lower_arg` to the result type inserts the box.
                let res = self.info.ty(e);
                let t = if res.is_reference() {
                    self.lower_arg(then_branch, &ty_to_ir(res))?
                } else {
                    self.expr(then_branch)?
                };
                let branches = match else_branch {
                    Some(els) => {
                        let e2 = if res.is_reference() {
                            self.lower_arg(els, &ty_to_ir(res))?
                        } else {
                            self.expr(els)?
                        };
                        vec![(Some(c), t), (None, e2)]
                    }
                    None => vec![(Some(c), t)],
                };
                self.emit_when(branches)
            }
            // `x is T` / `x !is T` / `x as T` → the existing `IrTypeOp` node (no new node).
            Expr::Is {
                operand,
                ty,
                negated,
            } => {
                // A reified type parameter (`x is T` in a `<reified T>` inline body) → the bound type.
                let ty = self.subst_type_ref(&ty);
                // A nullable reference target (`x is A?`): `null` IS an `A?`, but plain `instanceof`
                // yields false for null. Lower to `x == null || x is A` (and the De Morgan dual for
                // `x !is A?` → `x != null && x !is A`), binding the operand to a temp so it runs once.
                if ty.nullable {
                    // `ty_ref` returns `None` for any nullable type; resolve the non-null base — a
                    // reference, OR a boxable primitive (`x is Int?` → `x == null || x instanceof Integer`).
                    let mut base_ref = ty.clone();
                    base_ref.nullable = false;
                    // A non-reference base resolves to a primitive whose wrapper the `instanceof` tests
                    // (`x is Int?` → `x == null || x instanceof Integer`). Float/Double are now allowed: a
                    // smart-cast of them reaches the IEEE-correct numeric `==` conform. Unsigned stays
                    // excluded (its conform / value-box unbox isn't modeled).
                    let base = self.ty_ref(&base_ref).or_else(|| {
                        Ty::from_name(&base_ref.name)
                            .filter(|t| self.has_scalar_value_repr(*t) && !t.is_unsigned())
                    });
                    if let Some(target) = base {
                        let inst_operand = ty_to_ir(target);
                        // The operand is stored into an `Any` slot (below); a PRIMITIVE operand must be
                        // BOXED first (see `box_operand_for_instanceof`).
                        let raw = self.expr(operand)?;
                        let arg = self.box_operand_for_instanceof(operand, raw);
                        let v = self.fresh_value();
                        // The temp only feeds `== null` and `instanceof`, so an `Object` slot always
                        // holds it — a precise operand type (or `null`/`Nothing`) could be an invalid
                        // local-variable type.
                        let opnd_ty = ty_to_ir(Ty::obj("kotlin/Any"));
                        let g1 = self.emit_get_value(v);
                        let nullc = self.emit_const(IrConst::Null);
                        let null_test = self.emit_primitive_bin_op(
                            if negated {
                                IrBinOp::RefNe
                            } else {
                                IrBinOp::RefEq
                            },
                            g1,
                            nullc,
                        );
                        let g2 = self.emit_get_value(v);
                        let inst = self.emit_type_op(
                            if negated {
                                IrTypeOp::NotInstanceOf
                            } else {
                                IrTypeOp::InstanceOf
                            },
                            g2,
                            inst_operand,
                        );
                        let combined = self.emit_primitive_bin_op(
                            if negated { IrBinOp::And } else { IrBinOp::Or },
                            null_test,
                            inst,
                        );
                        let temp = self.emit_variable(v, opnd_ty, Some(arg));
                        return Some(self.emit_block(vec![temp], Some(combined)));
                    }
                }
                let raw = self.expr(operand)?;
                let arg = self.box_operand_for_instanceof(operand, raw);
                let op = if negated {
                    IrTypeOp::NotInstanceOf
                } else {
                    IrTypeOp::InstanceOf
                };
                // A reference target, or a primitive (`x is Int` → `instanceof` the boxed wrapper, which
                // the backend resolves from the primitive type_operand).
                let target = self.ty_ref(&ty).or_else(|| {
                    if ty.nullable {
                        None
                    } else {
                        // `x is Int`/`x is Double` → `instanceof` the boxed wrapper. Float/Double are
                        // allowed: a boxed-FP `==` reached after the test conforms with IEEE semantics.
                        Ty::from_name(&ty.name).filter(|t| self.has_scalar_value_repr(*t))
                    }
                })?;
                // An unsigned target tests against its inline-class object (`kotlin/UInt`), not the
                // representation's wrapper (`Integer`).
                let type_operand = if target.is_unsigned() {
                    ty_to_ir(self.unsigned_integer_box_type(target)?)
                } else {
                    ty_to_ir(target)
                };
                self.emit_type_op(op, arg, type_operand)
            }
            Expr::InRange {
                value,
                start,
                end,
                kind,
                negated,
            } => {
                use crate::ast::RangeKind;
                // A REFERENCE range (`x in a..b` where `a`/`b` are user/library types) is not a
                // primitive comparison chain — it desugars to `a.rangeTo(b).contains(x)`. Emit the two
                // operator calls (a member or a library member); an extension `rangeTo`/`contains` is a
                // later slice, so that shape returns `None` (skips) rather than miscompiles.
                let start_ty = self.info.ty(start);
                if start_ty.is_reference() {
                    let recv0 = self.expr(start)?;
                    let (range_v, range_ty) =
                        self.lower_op_call(recv0, start_ty, "rangeTo", &[end], e)?;
                    let (contains_v, _) =
                        self.lower_op_call(range_v, range_ty, "contains", &[value], e)?;
                    if negated {
                        // `!in` → `!contains(...)`, emitted as `contains == false` (the lowering has no
                        // logical-not node — see the primitive `UnOp::Not` path).
                        let f = self.emit_const(IrConst::Boolean(false));
                        return Some(self.emit_primitive_bin_op(IrBinOp::Eq, contains_v, f));
                    }
                    return Some(contains_v);
                }
                // Evaluate the bounds then the value once each (source order: start, end, value —
                // matching kotlinc's `start..end` then `.contains(value)`), into temps, then a
                // comparison chain. `!in` uses the De Morgan dual so no logical-not node is needed.
                let s = self.expr(start)?;
                let sv = self.fresh_value();
                let var_s = self.emit_variable(sv, ty_to_ir(self.info.ty(start)), Some(s));
                let en = self.expr(end)?;
                let ev = self.fresh_value();
                let var_e = self.emit_variable(ev, ty_to_ir(self.info.ty(end)), Some(en));
                let v = self.expr(value)?;
                let vv = self.fresh_value();
                let var_v = self.emit_variable(vv, ty_to_ir(self.info.ty(value)), Some(v));
                // `lo`/`hi` are the inclusive low / (in/ex)clusive high bound. `downTo` runs high→low, so
                // membership is `end <= value <= start` — swap the bounds.
                let (lo, hi, hi_strict) = match kind {
                    RangeKind::Through => (sv, ev, false),
                    RangeKind::Until => (sv, ev, true),
                    RangeKind::DownTo => (ev, sv, false),
                };
                // A comparison `a <op> b` on the loaded temps. Unsigned element types use the platform
                // unsigned comparator, matching kotlinc's unsigned-range membership.
                let elem = self.info.ty(value);
                let cmp = |this: &mut Self, op: IrBinOp, a: u32, b: u32| -> Option<u32> {
                    let la = this.emit_get_value(a);
                    let lb = this.emit_get_value(b);
                    this.compare_ordered(elem, op, la, lb)
                };
                // The De Morgan dual (`value < lo || value > hi`) of `!in` is only valid when the
                // element order is total. For IEEE floating point it is NOT: `!(x <= NaN)` is `true`
                // but `x > NaN` is `false` (all NaN comparisons are false), so distributing the
                // negation flips membership for NaN bounds/values. For float/double, compute the plain
                // `in` chain and boolean-negate it (matching kotlinc, which negates `contains`);
                // integral/char/unsigned ranges keep the cheaper De Morgan form.
                let float_elem = matches!(elem, Ty::Double | Ty::Float);
                let cond = if negated && !float_elem {
                    // value < lo  ||  value (> | >=) hi
                    let c1 = cmp(self, IrBinOp::Lt, vv, lo)?;
                    let c2 = cmp(
                        self,
                        if hi_strict { IrBinOp::Ge } else { IrBinOp::Gt },
                        vv,
                        hi,
                    )?;
                    self.emit_primitive_bin_op(IrBinOp::Or, c1, c2)
                } else {
                    // lo <= value  &&  value (< | <=) hi
                    let c1 = cmp(self, IrBinOp::Le, lo, vv)?;
                    let c2 = cmp(
                        self,
                        if hi_strict { IrBinOp::Lt } else { IrBinOp::Le },
                        vv,
                        hi,
                    )?;
                    let in_chain = self.emit_primitive_bin_op(IrBinOp::And, c1, c2);
                    if negated {
                        // float `!in`: negate the boolean `in` result (`in == false`).
                        let f = self.emit_const(IrConst::Boolean(false));
                        self.emit_primitive_bin_op(IrBinOp::Eq, in_chain, f)
                    } else {
                        in_chain
                    }
                };
                self.emit_block(vec![var_s, var_e, var_v], Some(cond))
            }
            Expr::RangeTo { lo, hi, kind } => {
                use crate::ast::RangeKind;
                let lt = self.info.ty(lo);
                let rt = self.info.ty(hi);
                let range = self.runtime.range_construction(lt, rt)?;
                let lo_v = self.lower_arg(lo, &ty_to_ir(range.elem))?;
                let hi_v = self.lower_arg(hi, &ty_to_ir(range.elem))?;
                match kind {
                    RangeKind::Through => {
                        if let Some(c) = range.through_static {
                            self.emit_library_static_call(c, vec![lo_v, hi_v], false)
                        } else {
                            let mut args = vec![lo_v, hi_v];
                            for _ in 0..range.through.trailing_nulls {
                                args.push(self.emit_const(IrConst::Null));
                            }
                            self.emit_new_external(
                                range.through.internal,
                                range.through.ctor_desc,
                                args,
                            )
                        }
                    }
                    RangeKind::Until => {
                        let c = range.until?;
                        self.emit_library_static_call(c, vec![lo_v, hi_v], false)
                    }
                    // `downTo` never reaches here (it parses as an infix function call, not `RangeTo`).
                    RangeKind::DownTo => return None,
                }
            }
            Expr::IncDec {
                target,
                dec,
                prefix,
            } => {
                // `var++`/`++var` as a value. Only a simple local/captured variable; anything else bails.
                // No temp slot: the update is `i = i ± 1`; the value is the new `i` (prefix) or, for a
                // postfix, the new `i` minus the step (the old value) — valid for every numeric type.
                let Expr::Name(name) = self.afile.expr(target).clone() else {
                    return None;
                };
                // A boxed mutable-capture local: `var++`/`++var` as a value, through its `Ref` holder.
                if let Some(elem) = self.boxed_elem.get(&name).cloned() {
                    let one_c = self.scalar_one_const(elem)?;
                    let (holder, _) = self.lookup(&name)?;
                    let elem_ir = ty_to_ir(elem);
                    let op = if dec { IrBinOp::Sub } else { IrBinOp::Add };
                    let undo = if dec { IrBinOp::Add } else { IrBinOp::Sub };
                    let h1 = self.emit_get_value(holder);
                    let cur = self.ir.add_expr(IrExpr::RefGet {
                        holder: h1,
                        elem: elem_ir.clone(),
                    });
                    let nv = self.scalar_update_value(cur, elem, op, one_c.clone());
                    let h2 = self.emit_get_value(holder);
                    let set = self.ir.add_expr(IrExpr::RefSet {
                        holder: h2,
                        elem: elem_ir.clone(),
                        value: nv,
                    });
                    let h3 = self.emit_get_value(holder);
                    let read = self.ir.add_expr(IrExpr::RefGet {
                        holder: h3,
                        elem: elem_ir,
                    });
                    let value = if prefix {
                        read
                    } else {
                        self.scalar_update_value(read, elem, undo, one_c)
                    };
                    return Some(self.emit_block(vec![set], Some(value)));
                }
                let (v, ty) = self.lookup(&name)?;
                // A user `inc`/`dec` operator on a non-numeric variable → `x = x.inc()` yielding the
                // new value (prefix) or the captured old value (postfix).
                if !ty.is_numeric_or_char() {
                    if prefix {
                        let call = self.lower_member_inc_dec(v, ty, dec)?;
                        let set = self.emit_set_value(v, call);
                        let value = self.emit_get_value(v);
                        return Some(self.emit_block(vec![set], Some(value)));
                    }
                    // Postfix: capture the old value before updating.
                    let tmp = self.fresh_value();
                    let old = self.emit_get_value(v);
                    let var_decl = self.emit_variable(tmp, ty_to_ir(ty), Some(old));
                    let call = self.lower_member_inc_dec(v, ty, dec)?;
                    let set = self.emit_set_value(v, call);
                    let value = self.emit_get_value(tmp);
                    return Some(self.emit_block(vec![var_decl, set], Some(value)));
                }
                let op = if dec { IrBinOp::Sub } else { IrBinOp::Add };
                if ty.int_arithmetic_repr() != ty {
                    // `Byte`/`Short`/`Char` narrow on update (wrap in their own width). No temp slot (a
                    // `Variable` inside an operand `Block` trips the verifier in a template/argument
                    // position): the postfix value is `narrow(new ∓ 1)`, which wraps back to the old value
                    // even at the boundary (`Byte` 127++: new = narrow(128) = -128; narrow(-128 - 1) = 127).
                    let cur = self.emit_get_value(v);
                    let narrowed = self.scalar_update_value(cur, ty, op, IrConst::Int(1));
                    let set = self.emit_set_value(v, narrowed);
                    let value = if prefix {
                        self.emit_get_value(v)
                    } else {
                        let read = self.emit_get_value(v);
                        let undo = if dec { IrBinOp::Add } else { IrBinOp::Sub };
                        self.scalar_update_value(read, ty, undo, IrConst::Int(1))
                    };
                    return Some(self.emit_block(vec![set], Some(value)));
                }
                let one = self.scalar_one_const(ty)?;
                // i = i ± 1 (no temp: wraparound is consistent for Int/Long/Float/Double)
                let cur = self.emit_get_value(v);
                let one1 = self.emit_const(one.clone());
                let nv = self.emit_primitive_bin_op(op, cur, one1);
                let set = self.emit_set_value(v, nv);
                // value: new `i` (prefix), or new `i` ∓ 1 = old `i` (postfix).
                let read = self.emit_get_value(v);
                let value = if prefix {
                    read
                } else {
                    let one2 = self.emit_const(one);
                    let undo = if dec { IrBinOp::Add } else { IrBinOp::Sub };
                    self.emit_primitive_bin_op(undo, read, one2)
                };
                self.emit_block(vec![set], Some(value))
            }
            Expr::As {
                operand,
                ty,
                nullable,
            } => {
                // A reified type parameter (`x as T` in a `<reified T>` inline body) → the bound type.
                let ty = self.subst_type_ref(&ty);
                // A `Unit`-typed OPERAND (`println() as Any`, `foo() as Unit`, `foo() as? Int`): run it
                // for effect, then its value is the `Unit.INSTANCE` singleton (a reference) — cast that.
                if self.info.ty(operand) == Ty::Unit {
                    let eff = self.expr(operand)?;
                    let non_null_ref = ast::TypeRef {
                        nullable: false,
                        ..ty.clone()
                    };
                    let value = if !nullable {
                        // `as T`: `checkcast` the singleton (only `Any`/`Unit` succeed; an impossible
                        // target was already rejected by the checker).
                        let target = self.ty_ref(&non_null_ref)?;
                        let unit = self.emit_unit();
                        self.emit_type_op(IrTypeOp::Cast, unit, ty_to_ir(target))
                    } else if let Some(target) = self.ty_ref(&non_null_ref) {
                        // `as? T` (reference target): the singleton is-a `T` (true for `Any`/`Unit`) →
                        // keep it, else `null`.
                        let u1 = self.emit_unit();
                        let is_t = self.emit_type_op(IrTypeOp::InstanceOf, u1, ty_to_ir(target));
                        let u2 = self.emit_unit();
                        let nullc = self.emit_const(IrConst::Null);
                        self.emit_when(vec![(Some(is_t), u2), (None, nullc)])
                    } else {
                        // `as? Prim` (`Unit` is never a primitive wrapper) → always `null`.
                        self.emit_const(IrConst::Null)
                    };
                    return Some(self.emit_block(vec![eff], Some(value)));
                }
                // `x as? T` (safe cast): `{ val t = x; if (t is T) t as T else null }` — `instanceof`
                // then `checkcast` on the non-null branch, `null` on a mismatch (never throws). The
                // target must be a reference (a primitive `as? Int` yields the boxed `Int?` wrapper —
                // its `instanceof`/`checkcast` already test/keep the wrapper, per the `TypeOp` backend).
                if nullable {
                    // The cast target. A type parameter (`x as? T`) erases to its bound — the same
                    // representation the non-null `as T` branch below uses — so the `instanceof`/`checkcast`
                    // run against the bound (`Object` for an unbounded `T`); `ty_ref` only yields concrete
                    // reference types, so the type-parameter case is resolved here first.
                    let target = match self.cur_tparams.iter().find(|(n, _, _)| *n == ty.name) {
                        Some((name, bound, _)) => Ty::ty_param(name, *bound),
                        // A PRIMITIVE target (`x as? Int`) tests/keeps the boxed wrapper — `instanceof`/
                        // `checkcast` run against `Integer` and the result is the nullable wrapper `Int?`.
                        // `ty_ref` yields only reference targets, so resolve the primitive here. `Unit` is
                        // a reference (`kotlin/Unit`), not a primitive — resolve it via `ty_ref`.
                        None if ty.name != "Unit" => match Ty::from_name(&ty.name) {
                            Some(p) if !p.is_reference() => p.nullable_boxed()?,
                            _ => self.ty_ref(&ty)?,
                        },
                        None => self.ty_ref(&ty)?,
                    };
                    let target_ir = ty_to_ir(target);
                    let mut v = self.expr(operand)?;
                    // A PRIMITIVE operand (`1 as? Int`, `1.0 as? Double`) carries a scalar value, but
                    // `instanceof`/`checkcast` need a reference — box it to `Any` first, then the var
                    // holds (and the cast keeps) the wrapper, exactly like a reference operand.
                    let operand_ty = self.info.ty(operand);
                    let mut oty = ty_to_ir(operand_ty);
                    if self.has_scalar_value_repr(operand_ty) {
                        let any = ty_to_ir(Ty::obj("kotlin/Any"));
                        v = self.emit_type_op(IrTypeOp::ImplicitCoercion, v, any);
                        oty = any;
                    }
                    let ov = self.fresh_value();
                    let var_t = self.emit_variable(ov, oty, Some(v));
                    let g1 = self.emit_get_value(ov);
                    let is_t = self.emit_type_op(IrTypeOp::InstanceOf, g1, target_ir.clone());
                    let g2 = self.emit_get_value(ov);
                    let cast_t = self.emit_type_op(IrTypeOp::Cast, g2, target_ir);
                    let nullc = self.emit_const(IrConst::Null);
                    let when = self.emit_when(vec![(Some(is_t), cast_t), (None, nullc)]);
                    return Some(self.emit_block(vec![var_t], Some(when)));
                }
                let arg = self.expr(operand)?;
                // A PRIMITIVE operand cast to a reference type (`42 as Any`, `'a' as Char?`, `b as
                // Byte?`) is a BOX: the primitive is boxed to its wrapper (which is-a the target), an
                // `ImplicitCoercion` the JVM backend emits as `valueOf`. Handle it before the
                // reference-target paths below (which assume a reference operand + `checkcast`).
                // The operand's ACTUAL representation: an inline body specializes a generic type
                // parameter to a primitive in its SLOT even though the checker's `info.ty` still reports
                // the erased reference — so a bare name consults its scope slot type.
                let operand_repr = match self.afile.expr(operand) {
                    Expr::Name(n) => self
                        .lookup(n)
                        .map(|(_, t)| t)
                        .unwrap_or(self.info.ty(operand)),
                    _ => self.info.ty(operand),
                };
                let target_is_tparam = self.cur_tparams.iter().any(|(n, _, _)| *n == ty.name);
                if self.has_scalar_value_repr(operand_repr)
                    && !operand_repr.is_unsigned()
                    && !target_is_tparam
                {
                    // A PRIMITIVE operand cast to a reference (`42 as Any`, `x as Object`) is a BOX to the
                    // target reference. Use the resolved target (`info.ty(e)` for `Any`/`Object`, else the
                    // non-null `TypeRef`) — a specialized operand's `info.ty(e)` can itself read as the
                    // erased operand, so resolve the target from the annotation when it isn't a reference.
                    let target = {
                        let t = self.info.ty(e);
                        if t.is_reference() {
                            Some(t)
                        } else {
                            let nn = ast::TypeRef {
                                nullable: false,
                                ..ty.clone()
                            };
                            self.ty_ref(&nn).filter(|t| t.is_reference())
                        }
                    };
                    if let Some(target) = target {
                        return Some(self.emit_type_op(
                            IrTypeOp::ImplicitCoercion,
                            arg,
                            ty_to_ir(target),
                        ));
                    }
                }
                // `x as T` — a cast to a type parameter in scope. The IR keeps `T` (with its bound) as
                // the cast target; the JVM backend erases it (checkcast to the bound, `Object` for an
                // unbounded `T`). A non-null `T` (`<T : Any>`, `<T : Foo>`) null-checks like kotlinc
                // (`CastNonNull`); a nullable target (`as T?`, or an unbounded `<T : Any?>`) does not.
                if let Some((name, bound, non_null)) =
                    self.cur_tparams.iter().find(|(n, _, _)| *n == ty.name)
                {
                    let op = if *non_null && !ty.nullable {
                        IrTypeOp::CastNonNull
                    } else {
                        IrTypeOp::Cast
                    };
                    let type_operand = Ty::ty_param(name, *bound);
                    return Some(self.emit_type_op(op, arg, type_operand));
                }
                // A GENUINE primitive operand cast to a DIFFERENT primitive (`1 as Byte`, `1.0 as Int`):
                // NOT a numeric conversion (`i2b` would be wrong) — box it to its own wrapper, then the
                // reference→primitive coercion below `checkcast`s the target wrapper (CCE on mismatch) and
                // unboxes. A REFERENCE operand (a boxed type-parameter value in an inline body) already
                // needs only the `checkcast`+unbox path below; a SAME-primitive cast is that identity.
                if !ty.nullable
                    && self.has_scalar_value_repr(operand_repr)
                    && !operand_repr.is_reference()
                {
                    if let Some(tprim) = Ty::from_name(&ty.name).filter(|t| {
                        self.has_scalar_value_repr(*t) && !t.is_unsigned() && *t != operand_repr
                    }) {
                        let any = ty_to_ir(Ty::obj("kotlin/Any"));
                        let boxed = self.emit_type_op(IrTypeOp::ImplicitCoercion, arg, any);
                        return Some(self.emit_type_op(
                            IrTypeOp::ImplicitCoercion,
                            boxed,
                            ty_to_ir(tprim),
                        ));
                    }
                }
                // `x as Int` (non-null primitive target) is an unbox: `checkcast Integer; intValue()`,
                // emitted by the `ImplicitCoercion` reference→primitive path. `ty_ref` only yields
                // reference types, so handle the primitive case before it.
                if !ty.nullable {
                    if let Some(prim) = Ty::from_name(&ty.name)
                        .filter(|t| self.has_scalar_value_repr(*t) && !t.is_unsigned())
                    {
                        return Some(self.emit_type_op(
                            IrTypeOp::ImplicitCoercion,
                            arg,
                            ty_to_ir(prim),
                        ));
                    }
                }
                // `x as Foo?` is a plain `checkcast Foo` (a reference target; `null` passes the
                // checkcast). `ty_ref` rejects any nullable `TypeRef`, so resolve the NON-NULL form —
                // the JVM cast target is the same class either way; only the null-throwing behaviour
                // (selected below via `ty.nullable`) differs.
                let non_null_ty = ast::TypeRef {
                    nullable: false,
                    ..ty.clone()
                };
                let target = self.ty_ref(&non_null_ty)?;
                // Preserve the target's `?` on the cast: the JVM `checkcast` class is the same either way,
                // but the value-class pass needs the nullability to decide a `Str?` (`= String?`, unboxed)
                // vs a non-null `Str` cast — a plain (non-VC) reference cast is unaffected (the emitter
                // peels the `?` for `checkcast`). Nullability tracking is otherwise erased in `Ty`.
                let type_operand = if ty.nullable {
                    ty_to_ir(Ty::nullable(target))
                } else {
                    ty_to_ir(target)
                };
                // `as T` to a non-null reference type throws on `null` (kotlinc null-checks before the
                // `checkcast`); `as T?` and primitive casts are a plain `checkcast`/coercion.
                let op = if !ty.nullable && target.is_reference() {
                    IrTypeOp::CastNonNull
                } else {
                    IrTypeOp::Cast
                };
                self.emit_type_op(op, arg, type_operand)
            }
            Expr::Unary { op, operand } => {
                use crate::ast::UnOp;
                let v = self.expr(operand)?;
                match op {
                    // `-x` → `0 - x` (zero typed to match); `!x` → `x == false`.
                    UnOp::Neg => {
                        // A negated `Double`/`Float` literal is the negative *constant* — not `0.0 - lit`,
                        // which yields `+0.0` for `-0.0` (losing the sign IEEE-754 comparisons distinguish,
                        // e.g. `Double.compare(0.0, -0.0) == 1`).
                        match self.afile.expr(operand) {
                            Expr::DoubleLit(d) => {
                                return Some(self.emit_const(IrConst::Double(-d)))
                            }
                            Expr::FloatLit(f) => return Some(self.emit_const(IrConst::Float(-f))),
                            _ => {}
                        }
                        // `-x` → `0 - x` with the zero typed to the operand so both Sub operands
                        // share one numeric type (Byte/Short/Char negate in the `int` category).
                        let zero = match self.info.ty(operand) {
                            Ty::Long => self.emit_const(IrConst::Long(0)),
                            Ty::Double => self.emit_const(IrConst::Double(0.0)),
                            Ty::Float => self.emit_const(IrConst::Float(0.0)),
                            _ => self.emit_const(IrConst::Int(0)),
                        };
                        self.emit_primitive_bin_op(IrBinOp::Sub, zero, v)
                    }
                    UnOp::Not => {
                        let f = self.emit_const(IrConst::Boolean(false));
                        self.emit_primitive_bin_op(IrBinOp::Eq, v, f)
                    }
                    // Unary `+` is identity on numerics — emit the operand unchanged. A non-numeric
                    // operand (a user `unaryPlus` operator) isn't modeled → skip the file.
                    UnOp::Plus => {
                        if !self.info.ty(operand).is_numeric() {
                            return None;
                        }
                        v
                    }
                }
            }
            // `when` → `IrWhen`. With a subject, each arm becomes `subject == cond` (OR-ed for
            // multiple conditions); the subject is re-evaluated per comparison (correct for the
            // side-effect-free subjects in the core subset). Without a subject, the conditions are
            // boolean tests directly.
            Expr::When { subject, arms } => {
                // Bail on shapes the flat IR can't emit safely: branches that mix `Unit` with real
                // values (only valid as a discarded statement, indistinguishable here from a value
                // use → inconsistent frames), and a subject `==` comparison that mixes a primitive
                // with a reference (e.g. `when (i: Int) { null -> … }` → bad-typed compare). A `Nothing`
                // (diverging `throw`/`return`) branch is exempt: it pushes nothing at the merge, so a
                // statement `when` with a throwing `else` (`is A -> r = …; else -> throw`) is fine.
                let body_tys: Vec<Ty> = arms.iter().map(|a| self.info.ty(a.body)).collect();
                // A `Nothing`-typed arm (a `throw`/`return`, or a CALL to a `Nothing`-returning function)
                // pushes nothing at the merge — it's exempt from the "mixes Unit with a value" bail. The
                // checker represents semantic bottom as `Ty::Nothing`.
                let unit_value_ty = stored_value_ty(Ty::Unit);
                let is_unit_body = |t: Ty| t == Ty::Unit || t == unit_value_ty;
                let any_unit = body_tys.iter().any(|t| is_unit_body(*t));
                let all_unit = any_unit
                    && body_tys
                        .iter()
                        .all(|t| is_unit_body(*t) || *t == Ty::Nothing);
                if any_unit && !all_unit {
                    return None;
                }
                // An unsigned subject compares its arms with unsigned `==` (bit-equal, same as signed),
                // but a `ULong` subject whose magnitude exceeds `Long.MAX` needs care, and the unsigned
                // const-val arms aren't materialized yet — bail rather than risk a mismatch.
                if subject.map_or(false, |s| self.info.ty(s).is_unsigned()) {
                    return None;
                }
                // A no-`else` `when` used as a *value* is only accepted by the checker when it is
                // exhaustive (every enum entry / both booleans / a sealed hierarchy covered). The flat
                // emitter can't *prove* exhaustiveness, but it can rely on it: the last arm is dropped
                // to the `else` (one arm always matches, so the final one is the catch-all). This is
                // behavior-preserving for an exhaustive `when`.
                let has_else = arms.iter().any(|a| a.conditions.is_empty());
                let make_last_else = !has_else && self.info.ty(e) != Ty::Unit && !arms.is_empty();
                if let Some(subj) = subject {
                    let st = self.info.ty(subj);
                    for arm in &arms {
                        for &c in &arm.conditions {
                            // `is`/`in` conditions are complete boolean tests, not `==` comparands —
                            // their type (`Boolean`) needn't match the subject's primitiveness.
                            if is_when_test(self.afile, c) {
                                continue;
                            }
                            if self.has_scalar_value_repr(st)
                                != self.has_scalar_value_repr(self.info.ty(c))
                            {
                                return None;
                            }
                        }
                    }
                }
                // Any subject other than a bare `Name` is evaluated ONCE into a temp: a branchy subject
                // (`when (when …)`) so it runs on a clean stack, and a side-effecting one (`when (a++)`,
                // a call) so its effect happens exactly once — never zero times (an empty `when`) nor
                // once per comparison. A bare `Name` stays on the cheap re-evaluate path, which is
                // side-effect-free and also correct for a smart-cast local (whose slot type differs
                // from its static type, and which a temp store would mis-frame).
                let subj_tmp = match subject {
                    Some(subj) if !matches!(self.afile.expr(subj), Expr::Name(_)) => {
                        let sv = self.expr(subj)?;
                        let v = self.fresh_value();
                        let var = self.emit_variable(v, ty_to_ir(self.info.ty(subj)), Some(sv));
                        Some((v, var))
                    }
                    _ => None,
                };
                let last = arms.len().saturating_sub(1);
                // Like `if`, a `when` whose result is a reference but whose arm is a primitive must box that
                // arm at the merge so every branch agrees on the (reference) stack type.
                let res = self.info.ty(e);
                let mut branches = Vec::new();
                for (ai, arm) in arms.iter().enumerate() {
                    let body = if all_unit {
                        self.lower_arg(arm.body, &unit_value_ty)?
                    } else if res.is_reference() {
                        self.lower_arg(arm.body, &ty_to_ir(res))?
                    } else {
                        self.expr(arm.body)?
                    };
                    if arm.conditions.is_empty() || (make_last_else && ai == last) {
                        branches.push((None, body)); // else (real, or the exhaustive last arm)
                    } else {
                        let mut cond: Option<u32> = None;
                        for &c in &arm.conditions {
                            // An `is`/`!is` or `in`/`!in` condition is already a complete boolean test
                            // involving the subject (the parser embeds it) — use it directly rather than
                            // comparing the subject against it with `==`.
                            let test = if is_when_test(self.afile, c) {
                                self.expr(c)?
                            } else {
                                match (subj_tmp, subject) {
                                    (Some((v, _)), _) => {
                                        let s = self.emit_get_value(v);
                                        let cv = self.expr(c)?;
                                        self.emit_primitive_bin_op(IrBinOp::Eq, s, cv)
                                    }
                                    (None, Some(subj)) => {
                                        let s = self.expr(subj)?;
                                        let cv = self.expr(c)?;
                                        self.emit_primitive_bin_op(IrBinOp::Eq, s, cv)
                                    }
                                    (None, None) => self.expr(c)?,
                                }
                            };
                            cond = Some(match cond {
                                Some(prev) => self.emit_primitive_bin_op(IrBinOp::Or, prev, test),
                                None => test,
                            });
                        }
                        branches.push((cond, body));
                    }
                }
                let when = self.emit_when(branches);
                // Prepend the subject-temp declaration (if any) so it's evaluated before the arms.
                match subj_tmp {
                    Some((_, var)) => self.emit_block(vec![var], Some(when)),
                    None => when,
                }
            }
            Expr::Template(parts) => {
                // Build an ordered list of parts, dropping empty string-literal chunks (kotlinc does),
                // and emit ONE `StringConcat` — the backend turns it into kotlinc's single-StringBuilder
                // (or `String.valueOf` for a lone interpolation) shape, not a `String.plus` chain.
                let mut ir_parts = Vec::new();
                for part in parts {
                    match part {
                        TemplatePart::Str(s) if s.is_empty() => {}
                        TemplatePart::Str(s) => ir_parts.push(self.ir_const_str(s)),
                        TemplatePart::Expr(e) => {
                            let v = self.expr(e)?;
                            // An unsigned interpolated value prints in unsigned decimal.
                            let ety = self.info.ty(e);
                            let v = if ety.is_unsigned() {
                                self.unsigned_to_string(v, ety)?
                            } else {
                                v
                            };
                            ir_parts.push(v);
                        }
                    }
                }
                if ir_parts.is_empty() {
                    ir_parts.push(self.ir_const_str(String::new()));
                }
                self.ir.add_expr(IrExpr::StringConcat(ir_parts))
            }
            // A receiver-lambda scope function the checker resolved (`x.run { … }`, `with(x) { … }`):
            // inline it generically — bind `this` to the receiver, lower the body — driven by the
            // checker's recorded decision, NOT a backend name-match.
            // A classpath value-class COMPANION call (`Result.success(42)`): load the companion singleton
            // (`getstatic <class>.<field>:L<companion>;`) as the receiver, then an inline-splice of the
            // companion's (instance) `inline` method — `success`'s `this` is the singleton, its param the
            // boxed argument. The splicer drops the unused `this` and inlines the arg, like kotlinc.
            // `suspendCoroutineUninterceptedOrReturn { c -> block }` — a `kotlin.coroutines` inline
            // intrinsic (recognized via the registry). The block runs with the enclosing suspend
            // function's own `Continuation` bound as its parameter; kotlinc inlines the block and returns
            // its `Any?` result. The leaf shape `{ COROUTINE_SUSPENDED }` (and any block that does NOT
            // read its continuation parameter) inlines to just the block body. A block that DOES read the
            // continuation needs the (post-CPS) continuation slot threaded in — not modeled here, so it
            // bails (skip the file) rather than binding a wrong slot.
            Expr::Call { callee, args }
                if args.len() == 1
                    && matches!(self.afile.expr(callee), ast::Expr::Name(n)
                        if crate::libraries::coroutine_intrinsic(n)
                            == Some(crate::libraries::CoroutineIntrinsic::SuspendCoroutineUninterceptedOrReturn)) =>
            {
                let ast::Expr::Lambda { params, body } = self.afile.expr(args[0]).clone() else {
                    return None;
                };
                let cont_name = ast::first_lambda_param_or_it(&params);
                if name_used_as_value(self.afile, body, &cont_name) {
                    // The block reads its continuation (`c.resume(t)`): bind `c` to the enclosing suspend
                    // function's own `Continuation` via the `CurrentContinuation` placeholder — the CPS
                    // pass rewrites it to the real continuation value once the trailing parameter exists.
                    let slot = self.fresh_value();
                    let cont = self.ir.add_expr(IrExpr::CurrentContinuation);
                    let cont_ty = Ty::obj("kotlin/coroutines/Continuation");
                    let var = self.emit_variable(slot, ty_to_ir(cont_ty), Some(cont));
                    let depth = self.scope.len();
                    self.scope.push((cont_name, slot, cont_ty));
                    let body_val = self.expr(body);
                    self.scope.truncate(depth);
                    let body_val = body_val?;
                    self.emit_block(vec![var], Some(body_val))
                } else {
                    self.expr(body)?
                }
            }
            Expr::Call { args, .. }
                if matches!(
                    self.info.expr_lowers.get(&e),
                    Some(ExprLowering::Invoke { .. })
                ) =>
            {
                let ExprLowering::Invoke {
                    receiver,
                    params,
                    kind,
                } = self.info.expr_lowers.get(&e).cloned()?
                else {
                    return None;
                };
                if params.len() != args.len() {
                    return None;
                }
                self.lower_invoke(e, receiver, &params, kind, &args)?
            }
            Expr::Call { .. }
                if matches!(
                    self.info.expr_lowers.get(&e),
                    Some(ExprLowering::InlineCall(_))
                ) =>
            {
                match self.info.expr_lowers.get(&e).cloned()? {
                    ExprLowering::InlineCall(InlineCall::ValueCompanion(cf)) => {
                        let args = match self.afile.expr(e).clone() {
                            Expr::Call { args, .. } => args,
                            _ => return None,
                        };
                        let recv_field = self.runtime.companion_instance_field(
                            &cf.class_internal.render(),
                            &cf.companion_internal.render(),
                            &cf.companion_field,
                        )?;
                        let recv = self.platform_static_field(recv_field);
                        // A value-class companion fn's params are erased reference types
                        // (`success(Object)`, `failure(Throwable)`) — target `Object` so a primitive
                        // argument is boxed (`Integer.valueOf`), matching kotlinc; a reference argument
                        // passes through unchanged.
                        let obj_ty = Ty::nullable(Ty::obj("kotlin/Any"));
                        let mut ir_args = Vec::with_capacity(args.len());
                        for &a in &args {
                            ir_args.push(self.lower_arg(a, &obj_ty)?);
                        }
                        Some(self.emit_call(
                            Callee::Static {
                                owner: cf.callable.owner,
                                name: cf.callable.name.clone(),
                                descriptor: cf.callable.descriptor.clone(),
                                inline: cf.callable.inline,
                            },
                            Some(recv),
                            ir_args,
                        ))?
                    }
                    ExprLowering::InlineCall(InlineCall::ReceiverLambda(rl)) => {
                        self.lower_receiver_lambda(rl)?
                    }
                    _ => return None,
                }
            }
            // A call with a spread argument (`foo(*a)`). Only the single-spread-to-a-top-level-vararg
            // form is handled (the array is passed through via the platform copy helper); ANY other
            // shape (mixed spreads, fixed args, member/library callee, primitive element, complex spread
            // expr) returns `None` → the file skips, never miscompiles. The guard ensures a spread arg
            // never reaches the normal vararg-packing paths below.
            Expr::Call { callee, args } if args.iter().any(|&a| self.afile.is_spread_arg(a)) => {
                self.lower_single_spread_call(e, callee, &args)?
            }
            Expr::Call { callee, args } => match self.afile.expr(callee).clone() {
                // Local top-level function, or constructor `C(args)`.
                Expr::Name(fname) => {
                    // An unqualified call to a classpath `object` MEMBER imported via `import Obj.member`
                    // (`logger {}`): the checker recorded the object. Dispatch on the singleton — read
                    // `getstatic Obj.INSTANCE` as the receiver and invoke the member.
                    if let Some(ExprLowering::ObjectMemberCall { internal }) =
                        self.info.expr_lowers.get(&e)
                    {
                        return self.lower_object_member_call(*internal, &fname, &args, e);
                    }
                    let one_lambda_arg = self.single_lambda_arg(&args);
                    // Reified free function `serializer<T>()` (kotlinx.serialization.serializer): a
                    // `reified inline` that can't be called directly (throws at runtime) — desugar to
                    // `T.serializer()` for a `@Serializable` T, the way kotlinc's inliner does.
                    if fname == "serializer"
                        && args.is_empty()
                        && self.lookup(&fname).is_none()
                        && !self.module_declares(&fname)
                    {
                        if let Some(c) = self
                            .afile
                            .call_type_args
                            .get(&e.0)
                            .and_then(|ts| ts.first())
                            .and_then(|tr| self.ty_ref(tr))
                            .and_then(|targ| self.serializable_internal(targ))
                        {
                            return Some(self.serializer_crossfile(c));
                        }
                    }
                    // No-receiver `run { … }` (the stdlib `inline fun <R> run(block: () -> R): R =
                    // block()`): inline the lambda body directly as the value. The receiver scope
                    // functions (`x.let`/`with(x)`) are intercepted similarly; without this, no-receiver
                    // `run` falls to the bytecode splicer, which bails on a branchy body (`run { if … }`).
                    if let ("run", Some((_, params, body)), true, true) = (
                        fname.as_str(),
                        one_lambda_arg.as_ref(),
                        self.lookup(&fname).is_none(),
                        !self.module_declares(&fname),
                    ) {
                        if params.is_empty() && !body_has_labeled_return(self.afile, *body, "run") {
                            return self.expr(*body);
                        }
                    }
                    // A call to a lifted local function — the checker mapped this call to its decl.
                    if let Some(target) = self.info.resolved_local_function(e).cloned() {
                        return self.lower_local_function_call(&target, &args);
                    }
                    // A call `param(args)` where `param` is a lambda parameter of the `inline fun`
                    // currently being expanded: inline the passed lambda's body in place.
                    if self.lookup(&fname).is_none() {
                        if let Some(idx) =
                            self.inline_lambdas.iter().rposition(|(n, ..)| *n == fname)
                        {
                            return self.lower_inline_lambda_invoke(idx, &args);
                        }
                    }
                    // A user-defined `inline fun foo(...)` — expand it here (kotlinc's inliner): bind its
                    // value parameters to the evaluated arguments, register its lambda arguments, and
                    // lower its body so a lambda capturing a mutable local works (no closure).
                    if self.lookup(&fname).is_none() {
                        if let Some(target) = self
                            .info
                            .resolved_module_top_level(e)
                            .filter(|target| target.name == fname && target.inline.can_inline())
                            .cloned()
                        {
                            return self.lower_inline_fn_call(
                                &fname,
                                &args,
                                e.0,
                                None,
                                Some(&target),
                            );
                        }
                    }
                    // SAM conversion `Pred { lambda }`: constructor syntax for a functional interface.
                    if let (Some((arg, params, body)), true) =
                        (one_lambda_arg.as_ref(), self.lookup(&fname).is_none())
                    {
                        if let Some(internal) = self.info.ty(e).obj_internal() {
                            let internal = internal.render();
                            let target = self.sam_target(&internal).or_else(|| {
                                self.syms
                                    .libraries
                                    .resolve_type(&internal)
                                    .and_then(|t| t.sam_method)
                                    .map(|m| (m.name, m.ret == Ty::Unit))
                            });
                            if let Some((method, void)) = target {
                                let iface = internal.to_string();
                                return self.lower_lambda_sam(
                                    *arg,
                                    params,
                                    *body,
                                    Some((iface, method, void)),
                                );
                            }
                        }
                    }
                    // `f(args)` where `f` is a field/property of the enclosing class (not a local value or
                    // a top-level function) — invoking a function value through a field isn't modeled;
                    // bail rather than miscompile (it would emit a bogus constructor call).
                    if self.lookup(&fname).is_none() && !self.module_declares(&fname) {
                        if let Some(cur) = self.cur_class {
                            if self
                                .class_info_name(cur)
                                .map_or(false, |ci| ci.fields.iter().any(|(n, _)| *n == fname))
                            {
                                return None;
                            }
                        }
                    }
                    // The array creators (`arrayOf`/`intArrayOf`/…/`IntArray(n)`/`Array(n){}`) are
                    // compiler synthetics — the synthetic registry (priority over the classpath)
                    // supplies their IR body directly. Honor user shadowing first: a user-defined `fun
                    // arrayOf` (or a local of that name) wins, exactly as in kotlinc.
                    let array_intrinsic_ok =
                        self.lookup(&fname).is_none() && !self.module_declares(&fname);
                    if array_intrinsic_ok {
                        if let Some(syn) = crate::synthetics::lookup(&fname) {
                            let call = crate::synthetics::SynthCall {
                                args: &args,
                                call: e,
                            };
                            if let Some(r) = (syn.body)(syn, self, &call) {
                                return Some(r);
                            }
                        }
                    }
                    // Member of the nearest implicit receiver shadows a same-module top-level function of
                    // the same name (kotlinc scoping — the checker resolves it as a member, so the lowerer
                    // must too). Only in a receiver-lambda body (`cur_class` cleared) and when the name is
                    // not a local; `lower_this_member_call` returns `None` when no member matches, so a
                    // genuine top-level call still falls through to the module-function path below.
                    if self.cur_class.is_none() && self.lookup(&fname).is_none() {
                        if let Some((this_v, this_ty)) = self.lookup("this") {
                            if let Some(r) =
                                self.lower_this_member_call(this_v, this_ty, &fname, &args, e)
                            {
                                return Some(r);
                            }
                        }
                    }
                    if let Some((target, fid)) = self
                        .info
                        .resolved_module_top_level(e)
                        .cloned()
                        .filter(|target| target.name == fname)
                        .and_then(|target| {
                            (target.source_file == Some(self.file_index))
                                .then(|| {
                                    target
                                        .source_decl
                                        .and_then(|decl| self.fun_ids_by_decl.get(&decl).copied())
                                        .map(|fid| (target, fid))
                                })
                                .flatten()
                        })
                    {
                        // A `vararg` function: pack the trailing arguments into a fresh array for the
                        // last (array) parameter. (Spread `*arr` and a branchy element are unsupported.)
                        if target.call_sig.vararg {
                            let params = self.ir.functions[fid as usize].params.clone();
                            let fixed = params.len() - 1;
                            if args.len() < fixed {
                                // Fewer than the fixed parameters were supplied — a trailing fixed
                                // parameter (a DEFAULT) is omitted along with the vararg. Route through the
                                // `$default` stub (which fills the defaults and takes an empty vararg
                                // array), rather than the plain vararg-packing path below.
                                let meta = target.param_meta.clone();
                                return self.lower_toplevel_default_call(
                                    e, fid, &meta, &args, &params, true,
                                );
                            }
                            let elem_ty = target.params[fixed].array_elem()?;
                            let elem_ir = ty_to_ir(elem_ty);
                            let mut a = Vec::new();
                            for (i, &arg) in args.iter().take(fixed).enumerate() {
                                a.push(self.lower_arg(arg, &params[i])?);
                            }
                            // For a GENERIC vararg (`vararg z: T`) the erased element type is `Any`, so a
                            // primitive argument would box to its own wrapper (`-1` → `Integer`). When the
                            // call supplies a primitive type argument (`mk<Long>(-1)`), coerce each element
                            // to that primitive first (`Int`→`Long`), then box — matching kotlinc.
                            let targ_prim = if elem_ty.is_erased_top() {
                                self.afile
                                    .call_type_args
                                    .get(&e.0)
                                    .and_then(|ts| ts.first())
                                    .map(|r| ty_of(self.afile, r, &*self.syms.libraries))
                                    .filter(|t| self.has_scalar_value_repr(*t))
                            } else {
                                None
                            };
                            let mut elements = Vec::new();
                            for &arg in &args[fixed..] {
                                if is_branchy(self.afile, arg) {
                                    return None;
                                }
                                if let Some(p) = targ_prim {
                                    let v = self.lower_arg(arg, &ty_to_ir(p))?;
                                    elements.push(self.emit_type_op(
                                        IrTypeOp::ImplicitCoercion,
                                        v,
                                        elem_ir.clone(),
                                    ));
                                } else {
                                    elements.push(self.lower_arg(arg, &elem_ir)?);
                                }
                            }
                            let arr = self.emit_vararg(params[fixed], elements);
                            a.push(arr);
                            return Some(self.emit_local_call(fid, a));
                        }
                        let params = self.ir.functions[fid as usize].params.clone();
                        let meta = target.param_meta.clone();
                        // Context parameters (`context(a: A) fun f()`): the checker resolved each leading
                        // context parameter to an in-scope source; load and PREPEND them, then the
                        // explicit arguments fill the remaining value parameters. Defaulted value params
                        // reuse the normal call-site default mapper on the sliced value-parameter list.
                        if !target.context_args.is_empty() {
                            let ctx_n = target.context_args.len();
                            if ctx_n <= params.len()
                                && ctx_n <= meta.len()
                                && args.len() <= params.len() - ctx_n
                            {
                                let mut a = Vec::new();
                                for src in &target.context_args {
                                    let (v, _) = self.lookup(src)?;
                                    a.push(self.emit_get_value(v));
                                }
                                let (mut value_args, prelude) = self.lower_args_defaulted(
                                    e,
                                    &meta[ctx_n..],
                                    &args,
                                    &params[ctx_n..],
                                )?;
                                a.append(&mut value_args);
                                let call = self.emit_local_call(fid, a);
                                return Some(self.wrap_arg_prelude(call, prelude));
                            }
                        }
                        // Omitted trailing args are filled from constant-literal defaults.
                        if self.erased_generic_call_unmodeled(e, &target.name) {
                            return None;
                        }
                        // Fill omitted arguments from CONST-literal defaults at the call site; if that
                        // bails (a NON-const/side-effecting omitted default), route through the
                        // `foo$default(…, mask, marker)` synthetic (kotlinc's default-argument ABI).
                        let call = if let Some((a, prelude)) =
                            self.lower_args_defaulted(e, &meta, &args, &params)
                        {
                            let call = self.emit_local_call(fid, a);
                            self.wrap_arg_prelude(call, prelude)
                        } else {
                            // The checker-selected call signature is the authoritative vararg flag (a
                            // vararg callee was already fully handled and returned in the vararg block
                            // above, so this is reliably `false` here).
                            self.lower_toplevel_default_call(
                                e,
                                fid,
                                &meta,
                                &args,
                                &params,
                                target.call_sig.vararg,
                            )?
                        };
                        let ret = self.ir.functions[fid as usize].ret.clone();
                        self.coerce_erased_call_result(e, call, &ret, target.ret_is_tparam)
                    } else if let Some((target, facade)) =
                        self.info
                            .resolved_module_top_level(e)
                            .cloned()
                            .filter(|target| target.name == fname)
                            .and_then(|target| {
                                target.source_file.zip(target.source_decl).and_then(
                                    |(file, decl)| {
                                        self.syms
                                            .fn_facades_by_decl
                                            .get(&(file, decl.0))
                                            .cloned()
                                            .map(|facade| (target, facade))
                                    },
                                )
                            })
                    {
                        self.lower_cross_file_module_call(e, &target, facade, &args)?
                    } else if let Some(r) = {
                        // Inside a receiver lambda / extension-fn body (`cur_class` cleared, `this` is the
                        // external receiver), an unqualified call resolves against the implicit `this`
                        // receiver — a member or a stdlib extension — BEFORE a receiver-less top-level
                        // function, matching Kotlin's scoping (`"ab".run { reversed() }` is
                        // `this.reversed()`, not the top-level `reversed`).
                        if self.cur_class.is_none()
                            && self.lookup(&fname).is_none()
                            && !self.module_declares(&fname)
                        {
                            self.lookup("this").and_then(|(this_v, this_ty)| {
                                self.lower_this_member_call(this_v, this_ty, &fname, &args, e)
                            })
                        } else {
                            None
                        }
                    } {
                        r
                    } else if let Some(r) = {
                        // An unqualified call inside a class that the checker resolved to an INHERITED
                        // member of a CLASSPATH superclass (`class Sub : lib.Base()` calling `secret()`).
                        // `resolve_method` walks user classes only, so this lowers as neither a sibling nor
                        // a top-level call; route it through the enclosing `this` (slot 0) and the member
                        // the checker recorded (`lower_this_member_call` reuses `resolved_calls`).
                        // Fire when the checker recorded the member, OR when it is a sibling method of the
                        // enclosing class (`resolve_method`) — the latter covers a bare call OMITTING a
                        // constant-default argument (`resolveRoles(id)` on `resolveRoles(id, x = null)`),
                        // which the checker does not record as `resolved_member`. `lower_this_member_call`
                        // then fills the omitted default (or falls through to `None` = skip the file).
                        if self.cur_class.is_some()
                            && self.lookup(&fname).is_none()
                            && !self.module_declares(&fname)
                            && (self.info.resolved_member(e).is_some()
                                || self.cur_class.as_ref().is_some_and(|cur| {
                                    self.resolve_method_name(*cur, &fname).is_some()
                                        || self
                                            .resolve_method_by_arity(*cur, &fname, args.len())
                                            .is_some()
                                }))
                        {
                            self.lookup("this").and_then(|(this_v, this_ty)| {
                                self.lower_this_member_call(this_v, this_ty, &fname, &args, e)
                            })
                        } else {
                            None
                        }
                    } {
                        r
                    } else if let Some(r) = {
                        // `this` was flow-narrowed to a subtype `B` by an enclosing `if (this is B)`, and
                        // the checker resolved the bare call to a member of `B` (`fun A.test() = if (this
                        // is B) foo()`). Load the implicit receiver (the extension receiver or enclosing
                        // `this`), `checkcast` it to `B`, and dispatch the member on `B` — the call analog
                        // of the narrowed bare-name property read.
                        if let Some(bi) = self.info.narrowed_this_member.get(&e).copied() {
                            self.lookup("this").and_then(|(this_v, _)| {
                                let recv = self.emit_get_value(this_v);
                                let cast = self.emit_type_op(
                                    IrTypeOp::Cast,
                                    recv,
                                    ty_to_ir(Ty::obj_name(bi)),
                                );
                                let (class, index, mfid, _) =
                                    self.resolve_method_name(bi, &fname)?;
                                let params = self.ir.functions[mfid as usize].params.clone();
                                let vararg = self.syms.method_is_vararg_name(bi, &fname);
                                let n_fixed = vararg_arity(vararg, params.len(), args.len())?;
                                let a =
                                    self.lower_call_args_vararg(&args, &params, vararg, n_fixed)?;
                                Some(self.emit_method_call(
                                    class,
                                    index,
                                    cast,
                                    a.into_iter().map(Some).collect(),
                                ))
                            })
                        } else {
                            None
                        }
                    } {
                        r
                    } else if let Some(c) = {
                        // A receiver-less top-level library function (`listOf(…)`) → `invokestatic
                        // facade.name(args)`. Resolved (vararg-aware) through the library set, so no
                        // stdlib facade or descriptor is hardcoded.
                        // A MEMBER of the enclosing class shadows a same-named top-level function for an
                        // unqualified call (`foo()` inside `C` is `this.foo()`, not a top-level `foo`) — the
                        // checker resolves it that way, so the lowerer must NOT pick a top-level callable
                        // here, or the two diverge (a sibling call mis-lowered to a static one).
                        crate::trace_compiler!(
                            "resolve",
                            "lower toplevel-callable probe {fname}() cur_class={:?} has_member={}",
                            self.cur_class,
                            self.cur_class.as_ref().is_some_and(|cur| self
                                .resolve_method_name(*cur, &fname)
                                .is_some())
                        );
                        if self
                            .cur_class
                            .as_ref()
                            .is_some_and(|cur| self.resolve_method_name(*cur, &fname).is_some())
                        {
                            None
                        } else {
                            // The callable the checker resolved for this call (keyed by the call ExprId).
                            // The checker is the sole resolver; the lowerer only reads.
                            self.info.resolved_top_level(e).cloned()
                        }
                    } {
                        // For a spliced top-level `inline fun` (`run { 2 + 3 }`), the body returns the
                        // ERASED `Object` (a generic `R`); coerce it to the logical type so a primitive
                        // result unboxes instead of landing boxed in a primitive slot.
                        let (call_inline, call_log, call_phys) =
                            (c.inline.can_inline(), c.ret, c.physical_ret);
                        if let Some(intrinsic) = self.lower_assert_fails_with_default(e, &c, &args)
                        {
                            return Some(intrinsic);
                        }
                        if let Some(intrinsic) = self.lower_assert(&c, &args) {
                            return Some(intrinsic);
                        }
                        if let Some(intrinsic) = self.lower_println(&c, &args) {
                            return Some(intrinsic);
                        }
                        // Is the callee a `suspend fun`? Read the flag the CHECKER recorded on the resolved
                        // callable (it flows uniformly from the AST for a module/sibling-file fn and from
                        // `@Metadata` for a classpath one). A suspend call is recorded by `ExprId` so the
                        // coroutine pass threads the continuation even when the callee lives in another
                        // compilation unit (absent from this file's `suspend_funs`).
                        let call_suspend = c.suspend;
                        // A sub-`Int` primitive type argument (`listOf<Short>(1, 2)`) erases its
                        // element to `Object`, so a wider literal would box as `Integer` and a later
                        // narrowing read (`map(::shortFoo)`) throws `ClassCastException`. kotlinc boxes
                        // the constant as the narrow type; krusty doesn't track that logical-vs-erased
                        // element type yet, so bail (skip) rather than miscompile.
                        let narrow_targ = self.afile.call_type_args.get(&e.0).map_or(false, |ts| {
                            ts.iter()
                                .any(|r| !r.nullable && matches!(r.name.as_str(), "Short" | "Byte"))
                        });
                        if narrow_targ
                            && args
                                .iter()
                                .any(|&a| matches!(self.info.ty(a), Ty::Int | Ty::Long | Ty::Char))
                        {
                            return None;
                        }
                        // Classpath callables preserve Kotlin `Byte`/`Short` parameter shapes. krusty
                        // does not yet adapt a widened `Int` argument/array to such params, so bail
                        // rather than emit a call whose JVM argument shape cannot match the callee.
                        if has_byte_or_short_param(&c.params) {
                            return None;
                        }
                        let last_is_array =
                            c.params.last().map_or(false, |p| p.array_elem().is_some());
                        let vararg = !c.params.is_empty()
                            && last_is_array
                            && (c.params.len() != args.len()
                                || self.info.ty(args[args.len() - 1]) != *c.params.last().unwrap());
                        let mut a = Vec::new();
                        let mut arg_prelude = Vec::new();
                        // Context parameters (`context(a: A) fun f()`): the checker resolved each leading
                        // context parameter to an in-scope source (`"this"` = the enclosing implicit
                        // receiver, or a named local). Load and PREPEND them so the emitted argument list
                        // matches the callee's leading context parameters. Combining context parameters
                        // with a vararg / `$default` call is not modelled — skip (sound).
                        let ctx_sources = self.info.context_args.get(&e).cloned();
                        let ctx_n = ctx_sources.as_ref().map_or(0, |v| v.len());
                        if ctx_n > 0 {
                            if vararg || c.default_call {
                                return None;
                            }
                            for src in ctx_sources.as_ref().unwrap() {
                                let (v, _) = self.lookup(src)?;
                                a.push(self.emit_get_value(v));
                            }
                        }
                        if vararg {
                            let fixed = c.params.len() - 1;
                            if args.len() < fixed {
                                return None;
                            }
                            for i in 0..fixed {
                                a.push(self.lower_arg(args[i], &ty_to_ir(c.params[i]))?);
                            }
                            let elem_ir = ty_to_ir(c.params[fixed].array_elem()?);
                            let bound = c.vararg_elem;
                            let mut elements = Vec::new();
                            for &arg in &args[fixed..] {
                                if is_branchy(self.afile, arg) {
                                    return None;
                                }
                                // Literal adaptation: an integer literal whose bound element type is `Long`
                                // (`listOf<Long>(3)`) is the `Long` constant `3L`, boxed as `Long` — kotlinc
                                // adapts the literal at compile time (no runtime `i2l`, and a non-literal
                                // `Int` is a kotlinc error here, so only constant literals adapt).
                                if bound == Some(Ty::Long) {
                                    if let Expr::IntLit(v) = *self.afile.expr(arg) {
                                        let lc = self.emit_const(IrConst::Long(v));
                                        elements.push(self.emit_type_op(
                                            IrTypeOp::ImplicitCoercion,
                                            lc,
                                            elem_ir.clone(),
                                        ));
                                        continue;
                                    }
                                }
                                elements.push(self.lower_arg(arg, &elem_ir)?);
                            }
                            a.push(self.emit_vararg(ty_to_ir(c.params[fixed]), elements));
                        } else if c.default_call {
                            // A `name$default` call (`assertEquals(a, b)` omits the `message` default):
                            // lower the provided prefix, then append a placeholder per omitted trailing
                            // parameter, an `int` bit-mask (a bit per omitted param), and a `null` marker.
                            // A generic function whose provided parameters share one type variable
                            // (`assertEquals(expected: T, actual: T)`) boxes each argument as its OWN
                            // primitive; mismatched primitives (`assertEquals(0, longVal)`) would compare
                            // `areEqual(Integer, Long)` = false (kotlinc unifies `T` and coerces the
                            // literal, which krusty doesn't model) — skip rather than miscompile.
                            let prim_args: Vec<Ty> = self
                                .arg_tys(&args)
                                .into_iter()
                                .filter(|t| self.has_scalar_value_repr(*t))
                                .collect();
                            let generic_provided =
                                c.params.iter().take(args.len()).all(|p| p.is_erased_top());
                            if generic_provided && prim_args.windows(2).any(|w| w[0] != w[1]) {
                                return None;
                            }
                            let trailing_lambda = args
                                .last()
                                .is_some_and(|&x| matches!(self.info.ty(x), Ty::Fun(_)));
                            self.append_default_call_args(
                                &mut a,
                                &c.params,
                                &args,
                                trailing_lambda,
                            )?;
                        } else {
                            // `ctx_n` leading context arguments are already in `a`; the explicit source
                            // arguments fill the remaining parameters `c.params[ctx_n..]`.
                            if c.params.len() != ctx_n + args.len() {
                                return None;
                            }
                            if ctx_n == 0 && self.info.resolved_call_arg_slots.contains_key(&e) {
                                let (slot_args, prelude) =
                                    self.lower_args_from_resolved_slots(e, &args, &c.params)?;
                                a.extend(slot_args);
                                arg_prelude = prelude;
                            } else {
                                for (i, &arg) in args.iter().enumerate() {
                                    a.push(self.lower_arg(arg, &ty_to_ir(c.params[ctx_n + i]))?);
                                }
                            }
                        }
                        let call = self.emit_library_static_call(c, a, call_suspend);
                        let call = if arg_prelude.is_empty() {
                            call
                        } else {
                            self.wrap_arg_prelude(call, arg_prelude)
                        };
                        // A spliced inline fn leaves its erased return on the stack. Refine it the same
                        // way as a type-parameter-returning source function: checkcast a stricter
                        // reference, but do not eagerly unbox nullable generic returns (`T?`), because
                        // null must stay a legal value until a primitive/non-null use site demands it.
                        if call_inline {
                            self.coerce_erased_call_result(e, call, &call_phys, true)
                        } else if call_phys.is_erased_top() && call_log != call_phys {
                            // A NON-inline classpath top-level fn with an ERASED generic return
                            // (`runBlocking<T> { … }`, whose `$default` returns `Object`): the checker
                            // substituted the concrete result type (`T = Ch`/`Int`), so `checkcast`/unbox
                            // the `Object` result to it — else it lands boxed in a stricter slot
                            // (`VerifyError`). A concrete (non-erased) return keeps the raw call, unchanged.
                            self.coerce_erased_call_result(e, call, &call_phys, true)
                        } else {
                            call
                        }
                    } else if let Some((cur, (class, index, mfid, _))) = self
                        .cur_class
                        .and_then(|cur| self.resolve_method_name(cur, &fname).map(|m| (cur, m)))
                    {
                        // Unqualified instance method call inside a class body: `foo()` → `this.foo()`.
                        crate::trace_compiler!(
                            "resolve",
                            "lower unqualified sibling {fname}() in {cur}: class={class} index={index} ret={:?}",
                            self.ir.functions[mfid as usize].ret
                        );
                        let params = self.ir.functions[mfid as usize].params.clone();
                        let vararg = self.syms.method_is_vararg_name(cur, &fname);
                        let n_fixed = vararg_arity(vararg, params.len(), args.len())?;
                        let this = self.emit_get_value(0);
                        let a = self.lower_call_args_vararg(&args, &params, vararg, n_fixed)?;
                        self.emit_method_call(class, index, this, a.into_iter().map(Some).collect())
                    } else if let Some((class, index, mfid, cur_id)) =
                        self.inner_outer_method(&fname)
                    {
                        // Unqualified call to an enclosing method from an inner class: `this.this$0.foo()`.
                        let params = self.ir.functions[mfid as usize].params.clone();
                        if args.len() != params.len() {
                            return None;
                        }
                        // A PRIVATE enclosing method can't be invoked (`invokespecial`) from the inner
                        // class — route through the owner's synthetic `access$foo` accessor (a public
                        // `invokevirtual`), exactly as a callable reference to it does.
                        let (class, index) = if self.ir.private_methods.contains(&mfid) {
                            let owner = self.ir.classes[class as usize].fq_name();
                            // Bail (skip) if the accessor can't be made — never fall back to the private
                            // method, which would emit an illegal `invokespecial` from the inner class.
                            let acc = self.ensure_private_accessor(&owner, &fname)?;
                            let (c, i, _, _) = self.resolve_method(&owner, &acc)?;
                            (c, i)
                        } else {
                            (class, index)
                        };
                        let this = self.emit_get_value(0);
                        let this0 = self.emit_get_field(this, cur_id, 0);
                        let a = self.lower_args(&args, &params)?;
                        self.emit_method_call(
                            class,
                            index,
                            this0,
                            a.into_iter().map(Some).collect(),
                        )
                    } else if let Some(internal) = self
                        .info
                        .ty(e)
                        .obj_internal()
                        .filter(|&i| !self.contains_class_name(i))
                        .map(|i| i.render())
                    {
                        // Constructing a classpath (non-IR) class — `RuntimeException("x")`,
                        // `StringBuilder()`. The constructor descriptor comes from the classpath. NAMED
                        // arguments are reordered onto parameter positions via the ctor's `@Metadata`
                        // parameter names before lowering (source-order emit would pair them wrong).
                        // A NAMED call (`Point(y = 2, x = 1)`, or `Cfg(a = 1, c = "x")` omitting a
                        // defaulted `b`) is lowered by `lower_external_new_named` — labels → positions, with
                        // the `<init>$default` synthetic (placeholder + bitmask + marker) for an omitted
                        // default. It handles the all-supplied case too (reorder + positional). A named call
                        // it can't map returns `None` (skip) — do NOT fall through to the positional path,
                        // which would pair the SOURCE-order args against the wrong parameters (a miscompile).
                        return self.lower_external_new(&internal, e, &args);
                    } else {
                        // Constructor: the call's result type is the class.
                        let ci = self.class_of(self.info.ty(e))?;
                        let class = ci.id;
                        // An `inner class` construction (`Inner(args)` inside the enclosing class) needs
                        // the enclosing INSTANCE as the synthetic first constructor argument (`this$0`,
                        // which the class synthesis put at field 0). Supply the current `this` and lower
                        // the explicit args after it. Only reached inside the enclosing instance (the
                        // checker resolved it there), so `this` is in scope. The `this$0` field name is
                        // krusty's synthetic outer-instance marker (created only by inner-class synthesis;
                        // `$` cannot appear in a plain Kotlin identifier), so it exactly identifies an
                        // inner class.
                        let is_inner = self.ir.classes[class as usize]
                            .fields
                            .first()
                            .is_some_and(|f| f.name == "this$0");
                        if is_inner {
                            let (this_v, _) = self.lookup("this")?;
                            let outer = self.emit_get_value(this_v);
                            let field_tys: Vec<Ty> = self.ir.classes[class as usize]
                                .fields
                                .iter()
                                .map(|f| f.ty)
                                .collect();
                            let ctor_n = self.ir.classes[class as usize].ctor_param_count as usize;
                            if ctor_n == args.len() + 1 {
                                let mut a = vec![outer];
                                for (i, &arg) in args.iter().enumerate() {
                                    a.push(self.lower_arg(arg, &field_tys[i + 1])?);
                                }
                                return Some(self.emit_new(class, a, None));
                            }
                            return None;
                        }
                        // Constructing an annotation (`A(args)`) builds its synthetic IMPL class — the
                        // annotation INTERFACE itself can't be `new`'d. Redirect to `<A>$annotationImpl`
                        // (same fields/ctor); the result still types as the annotation (the impl IS-A `A`).
                        let class = if self.ir.classes[class as usize].is_annotation {
                            let impl_name = format!(
                                "{}$annotationImpl",
                                self.ir.classes[class as usize].fq_name()
                            );
                            self.ir
                                .classes
                                .iter()
                                .position(|c| c.fq_name_matches(&impl_name))
                                .map(|p| p as u32)
                                .unwrap_or(class)
                        } else {
                            class
                        };
                        // The IR models only an exact positional match against the primary
                        // constructor's parameter fields. Default arguments and secondary
                        // constructors aren't lowered — bail (skip) rather than emit a call whose
                        // stack shape won't match the constructor descriptor (a VerifyError).
                        let ctor_count = self.ir.classes[class as usize].ctor_param_count as usize;
                        // Coerce each argument to its constructor-parameter type, filling named args +
                        // constant-literal defaults (`LongWrapper(2)`, `C(y = 1)`, `C()`). Use the FULL
                        // ctor-param list (`ctor_args`, property + plain params) when present, else the
                        // leading parameter fields (synthesized classes have empty `ctor_args`).
                        let ctor_args = self.ir.classes[class as usize].ctor_args.clone();
                        let field_tys: Vec<Ty> = if ctor_args.is_empty() {
                            self.ir.classes[class as usize].fields[..ctor_count]
                                .iter()
                                .map(|f| f.ty.clone())
                                .collect()
                        } else {
                            ctor_args.iter().map(|a| a.ty).collect()
                        };
                        // Generic constructor with a primitive type argument (`Box<Long>(-1)`): a
                        // type-parameter field gets its argument coerced to the type-argument primitive
                        // (`Int`→`Long`) before boxing — else an `Int` literal boxes as `Integer`, not
                        // `Long`. Only the simple all-property positional case.
                        // A NULLABLE type-param field (`val z: T?`) stays boxed (`Int?`) — only coerce a
                        // non-nullable one (`val value: T`); use an empty (non-matching) name for nullable.
                        let (tparams, prop_tys): (Vec<String>, Vec<String>) = self
                            .class_decl(&fname)
                            .map(|cd| {
                                (
                                    cd.type_params.clone(),
                                    cd.props
                                        .iter()
                                        .filter(|p| p.is_property)
                                        .map(|p| {
                                            if p.ty.nullable {
                                                String::new()
                                            } else {
                                                p.ty.name.clone()
                                            }
                                        })
                                        .collect(),
                                )
                            })
                            .unwrap_or_default();
                        let targs: Vec<Ty> = self
                            .afile
                            .call_type_args
                            .get(&e.0)
                            .map(|ts| {
                                ts.iter()
                                    .map(|r| ty_of(self.afile, r, &*self.syms.libraries))
                                    .collect()
                            })
                            .unwrap_or_default();
                        let no_named = self
                            .afile
                            .call_arg_names
                            .get(&e.0)
                            .map_or(true, |ns| ns.iter().all(|n| n.is_none()));
                        let arg_prims: Vec<Option<Ty>> = (0..args.len())
                            .map(|i| {
                                prop_tys
                                    .get(i)
                                    .and_then(|pn| tparams.iter().position(|tp| tp == pn))
                                    .and_then(|ti| targs.get(ti))
                                    .copied()
                                    .filter(|t| self.has_scalar_value_repr(*t))
                            })
                            .collect();
                        if !targs.is_empty()
                            && no_named
                            && args.len() == field_tys.len()
                            && prop_tys.len() == field_tys.len()
                            && arg_prims.iter().any(Option::is_some)
                        {
                            let mut a = Vec::new();
                            for (i, &arg) in args.iter().enumerate() {
                                if let Some(p) = arg_prims[i] {
                                    let v = self.lower_arg(arg, &ty_to_ir(p))?;
                                    a.push(self.emit_type_op(
                                        IrTypeOp::ImplicitCoercion,
                                        v,
                                        field_tys[i].clone(),
                                    ));
                                } else {
                                    a.push(self.lower_arg(arg, &field_tys[i])?);
                                }
                            }
                            return Some(self.emit_new(class, a, None));
                        }
                        let meta: Vec<(String, Option<AstExprId>)> = self
                            .class_decl(&fname)
                            .map(|cd| {
                                cd.props
                                    .iter()
                                    .map(|p| (p.name.clone(), p.default))
                                    .collect()
                            })
                            .unwrap_or_default();
                        // A secondary constructor whose parameter types MATCH the arguments is preferred
                        // over a lenient primary match (`Sc("x")` is the `String` secondary, not the
                        // `Int` primary coerced). Compare the argument IR types to each secondary's.
                        let arg_irs = tys_to_ir(&self.arg_tys(&args));
                        let secs = self.ir.classes[class as usize].secondary_ctors.clone();
                        // Whether the PRIMARY constructor can accept the args (each assignable to a field
                        // type). When it can't (`IC("abc")`: a `String` isn't assignable to `List<T>`),
                        // a secondary whose params accept the args is chosen instead of leniently coercing
                        // into the primary — otherwise the call would target `constructor-impl(List)` with
                        // a `String` and fail at runtime.
                        let primary_accepts = arg_irs.len() == field_tys.len()
                            && arg_irs
                                .iter()
                                .zip(&field_tys)
                                .all(|(a, p)| ir_arg_assignable(a, p));
                        // A named-argument call (`C(b = 9)`) references the PRIMARY ctor's parameter
                        // names — Kotlin never considers a secondary for it. Only positional calls pick
                        // a secondary by argument types (otherwise a same-arity secondary that merely
                        // coincides on types would hijack the named primary call → wrong fields).
                        let typed_secondary = no_named
                            .then(|| {
                                secs.iter()
                                    .find(|sc| sc.params == arg_irs)
                                    .or_else(|| {
                                        (!primary_accepts)
                                            .then(|| {
                                                secs.iter().find(|sc| {
                                                    sc.params.len() == arg_irs.len()
                                                        && arg_irs
                                                            .iter()
                                                            .zip(&sc.params)
                                                            .all(|(a, p)| ir_arg_assignable(a, p))
                                                })
                                            })
                                            .flatten()
                                    })
                                    .cloned()
                            })
                            .flatten();
                        // The primary constructor (exact/defaulted positional match), else a secondary
                        // constructor selected by argument count.
                        if let Some(sc) = typed_secondary {
                            let mut a = Vec::new();
                            for (arg, pt) in args.iter().zip(&sc.params) {
                                a.push(self.lower_arg(*arg, pt)?);
                            }
                            self.emit_new(class, a, Some(sc.params))
                        } else if let Some((a, prelude)) =
                            self.lower_args_defaulted(e, &meta, &args, &field_tys)
                        {
                            let new = self.emit_new(class, a, None);
                            self.wrap_arg_prelude(new, prelude)
                        } else if let Some(sc) = no_named
                            .then(|| {
                                self.ir.classes[class as usize]
                                    .secondary_ctors
                                    .clone()
                                    .into_iter()
                                    .find(|sc| sc.params.len() == args.len())
                            })
                            .flatten()
                        {
                            let mut a = Vec::new();
                            for (arg, pt) in args.iter().zip(&sc.params) {
                                a.push(self.lower_arg(*arg, pt)?);
                            }
                            self.emit_new(class, a, Some(sc.params))
                        } else {
                            return None;
                        }
                    }
                }
                // Instance method call `recv.m(args)`, or a stdlib intrinsic method.
                Expr::Member { receiver, name } => {
                    if let Some(ExprLowering::ObjectMemberCall { internal }) =
                        self.info.expr_lowers.get(&e)
                    {
                        return self.lower_object_member_call(*internal, &name, &args, e);
                    }
                    // `"""…""".trimIndent()` / `.trimMargin()` on a compile-time-constant string receiver:
                    // fold the stdlib transform to a string constant (kotlinc special-cases a constant
                    // receiver too). A non-constant receiver falls through and is skipped.
                    if args.is_empty() && matches!(name.as_str(), "trimIndent" | "trimMargin") {
                        if let Some(s) = const_string_value(self.afile, receiver) {
                            let folded = if name == "trimIndent" {
                                trim_indent(&s)
                            } else {
                                trim_margin(&s, "|")
                            };
                            return Some(self.ir_const_str(folded));
                        }
                    }
                    // A FULLY-QUALIFIED top-level FUNCTION call `a.b.helper(args)` (the checker typed it):
                    // the receiver is a package path, `helper` a top-level fn of that package — emit the
                    // static call to its facade. `None` falls through to normal member-call handling.
                    if let Some(v) = self.lower_fq_toplevel_call(receiver, &name, &args, e) {
                        return Some(v);
                    }
                    // Exact named user-member calls reorder arguments before positional lowering.
                    if self.afile.call_arg_names.contains_key(&e.0) {
                        if let Some(internal) = self.info.ty(receiver).obj_internal() {
                            if let Some((_, _, fid, _)) = self.resolve_method_name(internal, &name)
                            {
                                let params_len = self.ir.functions[fid as usize].params.len();
                                let no_defaults = self
                                    .ir
                                    .param_defaults(fid)
                                    .is_none_or(|d| d.iter().all(|x| x.is_none()));
                                // A no-default user member with named args: the ONLY correct lowering is a
                                // reorder — never the positional pairing below. Handle it (exact arity, no
                                // vararg) or bail (skip the file). `lower_arg` type-checks each argument, so
                                // an overload the class map didn't keep degrades to a skip, not a miscompile.
                                // A method WITH defaults keeps the existing default/positional path.
                                if no_defaults {
                                    let no_vararg =
                                        !self.syms.method_is_vararg_name(internal, &name);
                                    if args.len() == params_len && no_vararg {
                                        let internal = internal.render();
                                        return self.lower_named_member_call(
                                            e, receiver, &name, &args, &internal,
                                        );
                                    }
                                    return None;
                                }
                            }
                        }
                    }
                    // CLASSPATH nested-class construction `Outer.Nested(args)` (`Subject.User("x")`): the
                    // receiver names a type (not a value), and the call's result type is the nested
                    // classpath internal (`lib/Subject$User`, not an IR class). Emit `new … invokespecial`.
                    {
                        {
                            if let Some(internal) =
                                self.nested_ctor_internal(receiver, &name).filter(|i| {
                                    !self.contains_class(i)
                                        && self
                                            .info
                                            .ty(e)
                                            .obj_internal()
                                            .is_some_and(|n| n.matches(i.as_str()))
                                })
                            {
                                // NAMED args (`Op.Ext(a = 1, b = "x")`, or omitting a defaulted param) map
                                // labels onto positions via the nested class's `@Metadata`; positional
                                // (incl. an omitted default) goes through the plain path, which already
                                // emits the `<init>$default`/marker synthetic.
                                return self.lower_external_new(&internal, e, &args);
                            }
                        }
                    }
                    // `recv.startCoroutine(completion)` — a `kotlin.coroutines` intrinsic.
                    if let [completion_arg] = args.as_slice() {
                        if matches!(self.info.ty(receiver), Ty::Fun(s) if s.suspend)
                            && crate::libraries::coroutine_intrinsic(&name)
                                == Some(crate::libraries::CoroutineIntrinsic::StartCoroutine)
                        {
                            let recv_v = self.expr(receiver)?;
                            let cont_ir = ty_to_ir(Ty::obj("kotlin/coroutines/Continuation"));
                            let comp_v = self.lower_arg(*completion_arg, &cont_ir)?;
                            return self.runtime_call(
                                RuntimeOp::StartCoroutine,
                                Ty::Unit,
                                vec![recv_v, comp_v],
                            );
                        }
                    }
                    // `super.method(args)` → a non-virtual `invokespecial` on `this` (value 0). The
                    // checker records the concrete superclass/interface target; lowering only emits it.
                    let super_qual: Option<Option<String>> = match self.afile.expr(receiver) {
                        Expr::Name(rn) if rn.starts_with("super") => Some(
                            rn.strip_prefix("super<")
                                .and_then(|s| s.split('>').next())
                                .map(|s| s.to_string()),
                        ),
                        _ => None,
                    };
                    if super_qual.is_some() {
                        // A LABELED super (`super@A.f()`, `super<K>@A.f()`) selects an ENCLOSING class's
                        // supertype (inner classes) — the enclosing-scope dispatch isn't modeled, so skip.
                        if matches!(self.afile.expr(receiver), Expr::Name(rn) if rn.contains('@')) {
                            return None;
                        }
                        let cur = self.cur_class?;
                        let cur_id = self.class_info_name(cur)?.id as usize;
                        // A `super.f()` inside a `@JvmInline value class` calls through the unboxed
                        // receiver, which invokespecial can't target — not modeled (value classes are
                        // handled by the dedicated pass); skip rather than emit a verify error.
                        if self.ir.classes.get(cur_id).is_some_and(|c| c.is_value) {
                            return None;
                        }
                        let this = self.emit_get_value(0);
                        let target = self.info.resolved_super_call(e).cloned()?;
                        let descriptor =
                            target.descriptor.clone().map(Some).unwrap_or_else(|| {
                                self.runtime.method_descriptor(&target.params, target.ret)
                            })?;
                        if target.params.len() != args.len() {
                            return None;
                        }
                        let mut a = Vec::new();
                        for (arg, pt) in args.iter().zip(&target.params) {
                            a.push(self.lower_arg(*arg, &ty_to_ir(*pt))?);
                        }
                        return Some(self.emit_call(
                            Callee::Special {
                                owner: target.owner,
                                name: name.clone(),
                                descriptor,
                                interface: target.interface,
                            },
                            Some(this),
                            a,
                        ));
                    }
                    // Reified kotlinx.serialization round-trip: `fmt.encodeToString(x)` /
                    // `fmt.decodeFromString<C>(s)` are `reified inline` (uncallable directly) — desugar to
                    // the 2-arg member with a synthesized `C.serializer()`.
                    if let Some(call) = self.try_reified_serial(receiver, &name, &args, e) {
                        return Some(call);
                    }
                    if let ([arg], true) = (
                        &args[..],
                        self.has_scalar_value_repr(self.info.ty(receiver))
                            && !(self.afile.infix_calls.contains(&e.0)
                                && self.ext_fun_ids.contains_key(&(
                                    self.info.ty(receiver).erased_recv(),
                                    name.clone(),
                                ))),
                    ) {
                        if let Some(r) =
                            self.lower_prim_op_method(receiver, &name, *arg, self.info.ty(e))
                        {
                            return Some(r);
                        }
                    }
                    // Array `isEmpty()`/`isNotEmpty()`/`count()` (stdlib extensions) → the `arraylength`
                    // intrinsic: `size == 0` / `size != 0` / `size`.
                    if self.info.ty(receiver).array_elem().is_some() && args.is_empty() {
                        let cmp = match name.as_str() {
                            "isEmpty" => Some(Some(IrBinOp::Eq)),
                            "isNotEmpty" => Some(Some(IrBinOp::Ne)),
                            "count" => Some(None),
                            _ => None,
                        };
                        if let Some(op) = cmp {
                            let a = self.expr(receiver)?;
                            let size =
                                self.emit_external_call("kotlin/Array.size", Some(a), vec![]);
                            return Some(match op {
                                Some(c) => {
                                    let z = self.emit_const(IrConst::Int(0));
                                    self.emit_primitive_bin_op(c, size, z)
                                }
                                None => size,
                            });
                        }
                    }
                    // Inner-class construction `outerInstance.Inner(args)` → `new Outer$Inner(outer,
                    // args)`: the checker typed the call as the inner class (whose first field is the
                    // synthetic `this$0`), so pass the receiver as the leading constructor argument.
                    if let Some(class_id) = self
                        .info
                        .ty(e)
                        .obj_internal()
                        .and_then(|i| self.class_info_name(i))
                        .map(|ci| ci.id)
                        .filter(|&id| {
                            let c = &self.ir.classes[id as usize];
                            // The inner's `this$0` field type must match the receiver's type (the outer
                            // instance) — guards against a same-named method returning an inner-typed value.
                            let this0_outer = match c.fields.first() {
                                Some(IrField { name: n0, ty, .. }) if n0 == "this$0" => {
                                    ty.non_null().obj_internal()
                                }
                                _ => None,
                            };
                            c.fq_name().ends_with(&format!("${name}"))
                                && this0_outer == self.info.ty(receiver).obj_internal()
                        })
                    {
                        let field_tys: Vec<Ty> = self.ir.classes[class_id as usize]
                            .ctor_args
                            .iter()
                            .map(|a| a.ty)
                            .collect();
                        if field_tys.len() == args.len() + 1 {
                            let recv = self.expr(receiver)?;
                            let mut a = vec![recv];
                            for (arg, pt) in args.iter().zip(&field_tys[1..]) {
                                a.push(self.lower_arg(*arg, pt)?);
                            }
                            return Some(self.emit_new(class_id, a, None));
                        }
                    }
                    // `iterable.forEach { x -> body }` is the stdlib `inline fun` whose body is
                    // `for (x in this) body` — inline it to a for-each loop (no closure), so a mutable
                    // capture in the lambda works, exactly as kotlinc's inlining does. Gated on the
                    // receiver being iterable (so a user `forEach` on a non-iterable falls through).
                    let one_lambda_arg = self.single_lambda_arg(&args);
                    if let ("forEach", Some((_, params, lbody))) =
                        (name.as_str(), one_lambda_arg.as_ref())
                    {
                        let rty = self.info.ty(receiver);
                        // An array, a `String`, or an `Obj` iterable (List/Set/Iterable) — all handled
                        // by `lower_for_each` (and the checker element-types the lambda parameter).
                        let iterable = rty.array_elem().is_some()
                            || rty == Ty::String
                            || rty.obj_internal().map_or(false, |i| {
                                self.runtime.counted_loop_info_name(i).is_some()
                                    || self.info.iterator_protocol(receiver).is_some()
                            });
                        if iterable {
                            let param = ast::first_lambda_param_or_it(params);
                            return self.lower_for_each(&param, receiver, *lbody, None, true);
                        }
                    }
                    // `iterable.map/flatMap { … }` WHERE THE LAMBDA BODY SUSPENDS: a stdlib collection HOF
                    // lowers its lambda to a `FunctionN` impl that can't suspend, so inline it into an
                    // accumulating loop (kotlinc's own inline expansion) — putting the suspension in an
                    // ordinary for-loop the coroutine pass models. Only in a suspend fn and only when the
                    // lambda actually suspends, so a non-suspend `map`/`flatMap` keeps its library call.
                    // ABI guard: fire ONLY for the stdlib `Iterable.map`/`flatMap`, which return `List<R>`
                    // — so materializing the loop into an `ArrayList` (a `List`) is signature-correct.
                    // A lazy `Sequence.map` (returns `Sequence`) or a user overload returning another
                    // container (`Set`, …) has a non-`List` result type and a NON-`kotlin/collections`
                    // facade; gating on the `List` result type + a resolved stdlib-collections extension
                    // excludes them, so we never hand back an `ArrayList` where the static type is
                    // `Sequence`/`Set` (→ VerifyError / ClassCastException).
                    let stdlib_list_hof = (name == "map" || name == "flatMap")
                        && self.info.ty(e).obj_internal().is_some_and(|i| {
                            i == "kotlin/collections/List" || i == "kotlin/collections/MutableList"
                        })
                        && self
                            .info
                            .resolved_extension(e)
                            .is_some_and(|c| c.owner.starts_with("kotlin/collections/"));
                    if self.cur_fn_suspend && stdlib_list_hof && args.len() == 1 {
                        if let Expr::Lambda {
                            params,
                            body: lbody,
                        } = self.afile.expr(args[0]).clone()
                        {
                            let rty = self.info.ty(receiver);
                            let iterable = rty.obj_internal().is_some()
                                && self.info.iterator_protocol(receiver).is_some();
                            if iterable && self.ast_subtree_suspends(lbody) {
                                let param = ast::first_lambda_param_or_it(&params);
                                if let Some(v) = self.lower_suspend_accumulate_hof(
                                    name == "flatMap",
                                    &param,
                                    receiver,
                                    lbody,
                                ) {
                                    return Some(v);
                                }
                            }
                        }
                    }
                    // `mutex.withLock { body }` (a `suspend inline fun`) — kotlinc ALWAYS splices an
                    // inline fn (a non-suspending body still surrounds suspending lock()/unlock()),
                    // so route every shape through the dedicated lowering, never `withLock$default`.
                    if self.cur_fn_suspend
                        && name == "withLock"
                        && args.len() == 1
                        && self
                            .info
                            .resolved_extension(e)
                            .is_some_and(|c| c.owner.starts_with("kotlinx/coroutines/sync/"))
                    {
                        if let Expr::Lambda { body: lbody, .. } = self.afile.expr(args[0]).clone() {
                            // Inside a SUSPEND LAMBDA a non-suspending-body withLock keeps the
                            // `withLock\$default` call — the lambda machine doesn't model the
                            // splice's try/finally; a suspending body has no fallback anyway.
                            // A NON-LOCAL `return` in the body also keeps the call — the flattener
                            // doesn't model a `return` inside the splice's `try`/`finally`, and the
                            // `$default` path runs the same lock/unlock semantics — UNLESS the call
                            // is the function's tail expression: there `return v` ≡ `return@withLock v`
                            // and lowers through the splice's return frame.
                            if (self.ast_body_suspends(lbody) || !self.in_suspend_lambda_body)
                                && (!self.ast_body_has_nonlocal_return(lbody)
                                    || self.fn_body_tail == Some(e))
                            {
                                if let Some(v) = self.lower_suspend_withlock(e, receiver, lbody) {
                                    return Some(v);
                                }
                            }
                        }
                    }
                    // `iterable.forEachIndexed { i, x -> body }` — the inline `forEachIndexed`, whose
                    // body is `var i = 0; for (x in this) { action(i, x); i++ }`. Inline it via the
                    // iterator path with an index counter (Obj iterables only, same as `forEach`).
                    if let ("forEachIndexed", Some((_, params, lbody))) =
                        (name.as_str(), one_lambda_arg.as_ref())
                    {
                        let rty = self.info.ty(receiver);
                        let iterable = rty.obj_internal().is_some()
                            && self.info.iterator_protocol(receiver).is_some();
                        if iterable && params.len() == 2 {
                            let idx = params[0].clone();
                            let elem = params[1].clone();
                            return self.lower_foreach_iterator(
                                &elem,
                                receiver,
                                *lbody,
                                rty,
                                ForeachOpts {
                                    index: Some(&idx),
                                    label: None,
                                    hof_splice: true,
                                },
                            );
                        }
                    }
                    // Metadata-driven inline route: any library `inline fun` taking a single lambda whose
                    // body the platform can splice (`let`/`also`/…) is inlined from its REAL stdlib
                    // bytecode — no per-function desugar, no hardcoded name list. The route self-gates on
                    // the resolved callee's inline kind; backend splice failures are compiler errors, not
                    // semantic overload choices.
                    // (`map`/`filter`, branchy) and user methods simply fall through.
                    // `run`/`apply` are receiver lambdas (the lambda's `this` is the receiver); the
                    // bytecode splice routes them as ordinary value-lambdas, mishandling that receiver, so
                    // they go to the receiver-aware fallback below instead.
                    if !matches!(name.as_str(), "run" | "apply") {
                        if let Some((arg, ..)) = one_lambda_arg.as_ref() {
                            if let Some(call) = self.try_route_lambda_inline(e, receiver, *arg) {
                                return Some(call);
                            }
                        }
                    }
                    // FALLBACK for the cases the route can't splice — a lambda capturing `this`/fields (no
                    // closure form, so no `IrExpr::Lambda` to inline); it inlines the body directly.
                    // (Removing it costs ~13 box tests until this-capturing lambdas are modelled; the
                    // common closure-form cases already inline from real bytecode via the route above.)
                    // `let`/`also` bind the receiver to the lambda's value parameter (`it`); `run`/`apply`
                    // are receiver lambdas — the receiver is `this`, so member access in the body resolves
                    // against its class (bind `this` and set `cur_class` to the receiver's user class; a
                    // library receiver, whose members krusty can't reach through a bare `this`, falls
                    // through). `let`/`run` yield the body value; `also`/`apply` yield the receiver.
                    let is_recv_lambda = matches!(name.as_str(), "run" | "apply");
                    let scope_fn = matches!(name.as_str(), "let" | "also") || is_recv_lambda;
                    if let (true, Some((_, params, lbody))) = (scope_fn, one_lambda_arg.as_ref()) {
                        let rty = self.info.ty(receiver);
                        // A receiver lambda binds the receiver as `this`; member access in the body
                        // resolves against its type through the implicit-`this` paths (own class
                        // field/getter, or a builtin/library accessor for `String`/collections/…).
                        let recv = self.expr(receiver)?;
                        let depth = self.scope.len();
                        let p_slot = self.fresh_value();
                        let pname = if is_recv_lambda {
                            "this".to_string()
                        } else {
                            ast::first_lambda_param_or_it(params)
                        };
                        // An inlined receiver lambda runs in the *caller's* method, so the receiver's
                        // members are accessed externally (getter/setter), never as the enclosing
                        // class's own private fields — clear `cur_class` for the body.
                        let saved_cur = self.cur_class;
                        if is_recv_lambda {
                            self.cur_class = None;
                        }
                        self.scope.push((pname, p_slot, rty));
                        let var_p = self.emit_variable(p_slot, ty_to_ir(rty), Some(recv));
                        let body_val = self.expr(*lbody);
                        self.scope.truncate(depth);
                        self.cur_class = saved_cur;
                        let body_val = body_val?;
                        let returns_receiver = matches!(name.as_str(), "also" | "apply");
                        let result = if !returns_receiver {
                            self.emit_block(vec![var_p], Some(body_val))
                        } else {
                            let recv_read = self.emit_get_value(p_slot);
                            self.emit_block(vec![var_p, body_val], Some(recv_read))
                        };
                        return Some(result);
                    }
                    // Nested-class construction `Outer.Inner(args)` — the receiver is a class name and
                    // the call's result type is the nested class. Emit `new Outer$Inner(args)`.
                    if let Expr::Name(root) = self.afile.expr(receiver).clone() {
                        if self.lookup(&root).is_none() {
                            let qname = format!("{root}.{name}");
                            if let Some(ci) = self.class_info(&class_internal(self.afile, &qname)) {
                                let class = ci.id;
                                let ctor_count =
                                    self.ir.classes[class as usize].ctor_param_count as usize;
                                let field_tys: Vec<Ty> = self.ir.classes[class as usize].fields
                                    [..ctor_count]
                                    .iter()
                                    .map(|f| f.ty.clone())
                                    .collect();
                                let meta: Vec<(String, Option<AstExprId>)> = self
                                    .class_decl(&qname)
                                    .map(|cd| {
                                        cd.props
                                            .iter()
                                            .map(|p| (p.name.clone(), p.default))
                                            .collect()
                                    })
                                    .unwrap_or_default();
                                if let Some((a, prelude)) =
                                    self.lower_args_defaulted(e, &meta, &args, &field_tys)
                                {
                                    let new = self.emit_new(class, a, None);
                                    return Some(self.wrap_arg_prelude(new, prelude));
                                }
                                return None;
                            }
                        }
                    }
                    // `C.serializer()` on a `@Serializable` class — the serialization plugin synthesizes
                    // `serializer(): KSerializer<C>` as an INSTANCE method on `C`'s `Companion`, but only
                    // at the BACKEND phase (after this lowering). Emit the call BY SIGNATURE now, routed
                    // through the companion (`getstatic C.Companion; invokevirtual C$Companion.serializer
                    // (…)`); the plugin supplies the Companion class + accessor body before emit. Scoped
                    // to the plugin's synthetic so it can't shadow a user companion method.
                    if name == "serializer" {
                        if let Expr::Name(cls) = self.afile.expr(receiver).clone() {
                            let cd = self.class_decl(&cls);
                            let is_serializable = cd.is_some_and(|cd| {
                                // Same simple-name detection as the checker + the plugin.
                                cd.annotations
                                    .iter()
                                    .any(|a| a.rsplit(['/', '.']).next() == Some("Serializable"))
                            });
                            // A PLAIN non-generic `@Serializable` class routes `serializer()` through its
                            // `Companion` (where the plugin relocates the accessor); an enum / sealed /
                            // generic class keeps the static form (the plugin leaves those static).
                            let companion_routed =
                                cd.is_some_and(|cd| self.serializable_uses_companion_accessor(cd));
                            if is_serializable && self.lookup(&cls).is_none() {
                                if let Some(internal) = self
                                    .class_info(&class_internal(self.afile, &cls))
                                    .map(|ci| self.ir.classes[ci.id as usize].fq_name())
                                {
                                    let ret = ty_to_ir(Ty::obj_args(
                                        "kotlinx/serialization/KSerializer",
                                        &[Ty::obj(&internal)],
                                    ));
                                    let kser =
                                        ty_to_ir(Ty::obj("kotlinx/serialization/KSerializer"));
                                    let mut a = Vec::new();
                                    for arg in &args {
                                        a.push(self.lower_arg(*arg, &kser)?);
                                    }
                                    if companion_routed {
                                        let comp = format!("{internal}$Companion");
                                        let recv = self.ir.external_static_instance(
                                            &internal,
                                            &comp,
                                            "Companion",
                                        );
                                        return Some(self.ir.add_expr(IrExpr::Call {
                                            callee: Callee::CrossFileVirtual {
                                                owner: type_name(&comp),
                                                name: "serializer".to_string(),
                                                params: vec![kser; args.len()],
                                                ret,
                                                interface: false,
                                            },
                                            dispatch_receiver: Some(recv),
                                            args: a,
                                        }));
                                    }
                                    return Some(self.emit_cross_file_call(
                                        type_name(&internal),
                                        "serializer".to_string(),
                                        vec![kser; args.len()],
                                        ret,
                                        a,
                                    ));
                                }
                            }
                        }
                    }
                    // A user `inline fun <recv>.name(args)` — expand it here (kotlinc's inliner) with the
                    // receiver bound as `this`, instead of a real static call.
                    {
                        let recv_key = self.recv_ty(receiver).erased_recv();
                        let is_inline_ext = self.afile.decls.iter().any(|&d| {
                            matches!(self.afile.decl(d), Decl::Fun(f)
                                if f.name == name && f.is_inline
                                && f.receiver.as_ref().is_some_and(|r|
                                    f.type_params.iter().any(|tp| tp == &r.name)
                                    || ty_of(self.afile, r, &*self.syms.libraries).erased_recv() == recv_key))
                        });
                        if is_inline_ext {
                            if let Some(r) =
                                self.lower_inline_fn_call(&name, &args, e.0, Some(receiver), None)
                            {
                                return Some(r);
                            }
                        }
                    }
                    // A top-level extension function `recv.name(args)` → a static call whose first
                    // argument is the receiver (matching how the extension was registered/emitted).
                    {
                        if let Some((fid, decl_recv)) =
                            self.ext_fun_id_for_recv(self.recv_ty(receiver), &name, args.len())
                        {
                            let params = self.ir.functions[fid as usize].params.clone();
                            if params.len() == args.len() + 1 {
                                // A NAMED extension call may reorder the arguments: map labels onto
                                // positions and evaluate receiver + args in source order (never the
                                // positional pairing below, which would bind labels in the wrong order).
                                if self.afile.call_arg_names.contains_key(&e.0) {
                                    return self.lower_named_ext_call(e, receiver, fid, &args);
                                }
                                let recv =
                                    self.lower_ext_receiver(receiver, &decl_recv, &params[0])?;
                                let mut a = vec![recv];
                                for (arg, pt) in args.iter().zip(&params[1..]) {
                                    a.push(self.lower_arg(*arg, pt)?);
                                }
                                return Some(self.emit_local_call(fid, a));
                            }
                            // Omitted extension arguments are filled from constant defaults.
                            if let Some(param_info) = self.ir.fn_params.get(&fid).cloned() {
                                let defaults = param_info.defaults;
                                let names = param_info.names;
                                let n = params.len();
                                let arg_names = self.afile.call_arg_names.get(&e.0).cloned();
                                let recv =
                                    self.lower_ext_receiver(receiver, &decl_recv, &params[0])?;
                                let mut slot: Vec<Option<u32>> = vec![None; n];
                                slot[0] = Some(recv);
                                let mut pos = 1usize;
                                let mut ok = names.len() == n;
                                for (ai, arg) in args.iter().enumerate() {
                                    let nm = arg_names
                                        .as_ref()
                                        .and_then(|v| v.get(ai).cloned().flatten());
                                    let p = match nm {
                                        Some(s) => names.iter().position(|f| *f == s),
                                        None => {
                                            let p = pos;
                                            pos += 1;
                                            Some(p)
                                        }
                                    };
                                    match p {
                                        Some(p) if p < n && slot[p].is_none() => {
                                            slot[p] = Some(self.lower_arg(*arg, &params[p])?);
                                        }
                                        _ => {
                                            ok = false;
                                            break;
                                        }
                                    }
                                }
                                if ok {
                                    let mut a = Vec::with_capacity(n);
                                    for (k, s) in slot.iter().enumerate() {
                                        let v = match s {
                                            Some(v) => *v,
                                            // A constant default — clone it as a fresh node (avoid aliasing).
                                            None => match defaults
                                                .as_ref()
                                                .and_then(|defaults| {
                                                    defaults.get(k).and_then(|d| *d)
                                                })
                                                .map(|d| self.ir.exprs[d as usize].clone())
                                            {
                                                Some(IrExpr::Const(c)) => self.emit_const(c),
                                                _ => {
                                                    ok = false;
                                                    break;
                                                }
                                            },
                                        };
                                        a.push(v);
                                        let _ = k;
                                    }
                                    if ok && a.len() == n {
                                        return Some(self.emit_local_call(fid, a));
                                    }
                                }
                            }
                        }
                    }
                    // Unsigned conversions. `UInt`/`Int` and `ULong`/`Long` share a JVM representation,
                    // so a conversion that doesn't change the representation is a no-op reinterpret;
                    // `UInt.toLong()`/`toULong()` zero-extend via the platform helper; `ULong.toInt()`
                    // truncates (`l2i`); `inc`/`dec` are ±1.
                    {
                        let rty = self.info.ty(receiver);
                        if args.is_empty()
                            && (rty.is_unsigned() || matches!(name.as_str(), "toUInt" | "toULong"))
                        {
                            if rty.is_unsigned() && name == "toString" {
                                let r = self.expr(receiver)?;
                                return self.unsigned_to_string(r, rty);
                            }
                            if rty.is_unsigned() && matches!(name.as_str(), "inc" | "dec") {
                                let one = self.scalar_one_const(rty)?;
                                let r = self.expr(receiver)?;
                                let o = self.emit_const(one);
                                let op = if name == "dec" {
                                    IrBinOp::Sub
                                } else {
                                    IrBinOp::Add
                                };
                                return Some(self.emit_primitive_bin_op(op, r, o));
                            }
                            if is_conversion_call_name(&name) {
                                let target = self.info.ty(e);
                                if target == Ty::Error {
                                    return None;
                                }
                                let r = self.expr(receiver)?;
                                if matches!(target, Ty::Long | Ty::ULong) {
                                    // zero-extend the 32-bit unsigned value into a long
                                    if let Some(call) =
                                        self.runtime_call(RuntimeOp::UIntToLong, rty, vec![r])
                                    {
                                        return Some(call);
                                    }
                                }
                                let rrepr = self.scalar_value_repr(rty).unwrap_or(rty);
                                let trepr = self.scalar_value_repr(target).unwrap_or(target);
                                if rrepr == trepr {
                                    return Some(r); // identity reinterpret (UInt↔Int, ULong↔Long, UInt→UInt)
                                }
                                if self.has_scalar_value_repr(rrepr)
                                    && self.has_scalar_value_repr(trepr)
                                {
                                    return Some(self.emit_type_op(
                                        IrTypeOp::ImplicitCoercion,
                                        r,
                                        ty_to_ir(trepr),
                                    ));
                                }
                            }
                            // Any other unsigned conversion (e.g. unsigned→float) isn't modeled — bail.
                            return None;
                        }
                    }
                    // Primitive numeric/`Char` conversions (`n.toLong()`, `c.toInt()`, `i.toChar()`, …)
                    // are coercions — the backend emits the `i2l`/`l2i`/`i2c`/… opcode.
                    {
                        let rty = self.info.ty(receiver);
                        if matches!(
                            rty,
                            Ty::Int
                                | Ty::Long
                                | Ty::Byte
                                | Ty::Short
                                | Ty::Char
                                | Ty::Double
                                | Ty::Float
                        ) && args.is_empty()
                            && is_conversion_call_name(&name)
                        {
                            let target = self.info.ty(e);
                            if target == Ty::Error {
                                return None;
                            }
                            let r = self.expr(receiver)?;
                            return Some(self.emit_type_op(
                                IrTypeOp::ImplicitCoercion,
                                r,
                                ty_to_ir(target),
                            ));
                        }
                    }
                    // (`a.compareTo(b)` on a primitive is handled by the shared `lower_prim_op_method`
                    // above — one lowering for the plain `.` and the safe `?.` call.)
                    // `Int`/`Long.inv()` — the bitwise complement intrinsic (`x xor -1`). The binary
                    // bitwise/shift members (`and`/`or`/`xor`/`shl`/`shr`/`ushr`) are handled by the
                    // shared `lower_prim_op_method` above (one lowering for the plain `.` and safe `?.`
                    // call); only the zero-arg `inv` remains here (the helper is one-arg).
                    {
                        let rty = self.info.ty(receiver);
                        if matches!(rty, Ty::Int | Ty::Long) && name == "inv" && args.is_empty() {
                            let l = self.expr(receiver)?;
                            let neg1 = self.emit_const(if rty == Ty::Long {
                                IrConst::Long(-1)
                            } else {
                                IrConst::Int(-1)
                            });
                            return Some(self.emit_primitive_bin_op(IrBinOp::BitXor, l, neg1));
                        }
                    }
                    if let Expr::Name(rn) = self.afile.expr(receiver).clone() {
                        let internal = class_internal(self.afile, &rn);
                        if let Some(ci) = self.class_info(&internal) {
                            let cls = ci.id;
                            if !self.ir.classes[cls as usize].enum_entries.is_empty() {
                                if name == "values" && args.is_empty() {
                                    return Some(
                                        self.ir.add_expr(IrExpr::EnumValues { class: cls }),
                                    );
                                }
                                if let ("valueOf", [arg]) = (name.as_str(), &args[..]) {
                                    let a = self.expr(*arg)?;
                                    return Some(
                                        self.ir
                                            .add_expr(IrExpr::EnumValueOf { class: cls, arg: a }),
                                    );
                                }
                            }
                        }
                    }
                    let rt = self.recv_ty(receiver);
                    if let Some(ResolvedCall::ModuleMember {
                        owner,
                        name: target,
                        params,
                        ret,
                        interface,
                    }) = self.info.resolved_calls.get(&e).cloned()
                    {
                        if target != name {
                            return None;
                        }
                        let recv = self.expr(receiver)?;
                        let owner = owner.render();
                        if let Some((class, index, _fid, mret)) =
                            self.link_local_method(&owner, &target, &params)
                        {
                            let (provided, prelude) = if let Some(slots) =
                                self.info.resolved_call_arg_slots.get(&e).cloned()
                            {
                                self.lower_method_slot_args_source_order(&args, &slots, &params)?
                            } else {
                                if args.len() != params.len() {
                                    return None;
                                }
                                (
                                    self.lower_args(&args, &params)?
                                        .into_iter()
                                        .map(Some)
                                        .collect(),
                                    Vec::new(),
                                )
                            };
                            let call = self.emit_method_call(class, index, recv, provided);
                            // A generic higher-order member erases its `<R>` return to `Object`; the
                            // checker records the concrete result (`box.map { it.length }` → `Int`), so
                            // insert the `checkcast`/unbox kotlinc emits on the erased return.
                            let call = self.coerce_generic_read(call, e, mret);
                            self.wrap_arg_prelude(call, prelude)
                        } else {
                            if args.len() != params.len()
                                || self
                                    .info
                                    .resolved_call_arg_slots
                                    .get(&e)
                                    .is_some_and(|slots| slots.iter().any(Option::is_none))
                            {
                                return None;
                            }
                            let a = self.lower_args(&args, &params)?;
                            self.emit_call(
                                Callee::CrossFileVirtual {
                                    owner: type_name(&owner),
                                    name: target,
                                    params: tys_to_ir(&params),
                                    ret: ty_to_ir(ret),
                                    interface,
                                },
                                Some(recv),
                                a,
                            )
                        }
                    } else if matches!(name.as_str(), "toString" | "hashCode") && args.is_empty() {
                        // `x.toString()`/`x.hashCode()` → the `kotlin/Any` virtual (dispatches to any
                        // override), not a by-index member — so it needs no class-side method-table entry.
                        let recv = self.expr(receiver)?;
                        self.emit_external_call(format!("kotlin/Any.{name}"), Some(recv), vec![])
                    } else if let Some(resolved) = self.info.resolved_member(e).cloned() {
                        let recv = self.expr(receiver)?;
                        let ret = resolved.ret;
                        if let Some(r) =
                            self.lower_library_default_member_call(recv, rt, e, &resolved, &args)
                        {
                            return Some(r);
                        }
                        let member = resolved.member;
                        let physical_ret = member.physical_ret;
                        let mparams = member.params.clone();
                        let owner = member.owner.unwrap_or_else(|| {
                            rt.obj_internal()
                                .map(|n| n.render())
                                .unwrap_or_else(|| "kotlin/Any".to_string())
                                .into()
                        });
                        // Fewer arguments than the resolved member has parameters means a DEFAULTED
                        // argument was omitted, but the `$default` path above (`lower_library_default_member_
                        // call`) could not fill it — e.g. a method inherited through DELEGATION (`class C(x:
                        // A) : A by x`, whose default lives on interface `A`, with no `C.f$default`
                        // synthetic). The plain call below only lowers the PROVIDED arguments, so the emitted
                        // invocation would be arity-short and load an uninitialized slot for the missing one
                        // (VerifyError). Bail — skip, don't miscompile. A trailing vararg (array) parameter
                        // legitimately accepts fewer arguments, so it is excluded.
                        // `mparams` is the LOGICAL parameter list (a `suspend` member's trailing
                        // `Continuation` is threaded separately by the coroutine pass, not counted here), so
                        // this applies uniformly to suspend and non-suspend members.
                        if args.len() < mparams.len()
                            && mparams.last().is_none_or(|p| p.array_elem().is_none())
                        {
                            return None;
                        }
                        // The receiver's PRIMITIVE element type (`ArrayList<Byte>` → `Byte`,
                        // `ArrayList<Long>` → `Long`). `coll.add(0)` must box the value as THAT wrapper
                        // (`Byte`/`Long`/…), not the literal's own `Integer` — else iterating the element
                        // (`checkcast Byte`/`Long`) throws `ClassCastException`. Coerced only when the
                        // argument's primitive type actually differs from the element (below).
                        let elem_prim = if let Ty::Obj(_, targs) = &rt {
                            targs
                                .first()
                                .copied()
                                .filter(|t| self.has_scalar_value_repr(*t))
                        } else {
                            None
                        };
                        // Coerce each argument to the resolved parameter type so a primitive flowing into
                        // an erased `Any` parameter (`List<Int>.add(E)` → `add(Object)`) autoboxes.
                        let a = if let Some(slots) =
                            self.info.resolved_call_arg_slots.get(&e).cloned()
                        {
                            if slots.iter().any(Option::is_none) {
                                return None;
                            }
                            self.lower_call_slot_args_with_element(
                                &args, &slots, &mparams, elem_prim,
                            )?
                        } else {
                            let mut lowered = Vec::new();
                            for (i, &arg) in args.iter().enumerate() {
                                match mparams.get(i) {
                                    Some(p)
                                        if p.is_erased_top()
                                            && elem_prim.is_some_and(|e| {
                                                let a = self.info.ty(arg);
                                                self.has_scalar_value_repr(a) && a != e
                                            }) =>
                                    {
                                        // Coerce to the element primitive (i2b/i2l/…), then box as THAT
                                        // wrapper for the erased `Object` parameter.
                                        let e = elem_prim.unwrap();
                                        let v = self.lower_arg(arg, &ty_to_ir(e))?;
                                        lowered.push(self.emit_type_op(
                                            IrTypeOp::ImplicitCoercion,
                                            v,
                                            ty_to_ir(*p),
                                        ));
                                    }
                                    Some(p) => lowered.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                                    None => lowered.push(self.expr(arg)?),
                                }
                            }
                            lowered
                        };
                        let call = self.emit_library_member_call(
                            recv,
                            owner,
                            member,
                            ret,
                            resolved.suspend,
                            a,
                        );
                        // A generic member whose erased return is `Object` but whose substituted type is
                        // more specific (`List<Int>.get` → `Int`) gets the unbox/checkcast kotlinc emits.
                        self.coerce_to_static(call, ret, physical_ret)
                    } else if let Some((internal, m)) = {
                        // A `@JvmStatic` member of a classpath `object` (`UuidGen.of(x)`) → a static
                        // method on the object class (`invokestatic`), found in the type's static list.
                        rt.obj_internal()
                            .zip(self.info.resolved_companion(e).cloned())
                    } {
                        let owner = m.owner_type_or(internal);
                        let vararg_arr = m.params.last().copied().filter(|last| {
                            last.array_elem().is_some()
                                && !(args.len() == m.params.len()
                                    && args.last().is_some_and(|&arg| self.info.ty(arg) == *last))
                        });
                        let a = if let Some(arr_ty) = vararg_arr {
                            let elem = arr_ty.array_elem().unwrap();
                            let fixed = m.params.len() - 1;
                            let mut a = Vec::with_capacity(fixed + 1);
                            for (&arg, &pt) in args[..fixed].iter().zip(&m.params[..fixed]) {
                                a.push(self.lower_arg(arg, &ty_to_ir(pt))?);
                            }
                            let mut elems = Vec::with_capacity(args.len() - fixed);
                            for &arg in &args[fixed..] {
                                elems.push(self.lower_arg(arg, &ty_to_ir(elem))?);
                            }
                            a.push(self.emit_vararg(arr_ty, elems));
                            a
                        } else {
                            let mut a = Vec::new();
                            for (i, &arg) in args.iter().enumerate() {
                                match m.params.get(i) {
                                    Some(p) => a.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                                    None => a.push(self.expr(arg)?),
                                }
                            }
                            a
                        };
                        let call = self.emit_static_call(owner, m.name, m.descriptor, m.inline, a);
                        self.coerce_to_static(call, m.ret, m.physical_ret)
                    } else if let Some(c) = self.info.resolved_extension(e).cloned() {
                        // SAFETY GUARD (never miscompile): a non-inlined `suspend inline fun` (e.g.
                        // `Mutex.withLock`) is lowered below as a PLAIN `name$default(…, Function0, cont)`
                        // call — each lambda argument becomes a NON-suspend `Function`. That is valid only
                        // when the lambda body does not suspend (`m.withLock { 42 }` works). A non-suspend
                        // function-typed param whose lambda body DOES suspend is accepted by the front end
                        // solely because the callee is `inline` (an inline lambda inherits the caller's
                        // suspendability) — but krusty is NOT splicing it here, so the emitted `Function0`
                        // would be asked to call a suspend function it cannot, yielding invalid bytecode
                        // (krusty exits 0 but `-Xverify:all` reports an operand-stack underflow). Until
                        // general suspend-inline splicing lands (inline the lock/try/finally body and splice
                        // the user lambda into the enclosing CPS state machine, as kotlinc does), DECLINE.
                        // Generic (keyed on the shape, not the `withLock` name — the `$default` synthetic's
                        // metadata `inline` flag is `None` anyway, so it can't be the discriminator).
                        if c.suspend {
                            for &arg in args.iter() {
                                if let Expr::Lambda { body, .. } = self.afile.expr(arg) {
                                    let non_suspend_fun =
                                        matches!(self.info.ty(arg), Ty::Fun(s) if !s.suspend);
                                    if non_suspend_fun && self.ast_body_suspends(*body) {
                                        self.set_bail("suspend-inline HOF lambda suspends");
                                        return None;
                                    }
                                }
                            }
                        }
                        // A library extension `recv.name(args)` → `invokestatic facade.name(recv, args)`.
                        // The CHECKER resolved it (sole resolver) and recorded the callable; the lowerer
                        // only reads it. Owner + descriptor come from that record — no name hardcoded.
                        // Coerce the receiver + arguments to the extension's parameter types so a
                        // primitive flowing into a generic `Object` parameter (`fun <T> T.to(…)`) boxes.
                        let p0 = *c.params.first().unwrap_or(&rt);
                        let recv = self.lower_arg(receiver, &ty_to_ir(p0))?;
                        let mut a = vec![recv];
                        let explicit_params = c.params.get(1..)?;
                        // A `$default` call with a TRAILING LAMBDA: the lambda fills the LAST real parameter
                        // (`transform`), the leading args a prefix, the MIDDLE parameters default.
                        let trailing_lambda = c.default_call
                            && args
                                .last()
                                .is_some_and(|&x| matches!(self.info.ty(x), Ty::Fun(_)));
                        if let Some(slots) = self.info.resolved_call_arg_slots.get(&e).cloned() {
                            let slot_args =
                                self.lower_call_slot_args(&args, &slots, explicit_params)?;
                            if c.default_call {
                                let mask: i32 = slots
                                    .iter()
                                    .enumerate()
                                    .filter(|(_, slot)| slot.is_none())
                                    .map(|(i, _)| 1i32 << i)
                                    .sum();
                                a.extend(slot_args);
                                self.append_default_mask_marker(&mut a, mask);
                            } else {
                                if slots.iter().any(Option::is_none) {
                                    return None;
                                }
                                a.extend(slot_args);
                            }
                        } else if c.default_call {
                            self.append_default_call_args(
                                &mut a,
                                explicit_params,
                                &args,
                                trailing_lambda,
                            )?;
                        } else {
                            for (i, &arg) in args.iter().enumerate() {
                                match explicit_params.get(i) {
                                    Some(p) => a.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                                    None => a.push(self.expr(arg)?),
                                }
                            }
                        }
                        // A suspend EXTENSION resolved to its `name$default` synthetic (`m.withLock { … }`
                        // omitting the defaulted `owner`): its physical descriptor spells the `Continuation`
                        // before the mask/marker, so record the call for the coroutine pass to INSERT the
                        // continuation value there (`append_continuation`, `$default` arm). `c.ret` is the
                        // logical return the pass unboxes the erased `Object` suspension result by.
                        let physical_ret = c.physical_ret;
                        let suspend_default = c.default_call && c.suspend;
                        // `rt` is the extension receiver's type — its type args bind a reified `T` that is
                        // inferred from the receiver (`Collection<T>.toTypedArray()`) when none is explicit.
                        let reified_subst = self.reified_call_subst_for(e, &c, Some(rt));
                        let source_receiver = c.source_receiver;
                        let call = self.emit_library_static_call(c, a, suspend_default);
                        if !reified_subst.is_empty() {
                            self.ir.reified_call_subst.insert(call, reified_subst);
                        }
                        self.record_ext_source_receiver(call, source_receiver);
                        self.coerce_generic_read(call, e, physical_ret)
                    } else if let Some(ResolvedCall::LambdaReturnMember(c)) =
                        self.info.resolved_calls.get(&e).cloned()
                    {
                        // An INSTANCE MEMBER selected by lambda-return overload resolution (`recv.run2
                        // { … }`): the receiver is the DISPATCH receiver (`invokevirtual`/`invokeinterface`),
                        // NOT an argument. The checker recorded it; the lowerer has no other path for it
                        // (emitting it static would leave the receiver on the operand stack → `VerifyError`).
                        let phys = c.physical_ret;
                        let owner = c.owner_type();
                        let interface = self.library_type_is_interface(owner);
                        let recv = self.expr(receiver)?;
                        let mut a = Vec::new();
                        for (i, &arg) in args.iter().enumerate() {
                            match c.params.get(i) {
                                Some(p) => a.push(self.lower_arg(arg, &ty_to_ir(*p))?),
                                None => a.push(self.expr(arg)?),
                            }
                        }
                        let call =
                            self.emit_virtual_call(owner, c.name, c.descriptor, interface, recv, a);
                        self.coerce_generic_read(call, e, phys)
                    } else {
                        // A private `@InlineOnly` extension (scope fn / `String.uppercase()`) is recorded
                        // as an [`Extension`] by the checker and handled by the general branch above (its
                        // `inline` metadata makes the backend splice). Nothing left to resolve here.
                        self.set_bail("unrecorded qualified call target");
                        return None;
                    }
                }
                _ => return None,
            },
        })
    }
}

/// Whether `e` emits as a branch (a conditional that materializes via jumps + merge frames). Such an
/// expression can't be safely emitted while other operands sit on the stack (the merge frame would
/// omit them). Primitive `==`/`<`… and `if`/`when`/elvis are branchy; reference `==`
/// (`Intrinsics.areEqual`) and plain calls are not.
/// Does the expression (or any nested statement/expression) contain a `return`? Inlining a body or
/// lambda that returns non-locally isn't modeled, so such an `inline fun` is bailed (file skipped).
/// Whether `name` is referenced as a VALUE within `e` — anywhere except as the direct callee of a call.
/// An inline lambda parameter used only as `f(args)` can be spliced in place; one used as a value (passed
/// to another function, stored, or returned) must be materialized as a `FunctionN` instead.
fn name_used_as_value(file: &ast::File, e: AstExprId, name: &str) -> bool {
    match file.expr(e) {
        Expr::Name(n) => n == name,
        Expr::Call { callee, args } => {
            let callee_is_target = matches!(file.expr(*callee), Expr::Name(n) if n == name);
            (!callee_is_target && name_used_as_value(file, *callee, name))
                || args.iter().any(|&a| name_used_as_value(file, a, name))
        }
        _ => file.any_child_expr(e, &mut |c| name_used_as_value(file, c, name), &mut |s| {
            file.any_child_stmt(s, &mut |c| name_used_as_value(file, c, name))
        }),
    }
}

/// Does `e` contain a BARE `return` (no label — a non-local return from the enclosing function), at ANY
/// nesting depth INCLUDING inside nested lambdas? A bare return is non-local, so every lambda that
/// (transitively) encloses it must be inlined — a nested lambda's bare return surfaces in the outer
/// lambda's body once spliced, making the outer impl method invalid too. A labeled `return@x` (a local
/// return) is excluded. (Kotlin forbids a bare return inside a non-inline lambda, so descending is sound.)
fn body_has_bare_return(file: &ast::File, e: AstExprId) -> bool {
    fn stmt_bare(file: &ast::File, s: ast::StmtId) -> bool {
        match file.stmt(s) {
            Stmt::Return(_, None) => true,
            Stmt::Return(_, Some(_)) => false,
            _ => file.any_child_stmt(s, &mut |x| body_has_bare_return(file, x)),
        }
    }
    file.any_child_expr(e, &mut |x| body_has_bare_return(file, x), &mut |s| {
        stmt_bare(file, s)
    })
}

fn body_has_return(file: &ast::File, e: AstExprId) -> bool {
    file.any_child_expr(e, &mut |x| body_has_return(file, x), &mut |s| {
        stmt_has_return(file, s)
    })
}

/// Whether `e` or any descendant is a `try` expression — used to keep the `tailrec` loop transform off
/// a body with a `try`/`finally` (a tail call in a `finally` isn't loop-optimizable, and the
/// try-with-return codegen would miscompile under the transform).
fn body_has_try(file: &ast::File, e: AstExprId) -> bool {
    matches!(file.expr(e), Expr::Try { .. })
        || file.any_child_expr(e, &mut |x| body_has_try(file, x), &mut |s| {
            file.any_child_stmt(s, &mut |x| body_has_try(file, x))
        })
}

fn stmt_has_return(file: &ast::File, s: ast::StmtId) -> bool {
    matches!(file.stmt(s), Stmt::Return(..))
        || file.any_child_stmt(s, &mut |x| body_has_return(file, x))
}

/// Does `e` contain a `return@label` matching `label` (not descending into nested lambdas)?
fn body_has_labeled_return(file: &ast::File, e: AstExprId, label: &str) -> bool {
    fn stmt_has(file: &ast::File, s: ast::StmtId, lbl: &str) -> bool {
        match file.stmt(s) {
            Stmt::Return(_, l) => l.as_deref() == Some(lbl),
            _ => file.any_child_stmt(s, &mut |x| expr_has(file, x, lbl)),
        }
    }
    fn expr_has(file: &ast::File, e: AstExprId, lbl: &str) -> bool {
        if matches!(file.expr(e), Expr::Lambda { .. }) {
            return false;
        }
        file.any_child_expr(e, &mut |x| expr_has(file, x, lbl), &mut |s| {
            stmt_has(file, s, lbl)
        })
    }
    expr_has(file, e, label)
}

/// Does `e` contain a `return` the inline-lambda expander can't model — a `return@other` (labeled to some
/// OTHER inline fn, not the one being expanded)? A BARE `return` (non-local to the enclosing function) IS
/// modeled now: `lower_inline_lambda_invoke` clears the inline-return stack while lowering the body, so the
/// bare `return` targets the real enclosing function's return. A `return@own_label` (local to this lambda)
/// is also modeled (the `inline_lambda_ret` frame). Nested lambdas keep their own return scope.
fn body_has_disallowed_return(file: &ast::File, e: AstExprId, own_label: &str) -> bool {
    fn stmt_bad(file: &ast::File, s: ast::StmtId, own: &str) -> bool {
        match file.stmt(s) {
            // `return@other` — labeled to a different inline fn — isn't modeled; bail. Bare / `return@own`
            // are fine (handled by the real-return clear / the `inline_lambda_ret` frame respectively).
            Stmt::Return(_, Some(l)) if l != own => true,
            _ => file.any_child_stmt(s, &mut |x| expr_bad(file, x, own)),
        }
    }
    fn expr_bad(file: &ast::File, e: AstExprId, own: &str) -> bool {
        // A nested lambda has its own return scope — don't descend into it.
        if matches!(file.expr(e), Expr::Lambda { .. }) {
            return false;
        }
        file.any_child_expr(e, &mut |x| expr_bad(file, x, own), &mut |s| {
            stmt_bad(file, s, own)
        })
    }
    expr_bad(file, e, own_label)
}

fn is_branchy(file: &ast::File, e: AstExprId) -> bool {
    match file.expr(e) {
        Expr::If { .. } | Expr::When { .. } | Expr::Elvis { .. } => true,
        // A safe call `recv?.m()` lowers to a null-check branch (a stackmap frame), so it is not safe to
        // splice mid-sequence (e.g. as an array-literal element) — treat it as branchy so callers bail.
        Expr::SafeCall { .. } => true,
        // A `try`/`catch` expression emits exception-handler merge frames; as a mid-`Vararg`-fill element
        // those frames land inside the element-store sequence and fail the verifier — bail (skip).
        Expr::Try { .. } => true,
        Expr::Binary { op, lhs, .. } => {
            use ast::BinOp::*;
            matches!(op, Lt | Le | Gt | Ge | And | Or)
                || (matches!(op, Eq | Ne) && file_expr_is_jvm_scalar(file, *lhs))
        }
        Expr::Unary {
            op: ast::UnOp::Not, ..
        } => true,
        _ => false,
    }
}

/// Deep check: does `e` contain any branch-producing construct (`if`/`when`/elvis/safe-call/`try`/`&&`/
/// `||`/loop) anywhere within it? The branchless lambda-splice (the `let`/`also` inline route) can't
/// relocate the stackmap frames such a body produces, so a branchy lambda body must fall back to the
/// per-function desugar (which inlines the body through normal branchy lowering).
fn body_contains_branch(file: &ast::File, e: AstExprId) -> bool {
    match file.expr(e) {
        Expr::If { .. }
        | Expr::When { .. }
        | Expr::Elvis { .. }
        | Expr::SafeCall { .. }
        | Expr::Try { .. } => true,
        Expr::Binary {
            op: ast::BinOp::And | ast::BinOp::Or,
            ..
        } => true,
        Expr::Lambda { .. } => false, // a nested lambda is its own method body
        _ => file.any_child_expr(e, &mut |c| body_contains_branch(file, c), &mut |s| {
            stmt_contains_branch(file, s)
        }),
    }
}

fn stmt_contains_branch(file: &ast::File, s: ast::StmtId) -> bool {
    match file.stmt(s) {
        Stmt::While { .. } | Stmt::DoWhile { .. } | Stmt::For { .. } | Stmt::ForEach { .. } => true,
        _ => file.any_child_stmt(s, &mut |c| body_contains_branch(file, c)),
    }
}

fn has_byte_or_short_param(params: &[Ty]) -> bool {
    params.iter().any(|p| {
        matches!(p, Ty::Byte | Ty::Short)
            || p.array_elem()
                .is_some_and(|elem| matches!(elem, Ty::Byte | Ty::Short))
    })
}

/// A `when (subject) { … }` condition that is a complete boolean test of the subject (`is`/`!is`,
/// `in`/`!in` range) — built by the parser as a structural `Is`/`InRange` node, so it is used directly,
/// not compared with `subject == cond`.
fn is_when_test(file: &ast::File, e: AstExprId) -> bool {
    matches!(file.expr(e), Expr::Is { .. } | Expr::InRange { .. })
}

/// Const-fold an annotation argument expression to a String: a string literal, a `const val` name, or a
/// string template whose interpolations are themselves const-foldable (`"$prefix.bar"` with
/// `const val prefix = "foo"` → `"foo.bar"`). `None` for anything not statically a string.
fn const_string_value(file: &ast::File, e: AstExprId) -> Option<String> {
    const_string_value_d(file, e, 0)
}

/// `String.trimIndent()`: split into lines, drop the common minimal indentation of the non-blank
/// lines from every line, and omit a blank FIRST or LAST line — matching `kotlin.text.trimIndent`.
fn trim_indent(s: &str) -> String {
    let lines: Vec<&str> = s.split('\n').collect();
    let min_indent = lines
        .iter()
        .filter(|l| !l.trim().is_empty())
        .map(|l| l.len() - l.trim_start().len())
        .min()
        .unwrap_or(0);
    let last = lines.len().saturating_sub(1);
    let mut out: Vec<String> = Vec::new();
    for (i, line) in lines.iter().enumerate() {
        if (i == 0 || i == last) && line.trim().is_empty() {
            continue;
        }
        // A blank line may be shorter than `min_indent`; only cut what is there.
        let cut = min_indent.min(line.len());
        out.push(line[cut..].to_string());
    }
    out.join("\n")
}

/// `String.trimMargin(prefix)`: for each line, remove leading whitespace up to and including the
/// first `prefix`; a line without the prefix is left unchanged. A blank FIRST or LAST line is
/// omitted — matching `kotlin.text.trimMargin`.
fn trim_margin(s: &str, margin: &str) -> String {
    let lines: Vec<&str> = s.split('\n').collect();
    let last = lines.len().saturating_sub(1);
    let mut out: Vec<String> = Vec::new();
    for (i, line) in lines.iter().enumerate() {
        if (i == 0 || i == last) && line.trim().is_empty() {
            continue;
        }
        let trimmed = line.trim_start();
        if let Some(rest) = trimmed.strip_prefix(margin) {
            out.push(rest.to_string());
        } else {
            out.push(line.to_string());
        }
    }
    out.join("\n")
}

/// `depth` bounds the recursion through `const val` references so a cyclic chain
/// (`const val a = b; const val b = a`) terminates with `None` instead of overflowing the stack.
fn const_string_value_d(file: &ast::File, e: AstExprId, depth: u32) -> Option<String> {
    if depth > 32 {
        return None;
    }
    match file.expr(e) {
        Expr::StringLit(s) => Some(s.clone()),
        Expr::CharLit(c) => Some(c.to_string()),
        Expr::Name(n) => top_level_const_string_d(file, n, depth + 1),
        Expr::Template(parts) => {
            let mut out = String::new();
            for p in parts {
                match p {
                    TemplatePart::Str(s) => out.push_str(s),
                    TemplatePart::Expr(x) => {
                        out.push_str(&const_string_value_d(file, *x, depth + 1)?)
                    }
                }
            }
            Some(out)
        }
        _ => None,
    }
}

/// The string value of a top-level property `name` whose initializer const-folds to a string
/// (`const val prefix = "foo"`), or `None`. (krusty's parser doesn't currently retain the `const`
/// modifier on a top-level `val`, so this matches any top-level property with a foldable string init —
/// safe, since only literals/foldable templates fold.)
fn top_level_const_string_d(file: &ast::File, name: &str, depth: u32) -> Option<String> {
    if depth > 32 {
        return None;
    }
    file.decls.iter().find_map(|&d| match file.decl(d) {
        Decl::Property(p) if p.name == name => p
            .init
            .and_then(|i| const_string_value_d(file, i, depth + 1)),
        _ => None,
    })
}

/// `(property_name, serial_name)` for each primary-constructor property carrying `@SerialName("…")`
/// (const-folded). Empty when none — the serialization extension reads this to name descriptor elements.
/// Build the IR for a primary-constructor default value (file-independent — no AST `ExprId`, so it works
/// when a subclass/companion in a DIFFERENT file fills a base's default). A literal → a `Const`; an
/// object singleton → `getstatic <internal>.INSTANCE`.
fn ctor_default_to_ir(
    ir: &mut IrFile,
    runtime: &dyn TargetRuntime,
    dv: &CtorDefaultValue,
) -> Option<ExprId> {
    let e = match dv {
        CtorDefaultValue::Int(v) => IrExpr::Const(IrConst::Int(*v as i32)),
        CtorDefaultValue::Long(v) => IrExpr::Const(IrConst::Long(*v)),
        CtorDefaultValue::Double(v) => IrExpr::Const(IrConst::Double(*v)),
        CtorDefaultValue::Float(v) => IrExpr::Const(IrConst::Float(*v)),
        CtorDefaultValue::Bool(v) => IrExpr::Const(IrConst::Boolean(*v)),
        CtorDefaultValue::Char(v) => IrExpr::Const(IrConst::Char(*v)),
        CtorDefaultValue::Str(s) => IrExpr::Const(IrConst::String(s.clone())),
        CtorDefaultValue::Null => IrExpr::Const(IrConst::Null),
        CtorDefaultValue::Object(internal) => {
            let field = runtime.object_instance_field(internal)?;
            return Some(platform_field_expr(ir, field));
        }
    };
    Some(ir.add_expr(e))
}

impl crate::synthetics::SyntheticIrBuilder for Lower<'_> {
    fn emit(&mut self, expr: IrExpr) -> ExprId {
        Lower::emit(self, expr)
    }

    fn lower_arg(&mut self, expr: AstExprId, target: &Ty) -> Option<ExprId> {
        Lower::lower_arg(self, expr, target)
    }

    fn synth_expr(&mut self, expr: AstExprId) -> Option<ExprId> {
        Lower::synth_expr(self, expr)
    }

    fn synth_is_branchy(&self, expr: AstExprId) -> bool {
        Lower::synth_is_branchy(self, expr)
    }

    fn synth_array_elem(&self, call: AstExprId) -> Option<Ty> {
        Lower::synth_array_elem(self, call)
    }

    fn synth_arg_lambda(&self, arg: AstExprId) -> Option<(Vec<String>, AstExprId)> {
        Lower::synth_arg_lambda(self, arg)
    }

    fn build_fill_array(
        &mut self,
        elem: Ty,
        size_arg: AstExprId,
        params: Vec<String>,
        body: AstExprId,
    ) -> Option<ExprId> {
        Lower::build_fill_array(self, elem, size_arg, params, body)
    }
}

fn platform_field_expr(ir: &mut IrFile, field: PlatformField) -> ExprId {
    ir.external_static_field(&field.owner, field.name, field.descriptor)
}

/// Const-fold a primary-constructor default-value expression to an [`IrConst`] for the serialization
/// extension's `isOptional` element handling. Only obvious compile-time literals (the common
/// `= null`/`= 5`/`= "x"`/`= true` defaults); `None` for any non-literal default (the field is then
/// treated as non-optional — never miscompiled).
fn const_default_of(file: &ast::File, e: AstExprId) -> Option<crate::ir::IrConst> {
    use crate::ir::IrConst;
    Some(match file.expr(e) {
        Expr::NullLit => IrConst::Null,
        Expr::IntLit(v) => IrConst::Int(*v as i32),
        Expr::LongLit(v) => IrConst::Long(*v),
        Expr::BoolLit(v) => IrConst::Boolean(*v),
        Expr::DoubleLit(v) => IrConst::Double(*v),
        Expr::FloatLit(v) => IrConst::Float(*v),
        Expr::CharLit(v) => IrConst::Char(*v),
        Expr::StringLit(s) => IrConst::String(s.clone()),
        _ => return None,
    })
}

/// Widen a const-folded default literal to the field's declared numeric type so its JVM slot
/// width/kind matches the field local (`val x: Long = 5` folds `5` as `Int` but must store as `Long`;
/// likewise `Float`/`Double`). Non-numeric or already-matching consts pass through unchanged.
fn widen_const_to(c: crate::ir::IrConst, t: Ty) -> crate::ir::IrConst {
    use crate::ir::IrConst;
    match (t, c) {
        (Ty::Long, IrConst::Int(v)) => IrConst::Long(v as i64),
        (Ty::Long, IrConst::Byte(v)) => IrConst::Long(v as i64),
        (Ty::Long, IrConst::Short(v)) => IrConst::Long(v as i64),
        (Ty::Double, IrConst::Int(v)) => IrConst::Double(v as f64),
        (Ty::Double, IrConst::Long(v)) => IrConst::Double(v as f64),
        (Ty::Double, IrConst::Float(v)) => IrConst::Double(v as f64),
        (Ty::Float, IrConst::Int(v)) => IrConst::Float(v as f32),
        (Ty::Float, IrConst::Long(v)) => IrConst::Float(v as f32),
        (_, c) => c,
    }
}

fn is_const_literal(file: &ast::File, e: AstExprId) -> bool {
    matches!(
        file.expr(e),
        Expr::IntLit(_)
            | Expr::LongLit(_)
            | Expr::UIntLit(_)
            | Expr::ULongLit(_)
            | Expr::DoubleLit(_)
            | Expr::FloatLit(_)
            | Expr::BoolLit(_)
            | Expr::CharLit(_)
            | Expr::StringLit(_)
            | Expr::NullLit
    )
}

/// Best-effort: is the literal/operand a primitive (so `==` would use a numeric branch, not
/// `Intrinsics.areEqual`)? Conservative — only obvious primitive literals count.
fn file_expr_is_jvm_scalar(file: &ast::File, e: AstExprId) -> bool {
    matches!(
        file.expr(e),
        Expr::IntLit(_)
            | Expr::LongLit(_)
            | Expr::UIntLit(_)
            | Expr::ULongLit(_)
            | Expr::DoubleLit(_)
            | Expr::FloatLit(_)
            | Expr::BoolLit(_)
            | Expr::CharLit(_)
    )
}

/// The IR parameter type for a captured local lifted into a local function: a boxed capture is passed as
/// the runtime holder reference; an ordinary captured local by its own value.
fn captured_param_ir(runtime: &dyn TargetRuntime, ty: Ty, shared_cell: bool) -> Option<Ty> {
    if shared_cell {
        runtime.mutable_local_ref_type(ty).map(ty_to_ir)
    } else {
        Some(ty_to_ir(ty))
    }
}

fn lambda_info(info: &FrontendTypeInfo, e: AstExprId) -> LambdaInfo {
    match info.expr_lowers.get(&e) {
        Some(ExprLowering::Lambda(li)) => *li,
        _ => Default::default(),
    }
}

/// The fixed-parameter count for a (possibly `vararg`) call, or `None` when the argument count doesn't
/// fit: a `vararg` accepts `>= params.len() - 1` arguments (the rest pack into the trailing array); a
/// non-`vararg` requires an exact match.
fn vararg_arity(vararg: bool, n_params: usize, n_args: usize) -> Option<usize> {
    if vararg {
        let n_fixed = n_params.saturating_sub(1);
        (n_args >= n_fixed).then_some(n_fixed)
    } else {
        (n_args == n_params).then_some(n_params)
    }
}

fn shared_cell_vars_for_body(
    file: &ast::File,
    body: &FunBody,
    info: &FrontendTypeInfo,
) -> std::collections::HashSet<String> {
    let root = match body {
        FunBody::Expr(e) | FunBody::Block(e) => *e,
        FunBody::None => return std::collections::HashSet::new(),
    };
    shared_cell_vars_for_expr(file, root, info)
}

/// Every name referenced (read or written) inside a NON-inline closure — a non-inline lambda body or a
/// local-function body — within `body`. Used to bail on a `lateinit var` local captured by such a
/// closure (its uninitialized guard isn't threaded through the captured representation). An
/// inline-spliced lambda keeps its captures in the outer scope, so it is traversed like ordinary code
/// (its captures are NOT collected).
fn closure_captured_names_for_body(
    file: &ast::File,
    body: &FunBody,
    info: &FrontendTypeInfo,
) -> std::collections::HashSet<String> {
    let root = match body {
        FunBody::Expr(e) | FunBody::Block(e) => *e,
        FunBody::None => return std::collections::HashSet::new(),
    };
    let mut out = std::collections::HashSet::new();
    collect_closure_captured_expr(file, root, info, false, &mut out);
    out
}

fn collect_closure_captured_expr(
    file: &ast::File,
    e: AstExprId,
    info: &FrontendTypeInfo,
    in_closure: bool,
    out: &mut std::collections::HashSet<String>,
) {
    match file.expr(e) {
        Expr::Name(n) if in_closure => {
            out.insert(n.clone());
        }
        Expr::Lambda { body, .. } => {
            // An inline-spliced lambda's body stays in the enclosing scope — traverse it with the same
            // `in_closure` flag. A non-inline lambda is a real closure: everything in its body is captured.
            let inline = matches!(lambda_info(info, e).capture, LambdaCapture::InlineSplice);
            let child = in_closure || !inline;
            collect_closure_captured_expr(file, *body, info, child, out);
            return;
        }
        _ => {}
    }
    let mut child_exprs = Vec::new();
    let mut child_stmts = Vec::new();
    file.any_child_expr(
        e,
        &mut |c| {
            child_exprs.push(c);
            false
        },
        &mut |s| {
            child_stmts.push(s);
            false
        },
    );
    for c in child_exprs {
        collect_closure_captured_expr(file, c, info, in_closure, out);
    }
    for s in child_stmts {
        collect_closure_captured_stmt(file, s, info, in_closure, out);
    }
}

fn collect_closure_captured_stmt(
    file: &ast::File,
    s: ast::StmtId,
    info: &FrontendTypeInfo,
    in_closure: bool,
    out: &mut std::collections::HashSet<String>,
) {
    match file.stmt(s) {
        Stmt::Assign { name, .. } | Stmt::IncDec { name, .. } if in_closure => {
            out.insert(name.clone());
        }
        // A local function's body is a closure — everything it references is captured. Handle its body
        // here (with `in_closure` set) and return, so the generic child walk doesn't re-visit it.
        Stmt::LocalFun(f) => {
            match &f.body {
                FunBody::Expr(b) | FunBody::Block(b) => {
                    collect_closure_captured_expr(file, *b, info, true, out)
                }
                FunBody::None => {}
            }
            return;
        }
        _ => {}
    }
    file.any_child_stmt(s, &mut |c| {
        collect_closure_captured_expr(file, c, info, in_closure, out);
        false
    });
}

/// The captured-and-mutated `var`s of a single expression (a property initializer or `init` block) —
/// each must be boxed into a `Ref` holder so a closure's writes are visible. The constructor lowers
/// these expressions outside any `lower_body`, so it must seed `shared_cell_vars` from here too.
fn shared_cell_vars_for_expr(
    file: &ast::File,
    root: AstExprId,
    info: &FrontendTypeInfo,
) -> std::collections::HashSet<String> {
    let mut reassigned = std::collections::HashSet::new();
    collect_reassigned_names(file, root, &mut reassigned);
    let mut scopes: Vec<std::collections::HashMap<String, bool>> = Vec::new();
    let mut out = std::collections::HashSet::new();
    collect_shared_cell_expr(file, root, info, &reassigned, &mut scopes, &mut out);
    out
}

fn collect_shared_cell_expr(
    file: &ast::File,
    e: AstExprId,
    info: &FrontendTypeInfo,
    reassigned: &std::collections::HashSet<String>,
    scopes: &mut Vec<std::collections::HashMap<String, bool>>,
    out: &mut std::collections::HashSet<String>,
) {
    match file.expr(e) {
        Expr::Block { stmts, trailing } => {
            scopes.push(std::collections::HashMap::new());
            for &s in stmts {
                collect_shared_cell_stmt(file, s, info, reassigned, scopes, out);
            }
            if let Some(t) = trailing {
                collect_shared_cell_expr(file, *t, info, reassigned, scopes, out);
            }
            scopes.pop();
        }
        Expr::Lambda { params, body } => {
            let inline_splice = lambda_info(info, e).capture == LambdaCapture::InlineSplice;
            if !inline_splice {
                for (name, is_var) in visible_locals(scopes) {
                    let access = outer_local_access(file, *body, &name);
                    if is_var && (access.writes || (reassigned.contains(&name) && access.reads)) {
                        out.insert(name);
                    }
                }
            }
            scopes.push(params.iter().map(|p| (p.clone(), false)).collect());
            collect_shared_cell_expr(file, *body, info, reassigned, scopes, out);
            scopes.pop();
        }
        _ => {
            let mut exprs = Vec::new();
            let mut stmts = Vec::new();
            file.any_child_expr(
                e,
                &mut |c| {
                    exprs.push(c);
                    false
                },
                &mut |s| {
                    stmts.push(s);
                    false
                },
            );
            for c in exprs {
                collect_shared_cell_expr(file, c, info, reassigned, scopes, out);
            }
            for s in stmts {
                collect_shared_cell_stmt(file, s, info, reassigned, scopes, out);
            }
        }
    }
}

fn collect_shared_cell_stmt(
    file: &ast::File,
    s: crate::ast::StmtId,
    info: &FrontendTypeInfo,
    reassigned: &std::collections::HashSet<String>,
    scopes: &mut Vec<std::collections::HashMap<String, bool>>,
    out: &mut std::collections::HashSet<String>,
) {
    match file.stmt(s) {
        Stmt::Local {
            is_var, name, init, ..
        } => {
            collect_shared_cell_expr(file, *init, info, reassigned, scopes, out);
            if let Some(scope) = scopes.last_mut() {
                scope.insert(name.clone(), *is_var);
            }
        }
        Stmt::Destructure { entries, init } => {
            collect_shared_cell_expr(file, *init, info, reassigned, scopes, out);
            if let Some(scope) = scopes.last_mut() {
                for (name, is_var) in entries {
                    if name != "_" {
                        scope.insert(name.clone(), *is_var);
                    }
                }
            }
        }
        Stmt::For {
            name, range, body, ..
        } => {
            collect_shared_cell_expr(file, range.start, info, reassigned, scopes, out);
            collect_shared_cell_expr(file, range.end, info, reassigned, scopes, out);
            scopes.push(std::iter::once((name.clone(), false)).collect());
            collect_shared_cell_expr(file, *body, info, reassigned, scopes, out);
            scopes.pop();
        }
        Stmt::ForEach {
            name,
            iterable,
            body,
            ..
        } => {
            collect_shared_cell_expr(file, *iterable, info, reassigned, scopes, out);
            scopes.push(std::iter::once((name.clone(), false)).collect());
            collect_shared_cell_expr(file, *body, info, reassigned, scopes, out);
            scopes.pop();
        }
        Stmt::LocalFun(_) => {
            if let Some(local_fun) = info.local_fun(s) {
                for cap in &local_fun.captures {
                    if cap.shared_cell {
                        out.insert(cap.name.clone());
                    }
                }
            }
        }
        Stmt::LocalClass(_) => {}
        _ => {
            let mut exprs = Vec::new();
            file.any_child_stmt(s, &mut |c| {
                exprs.push(c);
                false
            });
            for c in exprs {
                collect_shared_cell_expr(file, c, info, reassigned, scopes, out);
            }
        }
    }
}

fn visible_locals(scopes: &[std::collections::HashMap<String, bool>]) -> Vec<(String, bool)> {
    let mut out = Vec::new();
    let mut seen = std::collections::HashSet::new();
    for scope in scopes.iter().rev() {
        for (name, is_var) in scope {
            if seen.insert(name.clone()) {
                out.push((name.clone(), *is_var));
            }
        }
    }
    out
}

fn collect_reassigned_names(
    file: &ast::File,
    e: AstExprId,
    out: &mut std::collections::HashSet<String>,
) {
    let mut exprs = Vec::new();
    let mut stmts = Vec::new();
    file.any_child_expr(
        e,
        &mut |x| {
            exprs.push(x);
            false
        },
        &mut |s| {
            stmts.push(s);
            false
        },
    );
    for x in exprs {
        collect_reassigned_names(file, x, out);
    }
    for s in stmts {
        match file.stmt(s) {
            Stmt::Assign { name, .. } | Stmt::IncDec { name, .. } => {
                out.insert(name.clone());
            }
            _ => {}
        }
        let mut child_exprs = Vec::new();
        file.any_child_stmt(s, &mut |x| {
            child_exprs.push(x);
            false
        });
        for x in child_exprs {
            collect_reassigned_names(file, x, out);
        }
    }
}

#[derive(Clone, Copy, Default)]
struct OuterLocalAccess {
    reads: bool,
    writes: bool,
}

impl OuterLocalAccess {
    fn join(&mut self, other: Self) {
        self.reads |= other.reads;
        self.writes |= other.writes;
    }
}

fn outer_local_access(file: &ast::File, e: AstExprId, name: &str) -> OuterLocalAccess {
    outer_local_access_expr(file, e, name, false)
}

fn outer_local_access_expr(
    file: &ast::File,
    e: AstExprId,
    name: &str,
    shadowed: bool,
) -> OuterLocalAccess {
    match file.expr(e) {
        Expr::Name(n) if !shadowed && n == name => OuterLocalAccess {
            reads: true,
            writes: false,
        },
        Expr::IncDec { target, .. } => {
            let mut out = outer_local_access_expr(file, *target, name, shadowed);
            if !shadowed && matches!(file.expr(*target), Expr::Name(n) if n == name) {
                out.writes = true;
            }
            out
        }
        Expr::Block { stmts, trailing } => {
            let mut out = OuterLocalAccess::default();
            let mut shadowed = shadowed;
            for &s in stmts {
                let (access, next_shadowed) = outer_local_access_stmt(file, s, name, shadowed);
                out.join(access);
                shadowed = next_shadowed;
            }
            if let Some(t) = trailing {
                out.join(outer_local_access_expr(file, *t, name, shadowed));
            }
            out
        }
        Expr::Lambda { params, body } => {
            let lambda_shadowed =
                shadowed || params.iter().any(|p| p == name) || (params.is_empty() && name == "it");
            outer_local_access_expr(file, *body, name, lambda_shadowed)
        }
        Expr::Try {
            body,
            catches,
            finally,
        } => {
            let mut out = outer_local_access_expr(file, *body, name, shadowed);
            for c in catches {
                out.join(outer_local_access_expr(
                    file,
                    c.body,
                    name,
                    shadowed || c.name == name,
                ));
            }
            if let Some(f) = finally {
                out.join(outer_local_access_expr(file, *f, name, shadowed));
            }
            out
        }
        _ => {
            let mut out = OuterLocalAccess::default();
            let mut exprs = Vec::new();
            let mut stmts = Vec::new();
            file.any_child_expr(
                e,
                &mut |c| {
                    exprs.push(c);
                    false
                },
                &mut |s| {
                    stmts.push(s);
                    false
                },
            );
            for c in exprs {
                out.join(outer_local_access_expr(file, c, name, shadowed));
            }
            for s in stmts {
                out.join(outer_local_access_stmt(file, s, name, shadowed).0);
            }
            out
        }
    }
}

fn outer_local_access_stmt(
    file: &ast::File,
    s: crate::ast::StmtId,
    name: &str,
    shadowed: bool,
) -> (OuterLocalAccess, bool) {
    match file.stmt(s) {
        Stmt::Local { name: n, init, .. } => {
            let access = outer_local_access_expr(file, *init, name, shadowed);
            (access, shadowed || n == name)
        }
        Stmt::LocalDelegate {
            name: n, delegate, ..
        } => {
            let access = outer_local_access_expr(file, *delegate, name, shadowed);
            (access, shadowed || n == name)
        }
        Stmt::Destructure { entries, init } => {
            let access = outer_local_access_expr(file, *init, name, shadowed);
            (
                access,
                shadowed || entries.iter().any(|(n, _)| n != "_" && n == name),
            )
        }
        Stmt::Assign { name: n, value } => {
            let mut access = outer_local_access_expr(file, *value, name, shadowed);
            if !shadowed && n == name {
                access.writes = true;
            }
            (access, shadowed)
        }
        Stmt::IncDec { name: n, .. } => (
            OuterLocalAccess {
                reads: !shadowed && n == name,
                writes: !shadowed && n == name,
            },
            shadowed,
        ),
        Stmt::For {
            name: n,
            range,
            body,
            ..
        } => {
            let mut access = outer_local_access_expr(file, range.start, name, shadowed);
            access.join(outer_local_access_expr(file, range.end, name, shadowed));
            access.join(outer_local_access_expr(
                file,
                *body,
                name,
                shadowed || n == name,
            ));
            (access, shadowed)
        }
        Stmt::ForEach {
            name: n,
            iterable,
            body,
            ..
        } => {
            let mut access = outer_local_access_expr(file, *iterable, name, shadowed);
            access.join(outer_local_access_expr(
                file,
                *body,
                name,
                shadowed || n == name,
            ));
            (access, shadowed)
        }
        Stmt::LocalFun(_) | Stmt::LocalClass(_) => (OuterLocalAccess::default(), shadowed),
        _ => {
            let mut access = OuterLocalAccess::default();
            file.any_child_stmt(s, &mut |c| {
                access.join(outer_local_access_expr(file, c, name, shadowed));
                false
            });
            (access, shadowed)
        }
    }
}

/// Collect the simple (`Name`-callee) function-call names anywhere in `e`'s subtree — used to decide
/// whether a lambda body calls a `suspend` function (same-file or classpath).
/// Collect every `Call` expr in `e` (incl. nested) — to resolve a call's suspend-ness via its `Invoke`
/// lowering (a suspend function VALUE / invoke operator) or its callee (a member suspend method), none of
/// which `collect_call_names` (top-level `Call{Name}` only) can see.
fn collect_calls(file: &ast::File, e: AstExprId, out: &std::cell::RefCell<Vec<AstExprId>>) {
    if matches!(file.expr(e), ast::Expr::Call { .. }) {
        out.borrow_mut().push(e);
    }
    file.any_child_expr(
        e,
        &mut |c| {
            collect_calls(file, c, out);
            false
        },
        &mut |s| {
            file.any_child_stmt(s, &mut |c| {
                collect_calls(file, c, out);
                false
            });
            false
        },
    );
}

fn collect_call_names(file: &ast::File, e: AstExprId, out: &std::cell::RefCell<Vec<String>>) {
    if let ast::Expr::Call { callee, .. } = file.expr(e) {
        if let ast::Expr::Name(n) = file.expr(*callee) {
            out.borrow_mut().push(n.clone());
        }
    }
    file.any_child_expr(
        e,
        &mut |c| {
            collect_call_names(file, c, out);
            false
        },
        &mut |s| {
            file.any_child_stmt(s, &mut |c| {
                collect_call_names(file, c, out);
                false
            });
            false
        },
    );
}

fn class_internal(file: &ast::File, name: &str) -> String {
    let mangled = name.replace('.', "$");
    match &file.package {
        Some(p) if !p.is_empty() => format!("{}/{}", p.replace('.', "/"), mangled),
        _ => mangled,
    }
}

/// The `ClassDecl` for a class named `name` (simple name) declared in this file, if any.
fn file_class_decl<'a>(file: &'a ast::File, name: &str) -> Option<&'a ast::ClassDecl> {
    file.decls.iter().find_map(|&d| match file.decl(d) {
        ast::Decl::Class(c) if c.name == name => Some(c),
        _ => None,
    })
}

/// The `ClassDecl` of a RUNTIME-retained `annotation class` named `name` declared in this file — the only
/// annotations krusty emits into `RuntimeVisibleAnnotations`. `None` for a non-annotation / non-file /
/// `SOURCE`/`BINARY`-retained annotation. Kotlin's default retention is RUNTIME.
fn runtime_annotation_decl<'a>(file: &'a ast::File, name: &str) -> Option<&'a ast::ClassDecl> {
    let cd = file_class_decl(file, name).filter(|c| c.kind == ast::ClassKind::Annotation)?;
    // `@Retention(AnnotationRetention.SOURCE|BINARY)` opts out; anything else (incl. no `@Retention`) is
    // RUNTIME. The retention argument is `AnnotationRetention.<X>` — an `Expr::Member`.
    let non_runtime = cd
        .annotations
        .iter()
        .zip(cd.annotation_args.iter())
        .any(|(n, a)| {
            n == "Retention"
                && a.first().is_some_and(|&arg| {
                    matches!(file.expr(arg), ast::Expr::Member { name, .. } if name == "SOURCE" || name == "BINARY")
                })
        });
    (!non_runtime).then_some(cd)
}

/// Fold an annotation argument expression to an encodable `AnnoValue` (JVMS §4.7.16.1), or `None` for a
/// shape not modeled — in which case the whole annotation is dropped (never emitted with a wrong value).
fn eval_anno_value(
    file: &ast::File,
    ir: &crate::ir::IrFile,
    e: AstExprId,
) -> Option<crate::ir::AnnoValue> {
    use crate::ir::{AnnoValue, IrConst};
    Some(match file.expr(e) {
        Expr::StringLit(s) => AnnoValue::Const(IrConst::String(s.clone())),
        Expr::IntLit(v) | Expr::UIntLit(v) => AnnoValue::Const(IrConst::Int(*v as i32)),
        Expr::LongLit(v) | Expr::ULongLit(v) => AnnoValue::Const(IrConst::Long(*v)),
        Expr::DoubleLit(v) => AnnoValue::Const(IrConst::Double(*v)),
        Expr::FloatLit(v) => AnnoValue::Const(IrConst::Float(*v)),
        Expr::BoolLit(v) => AnnoValue::Const(IrConst::Boolean(*v)),
        Expr::CharLit(v) => AnnoValue::Const(IrConst::Char(*v)),
        // `E.E0` — an ENUM constant (`receiver` names an enum class declared in this file).
        Expr::Member { receiver, name } => {
            let Expr::Name(enum_name) = file.expr(*receiver) else {
                return None;
            };
            file_class_decl(file, enum_name).filter(|c| c.kind == ast::ClassKind::Enum)?;
            let internal = class_internal(file, enum_name);
            AnnoValue::Enum(type_name(&internal), name.clone())
        }
        // `A::class` — a class literal.
        Expr::CallableRef {
            receiver: Some(r),
            name,
        } if name == "class" => {
            let Expr::Name(cn) = file.expr(*r) else {
                return None;
            };
            let internal = class_internal(file, cn);
            AnnoValue::Class(type_name(&internal))
        }
        Expr::Call { callee, args } => {
            let Expr::Name(fname) = file.expr(*callee) else {
                return None;
            };
            match fname.as_str() {
                "emptyArray" => AnnoValue::Array(Vec::new()),
                "arrayOf" | "intArrayOf" | "longArrayOf" | "doubleArrayOf" | "floatArrayOf"
                | "booleanArrayOf" | "charArrayOf" | "byteArrayOf" | "shortArrayOf" => {
                    let items: Option<Vec<_>> =
                        args.iter().map(|&a| eval_anno_value(file, ir, a)).collect();
                    AnnoValue::Array(items?)
                }
                // A NESTED annotation instance `A(...)`.
                _ => AnnoValue::Annotation(build_applied_annotation(file, fname, args, ir)?),
            }
        }
        _ => return None,
    })
}

/// Fold `@Name(args…)` (positional) to an `AppliedAnnotation`, pairing each argument with the annotation's
/// constructor-parameter name. `None` unless `Name` is a RUNTIME-retained file annotation class and every
/// argument folds to a constant.
fn build_applied_annotation(
    file: &ast::File,
    name: &str,
    args: &[AstExprId],
    ir: &crate::ir::IrFile,
) -> Option<crate::ir::AppliedAnnotation> {
    let cd = runtime_annotation_decl(file, name)?;
    let mut values = Vec::new();
    for (i, &arg) in args.iter().enumerate() {
        let pname = cd.props.get(i)?.name.clone();
        values.push((pname, eval_anno_value(file, ir, arg)?));
    }
    Some(crate::ir::AppliedAnnotation {
        internal: type_name(&class_internal(file, name)),
        values,
    })
}

fn build_applied_annotations(
    file: &ast::File,
    names: &[String],
    args: &[Vec<AstExprId>],
    ir: &crate::ir::IrFile,
) -> Vec<crate::ir::AppliedAnnotation> {
    names
        .iter()
        .zip(args.iter())
        .filter_map(|(name, args)| build_applied_annotation(file, name, args, ir))
        .collect()
}

/// User annotations on enum-constant fields. Same-file runtime annotations are folded; unsupported
/// annotations are skipped rather than emitted with wrong values.
fn class_field_annotations(
    file: &ast::File,
    c: &ast::ClassDecl,
    syms: &FrontendSymbols,
    ir: &crate::ir::IrFile,
) -> Vec<crate::ir::FieldAnnotations> {
    let mut out = Vec::new();
    for e in &c.enum_entries {
        let mut visible = Vec::new();
        let mut invisible = Vec::new();
        for (n, a) in e.annotations.iter().zip(e.annotation_args.iter()) {
            match resolve_field_annotation(file, syms, n, a, ir) {
                Some((anno, Retention::Runtime)) => visible.push(anno),
                Some((anno, Retention::Binary)) => invisible.push(anno),
                // SAME-FILE RUNTIME annotations still resolve through build_applied_annotation directly
                // when the classpath path can't (a file-local annotation class isn't on the classpath).
                None => {
                    if let Some(anno) = build_applied_annotation(file, n, a, ir) {
                        visible.push(anno);
                    }
                }
            }
        }
        if !visible.is_empty() || !invisible.is_empty() {
            out.push(crate::ir::FieldAnnotations {
                field: e.name.clone(),
                visible,
                invisible,
            });
        }
    }
    out
}

/// JVM retention of an annotation whose uses krusty emits: RUNTIME → `RuntimeVisibleAnnotations`,
/// BINARY (`RetentionPolicy.CLASS`) → `RuntimeInvisibleAnnotations`. SOURCE is dropped (returns `None`).
enum Retention {
    Runtime,
    Binary,
}

/// Resolve `@Name(args…)` applied to a FIELD to `(AppliedAnnotation, retention)`, handling a CLASSPATH
/// annotation (e.g. `@SerialName`): resolve the type through the file's imports, read its `@Retention`
/// and element names from the compiled annotation class. `None` for a same-file annotation (caller
/// falls back to [`build_applied_annotation`]), a SOURCE-retained one, an unresolved type, or a
/// non-constant argument.
fn resolve_field_annotation(
    file: &ast::File,
    syms: &FrontendSymbols,
    name: &str,
    args: &[AstExprId],
    ir: &crate::ir::IrFile,
) -> Option<(crate::ir::AppliedAnnotation, Retention)> {
    let internal = file.imports.iter().find_map(|imp| {
        let cand = imp.replace('.', "/");
        (imp.rsplit('.').next() == Some(name) && syms.libraries.resolve_type(&cand).is_some())
            .then_some(cand)
    })?;
    let lt = syms.libraries.resolve_type(&internal)?;
    if !lt.is_annotation() {
        return None;
    }
    let retention = match lt.retention.as_deref()? {
        "RUNTIME" => Retention::Runtime,
        "CLASS" => Retention::Binary,
        _ => return None, // SOURCE — kotlinc emits nothing
    };
    let elements = lt.annotation_members()?;
    let mut values = Vec::new();
    for (i, &arg) in args.iter().enumerate() {
        let ename = elements.get(i)?.0.clone();
        values.push((ename, eval_anno_value(file, ir, arg)?));
    }
    Some((
        crate::ir::AppliedAnnotation {
            internal: type_name(&internal),
            values,
        },
        retention,
    ))
}

/// The RUNTIME-retained applied annotations on a class declaration, folded for `RuntimeVisibleAnnotations`.
fn class_applied_annotations(
    file: &ast::File,
    c: &ast::ClassDecl,
    ir: &crate::ir::IrFile,
) -> Vec<crate::ir::AppliedAnnotation> {
    build_applied_annotations(file, &c.annotations, &c.annotation_args, ir)
}

/// Extract the BACKEND-AGNOSTIC generic-signature shape of a generic class (`class Box<T>`), or `None`
/// for a non-generic class / one with explicit supertypes (whose generic args aren't modeled yet) / an
/// unsupported bound. The `jvm` backend formats this into the class `Signature` attribute.
fn class_generic_sig(
    file: &ast::File,
    c: &ast::ClassDecl,
    libraries: &dyn SemanticPlatform,
    class_names: &ClassNames,
) -> Option<crate::ir::IrGenericSig> {
    // A CLASS with a PARAMETERIZED supertype (`object O : Operation<Result<Int>>`): carry the superclass
    // + interfaces as `Ty`s (with their type arguments) so the backend can format a class `Signature` a
    // cross-module reader uses to recover a member's concrete generic return. Independent of own type params.
    if c.supertypes.iter().any(|s| !s.targs.is_empty()) {
        let mut supers: Vec<Ty> = Vec::new();
        // Superclass first (kotlin/Any → the backend's Object when no base). Base-class type args aren't
        // preserved yet (the base is a bare name), so a base class is emitted raw.
        supers.push(match &c.base_class {
            Some(b) => Ty::obj(&resolve_super_internal(b, file, class_names)?),
            None => Ty::obj("kotlin/Any"),
        });
        for st in &c.supertypes {
            supers.push(supertype_ty(st, file, class_names)?);
        }
        let type_params = if c.type_params.is_empty() {
            Vec::new()
        } else {
            type_param_bounds_ir(file, &c.type_params, &c.type_param_bounds, libraries)?
        };
        crate::trace_compiler!("value_classes", "class {} supers = {:?}", c.name, supers);
        return Some(crate::ir::IrGenericSig {
            type_params,
            param_tparams: Vec::new(),
            ret_tparam: None,
            supers,
        });
    }
    // The original case: a generic class with only own type parameters and no supertypes.
    if c.type_params.is_empty() || c.base_class.is_some() || !c.supertypes.is_empty() {
        return None;
    }
    Some(crate::ir::IrGenericSig {
        type_params: type_param_bounds_ir(file, &c.type_params, &c.type_param_bounds, libraries)?,
        param_tparams: Vec::new(),
        ret_tparam: None,
        supers: Vec::new(),
    })
}

/// A supertype / type-argument `TypeRef` resolved to a platform-agnostic `Ty` carrying its type arguments
/// (`Operation<Result<Int>>` → `Obj("Operation", [Obj("kotlin/Result", [Int])])`). `None` when a name
/// can't be resolved to an internal (then no class `Signature` is emitted — a safe fallback).
fn supertype_ty(tr: &ast::TypeRef, file: &ast::File, class_names: &ClassNames) -> Option<Ty> {
    if let Some(t) = Ty::from_name(&tr.name) {
        return Some(t); // a builtin scalar / String / Any / Unit
    }
    let internal = resolve_super_internal(&tr.name, file, class_names)?;
    if tr.targs.is_empty() {
        return Some(Ty::obj(&internal));
    }
    let args: Vec<Ty> = tr
        .targs
        .iter()
        .map(|a| supertype_ty(a, file, class_names))
        .collect::<Option<_>>()?;
    Some(Ty::obj_args(&internal, &args))
}

/// Resolve a supertype / type-argument simple name to a krusty-canonical internal name: a class declared
/// in THIS file, else a classpath type via the platform's seeded name→internal map. `None` if unresolvable.
fn resolve_super_internal(
    name: &str,
    file: &ast::File,
    class_names: &ClassNames,
) -> Option<String> {
    if file
        .decls
        .iter()
        .any(|&d| matches!(file.decl(d), Decl::Class(ic) if ic.name == name))
    {
        return Some(class_internal(file, name));
    }
    // The signature phase's import-driven resolution already recorded this name → internal (a classpath
    // supertype resolves through the file's imports/default packages), so read it back here.
    class_names.get(name).map(TypeName::render)
}

/// For a generic class, list `(field name, type-parameter name)` for each property whose declared type
/// is a bare type-parameter reference (`class Pair<A, B>(val a: A, val b: B)` → `[("a","A"),("b","B")]`).
/// The JVM backend emits a field `Signature` (`TA;`) for each. Empty for a non-generic class.
fn class_field_tparams(c: &ast::ClassDecl) -> Vec<(String, String)> {
    if c.type_params.is_empty() {
        return Vec::new();
    }
    let tps = &c.type_params;
    let mut out = Vec::new();
    // Constructor `val`/`var` properties (backing fields), then class-body backing-field properties.
    for p in c.props.iter().filter(|p| p.is_property) {
        if ref_is_bare_tparam(&p.ty, tps) {
            out.push((p.name.clone(), p.ty.name.clone()));
        }
    }
    for p in c.body_props.iter().filter(|p| is_backing_field_prop(p)) {
        if let Some(ty) = &p.ty {
            if ref_is_bare_tparam(ty, tps) {
                out.push((p.name.clone(), ty.name.clone()));
            }
        }
    }
    out
}

/// Extract the backend-agnostic generic-signature shape of a type-parameterized function, or `None` for
/// a non-generic function / an unmodeled shape (a type parameter inside a generic argument like
/// `List<T>`, a vararg, an unsupported bound). Concrete parameter/return types are left to the backend
/// (which reads them from the `IrFunction`); only the bare-type-parameter positions are recorded.
fn fn_generic_sig(
    file: &ast::File,
    f: &ast::FunDecl,
    libraries: &dyn SemanticPlatform,
) -> Option<crate::ir::IrGenericSig> {
    if f.type_params.is_empty() {
        return None;
    }
    let tps = &f.type_params;
    let mut param_tparams = Vec::with_capacity(f.params.len());
    for p in &f.params {
        if p.is_vararg {
            return None;
        }
        if ref_is_bare_tparam(&p.ty, tps) {
            param_tparams.push(Some(p.ty.name.clone()));
        } else if ref_uses_tparam(&p.ty, tps) {
            return None;
        } else {
            param_tparams.push(None);
        }
    }
    let ret_tparam = match f.ret.as_ref() {
        Some(r) if ref_is_bare_tparam(r, tps) => Some(r.name.clone()),
        Some(r) if ref_uses_tparam(r, tps) => return None,
        _ => None,
    };
    Some(crate::ir::IrGenericSig {
        type_params: type_param_bounds_ir(file, tps, &f.type_param_bounds, libraries)?,
        param_tparams,
        ret_tparam,
        supers: Vec::new(),
    })
}

/// Pair each type-parameter name with its upper bound as a Kotlin `IrType` (`kotlin/Any` when none / an
/// `Any` bound). `None` if a bound is a non-`Any`, non-primitive type (not modeled yet → omit the whole
/// signature). Backend-agnostic: the bound is a Kotlin type; the JVM backend maps a primitive to its wrapper.
fn type_param_bounds_ir(
    file: &ast::File,
    names: &[String],
    bounds: &[(String, ast::TypeRef)],
    libraries: &dyn SemanticPlatform,
) -> Option<Vec<(String, Ty)>> {
    let any = || Ty::obj("kotlin/Any");
    let mut out = Vec::with_capacity(names.len());
    for tp in names {
        let bound = match bounds.iter().find(|(n, _)| n == tp) {
            None => any(),
            Some((_, b)) if b.name == "Any" && !b.nullable => any(),
            // A primitive bound (`T : Int`) is specialized; its Signature bound is the boxed wrapper.
            Some((_, b))
                if Ty::from_name(&b.name).is_some_and(|t| t.scalar_value_repr().is_some()) =>
            {
                ty_to_ir(Ty::from_name(&b.name).unwrap())
            }
            // A PARAMETERIZED bound (`T : Comparable<T>`, `T : List<String>`) needs a nested generic
            // signature we don't build here — suppress the whole signature rather than emit a wrong one.
            Some((_, b)) if !b.targs.is_empty() || b.arg.is_some() => return None,
            // A simple reference bound (`T : I`, `T : CharSequence`) → resolve to its class type; the
            // JVM backend (`jvm_bound_descriptor`) emits it as `L<internal>;` (kotlinc does the same).
            Some((_, b)) => match ty_to_ir(ty_of(file, b, libraries)) {
                t @ Ty::Obj(_, _) => t,
                _ => return None,
            },
        };
        out.push((tp.clone(), bound));
    }
    Some(out)
}

fn ref_is_bare_tparam(r: &ast::TypeRef, tps: &[String]) -> bool {
    // A nullable type-parameter ref (`T?`) is still `T<name>;` in the JVM generic signature — nullability
    // is not represented there (kotlinc drops it; the erased descriptor is `Object` either way).
    r.fun_params.is_empty() && r.targs.is_empty() && tps.iter().any(|t| t == &r.name)
}

fn ref_uses_tparam(r: &ast::TypeRef, tps: &[String]) -> bool {
    tps.iter().any(|t| t == &r.name)
        || r.targs.iter().any(|a| ref_uses_tparam(a, tps))
        || r.fun_params.iter().any(|a| ref_uses_tparam(a, tps))
        || r.arg.as_ref().is_some_and(|a| ref_uses_tparam(a, tps))
}

/// An IR field type that PRESERVES generic type arguments at every depth (`List<List<String>>` keeps both
/// the outer and inner element types). `ty_of`/`ty_to_ir` erase a general `Obj`'s args; this rebuilds them
/// recursively from the source `TypeRef` so the serialization extension can derive a nested element
/// serializer (`ListSerializer(ListSerializer(StringSerializer))`). Additive metadata on the type only.
fn field_ty_with_args(file: &ast::File, tr: &ast::TypeRef, plat: &dyn SemanticPlatform) -> Ty {
    let base = ty_to_ir(ty_of(file, tr, plat));
    // Rebuild the non-null type with recursively-preserved type arguments, then re-apply the source `?`
    // from the `TypeRef` (`ty_of` strips it from a reference type) — so a nullable element `String?` keeps
    // its nullability, which the element serializer needs for a `.nullable` wrapper.
    let resolved = match base.non_null().obj_internal() {
        Some(fq) if !tr.targs.is_empty() => {
            let targs: Vec<Ty> = tr
                .targs
                .iter()
                .map(|a| field_ty_with_args(file, a, plat))
                .collect();
            Ty::obj_args_name(fq, &targs)
        }
        _ => base.non_null(),
    };
    if tr.nullable {
        Ty::nullable(resolved)
    } else {
        resolved
    }
}

fn ty_of(file: &ast::File, r: &ast::TypeRef, plat: &dyn SemanticPlatform) -> Ty {
    // Function type, builtin scalar, or primitive array — the leaf shared by every type resolver.
    if let Some(t) = typeref_leaf(r, &mut |x| ty_of(file, x, plat)) {
        // Nullable primitives/Unit are reference slots consistent with the checker.
        if r.nullable {
            return t.nullable_non_ref().unwrap_or(t);
        }
        return t;
    }
    if r.name == "Array" {
        let elem = r
            .arg
            .as_ref()
            .map(|a| ty_of(file, a, plat))
            .unwrap_or_else(|| Ty::obj("kotlin/Any"));
        if elem.is_reference() {
            return Ty::array(elem);
        } else if elem.jvm_boxed_ref().is_some() {
            // A boxed primitive `Array<Int>` = `Integer[]` — `Obj("kotlin/Array", [Int])`, the same
            // logical form as `arrayOf(1)`/`Array(n){…}` (element read unboxed, backend boxes).
            return Ty::obj_args("kotlin/Array", &[elem]);
        }
    }
    let is_class = file
        .decls
        .iter()
        .any(|&d| matches!(file.decl(d), Decl::Class(c) if c.name == r.name));
    if is_class {
        Ty::obj(&class_internal(file, &r.name))
    } else if let Some(internal) = plat.builtin_type_internal(&r.name) {
        // A built-in collection/reference type resolves to its FRONT-END Kotlin name — a collection keeps
        // `kotlin/collections/{List,MutableList,…}` (read-only vs mutable; the platform erases both to the
        // single JVM interface at the emit boundary), so the core IR stays in Kotlin names.
        Ty::obj(&internal)
    } else {
        Ty::obj("kotlin/Any")
    }
}

/// Whether an `IrType` is a reference type (anything except a primitive class FqName / Unit).
fn ir_type_is_reference(t: &Ty) -> bool {
    // A NULLABLE value is always a reference: a nullable reference keeps its descriptor, and a nullable
    // PRIMITIVE (`Int?`, `UInt?`) is its BOXED wrapper (`java/lang/Integer`, `kotlin/UInt`) — a `?`
    // primitive can never occupy a primitive slot. (The IR used to carry these pre-boxed as `Obj(..)`;
    // with source types the `?`-primitive stays `Nullable(Int)`, so recognize it here.)
    if t.is_nullable() {
        return true;
    }
    // The IR now carries SOURCE `Ty` variants directly — `Ty::String` is a reference but has no
    // `obj_internal()`, so recognize it explicitly (before it was always `Obj("kotlin/String")` and
    // matched the fallback). `Ty::Fun` is a `FunctionN` reference; arrays are `Obj("kotlin/Array")` /
    // `Obj("kotlin/IntArray")` and fall through to the `obj_internal` clause.
    matches!(t, Ty::Fun(_) | Ty::String)
        || t.obj_internal()
            .is_some_and(|_| t.unboxed_primitive().is_none())
}

/// Whether `t` is exactly the erased top type (no `checkcast` to it).
fn ir_type_is_object(t: &Ty) -> bool {
    t.is_erased_top()
}

/// Conservative "is `arg` assignable to `param`" for constructor-overload selection: an exact match,
/// or any reference flowing into an erased `Object`/`Any` param (an erased generic type parameter).
/// Deliberately strict otherwise (no class-hierarchy data here) — used only to tell whether the PRIMARY
/// constructor can accept the args before falling back to a secondary (`IC("abc")`: a `String` is NOT
/// assignable to the primary's `List<T>` param, but IS to the secondary's erased `T`).
fn ir_arg_assignable(arg: &Ty, param: &Ty) -> bool {
    arg == param
        || (ir_type_is_object(param) && ir_type_is_reference(arg))
        // Same erased class with differing type arguments; the precise generic check already happened in
        // the checker.
        || arg
            .non_null()
            .obj_internal()
            .is_some_and(|a| param.non_null().obj_internal() == Some(a))
}

/// Whether `e` declares a local `val`/`var` (a `Stmt::Local`/`Destructure`), not descending into a
/// nested lambda. A `finally` that declares locals can't be inlined on the several exit paths krusty's
/// `emit_try` needs without the duplicated locals' slots clashing across copies — so such a `try` skips.
fn body_declares_local(file: &ast::File, e: AstExprId) -> bool {
    fn ex(file: &ast::File, e: AstExprId) -> bool {
        match file.expr(e) {
            Expr::Lambda { .. } | Expr::CallableRef { .. } => false,
            _ => file.any_child_expr(e, &mut |c| ex(file, c), &mut |s| st(file, s)),
        }
    }
    fn st(file: &ast::File, s: crate::ast::StmtId) -> bool {
        match file.stmt(s) {
            Stmt::Local { .. } | Stmt::Destructure { .. } => true,
            Stmt::Expr(e)
            | Stmt::Assign { value: e, .. }
            | Stmt::While { body: e, .. }
            | Stmt::DoWhile { body: e, .. }
            | Stmt::For { body: e, .. }
            | Stmt::ForEach { body: e, .. } => ex(file, *e),
            _ => false,
        }
    }
    ex(file, e)
}

/// Whether `e` contains a `break`/`continue` that escapes past this region (a loop-local one is fine).
/// `with_return` also flags a `return` — used where a `return` can't be modeled; `false` where the
/// lowerer handles `return` itself (inlining enclosing `finally`s) and only `break`/`continue` must bail.
fn body_has_break_continue(file: &ast::File, e: AstExprId) -> bool {
    body_has_exit(file, e, false)
}

/// Whether `e` (a `finally` body) contains a `break`/`continue` that escapes the `finally` — an
/// UNLABELED jump not enclosed by a loop within the body, or ANY LABELED jump (which may target a
/// loop outside the `finally`). Running a `finally` while transferring such a jump out isn't modeled,
/// so the enclosing `try` is skipped rather than miscompiled (a `break` out of a `finally` otherwise
/// leaves the operand stack / locals in a state the verifier rejects).
fn finally_has_escaping_break_continue(file: &ast::File, e: AstExprId) -> bool {
    fn ex(file: &ast::File, e: AstExprId, ld: u32) -> bool {
        match file.expr(e) {
            Expr::Lambda { .. } | Expr::CallableRef { .. } => false,
            _ => file.any_child_expr(e, &mut |c| ex(file, c, ld), &mut |s| st(file, s, ld)),
        }
    }
    fn st(file: &ast::File, s: crate::ast::StmtId, ld: u32) -> bool {
        match file.stmt(s) {
            // A labeled jump can target a loop OUTSIDE the finally regardless of nesting depth.
            Stmt::Break(Some(_)) | Stmt::Continue(Some(_)) => true,
            Stmt::Break(None) | Stmt::Continue(None) => ld == 0,
            Stmt::Expr(e)
            | Stmt::Local { init: e, .. }
            | Stmt::Assign { value: e, .. }
            | Stmt::Destructure { init: e, .. } => ex(file, *e, ld),
            Stmt::While { cond, body, .. } => ex(file, *cond, ld) || ex(file, *body, ld + 1),
            Stmt::DoWhile { body, cond, .. } => ex(file, *body, ld + 1) || ex(file, *cond, ld),
            Stmt::For { body, .. } | Stmt::ForEach { body, .. } => ex(file, *body, ld + 1),
            _ => false,
        }
    }
    ex(file, e, 0)
}

fn body_has_exit(file: &ast::File, e: AstExprId, with_return: bool) -> bool {
    fn ex(file: &ast::File, e: AstExprId, ld: u32, wr: bool) -> bool {
        match file.expr(e) {
            // A lambda's control flow is separate; a callable-ref receiver carries no return/break.
            Expr::Lambda { .. } | Expr::CallableRef { .. } => false,
            _ => file.any_child_expr(e, &mut |c| ex(file, c, ld, wr), &mut |s| {
                st(file, s, ld, wr)
            }),
        }
    }
    fn st(file: &ast::File, s: crate::ast::StmtId, ld: u32, wr: bool) -> bool {
        match file.stmt(s) {
            Stmt::Return(..) => wr,
            Stmt::Break(_) | Stmt::Continue(_) => ld == 0,
            Stmt::Expr(e)
            | Stmt::Local { init: e, .. }
            | Stmt::Assign { value: e, .. }
            | Stmt::Destructure { init: e, .. } => ex(file, *e, ld, wr),
            // A loop's body raises the loop depth, so its `break`/`continue` are loop-local.
            Stmt::While { cond, body, .. } => {
                ex(file, *cond, ld, wr) || ex(file, *body, ld + 1, wr)
            }
            Stmt::DoWhile { body, cond, .. } => {
                ex(file, *body, ld + 1, wr) || ex(file, *cond, ld, wr)
            }
            Stmt::For { body, .. } | Stmt::ForEach { body, .. } => ex(file, *body, ld + 1, wr),
            _ => false,
        }
    }
    ex(file, e, 0, with_return)
}

/// Carry a declared `?` into a field/underlying type. The JVM value-class pass keys unboxed-vs-boxed
/// representation on a value class's underlying nullability.
fn mark_nullable(t: Ty) -> Ty {
    Ty::nullable(t)
}

pub(crate) fn ty_to_ir(t: Ty) -> Ty {
    t
}

fn tys_to_ir(tys: &[Ty]) -> Vec<Ty> {
    tys.iter().copied().map(stored_value_ty).collect()
}

/// The IR element type of a captured mutable local's `Ref` holder — like [`ty_to_ir`], but PRESERVING a
/// reference type's nullability. `ty_to_ir` drops `?` on references (the IR carries no reference
/// nullability), but a shared cell must keep it: a NULLABLE reference-underlying value class (`var
/// res: Result<T>?`) is stored BOXED, and the value-class pass distinguishes that boxed form from a
/// non-null (unboxed-underlying) one ONLY by the element type's nullability. Without this the `?` is lost,
/// the pass reads the cell as an unboxed underlying, and a `res!!.getOrThrow()` fails to unbox the box.
fn ref_elem_ir(t: Ty) -> Ty {
    if t.is_nullable() {
        Ty::nullable(ty_to_ir(t.non_null()))
    } else {
        ty_to_ir(t)
    }
}

/// The element `IrType` of an array `IrType` target — a reference `Array<E>` (its type argument) or a
/// primitive specialized array (`kotlin/IntArray` → `kotlin/Int`). `None` for a non-array type. Used
/// to materialize an empty array (`emptyArray<T>()`) of the target's element type.
fn ir_array_element(t: &Ty) -> Option<Ty> {
    let Some(fq_name) = t.non_null().obj_internal() else {
        return None;
    };
    if fq_name.matches("kotlin/Array") {
        return t.non_null().type_args().first().copied();
    }
    let prim = if fq_name.matches("kotlin/IntArray") {
        "kotlin/Int"
    } else if fq_name.matches("kotlin/LongArray") {
        "kotlin/Long"
    } else if fq_name.matches("kotlin/DoubleArray") {
        "kotlin/Double"
    } else if fq_name.matches("kotlin/FloatArray") {
        "kotlin/Float"
    } else if fq_name.matches("kotlin/BooleanArray") {
        "kotlin/Boolean"
    } else if fq_name.matches("kotlin/CharArray") {
        "kotlin/Char"
    } else if fq_name.matches("kotlin/ByteArray") {
        "kotlin/Byte"
    } else if fq_name.matches("kotlin/ShortArray") {
        "kotlin/Short"
    } else {
        return None;
    };
    Some(Ty::obj(prim))
}

/// Per-parameter `Some(name)` when a non-null assertion (`Intrinsics.checkNotNullParameter`) should
/// guard it: a non-null reference parameter of a visible (non-`private`) function — matching kotlinc.
/// Primitives, nullable params (`String?`), and generic type parameters (`T`, which may be nullable)
/// are skipped. Conservative: when the parameter lists don't line up (e.g. an extension receiver
/// shifts them) no guards are emitted.
/// Whether the expression tree rooted at `e` contains a CALL to the unqualified `name` — recursing FULLY
/// through nested lambdas AND statement bodies (so a `sequence { for (…) { yield(i) } }` is found).
fn expr_tree_calls_name(file: &ast::File, e: AstExprId, name: &str) -> bool {
    if let Expr::Call { callee, .. } = file.expr(e) {
        if matches!(file.expr(*callee), Expr::Name(n) if n == name) {
            return true;
        }
    }
    file.any_child_expr(e, &mut |c| expr_tree_calls_name(file, c, name), &mut |s| {
        file.any_child_stmt(s, &mut |c| expr_tree_calls_name(file, c, name))
    })
}

fn param_checks_for(
    f: &ast::FunDecl,
    param_tys: &[Ty],
    class_type_params: &[String],
    class_nonnull_type_params: &std::collections::HashSet<String>,
) -> Vec<Option<String>> {
    if f.visibility.is_private() || f.receiver.is_some() || f.params.len() != param_tys.len() {
        return vec![None; param_tys.len()];
    }
    f.params
        .iter()
        .zip(param_tys)
        .map(|(p, ty)| {
            // A parameter typed as a TYPE PARAMETER (the function's own or the enclosing class's) is
            // null-checked only when that parameter has a NON-NULL bound; an unbounded `T` (= `Any?`,
            // nullable) is not — e.g. `Map<K, V>.get(key: K)` on a `K = Any?` instantiation accepts null.
            // A function type parameter uses the same rule via the function's non-null set.
            let nullable_type_param = (f.type_params.contains(&p.ty.name)
                && !f.non_null_type_params.contains(&p.ty.name))
                || (class_type_params.contains(&p.ty.name)
                    && !class_nonnull_type_params.contains(&p.ty.name));
            // A value-class parameter is erased to its underlying type; the null-check applies to that
            // (a primitive underlying gets none — the param is a primitive local, not a reference).
            if !p.ty.nullable && !nullable_type_param && ty.is_reference() {
                Some(p.name.clone())
            } else {
                None
            }
        })
        .collect()
}

fn bin_to_ir(op: BinOp) -> Option<IrBinOp> {
    Some(match op {
        BinOp::Add => IrBinOp::Add,
        BinOp::Sub => IrBinOp::Sub,
        BinOp::Mul => IrBinOp::Mul,
        BinOp::Div => IrBinOp::Div,
        BinOp::Rem => IrBinOp::Rem,
        BinOp::Lt => IrBinOp::Lt,
        BinOp::Le => IrBinOp::Le,
        BinOp::Gt => IrBinOp::Gt,
        BinOp::Ge => IrBinOp::Ge,
        BinOp::Eq => IrBinOp::Eq,
        BinOp::Ne => IrBinOp::Ne,
        BinOp::RefEq => IrBinOp::RefEq,
        BinOp::RefNe => IrBinOp::RefNe,
        BinOp::And => IrBinOp::And,
        BinOp::Or => IrBinOp::Or,
    })
}
